import { setup, assign } from 'xstate';

interface Doc {
  title: string;
  body: string;
}

interface Ctx {
  past: Doc[];
  present: Doc;
  future: Doc[];
}

type Ev =
  | { type: 'EDIT'; patch: Partial<Doc> }
  | { type: 'UNDO' }
  | { type: 'REDO' };

export const docHistoryMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canUndo: ({ context }) => context.past.length > 0,
    canRedo: ({ context }) => context.future.length > 0
  },
  actions: {
    applyPatch: assign(({ context, event }) => {
      if (event.type !== 'EDIT') return {};
      return {
        past: [...context.past, context.present],
        present: { ...context.present, ...event.patch },
        future: [] as Doc[]
      };
    }),
    undo: assign(({ context }) => ({
      past: context.past.slice(0, -1),
      present: context.past[context.past.length - 1] ?? context.present,
      future: [context.present, ...context.future]
    })),
    redo: assign(({ context }) => ({
      past: [...context.past, context.present],
      present: context.future[0] ?? context.present,
      future: context.future.slice(1)
    }))
  }
}).createMachine({
  id: 'docHistory',
  context: { past: [], present: { title: '', body: '' }, future: [] },
  on: {
    EDIT: { actions: 'applyPatch' },
    UNDO: { guard: 'canUndo', actions: 'undo' },
    REDO: { guard: 'canRedo', actions: 'redo' }
  }
});
