type Ctx = { dirty: boolean; confirmed: boolean };
type Ev = { type: 'OPEN' } | { type: 'EDIT' } | { type: 'REQUEST_CLOSE' } | { type: 'CONFIRM_CLOSE' } | { type: 'CANCEL_CLOSE' };

