```typescript
export type ItinState = { status: "none" } | { status: "booked"; id: string; legs: number };
export type ItinCommand = { type: "bookItinerary"; id: string; pax: string } | { type: "addLeg"; from: string; to: string };
export type ItinEvent = { type: "ItineraryBooked"; id: string; pax: string } | { type: "LegAdded"; from: string; to: string };

const initialState: ItinState = { status: "none" };

function evolve(s: ItinState, e: ItinEvent): ItinState {
  switch (e.type) {
    case "ItineraryBooked": return { status: "booked", id: e.id, legs: 0 };
    case "LegAdded":
      if (s.status !== "booked") return s;
      return { ...s, legs: s.legs + 1 };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: ItinCommand, s: ItinState): ItinEvent[] {
  switch (c.type) {
    case "bookItinerary":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "ItineraryBooked", id: c.id, pax: c.pax }];
    case "addLeg":
      if (s.status !== "booked") throw new Error("NOT_BOOKED");
      return [{ type: "LegAdded", from: c.from, to: c.to }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(name: string): Promise<{ revision: bigint; data: ItinEvent }[]>;
  appendToStream(name: string, events: ItinEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handleItinerary(cmd: ItinCommand, deps: { streamName: string; eventStore: EventStore }): Promise<void> {
  const stored = await deps.eventStore.readStream(deps.streamName);
  const state = stored.reduce<ItinState>((s, r) => evolve(s, r.data), initialState);
  const events = decide(cmd, state);
  const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  await deps.eventStore.appendToStream(deps.streamName, events, { expectedRevision });
}
