```typescript
import { Effect } from "effect";

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type PublicationDraftState =
  | { status: "none" }
  | { status: "drafting"; id: string }
  | { status: "inReview"; id: string }
  | { status: "accepted"; id: string };

export type PublicationDraftEvent =
  | { type: "PublicationDraftStarted"; id: string }
  | { type: "PublicationDraftSubmitted" }
  | { type: "PublicationDraftAccepted" };

const empty: PublicationDraftState = { status: "none" };

export function when(state: PublicationDraftState, event: PublicationDraftEvent): PublicationDraftState {
  switch (event.type) {
    case "PublicationDraftStarted":
      return { status: "drafting", id: event.id };
    case "PublicationDraftSubmitted":
      return state.status === "drafting" ? { status: "inReview", id: state.id } : state;
    case "PublicationDraftAccepted":
      return state.status === "inReview" ? { status: "accepted", id: state.id } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export const loadDraft = (stream: AsyncIterable<PublicationDraftEvent>) =>
  Effect.promise(() => aggregateStream(stream, when, empty));
