```typescript
export type CurrentDatasetVersion = {
  id: string;
  sizeBytes: number;
  schemaId: string;
};

export const CURRENT_VERSION = 3;

export type Snapshot<S> = { version: number; state: S };

type V1 = { id: string; size: number };
type V2 = { id: string; sizeBytes: number };

function v1ToV2(raw: V1): V2 {
  return { id: raw.id, sizeBytes: raw.size * 1_000_000 };
}

function v2ToV3(raw: V2): CurrentDatasetVersion {
  return { ...raw, schemaId: "schema/v0" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDatasetVersion> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1ToV2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2ToV3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`Unsupported version ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentDatasetVersion };
}
