```typescript
export type ProjectEvent =
  | { type: "ProjectPlanned"; id: string; name: string }
  | { type: "ProjectStarted"; at: string }
  | { type: "ProjectCompleted"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStreamRevision(stream: string): Promise<bigint | null>;
  appendToStream(
    stream: string,
    events: readonly ProjectEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(
    public readonly stream: string,
    public readonly expected: ExpectedRevision,
  ) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

function looksLikeConflict(err: unknown): boolean {
  if (!(err instanceof Error)) return false;
  const msg = err.message.toUpperCase();
  return msg.includes("WRONG_EXPECTED_VERSION") || msg.includes("REVISION");
}

export async function appendProjectEvents(
  store: EventStore,
  stream: string,
  events: readonly ProjectEvent[],
): Promise<bigint> {
  const currentRevision = await store.readStreamRevision(stream);
  const expectedRevision: ExpectedRevision = currentRevision ?? "no_stream";
  try {
    const result = await store.appendToStream(stream, events, { expectedRevision });
    return result.nextExpectedRevision;
  } catch (err) {
    if (looksLikeConflict(err)) {
      throw new ConcurrencyConflict(stream, expectedRevision);
    }
    throw err;
  }
}
```

Use `after` to schedule a delayed transition. Each TYPE re-enters `typing` which cancels the pending timer implicitly; after 500ms of quiet we transition to `searching`.

```typescript
import { setup, assign } from 'xstate';

export const searchMachine = setup({
  types: {
    context: {} as { query: string; results: string[] },
    events: {} as { type: 'TYPE'; q: string } | { type: 'SEARCHED'; hits: string[] }
  }
}).createMachine({
  id: 'search',
  context: { query: '', results: [] },
  initial: 'idle',
  states: {
    idle: {
      on: { TYPE: { target: 'typing', actions: assign({ query: ({ event }) => event.q }) } }
    },
    typing: {
      on: { TYPE: { target: 'typing', reenter: true, actions: assign({ query: ({ event }) => event.q }) } },
      after: {
        500: 'searching'
      }
    },
    searching: {
      on: {
        SEARCHED: { target: 'idle', actions: assign({ results: ({ event }) => event.hits }) }
      }
    }
  }
});
