```typescript
export type ManufacturingLotState =
  | { status: "none" }
  | { status: "open"; id: string; part: string; units: number }
  | { status: "released"; id: string; part: string; units: number; at: string }
  | { status: "scrapped"; id: string; reason: string };

export type ManufacturingLotCommand =
  | { type: "open"; id: string; part: string }
  | { type: "produce"; units: number }
  | { type: "release"; at: string }
  | { type: "scrap"; reason: string };

export type ManufacturingLotEvent =
  | { type: "LotOpened"; id: string; part: string }
  | { type: "LotProduced"; units: number }
  | { type: "LotReleased"; at: string; units: number }
  | { type: "LotScrapped"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const manufacturingLotDecider: Decider<ManufacturingLotCommand, ManufacturingLotEvent, ManufacturingLotState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "LotOpened", id: command.id, part: command.part }];
      case "produce":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (command.units <= 0) throw new DomainError("BAD_UNITS");
        return [{ type: "LotProduced", units: command.units }];
      case "release":
        if (state.status === "scrapped") throw new DomainError("SCRAPPED");
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (state.units <= 0) throw new DomainError("NO_UNITS");
        return [{ type: "LotReleased", at: command.at, units: state.units }];
      case "scrap":
        if (state.status === "scrapped") throw new DomainError("ALREADY");
        return [{ type: "LotScrapped", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "LotOpened":
        return { status: "open", id: event.id, part: event.part, units: 0 };
      case "LotProduced":
        if (state.status !== "open") return state;
        return { ...state, units: state.units + event.units };
      case "LotReleased":
        if (state.status !== "open") return state;
        return { status: "released", id: state.id, part: state.part, units: event.units, at: event.at };
      case "LotScrapped":
        return { status: "scrapped", id: "id" in state ? state.id : "", reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

```typescript
export type ChargeEvent =
  | { type: "ChargeAuthorized"; id: string; amount: number }
  | { type: "ChargeCaptured"; id: string; at: string };

export type ChargeState =
  | { status: "none" }
  | { status: "authorized"; id: string; amount: number }
  | { status: "captured"; id: string; amount: number; at: string };

export type ChargeCommand =
  | { type: "authorize"; id: string; amount: number }
  | { type: "capture"; at: string };

export class DomainError extends Error {}

export function evolve(s: ChargeState, e: ChargeEvent): ChargeState {
  switch (e.type) {
    case "ChargeAuthorized": return { status: "authorized", id: e.id, amount: e.amount };
    case "ChargeCaptured":
      if (s.status !== "authorized") return s;
      return { status: "captured", id: s.id, amount: s.amount, at: e.at };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: ChargeCommand, s: ChargeState): ChargeEvent[] {
  switch (c.type) {
    case "authorize":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ChargeAuthorized", id: c.id, amount: c.amount }];
    case "capture":
      if (s.status !== "authorized") throw new DomainError("NOT_AUTHORIZED");
      return [{ type: "ChargeCaptured", id: s.id, at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ChargeEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: ReadonlyArray<ChargeEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export type ChargeRow = Readonly<{ id: string; amount: number; status: "authorized" | "captured" }>;

export interface ReadStore {
  getCharge(id: string): Promise<ChargeRow | null>;
}

// write path
export async function handleCommand(
  store: EventStore,
  streamName: string,
  command: ChargeCommand,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, { status: "none" } as ChargeState);
  const produced = decide(command, state);
  if (produced.length === 0) return;
  await store.appendToStream(streamName, produced, { expectedRevision: revision ?? "no_stream" });
}

// read path (populated by a projection subscription, eventually consistent with the event store)
export async function queryView(reads: ReadStore, id: string): Promise<ChargeRow | null> {
  return reads.getCharge(id);
}
```

```typescript
export type ClaimEvent =
  | { type: "ClaimFiled"; id: string; amount: number }
  | { type: "ClaimApproved"; at: string };

export type ClaimState =
  | { status: "none" }
  | { status: "filed"; id: string; amount: number }
  | { status: "approved"; id: string; amount: number; at: string };

export function when(state: ClaimState, event: ClaimEvent): ClaimState {
  switch (event.type) {
    case "ClaimFiled":
      return { status: "filed", id: event.id, amount: event.amount };
    case "ClaimApproved":
      if (state.status !== "filed") return state;
      return { status: "approved", id: state.id, amount: state.amount, at: event.at };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let acc = initial;
  for await (const e of stream) acc = reducer(acc, e);
  return acc;
}

export async function hydrate(events: AsyncIterable<ClaimEvent>): Promise<ClaimState> {
  return aggregateStream<ClaimState, ClaimEvent>(events, when, { status: "none" });
}
