```typescript
import { Effect } from 'effect';

type ThreadEvent =
  | { type: 'ThreadOpened'; id: string; topic: string }
  | { type: 'ReplyPosted'; threadId: string; authorId: string };

interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

interface EventBus {
  readFrom(position: bigint | null): AsyncIterable<{ event: ThreadEvent; position: bigint }>;
}

interface Projection {
  apply(event: ThreadEvent): Promise<void>;
}

export function runThreadSubscription(
  name: string,
  checkpoints: CheckpointStore,
  bus: EventBus,
  projection: Projection,
) {
  return Effect.gen(function* () {
    const start = yield* Effect.promise(() => checkpoints.read(name));
    const iter = bus.readFrom(start);
    const consume = async (): Promise<void> => {
      for await (const { event, position } of iter) {
        await projection.apply(event);
        await checkpoints.write(name, position);
      }
    };
    yield* Effect.promise(() => consume());
  });
}
