```js
#!/usr/bin/env node
console.log('hello from my-tool');
```

`#!/usr/bin/env node` lets the OS pick up `node` from the user's PATH (works across nvm, brew, system installs). Make the file executable with `chmod +x ./bin/my-tool.js`. On publish, npm marks anything listed under `bin` as executable in the installed package.

```ts
import { z, ZodSchema } from 'zod';

export async function typedFetch<T>(
  url: string,
  schema: ZodSchema<T>,
  init?: RequestInit,
): Promise<T> {
  const res = await fetch(url, init);
  if (!res.ok) {
    throw new Error(`HTTP ${res.status} for ${url}`);
  }
  const body = await res.json();
  return schema.parse(body); // throws ZodError on mismatch
}
```

`ZodSchema<T>` flows the inferred type to the return. `parse` throws a `ZodError` on mismatch — the caller can catch it and inspect `err.issues` for field-level detail. Use `safeParse` if the caller prefers discriminated-union handling.

The `exporting` state invokes a `fromPromise` actor whose typed input receives the trim range and typed output is the blob url. `onDone` assigns the url into context, `onError` routes to a failure state so the UI can offer retry.

```typescript
import { setup, assign, fromPromise } from 'xstate';

const exportActor = fromPromise<{ url: string }, { inMs: number; outMs: number; src: string }>(
  async ({ input }) => {
    void input;
    return { url: 'blob://export-1' };
  }
);

interface Ctx { inMs: number; outMs: number; src: string; url: string | null; err: string | null }

type Ev = { type: 'EXPORT' } | { type: 'RESET' };

export const trimExporterMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { exportActor }
}).createMachine({
  id: 'trimExporter',
  context: { inMs: 0, outMs: 10_000, src: 'file.mp4', url: null, err: null },
  initial: 'ready',
  states: {
    ready: { on: { EXPORT: 'exporting' } },
    exporting: {
      invoke: {
        src: 'exportActor',
        input: ({ context }) => ({ inMs: context.inMs, outMs: context.outMs, src: context.src }),
        onDone: {
          target: 'done',
          actions: assign({ url: ({ event }) => event.output.url })
        },
        onError: {
          target: 'failed',
          actions: assign({ err: ({ event }) => String(event.error) })
        }
      }
    },
    done: { on: { RESET: 'ready' } },
    failed: { on: { RESET: 'ready' } }
  }
});
```

Convert this XState v4 fetch-with-timeout-and-retry machine to v5:

```js
const m = Machine({
  id: 'timed',
  initial: 'loading',
  context: { tries: 0, data: null },
  states: {
    loading: {
      invoke: {
        src: 'load',
        onDone: { target: 'ok', actions: assign({ data: (_, e) => e.data }) },
        onError: 'retry'
      },
      after: { 2000: 'retry' }
    },
    retry: {
      entry: assign({ tries: (c) => c.tries + 1 }),
      always: [
        { target: 'failed', cond: (c) => c.tries >= 3 },
        { target: 'loading' }
      ]
    },
    ok: { type: 'final' },
    failed: { type: 'final' }
  }
}, {
  services: { load: () => fetch('/x').then(r => r.json()) }
});
```

The `always` block with a `cond` becomes a guarded transition; the rest follows the v5 pattern — `fromPromise` actor, destructured assigns, `guard` replacing `cond`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Payload { readonly ok: boolean }

export const timedRetryMachine = setup({
  types: {
    context: {} as { tries: number; data: Payload | null },
    events: {} as { type: 'ABORT' }
  },
  guards: {
    outOfTries: ({ context }) => context.tries >= 3
  },
  actors: {
    load: fromPromise<Payload, void>(async () => {
      const r = await fetch('/x');
      return (await r.json()) as Payload;
    })
  }
}).createMachine({
  id: 'timed',
  initial: 'loading',
  context: { tries: 0, data: null },
  states: {
    loading: {
      invoke: {
        src: 'load',
        onDone:  { target: 'ok', actions: assign({ data: ({ event }) => event.output }) },
        onError: 'retry'
      },
      after: { 2000: 'retry' }
    },
    retry: {
      entry: assign({ tries: ({ context }) => context.tries + 1 }),
      always: [
        { target: 'failed', guard: 'outOfTries' },
        { target: 'loading' }
      ]
    },
    ok: { type: 'final' },
    failed: { type: 'final' }
  }
});
