Read the current stream revision, then append with `expectedRevision` set to that revision. If another writer won the race, the store will signal a wrong-revision error, which we convert into a typed `ConcurrencyConflict` for callers.

```typescript
export type RenewalEvent =
  | { type: "RenewalRequested"; id: string }
  | { type: "RenewalConfirmed"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {}

export async function appendRenewal(
  store: EventStore,
  stream: string,
  toAppend: RenewalEvent[],
): Promise<bigint> {
  const head = await store.readStream<RenewalEvent>(stream);
  try {
    const { nextRevision } = await store.appendToStream(stream, toAppend, {
      expectedRevision: head.revision,
    });
    return nextRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("WRONG_EXPECTED_REVISION")) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
```

