```typescript
export interface AppendOptions {
  expectedRevision: bigint | "no_stream" | "any";
}

export interface AppendResult {
  nextRevision: bigint;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], options: AppendOptions): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: AppendOptions["expectedRevision"]) {
    super(`CONCURRENCY_${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export type VariantEvent =
  | { type: "VariantRegistered"; id: string; key: string }
  | { type: "VariantTrafficAllocated"; percent: number };

export async function appendVariantEvents(
  store: EventStore,
  stream: string,
  events: VariantEvent[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<bigint> {
  try {
    const result = await store.appendToStream<VariantEvent>(stream, events, { expectedRevision });
    return result.nextRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("WrongExpectedVersion")) {
      throw new ConcurrencyConflict(stream, expectedRevision);
    }
    throw err;
  }
}
