```typescript
import { Effect } from "effect";

export type ApartmentState = { status: "none" } | { status: "listed"; id: string } | { status: "occupied"; id: string; by: string };
export type ApartmentCommand = { type: "list"; id: string } | { type: "occupy"; by: string };
export type ApartmentEvent = { type: "ApartmentListed"; id: string } | { type: "ApartmentOccupied"; by: string };

const initial: ApartmentState = { status: "none" };

function evolve(state: ApartmentState, event: ApartmentEvent): ApartmentState {
  switch (event.type) {
    case "ApartmentListed":
      return { status: "listed", id: event.id };
    case "ApartmentOccupied":
      if (state.status !== "listed") return state;
      return { status: "occupied", id: state.id, by: event.by };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(cmd: ApartmentCommand, state: ApartmentState): ApartmentEvent[] {
  switch (cmd.type) {
    case "list":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ApartmentListed", id: cmd.id }];
    case "occupy":
      if (state.status !== "listed") throw new Error("NOT_LISTED");
      return [{ type: "ApartmentOccupied", by: cmd.by }];
    default: {
      const _never: never = cmd;
      return _never;
    }
  }
}

interface EventStore<E> {
  readStream(s: string): Promise<{ data: E; revision: bigint }[]>;
  appendToStream(s: string, events: E[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export const handle = (
  store: EventStore<ApartmentEvent>,
  streamName: string,
  command: ApartmentCommand,
) =>
  Effect.gen(function* () {
    const stored = yield* Effect.promise(() => store.readStream(streamName));
    const state = stored.reduce<ApartmentState>((s, e) => evolve(s, e.data), initial);
    const events = decide(command, state);
    const expectedRevision: bigint | "no_stream" =
      stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
    yield* Effect.promise(() => store.appendToStream(streamName, events, { expectedRevision }));
  });
```

