```typescript
import { Effect } from "effect";

export type TreatmentEvent =
  | { type: "TreatmentAssigned"; treatmentId: string; subjectId: string }
  | { type: "TreatmentCompleted"; treatmentId: string; subjectId: string };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventEnvelope<E> { event: E; position: bigint; }

export interface EventStore<E> {
  readStream(from: bigint): AsyncIterable<EventEnvelope<E>>;
}

export class SubscriptionError { readonly _tag = "SubscriptionError"; constructor(readonly cause: unknown) {} }

export function runSubscription(
  name: string,
  store: EventStore<TreatmentEvent>,
  checkpoints: CheckpointStore,
  apply: (event: TreatmentEvent) => Promise<void>,
): Effect.Effect<void, SubscriptionError> {
  return Effect.gen(function* () {
    const last = yield* Effect.tryPromise({
      try: () => checkpoints.read(name),
      catch: (cause) => new SubscriptionError(cause),
    });
    const startFrom = last ?? 0n;
    yield* Effect.tryPromise({
      try: async () => {
        for await (const envelope of store.readStream(startFrom)) {
          await apply(envelope.event);
          await checkpoints.write(name, envelope.position);
        }
      },
      catch: (cause) => new SubscriptionError(cause),
    });
  });
}
```

