import { Effect } from "effect";

export type GoalEvent = { type: "GoalRecorded"; scorerId: string; matchId: string; minute: number };

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  appendToStream(stream: string, events: readonly GoalEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class GoalAppendError extends Error {
  constructor(public readonly stream: string) {
    super(`GOAL_APPEND_FAILED:${stream}`);
    this.name = "GoalAppendError";
  }
}

export function appendGoal(store: EventStore, stream: string, event: GoalEvent, expected: ExpectedRevision) {
  return Effect.gen(function* () {
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, [event], { expectedRevision: expected }),
      catch: () => new GoalAppendError(stream),
    });
    return result.nextRevision;
  });
}
```

```typescript
export type VideoProjectEvent =
  | { type: "VideoProjectCreated"; id: string; title: string }
  | { type: "VideoProjectArchived"; id: string; at: string };

export type IntegrationEvent =
  | { schema: "video.project.created.v1"; payload: { id: string; title: string } }
  | { schema: "video.project.archived.v1"; payload: { id: string; archivedAt: string } };

export interface OutboxRow {
  readonly id: string;
  readonly schema: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export function translate(event: VideoProjectEvent): IntegrationEvent | null {
  switch (event.type) {
    case "VideoProjectCreated":
      return { schema: "video.project.created.v1", payload: { id: event.id, title: event.title } };
    case "VideoProjectArchived":
      return { schema: "video.project.archived.v1", payload: { id: event.id, archivedAt: event.at } };
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface TxConnection<E> {
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export async function appendWithOutbox(
  tx: TxConnection<VideoProjectEvent>,
  streamName: string,
  events: readonly VideoProjectEvent[],
  expectedRevision: bigint | "no_stream" | "any",
  newOutboxId: () => string,
): Promise<bigint> {
  try {
    const rev = await tx.appendToStream(streamName, [...events], { expectedRevision });
    const rows: OutboxRow[] = [];
    for (const event of events) {
      const translated = translate(event);
      if (translated === null) continue;
      rows.push({
        id: newOutboxId(),
        schema: translated.schema,
        payload: JSON.stringify(translated.payload),
        publishedAt: null,
      });
    }
    if (rows.length > 0) await tx.insertOutbox(rows);
    await tx.commit();
    return rev;
  } catch (err) {
    await tx.rollback();
    throw err instanceof Error ? err : new Error(String(err));
  }
}
```

```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Comment = { id: string; body: string; status: 'pending' | 'confirmed' | 'failed' };

export const thread = setup({
  types: {
    context: {} as { comments: Comment[]; pendingId: string | null },
    events: {} as
      | { type: 'SEND'; body: string }
      | { type: 'RETRY' },
  },
  actors: {
    post: fromPromise<{ id: string }, { tempId: string; body: string }>(async ({ input }) => {
      const r = await fetch('/comments', {
        method: 'POST',
        body: JSON.stringify({ body: input.body }),
      });
      if (!r.ok) throw new Error('post failed');
      return r.json();
    }),
  },
}).createMachine({
  id: 'thread',
  initial: 'idle',
  context: { comments: [], pendingId: null },
  states: {
    idle: {
      on: {
        SEND: {
          target: 'posting',
          actions: assign({
            comments: ({ context, event }) => [
              ...context.comments,
              { id: `tmp-${Date.now()}`, body: event.body, status: 'pending' as const },
            ],
            pendingId: ({ context }) => `tmp-${Date.now()}`,
          }),
        },
      },
    },
    posting: {
      invoke: {
        src: 'post',
        input: ({ context }) => {
          const pending = context.comments.find((c) => c.id === context.pendingId);
          return { tempId: context.pendingId ?? '', body: pending?.body ?? '' };
        },
        onDone: {
          target: 'idle',
          actions: assign({
            comments: ({ context, event }) =>
              context.comments.map((c) =>
                c.id === context.pendingId
                  ? { ...c, id: event.output.id, status: 'confirmed' as const }
                  : c,
              ),
            pendingId: () => null,
          }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            comments: ({ context }) =>
              context.comments.map((c) =>
                c.id === context.pendingId ? { ...c, status: 'failed' as const } : c,
              ),
          }),
        },
      },
    },
    failed: {
      on: {
        RETRY: { target: 'posting' },
      },
    },
  },
});
