```typescript
export type LotState =
  | { status: "none" }
  | { status: "active"; id: string; sku: string; qty: number };

export type LotCommand =
  | { type: "create"; id: string; sku: string; qty: number }
  | { type: "consume"; qty: number };

export type LotEvent =
  | { type: "LotCreated"; id: string; sku: string; qty: number }
  | { type: "LotConsumed"; qty: number };

export class LotError extends Error {}

export const initialState: LotState = { status: "none" };

export function evolve(s: LotState, e: LotEvent): LotState {
  switch (e.type) {
    case "LotCreated": return { status: "active", id: e.id, sku: e.sku, qty: e.qty };
    case "LotConsumed":
      if (s.status !== "active") return s;
      return { ...s, qty: s.qty - e.qty };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: LotCommand, s: LotState): LotEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new LotError("EXISTS");
      return [{ type: "LotCreated", id: c.id, sku: c.sku, qty: c.qty }];
    case "consume":
      if (s.status !== "active") throw new LotError("NOT_ACTIVE");
      if (c.qty > s.qty) throw new LotError("INSUFFICIENT");
      return [{ type: "LotConsumed", qty: c.qty }];
    default: { const _n: never = c; throw new LotError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<LotEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<LotEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export async function handleLotCommand(
  streamName: string,
  command: LotCommand,
  store: EventStore,
): Promise<bigint> {
  const slice = await store.readStream(streamName);
  const state = slice.events.reduce(evolve, initialState);
  const out = decide(command, state);
  if (out.length === 0) return slice.revision ?? -1n;
  return store.appendToStream(streamName, out, { expectedRevision: slice.revision ?? "no_stream" });
}
```

Add a v2→v3 upgrade step to this League snapshot loader. v3 adds a `tierCount` number computed from the clubs map.

```typescript
export const CURRENT_VERSION = 2 as const;
interface LeagueV1 { id: string; clubs: string[] }
interface LeagueV2 { id: string; clubs: Record<string, number> }
```

```typescript
export interface Snapshot<S> {
  version: number;
  state: S;
}

export const CURRENT_VERSION = 3 as const;

export interface LeagueV1 { id: string; clubs: string[]; }
export interface LeagueV2 { id: string; clubs: Record<string, number>; }
export interface LeagueV3 { id: string; clubs: Record<string, number>; tierCount: number; }

export type CurrentState = LeagueV3;

function v1Tov2(snap: Snapshot<LeagueV1>): Snapshot<LeagueV2> {
  const clubs: Record<string, number> = {};
  for (const c of snap.state.clubs) clubs[c] = 1;
  return { version: 2, state: { id: snap.state.id, clubs } };
}

function v2Tov3(snap: Snapshot<LeagueV2>): Snapshot<LeagueV3> {
  const tierCount = new Set(Object.values(snap.state.clubs)).size;
  return { version: 3, state: { ...snap.state, tierCount } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentState> {
  let s: Snapshot<unknown> = raw;
  if (s.version === 1) s = v1Tov2(s as Snapshot<LeagueV1>);
  if (s.version === 2) s = v2Tov3(s as Snapshot<LeagueV2>);
  if (s.version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED:${s.version}`);
  return s as Snapshot<CurrentState>;
}

export function loadLeague(raw: unknown): CurrentState {
  if (typeof raw !== "object" || raw === null) throw new Error("INVALID");
  const snap = raw as Snapshot<unknown>;
  if (typeof snap.version !== "number") throw new Error("MISSING_VERSION");
  return upgradeSnapshot(snap).state;
}
```

