export type DispatchBeaconEvent =
  | { type: "DispatchBeaconArmed"; id: string }
  | { type: "DispatchBeaconPulsed"; id: string }
  | { type: "DispatchBeaconFired"; id: string; at: string };

export type RouteOptimisationEvent =
  | { type: "RoutePlanned"; id: string; stops: ReadonlyArray<string> }
  | { type: "RouteCompleted"; at: string };

export type RouteCommand =
  | { type: "planRoute"; routeId: string; beaconId: string }
  | { type: "completeRoute"; at: string };

export type SagaInput = DispatchBeaconEvent | RouteOptimisationEvent;

export function react(event: SagaInput): RouteCommand | null {
  switch (event.type) {
    case "DispatchBeaconArmed":
      return null;
    case "DispatchBeaconPulsed":
      return { type: "planRoute", routeId: `route-${event.id}`, beaconId: event.id };
    case "DispatchBeaconFired":
      return { type: "completeRoute", at: event.at };
    case "RoutePlanned":
      return null;
    case "RouteCompleted":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export function drainSaga(events: ReadonlyArray<SagaInput>): RouteCommand[] {
  const out: RouteCommand[] = [];
  for (const e of events) {
    const c = react(e);
    if (c !== null) out.push(c);
  }
  return out;
}

// Projection used by the saga subscriber to track how many commands were emitted.
export type SagaCounterView = Readonly<{ emitted: number }>;

export function project(view: SagaCounterView, event: SagaInput): SagaCounterView {
  const c = react(event);
  return c === null ? view : { emitted: view.emitted + 1 };
}
