export interface AppendResult {
  readonly nextExpectedRevision: bigint;
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: ReadonlyArray<E>; revision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<AppendResult & { ok: boolean }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export type CurationEvent =
  | { type: "CurationProposed"; id: string; curator: string }
  | { type: "CurationApproved"; by: string };

export async function appendCurationEvents(
  store: EventStore<CurationEvent>,
  stream: string,
  events: ReadonlyArray<CurationEvent>
): Promise<AppendResult> {
  const { revision } = await store.readStream(stream);
  const result = await store.appendToStream(stream, events, { expectedRevision: revision });
  if (!result.ok) {
    throw new ConcurrencyConflict(stream, revision);
  }
  return { nextExpectedRevision: result.nextExpectedRevision };
}
