export type FormularyEvent =
  | { type: "DrugListed"; code: string; name: string }
  | { type: "DrugDelisted"; code: string };

export interface StoredEvent<E> { readonly position: bigint; readonly event: E }
export interface EventStore<E> {
  readFromStream(stream: string, from: bigint, limit: number): Promise<StoredEvent<E>[]>;
}

export interface FormularyRow { readonly code: string; readonly name: string; readonly active: boolean }
export interface FormularyView { readonly drugs: Record<string, FormularyRow> }
export const emptyView: FormularyView = { drugs: {} };

export function project(v: FormularyView, e: FormularyEvent): FormularyView {
  switch (e.type) {
    case "DrugListed":
      return { drugs: { ...v.drugs, [e.code]: { code: e.code, name: e.name, active: true } } };
    case "DrugDelisted": {
      const row = v.drugs[e.code];
      if (!row) return v;
      return { drugs: { ...v.drugs, [e.code]: { ...row, active: false } } };
    }
    default: { const _never: never = e; return v; }
  }
}

export interface RebuildProgress { readonly cursor: bigint; readonly processed: number }

export interface RebuildOpts {
  readonly stream: string;
  readonly from: bigint;
  readonly batchSize: number;
  readonly persist: (view: FormularyView, cursor: bigint) => Promise<void>;
  readonly onProgress: (p: RebuildProgress) => void;
}

export async function rebuild(store: EventStore<FormularyEvent>, opts: RebuildOpts): Promise<void> {
  let cursor = opts.from;
  let processed = 0;
  let view: FormularyView = emptyView;
  while (true) {
    const batch = await store.readFromStream(opts.stream, cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const stored of batch) {
      view = project(view, stored.event);
      cursor = stored.position + 1n;
      processed++;
    }
    await opts.persist(view, cursor);
    opts.onProgress({ cursor, processed });
  }
}
