export interface DomainEvent {
  type: string;
  data: Record<string, unknown>;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  appendToStream(
    stream: string,
    events: DomainEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextExpectedRevision: bigint }>;
  readStream(stream: string): Promise<{ lastRevision: bigint | "no_stream" }>;
}

export class ConcurrencyConflict extends Error {
  constructor(stream: string, expected: ExpectedRevision) {
    super(`conflict on ${stream}, expected ${String(expected)}`);
  }
}

export async function appendWithOCC(
  store: EventStore,
  stream: string,
  events: DomainEvent[],
  expectedRevision: ExpectedRevision,
): Promise<bigint> {
  try {
    const res = await store.appendToStream(stream, events, {
      expectedRevision,
    });
    return res.nextExpectedRevision;
  } catch (err) {
    if (
      err instanceof Error &&
      /wrong.*(expected|revision|version)/i.test(err.message)
    ) {
      throw new ConcurrencyConflict(stream, expectedRevision);
    }
    throw err;
  }
}

export async function currentRevision(
  store: EventStore,
  stream: string,
): Promise<ExpectedRevision> {
  const { lastRevision } = await store.readStream(stream);
  return lastRevision === "no_stream" ? "no_stream" : lastRevision;
}
