export type PollingStationEvent =
  | { type: "StationOpened"; stationId: string; openedAt: string; position: bigint }
  | { type: "BallotCast"; stationId: string; position: bigint }
  | { type: "StationClosed"; stationId: string; closedAt: string; position: bigint };

export type StationView = Record<string, { ballots: number; open: boolean }>;
export const emptyView: StationView = {};

export function project(view: StationView, event: PollingStationEvent): StationView {
  switch (event.type) {
    case "StationOpened":
      return { ...view, [event.stationId]: { ballots: 0, open: true } };
    case "BallotCast": {
      const e = view[event.stationId] ?? { ballots: 0, open: true };
      return { ...view, [event.stationId]: { ...e, ballots: e.ballots + 1 } };
    }
    case "StationClosed": {
      const e = view[event.stationId] ?? { ballots: 0, open: true };
      return { ...view, [event.stationId]: { ...e, open: false } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventSource {
  readFrom(start: bigint): AsyncIterable<PollingStationEvent>;
}

export interface ViewStore {
  save(view: StationView): Promise<void>;
}

export async function runSubscription(
  name: string,
  checkpoints: CheckpointStore,
  source: EventSource,
  sink: ViewStore,
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? 0n;
  let view: StationView = emptyView;
  for await (const event of source.readFrom(start)) {
    view = project(view, event);
    await sink.save(view);
    await checkpoints.write(name, event.position);
  }
}
