export type FlightState =
  | { status: "none" }
  | { status: "scheduled"; id: string; gate: string; boarded: number }
  | { status: "boarding"; id: string; gate: string; boarded: number }
  | { status: "airborne"; id: string; boarded: number; departedAt: string };

export type FlightCommand =
  | { type: "schedule"; id: string; gate: string }
  | { type: "board"; pax: number }
  | { type: "takeoff"; at: string };

export type FlightEvent =
  | { type: "FlightScheduled"; id: string; gate: string }
  | { type: "PassengersBoarded"; pax: number }
  | { type: "FlightDeparted"; at: string };

export class FlightError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const flightDecider: Decider<FlightCommand, FlightEvent, FlightState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new FlightError("EXISTS");
        return [{ type: "FlightScheduled", id: command.id, gate: command.gate }];
      case "board":
        if (state.status === "airborne") throw new FlightError("ALREADY_DEPARTED");
        if (state.status === "none") throw new FlightError("NOT_SCHEDULED");
        if (command.pax <= 0) throw new FlightError("NO_PAX");
        return [{ type: "PassengersBoarded", pax: command.pax }];
      case "takeoff":
        if (state.status !== "boarding" && state.status !== "scheduled") throw new FlightError("NOT_READY");
        return [{ type: "FlightDeparted", at: command.at }];
      default: {
        const _n: never = command;
        throw new FlightError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FlightScheduled":
        return { status: "scheduled", id: event.id, gate: event.gate, boarded: 0 };
      case "PassengersBoarded":
        if (state.status === "none" || state.status === "airborne") return state;
        return { status: "boarding", id: state.id, gate: state.gate, boarded: state.boarded + event.pax };
      case "FlightDeparted":
        if (state.status === "none" || state.status === "airborne") return state;
        return { status: "airborne", id: state.id, boarded: state.boarded, departedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
