interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

interface StoredEvent<E> { data: E; revision: bigint }

interface Subscription<E> {
  [Symbol.asyncIterator](): AsyncIterator<StoredEvent<E>>;
}

interface EventStore<E> {
  subscribeFrom(stream: string, from: bigint): Subscription<E>;
}

export type BlockEvent = { type: "UnitOccupied"; unitId: string } | { type: "UnitVacated"; unitId: string };

export interface BlockView { occupied: number }

function project(view: BlockView, event: BlockEvent): BlockView {
  switch (event.type) {
    case "UnitOccupied":
      return { occupied: view.occupied + 1 };
    case "UnitVacated":
      return { occupied: Math.max(0, view.occupied - 1) };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

async function runSubscription(
  name: string,
  store: EventStore<BlockEvent>,
  checkpoints: CheckpointStore,
  persist: (v: BlockView) => Promise<void>,
): Promise<void> {
  const last = await checkpoints.read(name);
  const from = last ?? 0n;
  let view: BlockView = { occupied: 0 };
  const sub = store.subscribeFrom("building-events", from);
  for await (const stored of sub) {
    view = project(view, stored.data);
    await persist(view);
    await checkpoints.write(name, stored.revision);
  }
}

export { runSubscription };
```

A process manager is just a pure function from a domain event to zero or one commands. Keep it stateless when the outgoing command can be derived from the event alone; let the command handler enforce invariants. Events the saga does not care about return `null` instead of throwing, so the feed runner can keep moving. The thin dispatcher uses appendToStream with expectedRevision to emit the next command event.

```typescript
export type DomainEvent =
  | { type: "CodeReviewSubmitted"; prId: string; verdict: "approve" | "changes" }
  | { type: "BuildRunFinished"; commit: string }
  | { type: "FeatureBranchPushed"; name: string };

export type Command =
  | { type: "StartBuildRun"; prId: string }
  | { type: "TagCommitGreen"; commit: string };

export type CommandQueued =
  | { type: "StartBuildRunQueued"; prId: string }
  | { type: "TagCommitGreenQueued"; commit: string };

export function react(event: DomainEvent): Command | null {
  switch (event.type) {
    case "CodeReviewSubmitted":
      if (event.verdict !== "approve") return null;
      return { type: "StartBuildRun", prId: event.prId };
    case "BuildRunFinished":
      return { type: "TagCommitGreen", commit: event.commit };
    case "FeatureBranchPushed":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface EventStore {
  appendToStream(stream: string, events: CommandQueued[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function dispatch(store: EventStore, streamName: string, event: DomainEvent, revision: bigint | "no_stream"): Promise<void> {
  const cmd = react(event);
  if (!cmd) return;
  const queued: CommandQueued =
    cmd.type === "StartBuildRun"
      ? { type: "StartBuildRunQueued", prId: cmd.prId }
      : { type: "TagCommitGreenQueued", commit: cmd.commit };
  await store.appendToStream(streamName, [queued], { expectedRevision: revision });
}
```

```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type LotState = { status: "none" } | { status: "open"; id: string; units: number };
export type LotEvent = { type: "LotOpened"; id: string } | { type: "LotProduced"; units: number };

export function when(state: LotState, event: LotEvent): LotState {
  switch (event.type) {
    case "LotOpened": return { status: "open", id: event.id, units: 0 };
    case "LotProduced":
      if (state.status !== "open") return state;
      return { ...state, units: state.units + event.units };
    default: { const _n: never = event; return state; }
  }
}

export async function loadLot(stream: AsyncIterable<LotEvent>): Promise<LotState> {
  return aggregateStream(stream, when, { status: "none" });
}
```

A Season aggregate is a pure Decider: `initialState` is an empty marker, `decide` validates a command against the current state and emits events, and `evolve` folds those events back into state. Opening a season moves it from none to open; matches can only be scheduled while open; closing it freezes the set of matches and emits a champion. No I/O lives in the core.

```typescript
export type SeasonState =
  | { status: "none" }
  | { status: "open"; id: string; year: number; matches: string[] }
  | { status: "closed"; id: string; year: number; matches: string[]; champion: string };

export type SeasonCommand =
  | { type: "open"; id: string; year: number }
  | { type: "scheduleMatch"; matchId: string }
  | { type: "close"; champion: string };

export type SeasonEvent =
  | { type: "SeasonOpened"; id: string; year: number }
  | { type: "SeasonMatchScheduled"; matchId: string }
  | { type: "SeasonClosed"; champion: string };

export class SeasonError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const seasonDecider: Decider<SeasonCommand, SeasonEvent, SeasonState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "none") throw new SeasonError("ALREADY_OPEN");
        if (c.year < 1900) throw new SeasonError("INVALID_YEAR");
        return [{ type: "SeasonOpened", id: c.id, year: c.year }];
      case "scheduleMatch":
        if (s.status !== "open") throw new SeasonError("NOT_OPEN");
        if (s.matches.includes(c.matchId)) throw new SeasonError("DUPLICATE_MATCH");
        return [{ type: "SeasonMatchScheduled", matchId: c.matchId }];
      case "close":
        if (s.status !== "open") throw new SeasonError("NOT_OPEN");
        if (s.matches.length === 0) throw new SeasonError("NO_MATCHES");
        return [{ type: "SeasonClosed", champion: c.champion }];
      default: {
        const _never: never = c;
        throw new SeasonError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "SeasonOpened":
        return { status: "open", id: e.id, year: e.year, matches: [] };
      case "SeasonMatchScheduled":
        if (s.status !== "open") return s;
        return { ...s, matches: [...s.matches, e.matchId] };
      case "SeasonClosed":
        if (s.status !== "open") return s;
        return { status: "closed", id: s.id, year: s.year, matches: s.matches, champion: e.champion };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
