```typescript
export type ArtisanStudioCommand =
  | { type: "open"; id: string; owner: string }
  | { type: "admit"; member: string };

export type ArtisanStudioEvent =
  | { type: "StudioOpened"; id: string; owner: string }
  | { type: "StudioMemberAdmitted"; member: string };

type StudioState =
  | { status: "none" }
  | { status: "open"; id: string; members: number };

const initial: StudioState = { status: "none" };

function decide(c: ArtisanStudioCommand, s: StudioState): ArtisanStudioEvent[] {
  if (c.type === "open") {
    if (s.status === "open") throw new Error("open");
    return [{ type: "StudioOpened", id: c.id, owner: c.owner }];
  }
  if (s.status !== "open") throw new Error("closed");
  return [{ type: "StudioMemberAdmitted", member: c.member }];
}

function evolve(s: StudioState, e: ArtisanStudioEvent): StudioState {
  if (e.type === "StudioOpened") return { status: "open", id: e.id, members: 0 };
  return s.status === "open" ? { ...s, members: s.members + 1 } : s;
}

export interface EventStore {
  readStream(stream: string): Promise<{
    events: ArtisanStudioEvent[];
    lastRevision: bigint | "no_stream";
  }>;
  appendToStream(
    stream: string,
    events: ArtisanStudioEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export interface StudioView {
  id: string;
  owner: string;
  members: number;
}

export interface ReadStore {
  get(id: string): Promise<StudioView | null>;
}

// The read store is eventually consistent with the event store.
export async function handleCommand(
  command: ArtisanStudioCommand,
  ctx: { stream: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream(ctx.stream);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.stream, events, {
    expectedRevision: read.lastRevision,
  });
}

export async function queryView(
  reads: ReadStore,
  id: string,
): Promise<StudioView | null> {
  return reads.get(id);
}
