A snapshot carries a version tag plus the serialised state. On load, if the stored version is older than `CURRENT_VERSION`, successive upgraders run in order until the state matches the current schema. Writing is always at the current version.

```typescript
export type ReleaseStateV1 = { version: string; approved: boolean };
export type ReleaseStateV2 = { version: string; approved: boolean; approver: string | null };
export type ReleaseStateV3 = { version: string; approver: string | null; rolloutAt: string | null };

export type CurrentState = ReleaseStateV3;

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3;

function v1Tov2(s: ReleaseStateV1): ReleaseStateV2 {
  return { version: s.version, approved: s.approved, approver: null };
}

function v2Tov3(s: ReleaseStateV2): ReleaseStateV3 {
  return { version: s.version, approver: s.approver, rolloutAt: null };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v === 1) { state = v1Tov2(state as ReleaseStateV1); v = 2; }
  if (v === 2) { state = v2Tov3(state as ReleaseStateV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_SNAPSHOT_VERSION_${v}`);
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
