```typescript
export type TaskEvent =
  | { type: "TaskCreated"; id: string }
  | { type: "TaskAssigned"; assignee: string }
  | { type: "TaskCompleted"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: TaskEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: readonly TaskEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(stream: string) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

function looksLikeConflict(err: unknown): boolean {
  return err instanceof Error && /expected|revision|version/i.test(err.message);
}

export async function appendTaskEvents(
  store: EventStore,
  stream: string,
  buildEvents: (events: TaskEvent[]) => readonly TaskEvent[],
): Promise<bigint> {
  const { events, revision } = await store.readStream(stream);
  const newEvents = buildEvents(events);
  if (newEvents.length === 0) return revision ?? -1n;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  try {
    const result = await store.appendToStream(stream, newEvents, { expectedRevision });
    return result.nextExpectedRevision;
  } catch (err) {
    if (looksLikeConflict(err)) throw new ConcurrencyConflict(stream);
    throw err;
  }
}

export async function appendTaskEventsWithRetry(
  store: EventStore,
  stream: string,
  buildEvents: (events: TaskEvent[]) => readonly TaskEvent[],
): Promise<bigint> {
  try {
    return await appendTaskEvents(store, stream, buildEvents);
  } catch (err) {
    if (err instanceof ConcurrencyConflict) {
      return appendTaskEvents(store, stream, buildEvents);
    }
    throw err;
  }
}
