import { Effect } from "effect";

export type BaseCampEvent =
  | { type: "BaseCampPitched"; id: string; altitude: number }
  | { type: "OccupantCheckedIn" }
  | { type: "BaseCampStruck"; at: string };

export interface BaseCampState {
  readonly status: "none" | "pitched" | "struck";
  readonly id: string;
  readonly altitude: number;
  readonly occupants: number;
}

export const initialState: BaseCampState = { status: "none", id: "", altitude: 0, occupants: 0 };

export function evolve(state: BaseCampState, event: BaseCampEvent): BaseCampState {
  switch (event.type) {
    case "BaseCampPitched":
      return { status: "pitched", id: event.id, altitude: event.altitude, occupants: 0 };
    case "OccupantCheckedIn":
      return { ...state, occupants: state.occupants + 1 };
    case "BaseCampStruck":
      return { ...state, status: "struck" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolveFn: (state: S, event: E) => S,
  initial: S,
): Effect.Effect<S, Error> {
  return Effect.gen(function* () {
    let state = initial;
    const consume = async (): Promise<void> => {
      for await (const event of stream) {
        state = evolveFn(state, event);
      }
    };
    yield* Effect.promise(consume);
    return state;
  });
}
