export type SubscriptionState =
  | { status: "none" }
  | { status: "active"; id: string; plan: string; renewals: number }
  | { status: "cancelled"; id: string };

export type SubscriptionCommand =
  | { type: "subscribe"; id: string; plan: string }
  | { type: "renew" }
  | { type: "cancel"; reason: string };

export type SubscriptionEvent =
  | { type: "Subscribed"; id: string; plan: string }
  | { type: "Renewed" }
  | { type: "Cancelled"; reason: string };

export class SubscriptionError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const subscriptionDecider: Decider<SubscriptionCommand, SubscriptionEvent, SubscriptionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "subscribe":
        if (state.status !== "none") throw new SubscriptionError("EXISTS");
        if (command.plan.length === 0) throw new SubscriptionError("INVALID_PLAN");
        return [{ type: "Subscribed", id: command.id, plan: command.plan }];
      case "renew":
        if (state.status === "cancelled") throw new SubscriptionError("CANCELLED");
        if (state.status !== "active") throw new SubscriptionError("NOT_ACTIVE");
        return [{ type: "Renewed" }];
      case "cancel":
        if (state.status !== "active") throw new SubscriptionError("NOT_ACTIVE");
        return [{ type: "Cancelled", reason: command.reason }];
      default: { const _n: never = command; throw new SubscriptionError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Subscribed":
        return { status: "active", id: event.id, plan: event.plan, renewals: 0 };
      case "Renewed":
        if (state.status !== "active") return state;
        return { ...state, renewals: state.renewals + 1 };
      case "Cancelled":
        if (state.status !== "active") return state;
        return { status: "cancelled", id: state.id };
      default: { const _n: never = event; return state; }
    }
  },
};
