export type TrainingJobEvent =
  | { type: "TrainingJobSubmitted"; id: string }
  | { type: "TrainingJobCompleted"; metric: number };

export type TrainingJobView = { finished: number };
const empty: TrainingJobView = { finished: 0 };

function project(view: TrainingJobView, event: TrainingJobEvent): TrainingJobView {
  switch (event.type) {
    case "TrainingJobSubmitted":
      return view;
    case "TrainingJobCompleted":
      return { finished: view.finished + 1 };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface EventBatchReader<E> {
  readBatch(from: bigint, size: number): Promise<{ events: E[]; nextFrom: bigint | null }>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  reader: EventBatchReader<TrainingJobEvent>;
  persist: (view: TrainingJobView, cursor: bigint) => Promise<void>;
}): Promise<void> {
  let cursor = opts.from;
  let view: TrainingJobView = empty;
  let done = false;
  while (!done) {
    const { events, nextFrom } = await opts.reader.readBatch(cursor, opts.batchSize);
    for (const event of events) {
      view = project(view, event);
    }
    cursor = nextFrom ?? cursor;
    await opts.persist(view, cursor);
    if (nextFrom === null) done = true;
  }
}
