export type RemittanceEvent =
  | { type: "RemittanceInitiated"; id: string; amount: number; corridor: string }
  | { type: "RemittanceSettled"; id: string; at: string };

export type RemittanceState =
  | { status: "none" }
  | { status: "initiated"; id: string; amount: number; corridor: string }
  | { status: "settled"; id: string; amount: number; corridor: string; at: string };

export type RemittanceCommand =
  | { type: "initiate"; id: string; amount: number; corridor: string }
  | { type: "settle"; at: string };

export class DomainError extends Error {}

export function evolve(s: RemittanceState, e: RemittanceEvent): RemittanceState {
  switch (e.type) {
    case "RemittanceInitiated":
      return { status: "initiated", id: e.id, amount: e.amount, corridor: e.corridor };
    case "RemittanceSettled":
      if (s.status !== "initiated") return s;
      return { status: "settled", id: s.id, amount: s.amount, corridor: s.corridor, at: e.at };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: RemittanceCommand, s: RemittanceState): RemittanceEvent[] {
  switch (c.type) {
    case "initiate":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "RemittanceInitiated", id: c.id, amount: c.amount, corridor: c.corridor }];
    case "settle":
      if (s.status !== "initiated") throw new DomainError("NOT_INITIATED");
      return [{ type: "RemittanceSettled", id: s.id, at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(s: string): Promise<{ events: RemittanceEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: ReadonlyArray<RemittanceEvent>,
    o: { expectedRevision: bigint | "no_stream" },
  ): Promise<bigint>;
}

export type RemittanceStatusView = Readonly<{
  id: string;
  corridor: string;
  status: "initiated" | "settled";
}>;

export interface ReadStore {
  get(id: string): Promise<RemittanceStatusView | null>;
}

export async function handleCommand(
  store: EventStore,
  streamName: string,
  command: RemittanceCommand,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, { status: "none" } as RemittanceState);
  const produced = decide(command, state);
  if (produced.length === 0) return;
  await store.appendToStream(streamName, produced, { expectedRevision: revision ?? "no_stream" });
}

// the read store is populated asynchronously by a projection and is eventually consistent
export async function queryView(reads: ReadStore, id: string): Promise<RemittanceStatusView | null> {
  return reads.get(id);
}
