import { setup, assign, fromPromise } from 'xstate';

type Ctx = { queue: string[]; current: string | null; attempts: number };
type Ev =
  | { type: 'ENQUEUE'; file: string }
  | { type: 'START' }
  | { type: 'ABORT' };

export const uploadQueue = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    uploadOne: fromPromise(async ({ input }: { input: { file: string } }) => {
      await new Promise((r) => setTimeout(r, 50));
      if (input.file.startsWith('bad')) throw new Error('reject');
      return input.file;
    })
  },
  guards: {
    canRetry: ({ context }) => context.attempts < 3,
    hasNext: ({ context }) => context.queue.length > 0
  }
}).createMachine({
  id: 'upload-queue',
  initial: 'idle',
  context: { queue: [], current: null, attempts: 0 },
  states: {
    idle: {
      on: {
        ENQUEUE: {
          actions: assign({ queue: ({ context, event }) => context.queue.concat(event.file) })
        },
        START: { target: 'picking', guard: 'hasNext' }
      }
    },
    picking: {
      entry: assign({
        current: ({ context }) => context.queue[0] ?? null,
        queue: ({ context }) => context.queue.slice(1),
        attempts: 0
      }),
      always: 'uploading'
    },
    uploading: {
      invoke: {
        src: 'uploadOne',
        input: ({ context }) => ({ file: context.current ?? '' }),
        onDone: [
          { target: 'picking', guard: 'hasNext' },
          { target: 'done' }
        ],
        onError: [
          { target: 'uploading', guard: 'canRetry', reenter: true, actions: assign({ attempts: ({ context }) => context.attempts + 1 }) },
          { target: 'failed' }
        ]
      },
      on: { ABORT: 'idle' }
    },
    done: { on: { START: 'picking' } },
    failed: { on: { START: 'picking' } }
  }
});
