A projection is a pure function project(view, event) that folds only the events it cares about and leaves the view unchanged for events outside its interest.

```typescript
export type CandidateEvent =
  | { type: "Nominated"; id: string; name: string; party: string }
  | { type: "Verified"; at: string }
  | { type: "SteppedDown"; at: string }
  | { type: "VotesTallied"; id: string; delta: number };

export type Standings = {
  entries: Record<string, { name: string; party: string; status: "nominated" | "verified" | "stepped-down"; votes: number }>;
};

export const emptyStandings: Standings = { entries: {} };

export function project(view: Standings, event: CandidateEvent): Standings {
  switch (event.type) {
    case "Nominated":
      return { entries: { ...view.entries, [event.id]: { name: event.name, party: event.party, status: "nominated", votes: 0 } } };
    case "Verified": {
      const ids = Object.keys(view.entries);
      if (ids.length === 0) return view;
      const last = ids[ids.length - 1]!;
      const entry = view.entries[last]!;
      return { entries: { ...view.entries, [last]: { ...entry, status: "verified" } } };
    }
    case "SteppedDown": {
      const ids = Object.keys(view.entries);
      if (ids.length === 0) return view;
      const last = ids[ids.length - 1]!;
      const entry = view.entries[last]!;
      return { entries: { ...view.entries, [last]: { ...entry, status: "stepped-down" } } };
    }
    case "VotesTallied": {
      const entry = view.entries[event.id];
      if (!entry) return view;
      return { entries: { ...view.entries, [event.id]: { ...entry, votes: entry.votes + event.delta } } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}
```

The original handler mutates shared state. A proper command handler loads the stream, folds with a pure `evolve`, calls `decide` to produce events, and writes with `expectedRevision` for safe concurrency.

```typescript
type MessageCommand = { type: 'PostMessage'; id: string; body: string };
type MessageEvent = { type: 'MessagePosted'; id: string; body: string };
type MessageState = { status: 'draft' } | { status: 'live'; id: string };

const initialState: MessageState = { status: 'draft' };

function evolve(state: MessageState, event: MessageEvent): MessageState {
  switch (event.type) {
    case 'MessagePosted':
      return { status: 'live', id: event.id };
    default: {
      const _: never = event.type;
      return _;
    }
  }
}

function decide(command: MessageCommand, state: MessageState): MessageEvent[] {
  if (state.status !== 'draft') throw new Error('already posted');
  return [{ type: 'MessagePosted', id: command.id, body: command.body }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: MessageEvent; revision: bigint }>;
  appendToStream(
    s: string,
    events: readonly MessageEvent[],
    opts: { expectedRevision: bigint | 'no_stream' },
  ): Promise<void>;
}

export async function handlePostMessage(
  store: EventStore,
  streamName: string,
  command: MessageCommand,
): Promise<void> {
  let state = initialState;
  let expectedRevision: bigint | 'no_stream' = 'no_stream';
  for await (const { event, revision } of store.readStream(streamName)) {
    state = evolve(state, event);
    expectedRevision = revision;
  }
  await store.appendToStream(streamName, decide(command, state), { expectedRevision });
}
