The `debouncing` state hosts an `after` that transitions to `fetching`. `fetching` invokes the promise actor and surfaces suggestions through `onDone`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { query: string; suggestions: string[]; selected: string | null };
type Ev = { type: 'INPUT'; text: string } | { type: 'SELECT'; value: string };

const search = fromPromise<string[], { q: string }>(async ({ input }) => {
  if (!input.q) return [];
  return [`${input.q}-one`, `${input.q}-two`];
});

export const autocomplete = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { search },
}).createMachine({
  id: 'autocomplete',
  context: { query: '', suggestions: [], selected: null },
  initial: 'idle',
  states: {
    idle: {
      on: {
        INPUT: { target: 'debouncing', actions: assign({ query: ({ event }) => event.text }) },
      },
    },
    debouncing: {
      on: {
        INPUT: {
          target: 'debouncing',
          reenter: true,
          actions: assign({ query: ({ event }) => event.text }),
        },
      },
      after: { 250: 'fetching' },
    },
    fetching: {
      invoke: {
        src: 'search',
        input: ({ context }) => ({ q: context.query }),
        onDone: {
          target: 'idle',
          actions: assign({ suggestions: ({ event }) => event.output }),
        },
        onError: { target: 'idle' },
      },
      on: {
        INPUT: { target: 'debouncing', actions: assign({ query: ({ event }) => event.text }) },
      },
    },
  },
  on: {
    SELECT: { actions: assign({ selected: ({ event }) => event.value, suggestions: () => [] }) },
