export type EditSessionEvent =
  | { type: "EditSessionOpened"; id: string; editor: string }
  | { type: "EditSessionCutStaged" }
  | { type: "EditSessionCommitted"; at: string; totalCuts: number };

export type EditSessionState =
  | { status: "none" }
  | { status: "open"; id: string; editor: string; pendingCuts: number }
  | { status: "committed"; id: string; editor: string; totalCuts: number };

export const initialState: EditSessionState = { status: "none" };

export function evolve(state: EditSessionState, event: EditSessionEvent): EditSessionState {
  switch (event.type) {
    case "EditSessionOpened":
      return { status: "open", id: event.id, editor: event.editor, pendingCuts: 0 };
    case "EditSessionCutStaged":
      if (state.status !== "open") return state;
      return { ...state, pendingCuts: state.pendingCuts + 1 };
    case "EditSessionCommitted":
      if (state.status !== "open") return state;
      return { status: "committed", id: state.id, editor: state.editor, totalCuts: event.totalCuts };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export interface ReadResult<E> {
  readonly events: E[];
  readonly revision: bigint | "no_stream";
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export async function safeAppend(
  store: EventStore<EditSessionEvent>,
  streamName: string,
  produce: (state: EditSessionState) => EditSessionEvent[],
): Promise<bigint> {
  const loaded = await store.readStream(streamName);
  const state = loaded.events.reduce(evolve, initialState);
  const toAppend = produce(state);
  try {
    return await store.appendToStream(streamName, toAppend, { expectedRevision: loaded.revision });
  } catch (err) {
    throw new ConcurrencyConflict(streamName, loaded.revision);
  }
}
```

A Decider pairs three pure pieces: an `initialState` literal, a `decide(command, state)` that validates invariants and returns the resulting events, and an `evolve(state, event)` that folds events into new state. No I/O, no clocks, no randomness — every aggregate is a deterministic replay.

```typescript
export type AuctionRoomState =
  | { status: "closed" }
  | { status: "open"; id: string; highBid: number; highBidder: string | null };

export type AuctionRoomCommand =
  | { type: "open"; id: string; reservePrice: number }
  | { type: "bid"; bidder: string; amount: number }
  | { type: "close" };

export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; id: string; reservePrice: number }
  | { type: "BidPlaced"; bidder: string; amount: number }
  | { type: "AuctionRoomClosed" };

export class AuctionRoomError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "AuctionRoomError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const auctionRoomDecider: Decider<AuctionRoomCommand, AuctionRoomEvent, AuctionRoomState> = {
  initialState: { status: "closed" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status === "open") throw new AuctionRoomError("ALREADY_OPEN");
        return [{ type: "AuctionRoomOpened", id: command.id, reservePrice: command.reservePrice }];
      case "bid":
        if (state.status !== "open") throw new AuctionRoomError("NOT_OPEN");
        if (command.amount <= state.highBid) throw new AuctionRoomError("BID_TOO_LOW");
        return [{ type: "BidPlaced", bidder: command.bidder, amount: command.amount }];
      case "close":
        if (state.status !== "open") throw new AuctionRoomError("NOT_OPEN");
        return [{ type: "AuctionRoomClosed" }];
      default: {
        const _never: never = command;
        throw new AuctionRoomError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AuctionRoomOpened":
        return { status: "open", id: event.id, highBid: event.reservePrice, highBidder: null };
      case "BidPlaced":
        if (state.status !== "open") return state;
        return { status: "open", id: state.id, highBid: event.amount, highBidder: event.bidder };
      case "AuctionRoomClosed":
        return { status: "closed" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

Exiting a state with an `after` transition cancels its pending timer automatically. So a CANCEL event that targets `idle` from `polling` is enough — no manual `cancel(id)` needed for delayed transitions attached to states.

```typescript
