Each stroke is pushed onto a strokes array in context. An UNDO event pops the last stroke with assign. A guard prevents the pop when there are no strokes to undo, keeping the transition stable.

```typescript
import { setup, assign } from 'xstate';

interface Point { x: number; y: number }
interface Ctx { strokes: Point[][] }
type Ev = { type: 'ADD'; stroke: Point[] } | { type: 'UNDO' } | { type: 'CLEAR' };

export const undoablePad = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: { hasStrokes: ({ context }) => context.strokes.length > 0 }
}).createMachine({
  id: 'undoablePad',
  context: { strokes: [] },
  initial: 'ready',
  states: {
    ready: {
      on: {
        ADD: { actions: assign({ strokes: ({ context, event }) => [...context.strokes, event.stroke] }) },
        UNDO: { guard: 'hasStrokes', actions: assign({ strokes: ({ context }) => context.strokes.slice(0, -1) }) },
        CLEAR: { actions: assign({ strokes: () => [] }) }
      }
    }
  }
});
