  alpha: number;
  pValues: number[];
  verdict: "significant" | "not_significant" | "pending";
} {
  let alpha = 0;
  const pValues: number[] = [];
  let verdict: "significant" | "not_significant" | "pending" = "pending";
  for (const event of events) {
    switch (event.type) {
      case "SignificanceCheckStarted":
        alpha = event.alpha;
        break;
      case "SignificanceCheckPValueObserved":
        pValues.push(event.pValue);
        break;
      case "SignificanceCheckCompleted":
        verdict = event.verdict;
        break;
      default: {
        const _never: never = event;
      }
    }
  }
  return { alpha, pValues, verdict };
