export type PullRequestState = { status: "none" } | { status: "open"; id: string } | { status: "merged"; id: string };
export type PullRequestCommand = { type: "open"; id: string } | { type: "merge"; at: string };
export type PullRequestEvent = { type: "PullRequestOpened"; id: string } | { type: "PullRequestMerged"; at: string };

export const initialState: PullRequestState = { status: "none" };

export function evolve(state: PullRequestState, event: PullRequestEvent): PullRequestState {
  switch (event.type) {
    case "PullRequestOpened":
      return { status: "open", id: event.id };
    case "PullRequestMerged":
      if (state.status !== "open") return state;
      return { status: "merged", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(cmd: PullRequestCommand, state: PullRequestState): PullRequestEvent[] {
  switch (cmd.type) {
    case "open":
      if (state.status !== "none") throw new Error("ALREADY_OPEN");
      return [{ type: "PullRequestOpened", id: cmd.id }];
    case "merge":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "PullRequestMerged", at: cmd.at }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export interface CommandHandler<C> {
  handle(command: C, ctx: { streamName: string }): Promise<void>;
}

export function createHandler(store: EventStore<PullRequestEvent>): CommandHandler<PullRequestCommand> {
  return {
    async handle(command, ctx) {
      const loaded = await store.readStream(ctx.streamName);
      const state = loaded.events.reduce(evolve, initialState);
      const events = decide(command, state);
      await store.appendToStream(ctx.streamName, events, { expectedRevision: loaded.revision });
    },
  };
}
