The write uses one transaction for the domain append AND the outbox insert. A separate worker polls unpublished rows, publishes to a bus, and marks `publishedAt`. Without a single unit of work, you risk publishing events that were never stored (or storing without publishing).

```typescript
export type GeoFenceEvent =
  | { type: "GeoFenceDefined"; id: string; radiusM: number }
  | { type: "GeoFenceActivated"; at: string };

export interface OutboxRow {
  id: string;
  schema: string;
  payload: string;
  publishedAt: string | null;
}

export type ExpectedRevision = bigint | "no_stream";

export interface TxEventStore {
  appendToStream(
    stream: string,
    events: GeoFenceEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
  insertOutbox(rows: OutboxRow[]): Promise<void>;
}

export interface Transactional {
  run<T>(work: (tx: TxEventStore) => Promise<T>): Promise<T>;
}

// Publisher role (separate worker, not implemented here):
// poll outbox WHERE publishedAt IS NULL, dispatch each row to the message bus,
// then UPDATE outbox SET publishedAt = now() WHERE id = ?. Commits idempotently.
export async function appendWithOutbox(
  conn: Transactional,
  stream: string,
  events: GeoFenceEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: ExpectedRevision,
): Promise<bigint> {
  return conn.run(async (tx) => {
    const revision = await tx.appendToStream(stream, events, { expectedRevision });
    await tx.insertOutbox(outboxRows);
    return revision;
  });
}
