type Ev =
  | { type: 'UPLOAD' }
  | { type: 'PROGRESS'; pct: number }
  | { type: 'DONE'; url: string }
  | { type: 'FAIL'; reason: string }
  | { type: 'RESET' };

export const media = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    encode: fromCallback<Ev, void>(({ sendBack }) => {
      const h = setTimeout(() => sendBack({ type: 'DONE', url: 'blob://out' }), 500);
      return () => clearTimeout(h);
    })
  }
}).createMachine({
  id: 'media',
  initial: 'idle',
  context: { pct: 0, url: null, error: null },
  states: {
    idle: { on: { UPLOAD: { target: 'encoding', actions: assign({ pct: () => 0, url: () => null, error: () => null }) } } },
    encoding: {
      invoke: { src: 'encode' },
      on: {
        PROGRESS: { actions: assign({ pct: ({ event }) => event.pct }) },
        DONE: { target: 'ready', actions: assign({ url: ({ event }) => event.url, pct: () => 100 }) },
        FAIL: { target: 'failed', actions: assign({ error: ({ event }) => event.reason }) }
      }
    },
    ready: { on: { RESET: 'idle' } },
    failed: { on: { RESET: 'idle' } }
  }
});
