export type ProvisioningState =
  | { status: "none" }
  | { status: "gathering"; id: string; required: number; gathered: number }
  | { status: "finalised"; id: string; finalisedAt: string };

export type ProvisioningCommand =
  | { type: "open"; id: string; required: number }
  | { type: "record"; quantity: number }
  | { type: "finalise"; at: string };

export type ProvisioningEvent =
  | { type: "ProvisioningOpened"; id: string; required: number }
  | { type: "StockRecorded"; quantity: number }
  | { type: "ProvisioningFinalised"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const provisioningDecider: Decider<ProvisioningCommand, ProvisioningEvent, ProvisioningState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.required <= 0) throw new DomainError("BAD_REQUIRED");
        return [{ type: "ProvisioningOpened", id: command.id, required: command.required }];
      case "record":
        if (state.status !== "gathering") throw new DomainError("NOT_GATHERING");
        if (command.quantity <= 0) throw new DomainError("BAD_QUANTITY");
        return [{ type: "StockRecorded", quantity: command.quantity }];
      case "finalise":
        if (state.status !== "gathering") throw new DomainError("NOT_GATHERING");
        if (state.gathered < state.required) throw new DomainError("INCOMPLETE");
        return [{ type: "ProvisioningFinalised", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ProvisioningOpened":
        return { status: "gathering", id: event.id, required: event.required, gathered: 0 };
      case "StockRecorded":
        if (state.status !== "gathering") return state;
        return { ...state, gathered: state.gathered + event.quantity };
      case "ProvisioningFinalised":
        if (state.status !== "gathering") return state;
        return { status: "finalised", id: state.id, finalisedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
