```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type Command =
  | { type: 'Stake'; holder: string; region: string }
  | { type: 'Transfer'; to: string }
  | { type: 'Relinquish'; at: string };

type Event =
  | { type: 'ClaimStaked'; holder: string; region: string }
  | { type: 'ClaimTransferred'; from: string; to: string }
  | { type: 'ClaimRelinquished'; at: string };

type State =
  | { status: 'unstaked' }
  | { status: 'held'; holder: string; region: string }
  | { status: 'relinquished' };

class InvariantError extends Error {}

export const MineralClaim: Decider<Command, Event, State> = {
  initialState: { status: 'unstaked' },
  decide(command, state) {
    switch (command.type) {
      case 'Stake':
        if (state.status !== 'unstaked') throw new InvariantError('already staked');
        return [{ type: 'ClaimStaked', holder: command.holder, region: command.region }];
      case 'Transfer':
        if (state.status !== 'held') throw new InvariantError('cannot transfer');
        return [{ type: 'ClaimTransferred', from: state.holder, to: command.to }];
      case 'Relinquish':
        if (state.status !== 'held') throw new InvariantError('nothing to relinquish');
        return [{ type: 'ClaimRelinquished', at: command.at }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'ClaimStaked':
        return { status: 'held', holder: event.holder, region: event.region };
      case 'ClaimTransferred':
        return state.status === 'held' ? { ...state, holder: event.to } : state;
      case 'ClaimRelinquished':
        return { status: 'relinquished' };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
