export type CatalogEvent =
  | { type: "TitleAdded"; titleId: string; genre: string }
  | { type: "TitleRemoved"; titleId: string; genre: string }
  | { type: "TitleRenamed"; titleId: string; name: string }
  | { type: "CatalogPublished" };

export type CatalogView = Readonly<{
  titles: Record<string, { id: string; name: string; genre: string }>;
  totalsByGenre: Record<string, number>;
}>;

export const emptyView: CatalogView = { titles: {}, totalsByGenre: {} };

function bump(totals: Record<string, number>, genre: string, delta: number): Record<string, number> {
  const current = totals[genre] ?? 0;
  const next = current + delta;
  if (next <= 0) {
    const { [genre]: _drop, ...rest } = totals;
    return rest;
  }
  return { ...totals, [genre]: next };
}

export function project(view: CatalogView, event: CatalogEvent): CatalogView {
  switch (event.type) {
    case "TitleAdded":
      return {
        titles: { ...view.titles, [event.titleId]: { id: event.titleId, name: "", genre: event.genre } },
        totalsByGenre: bump(view.totalsByGenre, event.genre, +1),
      };
    case "TitleRemoved": {
      const { [event.titleId]: _removed, ...rest } = view.titles;
      return { titles: rest, totalsByGenre: bump(view.totalsByGenre, event.genre, -1) };
    }
    case "TitleRenamed": {
      const existing = view.titles[event.titleId];
      if (!existing) return view;
      return { ...view, titles: { ...view.titles, [event.titleId]: { ...existing, name: event.name } } };
    }
    case "CatalogPublished":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
