export type DisbursementState =
  | { status: "none" }
  | { status: "scheduled"; id: string; recipient: string; amount: number; dueAt: string }
  | { status: "executed"; id: string; recipient: string; amount: number; executedAt: string }
  | { status: "cancelled"; id: string; reason: string };

export type DisbursementCommand =
  | { type: "schedule"; id: string; recipient: string; amount: number; dueAt: string }
  | { type: "execute"; at: string }
  | { type: "cancel"; reason: string };

export type DisbursementEvent =
  | { type: "DisbursementScheduled"; id: string; recipient: string; amount: number; dueAt: string }
  | { type: "DisbursementExecuted"; at: string }
  | { type: "DisbursementCancelled"; reason: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const disbursementDecider: Decider<DisbursementCommand, DisbursementEvent, DisbursementState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.amount <= 0) throw new DomainError("INVALID_AMOUNT");
        return [{
          type: "DisbursementScheduled",
          id: command.id,
          recipient: command.recipient,
          amount: command.amount,
          dueAt: command.dueAt,
        }];
      case "execute":
        if (state.status === "cancelled") throw new DomainError("CANCELLED");
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "DisbursementExecuted", at: command.at }];
      case "cancel":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "DisbursementCancelled", reason: command.reason }];
      default: { const _n: never = command; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DisbursementScheduled":
        return {
          status: "scheduled",
          id: event.id,
          recipient: event.recipient,
          amount: event.amount,
          dueAt: event.dueAt,
        };
      case "DisbursementExecuted":
        if (state.status !== "scheduled") return state;
        return {
          status: "executed",
          id: state.id,
          recipient: state.recipient,
          amount: state.amount,
          executedAt: event.at,
        };
      case "DisbursementCancelled":
        if (state.status !== "scheduled") return state;
        return { status: "cancelled", id: state.id, reason: event.reason };
      default: { const _n: never = event; return state; }
    }
  },
};
