  switch (e.type) {
    case "ShiftClockedIn":
      return { ...s, staffId: e.staffId, workingSince: e.at, onBreak: false, endedAt: null };
    case "BreakStarted":
      return { ...s, onBreak: true };
    case "BreakEnded":
      return { ...s, onBreak: false, totalBreakMinutes: s.totalBreakMinutes + e.minutes };
    case "ShiftClockedOut":
      return { ...s, endedAt: e.at };
    default: {
      const _n: never = e;
      return s;
    }
  }
}

export function aggregate(events: StaffShiftEvent[]): StaffShiftState {
  return events.reduce(evolve, initial);
}
