```typescript
export type ChargeState =
  | { status: "none" }
  | { status: "authorized"; id: string; amount: number }
  | { status: "captured"; id: string; amount: number; capturedAt: string };

export type ChargeCommand =
  | { type: "authorize"; id: string; amount: number }
  | { type: "capture"; at: string };

export type ChargeEvent =
  | { type: "ChargeAuthorized"; id: string; amount: number }
  | { type: "ChargeCaptured"; at: string };

export class DomainError extends Error {}

export const initialState: ChargeState = { status: "none" };

export function evolve(s: ChargeState, e: ChargeEvent): ChargeState {
  switch (e.type) {
    case "ChargeAuthorized": return { status: "authorized", id: e.id, amount: e.amount };
    case "ChargeCaptured":
      if (s.status !== "authorized") return s;
      return { status: "captured", id: s.id, amount: s.amount, capturedAt: e.at };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: ChargeCommand, s: ChargeState): ChargeEvent[] {
  switch (c.type) {
    case "authorize":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ChargeAuthorized", id: c.id, amount: c.amount }];
    case "capture":
      if (s.status !== "authorized") throw new DomainError("NOT_AUTHORIZED");
      return [{ type: "ChargeCaptured", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ChargeEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: ReadonlyArray<ChargeEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export interface CommandHandler<C> {
  handle(streamName: string, command: C): Promise<void>;
}

export function makeChargeHandler(store: EventStore): CommandHandler<ChargeCommand> {
  return {
    async handle(streamName, command) {
      const { events, revision } = await store.readStream(streamName);
      const state = events.reduce(evolve, initialState);
      const produced = decide(command, state);
      if (produced.length === 0) return;
      const expectedRevision: ExpectedRevision = revision ?? "no_stream";
      await store.appendToStream(streamName, produced, { expectedRevision });
    },
  };
}
