import { setup, assign } from 'xstate';

interface Line { readonly sku: string; readonly qty: number }
interface CartCtx { readonly lines: ReadonlyArray<Line> }

type CartEvent =
  | { type: 'ADD';    sku: string; qty: number }
  | { type: 'REMOVE'; sku: string }
  | { type: 'CLEAR' };

