Tag every stored event with a version. At read time, upcast pattern-matches on (type, version) and rewrites older shapes into the current discriminated union. Only the upcast function knows about old shapes; the domain model never sees them.

```typescript
export type CurrentAOEvent =
  | { type: "Placed"; version: 2; id: string; vendorId: string; on: string }
  | { type: "Received"; version: 1; id: string; on: string };

type RawPlacedV1 = { type: "Placed"; version: 1; id: string; vendor: string; on: string };
type RawPlacedV2 = { type: "Placed"; version: 2; id: string; vendorId: string; on: string };
type RawReceivedV1 = { type: "Received"; version: 1; id: string; on: string };
type RawEvent = RawPlacedV1 | RawPlacedV2 | RawReceivedV1;

export class UnknownEventError extends Error {}

function parseRaw(raw: unknown): RawEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError("not object");
  return raw as RawEvent;
}

export function upcast(raw: unknown): CurrentAOEvent {
  const r = parseRaw(raw);
  switch (r.type) {
    case "Placed":
      if (r.version === 1) return { type: "Placed", version: 2, id: r.id, vendorId: r.vendor, on: r.on };
      return { type: "Placed", version: 2, id: r.id, vendorId: r.vendorId, on: r.on };
    case "Received":
      return { type: "Received", version: 1, id: r.id, on: r.on };
    default: {
      const _: never = r;
      throw new UnknownEventError("unknown event");
    }
  }
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<unknown>;
}

export async function loadUpcasted(store: EventStore, streamName: string): Promise<CurrentAOEvent[]> {
  const events: CurrentAOEvent[] = [];
  for await (const raw of store.readStream(streamName)) {
    events.push(upcast(raw));
  }
  return events;
}
```

```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

