export type CutListEvent =
  | { type: "CutListOpened"; id: string; projectId: string }
  | { type: "CutListCutAppended"; editor: string; durationMs: number }
  | { type: "CutListLocked"; at: string };

export interface CutListSummary {
  readonly id: string;
  readonly projectId: string;
  readonly totalCuts: number;
  readonly totalDurationMs: number;
  readonly locked: boolean;
}

export const emptySummary: CutListSummary = {
  id: "",
  projectId: "",
  totalCuts: 0,
  totalDurationMs: 0,
  locked: false,
};

export function project(view: CutListSummary, event: CutListEvent): CutListSummary {
  switch (event.type) {
    case "CutListOpened":
      return { ...emptySummary, id: event.id, projectId: event.projectId };
    case "CutListCutAppended":
      return { ...view, totalCuts: view.totalCuts + 1, totalDurationMs: view.totalDurationMs + event.durationMs };
    case "CutListLocked":
      return { ...view, locked: true };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface Batch {
  readonly events: readonly CutListEvent[];
  readonly nextRevision: bigint;
  readonly endOfStream: boolean;
}

export interface RebuildArgs {
  from: bigint;
  batchSize: number;
  read: (from: bigint, batchSize: number) => Promise<Batch>;
  persist: (view: CutListSummary, position: bigint) => Promise<void>;
}

export async function rebuild(args: RebuildArgs): Promise<void> {
  let cursor = args.from;
  let view = emptySummary;
  while (true) {
    const batch = await args.read(cursor, args.batchSize);
    for (const event of batch.events) {
      view = project(view, event);
    }
    await args.persist(view, batch.nextRevision);
    cursor = batch.nextRevision;
    if (batch.endOfStream) break;
  }
}
