export interface ReadStore {
  findByClub(club: string): Promise<StandingsRow | null>;
}

export async function handleCommand(store: EventStore, stream: string, cmd: MatchCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<MatchState>((s, { event }) => evolve(s, event), initialMatch);
  const expected = stored.length === 0 ? "no_stream" as const : stored[stored.length - 1]!.revision;
  const events = decide(cmd, state);
  await store.appendToStream(stream, events, { expectedRevision: expected });
}

// The read store is eventually consistent with the event store: a projector updates it asynchronously.
export async function queryView(reads: ReadStore, club: string): Promise<StandingsRow | null> {
  return reads.findByClub(club);
}
