  | { type: "PatientAdmitted"; id: string; ward: string; at: string }
  | { type: "PatientDischarged"; id: string; at: string };

export interface StoredEvent<E> { readonly position: bigint; readonly event: E }
export interface EventStore<E> {
  readFromStream(stream: string, from: bigint, limit: number): Promise<StoredEvent<E>[]>;
}

export interface AdmissionRow { readonly id: string; readonly ward: string | null; readonly mrn: string }
export interface AdmissionsView { readonly rows: Record<string, AdmissionRow> }
export const emptyView: AdmissionsView = { rows: {} };

export function project(view: AdmissionsView, event: PatientEvent): AdmissionsView {
  switch (event.type) {
    case "PatientRegistered":
      return { rows: { ...view.rows, [event.id]: { id: event.id, mrn: event.mrn, ward: null } } };
    case "PatientAdmitted": {
      const row = view.rows[event.id];
      if (!row) return view;
      return { rows: { ...view.rows, [event.id]: { ...row, ward: event.ward } } };
    }
    case "PatientDischarged": {
      const row = view.rows[event.id];
      if (!row) return view;
      return { rows: { ...view.rows, [event.id]: { ...row, ward: null } } };
    }
    default: { const _never: never = event; return view; }
  }
}

export interface RebuildOpts {
  readonly stream: string;
  readonly from: bigint;
  readonly batchSize: number;
  readonly persist: (view: AdmissionsView, cursor: bigint) => Promise<void>;
}

export async function rebuild(store: EventStore<PatientEvent>, opts: RebuildOpts): Promise<void> {
  let cursor = opts.from;
  let view: AdmissionsView = emptyView;
  while (true) {
    const batch = await store.readFromStream(opts.stream, cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const stored of batch) {
      view = project(view, stored.event);
      cursor = stored.position + 1n;
    }
    await opts.persist(view, cursor);
  }
}
