export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S
): Promise<S> {
  let state = initial;
  for await (const event of events) {
    state = evolve(state, event);
  }
  return state;
}

export interface Farm {
  readonly id: string;
  readonly owner: string;
  readonly activeCrops: number;
}

export type FarmEvent =
  | { type: "FarmRegistered"; id: string; owner: string }
  | { type: "FarmCropStarted" }
  | { type: "FarmCropEnded" };

const emptyFarm: Farm = { id: "", owner: "", activeCrops: 0 };

function evolve(state: Farm, event: FarmEvent): Farm {
  switch (event.type) {
    case "FarmRegistered":
      return { id: event.id, owner: event.owner, activeCrops: 0 };
    case "FarmCropStarted":
      return { ...state, activeCrops: state.activeCrops + 1 };
    case "FarmCropEnded":
      return { ...state, activeCrops: Math.max(0, state.activeCrops - 1) };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function loadFarm(events: AsyncIterable<FarmEvent>): Promise<Farm> {
  return aggregateStream(events, evolve, emptyFarm);
}
