import { z, ZodSchema } from 'zod';

export async function typedFetch<T>(
  url: string,
  schema: ZodSchema<T>,
  init?: RequestInit,
): Promise<T> {
  const res = await fetch(url, init);
  if (!res.ok) {
    throw new Error(`HTTP ${res.status} for ${url}`);
  }
  const body = await res.json();
  return schema.parse(body); // throws ZodError on mismatch
}
```

`ZodSchema<T>` flows the inferred type to the return. `parse` throws a `ZodError` on mismatch — the caller can catch it and inspect `err.issues` for field-level detail. Use `safeParse` if the caller prefers discriminated-union handling.

```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
export type AdvertisementEvent =
  | { type: "AdvertisementSubmitted"; id: string; headline: string }
  | { type: "AdvertisementApproved"; at: string };

export interface AdvertisementState {
  readonly id: string;
  readonly approved: boolean;
}

export const initialAd: AdvertisementState = { id: "", approved: false };

export function evolve(state: AdvertisementState, event: AdvertisementEvent): AdvertisementState {
  switch (event.type) {
    case "AdvertisementSubmitted":
      return { id: event.id, approved: false };
    case "AdvertisementApproved":
      return { ...state, approved: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent {
  readonly revision: bigint;
  readonly event: AdvertisementEvent;
}

export interface EventStore {
  readStream(stream: string): Promise<readonly StoredEvent[]>;
  appendToStream(
    stream: string,
    events: readonly AdvertisementEvent[],
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`Concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function approveAdvertisement(
  store: EventStore,
  stream: string,
  at: string,
): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<AdvertisementState>((s, { event }) => evolve(s, event), initialAd);
  if (state.approved) return;
  const lastRevision: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  const event: AdvertisementEvent = { type: "AdvertisementApproved", at };
  try {
    await store.appendToStream(stream, [event], { expectedRevision: lastRevision });
  } catch (err) {
    if ((err as { code?: string }).code === "WRONG_EXPECTED_REVISION") {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
