export type RenewalCommand = { type: "request"; id: string; term: number };
export type RenewalEvent = { type: "RenewalRequested"; id: string; term: number };
export type RenewalState = { status: "none" } | { status: "requested"; id: string };
export type RenewalView = { id: string; term: number; state: "pending" | "confirmed" };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export interface ReadStore {
  get(id: string): Promise<RenewalView | null>;
}

const initial: RenewalState = { status: "none" };

function evolve(s: RenewalState, e: RenewalEvent): RenewalState {
  switch (e.type) {
    case "RenewalRequested": return { status: "requested", id: e.id };
    default: { const _n: never = e.type; return s; }
  }
}

function decide(c: RenewalCommand, s: RenewalState): RenewalEvent[] {
  switch (c.type) {
    case "request":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "RenewalRequested", id: c.id, term: c.term }];
    default: { const _n: never = c.type; throw new Error("UNKNOWN"); }
  }
}

// Note: read model is eventually consistent with the event store.
export async function handleCommand(cmd: RenewalCommand, stream: string, store: EventStore): Promise<void> {
  const { events, revision } = await store.readStream<RenewalEvent>(stream);
  const state = events.reduce<RenewalState>(evolve, initial);
  const next = decide(cmd, state);
  await store.appendToStream<RenewalEvent>(stream, next, { expectedRevision: revision });
}

export async function queryView(id: string, reads: ReadStore): Promise<RenewalView | null> {
  return reads.get(id);
}
