export type AssetState =
  | { status: "none" }
  | { status: "active"; id: string; value: number };

export type AssetCommand =
  | { type: "register"; id: string; value: number }
  | { type: "revalue"; value: number };

export type AssetEvent =
  | { type: "AssetRegistered"; id: string; value: number }
  | { type: "AssetRevalued"; value: number };

export class AssetError extends Error {}

export const initialState: AssetState = { status: "none" };

export function decide(c: AssetCommand, s: AssetState): AssetEvent[] {
  switch (c.type) {
    case "register":
      if (s.status !== "none") throw new AssetError("EXISTS");
      return [{ type: "AssetRegistered", id: c.id, value: c.value }];
    case "revalue":
      if (s.status !== "active") throw new AssetError("NOT_ACTIVE");
      return [{ type: "AssetRevalued", value: c.value }];
    default: { const _n: never = c; throw new AssetError("UNKNOWN"); }
  }
}

export function evolve(s: AssetState, e: AssetEvent): AssetState {
  switch (e.type) {
    case "AssetRegistered":
      return { status: "active", id: e.id, value: e.value };
    case "AssetRevalued":
      if (s.status !== "active") return s;
      return { ...s, value: e.value };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ revision: bigint; events: AssetEvent[] }>;
  appendToStream(
    stream: string,
    events: AssetEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export async function handleAssetCommand(
  command: AssetCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const { revision, events } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce<AssetState>(evolve, initialState);
  const produced = decide(command, state);
  const expectedRevision: bigint | "no_stream" = events.length === 0 ? "no_stream" : revision;
  await ctx.eventStore.appendToStream(ctx.streamName, produced, { expectedRevision });
}

