  save(view: ReceiptView): Promise<void>;
}

export async function runSubscription(
  name: string,
  stream: string,
  ctx: { events: EventStore; checkpoints: CheckpointStore; views: ViewStore }
): Promise<void> {
  const start = await ctx.checkpoints.read(name);
  let view: ReceiptView = emptyView;
  for await (const { revision, event } of ctx.events.readFrom(stream, start)) {
    view = project(view, event);
    await ctx.views.save(view);
    await ctx.checkpoints.write(name, revision);
  }
}
