export type RolloutState =
  | { status: "draft" }
  | { status: "active"; id: string; stage: number; total: number }
  | { status: "halted"; id: string; haltedAt: string };

export type RolloutCommand =
  | { type: "plan"; id: string; total: number }
  | { type: "advance" }
  | { type: "halt"; at: string; reason: string };

export type RolloutEvent =
  | { type: "RolloutPlanned"; id: string; total: number }
  | { type: "RolloutAdvanced"; stage: number }
  | { type: "RolloutHalted"; at: string; reason: string };

export class RolloutError extends Error {
  constructor(code: string) { super(code); this.name = "RolloutError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const rolloutDecider: Decider<RolloutCommand, RolloutEvent, RolloutState> = {
  initialState: { status: "draft" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "draft") throw new RolloutError("ALREADY_PLANNED");
        if (command.total <= 0) throw new RolloutError("BAD_TOTAL");
        return [{ type: "RolloutPlanned", id: command.id, total: command.total }];
      case "advance":
        if (state.status !== "active") throw new RolloutError("NOT_ACTIVE");
        if (state.stage + 1 > state.total) throw new RolloutError("PAST_LAST_STAGE");
        return [{ type: "RolloutAdvanced", stage: state.stage + 1 }];
      case "halt":
        if (state.status !== "active") throw new RolloutError("NOT_ACTIVE");
        return [{ type: "RolloutHalted", at: command.at, reason: command.reason }];
      default: {
        const _never: never = command;
        throw new RolloutError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RolloutPlanned":
        return { status: "active", id: event.id, stage: 0, total: event.total };
      case "RolloutAdvanced":
        if (state.status !== "active") return state;
        return { ...state, stage: event.stage };
      case "RolloutHalted":
        if (state.status !== "active") return state;
        return { status: "halted", id: state.id, haltedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

