export type IRBApprovalState =
  | { status: "none" }
  | { status: "pending"; id: string; studyId: string }
  | { status: "approved"; id: string; studyId: string; expiresAt: string; amendments: number }
  | { status: "expired"; id: string; expiredAt: string };

export type IRBApprovalCommand =
  | { type: "submit"; id: string; studyId: string }
  | { type: "approve"; expiresAt: string }
  | { type: "amend"; summary: string }
  | { type: "expire"; at: string };

export type IRBApprovalEvent =
  | { type: "IRBApprovalSubmitted"; id: string; studyId: string }
  | { type: "IRBApprovalGranted"; expiresAt: string }
  | { type: "IRBApprovalAmended"; summary: string }
  | { type: "IRBApprovalExpired"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const irbApprovalDecider: Decider<IRBApprovalCommand, IRBApprovalEvent, IRBApprovalState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "submit":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "IRBApprovalSubmitted", id: command.id, studyId: command.studyId }];
      case "approve":
        if (state.status !== "pending") throw new DomainError("NOT_PENDING");
        return [{ type: "IRBApprovalGranted", expiresAt: command.expiresAt }];
      case "amend":
        if (state.status === "expired") throw new DomainError("EXPIRED");
        if (state.status !== "approved") throw new DomainError("NOT_APPROVED");
        return [{ type: "IRBApprovalAmended", summary: command.summary }];
      case "expire":
        if (state.status !== "approved") throw new DomainError("NOT_APPROVED");
        return [{ type: "IRBApprovalExpired", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "IRBApprovalSubmitted":
        return { status: "pending", id: event.id, studyId: event.studyId };
      case "IRBApprovalGranted":
        if (state.status !== "pending") return state;
        return { status: "approved", id: state.id, studyId: state.studyId, expiresAt: event.expiresAt, amendments: 0 };
      case "IRBApprovalAmended":
        if (state.status !== "approved") return state;
        return { ...state, amendments: state.amendments + 1 };
      case "IRBApprovalExpired":
        if (state.status !== "approved") return state;
        return { status: "expired", id: state.id, expiredAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
