`#!/usr/bin/env node` lets the OS pick up `node` from the user's PATH (works across nvm, brew, system installs). Make the file executable with `chmod +x ./bin/my-tool.js`. On publish, npm marks anything listed under `bin` as executable in the installed package.

A reconnect loop models transient disconnects as a dedicated `reconnecting` state that retries a `fromPromise` actor until it succeeds or exhausts a retry budget tracked in context. A guard gates whether another attempt is allowed, and `onDone` / `onError` route back to `inCall` or to `failed`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { retries: number; max: number };
type Ev = { type: 'DISCONNECT' } | { type: 'HANG_UP' };

declare const rtc: { reconnect: () => Promise<void> };

export const reconnectMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    reconnect: fromPromise<void, void>(() => rtc.reconnect())
  },
  guards: {
    canRetry: ({ context }) => context.retries < context.max
  }
}).createMachine({
  id: 'reconnect',
  initial: 'inCall',
  context: { retries: 0, max: 3 },
  states: {
    inCall: {
      on: { DISCONNECT: 'reconnecting', HANG_UP: 'ended' }
    },
    reconnecting: {
      entry: assign({ retries: ({ context }) => context.retries + 1 }),
      invoke: {
        src: 'reconnect',
        onDone: { target: 'inCall', actions: assign({ retries: () => 0 }) },
        onError: [
          { target: 'reconnecting', guard: 'canRetry', reenter: true },
          { target: 'ended' }
        ]
      }
    },
    ended: { type: 'final' }
  }
});
```

