A snapshot is a persisted aggregate state tagged with the schema version that produced it. On load, the service inspects the tag; when it is lower than the current version, upgrader functions run in order (v1Tov2, then v2Tov3) until the snapshot matches the current schema. Old streams stay intact; callers always see the current shape.

```typescript
type PlaylistV1 = { readonly id: string; readonly songs: readonly string[] };
type PlaylistV2 = PlaylistV1 & { readonly owner: string };
type PlaylistV3 = PlaylistV2 & { readonly isPublic: boolean };

export type CurrentState = PlaylistV3;
export const CURRENT_VERSION = 3 as const;

export type Snapshot<S> = { readonly version: number; readonly state: S };

function v1Tov2(prev: PlaylistV1): PlaylistV2 {
  return { ...prev, owner: 'unknown' };
}

function v2Tov3(prev: PlaylistV2): PlaylistV3 {
  return { ...prev, isPublic: false };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as PlaylistV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as PlaylistV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`unknown version ${version}`);
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
```

