```typescript
export type DomainEvent =
  | { type: "ReservationCreated"; id: string; guests: number }
  | { type: "ReservationConfirmed"; id: string; at: string }
  | { type: "ReservationCancelled"; id: string; reason: string }
  | { type: "ReservationArchived"; id: string };

export type IntegrationEvent =
  | { schema: "reservation.confirmed.v1"; payload: { reservationId: string; confirmedAt: string } }
  | { schema: "reservation.cancelled.v1"; payload: { reservationId: string; reason: string } };

export function translate(event: DomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "ReservationConfirmed":
      return {
        schema: "reservation.confirmed.v1",
        payload: { reservationId: event.id, confirmedAt: event.at },
      };
    case "ReservationCancelled":
      return {
        schema: "reservation.cancelled.v1",
        payload: { reservationId: event.id, reason: event.reason },
      };
    case "ReservationCreated":
    case "ReservationArchived":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export type OutboxView = Readonly<{ pending: ReadonlyArray<IntegrationEvent> }>;

export const emptyOutbox: OutboxView = { pending: [] };

export function project(view: OutboxView, event: DomainEvent): OutboxView {
  const translated = translate(event);
  if (translated === null) return view;
  return { pending: [...view.pending, translated] };
}

export function outboxFrom(events: DomainEvent[]): OutboxView {
  return events.reduce(project, emptyOutbox);
}
