A Decider for HoldoutGroup keeps the domain rules pure: `decide` validates the command against current state and returns events; `evolve` folds those events back into state. All I/O lives outside this core, so the rules stay deterministic and unit-testable.

```typescript
export type HoldoutGroupState =
  | { status: "none" }
  | { status: "registered"; id: string; size: number }
  | { status: "open"; id: string; size: number; openedAt: string }
  | { status: "closed"; id: string; size: number; closedAt: string };

export type HoldoutGroupCommand =
  | { type: "register"; id: string; size: number }
  | { type: "open"; at: string }
  | { type: "close"; at: string };

export type HoldoutGroupEvent =
  | { type: "HoldoutGroupRegistered"; id: string; size: number }
  | { type: "HoldoutGroupOpened"; at: string }
  | { type: "HoldoutGroupClosed"; at: string };

export class HoldoutGroupError extends Error {
  constructor(code: string) { super(code); this.name = "HoldoutGroupError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const holdoutGroupDecider: Decider<HoldoutGroupCommand, HoldoutGroupEvent, HoldoutGroupState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new HoldoutGroupError("EXISTS");
        if (command.size <= 0) throw new HoldoutGroupError("BAD_SIZE");
        return [{ type: "HoldoutGroupRegistered", id: command.id, size: command.size }];
      case "open":
        if (state.status !== "registered") throw new HoldoutGroupError("NOT_REGISTERED");
        return [{ type: "HoldoutGroupOpened", at: command.at }];
      case "close":
        if (state.status !== "open") throw new HoldoutGroupError("NOT_OPEN");
        return [{ type: "HoldoutGroupClosed", at: command.at }];
      default: {
        const _never: never = command;
        throw new HoldoutGroupError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "HoldoutGroupRegistered":
        return { status: "registered", id: event.id, size: event.size };
      case "HoldoutGroupOpened":
        if (state.status !== "registered") return state;
        return { status: "open", id: state.id, size: state.size, openedAt: event.at };
      case "HoldoutGroupClosed":
        if (state.status !== "open") return state;
        return { status: "closed", id: state.id, size: state.size, closedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

