export type SerialEvent =
  | { type: "SerialIssued"; id: string; sku: string; idempotencyKey: string }
  | { type: "SerialAttached"; crateId: string; idempotencyKey: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<SerialEvent>; revision: bigint | null }>;
  appendToStream(s: string, events: ReadonlyArray<SerialEvent>, opts: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export async function appendIfNew(
  store: EventStore,
  stream: string,
  events: ReadonlyArray<SerialEvent>,
): Promise<bigint> {
  const slice = await store.readStream(stream);
  const seen = new Set(slice.events.map((e) => e.idempotencyKey));
  const unseen = events.filter((e) => !seen.has(e.idempotencyKey));
  if (unseen.length === 0) return slice.revision ?? -1n;
  const expectedRevision: ExpectedRevision = slice.revision ?? "no_stream";
  return store.appendToStream(stream, unseen, { expectedRevision });
}
