Fix this TypeScript append so it uses optimistic concurrency with expectedRevision and a typed ConcurrencyConflict error.

```typescript
async function save(store: any, stream: string, events: unknown[]) {
  await store.appendToStream(stream, events);
}
```

The broken snippet appends blindly. Read the stream's revision first, pass `expectedRevision` on the append, and wrap the conflict signal in a typed error. The local `EventStore` interface avoids pulling in a third-party client type.

```typescript
export type RouteOptimisationEvent =
  | { type: "RoutePlanned"; id: string; stops: ReadonlyArray<string> }
  | { type: "RouteRerouted"; stops: ReadonlyArray<string> };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: RouteOptimisationEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: RouteOptimisationEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(stream: string) { super(`CONCURRENCY:${stream}`); this.name = "ConcurrencyConflict"; }
}

function isConflict(err: unknown): boolean {
  return err instanceof Error && /WrongExpectedVersion/i.test(err.message);
}

export async function save(
  store: EventStore,
  stream: string,
  events: RouteOptimisationEvent[],
): Promise<bigint> {
  const current = await store.readStream(stream);
  const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
  try {
    const appended = await store.appendToStream(stream, events, { expectedRevision });
    return appended.nextRevision;
  } catch (err) {
    if (isConflict(err)) throw new ConcurrencyConflict(stream);
    throw err;
  }
}
```

```typescript
export type PreprintVersionEvent =
  | { type: "PreprintVersionPublished"; id: string; doi: string }
  | { type: "PreprintVersionSupersededBy"; successorId: string };

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], options: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ ok: true; revision: bigint } | { ok: false }>;
}

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict";
  constructor(public readonly stream: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendGuarded(
  store: EventStore,
  stream: string,
  events: PreprintVersionEvent[],
): Promise<bigint> {
  const read = await store.readStream<PreprintVersionEvent>(stream);
  const expected = read.revision;
  const result = await store.appendToStream(stream, events, { expectedRevision: expected });
  if (!result.ok) throw new ConcurrencyConflict(stream, expected);
  return result.revision;
}
