export type ReceiptEvent =
  | { type: "ReceiptIssued"; cents: number }
  | { type: "ReceiptVoided" };

export type ReceiptView = Readonly<{ total: number; voided: number }>;

export function project(view: ReceiptView, e: ReceiptEvent): ReceiptView {
  switch (e.type) {
    case "ReceiptIssued": return { ...view, total: view.total + e.cents };
    case "ReceiptVoided": return { ...view, voided: view.voided + 1 };
    default: { const _n: never = e; return view; }
  }
}

export interface EventStoreBatch {
  readAll(opts: { fromRevision: bigint; maxCount: number }): Promise<{
    events: ReadonlyArray<{ revision: bigint; event: ReceiptEvent }>;
    nextRevision: bigint | null;
  }>;
}

export interface ReadStore {
  persist(view: ReceiptView, uptoRevision: bigint): Promise<void>;
}

export async function rebuild(
  opts: { from: bigint; batchSize: number; events: EventStoreBatch; reads: ReadStore }
): Promise<void> {
  let cursor: bigint | null = opts.from;
  let view: ReceiptView = { total: 0, voided: 0 };
  while (cursor !== null) {
    const { events: batch, nextRevision } = await opts.events.readAll({
      fromRevision: cursor,
      maxCount: opts.batchSize,
    });
    if (batch.length === 0) break;
    let last = cursor;
    for (const { revision, event } of batch) {
      view = project(view, event);
      last = revision;
    }
    await opts.reads.persist(view, last);
    cursor = nextRevision;
  }
}
