export type PalletState =
  | { status: "none" }
  | { status: "registered"; id: string; weight: number }
  | { status: "shipped"; id: string; weight: number; shippedAt: string };

export type PalletCommand =
  | { type: "register"; id: string; weight: number }
  | { type: "ship"; at: string }
  | { type: "reweigh"; weight: number };

export type PalletEvent =
  | { type: "PalletRegistered"; id: string; weight: number }
  | { type: "PalletShipped"; at: string }
  | { type: "PalletReweighed"; weight: number };

export class PalletError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const palletDecider: Decider<PalletCommand, PalletEvent, PalletState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new PalletError("EXISTS");
        if (command.weight <= 0) throw new PalletError("BAD_WEIGHT");
        return [{ type: "PalletRegistered", id: command.id, weight: command.weight }];
      case "ship":
        if (state.status !== "registered") throw new PalletError("NOT_REGISTERED");
        return [{ type: "PalletShipped", at: command.at }];
      case "reweigh":
        if (state.status !== "registered") throw new PalletError("NOT_REGISTERED");
        if (command.weight <= 0) throw new PalletError("BAD_WEIGHT");
        if (command.weight === state.weight) return [];
        return [{ type: "PalletReweighed", weight: command.weight }];
      default: {
        const _n: never = command;
        throw new PalletError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PalletRegistered":
        return { status: "registered", id: event.id, weight: event.weight };
      case "PalletShipped":
        if (state.status !== "registered") return state;
        return { status: "shipped", id: state.id, weight: state.weight, shippedAt: event.at };
      case "PalletReweighed":
        if (state.status !== "registered") return state;
        return { ...state, weight: event.weight };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
