export type TaskState =
  | { status: "none" }
  | { status: "todo"; id: string; summary: string }
  | { status: "inProgress"; id: string; summary: string; assignee: string }
  | { status: "done"; id: string; summary: string; completedAt: string };

export type TaskCommand =
  | { type: "createTask"; id: string; summary: string }
  | { type: "assignTask"; assignee: string }
  | { type: "completeTask"; at: string };

export type TaskEvent =
  | { type: "TaskCreated"; id: string; summary: string }
  | { type: "TaskAssigned"; assignee: string }
  | { type: "TaskCompleted"; at: string };

export class TaskError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const taskDecider: Decider<TaskCommand, TaskEvent, TaskState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "createTask":
        if (s.status !== "none") throw new TaskError("ALREADY_EXISTS");
        return [{ type: "TaskCreated", id: c.id, summary: c.summary }];
      case "assignTask":
        if (s.status === "done") throw new TaskError("ALREADY_COMPLETED");
        if (s.status === "none") throw new TaskError("NOT_FOUND");
        return [{ type: "TaskAssigned", assignee: c.assignee }];
      case "completeTask":
        if (s.status !== "inProgress") throw new TaskError("NOT_IN_PROGRESS");
        return [{ type: "TaskCompleted", at: c.at }];
      default: {
        const _n: never = c;
        throw new TaskError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "TaskCreated":
        return { status: "todo", id: e.id, summary: e.summary };
      case "TaskAssigned":
        if (s.status === "none" || s.status === "done") return s;
        return { status: "inProgress", id: s.id, summary: s.summary, assignee: e.assignee };
      case "TaskCompleted":
        if (s.status !== "inProgress") return s;
        return { status: "done", id: s.id, summary: s.summary, completedAt: e.at };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
