export type EpicState =
  | { status: "none" }
  | { status: "drafting"; id: string; title: string; children: readonly string[] }
  | { status: "finalized"; id: string; title: string; children: readonly string[] };

export type EpicCommand =
  | { type: "create"; id: string; title: string }
  | { type: "addChildTask"; taskId: string }
  | { type: "finalize" };

export type EpicEvent =
  | { type: "EpicCreated"; id: string; title: string }
  | { type: "ChildTaskAdded"; taskId: string }
  | { type: "EpicFinalized" };

export class EpicError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const epicDecider: Decider<EpicCommand, EpicEvent, EpicState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "create":
        if (s.status !== "none") throw new EpicError("EXISTS");
        return [{ type: "EpicCreated", id: c.id, title: c.title }];
      case "addChildTask":
        if (s.status !== "drafting") throw new EpicError("NOT_DRAFTING");
        if (s.children.includes(c.taskId)) throw new EpicError("DUPLICATE_CHILD");
        return [{ type: "ChildTaskAdded", taskId: c.taskId }];
      case "finalize":
        if (s.status !== "drafting") throw new EpicError("NOT_DRAFTING");
        if (s.children.length === 0) throw new EpicError("NO_CHILDREN");
        return [{ type: "EpicFinalized" }];
      default: {
        const _n: never = c;
        throw new EpicError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "EpicCreated":
        return { status: "drafting", id: e.id, title: e.title, children: [] };
      case "ChildTaskAdded":
        if (s.status !== "drafting") return s;
        return { ...s, children: [...s.children, e.taskId] };
      case "EpicFinalized":
        if (s.status !== "drafting") return s;
        return { status: "finalized", id: s.id, title: s.title, children: s.children };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
