export type AnnotationState = { status: "none" } | { status: "active"; id: string; text: string };
export type AnnotationCommand =
  | { type: "attach"; id: string; text: string }
  | { type: "edit"; text: string };
export type AnnotationEvent =
  | { type: "AnnotationAttached"; id: string; text: string }
  | { type: "AnnotationEdited"; text: string };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const annotationDecider: Decider<AnnotationCommand, AnnotationEvent, AnnotationState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "attach":
        if (s.status !== "none") throw new Error("EXISTS");
        return [{ type: "AnnotationAttached", id: c.id, text: c.text }];
      case "edit":
        if (s.status !== "active") throw new Error("NOT_ACTIVE");
        return [{ type: "AnnotationEdited", text: c.text }];
      default: { const _n: never = c; return []; }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "AnnotationAttached": return { status: "active", id: e.id, text: e.text };
      case "AnnotationEdited": return s.status === "active" ? { ...s, text: e.text } : s;
      default: { const _n: never = e; return s; }
    }
  },
};

export interface Env { readonly revision: bigint; readonly event: AnnotationEvent; }
export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<Env>>;
  appendToStream(s: string, e: AnnotationEvent[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handleAnnotation(cmd: AnnotationCommand, stream: string, store: EventStore): Promise<void> {
  const envs = await store.readStream(stream);
  const state = envs.map((e) => e.event).reduce(annotationDecider.evolve, annotationDecider.initialState);
  const expected = envs.length === 0 ? "no_stream" as const : envs[envs.length - 1]!.revision;
  const events = annotationDecider.decide(cmd, state);
  if (events.length > 0) await store.appendToStream(stream, events, { expectedRevision: expected });
}
