```typescript
export type TrainingJobState =
  | { status: "none" }
  | { status: "queued"; id: string }
  | { status: "running"; id: string }
  | { status: "completed"; id: string };

export type TrainingJobCommand =
  | { type: "submit"; id: string }
  | { type: "start" }
  | { type: "complete"; metric: number };

export type TrainingJobEvent =
  | { type: "TrainingJobSubmitted"; id: string }
  | { type: "TrainingJobStarted" }
  | { type: "TrainingJobCompleted"; metric: number };

const initial: TrainingJobState = { status: "none" };

function evolve(state: TrainingJobState, event: TrainingJobEvent): TrainingJobState {
  switch (event.type) {
    case "TrainingJobSubmitted":
      return { status: "queued", id: event.id };
    case "TrainingJobStarted":
      return state.status === "queued" ? { status: "running", id: state.id } : state;
    case "TrainingJobCompleted":
      return state.status === "running" ? { status: "completed", id: state.id } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: TrainingJobCommand, state: TrainingJobState): TrainingJobEvent[] {
  switch (command.type) {
    case "submit":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "TrainingJobSubmitted", id: command.id }];
    case "start":
      if (state.status !== "queued") throw new Error("NOT_QUEUED");
      return [{ type: "TrainingJobStarted" }];
    case "complete":
      if (state.status !== "running") throw new Error("NOT_RUNNING");
      return [{ type: "TrainingJobCompleted", metric: command.metric }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handle(
  command: TrainingJobCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream<TrainingJobEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
}
