```typescript
export type CampaignFlightState =
  | { status: "unscheduled" }
  | { status: "scheduled"; id: string }
  | { status: "running"; id: string }
  | { status: "ended"; id: string };

export type CampaignFlightCommand =
  | { type: "schedule"; id: string }
  | { type: "launch" }
  | { type: "end" };

export type CampaignFlightEvent =
  | { type: "CampaignFlightScheduled"; id: string }
  | { type: "CampaignFlightLaunched" }
  | { type: "CampaignFlightEnded" };

export interface EventEnvelope<E> {
  readonly revision: bigint;
  readonly metadata: { readonly idempotencyKey?: string };
  readonly event: E;
}

export const initialFlight: CampaignFlightState = { status: "unscheduled" };

export function decide(cmd: CampaignFlightCommand, state: CampaignFlightState): CampaignFlightEvent[] {
  switch (cmd.type) {
    case "schedule":
      if (state.status !== "unscheduled") throw new Error("ALREADY_SCHEDULED");
      return [{ type: "CampaignFlightScheduled", id: cmd.id }];
    case "launch":
      if (state.status !== "scheduled") throw new Error("NOT_SCHEDULED");
      return [{ type: "CampaignFlightLaunched" }];
    case "end":
      if (state.status !== "running") throw new Error("NOT_RUNNING");
      return [{ type: "CampaignFlightEnded" }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export function evolve(state: CampaignFlightState, event: CampaignFlightEvent): CampaignFlightState {
  switch (event.type) {
    case "CampaignFlightScheduled":
      return { status: "scheduled", id: event.id };
    case "CampaignFlightLaunched":
      if (state.status !== "scheduled") return state;
      return { status: "running", id: state.id };
    case "CampaignFlightEnded":
      if (state.status === "unscheduled" || state.status === "ended") return state;
      return { status: "ended", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(s: string): Promise<readonly EventEnvelope<CampaignFlightEvent>[]>;
  appendToStream(s: string, events: readonly CampaignFlightEvent[], opts: { expectedRevision: ExpectedRevision; metadata?: { idempotencyKey?: string } }): Promise<void>;
}

export async function handle(
  store: EventStore,
  stream: string,
  cmd: CampaignFlightCommand,
  idempotencyKey?: string,
): Promise<void> {
  const stored = await store.readStream(stream);
  if (idempotencyKey && stored.some((e) => e.metadata.idempotencyKey === idempotencyKey)) {
    return;
  }
  const state = stored.reduce<CampaignFlightState>((s, { event }) => evolve(s, event), initialFlight);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, decide(cmd, state), {
    expectedRevision: expected,
    metadata: idempotencyKey ? { idempotencyKey } : undefined,
  });
}
```

