```typescript
type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) { super("conflict"); this.name = "ConcurrencyConflict"; }
}

export type LoadAssignmentEvent =
  | { type: "LoadAssignmentCreated"; id: string }
  | { type: "LoadAssignmentAccepted"; driverId: string }
  | { type: "LoadAssignmentRejected"; reason: string };

async function currentRevision<E>(store: EventStore<E>, stream: string): Promise<ExpectedRevision> {
  let revision: bigint | undefined = undefined;
  for await (const ev of store.readStream(stream)) revision = ev.revision;
  return revision === undefined ? "no_stream" : revision;
}

export async function appendWithRetry(
  store: EventStore<LoadAssignmentEvent>,
  stream: string,
  build: () => readonly LoadAssignmentEvent[],
  maxAttempts = 3,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    const expected = await currentRevision(store, stream);
    try {
      const { nextRevision } = await store.appendToStream(stream, build(), { expectedRevision: expected });
      return nextRevision;
    } catch (e) {
      attempt++;
      if (attempt >= maxAttempts) throw new ConcurrencyConflict(stream);
    }
  }
  throw new ConcurrencyConflict(stream);
}
```

A Decider bundles the three pieces a single aggregate needs: an immutable initialState literal, a decide function that validates commands against current state and returns the events they produce, and a pure evolve that folds events back into state. A reducer only covers the evolve half — it has no notion of commands or invariants. The split is what lets you replay history deterministically while still guarding writes.

```typescript
export type TicketState =
  | { status: "none" }
  | { status: "open"; id: string; description: string }
  | { status: "assigned"; id: string; description: string; technician: string }
  | { status: "resolved"; id: string; resolvedAt: string };

export type TicketCommand =
  | { type: "open"; id: string; description: string }
  | { type: "assign"; technician: string }
  | { type: "resolve"; at: string };

export type TicketEvent =
  | { type: "TicketOpened"; id: string; description: string }
  | { type: "TicketAssigned"; technician: string }
  | { type: "TicketResolved"; at: string };

export class TicketError extends Error {
  constructor(public readonly code: string) { super(code); }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const ticketDecider: Decider<TicketCommand, TicketEvent, TicketState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new TicketError("ALREADY_OPEN");
        return [{ type: "TicketOpened", id: command.id, description: command.description }];
      case "assign":
        if (state.status !== "open") throw new TicketError("NOT_OPEN");
        return [{ type: "TicketAssigned", technician: command.technician }];
      case "resolve":
        if (state.status !== "assigned") throw new TicketError("NOT_ASSIGNED");
        return [{ type: "TicketResolved", at: command.at }];
      default: {
        const _never: never = command;
        return _never;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TicketOpened":
        return { status: "open", id: event.id, description: event.description };
      case "TicketAssigned":
        if (state.status !== "open") return state;
        return { status: "assigned", id: state.id, description: state.description, technician: event.technician };
      case "TicketResolved":
        if (state.status !== "assigned") return state;
        return { status: "resolved", id: state.id, resolvedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

The roster is a Map<string, User> in context. PEER_IN and PEER_OUT are upsert/delete events that produce a new Map via assign, keeping structural sharing minimal and avoiding duplicate entries if a peer rejoins.

```typescript
import { setup, assign } from 'xstate';

interface User { id: string; nick: string }
interface Ctx { roster: Map<string, User> }
type Ev =
  | { type: 'PEER_IN'; user: User }
  | { type: 'PEER_OUT'; id: string }
  | { type: 'CLEAR' };

export const rosterMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'roster',
  context: { roster: new Map() },
  initial: 'live',
  states: {
    live: {
      on: {
        PEER_IN: {
          actions: assign({
            roster: ({ context, event }) => {
              const next = new Map(context.roster);
              next.set(event.user.id, event.user);
              return next;
            }
          })
        },
        PEER_OUT: {
          actions: assign({
            roster: ({ context, event }) => {
              const next = new Map(context.roster);
              next.delete(event.id);
              return next;
            }
          })
        },
        CLEAR: { actions: assign({ roster: () => new Map() }) }
      }
    }
  }
});
```

