export type ApartmentEvent =
  | { type: "ApartmentListed"; id: string; rent: number }
  | { type: "ApartmentOccupied"; by: string };

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

interface Tx {
  appendToStream(s: string, events: ApartmentEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
  insertOutbox(row: OutboxRow): Promise<void>;
}

interface TxRunner {
  transaction<T>(fn: (tx: Tx) => Promise<T>): Promise<T>;
}

// A background publisher polls outbox rows where publishedAt IS NULL,
// publishes them to the bus, and updates publishedAt. Not implemented here.
export async function appendWithOutbox(
  runner: TxRunner,
  stream: string,
  events: ApartmentEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream",
): Promise<void> {
  await runner.transaction(async (tx) => {
    await tx.appendToStream(stream, events, { expectedRevision });
    for (const row of outboxRows) {
      await tx.insertOutbox(row);
    }
  });
}
