export type DomainEvent =
  | { type: "EntryDrafted"; id: string; journalId: string }
  | { type: "EntryPosted"; id: string; journalId: string; amount: number; postedAt: string }
  | { type: "JournalClosed"; journalId: string; closedAt: string }
  | { type: "EntryTagged"; id: string; tag: string };

export type IntegrationEvent =
  | { schema: "journal.entry-posted.v1"; payload: { entryId: string; journalId: string; amount: number; postedAt: string } }
  | { schema: "journal.closed.v1"; payload: { journalId: string; closedAt: string } };

export function translate(event: DomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "EntryPosted":
      return {
        schema: "journal.entry-posted.v1",
        payload: {
          entryId: event.id,
          journalId: event.journalId,
          amount: event.amount,
          postedAt: event.postedAt,
        },
      };
    case "JournalClosed":
      return {
        schema: "journal.closed.v1",
        payload: { journalId: event.journalId, closedAt: event.closedAt },
      };
    case "EntryDrafted":
    case "EntryTagged":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export type OutboxView = Readonly<{ pending: ReadonlyArray<IntegrationEvent> }>;

export const emptyOutbox: OutboxView = { pending: [] };

export function project(view: OutboxView, event: DomainEvent): OutboxView {
  const translated = translate(event);
  if (translated === null) return view;
  return { pending: [...view.pending, translated] };
}

export function outboxFrom(events: DomainEvent[]): OutboxView {
  return events.reduce(project, emptyOutbox);
}
