A checkpointed subscription reads events from the last saved position, applies each to a read model, then persists the new position. The write order is critical: apply, persist projection, then write checkpoint, so a crash mid-loop reprocesses at most one event.

```typescript
import { Effect } from "effect";

export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, p: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(position: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface Projection<V, E> {
  load(): Promise<V>;
  apply(v: V, e: E): Promise<V>;
  save(v: V): Promise<void>;
}

export const runSubscriptionEffect = <V, E>(
  name: string,
  source: EventSource<E>,
  checkpoints: CheckpointStore,
  projection: Projection<V, E>,
) =>
  Effect.gen(function* () {
    const start = yield* Effect.promise(() => checkpoints.read(name));
    const from: bigint = start ?? 0n;
    let view = yield* Effect.promise(() => projection.load());
    const run = async (): Promise<void> => {
      for await (const { position, event } of source.readFrom(from)) {
        view = await projection.apply(view, event);
        await projection.save(view);
        await checkpoints.write(name, position);
      }
    };
    yield* Effect.promise(() => run());
  });
```

```typescript
export type IngredientEvent =
  | { type: "IngredientRegistered"; id: string; name: string }
  | { type: "IngredientRestocked"; grams: number };

export interface IngredientAggregate {
  readonly id: string;
  readonly name: string;
  readonly grams: number;
}

export const emptyIngredient: IngredientAggregate = { id: "", name: "", grams: 0 };

export function when(state: IngredientAggregate, event: IngredientEvent): IngredientAggregate {
  switch (event.type) {
    case "IngredientRegistered":
      return { id: event.id, name: event.name, grams: 0 };
    case "IngredientRestocked":
      return { ...state, grams: state.grams + event.grams };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  async function main(): Promise<void> {
    for await (const event of stream) {
      state = reducer(state, event);
    }
  }
  await main();
  return state;
}

export function loadIngredient(events: AsyncIterable<IngredientEvent>): Promise<IngredientAggregate> {
  return aggregateStream(events, when, emptyIngredient);
}

