The read store is eventually consistent with the event store.

```typescript
export type DocumentCommand = { type: "create"; id: string; title: string };
export type DocumentEvent = { type: "DocumentCreated"; id: string; title: string };

export type DocumentState = { status: "empty" } | { status: "drafting"; id: string; title: string };

export interface Decider<C, E, S> {
  initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const documentDecider: Decider<DocumentCommand, DocumentEvent, DocumentState> = {
  initialState: { status: "empty" },
  decide(c, s) {
    if (c.type === "create") {
      if (s.status !== "empty") throw new Error("EXISTS");
      return [{ type: "DocumentCreated", id: c.id, title: c.title }];
    }
    return [];
  },
  evolve(s, e) {
    if (e.type === "DocumentCreated") return { status: "drafting", id: e.id, title: e.title };
    return s;
  },
};

export interface EventStore {
  readStream(s: string): Promise<DocumentEvent[]>;
  appendToStream(s: string, e: DocumentEvent[]): Promise<void>;
}

export async function handleCommand(cmd: DocumentCommand, stream: string, store: EventStore): Promise<void> {
  const events = await store.readStream(stream);
  const state = events.reduce(documentDecider.evolve, documentDecider.initialState);
  const next = documentDecider.decide(cmd, state);
  if (next.length > 0) await store.appendToStream(stream, next);
}

export interface DocumentView { id: string; title: string; }
export interface ViewStore { get(id: string): Promise<DocumentView | null>; }

export async function queryView(id: string, views: ViewStore): Promise<DocumentView | null> {
  return views.get(id);
}
```

```typescript
export type DeliveryEvent =
  | { type: "DeliveryDispatched"; id: string; courier: string }
  | { type: "DeliveryDelivered"; at: string }
  | { type: "DeliveryFailed"; reason: string };

export type DeliveryState =
  | { status: "none" }
  | { status: "dispatched"; id: string; courier: string }
  | { status: "delivered"; id: string; at: string }
  | { status: "failed"; id: string; reason: string };

export type DeliveryCommand =
  | { type: "dispatch"; id: string; courier: string }
  | { type: "markDelivered"; at: string }
  | { type: "markFailed"; reason: string };

export class DeliveryError extends Error {}

export function evolve(state: DeliveryState, event: DeliveryEvent): DeliveryState {
  switch (event.type) {
    case "DeliveryDispatched":
      return { status: "dispatched", id: event.id, courier: event.courier };
    case "DeliveryDelivered":
      if (state.status !== "dispatched") return state;
      return { status: "delivered", id: state.id, at: event.at };
    case "DeliveryFailed":
      if (state.status !== "dispatched") return state;
      return { status: "failed", id: state.id, reason: event.reason };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(command: DeliveryCommand, state: DeliveryState): DeliveryEvent[] {
  switch (command.type) {
    case "dispatch":
      if (state.status !== "none") throw new DeliveryError("EXISTS");
      return [{ type: "DeliveryDispatched", id: command.id, courier: command.courier }];
    case "markDelivered":
      if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
      return [{ type: "DeliveryDelivered", at: command.at }];
    case "markFailed":
      if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
      return [{ type: "DeliveryFailed", reason: command.reason }];
    default: {
      const _n: never = command;
      throw new DeliveryError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: DeliveryEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: DeliveryEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export async function handle(store: EventStore, stream: string, cmd: DeliveryCommand): Promise<bigint | null> {
  const { events, revision } = await store.readStream(stream);
  const state = events.reduce(evolve, { status: "none" } as DeliveryState);
  const newEvents = decide(cmd, state);
  if (newEvents.length === 0) return revision;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  return store.appendToStream(stream, newEvents, { expectedRevision });
}
```

```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const e of stream) state = evolve(state, e);
  return state;
}
export type DepositionRecordEvent = { type: "scheduled"; recordId: string } | { type: "sealed" };
export type DepositionRecordState = { status: "empty" } | { status: "active"; recordId: string } | { status: "sealed" };
function evolve(s: DepositionRecordState, e: DepositionRecordEvent): DepositionRecordState {
  switch (e.type) {
    case "scheduled": return { status: "active", recordId: e.recordId };
    case "sealed": return { status: "sealed" };
    default: { const _: never = e; return s; }
  }
}
export async function loadDeposition(stream: AsyncIterable<DepositionRecordEvent>): Promise<DepositionRecordState> {
  return aggregateStream<DepositionRecordState, DepositionRecordEvent>(stream, evolve, { status: "empty" });
}
