```typescript
export interface Snapshot<S> { version: number; revision: bigint; state: S }

export type TerritoryMapEvent =
  | { type: "created"; id: string }
  | { type: "districtAdded" }
  | { type: "sealed" };

export interface TerritoryMapState {
  id: string | null;
  districts: number;
  sealed: boolean;
}

export const CURRENT_VERSION = 1 as const;
export const initialState: TerritoryMapState = { id: null, districts: 0, sealed: false };

export function evolve(s: TerritoryMapState, e: TerritoryMapEvent): TerritoryMapState {
  switch (e.type) {
    case "created":
      return { ...s, id: e.id };
    case "districtAdded":
      return { ...s, districts: s.districts + 1 };
    case "sealed":
      return { ...s, sealed: true };
    default: {
      const _: never = e;
      return _;
    }
  }
}

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStreamFrom(stream: string, fromRevision: bigint): Promise<StoredEvent<E>[]>;
}

export interface SnapshotStore<S> {
  load(stream: string): Promise<Snapshot<S> | null>;
}

export async function load(
  stream: string,
  events: EventStore<TerritoryMapEvent>,
  snapshots: SnapshotStore<TerritoryMapState>,
): Promise<TerritoryMapState> {
  const snap = await snapshots.load(stream);
  const start = snap ? snap.revision + 1n : 0n;
  const base = snap ? snap.state : initialState;
  const stored = await events.readStreamFrom(stream, start);
  return stored.reduce<TerritoryMapState>((s, r) => evolve(s, r.event), base);
}
