import { Effect } from "effect";

export type MortgageEvent =
  | { type: "MortgageApplied"; id: string; amount: number }
  | { type: "MortgageApproved"; at: string };

export interface EventStore {
  readStream(stream: string): Promise<{ revision: bigint; events: MortgageEvent[] }>;
  appendToStream(
    stream: string,
    events: MortgageEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict" as const;
  constructor(public readonly stream: string) { super(`Conflict on ${stream}`); }
}

export const appendMortgage = (
  store: EventStore,
  stream: string,
  events: MortgageEvent[],
): Effect.Effect<bigint, ConcurrencyConflict | Error> =>
  Effect.gen(function* () {
    const current = yield* Effect.tryPromise({
      try: () => store.readStream(stream),
      catch: (e) => e as Error,
    });
    const expectedRevision: bigint | "no_stream" =
      current.events.length === 0 ? "no_stream" : current.revision;
    const appended = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision }),
      catch: (err) => {
        const e = err as { code?: string };
        return e.code === "WrongExpectedVersion" ? new ConcurrencyConflict(stream) : (err as Error);
      },
    });
    return appended.nextExpectedRevision;
  });

