  types: {
    context: {} as Ctx,
    events: {} as Ev,
    input: {} as { totalBytes: number; chunkSize: number }
  },
  actors: {
    putChunk: fromPromise(
      async ({ input }: { input: { offset: number; size: number } }) => {
        await new Promise((r) => setTimeout(r, 10));
        return input.size;
      }
    )
