  id: 'chunked',
  initial: 'ready',
  context: ({ input }) => ({
    bytesUploaded: 0,
    totalBytes: input.totalBytes,
    chunkSize: input.chunkSize
  }),
  states: {
    ready: { on: { START: 'uploading' } },
    uploading: {
      invoke: {
        src: 'putChunk',
        input: ({ context }) => ({
          offset: context.bytesUploaded,
          size: Math.min(context.chunkSize, context.totalBytes - context.bytesUploaded)
        }),
        onDone: [
          {
            target: 'uploading',
            guard: 'moreToUpload',
            reenter: true,
            actions: assign({
              bytesUploaded: ({ context, event }) => context.bytesUploaded + event.output
            })
          },
          {
            target: 'done',
            actions: assign({
              bytesUploaded: ({ context, event }) => context.bytesUploaded + event.output
            })
          }
        ]
      },
      on: { CANCEL: 'cancelled' }
    },
    done: { type: 'final' },
    cancelled: { type: 'final' }
  }
