import { Effect } from "effect";

export type DatasetVersionEvent =
  | { type: "DatasetVersionStarted"; id: string }
  | { type: "DatasetVersionPublished"; id: string };

export type DatasetVersionView = { totalPublished: number };
const empty: DatasetVersionView = { totalPublished: 0 };

function project(view: DatasetVersionView, event: DatasetVersionEvent): DatasetVersionView {
  switch (event.type) {
    case "DatasetVersionStarted":
      return view;
    case "DatasetVersionPublished":
      return { totalPublished: view.totalPublished + 1 };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface Cursor<E> { [Symbol.asyncIterator](): AsyncIterator<{ position: bigint; event: E }>; }

export const runSubscription = (
  name: string,
  cursor: Cursor<DatasetVersionEvent>,
  checkpoints: CheckpointStore,
  save: (v: DatasetVersionView) => Promise<void>,
) =>
  Effect.gen(function* () {
    let view = empty;
    const iter = cursor[Symbol.asyncIterator]();
    while (true) {
      const step = yield* Effect.promise(() => iter.next());
      if (step.done) break;
      const { position, event } = step.value;
      view = project(view, event);
      yield* Effect.promise(() => save(view));
      yield* Effect.promise(() => checkpoints.write(name, position));
    }
  });
