export type FlightEvent =
  | { type: "FlightScheduled"; data: { id: string; gate: string } }
  | { type: "GateChanged"; data: { gate: string } }
  | { type: "FlightDeparted"; data: { at: string } }
  | { type: "FlightLanded"; data: { at: string } };

export type FlightSummary = Readonly<{
  id: string;
  gate: string;
  status: "scheduled" | "airborne" | "landed";
  departedAt?: string;
  landedAt?: string;
}>;

export function when(current: Partial<FlightSummary>, event: FlightEvent): Partial<FlightSummary> {
  switch (event.type) {
    case "FlightScheduled":
      return { id: event.data.id, gate: event.data.gate, status: "scheduled" };
    case "GateChanged":
      return { ...current, gate: event.data.gate };
    case "FlightDeparted":
      return { ...current, status: "airborne", departedAt: event.data.at };
    case "FlightLanded":
      return { ...current, status: "landed", landedAt: event.data.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function aggregateStream<S, E>(
  events: ReadonlyArray<E>,
  reducer: (s: Partial<S>, e: E) => Partial<S>,
  check: (s: Partial<S>) => s is S,
): S {
  const state = events.reduce<Partial<S>>(reducer, {});
  if (!check(state)) throw new Error("SUMMARY_INCOMPLETE");
  return state;
}

export function isFlightSummary(v: Partial<FlightSummary>): v is FlightSummary {
  return typeof v.id === "string" && typeof v.gate === "string" && typeof v.status === "string";
}

export function summaryFrom(events: FlightEvent[]): FlightSummary {
  return aggregateStream<FlightSummary, FlightEvent>(events, when, isFlightSummary);
}
