export type DonationDriveEvent =
  | { type: "launched"; driveId: string; goal: number }
  | { type: "pledged"; driveId: string; amount: number }
  | { type: "closed"; driveId: string };

export interface StoredEvent<E> { globalPosition: bigint; event: E }

export interface EventReader<E> {
  readBatch(from: bigint, size: number): Promise<StoredEvent<E>[]>;
}

export interface DriveRow { driveId: string; raised: number; open: boolean }
export interface ReadStore {
  clear(): Promise<void>;
  save(rows: DriveRow[]): Promise<void>;
}

export function project(view: Record<string, DriveRow>, event: DonationDriveEvent): Record<string, DriveRow> {
  switch (event.type) {
    case "launched":
      return { ...view, [event.driveId]: { driveId: event.driveId, raised: 0, open: true } };
    case "pledged": {
      const row = view[event.driveId];
      if (!row) return view;
      return { ...view, [event.driveId]: { ...row, raised: row.raised + event.amount } };
    }
    case "closed": {
      const row = view[event.driveId];
      if (!row) return view;
      return { ...view, [event.driveId]: { ...row, open: false } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  reader: EventReader<DonationDriveEvent>;
  store: ReadStore;
}): Promise<bigint> {
  if (opts.from === 0n) await opts.store.clear();
  let cursor = opts.from;
  let view: Record<string, DriveRow> = {};
  for (;;) {
    const batch = await opts.reader.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const s of batch) {
      view = project(view, s.event);
      cursor = s.globalPosition;
    }
    await opts.store.save(Object.values(view));
  }
  return cursor;
}
