```typescript
export type JournalEvent =
  | { type: "EntryPosted"; id: string; journalId: string; amount: number }
  | { type: "EntryReversed"; id: string; journalId: string }
  | { type: "JournalArchived"; journalId: string };

export type JournalView = Readonly<{
  totalsByJournal: Readonly<Record<string, number>>;
  reversedEntries: Readonly<Record<string, boolean>>;
}>;

export const emptyView: JournalView = {
  totalsByJournal: {},
  reversedEntries: {},
};

export function project(view: JournalView, event: JournalEvent): JournalView {
  switch (event.type) {
    case "EntryPosted": {
      if (view.reversedEntries[event.id]) return view;
      const current = view.totalsByJournal[event.journalId] ?? 0;
      return {
        ...view,
        totalsByJournal: { ...view.totalsByJournal, [event.journalId]: current + event.amount },
      };
    }
    case "EntryReversed":
      return { ...view, reversedEntries: { ...view.reversedEntries, [event.id]: true } };
    case "JournalArchived": {
      const totals: Record<string, number> = { ...view.totalsByJournal };
      delete totals[event.journalId];
      return { ...view, totalsByJournal: totals };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface Reader {
  readBatch(from: bigint, size: number): Promise<ReadonlyArray<{ revision: bigint; event: JournalEvent }>>;
}

export interface Store {
  wipe(): Promise<void>;
  save(view: JournalView): Promise<void>;
}

export async function rebuildJournalView(
  reader: Reader,
  store: Store,
  options: { from: bigint; batchSize: number; wipeFirst: boolean },
): Promise<JournalView> {
  if (options.wipeFirst) await store.wipe();
  let cursor: bigint = options.from;
  let view: JournalView = emptyView;
  while (true) {
    const batch = await reader.readBatch(cursor, options.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = project(view, event);
      cursor = revision + 1n;
    }
    await store.save(view);
  }
  return view;
}
