export interface EventEnvelope<E> { readonly revision: bigint; readonly event: E; }

export interface AppendResult { readonly nextRevision: bigint; readonly conflict: boolean; readonly actual: bigint | null; }

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<EventEnvelope<E>>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

