  | { type: "ManuscriptStarted"; id: string }
  | { type: "ChapterAppended"; chapterId: string };

export async function appendManuscript(
  store: EventStore<ManuscriptEvent>,
  stream: string,
  newEvents: ManuscriptEvent[],
): Promise<bigint> {
  const envs = await store.readStream(stream);
  const expected: ExpectedRevision = envs.length === 0 ? "no_stream" : envs[envs.length - 1]!.revision;
  const outcome = await store.appendToStream(stream, newEvents, { expectedRevision: expected });
  if (outcome.conflict) throw new ConcurrencyConflict(outcome.actual);
  return outcome.nextRevision;
}
