export type ProjectEvent =
  | { type: "ProjectPlanned"; id: string; name: string }
  | { type: "ProjectStarted"; at: string }
  | { type: "ProjectCompleted"; at: string };

export type ProjectState =
  | { status: "none" }
  | { status: "planned"; id: string; name: string }
  | { status: "active"; id: string; name: string; startedAt: string }
  | { status: "completed"; id: string };

export type ProjectCommand =
  | { type: "start"; at: string }
  | { type: "complete"; at: string };

export class ProjectError extends Error {}

export function evolve(s: ProjectState, e: ProjectEvent): ProjectState {
  switch (e.type) {
    case "ProjectPlanned":
      return { status: "planned", id: e.id, name: e.name };
    case "ProjectStarted":
      if (s.status !== "planned") return s;
      return { status: "active", id: s.id, name: s.name, startedAt: e.at };
    case "ProjectCompleted":
      return { status: "completed", id: "id" in s ? s.id : "" };
    default: {
      const _n: never = e;
      return s;
    }
  }
}

export function decide(c: ProjectCommand, s: ProjectState): ProjectEvent[] {
  switch (c.type) {
    case "start":
      if (s.status !== "planned") throw new ProjectError("NOT_PLANNED");
      return [{ type: "ProjectStarted", at: c.at }];
    case "complete":
      if (s.status !== "active") throw new ProjectError("NOT_ACTIVE");
      return [{ type: "ProjectCompleted", at: c.at }];
    default: {
      const _n: never = c;
      throw new ProjectError("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream(s: string): Promise<{ events: ProjectEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: readonly ProjectEvent[], o: { expectedRevision: bigint | "no_stream" }): Promise<bigint>;
}

export type ProjectStatusView = Readonly<{
  id: string;
  name: string;
  status: "planned" | "active" | "completed";
  startedAt: string | null;
  completedAt: string | null;
}>;

export interface ReadStore {
  getProject(id: string): Promise<ProjectStatusView | null>;
}

// write side
export async function handleProjectCommand(
  store: EventStore,
  streamName: string,
  command: ProjectCommand,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, { status: "none" } as ProjectState);
  const produced = decide(command, state);
  if (produced.length === 0) return;
  await store.appendToStream(streamName, produced, { expectedRevision: revision ?? "no_stream" });
}

// read side is populated by a separate projection subscription; eventually consistent
export async function queryProject(read: ReadStore, id: string): Promise<ProjectStatusView | null> {
  return read.getProject(id);
}
