import { Effect } from "effect";

export type CodeReviewEvent =
  | { type: "CodeReviewRequested"; id: string }
  | { type: "CodeReviewSubmitted"; id: string; verdict: "approve" | "changes" };

export interface EventEnvelope<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed<E> {
  readFrom(position: bigint | null): AsyncIterable<EventEnvelope<E>>;
}

export interface ReadModelOps<V, E> {
  load(): Promise<V>;
  persist(view: V): Promise<void>;
  project(view: V, event: E): V;
}

async function drain<V extends object>(
  name: string,
  checkpoints: CheckpointStore,
  feed: EventFeed<CodeReviewEvent>,
  rm: ReadModelOps<V, CodeReviewEvent>,
): Promise<void> {
  const start = await checkpoints.read(name);
  let view: V = await rm.load();
  for await (const env of feed.readFrom(start)) {
    view = rm.project(view, env.event);
    await rm.persist(view);
    await checkpoints.write(name, env.position);
  }
}

export function runFeed<V extends object>(
  name: string,
  checkpoints: CheckpointStore,
  feed: EventFeed<CodeReviewEvent>,
  rm: ReadModelOps<V, CodeReviewEvent>,
): Effect.Effect<void, Error> {
  return Effect.tryPromise({
    try: () => drain(name, checkpoints, feed, rm),
    catch: (err) => (err instanceof Error ? err : new Error(String(err))),
  });
}
