  | { type: "TreatmentCompleted"; treatmentId: string; subjectId: string }
  | { type: "TreatmentDroppedOut"; treatmentId: string; subjectId: string; reason: string }
  | { type: "TreatmentLabelChanged"; treatmentId: string; label: string };

