The write side speaks events — commands go through `decide` and land in the stream via `appendToStream`. The read side speaks views — queries hit a projection store that a subscription keeps in sync. The two sides share only the event DU; their state shapes are intentionally different, because writes optimise for invariants and reads optimise for retrieval.

```typescript
export type CourseState =
  | { status: "draft" }
  | { status: "open"; id: string; title: string }
  | { status: "closed"; id: string };

export type CourseCommand =
  | { type: "open"; id: string; title: string }
  | { type: "close" };

export type CourseEvent =
  | { type: "CourseOpened"; id: string; title: string }
  | { type: "CourseClosed" };

export class CourseError extends Error {}

export const initialState: CourseState = { status: "draft" };

export function evolve(s: CourseState, e: CourseEvent): CourseState {
  switch (e.type) {
    case "CourseOpened":
      return { status: "open", id: e.id, title: e.title };
    case "CourseClosed":
      if (s.status !== "open") return s;
      return { status: "closed", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: CourseCommand, s: CourseState): CourseEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "draft") throw new CourseError("EXISTS");
      return [{ type: "CourseOpened", id: c.id, title: c.title }];
    case "close":
      if (s.status !== "open") throw new CourseError("NOT_OPEN");
      return [{ type: "CourseClosed" }];
    default: { const _n: never = c; throw new CourseError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<CourseEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<CourseEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
}

// The catalog read store is eventually consistent with the event store.
export type CatalogEntry = Readonly<{ id: string; title: string; closed: boolean }>;

export interface CatalogReadStore {
  lookup(id: string): Promise<CatalogEntry | null>;
}

export async function handleCommand(
  streamName: string,
  command: CourseCommand,
  store: EventStore,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const next = decide(command, state);
  if (next.length === 0) return;
  await store.appendToStream(streamName, next, { expectedRevision: revision ?? "no_stream" });
}

export async function queryView(
  readStore: CatalogReadStore,
  id: string,
): Promise<CatalogEntry | null> {
  return readStore.lookup(id);
}
