import { setup, assign } from 'xstate';

type Card = { id: string; column: string };
type MoveLog = { id: string; from: string; to: string };

export const undoKanban = setup({
  types: {
    context: {} as { cards: Card[]; history: MoveLog[] },
    events: {} as { type: 'MOVE'; id: string; column: string } | { type: 'UNDO' },
  },
  actions: {
    applyMove: assign({
      cards: ({ context, event }) => {
        if (event.type !== 'MOVE') return context.cards;
        return context.cards.map((c) =>
          c.id === event.id ? { ...c, column: event.column } : c,
        );
      },
      history: ({ context, event }) => {
        if (event.type !== 'MOVE') return context.history;
        const card = context.cards.find((c) => c.id === event.id);
        if (!card) return context.history;
        return [...context.history, { id: event.id, from: card.column, to: event.column }];
      },
    }),
    undoMove: assign({
      cards: ({ context }) => {
        const last = context.history[context.history.length - 1];
        if (!last) return context.cards;
        return context.cards.map((c) => (c.id === last.id ? { ...c, column: last.from } : c));
      },
      history: ({ context }) => context.history.slice(0, -1),
    }),
  },
  guards: {
    hasHistory: ({ context }) => context.history.length > 0,
  },
}).createMachine({
  id: 'undoKanban',
  context: { cards: [], history: [] },
  on: {
    MOVE: { actions: 'applyMove' },
    UNDO: { guard: 'hasHistory', actions: 'undoMove' },
  },
});
