import { Effect } from "effect";

export type SoundtrackCueCommand =
  | { type: "schedule"; id: string; trackId: string; tcIn: number }
  | { type: "finalize" };

export type SoundtrackCueEvent =
  | { type: "SoundtrackCueScheduled"; id: string; trackId: string; tcIn: number }
  | { type: "SoundtrackCueFinalized" };

export type SoundtrackCueState =
  | { status: "none" }
  | { status: "scheduled"; id: string; trackId: string; tcIn: number }
  | { status: "finalized"; id: string };

export const initialState: SoundtrackCueState = { status: "none" };

export function evolve(state: SoundtrackCueState, event: SoundtrackCueEvent): SoundtrackCueState {
  switch (event.type) {
    case "SoundtrackCueScheduled":
      return { status: "scheduled", id: event.id, trackId: event.trackId, tcIn: event.tcIn };
    case "SoundtrackCueFinalized":
      if (state.status !== "scheduled") return state;
      return { status: "finalized", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: SoundtrackCueCommand, state: SoundtrackCueState): SoundtrackCueEvent[] {
  switch (command.type) {
    case "schedule":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "SoundtrackCueScheduled", id: command.id, trackId: command.trackId, tcIn: command.tcIn }];
    case "finalize":
      if (state.status !== "scheduled") throw new Error("NOT_SCHEDULED");
      return [{ type: "SoundtrackCueFinalized" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export function handle(
  store: EventStore<SoundtrackCueEvent>,
  streamName: string,
  command: SoundtrackCueCommand,
): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const loaded = yield* Effect.promise(() => store.readStream(streamName));
    const state = loaded.events.reduce(evolve, initialState);
    const events = decide(command, state);
    yield* Effect.promise(() => store.appendToStream(streamName, events, { expectedRevision: loaded.revision }));
  });
}
