export type FuelEfficiencyEvent =
  | { type: "FuelEfficiencyReportOpened"; data: { id: string; vehicleId: string } }
  | { type: "FuelEfficiencyRecorded"; data: { distanceKm: number; litres: number } }
  | { type: "FuelEfficiencyReportClosed"; data: { at: string } };

export type FuelEfficiencyReport = Readonly<{
  id: string;
  vehicleId: string;
  totalDistance: number;
  totalLitres: number;
  peakEfficiency: number;
  status: "open" | "closed";
  closedAt?: string;
}>;

export function when(
  current: Partial<FuelEfficiencyReport>,
  event: FuelEfficiencyEvent,
): Partial<FuelEfficiencyReport> {
  switch (event.type) {
    case "FuelEfficiencyReportOpened":
      return {
        id: event.data.id,
        vehicleId: event.data.vehicleId,
        totalDistance: 0,
        totalLitres: 0,
        peakEfficiency: 0,
        status: "open",
      };
    case "FuelEfficiencyRecorded": {
      const kmpl = event.data.litres > 0 ? event.data.distanceKm / event.data.litres : 0;
      return {
        ...current,
        totalDistance: (current.totalDistance ?? 0) + event.data.distanceKm,
        totalLitres: (current.totalLitres ?? 0) + event.data.litres,
        peakEfficiency: Math.max(current.peakEfficiency ?? 0, kmpl),
      };
    }
    case "FuelEfficiencyReportClosed":
      return { ...current, status: "closed", closedAt: event.data.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

function isReport(v: Partial<FuelEfficiencyReport>): v is FuelEfficiencyReport {
  return !!v.id && !!v.vehicleId && typeof v.totalDistance === "number" && !!v.status;
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const folded = events.reduce<Partial<A>>(reducer, {});
  if (!check(folded)) throw new Error("INVALID");
  return folded;
}

export function reportFrom(events: FuelEfficiencyEvent[]): FuelEfficiencyReport {
  return aggregateStream<FuelEfficiencyReport, FuelEfficiencyEvent>(events, when, isReport);
}
