  | { type: "pack"; packer: string }
  | { type: "dispatch"; carrier: string };

export class DomainError extends Error {}

export function evolve(s: FulfilmentState, e: FulfilmentEvent): FulfilmentState {
  switch (e.type) {
    case "OrderPicked": return { status: "picked", picker: e.picker };
    case "OrderPacked":
      if (s.status !== "picked") return s;
      return { status: "packed", picker: s.picker, packer: e.packer };
    case "OrderDispatched": return { status: "dispatched", carrier: e.carrier };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: FulfilmentCommand, s: FulfilmentState): FulfilmentEvent[] {
  switch (c.type) {
    case "pack":
      if (s.status !== "picked") throw new DomainError("NOT_PICKED");
      return [{ type: "OrderPacked", orderId: "ord", packer: c.packer }];
    case "dispatch":
      if (s.status !== "packed") throw new DomainError("NOT_PACKED");
      return [{ type: "OrderDispatched", orderId: "ord", carrier: c.carrier }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

