export type RouteOptimisationState =
  | { status: "none" }
  | { status: "planned"; id: string; stops: ReadonlyArray<string> }
  | { status: "rerouted"; id: string; stops: ReadonlyArray<string>; version: number }
  | { status: "completed"; id: string; stops: ReadonlyArray<string>; completedAt: string };

export type RouteOptimisationCommand =
  | { type: "plan"; id: string; stops: ReadonlyArray<string> }
  | { type: "reroute"; stops: ReadonlyArray<string> }
  | { type: "complete"; at: string };

export type RouteOptimisationEvent =
  | { type: "RoutePlanned"; id: string; stops: ReadonlyArray<string> }
  | { type: "RouteRerouted"; stops: ReadonlyArray<string> }
  | { type: "RouteCompleted"; at: string };

export class RouteError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const routeOptimisationDecider: Decider<RouteOptimisationCommand, RouteOptimisationEvent, RouteOptimisationState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "none") throw new RouteError("ALREADY_PLANNED");
        if (command.stops.length < 2) throw new RouteError("TOO_FEW_STOPS");
        return [{ type: "RoutePlanned", id: command.id, stops: command.stops }];
      case "reroute":
        if (state.status === "completed") throw new RouteError("COMPLETED");
        if (state.status === "none") throw new RouteError("NOT_PLANNED");
        return [{ type: "RouteRerouted", stops: command.stops }];
      case "complete":
        if (state.status === "completed") throw new RouteError("ALREADY_COMPLETED");
        if (state.status === "none") throw new RouteError("NOT_PLANNED");
        return [{ type: "RouteCompleted", at: command.at }];
      default: { const _n: never = command; throw new RouteError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RoutePlanned":
        return { status: "planned", id: event.id, stops: event.stops };
      case "RouteRerouted":
        if (state.status === "none" || state.status === "completed") return state;
        return { status: "rerouted", id: state.id, stops: event.stops, version: (state.status === "rerouted" ? state.version : 1) + 1 };
      case "RouteCompleted":
        if (state.status === "none" || state.status === "completed") return state;
        return { status: "completed", id: state.id, stops: state.stops, completedAt: event.at };
      default: { const _n: never = event; return state; }
    }
  },
};
