import { Effect } from 'effect';

type AlbumEvent = { type: 'Released'; at: string } | { type: 'TrackAdded'; title: string };
interface ReadEvent { readonly event: AlbumEvent; readonly position: bigint }

interface Subscriber {
  subscribe(from: bigint | null): Promise<readonly ReadEvent[]>;
}

interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

type View = { readonly tracks: number; readonly released: boolean };
const emptyView: View = { tracks: 0, released: false };

function project(view: View, event: AlbumEvent): View {
  switch (event.type) {
    case 'TrackAdded': return { ...view, tracks: view.tracks + 1 };
    case 'Released': return { ...view, released: true };
    default: { const _e: never = event; return _e; }
  }
}

export const runAlbumSubscription = (sub: Subscriber, cps: CheckpointStore, name: string) =>
  Effect.gen(function* () {
    const start = yield* Effect.promise(() => cps.read(name));
    const events = yield* Effect.promise(() => sub.subscribe(start));
    let view: View = emptyView;
    for (const { event, position } of events) {
      view = project(view, event);
      yield* Effect.promise(() => cps.write(name, position));
    }
    return view;
  });
