export type DomainEvent =
  | { type: "ProcessingLineReserved"; lineId: string; batchId: string }
  | { type: "ProcessingLineReleased"; lineId: string }
  | { type: "ProcessingLineInspected"; lineId: string; by: string };

export type IntegrationEvent =
  | { schema: "processing.line-reserved.v1"; payload: { lineId: string; batchId: string } }
  | { schema: "processing.line-released.v1"; payload: { lineId: string } };

export function translate(event: DomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "ProcessingLineReserved":
      return { schema: "processing.line-reserved.v1", payload: { lineId: event.lineId, batchId: event.batchId } };
    case "ProcessingLineReleased":
      return { schema: "processing.line-released.v1", payload: { lineId: event.lineId } };
    case "ProcessingLineInspected":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface OutboxRow {
  readonly id: string;
  readonly payload: IntegrationEvent;
  readonly publishedAt: string | null;
}

export interface TxConn {
  insertOutboxRow(row: OutboxRow): Promise<void>;
  appendToStream(stream: string, events: DomainEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface Transactor {
  transact<T>(fn: (conn: TxConn) => Promise<T>): Promise<T>;
}

// A separate publisher worker polls outbox rows with publishedAt === null,
// delivers them to the message bus, and marks them published.
export async function appendWithOutbox(
  tx: Transactor,
  stream: string,
  events: DomainEvent[],
  expected: bigint | "no_stream" | "any",
  newId: () => string,
): Promise<void> {
  await tx.transact(async (conn) => {
    await conn.appendToStream(stream, events, { expectedRevision: expected });
    for (const event of events) {
      const integration = translate(event);
      if (integration === null) continue;
      await conn.insertOutboxRow({ id: newId(), payload: integration, publishedAt: null });
    }
  });
}
