import { setup, assign, enqueueActions } from 'xstate';

interface Ctx { selected: string[]; done: number; clearOnFinish: boolean }
type Ev =
  | { type: 'TOGGLE'; id: string }
  | { type: 'SET_CLEAR'; on: boolean }
  | { type: 'RUN' }
  | { type: 'FINISHED' };

export const batchEnqueue = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    toggleItem: assign({
      selected: ({ context, event }) => {
        if (event.type !== 'TOGGLE') return context.selected;
        return context.selected.includes(event.id)
          ? context.selected.filter((x) => x !== event.id)
          : [...context.selected, event.id];
      }
    }),
    setFlag: assign({ clearOnFinish: ({ event }) => (event.type === 'SET_CLEAR' ? event.on : false) }),
    clear: assign({ selected: () => [], done: () => 0 }),
    stamp: assign({ done: ({ context }) => context.selected.length })
  },
  guards: {
    shouldClear: ({ context }) => context.clearOnFinish
  }
}).createMachine({
  id: 'batchEnqueue',
  context: { selected: [], done: 0, clearOnFinish: true },
  initial: 'selecting',
  states: {
    selecting: {
      on: { TOGGLE: { actions: 'toggleItem' }, SET_CLEAR: { actions: 'setFlag' }, RUN: 'executing' }
    },
    executing: {
      on: {
        FINISHED: {
          target: 'idle',
          actions: enqueueActions(({ enqueue, check }) => {
            enqueue('stamp');
            if (check('shouldClear')) enqueue('clear');
