interface Step { selector: string; text: string }
interface Ctx { steps: readonly Step[]; index: number }
type Ev = { type: 'NEXT' } | { type: 'PREV' } | { type: 'END' };

export const highlightTour = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasNext: ({ context }) => context.index < context.steps.length - 1,
    hasPrev: ({ context }) => context.index > 0
  },
  actions: {
    next: assign({ index: ({ context }) => context.index + 1 }),
    prev: assign({ index: ({ context }) => context.index - 1 })
  }
