// Write side — authoritative event store.
export type BatchCommand = { type: "approve"; id: string; at: string };
export type BatchEvent = { type: "BatchApproved"; id: string; at: string };
export type BatchState = { status: "sampling"; id: string; samples: number } | { status: "approved"; id: string };

export function evolve(state: BatchState, event: BatchEvent): BatchState {
  switch (event.type) {
    case "BatchApproved":
      return { status: "approved", id: event.id };
    default: { const _n: never = event.type; return state; }
  }
}

export function decide(c: BatchCommand, s: BatchState): BatchEvent[] {
  if (c.type === "approve") {
    if (s.status !== "sampling") throw new Error("NOT_SAMPLING");
    return [{ type: "BatchApproved", id: c.id, at: c.at }];
  }
  const _n: never = c.type;
  throw new Error("UNKNOWN");
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: BatchEvent; revision: bigint }>;
  appendToStream(stream: string, events: BatchEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handleCommand(cmd: BatchCommand, ctx: { stream: string; store: EventStore }): Promise<void> {
  let state: BatchState = { status: "sampling", id: "", samples: 0 };
  let revision: ExpectedRevision = "no_stream";
  for await (const { event, revision: r } of ctx.store.readStream(ctx.stream)) {
    state = evolve(state, event);
    revision = r;
  }
  await ctx.store.appendToStream(ctx.stream, decide(cmd, state), { expectedRevision: revision });
}

// Read side — eventually consistent with the event store.
export interface BatchViewRow { id: string; approved: boolean; }
export interface ReadStore { get(id: string): Promise<BatchViewRow | null>; }
export async function queryView(id: string, reads: ReadStore): Promise<BatchViewRow | null> {
  return reads.get(id);
}
