Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
import { Effect } from "effect";

export type SubstitutionState =
  | { status: "pending"; matchId: string }
  | { status: "applied"; matchId: string; out: string; in: string; minute: number };

export type SubstitutionCommand =
  | { type: "plan"; matchId: string }
  | { type: "apply"; out: string; in: string; minute: number };

export type SubstitutionEvent =
  | { type: "SubstitutionPlanned"; matchId: string }
  | { type: "SubstitutionApplied"; out: string; in: string; minute: number };

export const initialSubstitution: SubstitutionState = { status: "pending", matchId: "" };

export function decide(c: SubstitutionCommand, s: SubstitutionState): SubstitutionEvent[] {
  switch (c.type) {
    case "plan":
      return [{ type: "SubstitutionPlanned", matchId: c.matchId }];
    case "apply":
      if (s.status !== "pending") throw new Error("ALREADY_APPLIED");
      if (c.minute < 0 || c.minute > 120) throw new Error("INVALID_MINUTE");
      return [{ type: "SubstitutionApplied", out: c.out, in: c.in, minute: c.minute }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: SubstitutionState, e: SubstitutionEvent): SubstitutionState {
  switch (e.type) {
    case "SubstitutionPlanned":
      return { status: "pending", matchId: e.matchId };
    case "SubstitutionApplied":
      if (s.status !== "pending") return s;
      return { status: "applied", matchId: s.matchId, out: e.out, in: e.in, minute: e.minute };
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: SubstitutionEvent }>>;
  appendToStream(stream: string, events: readonly SubstitutionEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export function handle(store: EventStore, stream: string, command: SubstitutionCommand) {
  return Effect.gen(function* () {
    const stored = yield* Effect.promise(() => store.readStream(stream));
    const state = stored.reduce<SubstitutionState>((s, { event }) => evolve(s, event), initialSubstitution);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const events = decide(command, state);
    yield* Effect.promise(() => store.appendToStream(stream, events, { expectedRevision: expected }));
  });
}
```

