```typescript
export type FeedingRegimeState =
  | { status: "none" }
  | { status: "defined"; id: string; kcalPerDay: number }
  | { status: "feeding"; id: string; kcalPerDay: number; startedAt: string }
  | { status: "paused"; id: string; kcalPerDay: number; pausedAt: string }
  | { status: "ended"; id: string; endedAt: string };

export type FeedingRegimeCommand =
  | { type: "define"; id: string; kcalPerDay: number }
  | { type: "startFeeding"; at: string }
  | { type: "pauseFeeding"; at: string }
  | { type: "endRegime"; at: string };

export type FeedingRegimeEvent =
  | { type: "FeedingRegimeDefined"; id: string; kcalPerDay: number }
  | { type: "FeedingRegimeStarted"; at: string }
  | { type: "FeedingRegimePaused"; at: string }
  | { type: "FeedingRegimeEnded"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const feedingRegimeDecider: Decider<FeedingRegimeCommand, FeedingRegimeEvent, FeedingRegimeState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "define":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.kcalPerDay <= 0) throw new DomainError("BAD_KCAL");
        return [{ type: "FeedingRegimeDefined", id: command.id, kcalPerDay: command.kcalPerDay }];
      case "startFeeding":
        if (state.status !== "defined" && state.status !== "paused") throw new DomainError("BAD_STATE");
        return [{ type: "FeedingRegimeStarted", at: command.at }];
      case "pauseFeeding":
        if (state.status !== "feeding") throw new DomainError("NOT_FEEDING");
        return [{ type: "FeedingRegimePaused", at: command.at }];
      case "endRegime":
        if (state.status === "ended" || state.status === "none") throw new DomainError("BAD_STATE");
        return [{ type: "FeedingRegimeEnded", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FeedingRegimeDefined":
        return { status: "defined", id: event.id, kcalPerDay: event.kcalPerDay };
      case "FeedingRegimeStarted":
        if (state.status !== "defined" && state.status !== "paused") return state;
        return { status: "feeding", id: state.id, kcalPerDay: state.kcalPerDay, startedAt: event.at };
      case "FeedingRegimePaused":
        if (state.status !== "feeding") return state;
        return { status: "paused", id: state.id, kcalPerDay: state.kcalPerDay, pausedAt: event.at };
      case "FeedingRegimeEnded":
        if (state.status === "ended" || state.status === "none") return state;
        return { status: "ended", id: state.id, endedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
