A command handler orchestrates but does not decide. It reads the stream to rebuild state, asks the pure decide function for events, and appends them with the last-seen revision as expectedRevision.

```typescript
export type ReadingGroupEvent = { type: "Created"; id: string } | { type: "Joined" } | { type: "Completed" };
export type ReadingGroupCommand = { type: "create"; id: string } | { type: "join" } | { type: "complete" };
export type ReadingGroupState = { id: string; members: number; done: boolean };

const initial: ReadingGroupState = { id: "", members: 0, done: false };

function evolve(state: ReadingGroupState, event: ReadingGroupEvent): ReadingGroupState {
  switch (event.type) {
    case "Created":
      return { id: event.id, members: 0, done: false };
    case "Joined":
      return { ...state, members: state.members + 1 };
    case "Completed":
      return { ...state, done: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(cmd: ReadingGroupCommand, state: ReadingGroupState): ReadingGroupEvent[] {
  switch (cmd.type) {
    case "create":
      return state.id ? [] : [{ type: "Created", id: cmd.id }];
    case "join":
      return state.done ? [] : [{ type: "Joined" }];
    case "complete":
      return state.done ? [] : [{ type: "Completed" }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export interface EventStore {
  readStream(n: string): AsyncIterable<{ event: ReadingGroupEvent; revision: bigint }>;
  appendToStream(
    n: string,
    es: ReadonlyArray<ReadingGroupEvent>,
    o: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export async function handleCommand(
  command: ReadingGroupCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initial;
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  const events = decide(command, state);
  if (events.length > 0) {
    await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
  }
}
