  | { type: 'SetlistLocked' };

type SetlistCommand =
  | { type: 'QueueSong'; title: string }
  | { type: 'Lock' };

const initial: Setlist = { songs: [], locked: false };

function evolve(state: Setlist, event: SetlistEvent): Setlist {
  switch (event.type) {
    case 'SongQueued': return { ...state, songs: [...state.songs, event.title] };
    case 'SetlistLocked': return { ...state, locked: true };
    default: { const _e: never = event; return _e; }
