      return [{ type: 'SongQueued', title: cmd.title }];
    case 'Lock':
      return state.locked ? [] : [{ type: 'SetlistLocked' }];
    default: { const _e: never = cmd; return _e; }
  }
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: SetlistEvent; revision: bigint }>;
  appendToStream(s: string, evs: readonly SetlistEvent[], opts: { expectedRevision: bigint | 'no_stream' | 'any' }): Promise<void>;
}

export class ConcurrencyConflict extends Error {}

export async function handle(stream: string, cmd: SetlistCommand, store: EventStore): Promise<void> {
  let state = initial;
  let rev: bigint | 'no_stream' = 'no_stream';
  for await (const { event, revision } of store.readStream(stream)) {
    state = evolve(state, event);
    rev = revision;
  }
  try {
    await store.appendToStream(stream, decide(cmd, state), { expectedRevision: rev });
  } catch {
    throw new ConcurrencyConflict('setlist stream moved');
  }
}
```

