export type CourierFeedEvent =
  | { type: "CourierOnboarded"; courierId: string; name: string }
  | { type: "CourierWentOnline"; courierId: string }
  | { type: "CourierWentOffline"; courierId: string }
  | { type: "CourierOffboarded"; courierId: string };

type Status = "online" | "offline" | "offboarded";

export interface DashboardView {
  readonly onlineCount: number;
  readonly offlineCount: number;
  readonly couriers: Readonly<Record<string, { name: string; status: Status }>>;
}

export const emptyView: DashboardView = { onlineCount: 0, offlineCount: 0, couriers: {} };

function setStatus(view: DashboardView, courierId: string, status: Status, name?: string): DashboardView {
  const prev = view.couriers[courierId];
  if (!prev && name === undefined) return view;
  const online = view.onlineCount + (status === "online" ? 1 : 0) - (prev?.status === "online" ? 1 : 0);
  const offline = view.offlineCount + (status === "offline" ? 1 : 0) - (prev?.status === "offline" ? 1 : 0);
  return {
    onlineCount: online,
    offlineCount: offline,
    couriers: { ...view.couriers, [courierId]: { name: prev?.name ?? name ?? courierId, status } },
  };
}

export function project(view: DashboardView, event: CourierFeedEvent): DashboardView {
  switch (event.type) {
    case "CourierOnboarded":
      return setStatus(view, event.courierId, "offline", event.name);
    case "CourierWentOnline":
      return setStatus(view, event.courierId, "online");
    case "CourierWentOffline":
      return setStatus(view, event.courierId, "offline");
    case "CourierOffboarded":
      return setStatus(view, event.courierId, "offboarded");
    default: { const _n: never = event; return view; }
  }
}
