export type DomainEvent =
  | { type: "DeliveryDispatched"; id: string; courier: string }
  | { type: "DeliveryDelivered"; id: string; at: string }
  | { type: "DeliveryFailed"; id: string; reason: string }
  | { type: "DeliveryArchived"; id: string };

export type IntegrationEvent =
  | { schema: "delivery.delivered.v1"; payload: { deliveryId: string; at: string } }
  | { schema: "delivery.failed.v1"; payload: { deliveryId: string; reason: string } };

export function translate(event: DomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "DeliveryDelivered":
      return { schema: "delivery.delivered.v1", payload: { deliveryId: event.id, at: event.at } };
    case "DeliveryFailed":
      return { schema: "delivery.failed.v1", payload: { deliveryId: event.id, reason: event.reason } };
    case "DeliveryDispatched":
    case "DeliveryArchived":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export type OutboxView = Readonly<{ pending: ReadonlyArray<IntegrationEvent> }>;

export const emptyOutbox: OutboxView = { pending: [] };

export function project(view: OutboxView, event: DomainEvent): OutboxView {
  const translated = translate(event);
  if (translated === null) return view;
  return { pending: [...view.pending, translated] };
}

export function outboxFrom(events: DomainEvent[]): OutboxView {
  return events.reduce(project, emptyOutbox);
}
