export type ManuscriptEvent =
  | { type: "ManuscriptStarted"; id: string; title: string }
  | { type: "ChapterAppended"; id: string; chapterId: string };

export interface ManuscriptView {
  readonly items: Readonly<Record<string, { title: string; chapters: ReadonlyArray<string> }>>;
}

export const emptyView: ManuscriptView = { items: {} };

export function project(view: ManuscriptView, event: ManuscriptEvent): ManuscriptView {
  switch (event.type) {
    case "ManuscriptStarted":
      return { items: { ...view.items, [event.id]: { title: event.title, chapters: [] } } };
    case "ChapterAppended": {
      const current = view.items[event.id];
      if (!current) return view;
      return { items: { ...view.items, [event.id]: { ...current, chapters: [...current.chapters, event.chapterId] } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface Batch<E> { readonly events: ReadonlyArray<E>; readonly nextCursor: bigint; readonly done: boolean; }
export interface EventStore<E> {
  readBatch(from: bigint, batchSize: number): Promise<Batch<E>>;
}
export interface Persist { (view: ManuscriptView, cursor: bigint): Promise<void>; }

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  store: EventStore<ManuscriptEvent>;
  persist: Persist;
}

export async function rebuild(opts: RebuildOptions): Promise<void> {
  let cursor = opts.from;
  let view: ManuscriptView = emptyView;
  for (;;) {
    const batch = await opts.store.readBatch(cursor, opts.batchSize);
    for (const e of batch.events) view = project(view, e);
    cursor = batch.nextCursor;
    await opts.persist(view, cursor);
    if (batch.done) return;
  }
}
