```typescript
export type PullRequestState =
  | { status: "none" }
  | { status: "open"; id: string; branch: string; approvals: number }
  | { status: "approved"; id: string; branch: string; approvers: string[] }
  | { status: "merged"; id: string; mergedAt: string }
  | { status: "closed"; id: string; reason: string };

export type PullRequestCommand =
  | { type: "open"; id: string; branch: string }
  | { type: "approve"; reviewer: string }
  | { type: "merge"; at: string }
  | { type: "close"; reason: string };

export type PullRequestEvent =
  | { type: "PullRequestOpened"; id: string; branch: string }
  | { type: "PullRequestApproved"; reviewer: string }
  | { type: "PullRequestMerged"; at: string }
  | { type: "PullRequestClosed"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const pullRequestDecider: Decider<PullRequestCommand, PullRequestEvent, PullRequestState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("PR_EXISTS");
        return [{ type: "PullRequestOpened", id: command.id, branch: command.branch }];
      case "approve":
        if (state.status === "merged") throw new DomainError("ALREADY_MERGED");
        if (state.status === "closed") throw new DomainError("ALREADY_CLOSED");
        if (state.status === "none") throw new DomainError("NOT_OPEN");
        return [{ type: "PullRequestApproved", reviewer: command.reviewer }];
      case "merge":
        if (state.status !== "approved") throw new DomainError("NOT_APPROVED");
        return [{ type: "PullRequestMerged", at: command.at }];
      case "close":
        if (state.status === "merged") throw new DomainError("ALREADY_MERGED");
        return [{ type: "PullRequestClosed", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PullRequestOpened":
        return { status: "open", id: event.id, branch: event.branch, approvals: 0 };
      case "PullRequestApproved":
        if (state.status === "open") {
          const approvals = state.approvals + 1;
          if (approvals >= 2) return { status: "approved", id: state.id, branch: state.branch, approvers: [event.reviewer] };
          return { ...state, approvals };
        }
        if (state.status === "approved") return { ...state, approvers: [...state.approvers, event.reviewer] };
        return state;
      case "PullRequestMerged":
        if (state.status !== "approved") return state;
        return { status: "merged", id: state.id, mergedAt: event.at };
      case "PullRequestClosed":
        if (state.status === "none" || state.status === "merged") return state;
        return { status: "closed", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
