```typescript
type FeedEvent =
  | { type: 'ChannelCreated'; channelId: string; name: string; at: string }
  | { type: 'MessagePosted'; channelId: string; at: string };

type FeedView = Readonly<{
  channelId: string;
  name: string;
  messageCount: number;
  lastAt: string | null;
}>;

interface EventSource {
  read(from: bigint, batchSize: number): Promise<{ events: { event: FeedEvent; revision: bigint }[]; nextFrom: bigint | null }>;
}

interface FeedStore {
  loadOrEmpty(channelId: string): Promise<FeedView>;
  save(views: readonly FeedView[], cursor: bigint): Promise<void>;
}

function project(view: FeedView, event: FeedEvent): FeedView {
  switch (event.type) {
    case 'ChannelCreated':
      return { channelId: event.channelId, name: event.name, messageCount: 0, lastAt: event.at };
    case 'MessagePosted':
      return { ...view, messageCount: view.messageCount + 1, lastAt: event.at };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function rebuildFeed(opts: {
  from: bigint;
  batchSize: number;
  source: EventSource;
  store: FeedStore;
  onProgress: (revision: bigint) => void;
}): Promise<void> {
  let cursor: bigint | null = opts.from;
  while (cursor !== null) {
    const { events, nextFrom } = await opts.source.read(cursor, opts.batchSize);
    const staged = new Map<string, FeedView>();
    for (const { event } of events) {
      const current = staged.get(event.channelId) ?? (await opts.store.loadOrEmpty(event.channelId));
      staged.set(event.channelId, project(current, event));
    }
    const last = events[events.length - 1];
    if (last) {
      await opts.store.save(Array.from(staged.values()), last.revision);
      opts.onProgress(last.revision);
    }
    cursor = nextFrom;
  }
}
