      on: { REQUEST: { target: 'fetching', actions: assign({ city: ({ event }) => event.city }) } }
    },
    fetching: {
      invoke: {
        src: 'fetchWeather',
        input: ({ context }) => ({ city: context.city }),
        onDone: {
          target: 'stale',
          actions: assign({ data: ({ event }) => event.output, fetchedAt: () => Date.now() })
        },
        onError: {
          target: 'idle',
          actions: assign({ error: ({ event }) => String(event.error) })
        }
      }
    },
    stale: {
      after: { 60000: 'refreshing' },
      on: { REFRESH: 'refreshing' }
    },
    refreshing: {
      invoke: {
        src: 'fetchWeather',
        input: ({ context }) => ({ city: context.city }),
        onDone: {
          target: 'stale',
          actions: assign({ data: ({ event }) => event.output, fetchedAt: () => Date.now() })
        },
        onError: 'stale'
      }
    }
  }
});
