interface Ctx { typed: number; total: number; correct: number }

type Ev = { type: 'TYPE'; correct: boolean } | { type: 'DONE' };

export const typingMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    output: {} as { score: number }
  }
}).createMachine({
  id: 'typing',
  context: { typed: 0, total: 50, correct: 0 },
  initial: 'running',
  states: {
    running: {
      on: {
        TYPE: {
          actions: assign({
            typed: ({ context }) => context.typed + 1,
            correct: ({ context, event }) => context.correct + (event.correct ? 1 : 0)
          })
        },
        DONE: 'finished'
      }
    },
    finished: { type: 'final' }
  },
  output: ({ context }) => ({
    score: context.total === 0 ? 0 : Math.round((context.correct / context.total) * 100)
  })
});
