type PlaylistEvent = { type: 'SongAdded'; songId: string };
type PlaylistCommand = { type: 'AddSong'; songId: string };
type PlaylistState = { readonly songs: readonly string[] };

const initialState: PlaylistState = { songs: [] };

function evolve(state: PlaylistState, event: PlaylistEvent): PlaylistState {
  switch (event.type) {
    case 'SongAdded': return { songs: [...state.songs, event.songId] };
    default: { const _e: never = event.type; return state; }
  }
}

function decide(cmd: PlaylistCommand): PlaylistEvent[] {
  return [{ type: 'SongAdded', songId: cmd.songId }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<PlaylistEvent>;
  appendToStream(s: string, evs: readonly PlaylistEvent[]): Promise<void>;
}

interface ReadStore {
  get(id: string): Promise<{ readonly count: number } | null>;
}

export async function handleCommand(id: string, cmd: PlaylistCommand, store: EventStore): Promise<void> {
  let state = initialState;
  for await (const ev of store.readStream(`playlist-${id}`)) state = evolve(state, ev);
  await store.appendToStream(`playlist-${id}`, decide(cmd));
}

// The read store is eventually consistent with the event store — projections catch up asynchronously.
export async function queryView(id: string, rs: ReadStore): Promise<{ readonly count: number } | null> {
  return rs.get(id);
}
