export type ControlArmEvent =
  | { type: "ControlArmSubjectEnrolled"; armId: string; subjectId: string }
  | { type: "ControlArmSubjectConverted"; armId: string; subjectId: string; at: string }
  | { type: "ControlArmRenamed"; armId: string; name: string };

export type ControlArmView = Readonly<{
  byArm: Readonly<Record<string, { enrolled: number; converted: number } | undefined>>;
}>;

export const emptyView: ControlArmView = { byArm: {} };

function bump(view: ControlArmView, armId: string, key: "enrolled" | "converted"): ControlArmView {
  const current = view.byArm[armId] ?? { enrolled: 0, converted: 0 };
  const next = { ...current, [key]: current[key] + 1 };
  return { byArm: { ...view.byArm, [armId]: next } };
}

export function project(view: ControlArmView, event: ControlArmEvent): ControlArmView {
  switch (event.type) {
    case "ControlArmSubjectEnrolled":
      return bump(view, event.armId, "enrolled");
    case "ControlArmSubjectConverted":
      return bump(view, event.armId, "converted");
    case "ControlArmRenamed":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function aggregateStream(events: ControlArmEvent[]): ControlArmView {
  return events.reduce<ControlArmView>(project, emptyView);
}
