```typescript
export type StoredEvent<E> = { type: string; data: E };
export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readLastRevision(stream: string): Promise<bigint | null>;
  appendToStream<E>(
    stream: string,
    events: ReadonlyArray<StoredEvent<E>>,
    options: { expectedRevision: ExpectedRevision },
  ): Promise<AppendOutcome>;
}

export type AppendOutcome =
  | { ok: true; nextRevision: bigint }
  | { ok: false; actual: bigint | null };

export class ConcurrencyConflict extends Error {
  constructor(
    public readonly stream: string,
    public readonly expected: ExpectedRevision,
    public readonly actual: bigint | null,
  ) {
    super("CONCURRENCY_CONFLICT");
  }
}

export async function appendWithOCC<E>(
  store: EventStore,
  stream: string,
  events: ReadonlyArray<StoredEvent<E>>,
): Promise<bigint> {
  const rev = await store.readLastRevision(stream);
  const expectedRevision: ExpectedRevision = rev ?? "no_stream";
  const outcome = await store.appendToStream(stream, events, { expectedRevision });
  if (!outcome.ok) throw new ConcurrencyConflict(stream, expectedRevision, outcome.actual);
  return outcome.nextRevision;
}
```

```typescript
export type SagaInput =
  | { type: "CampaignFlightLaunched"; flightId: string }
  | { type: "InventoryReserved"; flightId: string; reservationId: string }
  | { type: "BillingStarted"; flightId: string };

export type SagaCommand =
  | { type: "ReserveInventory"; flightId: string }
  | { type: "StartBilling"; flightId: string; reservationId: string };

export type SagaStatus = "idle" | "reservingInventory" | "billing" | "done";

export interface SagaState {
  readonly status: SagaStatus;
  readonly flightId: string | null;
  readonly reservationId: string | null;
}

export const initialSaga: SagaState = { status: "idle", flightId: null, reservationId: null };

export interface SagaStep {
  readonly nextState: SagaState;
  readonly command: SagaCommand | null;
}

export function react(state: SagaState, event: SagaInput): SagaStep {
  switch (event.type) {
    case "CampaignFlightLaunched":
      if (state.status !== "idle") return { nextState: state, command: null };
      return {
        nextState: { status: "reservingInventory", flightId: event.flightId, reservationId: null },
        command: { type: "ReserveInventory", flightId: event.flightId },
      };
    case "InventoryReserved":
      if (state.status !== "reservingInventory" || state.flightId !== event.flightId) {
        return { nextState: state, command: null };
      }
      return {
        nextState: { status: "billing", flightId: state.flightId, reservationId: event.reservationId },
        command: { type: "StartBilling", flightId: state.flightId, reservationId: event.reservationId },
      };
    case "BillingStarted":
      if (state.status !== "billing") return { nextState: state, command: null };
      return {
        nextState: { ...state, status: "done" },
        command: null,
      };
    default: {
      const _never: never = event;
      return { nextState: state, command: null };
    }
  }
}

export interface CommandBus {
  send(cmd: SagaCommand): Promise<void>;
}

export interface EventStore {
  subscribe(name: string): AsyncIterable<SagaInput>;
}

export async function runSaga(store: EventStore, bus: CommandBus, name: string): Promise<void> {
  let state = initialSaga;
  for await (const event of store.subscribe(name)) {
    const step = react(state, event);
    state = step.nextState;
    if (step.command) await bus.send(step.command);
  }
}
```

Tag every stored snapshot with its schema version. At load time, run upgraders in order until you reach CURRENT_VERSION, then assert the final shape. The stream itself never needs rewriting.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type EnrolmentV1 = { id: string; learner: string };
export type EnrolmentV2 = { id: string; learner: string; course: string };
export type EnrolmentV3 = {
  id: string;
  learner: string;
  course: string;
  status: "registered" | "confirmed" | "withdrawn";
};

export type CurrentEnrolment = EnrolmentV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: EnrolmentV1): EnrolmentV2 {
  return { ...s, course: "unknown" };
}

function v2Tov3(s: EnrolmentV2): EnrolmentV3 {
  return { ...s, status: "registered" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentEnrolment> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as EnrolmentV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as EnrolmentV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED");
  const out = s as CurrentEnrolment;
  if (!out.id || !out.learner) throw new UpgradeError("SHAPE");
  return { version: v, state: out };
}
```

A projection fans out a stream of domain events into a shape optimised for reads, not for writing. It is append-only: the projection function folds each event into the view, and the view's type is denormalised — flat fields, indexable identifiers, precomputed counts. evolve, by contrast, rebuilds an aggregate's internal state so decide can protect its invariants. The two share the event union but live on opposite sides of the CQRS boundary, and a single stream can feed many projections.

```typescript
export type WeatherWindowEvent =
  | { type: "WindowForecast"; windowId: string; from: string; to: string; quality: number }
  | { type: "WindowOpened"; windowId: string; at: string }
  | { type: "WindowClosed"; windowId: string; at: string };

export interface WindowRow {
  readonly windowId: string;
  readonly from: string;
  readonly to: string;
  readonly quality: number;
  readonly open: boolean;
}

export interface WeatherWindowView {
  readonly windows: ReadonlyArray<WindowRow>;
}

export const emptyView: WeatherWindowView = { windows: [] };

export function project(view: WeatherWindowView, event: WeatherWindowEvent): WeatherWindowView {
  switch (event.type) {
    case "WindowForecast": {
      const row: WindowRow = {
        windowId: event.windowId,
        from: event.from,
        to: event.to,
        quality: event.quality,
        open: false,
      };
      return { windows: [...view.windows, row] };
    }
    case "WindowOpened":
      return {
        windows: view.windows.map((w) => (w.windowId === event.windowId ? { ...w, open: true } : w)),
      };
    case "WindowClosed":
      return {
        windows: view.windows.map((w) => (w.windowId === event.windowId ? { ...w, open: false } : w)),
      };
    default: {
      const _never: never = event;
      return view;
    }
  }
}
