```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Job {
  id: string;
  payload: string;
}

interface QueueContext {
  queue: Job[];
  current: Job | null;
  processed: number;
}

type QueueEvent =
  | { type: 'ENQUEUE'; job: Job }
  | { type: 'DRAIN' };

const runJob = fromPromise<string, { job: Job }>(async ({ input }) => {
  await new Promise((r) => setTimeout(r, 10));
  return `done:${input.job.id}`;
});

export const queueWorkerMachine = setup({
  types: {
    context: {} as QueueContext,
    events: {} as QueueEvent
  },
  actors: { runJob },
  guards: {
    hasWork: ({ context }) => context.queue.length > 0
  },
  actions: {
    enqueue: assign({
      queue: ({ context, event }) =>
        event.type === 'ENQUEUE' ? [...context.queue, event.job] : context.queue
    }),
    takeNext: assign({
      current: ({ context }) => context.queue[0] ?? null,
      queue: ({ context }) => context.queue.slice(1)
    }),
    markDone: assign({
      current: () => null,
      processed: ({ context }) => context.processed + 1
    })
  }
}).createMachine({
  id: 'queue',
  context: { queue: [], current: null, processed: 0 },
  initial: 'idle',
  states: {
    idle: {
      always: [{ guard: 'hasWork', target: 'working', actions: 'takeNext' }],
      on: { ENQUEUE: { actions: 'enqueue' } }
    },
    working: {
      invoke: {
        src: 'runJob',
        input: ({ context }) => ({ job: context.current as Job }),
        onDone: { target: 'idle', actions: 'markDone' },
        onError: { target: 'idle', actions: 'markDone' }
      },
      on: { ENQUEUE: { actions: 'enqueue' } }
    }
  }
});
