export type PollingStationEvent =
  | { type: "StationOpened"; stationId: string; openedAt: string }
  | { type: "BallotCast"; stationId: string }
  | { type: "StationClosed"; stationId: string; closedAt: string }
  | { type: "StaffRotated"; stationId: string };

export type TurnoutEntry = {
  opened: string | null;
  closed: string | null;
  ballotsCast: number;
};

export type TurnoutView = {
  stations: Record<string, TurnoutEntry>;
};

export const emptyTurnout: TurnoutView = { stations: {} };

function entry(view: TurnoutView, id: string): TurnoutEntry {
  return view.stations[id] ?? { opened: null, closed: null, ballotsCast: 0 };
}

export function project(view: TurnoutView, event: PollingStationEvent): TurnoutView {
  switch (event.type) {
    case "StationOpened": {
      const e = entry(view, event.stationId);
      return { stations: { ...view.stations, [event.stationId]: { ...e, opened: event.openedAt } } };
    }
    case "BallotCast": {
      const e = entry(view, event.stationId);
      return { stations: { ...view.stations, [event.stationId]: { ...e, ballotsCast: e.ballotsCast + 1 } } };
    }
    case "StationClosed": {
      const e = entry(view, event.stationId);
      return { stations: { ...view.stations, [event.stationId]: { ...e, closed: event.closedAt } } };
    }
    case "StaffRotated":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function projectAll(events: PollingStationEvent[]): TurnoutView {
  return events.reduce(project, emptyTurnout);
}
