The cache is a `Record<key, value>` in context. On FETCH with a key, the machine first inspects the cache via an `always` path; if there's a hit it stays idle, otherwise it enters `loading`, which records the response under the key on success. This keeps the cache keys fully typed even though the shape is a plain object.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { key: string; cache: Record<string, string> };
type Ev = { type: 'FETCH'; key: string };

const load = fromPromise<string, { key: string }>(async ({ input }) => `value-for-${input.key}`);

export const keyedLoader = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { load },
  guards: {
    cached: ({ context }) => context.cache[context.key] !== undefined,
  },
}).createMachine({
  id: 'keyedLoader',
  context: { key: '', cache: {} },
  initial: 'idle',
  states: {
    idle: {
      on: {
        FETCH: {
          target: 'checking',
          actions: assign({ key: ({ event }) => event.key }),
