import { Effect } from "effect";

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface StoredEvent<E> { readonly position: bigint; readonly event: E }
export interface EventStore<E> { readFromStream(stream: string, from: bigint): AsyncIterable<StoredEvent<E>> }

export type ClinicalTrialEvent =
  | { type: "ParticipantEnrolled"; id: string }
  | { type: "ParticipantWithdrawn"; id: string };

export interface TrialView { readonly enrolled: number }
export const emptyView: TrialView = { enrolled: 0 };

export function project(v: TrialView, e: ClinicalTrialEvent): TrialView {
  switch (e.type) {
    case "ParticipantEnrolled": return { enrolled: v.enrolled + 1 };
    case "ParticipantWithdrawn": return { enrolled: Math.max(0, v.enrolled - 1) };
    default: { const _never: never = e; return v; }
  }
}

export const runSubscription = (
  name: string,
  stream: string,
  store: EventStore<ClinicalTrialEvent>,
  checkpoints: CheckpointStore,
  persist: (v: TrialView) => Promise<void>,
) =>
  Effect.gen(function* () {
    const start = (yield* Effect.tryPromise({ try: () => checkpoints.read(name), catch: (e) => new Error(String(e)) })) ?? 0n;
    let view: TrialView = emptyView;
    yield* Effect.tryPromise({
      try: async () => {
        for await (const stored of store.readFromStream(stream, start)) {
          view = project(view, stored.event);
          await persist(view);
          await checkpoints.write(name, stored.position);
        }
      },
      catch: (e) => new Error(String(e)),
    });
    return view;
  });
