export type RawProvisioningEvent =
  | { type: "ProvisioningOpened"; version: 1; data: { id: string; required: number } }
  | { type: "StockRecorded"; version: 1; data: { qty: number } }
  | { type: "StockRecorded"; version: 2; data: { quantity: number } }
  | { type: "ProvisioningFinalised"; version: 1; data: { finalisedAt: string } };

export type ProvisioningEvent =
  | { type: "ProvisioningOpened"; id: string; required: number }
  | { type: "StockRecorded"; quantity: number }
  | { type: "ProvisioningFinalised"; at: string };

export class UnknownEventError extends Error {
  constructor(public readonly rawType: string, public readonly rawVersion: number) {
    super(`unknown ${rawType}@${rawVersion}`);
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: RawProvisioningEvent): ProvisioningEvent {
  switch (raw.type) {
    case "ProvisioningOpened":
      if (raw.version === 1) return { type: "ProvisioningOpened", id: raw.data.id, required: raw.data.required };
      throw new UnknownEventError("ProvisioningOpened", 0);
    case "StockRecorded":
      if (raw.version === 1) return { type: "StockRecorded", quantity: raw.data.qty };
      if (raw.version === 2) return { type: "StockRecorded", quantity: raw.data.quantity };
      throw new UnknownEventError("StockRecorded", 0);
    case "ProvisioningFinalised":
      if (raw.version === 1) return { type: "ProvisioningFinalised", at: raw.data.finalisedAt };
      throw new UnknownEventError("ProvisioningFinalised", 0);
    default: {
      const _never: never = raw;
      throw new UnknownEventError("unknown", 0);
    }
  }
}

export function aggregate(raw: ReadonlyArray<RawProvisioningEvent>): ProvisioningEvent[] {
  return raw.map(upcast);
}
```

