  chef: "",
  stepsDone: 0,
  finishedAt: null,
};

export function when(state: CookingSessionAggregate, event: CookingSessionEvent): CookingSessionAggregate {
  switch (event.type) {
    case "CookingSessionStarted":
      return { id: event.id, chef: event.chef, stepsDone: 0, finishedAt: null };
    case "CookingStepLogged":
