A projection builds a denormalised read model targeted at queries, while evolve reconstructs the aggregate's own state for decision-making. Projections can cross aggregates and often ignore events they don't care about, whereas evolve is exhaustive over the aggregate's own event union.

```typescript
export type WaterQualityEvent =
  | { type: "WaterQualityLogOpened"; id: string }
  | { type: "WaterQualityReadingRecorded"; id: string; ph: number; tempC: number; at: string }
  | { type: "WaterQualityLogClosed"; id: string; at: string };

export interface LatestReading {
  readonly ph: number;
  readonly tempC: number;
  readonly at: string;
}

export interface LatestView {
  readonly byLog: Readonly<Record<string, LatestReading>>;
  readonly closed: ReadonlySet<string>;
}

export const emptyView: LatestView = {
  byLog: {},
  closed: new Set<string>(),
};

export function project(view: LatestView, event: WaterQualityEvent): LatestView {
  switch (event.type) {
    case "WaterQualityLogOpened":
      return view;
    case "WaterQualityReadingRecorded":
      return {
        ...view,
        byLog: {
          ...view.byLog,
          [event.id]: { ph: event.ph, tempC: event.tempC, at: event.at },
        },
      };
    case "WaterQualityLogClosed": {
      const next = new Set(view.closed);
      next.add(event.id);
      return { ...view, closed: next };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
```

```typescript
export type MortgageState =
  | { status: "draft" }
  | { status: "applied"; id: string; amount: number }
  | { status: "approved"; id: string; amount: number; approvedAt: string }
  | { status: "rejected"; id: string; reason: string };

export type MortgageCommand =
  | { type: "apply"; id: string; amount: number }
  | { type: "approve"; at: string }
  | { type: "reject"; reason: string };

export type MortgageEvent =
  | { type: "MortgageApplied"; id: string; amount: number }
  | { type: "MortgageApproved"; at: string }
  | { type: "MortgageRejected"; reason: string };

export class MortgageError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

// A Decider is a pure triple. `decide` validates commands and emits events;
// `evolve` folds an event into the next state. No I/O, no clocks, deterministic.
export const mortgageDecider: Decider<MortgageCommand, MortgageEvent, MortgageState> = {
  initialState: { status: "draft" },
  decide(c, s) {
    switch (c.type) {
      case "apply":
        if (s.status !== "draft") throw new MortgageError("ALREADY_APPLIED");
        if (c.amount <= 0) throw new MortgageError("INVALID_AMOUNT");
        return [{ type: "MortgageApplied", id: c.id, amount: c.amount }];
      case "approve":
        if (s.status === "rejected") throw new MortgageError("REJECTED");
        if (s.status !== "applied") throw new MortgageError("NOT_APPLIED");
        return [{ type: "MortgageApproved", at: c.at }];
      case "reject":
        if (s.status !== "applied") throw new MortgageError("NOT_APPLIED");
        return [{ type: "MortgageRejected", reason: c.reason }];
      default: { const _n: never = c; throw new MortgageError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "MortgageApplied":
        return { status: "applied", id: e.id, amount: e.amount };
      case "MortgageApproved":
        if (s.status !== "applied") return s;
        return { status: "approved", id: s.id, amount: s.amount, approvedAt: e.at };
      case "MortgageRejected":
        if (s.status !== "applied") return s;
        return { status: "rejected", id: s.id, reason: e.reason };
      default: { const _n: never = e; return s; }
    }
  },
};

