```typescript
export type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { readonly event: E; readonly revision: bigint; }

export interface AppendOptions { expectedRevision: ExpectedRevision; }
export interface AppendOutcome { kind: "ok"; nextRevision: bigint; }
export interface AppendConflict { kind: "conflict"; actualRevision: bigint | null; }

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream(stream: string, events: E[], opts: AppendOptions): Promise<AppendOutcome | AppendConflict>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly expected: ExpectedRevision, public readonly actual: bigint | null) {
    super("CONCURRENCY_CONFLICT");
    this.name = "ConcurrencyConflict";
  }
}

export type DocumentEvent =
  | { type: "DocumentCreated"; id: string; title: string }
  | { type: "DocumentSubmitted"; at: string };

export async function appendDocumentEvents(
  store: EventStore<DocumentEvent>,
  stream: string,
  events: DocumentEvent[],
): Promise<bigint> {
  const current = await store.readStream(stream);
  const expected: ExpectedRevision = current.length === 0
    ? "no_stream"
    : current[current.length - 1]!.revision;
  const result = await store.appendToStream(stream, events, { expectedRevision: expected });
  if (result.kind === "conflict") {
    throw new ConcurrencyConflict(expected, result.actualRevision);
  }
  return result.nextRevision;
}
```

```typescript
type BroadcastGroupCommand =
  | { type: 'CreateBroadcastGroup'; id: string; name: string }
  | { type: 'AddRecipient'; userId: string }
  | { type: 'SendBroadcast'; body: string; at: string };

type BroadcastGroupEvent =
  | { type: 'BroadcastGroupCreated'; id: string; name: string }
  | { type: 'RecipientAdded'; userId: string }
  | { type: 'BroadcastSent'; body: string; at: string };

type BroadcastGroupState =
  | { status: 'empty' }
  | { status: 'ready'; id: string; name: string; recipients: readonly string[] };

class BroadcastRuleError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const BroadcastGroupDecider: Decider<BroadcastGroupCommand, BroadcastGroupEvent, BroadcastGroupState> = {
  initialState: { status: 'empty' },
  decide(command, state) {
    switch (command.type) {
      case 'CreateBroadcastGroup':
        if (state.status !== 'empty') throw new BroadcastRuleError('exists');
        return [{ type: 'BroadcastGroupCreated', id: command.id, name: command.name }];
      case 'AddRecipient':
        if (state.status !== 'ready') throw new BroadcastRuleError('not ready');
        if (state.recipients.includes(command.userId)) return [];
        return [{ type: 'RecipientAdded', userId: command.userId }];
      case 'SendBroadcast':
        if (state.status !== 'ready') throw new BroadcastRuleError('not ready');
        if (state.recipients.length === 0) throw new BroadcastRuleError('no recipients');
        return [{ type: 'BroadcastSent', body: command.body, at: command.at }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'BroadcastGroupCreated':
        return { status: 'ready', id: event.id, name: event.name, recipients: [] };
      case 'RecipientAdded':
        return state.status === 'ready'
          ? { ...state, recipients: [...state.recipients, event.userId] }
          : state;
      case 'BroadcastSent':
        return state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
