}

interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export const runPlaylistSubscription = (sub: Subscriber, cps: CheckpointStore, name: string) =>
  Effect.gen(function* () {
    const start = yield* Effect.promise(() => cps.read(name));
    const events = yield* Effect.promise(() => sub.subscribe(start));
    let view: View = { count: 0 };
    for (const { event, position } of events) {
      view = project(view, event);
      yield* Effect.promise(() => cps.write(name, position));
    }
    return view;
  });
