```typescript
import { Effect } from 'effect';

type MessageCommand =
  | { type: 'PostMessage'; id: string; authorId: string; body: string }
  | { type: 'EditMessage'; body: string };

type MessageEvent =
  | { type: 'MessagePosted'; id: string; authorId: string; body: string }
  | { type: 'MessageEdited'; body: string };

type MessageState =
  | { status: 'draft' }
  | { status: 'live'; id: string; body: string };

const initialState: MessageState = { status: 'draft' };

function evolve(state: MessageState, event: MessageEvent): MessageState {
  switch (event.type) {
    case 'MessagePosted':
      return { status: 'live', id: event.id, body: event.body };
    case 'MessageEdited':
      return state.status === 'live' ? { ...state, body: event.body } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(command: MessageCommand, state: MessageState): MessageEvent[] {
  switch (command.type) {
    case 'PostMessage':
      if (state.status !== 'draft') throw new Error('already posted');
      return [{ type: 'MessagePosted', id: command.id, authorId: command.authorId, body: command.body }];
    case 'EditMessage':
      if (state.status !== 'live') throw new Error('not live');
      return [{ type: 'MessageEdited', body: command.body }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

interface EventStore {
  load(stream: string): Promise<{ events: MessageEvent[]; revision: bigint | 'no_stream' }>;
  append(stream: string, events: readonly MessageEvent[], expectedRevision: bigint | 'no_stream'): Promise<void>;
}

export function handleMessage(store: EventStore, streamName: string, command: MessageCommand) {
  return Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => store.load(streamName));
    const state = events.reduce(evolve, initialState);
    const newEvents = decide(command, state);
    yield* Effect.promise(() => store.append(streamName, newEvents, revision));
  });
}
