```typescript
export interface ToolingEvent { type: string; payload: unknown; }

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: ToolingEvent; revision: bigint }>;
  appendToStream(
    stream: string,
    events: ToolingEvent[],
    opts: { expectedRevision: ExpectedRevision }
  ): Promise<{ ok: boolean; nextRevision?: bigint; actualRevision?: bigint | "no_stream" }>;
}

export class ConcurrencyConflict extends Error {
  constructor(
    readonly stream: string,
    readonly expected: ExpectedRevision,
    readonly actual: bigint | "no_stream"
  ) {
    super("CONCURRENCY_CONFLICT");
    this.name = "ConcurrencyConflict";
  }
}

export async function writeToolingEvents(
  store: EventStore,
  stream: string,
  events: ToolingEvent[]
): Promise<bigint> {
  let revision: ExpectedRevision = "no_stream";
  for await (const { revision: r } of store.readStream(stream)) {
    revision = r;
  }
  const outcome = await store.appendToStream(stream, events, { expectedRevision: revision });
  if (!outcome.ok) {
    throw new ConcurrencyConflict(stream, revision, outcome.actualRevision ?? "no_stream");
  }
  if (outcome.nextRevision === undefined) throw new Error("NO_NEXT");
  return outcome.nextRevision;
}
```

Use a small discriminated union of error classes. decide() throws typed instances; the caller switches on `instanceof` or on a `kind` tag.

```typescript
export class DomainError extends Error {
  readonly kind: string = "DomainError";
}
export class InvalidTransition extends DomainError {
  override readonly kind = "InvalidTransition" as const;
  constructor(public from: string, public command: string) {
    super(`cannot ${command} from ${from}`);
  }
}
export class AlreadyFinalized extends DomainError {
  override readonly kind = "AlreadyFinalized" as const;
  constructor() { super("ballot already finalized"); }
}

export type BallotState =
  | { status: "issued" }
  | { status: "submitted" };

export type BallotCommand =
  | { type: "submit"; at: string }
  | { type: "retract" };

export type BallotEvent =
  | { type: "Submitted"; at: string }
  | { type: "Retracted" };

export function decide(c: BallotCommand, s: BallotState): BallotEvent[] {
  switch (c.type) {
    case "submit":
      if (s.status !== "issued") throw new InvalidTransition(s.status, c.type);
      return [{ type: "Submitted", at: c.at }];
    case "retract":
      if (s.status === "submitted") throw new AlreadyFinalized();
      return [{ type: "Retracted" }];
    default: {
      const _: never = c;
      return _;
    }
  }
}
```

Upcasting keeps history immutable. You never rewrite past events; instead the read path pattern-matches on {type, version} and projects each stored shape forward into the current shape. Decide and evolve then see one union only.

```typescript
interface CookingSessionStartedV1 {
  type: "CookingSessionStarted";
  version: 1;
  id: string;
}

interface CookingSessionStartedV2 {
  type: "CookingSessionStarted";
  version: 2;
  id: string;
  chefId: string;
}

interface CookingStepLoggedV1 {
  type: "CookingStepLogged";
  version: 1;
}

export type StoredCookingEvent = CookingSessionStartedV1 | CookingSessionStartedV2 | CookingStepLoggedV1;
export type CookingEvent = CookingSessionStartedV2 | CookingStepLoggedV1;

export class UnknownEventError extends Error {
  constructor(public readonly detail: unknown) {
    super("unknown stored cooking event");
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: unknown): CookingEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError(raw);
  const candidate = raw as { type?: unknown; version?: unknown };
  if (candidate.type === "CookingSessionStarted" && candidate.version === 1) {
    const v1 = raw as CookingSessionStartedV1;
    return { type: "CookingSessionStarted", version: 2, id: v1.id, chefId: v1.id };
  }
  if (candidate.type === "CookingSessionStarted" && candidate.version === 2) {
    return raw as CookingSessionStartedV2;
  }
  if (candidate.type === "CookingStepLogged" && candidate.version === 1) {
    return raw as CookingStepLoggedV1;
  }
  throw new UnknownEventError(raw);
}

export interface CookingReadModel {
  readonly id: string;
  readonly chefId: string;
  readonly steps: number;
}

export function when(state: CookingReadModel, event: CookingEvent): CookingReadModel {
  switch (event.type) {
    case "CookingSessionStarted":
      return { id: event.id, chefId: event.chefId, steps: 0 };
    case "CookingStepLogged":
      return { ...state, steps: state.steps + 1 };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function replay(stored: ReadonlyArray<unknown>): CookingReadModel {
  const empty: CookingReadModel = { id: "", chefId: "", steps: 0 };
  return stored.reduce<CookingReadModel>((state, raw) => when(state, upcast(raw)), empty);
}

```

A `when(state, event)` function is the pure reducer that encodes how a single event evolves aggregate state. `aggregateStream` wraps it so callers can pass any async iterable of events — a DB cursor, a network stream, a subscription page — and receive the folded state. Because `when` is pure and `aggregateStream` is a thin loop, replay is deterministic.

```typescript
export type LineState = { status: "none" } | { status: "idle"; id: string } | { status: "running"; id: string };
export type LineEvent = { type: "LineCommissioned"; id: string } | { type: "LineStarted" } | { type: "LineStopped" };

export function when(state: LineState, event: LineEvent): LineState {
  switch (event.type) {
    case "LineCommissioned": return { status: "idle", id: event.id };
    case "LineStarted":
      if (state.status !== "idle") return state;
      return { status: "running", id: state.id };
    case "LineStopped":
      if (state.status !== "running") return state;
      return { status: "idle", id: state.id };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S
): Promise<S> {
  let acc = initial;
  for await (const event of events) {
    acc = reducer(acc, event);
  }
  return acc;
}
```

```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}
```

