```typescript
export type CookingSessionState =
  | { status: "none" }
  | { status: "running"; id: string; stepsDone: number }
  | { status: "finished"; id: string };

export type CookingSessionCommand =
  | { type: "start"; id: string }
  | { type: "logStep" }
  | { type: "finish"; at: string };

export type CookingSessionEvent =
  | { type: "CookingSessionStarted"; id: string }
  | { type: "CookingStepLogged" }
  | { type: "CookingSessionFinished"; at: string };

export const initialCookingSession: CookingSessionState = { status: "none" };

export function decide(c: CookingSessionCommand, s: CookingSessionState): CookingSessionEvent[] {
  switch (c.type) {
    case "start":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "CookingSessionStarted", id: c.id }];
    case "logStep":
      if (s.status !== "running") throw new Error("NOT_RUNNING");
      return [{ type: "CookingStepLogged" }];
    case "finish":
      if (s.status !== "running") throw new Error("NOT_RUNNING");
      return [{ type: "CookingSessionFinished", at: c.at }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: CookingSessionState, e: CookingSessionEvent): CookingSessionState {
  switch (e.type) {
    case "CookingSessionStarted":
      return { status: "running", id: e.id, stepsDone: 0 };
    case "CookingStepLogged":
      if (s.status !== "running") return s;
      return { ...s, stepsDone: s.stepsDone + 1 };
    case "CookingSessionFinished":
      if (s.status !== "running") return s;
      return { status: "finished", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: CookingSessionEvent }>>;
  appendToStream(stream: string, events: readonly CookingSessionEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handle(store: EventStore, stream: string, command: CookingSessionCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<CookingSessionState>((s, { event }) => evolve(s, event), initialCookingSession);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  const events = decide(command, state);
  await store.appendToStream(stream, events, { expectedRevision: expected });
}

