export type VariantEvent =
  | { type: "VariantRegistered"; id: string; key: string }
  | { type: "VariantTrafficAllocated"; percent: number }
  | { type: "VariantPaused" };

export type VariantState = Readonly<{
  id?: string;
  key?: string;
  traffic: number;
  paused: boolean;
}>;

export const initialState: VariantState = { traffic: 0, paused: false };

export function when(state: VariantState, event: VariantEvent): VariantState {
  switch (event.type) {
    case "VariantRegistered":
      return { ...state, id: event.id, key: event.key };
    case "VariantTrafficAllocated":
      return { ...state, traffic: event.percent };
    case "VariantPaused":
      return { ...state, paused: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export async function loadVariant(stream: AsyncIterable<VariantEvent>): Promise<VariantState> {
  return aggregateStream<VariantState, VariantEvent>(stream, when, initialState);
}
