export type ProjectEvent =
  | { type: "project-planned"; data: { id: string; name: string } }
  | { type: "project-started"; data: { at: string } }
  | { type: "project-completed"; data: { at: string } };

export type Project = Readonly<{
  id: string;
  name: string;
  startedAt: string | null;
  completedAt: string | null;
}>;

export function when(
  current: Partial<Project>,
  event: ProjectEvent,
): Partial<Project> {
  switch (event.type) {
    case "project-planned":
      return { id: event.data.id, name: event.data.name, startedAt: null, completedAt: null };
    case "project-started":
      return { ...current, startedAt: event.data.at };
    case "project-completed":
      return { ...current, completedAt: event.data.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function isProject(value: Partial<Project>): value is Project {
  return (
    typeof value.id === "string" && value.id.length > 0 &&
    typeof value.name === "string" && value.name.length > 0 &&
    (value.startedAt === null || typeof value.startedAt === "string") &&
    (value.completedAt === null || typeof value.completedAt === "string")
  );
}

export function aggregateStream<A, E>(
  events: readonly E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const s = events.reduce<Partial<A>>(reducer, {});
  if (!check(s)) throw new Error("INVALID_STATE");
  return s;
}

export function projectFrom(events: ProjectEvent[]): Project {
  return aggregateStream(events, when, isProject);
}
