export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface MeterV1 { meterId: string; reading: number }
export interface MeterV2 { meterId: string; reading: number; unit: "kWh" | "m3" }
export interface MeterV3 { meterId: string; reading: number; unit: "kWh" | "m3"; tariff: number }

export type CurrentMeter = MeterV3;
export const CURRENT_VERSION = 3 as const;

function v1Tov2(raw: MeterV1): MeterV2 {
  return { ...raw, unit: "kWh" };
}
function v2Tov3(raw: MeterV2): MeterV3 {
  return { ...raw, tariff: 0 };
}

export function load(snap: Snapshot<unknown>): Snapshot<CurrentMeter> {
  let state: unknown = snap.state;
  let version = snap.version;
  if (version === 1) { state = v1Tov2(state as MeterV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as MeterV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error("BAD_VERSION");
  return { version: CURRENT_VERSION, state: state as CurrentMeter };
}
