import { setup, assign, fromPromise } from 'xstate';

interface Ctx {
  username: string;
  available: boolean | null;
  error: string | null;
}

type Ev = { type: 'SET_USERNAME'; value: string };

const checkUsername = fromPromise<boolean, { username: string }>(
  async ({ input }) => input.username.length >= 4 && input.username !== 'admin'
);

export const usernameMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { checkUsername },
  actions: {
    setUsername: assign({
      username: ({ event }) => event.value,
      available: () => null,
      error: () => null
    }),
    setError: assign({ error: () => 'check failed' })
  }
}).createMachine({
  id: 'uname',
  context: { username: '', available: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { SET_USERNAME: { target: 'debouncing', actions: 'setUsername' } } },
    debouncing: {
      on: { SET_USERNAME: { target: 'debouncing', actions: 'setUsername', reenter: true } },
      after: { 300: { target: 'checking' } }
    },
    checking: {
      invoke: {
        id: 'check',
        src: 'checkUsername',
        input: ({ context }) => ({ username: context.username }),
        onDone: {
          target: 'idle',
          actions: assign({ available: ({ event }) => event.output })
        },
        onError: { target: 'idle', actions: 'setError' }
      },
      on: { SET_USERNAME: { target: 'debouncing', actions: 'setUsername' } }
    }
  }
});
