export type GuestCheckCommand =
  | { type: "openCheck"; id: string }
  | { type: "pay"; at: string };

export type GuestCheckEvent =
  | { type: "CheckOpened"; id: string }
  | { type: "CheckPaid"; at: string };

type WriteState =
  | { status: "none" }
  | { status: "open"; id: string }
  | { status: "paid"; id: string; at: string };

const initial: WriteState = { status: "none" };

function evolve(s: WriteState, e: GuestCheckEvent): WriteState {
  switch (e.type) {
    case "CheckOpened": return { status: "open", id: e.id };
    case "CheckPaid":
      return s.status === "open" ? { status: "paid", id: s.id, at: e.at } : s;
    default: { const _n: never = e; return s; }
  }
}

export class DomainError extends Error { constructor(m: string) { super(m); this.name = "DomainError"; } }

function decide(c: GuestCheckCommand, s: WriteState): GuestCheckEvent[] {
  switch (c.type) {
    case "openCheck":
      if (s.status !== "none") throw new DomainError("ALREADY_OPEN");
      return [{ type: "CheckOpened", id: c.id }];
    case "pay":
      if (s.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "CheckPaid", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(s: string): AsyncIterable<{ revision: bigint; event: GuestCheckEvent }>;
  appendToStream(s: string, ev: GuestCheckEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export async function handleCommand(cmd: GuestCheckCommand, streamName: string, store: EventStore): Promise<void> {
  let state = initial;
  let rev: bigint | "no_stream" = "no_stream";
  for await (const { revision, event } of store.readStream(streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  const events = decide(cmd, state);
  if (events.length > 0) await store.appendToStream(streamName, events, { expectedRevision: rev });
}

// The read side uses a completely different shape: a denormalized view
// populated by a background subscription. Eventually consistent with writes.
export type GuestCheckView = Readonly<{ id: string; paid: boolean; paidAt?: string }>;

export interface ReadStore {
  get(id: string): Promise<GuestCheckView | null>;
}

export async function queryView(id: string, reads: ReadStore): Promise<GuestCheckView | null> {
  return reads.get(id);
}
