```typescript
import { Effect } from "effect";

export type TractorEvent =
  | { type: "TractorRegistered"; id: string; model: string }
  | { type: "TractorServiced"; id: string; at: string }
  | { type: "TractorRetired"; id: string };

export interface StoredEvent<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventSource<E> {
  from(position: bigint | null): AsyncIterable<StoredEvent<E>>;
}

export interface Projection<E> {
  apply(event: E): Promise<void>;
}

export function runTractorSubscription(
  name: string,
  source: EventSource<TractorEvent>,
  projection: Projection<TractorEvent>,
  checkpoints: CheckpointStore
): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const start = yield* Effect.tryPromise(() => checkpoints.read(name));
    const iter = source.from(start);
    yield* Effect.tryPromise(async () => {
      for await (const stored of iter) {
        await projection.apply(stored.event);
        await checkpoints.write(name, stored.position);
      }
    });
  });
}
```

The handler is pure orchestration — it does not decide. It loads events, folds them through `evolve` to reconstruct state, calls `decide`, and appends with `expectedRevision` pinned to what it just read.

```typescript
export type AlertState = { status: "quiet" } | { status: "raised"; id: string; level: number };
export type AlertCommand = { type: "raise"; id: string; level: number };
export type AlertEvent = { type: "AlertRaised"; id: string; level: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

const initial: AlertState = { status: "quiet" };

function evolve(s: AlertState, e: AlertEvent): AlertState {
  switch (e.type) {
    case "AlertRaised": return { status: "raised", id: e.id, level: e.level };
    default: { const _n: never = e.type; return s; }
  }
}

function decide(c: AlertCommand, s: AlertState): AlertEvent[] {
  switch (c.type) {
    case "raise":
      if (s.status === "raised") throw new Error("ALREADY_RAISED");
      return [{ type: "AlertRaised", id: c.id, level: c.level }];
    default: { const _n: never = c.type; throw new Error("UNKNOWN"); }
  }
}

export async function handle(
  command: AlertCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream<AlertEvent>(ctx.streamName);
  const state = events.reduce<AlertState>(evolve, initial);
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream<AlertEvent>(ctx.streamName, newEvents, { expectedRevision: revision });
}
```

```typescript
// Command side writes to the event store; query side reads the eventually
// consistent projection.

export type PolicyState = { status: "none" } | { status: "drafted"; id: string; premium: number };
export type PolicyCommand = { type: "quote"; id: string; premium: number };
export type PolicyEvent = { type: "PolicyQuoted"; id: string; premium: number };
export type PolicyView = Readonly<{ id: string; premium: number; active: boolean }>;

const initial: PolicyState = { status: "none" };

function decide(c: PolicyCommand, s: PolicyState): PolicyEvent[] {
  switch (c.type) {
    case "quote":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "PolicyQuoted", id: c.id, premium: c.premium }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

function evolve(s: PolicyState, e: PolicyEvent): PolicyState {
  switch (e.type) {
    case "PolicyQuoted":
      return { status: "drafted", id: e.id, premium: e.premium };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore<E> {
  readStream(s: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    s: string, e: readonly E[], o: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export interface ViewStore {
  get(id: string): Promise<PolicyView | null>;
}

export async function handleCommand(
  cmd: PolicyCommand,
  ctx: { streamName: string; eventStore: EventStore<PolicyEvent> },
): Promise<void> {
  let state = initial;
  let rev: bigint | "no_stream" = "no_stream";
  for await (const rec of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, rec.event);
    rev = rec.revision;
  }
  await ctx.eventStore.appendToStream(ctx.streamName, decide(cmd, state), { expectedRevision: rev });
}

export async function queryView(id: string, store: ViewStore): Promise<PolicyView | null> {
  return store.get(id);
}
