Split the machine into two parallel regions: one holds the slide index, the other holds play/paused. Hover sends `PAUSE`; the `playing` state owns the `after` timer and exits on pause, which cancels the timer.

```typescript
import { setup, assign, raise } from 'xstate';

type Ctx = { i: number; total: number };
type Ev =
  | { type: 'NEXT' }
  | { type: 'PAUSE' }
  | { type: 'PLAY' };

export const autoplay = setup({
  types: { context: {} as Ctx, events: {} as Ev, input: {} as { total: number } },
  delays: { STEP: 2500 },
  actions: {
    advance: assign({ i: ({ context }) => (context.i + 1) % context.total })
  }
}).createMachine({
  id: 'autoplay',
  type: 'parallel',
  context: ({ input }) => ({ i: 0, total: input.total }),
  states: {
    slides: {
      on: { NEXT: { actions: 'advance' } }
    },
    mode: {
      initial: 'playing',
      states: {
        playing: {
          on: { PAUSE: 'paused' },
          after: {
            STEP: { target: 'playing', reenter: true, actions: raise({ type: 'NEXT' }) }
          }
        },
        paused: { on: { PLAY: 'playing' } }
      }
    }
  }
});
```

Purity in `when` (a.k.a. `evolve`) is what makes replay deterministic. If a reducer reads the clock, generates IDs, or calls I/O, replaying the same stream will not yield the same state. All non-deterministic data has to be captured inside the event itself.

```typescript
export type ProcedureEvent =
  | { type: "ProcedureScheduled"; id: string; name: string; at: string }
  | { type: "ProcedureStarted"; at: string }
  | { type: "ProcedurePerformed"; at: string }
  | { type: "ProcedureCancelled"; reason: string };

export interface ProcedureState {
  readonly id: string | null;
  readonly name: string | null;
  readonly scheduledAt: string | null;
  readonly startedAt: string | null;
  readonly performedAt: string | null;
  readonly cancelled: boolean;
}

export const initialProcedure: ProcedureState = {
  id: null, name: null, scheduledAt: null, startedAt: null, performedAt: null, cancelled: false,
};

export function when(state: ProcedureState, event: ProcedureEvent): ProcedureState {
  switch (event.type) {
    case "ProcedureScheduled":
      return { ...state, id: event.id, name: event.name, scheduledAt: event.at };
    case "ProcedureStarted":
      return { ...state, startedAt: event.at };
    case "ProcedurePerformed":
      return { ...state, performedAt: event.at };
    case "ProcedureCancelled":
      return { ...state, cancelled: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: ProcedureEvent[]): ProcedureState {
  return events.reduce(when, initialProcedure);
}
```

Schedule a delayed internal `REDRAW` via `raise` with an `id`, and `cancel` it every time a new `TICK` arrives; only the last scheduled one fires.

```typescript
import { setup, assign, raise, cancel } from 'xstate';

export const debouncedDash = setup({
  types: {
    context: {} as { buffer: number[]; last: number[] },
    events: {} as { type: 'TICK'; value: number } | { type: 'REDRAW' },
  },
}).createMachine({
  id: 'debounced',
  context: { buffer: [], last: [] },
  on: {
    TICK: {
      actions: [
        assign({ buffer: ({ context, event }) => [...context.buffer, event.value] }),
        cancel('redraw'),
        raise({ type: 'REDRAW' }, { id: 'redraw', delay: 200 }),
      ],
    },
    REDRAW: {
      actions: assign({
        last: ({ context }) => context.buffer,
        buffer: () => [],
      }),
    },
  },
});
