export type ClaimState =
  | { status: "none" }
  | { status: "filed"; id: string; amount: number }
  | { status: "assessed"; id: string; amount: number; adjuster: string }
  | { status: "approved"; id: string; amount: number; adjuster: string; at: string }
  | { status: "rejected"; id: string; reason: string };

export type ClaimCommand =
  | { type: "file"; id: string; amount: number }
  | { type: "assess"; adjuster: string }
  | { type: "approve"; at: string }
  | { type: "reject"; reason: string };

export type ClaimEvent =
  | { type: "ClaimFiled"; id: string; amount: number }
  | { type: "ClaimAssessed"; adjuster: string }
  | { type: "ClaimApproved"; at: string }
  | { type: "ClaimRejected"; reason: string };

export class ClaimError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const claimDecider: Decider<ClaimCommand, ClaimEvent, ClaimState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "file":
        if (s.status !== "none") throw new ClaimError("EXISTS");
        if (c.amount <= 0) throw new ClaimError("AMOUNT");
        return [{ type: "ClaimFiled", id: c.id, amount: c.amount }];
      case "assess":
        if (s.status !== "filed") throw new ClaimError("NOT_FILED");
        return [{ type: "ClaimAssessed", adjuster: c.adjuster }];
      case "approve":
        if (s.status !== "assessed") throw new ClaimError("NOT_ASSESSED");
        return [{ type: "ClaimApproved", at: c.at }];
      case "reject":
        if (s.status === "approved") throw new ClaimError("ALREADY_APPROVED");
        if (s.status === "rejected") return [];
        return [{ type: "ClaimRejected", reason: c.reason }];
      default: { const _n: never = c; throw new ClaimError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ClaimFiled":
        return { status: "filed", id: e.id, amount: e.amount };
      case "ClaimAssessed":
        if (s.status !== "filed") return s;
        return { status: "assessed", id: s.id, amount: s.amount, adjuster: e.adjuster };
      case "ClaimApproved":
        if (s.status !== "assessed") return s;
        return { status: "approved", id: s.id, amount: s.amount, adjuster: s.adjuster, at: e.at };
      case "ClaimRejected":
        return { status: "rejected", id: "id" in s ? s.id : "", reason: e.reason };
      default: { const _n: never = e; return s; }
    }
  },
};
