export type EvaluationState =
  | { status: "none" }
  | { status: "queued"; id: string; modelId: string }
  | { status: "running"; id: string }
  | { status: "passed"; id: string; score: number }
  | { status: "failed"; id: string; score: number; reason: string };

export type EvaluationCommand =
  | { type: "queue"; id: string; modelId: string }
  | { type: "run" }
  | { type: "pass"; score: number }
  | { type: "fail"; score: number; reason: string };

export type EvaluationEvent =
  | { type: "EvaluationQueued"; id: string; modelId: string }
  | { type: "EvaluationRan" }
  | { type: "EvaluationPassed"; score: number }
  | { type: "EvaluationFailed"; score: number; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const evaluationDecider: Decider<EvaluationCommand, EvaluationEvent, EvaluationState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "queue":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "EvaluationQueued", id: command.id, modelId: command.modelId }];
      case "run":
        if (state.status !== "queued") throw new DomainError("NOT_QUEUED");
        return [{ type: "EvaluationRan" }];
      case "pass":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "EvaluationPassed", score: command.score }];
      case "fail":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "EvaluationFailed", score: command.score, reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "EvaluationQueued":
        return { status: "queued", id: event.id, modelId: event.modelId };
      case "EvaluationRan":
        if (state.status !== "queued") return state;
        return { status: "running", id: state.id };
      case "EvaluationPassed":
        if (state.status !== "running") return state;
        return { status: "passed", id: state.id, score: event.score };
      case "EvaluationFailed":
        if (state.status !== "running") return state;
        return { status: "failed", id: state.id, score: event.score, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
