export interface ChapterEvent { readonly type: string; readonly chapterId: string; readonly position: bigint; }

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed<E> {
  readFrom(position: bigint | null): AsyncIterable<E>;
}

export interface View { readonly counts: Readonly<Record<string, number>>; }
export const emptyView: View = { counts: {} };

export function project(view: View, event: ChapterEvent): View {
  if (event.type !== "ChapterAdded") return view;
  return { counts: { ...view.counts, [event.chapterId]: (view.counts[event.chapterId] ?? 0) + 1 } };
}

export interface ViewStore {
  read(): Promise<View>;
  write(v: View): Promise<void>;
}

export async function runSubscription(
  name: string,
  feed: EventFeed<ChapterEvent>,
  checkpoints: CheckpointStore,
  store: ViewStore,
): Promise<void> {
  async function main(): Promise<void> {
    const from = await checkpoints.read(name);
    let view = await store.read();
    for await (const event of feed.readFrom(from)) {
      view = project(view, event);
      await store.write(view);
      await checkpoints.write(name, event.position);
    }
  }
  await main();
}
