export type RefundState =
  | { status: "none" }
  | { status: "pending"; id: string; amount: number }
  | { status: "approved"; id: string; amount: number; approver: string }
  | { status: "settled"; id: string; amount: number; settledAt: string }
  | { status: "rejected"; id: string; reason: string };

export type RefundCommand =
  | { type: "initiate"; id: string; amount: number }
  | { type: "approve"; approver: string }
  | { type: "settle"; at: string }
  | { type: "reject"; reason: string };

export type RefundEvent =
  | { type: "RefundInitiated"; id: string; amount: number }
  | { type: "RefundApproved"; approver: string }
  | { type: "RefundSettled"; at: string }
  | { type: "RefundRejected"; reason: string };

export class RefundError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const refundDecider: Decider<RefundCommand, RefundEvent, RefundState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "initiate":
        if (state.status !== "none") throw new RefundError("EXISTS");
        if (command.amount <= 0) throw new RefundError("INVALID_AMOUNT");
        return [{ type: "RefundInitiated", id: command.id, amount: command.amount }];
      case "approve":
        if (state.status === "rejected") throw new RefundError("REJECTED");
        if (state.status !== "pending") throw new RefundError("NOT_PENDING");
        return [{ type: "RefundApproved", approver: command.approver }];
      case "settle":
        if (state.status !== "approved") throw new RefundError("NOT_APPROVED");
        return [{ type: "RefundSettled", at: command.at }];
      case "reject":
        if (state.status !== "pending") throw new RefundError("NOT_PENDING");
        return [{ type: "RefundRejected", reason: command.reason }];
      default: { const _n: never = command; throw new RefundError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RefundInitiated":
        return { status: "pending", id: event.id, amount: event.amount };
      case "RefundApproved":
        if (state.status !== "pending") return state;
        return { status: "approved", id: state.id, amount: state.amount, approver: event.approver };
      case "RefundSettled":
        if (state.status !== "approved") return state;
        return { status: "settled", id: state.id, amount: state.amount, settledAt: event.at };
      case "RefundRejected":
        if (state.status !== "pending") return state;
        return { status: "rejected", id: state.id, reason: event.reason };
      default: { const _n: never = event; return state; }
    }
  },
};
