type Session = { readonly id: string; readonly trackCount: number; readonly closed: boolean };
type SessionEvent =
  | { type: 'SessionOpened'; id: string }
  | { type: 'TrackRecorded' }
  | { type: 'SessionClosed' };
type SessionCommand = { type: 'Close'; id: string };

const initial: Session = { id: '', trackCount: 0, closed: false };

function evolve(state: Session, event: SessionEvent): Session {
  switch (event.type) {
    case 'SessionOpened': return { id: event.id, trackCount: 0, closed: false };
    case 'TrackRecorded': return { ...state, trackCount: state.trackCount + 1 };
    case 'SessionClosed': return { ...state, closed: true };
    default: { const _e: never = event; return _e; }
  }
}

function decide(cmd: SessionCommand, state: Session): SessionEvent[] {
  if (state.closed) return [];
  return [{ type: 'SessionClosed' }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: SessionEvent; revision: bigint }>;
  appendToStream(s: string, evs: readonly SessionEvent[], opts: { expectedRevision: bigint | 'no_stream' | 'any' }): Promise<void>;
}

export async function handle(cmd: SessionCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  let state = initial;
  let rev: bigint | 'no_stream' = 'no_stream';
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  const events = decide(cmd, state);
  if (events.length === 0) return;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: rev });
}
