export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type LeaseState = { status: "none" } | { status: "draft"; id: string } | { status: "active"; id: string };
export type LeaseEvent = { type: "LeaseDrafted"; id: string } | { type: "LeaseSigned" };

export function evolve(state: LeaseState, event: LeaseEvent): LeaseState {
  switch (event.type) {
    case "LeaseDrafted":
      return { status: "draft", id: event.id };
    case "LeaseSigned":
      if (state.status !== "draft") return state;
      return { status: "active", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function loadLease(stream: AsyncIterable<LeaseEvent>): Promise<LeaseState> {
  return aggregateStream(stream, evolve, { status: "none" });
}
