export type ModelCheckpointState =
  | { status: "none" }
  | { status: "created"; id: string; step: number }
  | { status: "withArtifact"; id: string; step: number; uri: string }
  | { status: "promoted"; id: string; stage: string }
  | { status: "retired"; id: string };

export type ModelCheckpointCommand =
  | { type: "create"; id: string; step: number }
  | { type: "attachArtifact"; uri: string }
  | { type: "promote"; stage: string }
  | { type: "retire" };

export type ModelCheckpointEvent =
  | { type: "CheckpointCreated"; id: string; step: number }
  | { type: "CheckpointArtifactAttached"; uri: string }
  | { type: "CheckpointPromoted"; stage: string }
  | { type: "CheckpointRetired" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const checkpointDecider: Decider<ModelCheckpointCommand, ModelCheckpointEvent, ModelCheckpointState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "CheckpointCreated", id: command.id, step: command.step }];
      case "attachArtifact":
        if (state.status !== "created") throw new DomainError("BAD_STATE");
        return [{ type: "CheckpointArtifactAttached", uri: command.uri }];
      case "promote":
        if (state.status !== "withArtifact") throw new DomainError("NO_ARTIFACT");
        return [{ type: "CheckpointPromoted", stage: command.stage }];
      case "retire":
        if (state.status === "retired" || state.status === "none") throw new DomainError("CANNOT_RETIRE");
        return [{ type: "CheckpointRetired" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CheckpointCreated":
        return { status: "created", id: event.id, step: event.step };
      case "CheckpointArtifactAttached":
        if (state.status !== "created") return state;
        return { status: "withArtifact", id: state.id, step: state.step, uri: event.uri };
      case "CheckpointPromoted":
        if (state.status !== "withArtifact") return state;
        return { status: "promoted", id: state.id, stage: event.stage };
      case "CheckpointRetired":
        if (state.status === "none") return state;
        return { status: "retired", id: "id" in state ? state.id : "" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
