export type AcquisitionEvent = { type: string; data: Readonly<Record<string, unknown>> };

export interface AppendOptions {
  expectedRevision: bigint | "no_stream" | "any";
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: AcquisitionEvent; revision: bigint }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<AcquisitionEvent>,
    options: AppendOptions,
  ): Promise<{ nextExpectedRevision: bigint; conflict?: true }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string, public readonly expected: bigint | "no_stream" | "any") {
    super("concurrency conflict on " + streamName);
  }
}

export async function appendWithExpectedRevision(
  store: EventStore,
  streamName: string,
  events: ReadonlyArray<AcquisitionEvent>,
  expected: bigint | "no_stream" | "any",
): Promise<bigint> {
  const result = await store.appendToStream(streamName, events, { expectedRevision: expected });
  if (result.conflict) throw new ConcurrencyConflict(streamName, expected);
  return result.nextExpectedRevision;
}

export async function readCurrentRevision(store: EventStore, streamName: string): Promise<bigint | "no_stream"> {
  let last: bigint | "no_stream" = "no_stream";
  for await (const { revision } of store.readStream(streamName)) {
    last = revision;
  }
  return last;
}
