export type MentorshipSessionEvent =
  | { type: "SessionBooked"; id: string; mentor: string; mentee: string }
  | { type: "GoalSet"; goal: string }
  | { type: "NoteLogged"; note: string }
  | { type: "SessionCompleted"; rating: number };

