  id: string;
  mentor: string;
  mentee: string;
  goals: string[];
  notes: number;
  rating: number | null;
}

export const emptyView: ProgressView = {
  id: "",
  mentor: "",
  mentee: "",
  goals: [],
  notes: 0,
  rating: null,
};

export function project(
  view: ProgressView,
  event: MentorshipSessionEvent,
): ProgressView {
  switch (event.type) {
    case "SessionBooked":
      return {
        ...view,
        id: event.id,
        mentor: event.mentor,
        mentee: event.mentee,
      };
    case "GoalSet":
      return { ...view, goals: [...view.goals, event.goal] };
    case "NoteLogged":
      return { ...view, notes: view.notes + 1 };
    case "SessionCompleted":
      return { ...view, rating: event.rating };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function foldProgress(
  events: MentorshipSessionEvent[],
): ProgressView {
  return events.reduce(project, emptyView);
}
