export type CohortState =
  | { status: "none" }
  | { status: "forming"; id: string; members: ReadonlyArray<string> }
  | { status: "sealed"; id: string };

export type CohortCommand =
  | { type: "form"; id: string }
  | { type: "admit"; learner: string };

export type CohortEvent =
  | { type: "CohortFormed"; id: string }
  | { type: "LearnerAdmitted"; learner: string };

export const initialState: CohortState = { status: "none" };

export function evolve(state: CohortState, event: CohortEvent): CohortState {
  switch (event.type) {
    case "CohortFormed":
      return { status: "forming", id: event.id, members: [] };
    case "LearnerAdmitted":
      if (state.status !== "forming") return state;
      return { ...state, members: [...state.members, event.learner] };
    default: { const _n: never = event; return state; }
  }
}

export class DomainError extends Error {}
export class ConcurrencyConflict extends Error {}

export function decide(c: CohortCommand, s: CohortState): CohortEvent[] {
  switch (c.type) {
    case "form":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "CohortFormed", id: c.id }];
    case "admit":
      if (s.status !== "forming") throw new DomainError("NOT_FORMING");
      return [{ type: "LearnerAdmitted", learner: c.learner }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<CohortEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<CohortEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<{ ok: true; nextRevision: bigint } | { ok: false; actualRevision: bigint | null }>;
}

export async function handleCohortCommand(
  store: EventStore,
  streamName: string,
  command: CohortCommand,
): Promise<bigint> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const newEvents = decide(command, state);
  if (newEvents.length === 0) return revision ?? 0n;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  const result = await store.appendToStream(streamName, newEvents, { expectedRevision });
  if (!result.ok) throw new ConcurrencyConflict("REVISION_MISMATCH");
  return result.nextRevision;
}
```

