`ZodSchema<T>` flows the inferred type to the return. `parse` throws a `ZodError` on mismatch — the caller can catch it and inspect `err.issues` for field-level detail. Use `safeParse` if the caller prefers discriminated-union handling.

```typescript
type ThreadV1 = Readonly<{ id: string; topic: string }>;
type ThreadV2 = Readonly<{ id: string; topic: string; pinned: boolean }>;
type ThreadV3 = Readonly<{ id: string; topic: string; pinned: boolean; archivedAt: string | null }>;

export type CurrentThread = ThreadV3;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 3 as const;

const v1Tov2 = (s: ThreadV1): ThreadV2 => ({ ...s, pinned: false });
const v2Tov3 = (s: ThreadV2): ThreadV3 => ({ ...s, archivedAt: null });

export function loadSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentThread> {
  let version = snap.version;
  let state: unknown = snap.state;

  if (version === 1) {
    state = v1Tov2(state as ThreadV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as ThreadV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unsupported snapshot version: ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentThread };
}
```

