export type ChapterState = { status: "none" } | { status: "open"; id: string; title: string };
export type ChapterCommand = { type: "add"; id: string; title: string } | { type: "rename"; title: string };
export type ChapterEvent = { type: "ChapterAdded"; id: string; title: string } | { type: "ChapterRenamed"; title: string };

export const initialState: ChapterState = { status: "none" };

export function decide(c: ChapterCommand, s: ChapterState): ChapterEvent[] {
  switch (c.type) {
    case "add":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "ChapterAdded", id: c.id, title: c.title }];
    case "rename":
      if (s.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "ChapterRenamed", title: c.title }];
    default: { const _n: never = c; return []; }
  }
}

export function evolve(s: ChapterState, e: ChapterEvent): ChapterState {
  switch (e.type) {
    case "ChapterAdded": return { status: "open", id: e.id, title: e.title };
    case "ChapterRenamed": return s.status === "open" ? { ...s, title: e.title } : s;
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";
export interface Env { readonly revision: bigint; readonly event: ChapterEvent; }
export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<Env>>;
  appendToStream(s: string, e: ChapterEvent[], o: { expectedRevision: ExpectedRevision }): Promise<{ ok: boolean; actual: bigint | null; nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly actual: bigint | null) { super("CONFLICT"); this.name = "ConcurrencyConflict"; }
}

export interface CommandHandler<C> {
  handle(cmd: C, ctx: { streamName: string; eventStore: EventStore }): Promise<void>;
}

export const chapterHandler: CommandHandler<ChapterCommand> = {
  async handle(cmd, { streamName, eventStore }) {
    const envs = await eventStore.readStream(streamName);
    const state = envs.map((e) => e.event).reduce(evolve, initialState);
    const expected: ExpectedRevision = envs.length === 0 ? "no_stream" : envs[envs.length - 1]!.revision;
    const events = decide(cmd, state);
    if (events.length === 0) return;
    const outcome = await eventStore.appendToStream(streamName, events, { expectedRevision: expected });
    if (!outcome.ok) throw new ConcurrencyConflict(outcome.actual);
  },
};
```

