export type ConsentPackageState =
  | { status: "none" }
  | { status: "draft"; id: string; subject: string; clauses: number }
  | { status: "signed"; id: string; subject: string; signedAt: string }
  | { status: "revoked"; id: string; revokedAt: string };

export type ConsentPackageCommand =
  | { type: "draft"; id: string; subject: string }
  | { type: "addClause" }
  | { type: "sign"; at: string }
  | { type: "revoke"; at: string };

export type ConsentPackageEvent =
  | { type: "ConsentPackageDrafted"; id: string; subject: string }
  | { type: "ConsentClauseAdded" }
  | { type: "ConsentPackageSigned"; at: string }
  | { type: "ConsentPackageRevoked"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const consentPackageDecider: Decider<ConsentPackageCommand, ConsentPackageEvent, ConsentPackageState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "draft":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ConsentPackageDrafted", id: command.id, subject: command.subject }];
      case "addClause":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "ConsentClauseAdded" }];
      case "sign":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (state.clauses === 0) throw new DomainError("NO_CLAUSES");
        return [{ type: "ConsentPackageSigned", at: command.at }];
      case "revoke":
        if (state.status !== "signed") throw new DomainError("NOT_SIGNED");
        return [{ type: "ConsentPackageRevoked", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ConsentPackageDrafted":
        return { status: "draft", id: event.id, subject: event.subject, clauses: 0 };
      case "ConsentClauseAdded":
        if (state.status !== "draft") return state;
        return { ...state, clauses: state.clauses + 1 };
      case "ConsentPackageSigned":
        if (state.status !== "draft") return state;
        return { status: "signed", id: state.id, subject: state.subject, signedAt: event.at };
      case "ConsentPackageRevoked":
        if (state.status !== "signed") return state;
        return { status: "revoked", id: state.id, revokedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
