```typescript
type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<StoredEvent<E>>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<{ state: S; revision: bigint | undefined }> {
  let state = initial;
  let revision: bigint | undefined = undefined;
  for await (const { event, revision: r } of stream) {
    state = evolve(state, event);
    revision = r;
  }
  return { state, revision };
}

export type CourierState =
  | { status: "pending" }
  | { status: "offline"; id: string }
  | { status: "online"; id: string };

export type CourierCommand =
  | { type: "onboard"; id: string }
  | { type: "goOnline" };

export type CourierEvent =
  | { type: "CourierOnboarded"; id: string }
  | { type: "CourierWentOnline" };

const initial: CourierState = { status: "pending" };

function evolve(s: CourierState, e: CourierEvent): CourierState {
  switch (e.type) {
    case "CourierOnboarded": return { status: "offline", id: e.id };
    case "CourierWentOnline":
      if (s.status !== "offline") return s;
      return { status: "online", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: CourierCommand, s: CourierState): CourierEvent[] {
  switch (c.type) {
    case "onboard":
      if (s.status !== "pending") throw new Error("EXISTS");
      return [{ type: "CourierOnboarded", id: c.id }];
    case "goOnline":
      if (s.status !== "offline") throw new Error("NOT_OFFLINE");
      return [{ type: "CourierWentOnline" }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export async function handleCourier(
  command: CourierCommand,
  ctx: { streamName: string; eventStore: EventStore<CourierEvent> },
): Promise<void> {
  const { state, revision } = await aggregateStream(ctx.eventStore.readStream(ctx.streamName), evolve, initial);
  const events = decide(command, state);
  if (events.length === 0) return;
  const expected: ExpectedRevision = revision ?? "no_stream";
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}
```

A projection folds events into a flat query-friendly view shared across many aggregates. It never enforces invariants and never refuses events; events the view doesn't care about are returned unchanged. An aggregate `evolve` by contrast folds only events from one stream into that aggregate's own state, which `decide` inspects to enforce invariants. The projection is consumer-specific; `evolve` is authoritative.

```typescript
export type GreenhouseEvent =
  | { type: "GreenhouseOpened"; id: string }
  | { type: "GreenhouseClimateSet"; id: string; temperatureC: number; humidity: number; at: string }
  | { type: "GreenhouseSealed"; id: string; at: string };

export interface ClimateView {
  readonly byId: Readonly<Record<string, { temperatureC: number; humidity: number; at: string }>>;
  readonly sealed: ReadonlyArray<string>;
}

export const emptyView: ClimateView = { byId: {}, sealed: [] };

export function project(view: ClimateView, event: GreenhouseEvent): ClimateView {
  switch (event.type) {
    case "GreenhouseOpened":
      return view;
    case "GreenhouseClimateSet":
      return {
        ...view,
        byId: {
          ...view.byId,
          [event.id]: { temperatureC: event.temperatureC, humidity: event.humidity, at: event.at },
        },
      };
    case "GreenhouseSealed":
      return view.sealed.includes(event.id)
        ? view
        : { ...view, sealed: [...view.sealed, event.id] };
    default: {
      const _n: never = event;
      return view;
    }
  }
}
