import { Effect } from "effect";

export type MenuItemState =
  | { status: "none" }
  | { status: "available"; id: string; priceCents: number };

export type MenuItemCommand =
  | { type: "addItem"; id: string; priceCents: number }
  | { type: "setPrice"; priceCents: number };

export type MenuItemEvent =
  | { type: "MenuItemAdded"; id: string; priceCents: number }
  | { type: "MenuItemPriceChanged"; priceCents: number };

const initial: MenuItemState = { status: "none" };

function evolve(s: MenuItemState, e: MenuItemEvent): MenuItemState {
  switch (e.type) {
    case "MenuItemAdded": return { status: "available", id: e.id, priceCents: e.priceCents };
    case "MenuItemPriceChanged":
      return s.status === "available" ? { ...s, priceCents: e.priceCents } : s;
    default: { const _n: never = e; return s; }
  }
}

export class DomainError extends Error { constructor(m: string) { super(m); this.name = "DomainError"; } }

function decide(c: MenuItemCommand, s: MenuItemState): MenuItemEvent[] {
  switch (c.type) {
    case "addItem":
      if (s.status !== "none") throw new DomainError("ALREADY");
      return [{ type: "MenuItemAdded", id: c.id, priceCents: c.priceCents }];
    case "setPrice":
      if (s.status !== "available") throw new DomainError("NOT_ADDED");
      return [{ type: "MenuItemPriceChanged", priceCents: c.priceCents }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: MenuItemEvent }>;
  appendToStream(stream: string, events: MenuItemEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export function handleMenuItem(
  command: MenuItemCommand,
  ctx: { streamName: string; eventStore: EventStore }
): Effect.Effect<void, DomainError> {
  return Effect.gen(function* () {
    const loaded = yield* Effect.tryPromise({
      try: async () => {
        let state = initial;
        let rev: bigint | "no_stream" = "no_stream";
        for await (const { revision, event } of ctx.eventStore.readStream(ctx.streamName)) {
          state = evolve(state, event);
          rev = revision;
        }
        return { state, rev };
      },
      catch: (e) => new DomainError(String(e)),
    });
    const events = decide(command, loaded.state);
    if (events.length === 0) return;
    yield* Effect.tryPromise({
      try: () => ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: loaded.rev }),
      catch: (e) => new DomainError(String(e)),
    });
  });
}
