export type GuestCheckState =
  | { status: "none" }
  | { status: "open"; id: string; totalCents: number }
  | { status: "split"; id: string; parts: number; totalCents: number }
  | { status: "paid"; id: string; paidAt: string };

export type GuestCheckCommand =
  | { type: "openCheck"; id: string }
  | { type: "addLineItem"; cents: number }
  | { type: "splitCheck"; parts: number }
  | { type: "pay"; at: string };

export type GuestCheckEvent =
  | { type: "CheckOpened"; id: string }
  | { type: "LineItemAdded"; cents: number }
  | { type: "CheckSplit"; parts: number }
  | { type: "CheckPaid"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const guestCheckDecider: Decider<GuestCheckCommand, GuestCheckEvent, GuestCheckState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "openCheck":
        if (s.status !== "none") throw new DomainError("ALREADY_OPEN");
        return [{ type: "CheckOpened", id: c.id }];
      case "addLineItem":
        if (s.status !== "open") throw new DomainError("NOT_OPEN");
        if (c.cents <= 0) throw new DomainError("INVALID_AMOUNT");
        return [{ type: "LineItemAdded", cents: c.cents }];
      case "splitCheck":
        if (s.status === "paid") throw new DomainError("ALREADY_PAID");
        if (s.status !== "open") throw new DomainError("NOT_OPEN");
        if (c.parts < 2) throw new DomainError("MIN_TWO_PARTS");
        return [{ type: "CheckSplit", parts: c.parts }];
      case "pay":
        if (s.status !== "open" && s.status !== "split") throw new DomainError("NOT_PAYABLE");
        return [{ type: "CheckPaid", at: c.at }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "CheckOpened": return { status: "open", id: e.id, totalCents: 0 };
      case "LineItemAdded":
        return s.status === "open"
          ? { ...s, totalCents: s.totalCents + e.cents }
          : s;
      case "CheckSplit":
        return s.status === "open"
          ? { status: "split", id: s.id, parts: e.parts, totalCents: s.totalCents }
          : s;
      case "CheckPaid":
        return s.status === "open" || s.status === "split"
          ? { status: "paid", id: s.id, paidAt: e.at }
          : s;
      default: { const _n: never = e; return s; }
    }
  },
};
