Move the fetch into a `fromPromise` actor with typed `input`, register it, and pass `input: ({ context }) => ...` from the invocation.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface User { readonly id: string; readonly name: string }

export const userMachine = setup({
  types: {
    context: {} as { userId: string; user: User | null },
    events: {} as { type: 'RELOAD' }
  },
  actors: {
    loadUser: fromPromise<User, { userId: string }>(async ({ input }) => {
      const r = await fetch(`/users/${input.userId}`);
      return (await r.json()) as User;
    })
  }
}).createMachine({
  id: 'user',
  initial: 'loading',
  context: { userId: 'u1', user: null },
  states: {
    loading: {
