  | { type: "PaymentSettled"; amount: number }
  | { type: "PaymentRefunded"; amount: number };

export const initialState: PaymentState = { balance: 0, status: "pending" };

export function evolve(state: PaymentState, event: PaymentEvent): PaymentState {
  switch (event.type) {
    case "PaymentScheduled":
      return { balance: state.balance + event.amount, status: "pending" };
    case "PaymentSettled":
      return { balance: state.balance - event.amount, status: "settled" };
    case "PaymentRefunded":
      return { balance: state.balance + event.amount, status: "refunded" };
    default: {
      const _never: never = event;
      return state;
