export class DomainError extends Error {}

export type TerritoryMapState = { status: "empty" } | { status: "open"; id: string; districts: number };
export type TerritoryMapCommand = { type: "create"; id: string } | { type: "addDistrict" };
export type TerritoryMapEvent = { type: "created"; id: string } | { type: "districtAdded" };

const initialState: TerritoryMapState = { status: "empty" };

function evolve(s: TerritoryMapState, e: TerritoryMapEvent): TerritoryMapState {
  switch (e.type) {
    case "created":
      return { status: "open", id: e.id, districts: 0 };
    case "districtAdded":
      return s.status === "open" ? { ...s, districts: s.districts + 1 } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: TerritoryMapCommand, s: TerritoryMapState): TerritoryMapEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "empty") throw new DomainError("exists");
      return [{ type: "created", id: c.id }];
    case "addDistrict":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "districtAdded" }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" }): Promise<{ nextRevision: bigint }>;
}

export async function handle(
  command: TerritoryMapCommand,
  ctx: { streamName: string; eventStore: EventStore<TerritoryMapEvent> },
): Promise<void> {
  const stored = await ctx.eventStore.readStream(ctx.streamName);
  const state = stored.reduce<TerritoryMapState>((s, r) => evolve(s, r.event), initialState);
  const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision });
}
