Read events in batches from the cursor, run project per event, persist the batch, advance the cursor, and emit progress. The from option makes rebuilds resumable after a crash.

```typescript
export type DropOffEvent =
  | { type: "DropOffSucceeded"; id: string; at: string }
  | { type: "DropOffFailed"; id: string; reason: string };

export interface PositionedEvent { position: bigint; event: DropOffEvent }

export interface EventReader {
  read(from: bigint, batchSize: number): Promise<readonly PositionedEvent[]>;
}

export interface DropOffRow { status: "succeeded" | "failed"; info: string }

export interface ReadStore {
  persistBatch(rows: Readonly<Record<string, DropOffRow>>): Promise<void>;
  setCursor(pos: bigint): Promise<void>;
}

export interface ProgressSink { report(count: number, cursor: bigint): void }

function project(rows: Readonly<Record<string, DropOffRow>>, e: DropOffEvent): Readonly<Record<string, DropOffRow>> {
  switch (e.type) {
    case "DropOffSucceeded": return { ...rows, [e.id]: { status: "succeeded", info: e.at } };
    case "DropOffFailed": return { ...rows, [e.id]: { status: "failed", info: e.reason } };
    default: { const _n: never = e; return rows; }
  }
}

export async function rebuild(opts: { from: bigint; batchSize: number; reader: EventReader; store: ReadStore; progress: ProgressSink }): Promise<void> {
  let cursor = opts.from;
  let total = 0;
  while (true) {
    const batch = await opts.reader.read(cursor, opts.batchSize);
    if (batch.length === 0) return;
    let rows: Readonly<Record<string, DropOffRow>> = {};
    for (const { event } of batch) {
      rows = project(rows, event);
    }
    await opts.store.persistBatch(rows);
    total += batch.length;
    cursor = batch[batch.length - 1].position + 1n;
    await opts.store.setCursor(cursor);
    opts.progress.report(total, cursor);
  }
}
```

Read the stream to learn its current revision, decide new events from the folded state, then appendToStream with expectedRevision equal to that revision.  If the store reports a conflict, surface a typed ConcurrencyConflict so the caller can retry the whole decision.

```typescript
export type FineEvent =
  | { type: "FineIssued"; amount: number }
  | { type: "FinePaid"; amount: number }
  | { type: "FineWaived"; reason: string };

export type FineState = { balance: number; closed: boolean };

export class ConcurrencyConflict extends Error {}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: FineEvent; revision: bigint }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<FineEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint; conflict?: true }>;
}

function evolve(state: FineState, event: FineEvent): FineState {
  switch (event.type) {
    case "FineIssued":
      return { balance: state.balance + event.amount, closed: false };
    case "FinePaid":
      return { balance: state.balance - event.amount, closed: state.balance - event.amount <= 0 };
    case "FineWaived":
      return { balance: 0, closed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function payFine(store: EventStore, streamName: string, amount: number): Promise<void> {
  let state: FineState = { balance: 0, closed: false };
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of store.readStream(streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  if (state.closed) throw new Error("fine already closed");
  const result = await store.appendToStream(
    streamName,
    [{ type: "FinePaid", amount }],
    { expectedRevision: expected },
  );
  if (result.conflict) throw new ConcurrencyConflict("fine stream moved");
}
