export type PolicyState =
  | { status: "none" }
  | { status: "draft"; id: string; premium: number }
  | { status: "active"; id: string; premium: number; activatedAt: string }
  | { status: "lapsed"; id: string; reason: string };

export type PolicyCommand =
  | { type: "quote"; id: string; premium: number }
  | { type: "activate"; at: string }
  | { type: "lapse"; reason: string };

export type PolicyEvent =
  | { type: "PolicyQuoted"; id: string; premium: number }
  | { type: "PolicyActivated"; at: string }
  | { type: "PolicyLapsed"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const policyDecider: Decider<PolicyCommand, PolicyEvent, PolicyState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "quote":
        if (state.status !== "none") throw new DomainError("POLICY_EXISTS");
        if (command.premium <= 0) throw new DomainError("PREMIUM_INVALID");
        return [{ type: "PolicyQuoted", id: command.id, premium: command.premium }];
      case "activate":
        if (state.status === "lapsed") throw new DomainError("LAPSED");
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "PolicyActivated", at: command.at }];
      case "lapse":
        if (state.status === "none") throw new DomainError("NOT_FOUND");
        if (state.status === "lapsed") return [];
        return [{ type: "PolicyLapsed", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PolicyQuoted":
        return { status: "draft", id: event.id, premium: event.premium };
      case "PolicyActivated":
        if (state.status !== "draft") return state;
        return { status: "active", id: state.id, premium: state.premium, activatedAt: event.at };
      case "PolicyLapsed":
        if (state.status === "none") return state;
        return { status: "lapsed", id: "id" in state ? state.id : "", reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
