```typescript
import { setup, assign } from 'xstate';

interface Ctx {
  past: string[];
  present: string;
  future: string[];
  checkpoints: string[];
}

type Ev =
  | { type: 'SET'; v: string }
  | { type: 'UNDO' }
  | { type: 'REDO' }
  | { type: 'CHECKPOINT' };

export const checkpointMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canUndo: ({ context }) => context.past.length > 0,
    canRedo: ({ context }) => context.future.length > 0
  },
  actions: {
    apply: assign(({ context, event }) => {
      if (event.type !== 'SET') return {};
      return {
        past: [...context.past, context.present],
        present: event.v,
        future: [] as string[]
      };
    }),
    undo: assign(({ context }) => ({
      past: context.past.slice(0, -1),
      present: context.past[context.past.length - 1] ?? context.present,
      future: [context.present, ...context.future]
    })),
    redo: assign(({ context }) => ({
      past: [...context.past, context.present],
      present: context.future[0] ?? context.present,
      future: context.future.slice(1)
    })),
    snapshot: assign({
      checkpoints: ({ context }) => [...context.checkpoints, context.present],
      past: () => [] as string[],
      future: () => [] as string[]
    })
  }
}).createMachine({
  id: 'checkpoint',
  context: { past: [], present: '', future: [], checkpoints: [] },
  on: {
    SET: { actions: 'apply' },
    UNDO: { guard: 'canUndo', actions: 'undo' },
    REDO: { guard: 'canRedo', actions: 'redo' },
    CHECKPOINT: { actions: 'snapshot' }
  }
});
