export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(position: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface ReadModelStore<V, E> {
  load(): Promise<V>;
  project(view: V, event: E): Promise<V>;
  save(view: V): Promise<void>;
}

export async function runSubscription<V, E>(
  subscriptionName: string,
  source: EventSource<E>,
  checkpoints: CheckpointStore,
  readModel: ReadModelStore<V, E>,
): Promise<void> {
  const last = await checkpoints.read(subscriptionName);
  const start: bigint = last ?? 0n;
  let view: V = await readModel.load();
  for await (const { position, event } of source.readFrom(start)) {
    view = await readModel.project(view, event);
    await readModel.save(view);
    await checkpoints.write(subscriptionName, position);
  }
}
