export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type ManuscriptEvent =
  | { type: "ManuscriptStarted"; id: string }
  | { type: "ChapterAppended"; chapterId: string }
  | { type: "ManuscriptLocked"; at: string };

export type ManuscriptState =
  | { status: "empty" }
  | { status: "open"; id: string; chapters: string[] }
  | { status: "locked"; id: string; chapters: string[]; lockedAt: string };

export function when(state: ManuscriptState, event: ManuscriptEvent): ManuscriptState {
  switch (event.type) {
    case "ManuscriptStarted": return { status: "open", id: event.id, chapters: [] };
    case "ChapterAppended":
      if (state.status !== "open") return state;
      return { ...state, chapters: [...state.chapters, event.chapterId] };
    case "ManuscriptLocked":
      if (state.status !== "open") return state;
      return { status: "locked", id: state.id, chapters: state.chapters, lockedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export async function loadManuscript(stream: AsyncIterable<ManuscriptEvent>): Promise<ManuscriptState> {
  return aggregateStream<ManuscriptState, ManuscriptEvent>(stream, when, { status: "empty" });
}
