export type CandidateEvent =
  | { type: "Nominated"; id: string; name: string; party: string; position: bigint }
  | { type: "Verified"; id: string; position: bigint }
  | { type: "VotesTallied"; id: string; delta: number; position: bigint };

export type Standings = Record<string, { name: string; party: string; verified: boolean; votes: number }>;
export const emptyStandings: Standings = {};

export function project(view: Standings, event: CandidateEvent): Standings {
  switch (event.type) {
    case "Nominated":
      return { ...view, [event.id]: { name: event.name, party: event.party, verified: false, votes: 0 } };
    case "Verified": {
      const cur = view[event.id];
      return cur ? { ...view, [event.id]: { ...cur, verified: true } } : view;
    }
    case "VotesTallied": {
      const cur = view[event.id];
      return cur ? { ...view, [event.id]: { ...cur, votes: cur.votes + event.delta } } : view;
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface BatchSource {
  fetch(from: bigint, size: number): Promise<CandidateEvent[]>;
}
export interface ReadStore {
  persist(view: Standings, upto: bigint): Promise<void>;
}

export type RebuildOpts = {
  from: bigint;
  batchSize: number;
  source: BatchSource;
  store: ReadStore;
};

export async function rebuild(opts: RebuildOpts): Promise<void> {
  let cursor = opts.from;
  let view: Standings = emptyStandings;
  for (;;) {
    const batch = await opts.source.fetch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const event of batch) {
      view = project(view, event);
      cursor = event.position;
    }
    await opts.store.persist(view, cursor);
  }
}
