export type GeoFenceState =
  | { status: "none" }
  | { status: "defined"; id: string; radiusM: number }
  | { status: "active"; id: string; radiusM: number; activatedAt: string };

export class UnknownEventError extends Error {
  constructor(key: string) { super(`UNKNOWN_EVENT:${key}`); this.name = "UnknownEventError"; }
}

export function upcast(raw: RawGeoFenceEvent): GeoFenceEvent {
  switch (raw.type) {
    case "GeoFenceDefined":
      if (raw.version === 1) return { type: "GeoFenceDefined", id: raw.id, radiusM: raw.radius };
      if (raw.version === 2) return { type: "GeoFenceDefined", id: raw.id, radiusM: raw.radiusM };
      throw new UnknownEventError(`GeoFenceDefined:${(raw as { version: number }).version}`);
    case "GeoFenceActivated":
      if (raw.version === 1) return { type: "GeoFenceActivated", at: "1970-01-01T00:00:00Z" };
      if (raw.version === 2) return { type: "GeoFenceActivated", at: raw.at };
      throw new UnknownEventError(`GeoFenceActivated:${(raw as { version: number }).version}`);
    case "GeoFenceBreached":
      if (raw.version === 1) return { type: "GeoFenceBreached", at: raw.at, by: raw.by };
      throw new UnknownEventError(`GeoFenceBreached:${(raw as { version: number }).version}`);
    default: {
      const _n: never = raw;
      throw new UnknownEventError("UNKNOWN");
    }
  }
}

export function evolve(state: GeoFenceState, event: GeoFenceEvent): GeoFenceState {
  switch (event.type) {
    case "GeoFenceDefined":
      return { status: "defined", id: event.id, radiusM: event.radiusM };
    case "GeoFenceActivated":
      if (state.status !== "defined") return state;
      return { status: "active", id: state.id, radiusM: state.radiusM, activatedAt: event.at };
    case "GeoFenceBreached":
      return state;
    default: { const _n: never = event; return state; }
  }
}

export function replayRaw(raws: RawGeoFenceEvent[]): GeoFenceState {
  const upcasted: GeoFenceEvent[] = raws.map(upcast);
  let state: GeoFenceState = { status: "none" };
  for (const e of upcasted) {
    state = evolve(state, e);
  }
  return state;
}
```

