export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S
): Promise<S> {
  let acc = initial;
  for await (const event of events) {
    acc = evolve(acc, event);
  }
  return acc;
}

export interface LivestockHerd {
  readonly id: string;
  readonly species: string;
  readonly headCount: number;
  readonly retired: boolean;
}

export type LivestockHerdEvent =
  | { type: "LivestockHerdRegistered"; id: string; species: string }
  | { type: "LivestockHerdAnimalsAdded"; count: number }
  | { type: "LivestockHerdAnimalsRemoved"; count: number }
  | { type: "LivestockHerdRetired" };

const empty: LivestockHerd = { id: "", species: "", headCount: 0, retired: false };

function evolve(state: LivestockHerd, event: LivestockHerdEvent): LivestockHerd {
  switch (event.type) {
    case "LivestockHerdRegistered":
      return { id: event.id, species: event.species, headCount: 0, retired: false };
    case "LivestockHerdAnimalsAdded":
      return { ...state, headCount: state.headCount + event.count };
    case "LivestockHerdAnimalsRemoved":
      return { ...state, headCount: Math.max(0, state.headCount - event.count) };
    case "LivestockHerdRetired":
      return { ...state, retired: true };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function loadHerd(events: AsyncIterable<LivestockHerdEvent>): Promise<LivestockHerd> {
  return aggregateStream(events, evolve, empty);
}
