export type AcclimatisationEvent =
  | { type: "AcclimatisationBegun"; climberId: string }
  | { type: "RotationCompleted"; altitude: number };

export interface AcclimatisationView {
  readonly climberId: string;
  readonly rotations: number;
  readonly highestAltitude: number;
}

export const emptyView: AcclimatisationView = { climberId: "", rotations: 0, highestAltitude: 0 };

export function project(view: AcclimatisationView, event: AcclimatisationEvent): AcclimatisationView {
  switch (event.type) {
    case "AcclimatisationBegun":
      return { climberId: event.climberId, rotations: 0, highestAltitude: 0 };
    case "RotationCompleted":
      return { ...view, rotations: view.rotations + 1, highestAltitude: Math.max(view.highestAltitude, event.altitude) };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface EventBatch<E> {
  readonly events: ReadonlyArray<E>;
  readonly nextRevision: bigint;
}

export interface EventStore<E> {
  readStream(from: bigint, batchSize: number): Promise<EventBatch<E>>;
}

export interface RebuildOptions<E, V> {
  readonly from: bigint;
  readonly batchSize: number;
  readonly project: (view: V, event: E) => V;
  readonly persist: (view: V) => Promise<void>;
  readonly truncate: () => Promise<void>;
}

export async function rebuild(
  store: EventStore<AcclimatisationEvent>,
  opts: RebuildOptions<AcclimatisationEvent, AcclimatisationView>,
): Promise<void> {
  if (opts.from === 0n) await opts.truncate();
  let cursor = opts.from;
  let view = emptyView;
  let done = false;
  while (!done) {
    const batch = await store.readStream(cursor, opts.batchSize);
    if (batch.events.length === 0) {
      done = true;
      break;
    }
    for (const event of batch.events) {
      view = opts.project(view, event);
    }
    await opts.persist(view);
    cursor = batch.nextRevision;
  }
}
