```typescript
import { Effect, Data } from "effect";

export interface DomainEvent {
  type: string;
  data: Record<string, unknown>;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  appendToStream(
    stream: string,
    events: DomainEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Data.TaggedError(
  "ConcurrencyConflict",
)<{ stream: string }> {}

export class AppendFailure extends Data.TaggedError("AppendFailure")<{
  cause: string;
}> {}

export const appendSafe = (
  store: EventStore,
  stream: string,
  events: DomainEvent[],
  expectedRevision: ExpectedRevision,
): Effect.Effect<bigint, ConcurrencyConflict | AppendFailure> =>
  Effect.gen(function* () {
    const result = yield* Effect.tryPromise({
      try: () =>
        store.appendToStream(stream, events, { expectedRevision }),
      catch: (err) => {
        if (
          err instanceof Error &&
          /wrong.*(revision|version)/i.test(err.message)
        ) {
          return new ConcurrencyConflict({ stream });
        }
        return new AppendFailure({ cause: String(err) });
      },
    });
    return result.nextExpectedRevision;
  });
