  | { type: "ReserveStock"; orderId: string }
  | { type: "ChargePayment"; orderId: string; amount: number }
  | { type: "RefundOrder"; orderId: string; reason: string };

export function react(
  event: IncomingEvent,
  context: { amountsByOrder: Readonly<Record<string, number>> },
): OutgoingCommand | null {
  switch (event.type) {
    case "OrderConfirmed":
      return { type: "ReserveStock", orderId: event.orderId };
    case "StockReserved": {
      const amount = context.amountsByOrder[event.orderId];
      if (amount === undefined) return null;
      return { type: "ChargePayment", orderId: event.orderId, amount };
    }
    case "StockReservationFailed":
      return { type: "RefundOrder", orderId: event.orderId, reason: event.reason };
    case "PaymentCharged":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export type Context = { amountsByOrder: Readonly<Record<string, number>> };

export function project(ctx: Context, event: IncomingEvent): Context {
  if (event.type === "OrderConfirmed") {
    return { amountsByOrder: { ...ctx.amountsByOrder, [event.orderId]: event.amount } };
  }
  return ctx;
}
