export interface GlazeTestEvent {
  type: string;
  data: Record<string, unknown>;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult {
  nextExpectedRevision: bigint;
}

export interface ReadResult<E> {
  events: E[];
  lastRevision: bigint | "no_stream";
}

export interface EventStore {
  readStream<E>(stream: string): Promise<ReadResult<E>>;
  appendToStream(
    stream: string,
    events: GlazeTestEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`concurrency conflict on ${stream}`);
  }
}

export async function appendChecked(
  store: EventStore,
  stream: string,
  events: GlazeTestEvent[],
): Promise<bigint> {
  const { lastRevision } = await store.readStream<GlazeTestEvent>(stream);
  const expectedRevision: ExpectedRevision =
    lastRevision === "no_stream" ? "no_stream" : lastRevision;
  try {
    const result = await store.appendToStream(stream, events, {
      expectedRevision,
    });
    return result.nextExpectedRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("WrongExpectedVersion")) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
