export interface YieldEvent { type: "EntryRecorded" | "ReportFinalized"; position: bigint; payload: unknown; }

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventStore {
  readFromStream(stream: string, fromPosition: bigint): AsyncIterable<YieldEvent>;
}

export interface YieldView { totalEntries: number; finalized: number; }

