  switch (event.type) {
    case "EntryRecorded": return { ...view, totalEntries: view.totalEntries + 1 };
    case "ReportFinalized": return { ...view, finalized: view.finalized + 1 };
    default: { const _n: never = event.type; return view; }
  }
}

export async function runSubscription(
  name: string,
  stream: string,
  store: EventStore,
  checkpoints: CheckpointStore,
  persist: (v: YieldView) => Promise<void>
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? 0n;
  let view: YieldView = { totalEntries: 0, finalized: 0 };
  for await (const event of store.readFromStream(stream, start)) {
    view = project(view, event);
    await persist(view);
    await checkpoints.write(name, event.position);
  }
}
