  readonly placedAt: string;
  readonly resultedAt: string | null;
  readonly turnaroundMs: number | null;
  readonly cancelled: boolean;
}

export interface TurnaroundView {
  readonly orders: Record<string, TurnaroundRow>;
}

export const emptyView: TurnaroundView = { orders: {} };

function diffMs(a: string, b: string): number {
  return Date.parse(b) - Date.parse(a);
}

export function project(view: TurnaroundView, event: LabOrderEvent): TurnaroundView {
  switch (event.type) {
    case "LabOrderPlaced":
      return { orders: { ...view.orders, [event.id]: { id: event.id, panel: event.panel, placedAt: event.at, resultedAt: null, turnaroundMs: null, cancelled: false } } };
    case "SpecimenCollected":
      return view;
    case "LabOrderResulted": {
      const row = view.orders[event.id];
      if (!row) return view;
      return { orders: { ...view.orders, [event.id]: { ...row, resultedAt: event.at, turnaroundMs: diffMs(row.placedAt, event.at) } } };
    }
    case "LabOrderCancelled": {
      const row = view.orders[event.id];
      if (!row) return view;
      return { orders: { ...view.orders, [event.id]: { ...row, cancelled: true } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
```

Fix this XState v4 code to v5 idioms — the guard uses the old cond key and positional signature:

```js
