```typescript
import { setup, assign, fromTransition, type ActorRefFrom } from 'xstate';

const tabLogic = fromTransition(
  (
    state: { content: string; dirty: boolean },
    event: { type: 'EDIT'; value: string } | { type: 'SAVE' },
  ) => {
    if (event.type === 'EDIT') return { content: event.value, dirty: true };
    if (event.type === 'SAVE') return { ...state, dirty: false };
    return state;
  },
  { content: '', dirty: false },
);

type TabRef = ActorRefFrom<typeof tabLogic>;

export const editorMachine = setup({
  types: {
    context: {} as {
      tabs: { id: string; ref: TabRef }[];
      active: string | null;
    },
    events: {} as
      | { type: 'OPEN'; id: string }
      | { type: 'CLOSE'; id: string }
      | { type: 'FOCUS'; id: string },
  },
  actors: { tabLogic },
  actions: {
    openTab: assign({
      tabs: ({ context, event, spawn }) => {
        if (event.type !== 'OPEN') return context.tabs;
        return [...context.tabs, { id: event.id, ref: spawn('tabLogic', { id: event.id }) }];
      },
      active: ({ context, event }) => (event.type === 'OPEN' ? event.id : context.active),
    }),
    closeTab: assign({
      tabs: ({ context, event }) =>
        event.type === 'CLOSE' ? context.tabs.filter((t) => t.id !== event.id) : context.tabs,
    }),
    focusTab: assign({
      active: ({ context, event }) => (event.type === 'FOCUS' ? event.id : context.active),
    }),
  },
}).createMachine({
  id: 'editor',
  context: { tabs: [], active: null },
  on: {
    OPEN: { actions: 'openTab' },
    CLOSE: { actions: 'closeTab' },
    FOCUS: { actions: 'focusTab' },
  },
});
