Convert this XState v4 fetch machine to v5. It uses exponential backoff driven by context.attempt:

```js
const m = Machine({
  id: 'backoff',
  initial: 'fetching',
  context: { attempt: 0, data: null },
  states: {
    fetching: {
      invoke: {
        src: 'load',
        onDone: { target: 'done', actions: assign({ data: (_, e) => e.data }) },
        onError: { target: 'waiting', cond: (c) => c.attempt < 5, actions: assign({ attempt: (c) => c.attempt + 1 }) }
      }
    },
    waiting: {
      after: {
        RETRY_DELAY: 'fetching'
      }
    },
    done: { type: 'final' }
  }
}, {
  delays: { RETRY_DELAY: (ctx) => 1000 * Math.pow(2, ctx.attempt) },
  services: { load: () => fetch('/x').then(r => r.json()) }
});
```

`setup({ delays })` takes the place of the v4 options block. The named delay reads `context.attempt` via destructuring, `cond` is `guard`, and the service becomes a `fromPromise` actor.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Payload { readonly ok: boolean }

export const backoffMachine = setup({
  types: {
    context: {} as { attempt: number; data: Payload | null },
    events: {} as { type: 'GIVE_UP' }
  },
  guards: {
    canRetry: ({ context }) => context.attempt < 5
  },
  delays: {
    RETRY_DELAY: ({ context }) => 1000 * Math.pow(2, context.attempt)
  },
  actors: {
    load: fromPromise<Payload, void>(async () => {
      const r = await fetch('/x');
      return (await r.json()) as Payload;
    })
  }
}).createMachine({
  id: 'backoff',
  initial: 'fetching',
  context: { attempt: 0, data: null },
  states: {
    fetching: {
      invoke: {
        src: 'load',
        onDone: { target: 'done', actions: assign({ data: ({ event }) => event.output }) },
        onError: {
          target: 'waiting',
          guard: 'canRetry',
          actions: assign({ attempt: ({ context }) => context.attempt + 1 })
        }
      }
    },
    waiting: { after: { RETRY_DELAY: 'fetching' } },
    done: { type: 'final' }
  }
});
```

```typescript
export type DomainEvent =
  | { type: "PullRequestMerged"; prId: string; commit: string; at: string }
  | { type: "BuildRunFinished"; runId: string; commit: string; artefactId: string }
  | { type: "BuildRunFailed"; runId: string; commit: string; reason: string }
  | { type: "ArtefactPublished"; id: string }
  | { type: "CodeReviewRequested"; id: string };

export type Command =
  | { type: "StartBuildRun"; runId: string; commit: string }
  | { type: "PublishArtefact"; id: string; commit: string }
  | { type: "NotifyBuildFailure"; commit: string; reason: string };

export type CommandEvent =
  | { type: "StartBuildRunQueued"; runId: string; commit: string }
  | { type: "PublishArtefactQueued"; id: string; commit: string }
  | { type: "NotifyBuildFailureQueued"; commit: string; reason: string };

export function react(event: DomainEvent): Command | null {
  switch (event.type) {
    case "PullRequestMerged":
      return { type: "StartBuildRun", runId: `run-${event.prId}`, commit: event.commit };
    case "BuildRunFinished":
      return { type: "PublishArtefact", id: event.artefactId, commit: event.commit };
    case "BuildRunFailed":
      return { type: "NotifyBuildFailure", commit: event.commit, reason: event.reason };
    case "ArtefactPublished":
      return null;
    case "CodeReviewRequested":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface EventStore {
  appendToStream(stream: string, events: CommandEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function dispatch(store: EventStore, streamName: string, event: DomainEvent, revision: bigint | "no_stream"): Promise<void> {
  const cmd = react(event);
  if (!cmd) return;
  const toEvent: CommandEvent =
    cmd.type === "StartBuildRun"
      ? { type: "StartBuildRunQueued", runId: cmd.runId, commit: cmd.commit }
      : cmd.type === "PublishArtefact"
        ? { type: "PublishArtefactQueued", id: cmd.id, commit: cmd.commit }
        : { type: "NotifyBuildFailureQueued", commit: cmd.commit, reason: cmd.reason };
  await store.appendToStream(streamName, [toEvent], { expectedRevision: revision });
}
```

The outbox pattern persists domain events and an integration-ready row inside the same transaction the write happens in. A downstream worker polls the outbox table, publishes the payload, and marks the row published. That avoids a dual-write between the event store and a message broker: if the transaction commits, both the stream append and the outbox row are durable; if it rolls back, neither side is visible.

```typescript
interface OutboxRow {
  readonly id: string;
  readonly payload: unknown;
  readonly publishedAt: string | null;
}

interface StoredEvent { readonly type: string; readonly data: unknown }

interface Tx {
  insertOutbox(row: OutboxRow): Promise<void>;
  appendToStream(stream: string, events: readonly StoredEvent[], opts: { expectedRevision: bigint | 'no_stream' | 'any' }): Promise<void>;
}

interface Conn {
  transaction<T>(body: (tx: Tx) => Promise<T>): Promise<T>;
}

// A separate worker polls rows where publishedAt IS NULL, ships them, then marks them published.
export async function appendWithOutbox(
  stream: string,
  events: readonly StoredEvent[],
  outboxRows: readonly OutboxRow[],
  conn: Conn,
): Promise<void> {
  await conn.transaction(async (tx) => {
    await tx.appendToStream(stream, events, { expectedRevision: 'any' });
    for (const row of outboxRows) {
      await tx.insertOutbox(row);
    }
  });
}
```

A League tracks member clubs and each club's tier; a promote/demote shifts a club by one tier. The Decider is a pure triple over a discriminated state union.

```typescript
export type LeagueState =
  | { status: "none" }
  | { status: "active"; id: string; clubs: Record<string, number> };

export type LeagueCommand =
  | { type: "found"; id: string }
  | { type: "register"; club: string; tier: number }
  | { type: "promote"; club: string }
  | { type: "demote"; club: string };

export type LeagueEvent =
  | { type: "LeagueFounded"; id: string }
  | { type: "LeagueClubRegistered"; club: string; tier: number }
  | { type: "LeagueClubPromoted"; club: string; newTier: number }
  | { type: "LeagueClubDemoted"; club: string; newTier: number };

export class LeagueError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const leagueDecider: Decider<LeagueCommand, LeagueEvent, LeagueState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "found":
        if (s.status !== "none") throw new LeagueError("ALREADY_FOUNDED");
        return [{ type: "LeagueFounded", id: c.id }];
      case "register":
        if (s.status !== "active") throw new LeagueError("NOT_ACTIVE");
        if (c.club in s.clubs) throw new LeagueError("DUPLICATE_CLUB");
        if (c.tier < 1) throw new LeagueError("INVALID_TIER");
        return [{ type: "LeagueClubRegistered", club: c.club, tier: c.tier }];
      case "promote": {
        if (s.status !== "active") throw new LeagueError("NOT_ACTIVE");
        const cur = s.clubs[c.club];
        if (cur === undefined) throw new LeagueError("UNKNOWN_CLUB");
        if (cur <= 1) throw new LeagueError("TOP_TIER");
        return [{ type: "LeagueClubPromoted", club: c.club, newTier: cur - 1 }];
      }
      case "demote": {
        if (s.status !== "active") throw new LeagueError("NOT_ACTIVE");
        const cur = s.clubs[c.club];
        if (cur === undefined) throw new LeagueError("UNKNOWN_CLUB");
        return [{ type: "LeagueClubDemoted", club: c.club, newTier: cur + 1 }];
      }
      default: {
        const _never: never = c;
        throw new LeagueError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "LeagueFounded":
        return { status: "active", id: e.id, clubs: {} };
      case "LeagueClubRegistered":
        if (s.status !== "active") return s;
        return { ...s, clubs: { ...s.clubs, [e.club]: e.tier } };
      case "LeagueClubPromoted":
      case "LeagueClubDemoted":
        if (s.status !== "active") return s;
        return { ...s, clubs: { ...s.clubs, [e.club]: e.newTier } };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
```

