Store each snapshot as `{ version, state }`. At load time, run upgraders until you reach CURRENT_VERSION and then assert the final shape. Each step returns a new object rather than mutating the stored blob.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type SprintV1 = { id: string; goal: string };
export type SprintV2 = { id: string; goal: string; points: number };
export type SprintV3 = {
  id: string;
  goal: string;
  points: number;
  status: "active" | "closed";
};

export type CurrentSprint = SprintV3;
export const CURRENT_VERSION = 3;

class SprintUpgradeError extends Error {}

function v1Tov2(s: SprintV1): SprintV2 {
  return { ...s, points: 0 };
}

function v2Tov3(s: SprintV2): SprintV3 {
  return { ...s, status: "active" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentSprint> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) {
    s = v1Tov2(s as SprintV1);
    v = 2;
  }
  if (v === 2) {
    s = v2Tov3(s as SprintV2);
    v = 3;
  }
  if (v !== CURRENT_VERSION) throw new SprintUpgradeError("UNSUPPORTED");
  const out = s as CurrentSprint;
  if (typeof out.id !== "string" || typeof out.points !== "number") {
    throw new SprintUpgradeError("SHAPE");
  }
  return { version: v, state: out };
}

export function loadSprint(raw: Snapshot<unknown>): CurrentSprint {
  return upgradeSnapshot(raw).state;
}
```

```typescript
export type RestaurantV1 = { id: string; openedAt: string };
export type RestaurantV2 = { id: string; openedAt: string; covers: number };
export type RestaurantV3 = { id: string; shiftStartedAt: string; covers: number };

export type CurrentRestaurant = RestaurantV3;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 3;

function v1Tov2(snap: Snapshot<RestaurantV1>): Snapshot<RestaurantV2> {
  return { version: 2, state: { ...snap.state, covers: 0 } };
}

function v2Tov3(snap: Snapshot<RestaurantV2>): Snapshot<RestaurantV3> {
  const { openedAt, ...rest } = snap.state;
  return { version: 3, state: { ...rest, shiftStartedAt: openedAt } };
}

export class SnapshotError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "SnapshotError"; }
}

export function loadSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentRestaurant> {
  let current: Snapshot<unknown> = raw;
  if (current.version === 1) current = v1Tov2(current as Snapshot<RestaurantV1>);
  if (current.version === 2) current = v2Tov3(current as Snapshot<RestaurantV2>);
  if (current.version !== CURRENT_VERSION) {
    throw new SnapshotError(`UNSUPPORTED_VERSION_${current.version}`);
  }
  return current as Snapshot<CurrentRestaurant>;
}
