```typescript
export type OrderEvent =
  | { type: "OrderPlaced"; id: string; total: number }
  | { type: "OrderPaid"; at: string }
  | { type: "OrderShipped"; tracking: string };

export type OrderState =
  | { status: "none" }
  | { status: "placed"; id: string; total: number }
  | { status: "paid"; id: string; total: number; paidAt: string }
  | { status: "shipped"; id: string; total: number; tracking: string };

export const initialOrderState: OrderState = { status: "none" };

export function evolve(state: OrderState, event: OrderEvent): OrderState {
  switch (event.type) {
    case "OrderPlaced":
      return { status: "placed", id: event.id, total: event.total };
    case "OrderPaid":
      if (state.status !== "placed") return state;
      return { status: "paid", id: state.id, total: state.total, paidAt: event.at };
    case "OrderShipped":
      if (state.status !== "paid") return state;
      return { status: "shipped", id: state.id, total: state.total, tracking: event.tracking };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregateStream<S, E>(
  events: ReadonlyArray<E>,
  reducer: (s: S, e: E) => S,
  initial: S,
): S {
  let state = initial;
  for (const event of events) {
    state = reducer(state, event);
  }
  return state;
}

export function orderFrom(events: OrderEvent[]): OrderState {
  return aggregateStream(events, evolve, initialOrderState);
}
