export type RestaurantEvent =
  | { type: "RestaurantOpened"; id: string }
  | { type: "GuestsSeated"; count: number }
  | { type: "RestaurantClosed" };

export type OccupancyView = Readonly<{ seated: number; isOpen: boolean }>;
const empty: OccupancyView = { seated: 0, isOpen: false };

export function project(view: OccupancyView, e: RestaurantEvent): OccupancyView {
  switch (e.type) {
    case "RestaurantOpened": return { seated: 0, isOpen: true };
    case "GuestsSeated": return { ...view, seated: view.seated + e.count };
    case "RestaurantClosed": return { ...view, isOpen: false };
    default: { const _n: never = e; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed {
  readFrom(stream: string, from: bigint | null): AsyncIterable<{ revision: bigint; event: RestaurantEvent }>;
}

export interface ViewStore {
  save(view: OccupancyView): Promise<void>;
}

export async function runSubscription(
  ctx: { feed: EventFeed; checkpoints: CheckpointStore; views: ViewStore },
  stream: string,
  subscriptionName: string
): Promise<void> {
  const from = await ctx.checkpoints.read(subscriptionName);
  let view: OccupancyView = empty;
  for await (const { revision, event } of ctx.feed.readFrom(stream, from)) {
    view = project(view, event);
    // Save the view BEFORE the checkpoint so a crash replays, never skips.
    await ctx.views.save(view);
    await ctx.checkpoints.write(subscriptionName, revision);
  }
}
