export type RunbookEvent =
  | { type: "RunbookAuthored"; id: string; title: string }
  | { type: "StepAdded" }
  | { type: "RunbookRetired" };

export type RunbookView = { id: string; title: string; steps: number; retired: boolean };

export const empty: RunbookView = { id: "", title: "", steps: 0, retired: false };

export function project(v: RunbookView, e: RunbookEvent): RunbookView {
  switch (e.type) {
    case "RunbookAuthored": return { id: e.id, title: e.title, steps: 0, retired: false };
    case "StepAdded": return { ...v, steps: v.steps + 1 };
    case "RunbookRetired": return { ...v, retired: true };
    default: { const _n: never = e; return v; }
  }
}

export interface Batch<E> { events: E[]; nextCursor: bigint | null; lastRevision: bigint }

export interface Source<E> { readBatch(from: bigint, size: number): Promise<Batch<E>> }

export interface Persist { save(view: RunbookView, revision: bigint): Promise<void> }

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  project: (view: RunbookView, event: RunbookEvent) => RunbookView;
  persist: (view: RunbookView, revision: bigint) => Promise<void>;
}

export async function rebuild(src: Source<RunbookEvent>, opts: RebuildOptions): Promise<void> {
  let cursor: bigint | null = opts.from;
  let view: RunbookView = empty;
  while (cursor !== null) {
    const batch: Batch<RunbookEvent> = await src.readBatch(cursor, opts.batchSize);
    if (batch.events.length === 0) break;
    for (const e of batch.events) view = opts.project(view, e);
    await opts.persist(view, batch.lastRevision);
    cursor = batch.nextCursor;
  }
}
