```typescript
import { Effect } from "effect";

export type PipelineState = { status: "none" } | { status: "created"; id: string };
export type PipelineCommand = { type: "create"; id: string; name: string };
export type PipelineEvent = { type: "PipelineCreated"; id: string; name: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

const initial: PipelineState = { status: "none" };

function evolve(s: PipelineState, e: PipelineEvent): PipelineState {
  switch (e.type) {
    case "PipelineCreated": return { status: "created", id: e.id };
    default: { const _n: never = e.type; return s; }
  }
}

function decide(c: PipelineCommand, s: PipelineState): PipelineEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "PipelineCreated", id: c.id, name: c.name }];
    default: { const _n: never = c.type; throw new Error("UNKNOWN"); }
  }
}

export function handle(command: PipelineCommand, stream: string, store: EventStore) {
  return Effect.gen(function* () {
    const head = yield* Effect.promise(() => store.readStream<PipelineEvent>(stream));
    const state = head.events.reduce<PipelineState>(evolve, initial);
    const newEvents = decide(command, state);
    yield* Effect.promise(() =>
      store.appendToStream<PipelineEvent>(stream, newEvents, { expectedRevision: head.revision }),
    );
  });
}
