export type ProvisioningEvent =
  | { type: "ProvisioningOpened"; id: string; required: number }
  | { type: "StockRecorded"; quantity: number }
  | { type: "ProvisioningFinalised"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult {
  readonly nextExpectedRevision: bigint;
}

export interface StoreConflict {
  readonly kind: "conflict";
  readonly streamRevision: bigint | "no_stream";
}

export interface EventStore<E> {
  readStreamRevision(stream: string): Promise<bigint | "no_stream">;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<AppendResult | StoreConflict>;
}

export class ConcurrencyConflict extends Error {
  constructor(
    public readonly stream: string,
    public readonly expected: ExpectedRevision,
  ) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function writeProvisioning(
  store: EventStore<ProvisioningEvent>,
  stream: string,
  events: ReadonlyArray<ProvisioningEvent>,
): Promise<bigint> {
  const expectedRevision = await store.readStreamRevision(stream);
  const result = await store.appendToStream(stream, events, { expectedRevision });
  if ("kind" in result && result.kind === "conflict") {
    throw new ConcurrencyConflict(stream, expectedRevision);
  }
  return (result as AppendResult).nextExpectedRevision;
}
