export type GateAssignmentState =
  | { status: "none" }
  | { status: "requested"; id: string }
  | { status: "assigned"; id: string; gate: string }
  | { status: "released"; id: string };

export type GateAssignmentCommand =
  | { type: "requestGate"; id: string }
  | { type: "assignGate"; gate: string; occupied: boolean }
  | { type: "releaseGate" };

export type GateAssignmentEvent =
  | { type: "GateRequested"; id: string }
  | { type: "GateAssigned"; gate: string }
  | { type: "GateReleased" };

export class DomainError extends Error { constructor(public readonly code: string) { super(code); } }

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const gateDecider: Decider<GateAssignmentCommand, GateAssignmentEvent, GateAssignmentState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "requestGate":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "GateRequested", id: c.id }];
      case "assignGate":
        if (s.status !== "requested") throw new DomainError("NOT_REQUESTED");
        if (c.occupied) throw new DomainError("GATE_OCCUPIED");
        return [{ type: "GateAssigned", gate: c.gate }];
      case "releaseGate":
        if (s.status !== "assigned") throw new DomainError("NOT_ASSIGNED");
        return [{ type: "GateReleased" }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "GateRequested": return { status: "requested", id: e.id };
      case "GateAssigned":
        if (s.status !== "requested") return s;
        return { status: "assigned", id: s.id, gate: e.gate };
      case "GateReleased":
        if (s.status !== "assigned") return s;
        return { status: "released", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};
