type DropState = { readonly sku: string; readonly stock: number; readonly closed: boolean };
type DropEvent =
  | { type: 'Announced'; sku: string; stock: number }
  | { type: 'UnitSold' }
  | { type: 'Closed' };
type DropCommand = { type: 'Sell' };

const initial: DropState = { sku: '', stock: 0, closed: false };

function evolve(state: DropState, event: DropEvent): DropState {
  switch (event.type) {
    case 'Announced': return { sku: event.sku, stock: event.stock, closed: false };
    case 'UnitSold': return { ...state, stock: state.stock - 1 };
    case 'Closed': return { ...state, closed: true };
    default: { const _e: never = event; return _e; }
  }
}

function decide(_cmd: DropCommand, state: DropState): DropEvent[] {
  if (state.closed || state.stock === 0) throw new Error('no stock');
  const next: DropEvent[] = [{ type: 'UnitSold' }];
  if (state.stock - 1 === 0) next.push({ type: 'Closed' });
  return next;
}

async function aggregateStream<S, E>(stream: AsyncIterable<E>, fn: (s: S, e: E) => S, init: S): Promise<S> {
  let s = init;
  for await (const e of stream) s = fn(s, e);
  return s;
}

interface EventStore {
  readStream(s: string): AsyncIterable<DropEvent>;
  appendToStream(s: string, evs: readonly DropEvent[]): Promise<void>;
}

export async function handle(stream: string, cmd: DropCommand, store: EventStore): Promise<void> {
  const state = await aggregateStream<DropState, DropEvent>(store.readStream(stream), evolve, initial);
  const events = decide(cmd, state);
  await store.appendToStream(stream, events);
}
