import { Effect } from "effect";

export type CampaignStopEvent =
  | { type: "planned"; id: string; city: string }
  | { type: "confirmed"; date: string }
  | { type: "executed"; at: string };

export interface CampaignStopState {
  id: string | null;
  city: string | null;
  confirmedFor: string | null;
  executedAt: string | null;
}

export const initialCampaignStop: CampaignStopState = {
  id: null,
  city: null,
  confirmedFor: null,
  executedAt: null,
};

type Handlers<S, E extends { type: string }> = {
  [K in E["type"]]: (state: S, event: Extract<E, { type: K }>) => S;
};

export function when<S, E extends { type: string }>(h: Handlers<S, E>): (s: S, e: E) => S {
  return (s, e) => (h[e.type as E["type"]] as (s: S, e: E) => S)(s, e);
}

export const evolveCampaignStop = when<CampaignStopState, CampaignStopEvent>({
  planned: (s, e) => ({ ...s, id: e.id, city: e.city }),
  confirmed: (s, e) => ({ ...s, confirmedFor: e.date }),
  executed: (s, e) => ({ ...s, executedAt: e.at }),
});

export function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Effect.Effect<S, Error, never> {
  return Effect.tryPromise({
    try: async () => {
      let state = initial;
      for await (const event of stream) {
        state = evolve(state, event);
      }
      return state;
    },
    catch: (u) => (u instanceof Error ? u : new Error(String(u))),
  });
}

export function loadCampaignStop(
  stream: AsyncIterable<CampaignStopEvent>,
