const refresh = fromPromise<number, void>(async () => 42);

export const swrMachine = setup({
  types: { context: {} as Ctx, events: {} as { type: 'FORCE' } },
  actors: { refresh }
}).createMachine({
  id: 'swr',
  context: { data: null },
  initial: 'cold',
  states: {
    cold: { always: 'revalidating' },
    fresh: { after: { 10000: 'revalidating' }, on: { FORCE: 'revalidating' } },
    revalidating: {
      invoke: {
        src: 'refresh',
        onDone: { target: 'fresh', actions: assign({ data: ({ event }) => event.output }) },
        onError: 'fresh'
