```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

`when(state, event)` is a pure function you pass to `reduce`. It must exhaustively switch on `event.type` with a `never` default so TS catches missing cases.

```typescript
type DraftThreadEvent =
  | { type: 'DraftCreated'; id: string; title: string }
  | { type: 'DraftTitleChanged'; title: string }
  | { type: 'DraftPublished'; publishedAt: string };

type DraftThreadState = Readonly<{
  id: string;
  title: string;
  publishedAt: string | null;
}>;

const initial: DraftThreadState = { id: '', title: '', publishedAt: null };

export function when(state: DraftThreadState, event: DraftThreadEvent): DraftThreadState {
  switch (event.type) {
    case 'DraftCreated':
      return { id: event.id, title: event.title, publishedAt: null };
    case 'DraftTitleChanged':
      return { ...state, title: event.title };
    case 'DraftPublished':
      return { ...state, publishedAt: event.publishedAt };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function buildDraft(events: DraftThreadEvent[]): DraftThreadState {
  return events.reduce(when, initial);
}

// Direct call verification: when(initial, { type: 'DraftCreated', id: 'd1', title: 'x' });
when(initial, { type: 'DraftCreated', id: 'd1', title: 'x' });
