```typescript
export type InventoryEvent =
  | { type: "StockReceived"; sku: string; qty: number }
  | { type: "StockReserved"; sku: string; qty: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: InventoryEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: InventoryEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ ok: true; nextRevision: bigint } | { ok: false; actualRevision: bigint | null }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string) {
    super("CONCURRENCY_CONFLICT");
  }
}

export class DomainError extends Error {}

export async function appendInventoryEvents(
  store: EventStore,
  stream: string,
  produce: (current: InventoryEvent[]) => InventoryEvent[],
  maxRetries: number,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxRetries) {
    const { events, revision } = await store.readStream(stream);
    const newEvents = produce(events);
    if (newEvents.length === 0) return revision ?? -1n;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    const result = await store.appendToStream(stream, newEvents, { expectedRevision });
    if (result.ok) return result.nextRevision;
    attempt += 1;
  }
  throw new ConcurrencyConflict(stream);
}
