export type AssignmentState =
  | { status: "none" }
  | { status: "assigned"; id: string; learner: string; dueAt: string }
  | { status: "submitted"; id: string; learner: string; submittedAt: string; artefact: string }
  | { status: "graded"; id: string; learner: string; score: number };

export type AssignmentCommand =
  | { type: "assign"; id: string; learner: string; dueAt: string }
  | { type: "submit"; at: string; artefact: string }
  | { type: "grade"; score: number };

export type AssignmentEvent =
  | { type: "AssignmentAssigned"; id: string; learner: string; dueAt: string }
  | { type: "AssignmentSubmitted"; at: string; artefact: string }
  | { type: "AssignmentGraded"; score: number };

export class AssignmentError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const assignmentDecider: Decider<AssignmentCommand, AssignmentEvent, AssignmentState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "assign":
        if (s.status !== "none") throw new AssignmentError("ALREADY_ASSIGNED");
        return [{ type: "AssignmentAssigned", id: c.id, learner: c.learner, dueAt: c.dueAt }];
      case "submit":
        if (s.status !== "assigned") throw new AssignmentError("NOT_ASSIGNED");
        if (c.artefact.length === 0) throw new AssignmentError("EMPTY_ARTEFACT");
        return [{ type: "AssignmentSubmitted", at: c.at, artefact: c.artefact }];
      case "grade":
        if (s.status !== "submitted") throw new AssignmentError("NOT_SUBMITTED");
        if (c.score < 0 || c.score > 100) throw new AssignmentError("SCORE_OUT_OF_RANGE");
        return [{ type: "AssignmentGraded", score: c.score }];
      default: { const _n: never = c; throw new AssignmentError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "AssignmentAssigned":
        return { status: "assigned", id: e.id, learner: e.learner, dueAt: e.dueAt };
      case "AssignmentSubmitted":
        if (s.status !== "assigned") return s;
        return { status: "submitted", id: s.id, learner: s.learner, submittedAt: e.at, artefact: e.artefact };
      case "AssignmentGraded":
        if (s.status !== "submitted") return s;
        return { status: "graded", id: s.id, learner: s.learner, score: e.score };
      default: { const _n: never = e; return s; }
    }
  },
};
