export type GuestStayEvent =
  | { type: "checked-in"; data: { id: string; guest: string } }
  | { type: "night-charged"; data: { amount: number } }
  | { type: "checked-out"; data: { at: string } };

export type GuestStay = Readonly<{
  id: string;
  guest: string;
  nights: number;
  totalCharged: number;
  status: "checked-in" | "checked-out";
  checkedOutAt?: string;
}>;

export function when(
  current: Partial<GuestStay>,
  event: GuestStayEvent,
): Partial<GuestStay> {
  switch (event.type) {
    case "checked-in":
      return {
        id: event.data.id,
        guest: event.data.guest,
        nights: 0,
        totalCharged: 0,
        status: "checked-in",
      };
    case "night-charged":
      return {
        ...current,
        nights: (current.nights ?? 0) + 1,
        totalCharged: (current.totalCharged ?? 0) + event.data.amount,
      };
    case "checked-out":
      return {
        ...current,
        status: "checked-out",
        checkedOutAt: event.data.at,
      };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

function isGuestStay(v: Partial<GuestStay>): v is GuestStay {
  return !!v.id && !!v.guest && typeof v.nights === "number" && typeof v.totalCharged === "number" && !!v.status;
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const s = events.reduce<Partial<A>>(reducer, {});
  if (!check(s)) throw new Error("INVALID_STATE");
  return s;
}

export function stayFrom(events: GuestStayEvent[]): GuestStay {
  return aggregateStream(events, when, isGuestStay);
}
