  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ColorGradeCreated", id: command.id, shotId: command.shotId }];
      case "applyLut":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "ColorGradeLutApplied", lut: command.lut }];
      case "approve":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (state.lut === null) throw new DomainError("NO_LUT");
        return [{ type: "ColorGradeApproved", approvedBy: command.approvedBy, lut: state.lut }];
      case "revoke":
        if (state.status !== "approved") throw new DomainError("NOT_APPROVED");
        return [{ type: "ColorGradeRevoked" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ColorGradeCreated":
        return { status: "draft", id: event.id, shotId: event.shotId, lut: null };
      case "ColorGradeLutApplied":
        if (state.status !== "draft") return state;
        return { ...state, lut: event.lut };
      case "ColorGradeApproved":
        if (state.status !== "draft") return state;
        return { status: "approved", id: state.id, shotId: state.shotId, lut: event.lut, approvedBy: event.approvedBy };
      case "ColorGradeRevoked":
        if (state.status !== "approved") return state;
        return { status: "revoked", id: state.id, shotId: state.shotId };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
