import { setup, assign } from 'xstate';

interface Ctx { previousVersion: string | null; currentVersion: string; error: string | null }

type Ev =
  | { type: 'DEPLOY'; version: string }
  | { type: 'DEPLOYED' }
  | { type: 'PROD_FAILED'; error: string }
  | { type: 'ROLLBACK_DONE' };

export const rollbackDeployMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    stashPrevious: assign({ previousVersion: ({ context }) => context.currentVersion }),
    applyDeploy: assign({
      currentVersion: ({ event }) => (event.type === 'DEPLOY' ? event.version : '')
    }),
    recordError: assign({ error: ({ event }) => (event.type === 'PROD_FAILED' ? event.error : null) }),
    restorePrevious: assign({
      currentVersion: ({ context }) => context.previousVersion ?? context.currentVersion
    })
  },
  guards: {
    hasPrevious: ({ context }) => context.previousVersion !== null
  }
}).createMachine({
  id: 'rollbackDeploy',
  context: { previousVersion: null, currentVersion: 'v0', error: null },
  initial: 'idle',
  states: {
    idle: { on: { DEPLOY: { target: 'deploying', actions: ['stashPrevious', 'applyDeploy'] } } },
    deploying: { on: { DEPLOYED: 'live', PROD_FAILED: { target: 'rolling', actions: 'recordError' } } },
    live: { on: { DEPLOY: { target: 'deploying', actions: ['stashPrevious', 'applyDeploy'] } } },
    rolling: {
      entry: [{ type: 'restorePrevious' }],
