  | { type: "ClickReverted"; clickId: string };

export interface StoredEvent<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface EventStore<E> {
  readBatch(stream: string, from: bigint, limit: number): Promise<readonly StoredEvent<E>[]>;
}

export async function* readFromStream(
  store: EventStore<ClickEvent>,
  stream: string,
  fromRevision: bigint,
  batchSize = 128,
): AsyncIterable<StoredEvent<ClickEvent>> {
  let cursor = fromRevision;
  for (;;) {
    const batch = await store.readBatch(stream, cursor, batchSize);
    if (batch.length === 0) return;
    for (const stored of batch) {
      yield stored;
      cursor = stored.revision + 1n;
    }
    if (batch.length < batchSize) return;
  }
}

