  for await (const stored of readFromStream(store, "clicks-abc", 0n)) {
    if (stored.event.type === "ClickRecorded") {
      console.log(stored.event.creativeId, stored.event.at);
    }
  }
}

main(null as unknown as EventStore<ClickEvent>).catch((err: unknown) => {
  console.error(err);
  process.exitCode = 1;
