```typescript
interface RecipeCreatedV1 {
  type: "RecipeCreated";
  version: 1;
  name: string;
  id: string;
}

interface RecipeStepAddedV1 {
  type: "RecipeStepAdded";
  version: 1;
}

interface RecipeCreatedV2 {
  type: "RecipeCreated";
  version: 2;
  title: string;
  id: string;
}

interface RecipeStepAddedV2 {
  type: "RecipeStepAdded";
  version: 2;
  stepIndex: number;
}

export type StoredRecipeEvent = RecipeCreatedV1 | RecipeStepAddedV1 | RecipeCreatedV2 | RecipeStepAddedV2;
export type RecipeEvent = RecipeCreatedV2 | RecipeStepAddedV2;

export class UnknownEventError extends Error {
  constructor(public readonly detail: unknown) {
    super("unknown stored event");
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: unknown): RecipeEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError(raw);
  const candidate = raw as { type?: unknown; version?: unknown };
  if (candidate.type === "RecipeCreated" && candidate.version === 1) {
    const v1 = raw as RecipeCreatedV1;
    return { type: "RecipeCreated", version: 2, id: v1.id, title: v1.name };
  }
  if (candidate.type === "RecipeCreated" && candidate.version === 2) {
    return raw as RecipeCreatedV2;
  }
  if (candidate.type === "RecipeStepAdded" && candidate.version === 1) {
    return { type: "RecipeStepAdded", version: 2, stepIndex: 0 };
  }
  if (candidate.type === "RecipeStepAdded" && candidate.version === 2) {
    return raw as RecipeStepAddedV2;
  }
  throw new UnknownEventError(raw);
}

export interface RecipeReadModel {
  readonly id: string;
  readonly title: string;
  readonly steps: number;
}

export function when(state: RecipeReadModel, event: RecipeEvent): RecipeReadModel {
  switch (event.type) {
    case "RecipeCreated":
      return { id: event.id, title: event.title, steps: 0 };
    case "RecipeStepAdded":
      return { ...state, steps: Math.max(state.steps, event.stepIndex + 1) };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function replay(stored: ReadonlyArray<unknown>): RecipeReadModel {
  const empty: RecipeReadModel = { id: "", title: "", steps: 0 };
  return stored.reduce<RecipeReadModel>((state, raw) => when(state, upcast(raw)), empty);
}

