import { Effect } from "effect";

export type ProvisioningEvent =
  | { type: "StockRecorded"; quantity: number }
  | { type: "ProvisioningFinalised"; at: string };

export interface EventEnvelope<E> {
  readonly event: E;
  readonly position: bigint;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface ProvisioningReadModel {
  apply(event: ProvisioningEvent): Promise<void>;
}

export function runSubscription(
  name: string,
  source: AsyncIterable<EventEnvelope<ProvisioningEvent>>,
  checkpointStore: CheckpointStore,
  readModel: ProvisioningReadModel,
): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const start = yield* Effect.promise(() => checkpointStore.read(name));
    const loop = async (): Promise<void> => {
      for await (const envelope of source) {
        if (start !== null && envelope.position <= start) continue;
        await readModel.apply(envelope.event);
        await checkpointStore.write(name, envelope.position);
      }
    };
    yield* Effect.promise(loop);
  });
}

export function readStream<E>(
  source: AsyncIterable<EventEnvelope<E>>,
): AsyncIterable<EventEnvelope<E>> {
  return source;
}
