```typescript
export type PipelineEvent =
  | { type: "PipelineCreated"; id: string }
  | { type: "StageFinished"; success: boolean };

export type PipelineView = { id: string; passed: number; failed: number };

export const emptyView: PipelineView = { id: "", passed: 0, failed: 0 };

function defaultProject(view: PipelineView, e: PipelineEvent): PipelineView {
  switch (e.type) {
    case "PipelineCreated": return { id: e.id, passed: 0, failed: 0 };
    case "StageFinished": return e.success
      ? { ...view, passed: view.passed + 1 }
      : { ...view, failed: view.failed + 1 };
    default: { const _n: never = e; return view; }
  }
}

export interface EventStoreIterator<E> {
  readBatch(from: bigint, size: number): Promise<{ events: { event: E; revision: bigint }[]; next: bigint | null }>;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  project: (view: PipelineView, event: PipelineEvent) => PipelineView;
  persist: (view: PipelineView, revision: bigint) => Promise<void>;
}

export async function rebuild(
  src: EventStoreIterator<PipelineEvent>,
  opts: RebuildOptions,
): Promise<void> {
  let cursor: bigint | null = opts.from;
  let view: PipelineView = emptyView;
  while (cursor !== null) {
    const { events, next }: { events: { event: PipelineEvent; revision: bigint }[]; next: bigint | null } =
      await src.readBatch(cursor, opts.batchSize);
    if (events.length === 0) break;
    let lastRev: bigint = cursor;
    for (const { event, revision } of events) {
      view = opts.project(view, event);
      lastRev = revision;
    }
    await opts.persist(view, lastRev);
    cursor = next;
  }
}

export { defaultProject };
