```typescript
interface ContainerV1 {
  id: string;
  seal: string;
  weight: number;
}

interface ContainerV2 {
  id: string;
  seal: string;
  grossWeight: number;
  tareWeight: number;
}

interface ContainerV3 {
  id: string;
  seal: string;
  grossWeight: number;
  tareWeight: number;
  origin: string;
  route: ReadonlyArray<string>;
}

export type CurrentContainer = ContainerV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3 as const;

function v1Tov2(prev: ContainerV1): ContainerV2 {
  return { id: prev.id, seal: prev.seal, grossWeight: prev.weight, tareWeight: 0 };
}

function v2Tov3(prev: ContainerV2): ContainerV3 {
  return { ...prev, origin: "UNKNOWN", route: [] };
}

function isCurrent(value: unknown): value is CurrentContainer {
  if (typeof value !== "object" || value === null) return false;
  const v = value as Partial<CurrentContainer>;
  return typeof v.id === "string"
    && typeof v.seal === "string"
    && typeof v.grossWeight === "number"
    && typeof v.tareWeight === "number"
    && typeof v.origin === "string"
    && Array.isArray(v.route);
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentContainer> {
  let current: { version: number; state: unknown } = { version: snap.version, state: snap.state };
  if (current.version === 1) {
    current = { version: 2, state: v1Tov2(current.state as ContainerV1) };
  }
  if (current.version === 2) {
    current = { version: 3, state: v2Tov3(current.state as ContainerV2) };
  }
  if (current.version !== CURRENT_VERSION) {
    throw new Error(`Unsupported snapshot version ${current.version}`);
  }
  if (!isCurrent(current.state)) {
    throw new Error("Upgraded snapshot does not match CurrentContainer shape");
  }
  return { version: CURRENT_VERSION, state: current.state };
}
