import { Effect } from "effect";

export type DeploymentState = { status: "idle" } | { status: "running"; id: string };
export type DeploymentCommand = { type: "start"; id: string; target: string };
export type DeploymentEvent = { type: "DeploymentStarted"; id: string; target: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

const initial: DeploymentState = { status: "idle" };

function evolve(s: DeploymentState, e: DeploymentEvent): DeploymentState {
  switch (e.type) {
    case "DeploymentStarted": return { status: "running", id: e.id };
    default: { const _n: never = e.type; return s; }
  }
}

function decide(c: DeploymentCommand, s: DeploymentState): DeploymentEvent[] {
  switch (c.type) {
    case "start":
      if (s.status !== "idle") throw new Error("IN_PROGRESS");
      return [{ type: "DeploymentStarted", id: c.id, target: c.target }];
    default: { const _n: never = c.type; throw new Error("UNKNOWN"); }
  }
}

export function handle(cmd: DeploymentCommand, stream: string, store: EventStore) {
  return Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => store.readStream<DeploymentEvent>(stream));
    const state = events.reduce<DeploymentState>(evolve, initial);
    const next = decide(cmd, state);
    yield* Effect.promise(() =>
      store.appendToStream<DeploymentEvent>(stream, next, { expectedRevision: revision }),
    );
  });
}
