A Decider bundles three pure functions over an aggregate: an `initialState` literal, a `decide(command, state)` that validates invariants and returns the events the command produced (or throws a typed error), and an `evolve(state, event)` that folds an event into the next state. Both functions are I/O-free, which makes them trivial to unit-test and to replay against an event stream. The I/O adapters (read stream, append stream) live outside; the Decider never touches a clock or a database.

```typescript
export type HarvestState =
  | { status: "scheduled"; id: string; cropId: string; plannedAt: string }
  | { status: "inProgress"; id: string; cropId: string; startedAt: string }
  | { status: "completed"; id: string; yieldKg: number }
  | { status: "none" };

export type HarvestCommand =
  | { type: "schedule"; id: string; cropId: string; plannedAt: string }
  | { type: "start"; at: string }
  | { type: "complete"; yieldKg: number };

export type HarvestEvent =
  | { type: "HarvestScheduled"; id: string; cropId: string; plannedAt: string }
  | { type: "HarvestStarted"; at: string }
  | { type: "HarvestCompleted"; yieldKg: number };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const harvestDecider: Decider<HarvestCommand, HarvestEvent, HarvestState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new DomainError("ALREADY_SCHEDULED");
        return [{ type: "HarvestScheduled", id: command.id, cropId: command.cropId, plannedAt: command.plannedAt }];
      case "start":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "HarvestStarted", at: command.at }];
      case "complete":
        if (state.status !== "inProgress") throw new DomainError("NOT_IN_PROGRESS");
        if (command.yieldKg < 0) throw new DomainError("NEGATIVE_YIELD");
        return [{ type: "HarvestCompleted", yieldKg: command.yieldKg }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "HarvestScheduled":
        return { status: "scheduled", id: event.id, cropId: event.cropId, plannedAt: event.plannedAt };
      case "HarvestStarted":
        if (state.status !== "scheduled") return state;
        return { status: "inProgress", id: state.id, cropId: state.cropId, startedAt: event.at };
      case "HarvestCompleted":
        if (state.status !== "inProgress") return state;
        return { status: "completed", id: state.id, yieldKg: event.yieldKg };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
