On conflict, reload the stream, re-decide against the fresh state, and try again. Bound the retries so a runaway command doesn't loop forever. The expectedRevision flows from the latest read each attempt.

```typescript
export type SubmissionEvent =
  | { type: "SubmissionStarted"; id: string }
  | { type: "AttachmentAttached"; filename: string }
  | { type: "SubmissionTurnedIn"; at: string };

export type ExpectedRevision = bigint | "no_stream";

export interface ReadSlice {
  events: ReadonlyArray<SubmissionEvent>;
  revision: bigint | null;
}

export interface EventStore {
  readStream(stream: string): Promise<ReadSlice>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<SubmissionEvent>,
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ ok: true; nextRevision: bigint } | { ok: false }>;
}

export class ConcurrencyConflict extends Error {}

export async function appendWithRetry(
  store: EventStore,
  stream: string,
  decide: (events: ReadonlyArray<SubmissionEvent>) => ReadonlyArray<SubmissionEvent>,
  maxAttempts: number,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    const slice = await store.readStream(stream);
    const next = decide(slice.events);
    if (next.length === 0) return slice.revision ?? 0n;
    const expectedRevision: ExpectedRevision = slice.revision ?? "no_stream";
    const result = await store.appendToStream(stream, next, { expectedRevision });
    if (result.ok) return result.nextRevision;
    attempt = attempt + 1;
  }
  throw new ConcurrencyConflict("MAX_RETRIES_EXHAUSTED");
}
```

