export type TestSuiteEvent =
  | { type: "TestSuiteRegistered"; id: string; name: string }
  | { type: "TestSuiteRunStarted"; runId: string }
  | { type: "TestSuiteResultReported"; passed: number; failed: number };

export interface TestSuiteView {
  readonly id?: string;
  readonly name?: string;
  readonly runId?: string;
  readonly passed: number;
  readonly failed: number;
}

export const initial: TestSuiteView = { passed: 0, failed: 0 };

export function when(state: TestSuiteView, event: TestSuiteEvent): TestSuiteView {
  switch (event.type) {
    case "TestSuiteRegistered":
      return { ...state, id: event.id, name: event.name };
    case "TestSuiteRunStarted":
      return { ...state, runId: event.runId };
    case "TestSuiteResultReported":
      return { ...state, passed: state.passed + event.passed, failed: state.failed + event.failed };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (state: S, event: E) => S,
  initialState: S,
): Promise<S> {
  let state: S = initialState;
  for await (const event of stream) {
    state = reducer(state, event);
  }
  return state;
}

export async function loadTestSuite(stream: AsyncIterable<TestSuiteEvent>): Promise<TestSuiteView> {
  return aggregateStream(stream, when, initial);
}
