export type TrainingJobEvent =
  | { type: "TrainingJobSubmitted"; id: string }
  | { type: "TrainingJobStarted" }
  | { type: "TrainingJobCompleted"; metric: number };

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(
    stream: string,
    events: E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ ok: true; revision: bigint } | { ok: false; actualRevision: bigint | "no_stream" }>;
}

export class ConcurrencyConflict extends Error {
  constructor(
    public readonly stream: string,
    public readonly expected: bigint | "no_stream" | "any",
    public readonly actual: bigint | "no_stream",
  ) {
    super(`conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function writeTrainingJob(
  store: EventStore,
  streamName: string,
  expectedRevision: bigint | "no_stream" | "any",
  events: TrainingJobEvent[],
): Promise<bigint> {
  const result = await store.appendToStream(streamName, events, { expectedRevision });
  if (!result.ok) {
    throw new ConcurrencyConflict(streamName, expectedRevision, result.actualRevision);
  }
  return result.revision;
}
