```typescript
export type BallotStateV3 = {
  id: string;
  voterId: string;
  choices: string[];
  status: "issued" | "marked" | "submitted" | "spoiled";
  submittedAt: string | null;
};

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3;

type V1 = { id: string; voterId: string; choice: string; status: string };
type V2 = { id: string; voterId: string; choice: string | null; status: string };

function v1ToV2(raw: V1): V2 {
  return { id: raw.id, voterId: raw.voterId, choice: raw.choice || null, status: raw.status };
}

function v2ToV3(raw: V2): BallotStateV3 {
  const status =
    raw.status === "issued" || raw.status === "marked" || raw.status === "submitted" || raw.status === "spoiled"
      ? raw.status
      : "issued";
  return {
    id: raw.id,
    voterId: raw.voterId,
    choices: raw.choice ? [raw.choice] : [],
    status,
    submittedAt: null,
  };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<BallotStateV3> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1ToV2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2ToV3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unsupported snapshot version ${snap.version}`);
  }
  return { version: CURRENT_VERSION, state: state as BallotStateV3 };
}
