Declare `types.emitted` in `setup` and call `emit` after each successful chunk. Subscribers can react via `actor.on('PROGRESS', ...)`.

```typescript
import { setup, assign, emit, fromPromise } from 'xstate';

type Ctx = { total: number; done: number };
type Ev = { type: 'START' };
type Emitted = { type: 'PROGRESS'; pct: number };

export const progressMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    emitted: {} as Emitted,
    input: {} as { total: number }
  },
  actors: {
    chunk: fromPromise(async () => {
      await new Promise((r) => setTimeout(r, 20));
    })
  }
}).createMachine({
  id: 'progress',
  initial: 'idle',
  context: ({ input }) => ({ total: input.total, done: 0 }),
  states: {
    idle: { on: { START: 'running' } },
    running: {
      invoke: {
        src: 'chunk',
        onDone: {
          target: 'running',
          reenter: true,
          actions: [
            assign({ done: ({ context }) => context.done + 1 }),
            emit(({ context }) => ({
              type: 'PROGRESS' as const,
              pct: Math.round((100 * (context.done + 1)) / context.total)
            }))
          ]
        }
      }
    }
  }
});
