export type BillablePeriodEvent =
  | { type: "periodStarted"; periodId: string; matter: string }
  | { type: "hoursLogged"; periodId: string; matter: string; hours: number }
  | { type: "periodClosed"; periodId: string };
export type MatterRow = { matter: string; hours: number };
export type MatterView = { rows: MatterRow[] };
export const emptyView: MatterView = { rows: [] };
function bump(view: MatterView, matter: string, delta: number): MatterView {
  const existing = view.rows.find(r => r.matter === matter);
  const next = existing
    ? view.rows.map(r => r.matter === matter ? { ...r, hours: r.hours + delta } : r)
    : [...view.rows, { matter, hours: delta }];
  return { rows: next.sort((a, b) => b.hours - a.hours).slice(0, 10) };
}
export function project(v: MatterView, e: BillablePeriodEvent): MatterView {
  switch (e.type) {
    case "periodStarted": return v;
    case "hoursLogged": return bump(v, e.matter, e.hours);
    case "periodClosed": return v;
    default: { const _: never = e; return v; }
  }
}
