export type ServicingCheckState =
  | { status: "none" }
  | { status: "scheduled"; id: string; open: string[]; passed: string[] }
  | { status: "signed"; id: string };

export type ServicingCheckCommand =
  | { type: "schedule"; id: string; items: string[] }
  | { type: "recordItem"; item: string; pass: boolean }
  | { type: "signOff"; by: string };

export type ServicingCheckEvent =
  | { type: "ServicingCheckScheduled"; id: string; items: string[] }
  | { type: "ServicingItemRecorded"; item: string; pass: boolean }
  | { type: "ServicingCheckSigned"; by: string };

export class DomainError extends Error { constructor(public readonly code: string) { super(code); } }

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const servicingCheckDecider: Decider<ServicingCheckCommand, ServicingCheckEvent, ServicingCheckState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "schedule":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ServicingCheckScheduled", id: c.id, items: c.items }];
      case "recordItem":
        if (s.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        if (!s.open.includes(c.item)) throw new DomainError("UNKNOWN_ITEM");
        if (!c.pass) throw new DomainError("FAILED_ITEM");
        return [{ type: "ServicingItemRecorded", item: c.item, pass: c.pass }];
      case "signOff":
        if (s.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        if (s.open.length > 0) throw new DomainError("OPEN_ITEMS");
        return [{ type: "ServicingCheckSigned", by: c.by }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ServicingCheckScheduled":
        return { status: "scheduled", id: e.id, open: e.items, passed: [] };
      case "ServicingItemRecorded":
        if (s.status !== "scheduled") return s;
        return { ...s, open: s.open.filter((i) => i !== e.item), passed: [...s.passed, e.item] };
      case "ServicingCheckSigned":
        if (s.status !== "scheduled") return s;
        return { status: "signed", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};
