type ConversationV1 = Readonly<{ id: string; users: readonly string[] }>;
type ConversationV2 = Readonly<{ id: string; members: readonly string[] }>;
type ConversationV3 = Readonly<{ id: string; members: readonly string[]; closed: boolean }>;

export type CurrentConversation = ConversationV3;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 3 as const;

function v1Tov2(s: ConversationV1): ConversationV2 {
  return { id: s.id, members: s.users };
