  let { version, state } = snap;
  if (version === 1) {
    state = v1Tov2(state as ConversationV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as ConversationV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unknown snapshot version: ${version}`);
