type ConcertEvent =
  | { type: 'Scheduled'; id: string; capacity: number }
  | { type: 'TicketsSold'; qty: number; priceCents: number }
  | { type: 'Cancelled' };

type RevenueView = {
  readonly id: string;
  readonly capacity: number;
  readonly sold: number;
  readonly grossCents: number;
  readonly cancelled: boolean;
};

