  id: '',
  capacity: 0,
  sold: 0,
  grossCents: 0,
  cancelled: false,
};

export function project(view: RevenueView, event: ConcertEvent): RevenueView {
  switch (event.type) {
    case 'Scheduled':
      return { ...view, id: event.id, capacity: event.capacity };
    case 'TicketsSold':
      return {
        ...view,
        sold: view.sold + event.qty,
        grossCents: view.grossCents + event.qty * event.priceCents,
      };
    case 'Cancelled':
      return { ...view, cancelled: true };
    default: { const _e: never = event; return _e; }
  }
}
