```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
import { Effect } from "effect";

export type CodeReviewCommand =
  | { type: "request"; id: string; author: string; reviewers: string[] }
  | { type: "submit"; verdict: "approve" | "changes" };

export type CodeReviewEvent =
  | { type: "CodeReviewRequested"; id: string; author: string; reviewers: string[] }
  | { type: "CodeReviewSubmitted"; verdict: "approve" | "changes" };

export type CodeReviewState =
  | { status: "none" }
  | { status: "open"; id: string }
  | { status: "completed"; id: string; verdict: "approve" | "changes" };

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`concurrency conflict on ${streamName}`);
    this.name = "ConcurrencyConflict";
  }
}

export interface ReadResult<E> {
  readonly events: E[];
  readonly revision: bigint | "no_stream";
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export const initialState: CodeReviewState = { status: "none" };

export function evolve(state: CodeReviewState, event: CodeReviewEvent): CodeReviewState {
  switch (event.type) {
    case "CodeReviewRequested":
      return { status: "open", id: event.id };
    case "CodeReviewSubmitted":
      if (state.status !== "open") return state;
      return { status: "completed", id: state.id, verdict: event.verdict };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: CodeReviewCommand, state: CodeReviewState): CodeReviewEvent[] {
  switch (command.type) {
    case "request":
      if (state.status !== "none") throw new Error("ALREADY_REQUESTED");
      return [{ type: "CodeReviewRequested", id: command.id, author: command.author, reviewers: command.reviewers }];
    case "submit":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "CodeReviewSubmitted", verdict: command.verdict }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export function handle(
  store: EventStore<CodeReviewEvent>,
  streamName: string,
  command: CodeReviewCommand,
): Effect.Effect<void, ConcurrencyConflict | Error> {
  return Effect.gen(function* () {
    const loaded = yield* Effect.promise(() => store.readStream(streamName));
    const state = loaded.events.reduce(evolve, initialState);
    const newEvents = decide(command, state);
    yield* Effect.tryPromise({
      try: () => store.appendToStream(streamName, newEvents, { expectedRevision: loaded.revision }),
      catch: (err) => (err instanceof ConcurrencyConflict ? err : new ConcurrencyConflict(streamName, loaded.revision)),
    });
  });
}
```

CQRS splits reads from writes because they have different needs. The write side owns invariants, needs the aggregate's full state to call decide, and lives behind the event store. The read side only needs a denormalised view shaped for a query, populated by a projection subscribed to the same events. If both sides shared a state type you would couple query response shape to aggregate internals, making both harder to evolve. Keeping them independent lets you spin up as many read models as you need per stream.

```typescript
export type UnitCommand = { type: "register"; id: string; rooms: number } | { type: "decommission" };
export type UnitEvent = { type: "UnitRegistered"; id: string; rooms: number } | { type: "UnitDecommissioned" };
export type UnitState = { status: "none" } | { status: "active"; id: string; rooms: number } | { status: "decommissioned" };

function evolve(s: UnitState, e: UnitEvent): UnitState {
  switch (e.type) {
    case "UnitRegistered":
      return { status: "active", id: e.id, rooms: e.rooms };
    case "UnitDecommissioned":
      return { status: "decommissioned" };
    default: {
      const _never: never = e;
      return s;
    }
  }
}

function decide(c: UnitCommand, s: UnitState): UnitEvent[] {
  switch (c.type) {
    case "register":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "UnitRegistered", id: c.id, rooms: c.rooms }];
    case "decommission":
      if (s.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "UnitDecommissioned" }];
    default: {
      const _never: never = c;
      return _never;
    }
  }
}

interface EventStore {
  readStream(s: string): Promise<{ data: UnitEvent; revision: bigint }[]>;
  appendToStream(s: string, events: UnitEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export interface UnitView { id: string; rooms: number; decommissioned: boolean }

export async function handleCommand(
  id: string,
  cmd: UnitCommand,
  store: EventStore,
): Promise<void> {
  const s = `unit-${id}`;
  const stored = await store.readStream(s);
  const state = stored.reduce<UnitState>((a, e) => evolve(a, e.data), { status: "none" });
  const events = decide(cmd, state);
  const exp: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  await store.appendToStream(s, events, { expectedRevision: exp });
}

export async function queryView(id: string, read: { get(id: string): Promise<UnitView | null> }): Promise<UnitView | null> {
  return read.get(id);
}
