```typescript
type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export type RouteState =
  | { status: "none" }
  | { status: "planned"; id: string; stops: number }
  | { status: "active"; id: string; stops: number };

export type RouteCommand =
  | { type: "plan"; id: string; stops: number }
  | { type: "activate"; at: string };

export type RouteEvent =
  | { type: "RoutePlanned"; id: string; stops: number }
  | { type: "RouteActivated"; at: string };

const initialState: RouteState = { status: "none" };

function evolve(state: RouteState, event: RouteEvent): RouteState {
  switch (event.type) {
    case "RoutePlanned": return { status: "planned", id: event.id, stops: event.stops };
    case "RouteActivated":
      if (state.status !== "planned") return state;
      return { status: "active", id: state.id, stops: state.stops };
    default: { const _n: never = event; return state; }
  }
}

function decide(command: RouteCommand, state: RouteState): RouteEvent[] {
  switch (command.type) {
    case "plan":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "RoutePlanned", id: command.id, stops: command.stops }];
    case "activate":
      if (state.status !== "planned") throw new Error("NOT_PLANNED");
      return [{ type: "RouteActivated", at: command.at }];
    default: { const _n: never = command; throw new Error("UNKNOWN"); }
  }
}

export async function handle(
  command: RouteCommand,
  ctx: { streamName: string; eventStore: EventStore<RouteEvent> },
): Promise<void> {
  let state = initialState;
  let revision: bigint | undefined = undefined;
  for await (const { event, revision: r } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    revision = r;
  }
  const events = decide(command, state);
  if (events.length === 0) return;
  const expected: ExpectedRevision = revision ?? "no_stream";
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}
