export type GuardrailMetricEvent =
  | { type: "GuardrailMetricSampled"; metricId: string; value: number }
  | { type: "GuardrailMetricBreached"; metricId: string; threshold: number };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventEnvelope<E> { event: E; position: bigint; }

export interface EventStore<E> {
  readStream(from: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface ReadModelStore {
  applySample(metricId: string, value: number): Promise<void>;
  applyBreach(metricId: string, threshold: number): Promise<void>;
}

export interface GuardrailView {
  byMetric: Record<string, { count: number; breaches: number } | undefined>;
}

export function project(view: GuardrailView, event: GuardrailMetricEvent): GuardrailView {
  switch (event.type) {
    case "GuardrailMetricSampled": {
      const prev = view.byMetric[event.metricId] ?? { count: 0, breaches: 0 };
      return { byMetric: { ...view.byMetric, [event.metricId]: { ...prev, count: prev.count + 1 } } };
    }
    case "GuardrailMetricBreached": {
      const prev = view.byMetric[event.metricId] ?? { count: 0, breaches: 0 };
      return { byMetric: { ...view.byMetric, [event.metricId]: { ...prev, breaches: prev.breaches + 1 } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export async function runSubscription(
  name: string,
  store: EventStore<GuardrailMetricEvent>,
  checkpoints: CheckpointStore,
  readModel: ReadModelStore,
): Promise<void> {
  const last = (await checkpoints.read(name)) ?? 0n;
  for await (const { event, position } of store.readStream(last)) {
    switch (event.type) {
      case "GuardrailMetricSampled":
        await readModel.applySample(event.metricId, event.value);
        break;
      case "GuardrailMetricBreached":
        await readModel.applyBreach(event.metricId, event.threshold);
        break;
      default: {
        const _never: never = event;
      }
    }
    await checkpoints.write(name, position);
  }
}
