  | { type: "list"; id: string; rent: number }
  | { type: "reserve"; for: string }
  | { type: "occupy"; by: string };

export type ApartmentEvent =
  | { type: "ApartmentListed"; id: string; rent: number }
  | { type: "ApartmentReserved"; for: string }
  | { type: "ApartmentOccupied"; by: string };

export class ApartmentError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "ApartmentError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const apartmentDecider: Decider<ApartmentCommand, ApartmentEvent, ApartmentState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "list":
        if (state.status !== "empty") throw new ApartmentError("ALREADY_LISTED");
        return [{ type: "ApartmentListed", id: command.id, rent: command.rent }];
      case "reserve":
        if (state.status === "occupied") throw new ApartmentError("ALREADY_OCCUPIED");
        if (state.status !== "listed") throw new ApartmentError("NOT_LISTED");
        return [{ type: "ApartmentReserved", for: command.for }];
      case "occupy":
        if (state.status !== "reserved") throw new ApartmentError("NOT_RESERVED");
        return [{ type: "ApartmentOccupied", by: command.by }];
      default: {
        const _never: never = command;
        return _never;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ApartmentListed":
        return { status: "listed", id: event.id, rent: event.rent };
      case "ApartmentReserved":
        if (state.status !== "listed") return state;
        return { status: "reserved", id: state.id, rent: state.rent, reservedFor: event.for };
      case "ApartmentOccupied":
        if (state.status !== "reserved") return state;
        return { status: "occupied", id: state.id, rent: state.rent, occupant: event.by };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
