A `when` helper is conventionally a partial-state folder: it takes the current (possibly empty) partial aggregate and an event, returning an updated partial. `evolve` is typically the full-state version where the state is a discriminated union with a status field and every transition is total. Both feed into a stream fold; `when` is handy when initial state is literally empty and you want to accumulate fields lazily.

```typescript
export type VotingSessionEvent =
  | { type: "Scheduled"; id: string; opensAt: string }
  | { type: "Opened"; at: string }
  | { type: "VoteCast" }
  | { type: "Closed"; at: string };

export type VotingSession = {
  id: string;
  opensAt: string;
  openedAt: string | null;
  closedAt: string | null;
  votes: number;
};

export function when(current: Partial<VotingSession>, event: VotingSessionEvent): Partial<VotingSession> {
  switch (event.type) {
    case "Scheduled":
      return { id: event.id, opensAt: event.opensAt, openedAt: null, closedAt: null, votes: 0 };
    case "Opened":
      return { ...current, openedAt: event.at };
    case "VoteCast":
      return { ...current, votes: (current.votes ?? 0) + 1 };
    case "Closed":
      return { ...current, closedAt: event.at };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function aggregateSession(events: VotingSessionEvent[]): Partial<VotingSession> {
  return events.reduce(when, {} as Partial<VotingSession>);
}
```

