export type CourseState =
  | { status: "draft" }
  | { status: "open"; id: string; title: string }
  | { status: "closed"; id: string; title: string };

export type CourseCommand =
  | { type: "open"; id: string; title: string }
  | { type: "close" };

export type CourseEvent =
  | { type: "CourseOpened"; id: string; title: string }
  | { type: "CourseClosed" };

export class DomainError extends Error {}

export const initialState: CourseState = { status: "draft" };

export function evolve(s: CourseState, e: CourseEvent): CourseState {
  switch (e.type) {
    case "CourseOpened":
      return { status: "open", id: e.id, title: e.title };
    case "CourseClosed":
      if (s.status !== "open") return s;
      return { status: "closed", id: s.id, title: s.title };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: CourseCommand, s: CourseState): CourseEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "draft") throw new DomainError("EXISTS");
      return [{ type: "CourseOpened", id: c.id, title: c.title }];
    case "close":
      if (s.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "CourseClosed" }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<CourseEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<CourseEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
}

export async function handleCourseCommand(
  streamName: string,
  command: CourseCommand,
  store: EventStore,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const next = decide(command, state);
  if (next.length === 0) return;
  await store.appendToStream(streamName, next, { expectedRevision: revision ?? "no_stream" });
}

export function inMemoryStore(): EventStore {
  const streams = new Map<string, CourseEvent[]>();
  return {
    async readStream(name) {
      const events = streams.get(name) ?? [];
      return { events, revision: events.length === 0 ? null : BigInt(events.length - 1) };
    },
    async appendToStream(name, events) {
      const current = streams.get(name) ?? [];
      streams.set(name, [...current, ...events]);
    },
  };
}
