export type SettlementOfferEvent =
  | { type: "offerMade"; caseId: string; amount: number; offerId: string }
  | { type: "offerWithdrawn"; caseId: string; offerId: string };
export type SettlementView = { caseId: string; bestOffer: number; active: boolean };
export function emptyView(caseId: string): SettlementView { return { caseId, bestOffer: 0, active: true }; }
export function project(v: SettlementView, e: SettlementOfferEvent): SettlementView {
  switch (e.type) {
    case "offerMade": return { ...v, bestOffer: Math.max(v.bestOffer, e.amount) };
    case "offerWithdrawn": return { ...v, active: false };
    default: { const _: never = e; return v; }
  }
}
export interface Stored<E> { revision: bigint; event: E }
export interface EventStore<E> { readBatch(from: bigint, size: number): Promise<Stored<E>[]> }
export interface ReadStore { persist(caseId: string, view: SettlementView): Promise<void> }
export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  eventStore: EventStore<SettlementOfferEvent>;
  readStore: ReadStore;
  caseIdOf: (e: SettlementOfferEvent) => string;
}): Promise<void> {
  let cursor = opts.from;
  const views: Record<string, SettlementView> = {};
  while (true) {
    const batch = await opts.eventStore.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const rec of batch) {
      const id = opts.caseIdOf(rec.event);
      views[id] = project(views[id] ?? emptyView(id), rec.event);
      await opts.readStore.persist(id, views[id]);
      cursor = rec.revision + 1n;
    }
  }
}
