export type CampaignFlightState =
  | { status: "unscheduled" }
  | { status: "scheduled"; id: string; startDate: string; endDate: string }
  | { status: "running"; id: string; startDate: string; endDate: string }
  | { status: "paused"; id: string; startDate: string; endDate: string }
  | { status: "ended"; id: string };

export type CampaignFlightCommand =
  | { type: "schedule"; id: string; startDate: string; endDate: string }
  | { type: "launch"; now: string }
  | { type: "pause" }
  | { type: "resume" }
  | { type: "end" };

export type CampaignFlightEvent =
  | { type: "CampaignFlightScheduled"; id: string; startDate: string; endDate: string }
  | { type: "CampaignFlightLaunched"; now: string }
  | { type: "CampaignFlightPaused" }
  | { type: "CampaignFlightResumed" }
  | { type: "CampaignFlightEnded" };

export class CampaignFlightError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "CampaignFlightError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const campaignFlightDecider: Decider<CampaignFlightCommand, CampaignFlightEvent, CampaignFlightState> = {
  initialState: { status: "unscheduled" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "unscheduled") throw new CampaignFlightError("ALREADY_SCHEDULED");
        if (command.endDate <= command.startDate) throw new CampaignFlightError("BAD_DATES");
        return [{ type: "CampaignFlightScheduled", id: command.id, startDate: command.startDate, endDate: command.endDate }];
      case "launch":
        if (state.status !== "scheduled") throw new CampaignFlightError("NOT_SCHEDULED");
        if (command.now > state.endDate) throw new CampaignFlightError("PAST_END_DATE");
        return [{ type: "CampaignFlightLaunched", now: command.now }];
      case "pause":
        if (state.status !== "running") throw new CampaignFlightError("NOT_RUNNING");
        return [{ type: "CampaignFlightPaused" }];
      case "resume":
        if (state.status !== "paused") throw new CampaignFlightError("NOT_PAUSED");
        return [{ type: "CampaignFlightResumed" }];
      case "end":
        if (state.status === "ended" || state.status === "unscheduled") throw new CampaignFlightError("CANNOT_END");
        return [{ type: "CampaignFlightEnded" }];
      default: {
        const _never: never = command;
        throw new CampaignFlightError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CampaignFlightScheduled":
        return { status: "scheduled", id: event.id, startDate: event.startDate, endDate: event.endDate };
      case "CampaignFlightLaunched":
        if (state.status !== "scheduled") return state;
        return { status: "running", id: state.id, startDate: state.startDate, endDate: state.endDate };
      case "CampaignFlightPaused":
        if (state.status !== "running") return state;
        return { status: "paused", id: state.id, startDate: state.startDate, endDate: state.endDate };
      case "CampaignFlightResumed":
        if (state.status !== "paused") return state;
        return { status: "running", id: state.id, startDate: state.startDate, endDate: state.endDate };
      case "CampaignFlightEnded":
        if (state.status === "unscheduled" || state.status === "ended") return state;
        return { status: "ended", id: state.id };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
