```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
export type ImpressionEvent =
  | { type: "ImpressionRecorded"; adId: string; at: string }
  | { type: "ImpressionInvalidated"; adId: string; reason: string };

export interface ImpressionView {
  readonly perAd: Readonly<Record<string, number>>;
}

export const emptyView: ImpressionView = { perAd: {} };

export interface StoredEvent<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface EventSource<E> {
  readBatch(from: bigint, limit: number): Promise<readonly StoredEvent<E>[]>;
}

export interface RebuildOptions<V, E> {
  readonly from: bigint;
  readonly batchSize: number;
  readonly project: (view: V, event: E) => V;
  readonly persist: (view: V, revision: bigint) => Promise<void>;
  readonly source: EventSource<E>;
  readonly initial: V;
  readonly onProgress?: (revision: bigint) => void;
}

export async function rebuild<V, E>(opts: RebuildOptions<V, E>): Promise<void> {
  let cursor = opts.from;
  let view = opts.initial;
  for (;;) {
    const batch = await opts.source.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const stored of batch) {
      view = opts.project(view, stored.event);
      cursor = stored.revision;
    }
    await opts.persist(view, cursor);
    opts.onProgress?.(cursor);
    if (batch.length < opts.batchSize) return;
  }
}

export function projectImpression(view: ImpressionView, event: ImpressionEvent): ImpressionView {
  switch (event.type) {
    case "ImpressionRecorded": {
      const count = (view.perAd[event.adId] ?? 0) + 1;
      return { perAd: { ...view.perAd, [event.adId]: count } };
    }
    case "ImpressionInvalidated": {
      const count = Math.max(0, (view.perAd[event.adId] ?? 0) - 1);
      return { perAd: { ...view.perAd, [event.adId]: count } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
