```typescript
export type ReservationState = { status: "none" } | { status: "open"; guests: number };
export type ReservationCommand =
  | { type: "open"; guests: number }
  | { type: "addGuest" };
export type ReservationEvent =
  | { type: "ReservationOpened"; guests: number }
  | { type: "GuestAdded" };

export class DomainError extends Error {}

export const initialState: ReservationState = { status: "none" };

export function evolve(state: ReservationState, event: ReservationEvent): ReservationState {
  switch (event.type) {
    case "ReservationOpened":
      return { status: "open", guests: event.guests };
    case "GuestAdded":
      if (state.status !== "open") return state;
      return { ...state, guests: state.guests + 1 };
    default: { const _n: never = event; return state; }
  }
}

export function decide(command: ReservationCommand, state: ReservationState): ReservationEvent[] {
  switch (command.type) {
    case "open":
      if (state.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ReservationOpened", guests: command.guests }];
    case "addGuest":
      if (state.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "GuestAdded" }];
    default: { const _n: never = command; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<{ events: ReservationEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: ReservationEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export async function handle(
  command: ReservationCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initialState);
  const newEvents = decide(command, state);
  if (newEvents.length === 0) return;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision });
}
