```typescript
export type HoldingEvent =
  | { type: "HoldingRegistered"; id: string; symbol: string; units: number }
  | { type: "HoldingIncreased"; units: number }
  | { type: "HoldingReduced"; units: number };

export type Holding = Readonly<{ id: string; symbol: string; units: number }>;

export function when(state: Partial<Holding>, event: HoldingEvent): Partial<Holding> {
  switch (event.type) {
    case "HoldingRegistered":
      return { id: event.id, symbol: event.symbol, units: event.units };
    case "HoldingIncreased":
      return { ...state, units: (state.units ?? 0) + event.units };
    case "HoldingReduced":
      return { ...state, units: (state.units ?? 0) - event.units };
    default: { const _n: never = event; return state; }
  }
}

export function isHolding(s: Partial<Holding>): s is Holding {
  return !!s.id && !!s.symbol && typeof s.units === "number";
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const state = events.reduce<Partial<A>>(reducer, {});
  if (!check(state)) throw new Error("INVALID_AGGREGATE_STATE");
  return state;
}

export const holdingFrom = (events: HoldingEvent[]): Holding =>
  aggregateStream(events, when, isHolding);

