import { setup, assign } from 'xstate';

type Ev =
  | { type: 'START' }
  | { type: 'SCORE'; pts: number }
  | { type: 'END' };

export const scoreMachine = setup({
  types: {
    context: {} as { score: number; best: number },
    events: {} as Ev,
    output: {} as { score: number; best: number }
  },
  actions: {
    reset: assign({ score: 0 }),
    add: assign({
      score: ({ context, event }) =>
        event.type === 'SCORE' ? context.score + event.pts : context.score
    }),
    record: assign({
      best: ({ context }) => Math.max(context.best, context.score)
    })
  }
}).createMachine({
  id: 'score',
  initial: 'idle',
  context: { score: 0, best: 0 },
  states: {
    idle: { on: { START: { target: 'playing', actions: 'reset' } } },
    playing: { on: { END: { target: 'done', actions: 'record' } } },
    done: { type: 'final' }
  },
  output: ({ context }) => ({ score: context.score, best: context.best })
});
```

The optimistic pattern inserts the new item synchronously into context, then invokes a promise actor to confirm it against the server. `onDone` swaps the temp id for the server-assigned id and marks the item confirmed; `onError` either marks the item as failed (so the UI can show a retry affordance) or removes it. All three outcomes are typed via `setup.types` so nothing escapes strict mode.

