export type PolicyEvent =
  | { type: "PolicyQuoted"; id: string; premium: number }
  | { type: "PolicyActivated"; at: string };

export interface EventRecord<E> { revision: bigint; event: E; }

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<EventRecord<E>>;
  appendToStream(
    stream: string,
    events: readonly E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | string) {
    super("concurrency_conflict");
    this.name = "ConcurrencyConflict";
  }
}

export async function appendPolicyEvents(
  store: EventStore<PolicyEvent>,
  stream: string,
  events: readonly PolicyEvent[],
): Promise<bigint> {
  let expected: bigint | "no_stream" = "no_stream";
  let seen = false;
  for await (const rec of store.readStream(stream)) {
    expected = rec.revision;
    seen = true;
  }
  const opts = seen ? { expectedRevision: expected } : { expectedRevision: "no_stream" as const };
  try {
    const res = await store.appendToStream(stream, events, opts);
    return res.nextExpectedRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("wrong_expected_version")) {
      throw new ConcurrencyConflict(stream, expected);
    }
    throw err;
  }
}
