export type NutritionProfileState =
  | { status: "none" }
  | { status: "editing"; id: string; entries: number }
  | { status: "locked"; id: string };

export type NutritionProfileCommand =
  | { type: "open"; id: string }
  | { type: "declare"; calories: number }
  | { type: "lock"; at: string };

export type NutritionProfileEvent =
  | { type: "NutritionProfileOpened"; id: string }
  | { type: "NutritionMacrosDeclared"; calories: number }
  | { type: "NutritionProfileLocked"; at: string };

export const initialNutritionProfile: NutritionProfileState = { status: "none" };

export function decide(c: NutritionProfileCommand, s: NutritionProfileState): NutritionProfileEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "NutritionProfileOpened", id: c.id }];
    case "declare":
      if (s.status !== "editing") throw new Error("NOT_EDITING");
      if (c.calories < 0) throw new Error("NEGATIVE");
      return [{ type: "NutritionMacrosDeclared", calories: c.calories }];
    case "lock":
      if (s.status !== "editing") throw new Error("NOT_EDITING");
      if (s.entries === 0) throw new Error("EMPTY");
      return [{ type: "NutritionProfileLocked", at: c.at }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: NutritionProfileState, e: NutritionProfileEvent): NutritionProfileState {
  switch (e.type) {
    case "NutritionProfileOpened":
      return { status: "editing", id: e.id, entries: 0 };
    case "NutritionMacrosDeclared":
      if (s.status !== "editing") return s;
      return { ...s, entries: s.entries + 1 };
    case "NutritionProfileLocked":
      if (s.status !== "editing") return s;
      return { status: "locked", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: NutritionProfileEvent }>>;
  appendToStream(stream: string, events: readonly NutritionProfileEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export class CommandHandler {
  constructor(private readonly store: EventStore) {}

  async handle(stream: string, command: NutritionProfileCommand): Promise<void> {
    const stored = await this.store.readStream(stream);
    const state = stored.reduce<NutritionProfileState>((s, { event }) => evolve(s, event), initialNutritionProfile);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const events = decide(command, state);
    await this.store.appendToStream(stream, events, { expectedRevision: expected });
  }
}

