```typescript
import { Effect } from "effect";

export type ExpectedRevision = bigint | "no_stream" | "any";

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict" as const;
  constructor(public readonly actual: bigint | null) { super("CONCURRENCY_CONFLICT"); }
}

export interface RevisionEvent { readonly type: string; readonly payload: Record<string, unknown>; }
export interface Envelope { readonly revision: bigint; readonly event: RevisionEvent; }

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<Envelope>>;
  appendToStream(stream: string, events: RevisionEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint; conflict: boolean; actual: bigint | null }>;
}

export const appendRevision = (store: EventStore, stream: string, events: RevisionEvent[]) =>
  Effect.gen(function* () {
    const envs = yield* Effect.promise(() => store.readStream(stream));
    const expected: ExpectedRevision = envs.length === 0 ? "no_stream" : envs[envs.length - 1]!.revision;
    const outcome = yield* Effect.promise(() =>
      store.appendToStream(stream, events, { expectedRevision: expected }),
    );
    if (outcome.conflict) {
      return yield* Effect.fail(new ConcurrencyConflict(outcome.actual));
    }
    return outcome.nextRevision;
  });
