export type ArtAuctionState =
  | { status: "none" }
  | { status: "open"; id: string; high: number; leader: string | null }
  | { status: "closed"; id: string; winningBid: number; winner: string | null };

export type ArtAuctionCommand =
  | { type: "start"; id: string; reserve: number }
  | { type: "bid"; bidder: string; amount: number }
  | { type: "close" };

export type ArtAuctionEvent =
  | { type: "ArtAuctionStarted"; id: string; reserve: number }
  | { type: "ArtAuctionBidPlaced"; bidder: string; amount: number }
  | { type: "ArtAuctionClosed"; winner: string | null; amount: number };

const initial: ArtAuctionState = { status: "none" };

function evolve(state: ArtAuctionState, event: ArtAuctionEvent): ArtAuctionState {
  switch (event.type) {
    case "ArtAuctionStarted":
      return { status: "open", id: event.id, high: event.reserve, leader: null };
    case "ArtAuctionBidPlaced":
      if (state.status !== "open") return state;
      return { ...state, high: event.amount, leader: event.bidder };
    case "ArtAuctionClosed":
      if (state.status !== "open") return state;
      return { status: "closed", id: state.id, winningBid: event.amount, winner: event.winner };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: ArtAuctionCommand, state: ArtAuctionState): ArtAuctionEvent[] {
  switch (command.type) {
    case "start":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ArtAuctionStarted", id: command.id, reserve: command.reserve }];
    case "bid":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      if (command.amount <= state.high) throw new Error("TOO_LOW");
      return [{ type: "ArtAuctionBidPlaced", bidder: command.bidder, amount: command.amount }];
    case "close":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "ArtAuctionClosed", winner: state.leader, amount: state.high }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handle(
  command: ArtAuctionCommand,
  ctx: { streamName: string; eventStore: EventStore<ArtAuctionEvent> }
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initial);
  const produced = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, produced, { expectedRevision: revision });
}
