export type RecipeEvent =
  | { type: "RecipeCreated"; id: string; title: string }
  | { type: "RecipeStepAdded" }
  | { type: "RecipePublished"; at: string };

export interface RecipeAggregate {
  readonly id: string;
  readonly title: string;
  readonly steps: number;
  readonly publishedAt: string | null;
}

export const emptyRecipe: RecipeAggregate = { id: "", title: "", steps: 0, publishedAt: null };

export function when(state: RecipeAggregate, event: RecipeEvent): RecipeAggregate {
  switch (event.type) {
    case "RecipeCreated":
      return { id: event.id, title: event.title, steps: 0, publishedAt: null };
    case "RecipeStepAdded":
      return { ...state, steps: state.steps + 1 };
    case "RecipePublished":
      return { ...state, publishedAt: event.at };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  async function main(): Promise<void> {
    for await (const event of stream) {
      state = reducer(state, event);
    }
  }
  await main();
  return state;
}

