export type ChapterHouseEvent =
  | { type: "opened"; houseId: string; name: string }
  | { type: "renamed"; houseId: string; name: string };

export type ChapterHouseCommand =
  | { type: "open"; houseId: string; name: string }
  | { type: "rename"; name: string };

interface WriteState { status: "none" | "open"; houseId?: string; name?: string }
const initial: WriteState = { status: "none" };

function evolve(s: WriteState, e: ChapterHouseEvent): WriteState {
  switch (e.type) {
    case "opened":
      return { status: "open", houseId: e.houseId, name: e.name };
    case "renamed":
      return s.status === "open" ? { ...s, name: e.name } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: ChapterHouseCommand, s: WriteState): ChapterHouseEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new Error("exists");
      return [{ type: "opened", houseId: c.houseId, name: c.name }];
    case "rename":
      if (s.status !== "open" || !s.houseId) throw new Error("not open");
      return [{ type: "renamed", houseId: s.houseId, name: c.name }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface EventStore<E> {
  readStream(s: string): Promise<E[]>;
  appendToStream(s: string, e: E[]): Promise<void>;
}
export interface ChapterReadRow { houseId: string; displayName: string; lastSeen: string }
export interface ReadStore { find(id: string): Promise<ChapterReadRow | null> }

// Read store is eventually consistent with the event store.
export async function handleCommand(
  cmd: ChapterHouseCommand,
  stream: string,
  store: EventStore<ChapterHouseEvent>,
): Promise<void> {
  const events = await store.readStream(stream);
  const state = events.reduce<WriteState>(evolve, initial);
  await store.appendToStream(stream, decide(cmd, state));
}

export function queryView(id: string, reads: ReadStore): Promise<ChapterReadRow | null> {
  return reads.find(id);
}
