A DriverAssessment aggregate uses a pure Decider: `decide` validates invariants and emits events, `evolve` folds events into state. The signing invariant lives in `decide`; state never mutates.

```typescript
export type DriverAssessmentState =
  | { status: "new" }
  | { status: "scored"; id: string; score: number }
  | { status: "signed"; id: string; score: number; signedBy: string }
  | { status: "revoked"; id: string; reason: string };

export type DriverAssessmentCommand =
  | { type: "score"; id: string; score: number }
  | { type: "sign"; signedBy: string }
  | { type: "revoke"; reason: string };

export type DriverAssessmentEvent =
  | { type: "DriverAssessmentScored"; id: string; score: number }
  | { type: "DriverAssessmentSigned"; signedBy: string }
  | { type: "DriverAssessmentRevoked"; reason: string };

export class AssessmentError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const driverAssessmentDecider: Decider<DriverAssessmentCommand, DriverAssessmentEvent, DriverAssessmentState> = {
  initialState: { status: "new" },
  decide(command, state) {
    switch (command.type) {
      case "score":
        if (state.status !== "new") throw new AssessmentError("ALREADY_SCORED");
        if (command.score < 0 || command.score > 100) throw new AssessmentError("OUT_OF_RANGE");
        return [{ type: "DriverAssessmentScored", id: command.id, score: command.score }];
      case "sign":
        if (state.status !== "scored") throw new AssessmentError("NOT_SCORED");
        return [{ type: "DriverAssessmentSigned", signedBy: command.signedBy }];
      case "revoke":
        if (state.status === "revoked") throw new AssessmentError("ALREADY_REVOKED");
        if (state.status === "new") throw new AssessmentError("NOT_SCORED");
        return [{ type: "DriverAssessmentRevoked", reason: command.reason }];
      default: { const _n: never = command; throw new AssessmentError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DriverAssessmentScored":
        return { status: "scored", id: event.id, score: event.score };
      case "DriverAssessmentSigned":
        if (state.status !== "scored") return state;
        return { status: "signed", id: state.id, score: state.score, signedBy: event.signedBy };
      case "DriverAssessmentRevoked":
        if (state.status === "new") return state;
        return { status: "revoked", id: "id" in state ? state.id : "", reason: event.reason };
      default: { const _n: never = event; return state; }
    }
  },
};
