import { Effect } from "effect";

export type SherpaEvent =
  | { type: "SherpaHired"; id: string; name: string }
  | { type: "SherpaAssigned"; expeditionId: string }
  | { type: "SherpaDischarged" };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult {
  readonly nextExpectedRevision: bigint;
}

export interface EventStore<E> {
  readStreamRevision(stream: string): Promise<bigint | "no_stream">;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<AppendResult | { conflict: true }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export function appendSherpaEvents(
  store: EventStore<SherpaEvent>,
  stream: string,
  events: ReadonlyArray<SherpaEvent>,
): Effect.Effect<bigint, ConcurrencyConflict | Error> {
  return Effect.gen(function* () {
    const expectedRevision = yield* Effect.promise(() => store.readStreamRevision(stream));
    const result = yield* Effect.promise(() =>
      store.appendToStream(stream, events, { expectedRevision }),
    );
    if ("conflict" in result) {
      return yield* Effect.fail(new ConcurrencyConflict(stream));
    }
    return result.nextExpectedRevision;
  });
}
