export type CropState = { status: "none" } | { status: "planted"; id: string } | { status: "harvested"; id: string };
export type CropCommand = { type: "plant"; id: string; variety: string } | { type: "harvest" };
export type CropEvent = { type: "CropPlanted"; id: string; variety: string } | { type: "CropHarvested" };

export const initialState: CropState = { status: "none" };

export function evolve(state: CropState, event: CropEvent): CropState {
  switch (event.type) {
    case "CropPlanted":
      return { status: "planted", id: event.id };
    case "CropHarvested":
      if (state.status !== "planted") return state;
      return { status: "harvested", id: state.id };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(cmd: CropCommand, state: CropState): CropEvent[] {
  switch (cmd.type) {
    case "plant":
      if (state.status !== "none") throw new Error("ALREADY_PLANTED");
      return [{ type: "CropPlanted", id: cmd.id, variety: cmd.variety }];
    case "harvest":
      if (state.status !== "planted") throw new Error("NOT_READY");
      return [{ type: "CropHarvested" }];
    default: {
      const _n: never = cmd;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: E }>>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export interface CommandHandler<C, E> {
  handle(cmd: C, ctx: { streamName: string; store: EventStore<E> }): Promise<void>;
}

export const cropCommandHandler: CommandHandler<CropCommand, CropEvent> = {
  async handle(cmd, ctx) {
    const stored = await ctx.store.readStream(ctx.streamName);
    const state = stored.reduce<CropState>((s, r) => evolve(s, r.event), initialState);
    const events = decide(cmd, state);
    const expected: bigint | "no_stream" =
      stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    await ctx.store.appendToStream(ctx.streamName, events, { expectedRevision: expected });
  },
};
