export type SymptomEvent =
  | { type: "SymptomReported"; id: string; label: string; severity: number; at: string }
  | { type: "SymptomEscalated"; severity: number; at: string }
  | { type: "SymptomResolved"; at: string };

export interface SymptomState {
  readonly id: string | null;
  readonly label: string | null;
  readonly severity: number;
  readonly resolvedAt: string | null;
}

export const initialSymptom: SymptomState = { id: null, label: null, severity: 0, resolvedAt: null };

export function when(state: SymptomState, event: SymptomEvent): SymptomState {
  switch (event.type) {
    case "SymptomReported":
      return { id: event.id, label: event.label, severity: event.severity, resolvedAt: null };
    case "SymptomEscalated":
      return { ...state, severity: event.severity };
    case "SymptomResolved":
      return { ...state, resolvedAt: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream(source: AsyncIterable<SymptomEvent>): Promise<SymptomState> {
  let state = initialSymptom;
  async function fold(): Promise<void> {
    for await (const event of source) state = when(state, event);
  }
  await fold();
  return state;
}
