```typescript
export type SanctionState =
  | { status: "none" }
  | { status: "issued"; id: string; playerId: string; minutes: number; issuedAt: string }
  | { status: "served"; id: string; playerId: string; servedAt: string }
  | { status: "rescinded"; id: string; reason: string };

export type SanctionCommand =
  | { type: "issue"; id: string; playerId: string; minutes: number; at: string }
  | { type: "serve"; at: string }
  | { type: "rescind"; reason: string };

export type SanctionEvent =
  | { type: "SanctionIssued"; id: string; playerId: string; minutes: number; at: string }
  | { type: "SanctionServed"; at: string }
  | { type: "SanctionRescinded"; reason: string };

export const initialSanction: SanctionState = { status: "none" };

export function decide(c: SanctionCommand, s: SanctionState): SanctionEvent[] {
  switch (c.type) {
    case "issue":
      if (s.status !== "none") throw new Error("ALREADY_ISSUED");
      if (c.minutes <= 0) throw new Error("INVALID_MINUTES");
      return [{ type: "SanctionIssued", id: c.id, playerId: c.playerId, minutes: c.minutes, at: c.at }];
    case "serve":
      if (s.status !== "issued") throw new Error("NOT_ISSUED");
      return [{ type: "SanctionServed", at: c.at }];
    case "rescind":
      if (s.status !== "issued") throw new Error("NOT_RESCINDABLE");
      return [{ type: "SanctionRescinded", reason: c.reason }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: SanctionState, e: SanctionEvent): SanctionState {
  switch (e.type) {
    case "SanctionIssued":
      return { status: "issued", id: e.id, playerId: e.playerId, minutes: e.minutes, issuedAt: e.at };
    case "SanctionServed":
      if (s.status !== "issued") return s;
      return { status: "served", id: s.id, playerId: s.playerId, servedAt: e.at };
    case "SanctionRescinded":
      if (s.status !== "issued") return s;
      return { status: "rescinded", id: s.id, reason: e.reason };
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: SanctionEvent }>>;
  appendToStream(stream: string, events: readonly SanctionEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handleSanction(store: EventStore, stream: string, command: SanctionCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<SanctionState>((s, { event }) => evolve(s, event), initialSanction);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  const events = decide(command, state);
  await store.appendToStream(stream, events, { expectedRevision: expected });
}
