  | { type: "ExhibitionCurated"; id: string; theme: string; pieces: number }
  | { type: "ExhibitionStarted"; id: string }
  | { type: "ExhibitionEnded"; id: string; endedAt: string };

export interface ExhibitionView {
  readonly byId: Readonly<Record<string, { theme: string; status: "curated" | "running" | "ended" }>>;
}

const empty: ExhibitionView = { byId: {} };

function project(view: ExhibitionView, event: ExhibitionEvent): ExhibitionView {
  switch (event.type) {
    case "ExhibitionCurated":
      return { byId: { ...view.byId, [event.id]: { theme: event.theme, status: "curated" } } };
    case "ExhibitionStarted": {
      const prev = view.byId[event.id];
      if (!prev) return view;
      return { byId: { ...view.byId, [event.id]: { theme: prev.theme, status: "running" } } };
    }
    case "ExhibitionEnded": {
      const prev = view.byId[event.id];
      if (!prev) return view;
      return { byId: { ...view.byId, [event.id]: { theme: prev.theme, status: "ended" } } };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventCursor<E> {
  from(position: bigint | null): AsyncIterable<{ position: bigint; event: E }>;
}

export async function runSubscription(
  name: string,
  cursor: EventCursor<ExhibitionEvent>,
  checkpoints: CheckpointStore,
  save: (view: ExhibitionView) => Promise<void>
): Promise<void> {
  const start = await checkpoints.read(name);
  let view = empty;
  for await (const { position, event } of cursor.from(start)) {
    view = project(view, event);
    await save(view);
    await checkpoints.write(name, position);
  }
}
