A read model is a query-optimised view built by folding a subset of events. It denormalises the aggregate state so reads are a single lookup instead of a stream replay. The projection function is pure: given a view and an event it returns a new view, ignoring events outside its interest.

```typescript
type ConversationDomainEvent =
  | { type: 'ConversationStarted'; conversationId: string; starterId: string }
  | { type: 'ParticipantAdded'; conversationId: string; userId: string }
  | { type: 'ParticipantRemoved'; conversationId: string; userId: string }
  | { type: 'ConversationClosed'; conversationId: string };

type ParticipantsView = Readonly<{
  conversationId: string;
  members: readonly string[];
  closed: boolean;
}>;

export const emptyParticipants: ParticipantsView = {
  conversationId: '',
  members: [],
  closed: false,
};

export function project(view: ParticipantsView, event: ConversationDomainEvent): ParticipantsView {
  switch (event.type) {
    case 'ConversationStarted':
      return { conversationId: event.conversationId, members: [event.starterId], closed: false };
    case 'ParticipantAdded':
      return view.members.includes(event.userId)
        ? view
        : { ...view, members: [...view.members, event.userId] };
    case 'ParticipantRemoved':
      return { ...view, members: view.members.filter((m) => m !== event.userId) };
    case 'ConversationClosed':
      return { ...view, closed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}
