  switch (event.type) {
    case "VehicleRegistered":
      return { ...state, vin: event.vin, make: event.make };
    case "VehicleServiced":
      return { ...state, odometerKm: Math.max(state.odometerKm, event.odometerKm) };
    case "VehicleRetired":
      return { ...state, retired: true };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export async function loadVehicle(stream: AsyncIterable<VehicleEvent>): Promise<VehicleState> {
  return aggregateStream(stream, when, emptyVehicle);
