```typescript
export type ExpeditionState =
  | { status: "none" }
  | { status: "planned"; id: string; peak: string }
  | { status: "launched"; id: string; peak: string; at: string };

export type ExpeditionCommand =
  | { type: "plan"; id: string; peak: string }
  | { type: "launch"; at: string };

export type ExpeditionEvent =
  | { type: "ExpeditionPlanned"; id: string; peak: string }
  | { type: "ExpeditionLaunched"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export function decide(command: ExpeditionCommand, state: ExpeditionState): ExpeditionEvent[] {
  switch (command.type) {
    case "plan":
      if (state.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ExpeditionPlanned", id: command.id, peak: command.peak }];
    case "launch":
      if (state.status !== "planned") throw new DomainError("NOT_PLANNED");
      return [{ type: "ExpeditionLaunched", at: command.at }];
    default: {
      const _never: never = command;
      throw new DomainError("UNKNOWN_COMMAND");
    }
  }
}

export function evolve(state: ExpeditionState, event: ExpeditionEvent): ExpeditionState {
  switch (event.type) {
    case "ExpeditionPlanned":
      return { status: "planned", id: event.id, peak: event.peak };
    case "ExpeditionLaunched":
      if (state.status !== "planned") return state;
      return { status: "launched", id: state.id, peak: state.peak, at: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}
```

A Projection folds a subset of events into a denormalised, query-friendly shape. Unlike an aggregate's evolve, which reconstructs the write-side state, a projection only cares about what a specific read needs. Projections are often persisted in a read store and rebuilt from scratch any time the shape changes. The pure project function takes the current view plus one event and returns an updated view, ignoring events it does not care about.

```typescript
export type TicketEvent =
  | { type: "TicketOpened"; ticketId: string; priority: "low" | "high"; openedAt: string }
  | { type: "TicketAssigned"; ticketId: string; technician: string }
  | { type: "TicketResolved"; ticketId: string }
  | { type: "CommentAdded"; ticketId: string; comment: string };

export interface BacklogView {
  readonly openHighPriority: number;
  readonly openLowPriority: number;
  readonly resolved: number;
}

export const emptyView: BacklogView = { openHighPriority: 0, openLowPriority: 0, resolved: 0 };

export function project(view: BacklogView, event: TicketEvent): BacklogView {
  switch (event.type) {
    case "TicketOpened":
      return event.priority === "high"
        ? { ...view, openHighPriority: view.openHighPriority + 1 }
        : { ...view, openLowPriority: view.openLowPriority + 1 };
    case "TicketResolved":
      return { ...view, resolved: view.resolved + 1 };
    case "TicketAssigned":
      return view;
    case "CommentAdded":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}
