export type VendorState =
  | { status: "none" }
  | { status: "onboarded"; id: string; name: string }
  | { status: "approved"; id: string; name: string; approvedAt: string }
  | { status: "suspended"; id: string; name: string; reason: string };

export type VendorCommand =
  | { type: "onboard"; id: string; name: string }
  | { type: "approve"; at: string }
  | { type: "suspend"; reason: string }
  | { type: "reactivate" };

export type VendorEvent =
  | { type: "VendorOnboarded"; id: string; name: string }
  | { type: "VendorApproved"; at: string }
  | { type: "VendorSuspended"; reason: string }
  | { type: "VendorReactivated" };

export class VendorError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const vendorDecider: Decider<VendorCommand, VendorEvent, VendorState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "onboard":
        if (s.status !== "none") throw new VendorError("EXISTS");
        return [{ type: "VendorOnboarded", id: c.id, name: c.name }];
      case "approve":
        if (s.status !== "onboarded") throw new VendorError("NOT_ONBOARDED");
        return [{ type: "VendorApproved", at: c.at }];
      case "suspend":
        if (s.status === "suspended") throw new VendorError("ALREADY_SUSPENDED");
        if (s.status === "none") throw new VendorError("NOT_FOUND");
        return [{ type: "VendorSuspended", reason: c.reason }];
      case "reactivate":
        if (s.status !== "suspended") throw new VendorError("NOT_SUSPENDED");
        return [{ type: "VendorReactivated" }];
      default: { const _n: never = c; throw new VendorError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "VendorOnboarded":
        return { status: "onboarded", id: e.id, name: e.name };
      case "VendorApproved":
        if (s.status !== "onboarded") return s;
        return { status: "approved", id: s.id, name: s.name, approvedAt: e.at };
      case "VendorSuspended":
        if (s.status !== "approved" && s.status !== "onboarded") return s;
        return { status: "suspended", id: s.id, name: s.name, reason: e.reason };
      case "VendorReactivated":
        if (s.status !== "suspended") return s;
        return { status: "approved", id: s.id, name: s.name, approvedAt: "" };
      default: { const _n: never = e; return s; }
    }
  },
};
