```typescript
export type AllocationEvent =
  | { type: "HoursAllocated"; taskId: string; assignee: string; hours: number }
  | { type: "HoursReassigned"; taskId: string; fromAssignee: string; toAssignee: string }
  | { type: "HoursReleased"; taskId: string; assignee: string; hours: number }
  | { type: "TaskNoteAdded"; taskId: string; note: string };

export type AllocationView = Readonly<{
  hoursByAssignee: Readonly<Record<string, number>>;
  taskAssignee: Readonly<Record<string, string>>;
  taskHours: Readonly<Record<string, number>>;
}>;

export const emptyAllocation: AllocationView = {
  hoursByAssignee: {},
  taskAssignee: {},
  taskHours: {},
};

export function project(view: AllocationView, event: AllocationEvent): AllocationView {
  switch (event.type) {
    case "HoursAllocated": {
      const prior = view.hoursByAssignee[event.assignee] ?? 0;
      return {
        hoursByAssignee: { ...view.hoursByAssignee, [event.assignee]: prior + event.hours },
        taskAssignee: { ...view.taskAssignee, [event.taskId]: event.assignee },
        taskHours: { ...view.taskHours, [event.taskId]: event.hours },
      };
    }
    case "HoursReassigned": {
      const hours = view.taskHours[event.taskId] ?? 0;
      const fromPrior = view.hoursByAssignee[event.fromAssignee] ?? 0;
      const toPrior = view.hoursByAssignee[event.toAssignee] ?? 0;
      return {
        hoursByAssignee: {
          ...view.hoursByAssignee,
          [event.fromAssignee]: fromPrior - hours,
          [event.toAssignee]: toPrior + hours,
        },
        taskAssignee: { ...view.taskAssignee, [event.taskId]: event.toAssignee },
        taskHours: view.taskHours,
      };
    }
    case "HoursReleased": {
      const prior = view.hoursByAssignee[event.assignee] ?? 0;
      return { ...view, hoursByAssignee: { ...view.hoursByAssignee, [event.assignee]: prior - event.hours } };
    }
    case "TaskNoteAdded":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function allocationFrom(events: AllocationEvent[]): AllocationView {
  return events.reduce(project, emptyAllocation);
}
