// The read store is eventually consistent with the event store.

type Command = { type: 'StartSurvey'; surveyor: string; at: string };
type SurveyEvent = { type: 'SurveyStarted'; surveyor: string; at: string };
type State = { status: 'empty' } | { status: 'active'; surveyor: string };
const initial: State = { status: 'empty' };

function evolve(state: State, event: SurveyEvent): State {
  switch (event.type) {
    case 'SurveyStarted':
      return { status: 'active', surveyor: event.surveyor };
    default: {
      const _: never = event.type;
      return _;
    }
  }
}

function decide(cmd: Command, state: State): SurveyEvent[] {
  if (state.status !== 'empty') throw new Error('already active');
  return [{ type: 'SurveyStarted', surveyor: cmd.surveyor, at: cmd.at }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: SurveyEvent; revision: bigint }>;
  appendToStream(s: string, e: SurveyEvent[], o: { expectedRevision: bigint | 'no_stream' }): Promise<void>;
}

interface ReadStore {
  get(id: string): Promise<{ surveyor: string } | null>;
}

export async function handleCommand(
  cmd: Command,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initial;
  let rev: bigint | 'no_stream' = 'no_stream';
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  await ctx.eventStore.appendToStream(ctx.streamName, decide(cmd, state), { expectedRevision: rev });
}

export async function queryView(id: string, readStore: ReadStore): Promise<{ surveyor: string } | null> {
  return readStore.get(id);
}
