export type GlazeTestState =
  | { status: "new" }
  | { status: "running"; id: string };

export type GlazeTestCommand =
  | { type: "register"; id: string }
  | { type: "score"; value: number };

export type GlazeTestEvent =
  | { type: "GlazeTestRegistered"; id: string }
  | { type: "GlazeTestScored"; value: number };

const initialState: GlazeTestState = { status: "new" };

function decide(
  c: GlazeTestCommand,
  s: GlazeTestState,
): GlazeTestEvent[] {
  if (c.type === "register") {
    if (s.status !== "new") throw new Error("already registered");
    return [{ type: "GlazeTestRegistered", id: c.id }];
  }
  if (s.status !== "running") throw new Error("not running");
  return [{ type: "GlazeTestScored", value: c.value }];
}

function evolve(
  s: GlazeTestState,
  e: GlazeTestEvent,
): GlazeTestState {
  if (e.type === "GlazeTestRegistered") return { status: "running", id: e.id };
  return s;
}

export interface EventStore {
  readStream(stream: string): Promise<{
    events: GlazeTestEvent[];
    lastRevision: bigint | "no_stream";
  }>;
  appendToStream(
    stream: string,
    events: GlazeTestEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export async function handle(
  command: GlazeTestCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const { events, lastRevision } = await ctx.eventStore.readStream(
    ctx.streamName,
  );
  const state = events.reduce(evolve, initialState);
  const produced = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, produced, {
    expectedRevision: lastRevision,
  });
}
