```typescript
import { Effect } from "effect";

export type NetPenState =
  | { status: "none" }
  | { status: "installed"; id: string; capacity: number; loaded: number };

export type NetPenCommand =
  | { type: "install"; id: string; capacity: number }
  | { type: "load"; count: number };

export type NetPenEvent =
  | { type: "NetPenInstalled"; id: string; capacity: number }
  | { type: "NetPenLoaded"; count: number };

const initial: NetPenState = { status: "none" };

function evolve(state: NetPenState, event: NetPenEvent): NetPenState {
  switch (event.type) {
    case "NetPenInstalled":
      return { status: "installed", id: event.id, capacity: event.capacity, loaded: 0 };
    case "NetPenLoaded":
      return state.status === "installed" ? { ...state, loaded: state.loaded + event.count } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: NetPenCommand, state: NetPenState): NetPenEvent[] {
  switch (command.type) {
    case "install":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "NetPenInstalled", id: command.id, capacity: command.capacity }];
    case "load":
      if (state.status !== "installed") throw new Error("NOT_INSTALLED");
      if (state.loaded + command.count > state.capacity) throw new Error("OVER_CAPACITY");
      return [{ type: "NetPenLoaded", count: command.count }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export const handle = (command: NetPenCommand, ctx: { streamName: string; eventStore: EventStore }) =>
  Effect.gen(function* () {
    const current = yield* Effect.promise(() => ctx.eventStore.readStream<NetPenEvent>(ctx.streamName));
    const state = current.events.reduce(evolve, initial);
    const events = decide(command, state);
    yield* Effect.promise(() =>
      ctx.eventStore.appendToStream<NetPenEvent>(ctx.streamName, events, {
        expectedRevision: current.revision,
      }),
    );
  });
