export function project(view: PilotLogView, event: PilotLogEvent): PilotLogView {
  switch (event.type) {
    case "LogOpened":
      return { byPilot: { ...view.byPilot, [event.pilotId]: { totalHours: 0, closed: false } } };
    case "HoursLogged": {
      const r = row(view, event.pilotId);
      return { byPilot: { ...view.byPilot, [event.pilotId]: { ...r, totalHours: r.totalHours + event.hours } } };
    }
    case "LogClosed": {
      const r = row(view, event.pilotId);
      return { byPilot: { ...view.byPilot, [event.pilotId]: { ...r, closed: true } } };
    }
    default: { const _n: never = event; return view; }
  }
}
