export type ChapterEvent =
  | { type: "ChapterAdded"; id: string; title: string }
  | { type: "ChapterRenamed"; title: string }
  | { type: "ChapterFinalized"; wordCount: number };

export type ChapterState =
  | { status: "none" }
  | { status: "open"; id: string; title: string; words: number }
  | { status: "final"; id: string; title: string; words: number };

export function when(state: ChapterState, event: ChapterEvent): ChapterState {
  switch (event.type) {
    case "ChapterAdded": return { status: "open", id: event.id, title: event.title, words: 0 };
    case "ChapterRenamed": return state.status === "open" ? { ...state, title: event.title } : state;
    case "ChapterFinalized":
      if (state.status !== "open") return state;
      return { status: "final", id: state.id, title: state.title, words: event.wordCount };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>, reducer: (s: S, e: E) => S, initial: S,
): Promise<S> {
  let acc = initial;
  for await (const e of stream) acc = reducer(acc, e);
  return acc;
}

export async function loadChapter(s: AsyncIterable<ChapterEvent>): Promise<ChapterState> {
  return aggregateStream<ChapterState, ChapterEvent>(s, when, { status: "none" });
}
