export type RestaurantCommand =
  | { type: "openRestaurant"; id: string; at: string }
  | { type: "closeRestaurant"; at: string };

export type RestaurantEvent =
  | { type: "RestaurantOpened"; id: string; at: string }
  | { type: "RestaurantClosed"; at: string };

type WriteState =
  | { status: "none" }
  | { status: "open"; id: string }
  | { status: "closed"; id: string };

const initial: WriteState = { status: "none" };

function evolve(s: WriteState, e: RestaurantEvent): WriteState {
  switch (e.type) {
    case "RestaurantOpened": return { status: "open", id: e.id };
    case "RestaurantClosed":
      return s.status === "open" ? { status: "closed", id: s.id } : s;
    default: { const _n: never = e; return s; }
  }
}

export class DomainError extends Error { constructor(m: string) { super(m); this.name = "DomainError"; } }

function decide(c: RestaurantCommand, s: WriteState): RestaurantEvent[] {
  switch (c.type) {
    case "openRestaurant":
      if (s.status === "open") throw new DomainError("ALREADY_OPEN");
      return [{ type: "RestaurantOpened", id: c.id, at: c.at }];
    case "closeRestaurant":
      if (s.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "RestaurantClosed", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(s: string): AsyncIterable<{ revision: bigint; event: RestaurantEvent }>;
  appendToStream(s: string, ev: RestaurantEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export async function handleCommand(cmd: RestaurantCommand, streamName: string, store: EventStore): Promise<void> {
  let state = initial;
  let rev: bigint | "no_stream" = "no_stream";
  for await (const { revision, event } of store.readStream(streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  const events = decide(cmd, state);
  if (events.length > 0) await store.appendToStream(streamName, events, { expectedRevision: rev });
}

// The read model is populated asynchronously by a subscription; this query
// store is eventually consistent with the event store.
export type RestaurantView = Readonly<{ id: string; isOpen: boolean }>;

export interface ReadStore {
  get(id: string): Promise<RestaurantView | null>;
}

export async function queryView(id: string, reads: ReadStore): Promise<RestaurantView | null> {
  return reads.get(id);
}
