```typescript
export type IrrigationCycleEvent =
  | { type: "IrrigationCycleStarted"; id: string; zone: string; flowRate: number; at: string }
  | { type: "IrrigationCycleStopped"; totalMinutes: number };

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: E }>>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendIrrigationEvents(
  store: EventStore<IrrigationCycleEvent>,
  stream: string,
  events: ReadonlyArray<IrrigationCycleEvent>
): Promise<bigint> {
  const existing = await store.readStream(stream);
  const expected: bigint | "no_stream" =
    existing.length === 0 ? "no_stream" : existing[existing.length - 1]!.revision;
  try {
    const out = await store.appendToStream(stream, events, { expectedRevision: expected });
    return out.nextExpectedRevision;
  } catch (err) {
    if (err instanceof Error && /conflict|revision/i.test(err.message)) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
