import { setup, assign, fromPromise } from 'xstate';

interface Job { readonly id: string; readonly pages: number }
interface Ctx { readonly queue: readonly Job[]; readonly current: Job | null; readonly errors: number }
type Ev =
  | { type: 'ENQUEUE'; job: Job }
  | { type: 'CANCEL' }
  | { type: 'RETRY' };

export const printer = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    print: fromPromise<void, { job: Job }>(async () => undefined)
  },
  guards: {
    queueNotEmpty: ({ context }) => context.queue.length > 0
  },
  actions: {
    takeNext: assign({
      current: ({ context }) => context.queue[0] ?? null,
      queue: ({ context }) => context.queue.slice(1)
    }),
    clearCurrent: assign({ current: () => null }),
    bumpErrors: assign({ errors: ({ context }) => context.errors + 1 })
  }
}).createMachine({
  id: 'printer',
  initial: 'idle',
  context: { queue: [], current: null, errors: 0 },
  states: {
    idle: {
      on: {
        ENQUEUE: {
          target: 'printing',
          actions: [
            assign({ queue: ({ context, event }) => [...context.queue, event.job] }),
            'takeNext'
          ]
        }
      }
    },
    printing: {
      invoke: {
        src: 'print',
        input: ({ context }) => ({ job: context.current as Job }),
        onDone: [
          { guard: 'queueNotEmpty', target: 'printing', actions: 'takeNext', reenter: true },
          { target: 'idle', actions: 'clearCurrent' }
        ],
        onError: { target: 'failed', actions: 'bumpErrors' }
      },
      on: {
        ENQUEUE: { actions: assign({ queue: ({ context, event }) => [...context.queue, event.job] }) },
        CANCEL: { target: 'idle', actions: 'clearCurrent' }
      }
    },
    failed: { on: { RETRY: 'printing' } }
  }
});
