```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide: (command: C, state: S) => E[];
  evolve: (state: S, event: E) => S;
}

export type ArtisanStudioState =
  | { status: "none" }
  | { status: "open"; id: string; owner: string; members: number }
  | { status: "closed"; id: string; closedAt: string };

export type ArtisanStudioCommand =
  | { type: "open"; id: string; owner: string }
  | { type: "admit"; member: string }
  | { type: "close"; closedAt: string };

export type ArtisanStudioEvent =
  | { type: "StudioOpened"; id: string; owner: string }
  | { type: "StudioMemberAdmitted"; member: string }
  | { type: "StudioClosed"; closedAt: string };

export class DomainError extends Error {}

export const initialState: ArtisanStudioState = { status: "none" };

export function decide(
  command: ArtisanStudioCommand,
  state: ArtisanStudioState,
): ArtisanStudioEvent[] {
  switch (command.type) {
    case "open":
      if (state.status === "open") throw new DomainError("already open");
      return [{ type: "StudioOpened", id: command.id, owner: command.owner }];
    case "admit":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "StudioMemberAdmitted", member: command.member }];
    case "close":
      if (state.status !== "open") throw new DomainError("cannot close");
      return [{ type: "StudioClosed", closedAt: command.closedAt }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(
  state: ArtisanStudioState,
  event: ArtisanStudioEvent,
): ArtisanStudioState {
  switch (event.type) {
    case "StudioOpened":
      return { status: "open", id: event.id, owner: event.owner, members: 0 };
    case "StudioMemberAdmitted":
      return state.status === "open"
        ? { ...state, members: state.members + 1 }
        : state;
    case "StudioClosed":
      return state.status === "open"
        ? { status: "closed", id: state.id, closedAt: event.closedAt }
        : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const artisanStudioDecider: Decider<
  ArtisanStudioCommand,
  ArtisanStudioEvent,
  ArtisanStudioState
> = { initialState, decide, evolve };
```

```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface VideoProjectV1 {
  readonly id: string;
  readonly name: string;
}

export interface VideoProjectV2 {
  readonly id: string;
  readonly title: string;
  readonly scenes: number;
}

export interface VideoProjectV3 {
  readonly id: string;
  readonly title: string;
  readonly scenes: number;
  readonly archived: boolean;
}

export type CurrentVideoProject = VideoProjectV3;
export const CURRENT_VERSION = 3;

function v1Tov2(s: VideoProjectV1): VideoProjectV2 {
  return { id: s.id, title: s.name, scenes: 0 };
}

function v2Tov3(s: VideoProjectV2): VideoProjectV3 {
  return { ...s, archived: false };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentVideoProject> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as VideoProjectV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as VideoProjectV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${version}`);
  return { version, state: state as CurrentVideoProject };
}
