export interface RawEventV1 {
  type: "LoanOriginated";
  version: 1;
  data: { id: string; amount: number };
}

export interface RawEventV2 {
  type: "LoanOriginated";
  version: 2;
  data: { id: string; principal: number };
}

export interface RawLoanDisbursed {
  type: "LoanDisbursed";
  version: 1;
  data: { at: string };
}

export type RawLoanEvent = RawEventV1 | RawEventV2 | RawLoanDisbursed;

export type LoanEvent =
  | { type: "LoanOriginated"; id: string; principal: number }
  | { type: "LoanDisbursed"; at: string };

export class UnknownEventError extends Error {}

export function upcast(raw: RawLoanEvent): LoanEvent {
  switch (raw.type) {
    case "LoanOriginated":
      if (raw.version === 1)
        return { type: "LoanOriginated", id: raw.data.id, principal: raw.data.amount };
      if (raw.version === 2)
        return { type: "LoanOriginated", id: raw.data.id, principal: raw.data.principal };
      throw new UnknownEventError("unknown version");
    case "LoanDisbursed":
      return { type: "LoanDisbursed", at: raw.data.at };
    default: { const _n: never = raw; throw new UnknownEventError("unknown event"); }
  }
}

export function upcastAll(raws: RawLoanEvent[]): LoanEvent[] {
  return raws.map(upcast);
}

export function aggregate(events: RawLoanEvent[]): LoanEvent[] {
  return upcastAll(events);
}

