```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type ResearchStudyState =
  | { status: "none" }
  | { status: "open"; id: string; enrolments: number }
  | { status: "closed"; id: string };

export type ResearchStudyEvent =
  | { type: "ResearchStudyRegistered"; id: string }
  | { type: "ResearchStudyParticipantEnrolled" }
  | { type: "ResearchStudyClosed" };

const empty: ResearchStudyState = { status: "none" };

function when(state: ResearchStudyState, event: ResearchStudyEvent): ResearchStudyState {
  switch (event.type) {
    case "ResearchStudyRegistered":
      return { status: "open", id: event.id, enrolments: 0 };
    case "ResearchStudyParticipantEnrolled":
      return state.status === "open" ? { ...state, enrolments: state.enrolments + 1 } : state;
    case "ResearchStudyClosed":
      return state.status === "open" ? { status: "closed", id: state.id } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function loadResearchStudy(stream: AsyncIterable<ResearchStudyEvent>): Promise<ResearchStudyState> {
  return aggregateStream(stream, when, empty);
}
