import { setup, assign } from 'xstate';

type Ctx = { anchor: string | null; selected: readonly string[] };
type Ev =
  | { type: 'CLICK'; id: string; shift: boolean; allIds: readonly string[] }
  | { type: 'CLEAR' };

export const anchoredSelect = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    isShift: ({ event }) => event.type === 'CLICK' && event.shift && event.id !== undefined,
    isPlain: ({ event }) => event.type === 'CLICK' && !event.shift
  },
  actions: {
    selectRange: assign(({ context, event }) => {
      if (event.type !== 'CLICK') return context;
      if (context.anchor === null) return { anchor: event.id, selected: [event.id] };
      const a = event.allIds.indexOf(context.anchor);
      const b = event.allIds.indexOf(event.id);
      if (a === -1 || b === -1) return context;
      const [lo, hi] = a < b ? [a, b] : [b, a];
      return { anchor: context.anchor, selected: event.allIds.slice(lo, hi + 1) };
    }),
    selectOne: assign(({ event }) => {
      if (event.type !== 'CLICK') return { anchor: null, selected: [] };
      return { anchor: event.id, selected: [event.id] };
    }),
    clear: assign({ anchor: () => null, selected: () => [] as readonly string[] })
  }
}).createMachine({
  id: 'anchoredSelect',
  initial: 'idle',
  context: { anchor: null, selected: [] },
  states: {
    idle: {
      on: {
        CLICK: [
          { guard: 'isShift', actions: 'selectRange' },
          { guard: 'isPlain', actions: 'selectOne' }
        ],
        CLEAR: { actions: 'clear' }
      }
    }
  }
});
