A sensor-poll promise actor rejects when the device returns a bad status. The invoking state has an `onError` transition that reads the typed `event.error`, assigns it into context, and moves to a dedicated `faulted` state — so UI and retry logic don't have to inspect a union inside the healthy path.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Ctx { reading: number | null; error: string | null }
type Ev = { type: 'POLL' } | { type: 'RESET' };

export const deviceFault = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    read: fromPromise<number, void>(async () => {
      throw new Error('E_SENSOR_TIMEOUT');
    })
  },
  actions: {
    storeReading: assign({ reading: ({ event }) => ('output' in event ? (event as { output: number }).output : null), error: () => null }),
    storeError: assign({ error: ({ event }) => ('error' in event ? String((event as { error: unknown }).error) : 'read failed') }),
    clearError: assign({ error: () => null })
  }
}).createMachine({
  id: 'deviceFault',
  context: { reading: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { POLL: 'reading' } },
    reading: {
      invoke: {
        src: 'read',
        onDone: { target: 'idle', actions: 'storeReading' },
        onError: { target: 'faulted', actions: 'storeError' }
      }
    },
    faulted: { on: { RESET: { target: 'idle', actions: 'clearError' } } }
  }
});
```

Snapshots cache the folded state of an aggregate so we can skip replaying the whole stream. When the schema evolves, older snapshots need forward upgraders, one per version bump, chained until the payload matches the current shape. The loader picks the starting upgrader using the snapshot's version tag.

```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface LotV1 { id: string; part: string; units: number; }
export interface LotV2 { id: string; part: string; units: number; line: string; }
export interface LotV3 { id: string; part: string; units: number; line: string; site: string; }

export type CurrentLot = LotV3;
export const CURRENT_VERSION = 3;

function v1Tov2(s: LotV1): LotV2 { return { ...s, line: "unknown" }; }
function v2Tov3(s: LotV2): LotV3 { return { ...s, site: "unknown" }; }

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentLot> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as LotV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as LotV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED:${version}`);
  return { version: CURRENT_VERSION, state: state as CurrentLot };
}
```

```typescript
import { Effect } from "effect";

export type OrderEvent =
  | { type: "OrderPlaced"; id: string; total: number }
  | { type: "OrderPaid"; at: string };

export type OrderCommand =
  | { type: "place"; id: string; total: number }
  | { type: "pay"; at: string };

export type OrderState =
  | { status: "none" }
  | { status: "placed"; id: string; total: number }
  | { status: "paid"; id: string; total: number };

export class OrderError extends Error {}

export function evolve(state: OrderState, event: OrderEvent): OrderState {
  switch (event.type) {
    case "OrderPlaced":
      return { status: "placed", id: event.id, total: event.total };
    case "OrderPaid":
      if (state.status !== "placed") return state;
      return { status: "paid", id: state.id, total: state.total };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(command: OrderCommand, state: OrderState): OrderEvent[] {
  switch (command.type) {
    case "place":
      if (state.status !== "none") throw new OrderError("EXISTS");
      return [{ type: "OrderPlaced", id: command.id, total: command.total }];
    case "pay":
      if (state.status !== "placed") throw new OrderError("NOT_PLACED");
      return [{ type: "OrderPaid", at: command.at }];
    default: {
      const _n: never = command;
      throw new OrderError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: OrderEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: OrderEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export const handleOrder = (store: EventStore) => (stream: string, command: OrderCommand) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => store.readStream(stream));
    const state = events.reduce(evolve, { status: "none" } as OrderState);
    const newEvents = decide(command, state);
    if (newEvents.length === 0) return revision;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() =>
      store.appendToStream(stream, newEvents, { expectedRevision }),
    );
  });
```

