export const loader = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { load },
  guards: {
    hasFresh: ({ context }) => context.data !== null && Date.now() - context.fetchedAt < TTL_MS,
  },
}).createMachine({
  id: 'loader',
  context: { data: null, fetchedAt: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        FETCH: [
          { guard: 'hasFresh', target: 'idle' },
          { target: 'loading' },
