        INVALIDATE: { actions: assign({ fetchedAt: () => 0 }) },
      },
    },
    loading: {
      invoke: {
        src: 'load',
        onDone: {
          target: 'idle',
          actions: assign({
            data: ({ event }) => event.output,
            fetchedAt: () => Date.now(),
          }),
        },
        onError: { target: 'idle' },
      },
    },
  },
});
