`evolve` drives the command path over strict state unions; `when` is the projection-friendly variant that folds over `Partial<A>` and validates the final shape with a type guard. Use `evolve` on the write side, `when` + `aggregateStream` on the read side.

```typescript
export type VehicleInspectionEvent =
  | { type: "VehicleInspected"; data: { id: string; odometer: number } }
  | { type: "VehicleInspectionFaultLogged"; data: { fault: string } }
  | { type: "VehicleInspectionClosed"; data: { at: string } };

export type VehicleInspection = Readonly<{
  id: string;
  odometer: number;
  faults: ReadonlyArray<string>;
  status: "open" | "closed";
  closedAt?: string;
}>;

export function when(
  current: Partial<VehicleInspection>,
  event: VehicleInspectionEvent,
): Partial<VehicleInspection> {
  switch (event.type) {
    case "VehicleInspected":
      return { id: event.data.id, odometer: event.data.odometer, faults: [], status: "open" };
    case "VehicleInspectionFaultLogged":
      return { ...current, faults: [...(current.faults ?? []), event.data.fault] };
    case "VehicleInspectionClosed":
      return { ...current, status: "closed", closedAt: event.data.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

function isInspection(v: Partial<VehicleInspection>): v is VehicleInspection {
  return !!v.id && typeof v.odometer === "number" && Array.isArray(v.faults) && !!v.status;
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const folded = events.reduce<Partial<A>>(reducer, {});
  if (!check(folded)) throw new Error("INVALID");
  return folded;
}

export function inspectionFrom(events: VehicleInspectionEvent[]): VehicleInspection {
  return aggregateStream<VehicleInspection, VehicleInspectionEvent>(events, when, isInspection);
}
```

