export type BookingEvent =
  | { type: "BookingRequested"; id: string; guests: number }
  | { type: "BookingConfirmed"; id: string; at: string };

export type BookingState =
  | { status: "none" }
  | { status: "requested"; id: string; guests: number }
  | { status: "confirmed"; id: string; guests: number; at: string };

export type BookingCommand =
  | { type: "request"; id: string; guests: number }
  | { type: "confirm"; at: string };

export class DomainError extends Error {}

export function evolve(state: BookingState, event: BookingEvent): BookingState {
  switch (event.type) {
    case "BookingRequested":
      return { status: "requested", id: event.id, guests: event.guests };
    case "BookingConfirmed":
      if (state.status !== "requested") return state;
      return { status: "confirmed", id: state.id, guests: state.guests, at: event.at };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(c: BookingCommand, s: BookingState): BookingEvent[] {
  switch (c.type) {
    case "request":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "BookingRequested", id: c.id, guests: c.guests }];
    case "confirm":
      if (s.status !== "requested") throw new DomainError("NOT_REQUESTED");
      return [{ type: "BookingConfirmed", id: "", at: c.at }];
    default: {
      const _n: never = c;
      throw new DomainError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: BookingEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: BookingEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export type BookingListItem = Readonly<{
  id: string;
  guests: number;
  status: "requested" | "confirmed";
}>;

export interface ViewStore {
  list(): Promise<ReadonlyArray<BookingListItem>>;
  getById(id: string): Promise<BookingListItem | null>;
}

export async function handleCommand(store: EventStore, stream: string, cmd: BookingCommand): Promise<bigint | null> {
  const { events, revision } = await store.readStream(stream);
  const state = events.reduce(evolve, { status: "none" } as BookingState);
  const newEvents = decide(cmd, state);
  if (newEvents.length === 0) return revision;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  return store.appendToStream(stream, newEvents, { expectedRevision });
}

// The read store is eventually consistent — a separate subscription populates it.
export async function queryList(views: ViewStore): Promise<ReadonlyArray<BookingListItem>> {
  return views.list();
}
