export async function aggregateStream<S, E>(
  source: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let s = initial;
  async function fold(): Promise<void> {
    for await (const e of source) s = reducer(s, e);
  }
  await fold();
  return s;
