export interface StoredEvent<E> { revision: bigint; data: E; }

export interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendGateEvents<E>(
  store: EventStore<E>,
  stream: string,
  events: E[],
): Promise<bigint> {
  const existing = await store.readStream(stream);
  const expectedRevision: bigint | "no_stream" = existing.length === 0 ? "no_stream" : existing[existing.length - 1].revision;
  try {
    const res = await store.appendToStream(stream, events, { expectedRevision });
    return res.nextExpectedRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("WrongExpectedVersion")) {
      throw new ConcurrencyConflict(stream, expectedRevision);
    }
    throw err;
  }
}
