```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

```typescript
export type DiningTableEvent =
  | { type: "TableOpened"; tableNo: number; seats: number }
  | { type: "PartySeated"; tableNo: number; guests: number }
  | { type: "PartyLeft"; tableNo: number };

export type TableInfo = Readonly<{ tableNo: number; seats: number; currentGuests: number }>;
export type TableView = Readonly<{ tables: Readonly<Record<number, TableInfo>> }>;

export function project(view: TableView, e: DiningTableEvent): TableView {
  switch (e.type) {
    case "TableOpened":
      return {
        tables: { ...view.tables, [e.tableNo]: { tableNo: e.tableNo, seats: e.seats, currentGuests: 0 } },
      };
    case "PartySeated": {
      const t = view.tables[e.tableNo];
      if (!t) return view;
      return { tables: { ...view.tables, [e.tableNo]: { ...t, currentGuests: e.guests } } };
    }
    case "PartyLeft": {
      const t = view.tables[e.tableNo];
      if (!t) return view;
      return { tables: { ...view.tables, [e.tableNo]: { ...t, currentGuests: 0 } } };
    }
    default: { const _n: never = e; return view; }
  }
}

export interface EventStore {
  readRange(from: bigint, max: number): Promise<ReadonlyArray<{ revision: bigint; event: DiningTableEvent }>>;
}

export interface PersistStore {
  saveCheckpoint(view: TableView, revision: bigint): Promise<void>;
}

export async function rebuild(
  opts: { from: bigint; batchSize: number; events: EventStore; reads: PersistStore }
): Promise<void> {
  let cursor = opts.from;
  let view: TableView = { tables: {} };
  for (;;) {
    const batch = await opts.events.readRange(cursor, opts.batchSize);
    if (batch.length === 0) return;
    let last = cursor;
    for (const { revision, event } of batch) {
      view = project(view, event);
      last = revision;
    }
    await opts.reads.saveCheckpoint(view, last);
    cursor = last + 1n;
  }
}
