export interface StoredEvent<E> { readonly revision: bigint; readonly event: E }

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(
    stream: string,
    events: E[],
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super("concurrency conflict on " + stream);
    this.name = "ConcurrencyConflict";
  }
}

export type ReservationEvent =
  | { type: "ReservationRequested"; partySize: number }
  | { type: "ReservationConfirmed"; tableNo: number };

export type ReservationState = { partySize: number; confirmed: boolean };

const initial: ReservationState = { partySize: 0, confirmed: false };

function evolve(s: ReservationState, e: ReservationEvent): ReservationState {
  switch (e.type) {
    case "ReservationRequested": return { partySize: e.partySize, confirmed: false };
    case "ReservationConfirmed": return { ...s, confirmed: true };
    default: { const _n: never = e; return s; }
  }
}

export async function confirmReservation(
  store: EventStore<ReservationEvent>,
  stream: string,
  tableNo: number
): Promise<bigint> {
  let state = initial;
  let lastRevision: bigint | "no_stream" = "no_stream";
  for await (const { revision, event } of store.readStream(stream)) {
    state = evolve(state, event);
    lastRevision = revision;
  }
  if (state.confirmed) throw new Error("ALREADY_CONFIRMED");
  const events: ReservationEvent[] = [{ type: "ReservationConfirmed", tableNo }];
  try {
    const { nextRevision } = await store.appendToStream(stream, events, { expectedRevision: lastRevision });
    return nextRevision;
  } catch {
    throw new ConcurrencyConflict(stream);
  }
}
