export type RiskLimitEvent =
  | { type: "LimitRegistered"; id: string; threshold: number }
  | { type: "ThresholdAdjusted"; threshold: number }
  | { type: "LimitBreached"; at: string };

export type RiskLimit = Readonly<{ id: string; threshold: number; breachedAt?: string }>;

export function when(state: Partial<RiskLimit>, event: RiskLimitEvent): Partial<RiskLimit> {
  switch (event.type) {
    case "LimitRegistered":
      return { id: event.id, threshold: event.threshold };
    case "ThresholdAdjusted":
      return { ...state, threshold: event.threshold };
    case "LimitBreached":
      return { ...state, breachedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export function isRiskLimit(s: Partial<RiskLimit>): s is RiskLimit {
  return !!s.id && typeof s.threshold === "number";
}

export async function aggregateStream<A, E>(
  stream: AsyncIterable<E>,
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): Promise<A> {
  let state: Partial<A> = {};
  for await (const event of stream) {
    state = reducer(state, event);
  }
  if (!check(state)) throw new Error("INVALID_AGGREGATE_STATE");
  return state;
}

export const riskLimitFromStream = (s: AsyncIterable<RiskLimitEvent>): Promise<RiskLimit> =>
  aggregateStream(s, when, isRiskLimit);

