export type LegEvent =
  | { type: "LegScheduled"; id: string; routeId: string }
  | { type: "LegStarted"; id: string }
  | { type: "LegCompleted"; id: string };

export interface PositionedEvent { position: bigint; event: LegEvent }

export interface EventReader {
  readBatch(from: bigint, batchSize: number): Promise<readonly PositionedEvent[]>;
}

export interface LegRow { routeId: string; status: "scheduled" | "started" | "completed" }

export interface ReadStore {
  write(id: string, row: LegRow): Promise<void>;
  setCursor(name: string, position: bigint): Promise<void>;
}

export function project(rows: Readonly<Record<string, LegRow>>, event: LegEvent): Readonly<Record<string, LegRow>> {
  switch (event.type) {
    case "LegScheduled": return { ...rows, [event.id]: { routeId: event.routeId, status: "scheduled" } };
    case "LegStarted": {
      const prev = rows[event.id];
      if (!prev) return rows;
      return { ...rows, [event.id]: { ...prev, status: "started" } };
    }
    case "LegCompleted": {
      const prev = rows[event.id];
      if (!prev) return rows;
      return { ...rows, [event.id]: { ...prev, status: "completed" } };
    }
    default: { const _n: never = event; return rows; }
  }
}

export async function rebuild(opts: { from: bigint; batchSize: number; reader: EventReader; store: ReadStore; name: string }): Promise<void> {
  let cursor = opts.from;
  let rows: Readonly<Record<string, LegRow>> = {};
  while (true) {
    const batch = await opts.reader.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const { event } of batch) {
      rows = project(rows, event);
    }
    for (const [id, row] of Object.entries(rows)) {
      await opts.store.write(id, row);
    }
    const last = batch[batch.length - 1];
    cursor = last.position + 1n;
    await opts.store.setCursor(opts.name, cursor);
  }
}
```

A Decider locks all business rules inside `decide` and treats `evolve` as a total fold. `decide(command, state)` either produces events or throws a typed error; `evolve(state, event)` can assume every incoming event is already legal because `decide` guards the write path. That separation makes rehydration from the event stream deterministic.

```typescript
export type LotState =
  | { status: "none" }
  | { status: "active"; id: string; sku: string; qty: number }
  | { status: "quarantined"; id: string; sku: string; qty: number; reason: string };

export type LotCommand =
  | { type: "create"; id: string; sku: string; qty: number }
  | { type: "quarantine"; reason: string }
  | { type: "release" };

export type LotEvent =
  | { type: "LotCreated"; id: string; sku: string; qty: number }
  | { type: "LotQuarantined"; reason: string }
  | { type: "LotReleased" };

export class LotError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const lotDecider: Decider<LotCommand, LotEvent, LotState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "create":
        if (s.status !== "none") throw new LotError("EXISTS");
        if (c.qty <= 0) throw new LotError("QTY_INVALID");
        return [{ type: "LotCreated", id: c.id, sku: c.sku, qty: c.qty }];
      case "quarantine":
        if (s.status !== "active") throw new LotError("NOT_ACTIVE");
        return [{ type: "LotQuarantined", reason: c.reason }];
      case "release":
        if (s.status !== "quarantined") throw new LotError("NOT_QUARANTINED");
        return [{ type: "LotReleased" }];
      default: { const _n: never = c; throw new LotError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "LotCreated":
        return { status: "active", id: e.id, sku: e.sku, qty: e.qty };
      case "LotQuarantined":
        if (s.status !== "active") return s;
        return { status: "quarantined", id: s.id, sku: s.sku, qty: s.qty, reason: e.reason };
      case "LotReleased":
        if (s.status !== "quarantined") return s;
        return { status: "active", id: s.id, sku: s.sku, qty: s.qty };
      default: { const _n: never = e; return s; }
    }
  },
};
```

```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type Command =
  | { type: 'StartSurvey'; surveyor: string; at: string }
  | { type: 'RecordWaypoint'; lat: number; lon: number; at: string }
  | { type: 'CloseSurvey'; at: string };

type Event =
  | { type: 'SurveyStarted'; surveyor: string; at: string }
  | { type: 'WaypointRecorded'; lat: number; lon: number; at: string }
  | { type: 'SurveyClosed'; at: string };

type State =
  | { status: 'empty' }
  | { status: 'active'; surveyor: string; waypoints: number }
  | { status: 'closed' };

class InvariantError extends Error {}

export const FieldSurvey: Decider<Command, Event, State> = {
  initialState: { status: 'empty' },
  decide(command, state) {
    switch (command.type) {
      case 'StartSurvey':
        if (state.status !== 'empty') throw new InvariantError('already started');
        return [{ type: 'SurveyStarted', surveyor: command.surveyor, at: command.at }];
      case 'RecordWaypoint':
        if (state.status !== 'active') throw new InvariantError('not active');
        return [{ type: 'WaypointRecorded', lat: command.lat, lon: command.lon, at: command.at }];
      case 'CloseSurvey':
        if (state.status !== 'active') throw new InvariantError('not active');
        return [{ type: 'SurveyClosed', at: command.at }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'SurveyStarted':
        return { status: 'active', surveyor: event.surveyor, waypoints: 0 };
      case 'WaypointRecorded':
        return state.status === 'active'
          ? { ...state, waypoints: state.waypoints + 1 }
          : state;
      case 'SurveyClosed':
        return { status: 'closed' };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};

void FieldSurvey.decide({ type: 'StartSurvey', surveyor: 'A', at: '2025-01-01' }, FieldSurvey.initialState);
