```typescript
export type PayoutState =
  | { status: "none" }
  | { status: "requested"; id: string; amount: number }
  | { status: "approved"; id: string; amount: number };

export type PayoutCommand =
  | { type: "request"; id: string; amount: number }
  | { type: "approve"; approver: string };

export type PayoutEvent =
  | { type: "PayoutRequested"; id: string; amount: number }
  | { type: "PayoutApproved"; approver: string };

export class DomainError extends Error {}
export class ConcurrencyConflict extends Error {}

export const initialState: PayoutState = { status: "none" };

export function evolve(s: PayoutState, e: PayoutEvent): PayoutState {
  switch (e.type) {
    case "PayoutRequested": return { status: "requested", id: e.id, amount: e.amount };
    case "PayoutApproved":
      if (s.status !== "requested") return s;
      return { status: "approved", id: s.id, amount: s.amount };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: PayoutCommand, s: PayoutState): PayoutEvent[] {
  switch (c.type) {
    case "request":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "PayoutRequested", id: c.id, amount: c.amount }];
    case "approve":
      if (s.status !== "requested") throw new DomainError("NOT_REQUESTED");
      return [{ type: "PayoutApproved", approver: c.approver }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: PayoutEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: ReadonlyArray<PayoutEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export async function handle(
  store: EventStore,
  streamName: string,
  command: PayoutCommand,
  maxAttempts: number,
): Promise<void> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    attempt = attempt + 1;
    const { events, revision } = await store.readStream(streamName);
    const state = events.reduce(evolve, initialState);
    const produced = decide(command, state);
    if (produced.length === 0) return;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    try {
      await store.appendToStream(streamName, produced, { expectedRevision });
      return;
    } catch (err) {
      if (!(err instanceof ConcurrencyConflict)) throw err;
      if (attempt >= maxAttempts) throw err;
    }
  }
}
```

