export type PolicyEvent =
  | { type: "PolicyQuoted"; id: string; premium: number }
  | { type: "PolicyActivated"; id: string; at: string };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface Subscription<E> {
  subscribe(from: bigint | null): AsyncIterable<{ position: bigint; event: E }>;
}

export interface ViewStore<V> {
  get(): Promise<V>;
  put(v: V): Promise<void>;
}

export async function runSubscription<V>(
  name: string,
  sub: Subscription<PolicyEvent>,
  cps: CheckpointStore,
  views: ViewStore<V>,
  project: (view: V, event: PolicyEvent) => V,
): Promise<void> {
  const start = await cps.read(name);
  for await (const { position, event } of sub.subscribe(start)) {
    const view = await views.get();
    const next = project(view, event);
    await views.put(next);
    await cps.write(name, position);
  }
}
