export type LoanEvent =
  | { type: "LoanOriginated"; id: string; principal: number }
  | { type: "LoanClosed"; id: string };

export interface EventEnvelope { readonly position: bigint; readonly event: LoanEvent; }

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface LoanBookView {
  readonly active: ReadonlyArray<string>;
  readonly closed: ReadonlyArray<string>;
}

export const emptyView: LoanBookView = { active: [], closed: [] };

export function project(view: LoanBookView, event: LoanEvent): LoanBookView {
  switch (event.type) {
    case "LoanOriginated":
      return { ...view, active: [...view.active, event.id] };
    case "LoanClosed":
      return {
        active: view.active.filter((id) => id !== event.id),
        closed: [...view.closed, event.id],
      };
    default: { const _n: never = event; return view; }
  }
}

export async function runSubscription(
  name: string,
  checkpoints: CheckpointStore,
  stream: AsyncIterable<EventEnvelope>,
  persistView: (v: LoanBookView) => Promise<void>,
): Promise<void> {
  const from = (await checkpoints.read(name)) ?? 0n;
  let view: LoanBookView = emptyView;
  for await (const env of stream) {
    if (env.position <= from) continue;
    view = project(view, env.event);
    await persistView(view);
    await checkpoints.write(name, env.position);
  }
}

