export class DriverShiftError extends Error {
  constructor(public readonly code: "NO_SHIFT" | "ALREADY_OPEN" | "UNKNOWN") {
    super(code);
    this.name = "DriverShiftError";
  }
}

export type DriverShiftState =
  | { status: "idle"; driverId: string }
  | { status: "onShift"; driverId: string; startedAt: string };

export type DriverShiftCommand =
  | { type: "clockIn"; at: string }
  | { type: "clockOut"; at: string };

export type DriverShiftEvent =
  | { type: "ShiftOpened"; at: string }
  | { type: "ShiftClosed"; at: string };

function evolve(s: DriverShiftState, e: DriverShiftEvent): DriverShiftState {
  switch (e.type) {
    case "ShiftOpened":
      return { status: "onShift", driverId: s.driverId, startedAt: e.at };
    case "ShiftClosed":
      return { status: "idle", driverId: s.driverId };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: DriverShiftCommand, s: DriverShiftState): DriverShiftEvent[] {
  switch (c.type) {
    case "clockIn":
      if (s.status !== "idle") throw new DriverShiftError("ALREADY_OPEN");
      return [{ type: "ShiftOpened", at: c.at }];
    case "clockOut":
      if (s.status !== "onShift") throw new DriverShiftError("NO_SHIFT");
      return [{ type: "ShiftClosed", at: c.at }];
    default: { const _n: never = c; throw new DriverShiftError("UNKNOWN"); }
  }
}

export async function handleDriverShift(
  driverId: string,
  command: DriverShiftCommand,
  ctx: { streamName: string; eventStore: EventStore<DriverShiftEvent> },
): Promise<void> {
  let state: DriverShiftState = { status: "idle", driverId };
  let revision: bigint | undefined = undefined;
  for await (const { event, revision: r } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    revision = r;
  }
  const events = decide(command, state);
  if (events.length === 0) return;
  const expected: ExpectedRevision = revision ?? "no_stream";
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}
