export type ExpectedRevision = bigint | "no_stream" | "any";

export interface Snapshot<S> { readonly version: number; readonly state: S; readonly revision: bigint }
export interface SnapshotStore<S> {
  load(stream: string): Promise<Snapshot<S> | null>;
  save(stream: string, snap: Snapshot<S>): Promise<void>;
}

export interface StoredEvent<E> { readonly position: bigint; readonly event: E }
export interface EventStore<E> {
  readFromStream(stream: string, from: bigint): Promise<StoredEvent<E>[]>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export type FormularyCommand =
  | { type: "list"; code: string; name: string }
  | { type: "delist"; code: string };
export type FormularyEvent =
  | { type: "DrugListed"; code: string; name: string }
  | { type: "DrugDelisted"; code: string };
export interface FormularyState { readonly drugs: Record<string, { code: string; name: string; active: boolean }> }

export const CURRENT_VERSION = 1 as const;
export const initialState: FormularyState = { drugs: {} };

export function evolve(s: FormularyState, e: FormularyEvent): FormularyState {
  switch (e.type) {
    case "DrugListed":
      return { drugs: { ...s.drugs, [e.code]: { code: e.code, name: e.name, active: true } } };
    case "DrugDelisted": {
      const row = s.drugs[e.code];
      if (!row) return s;
      return { drugs: { ...s.drugs, [e.code]: { ...row, active: false } } };
    }
    default: { const _never: never = e; return s; }
  }
}

export function decide(c: FormularyCommand, s: FormularyState): FormularyEvent[] {
  switch (c.type) {
    case "list":
      if (s.drugs[c.code]?.active) throw new Error("ALREADY_LISTED");
      return [{ type: "DrugListed", code: c.code, name: c.name }];
    case "delist":
      if (!s.drugs[c.code]?.active) throw new Error("NOT_LISTED");
      return [{ type: "DrugDelisted", code: c.code }];
    default: { const _never: never = c; throw new Error("UNKNOWN"); }
  }
}

export async function handle(
  command: FormularyCommand,
  stream: string,
  store: EventStore<FormularyEvent>,
  snaps: SnapshotStore<FormularyState>,
): Promise<bigint> {
  const snap = await snaps.load(stream);
  const baseState = snap?.state ?? initialState;
  const from = snap ? snap.revision + 1n : 0n;
  const tail = await store.readFromStream(stream, from);
  const state = tail.reduce<FormularyState>((s, ev) => evolve(s, ev.event), baseState);
  const events = decide(command, state);
  const last = tail.length > 0 ? tail[tail.length - 1].position : snap?.revision ?? -1n;
  const expectedRevision: ExpectedRevision = last < 0n ? "no_stream" : last;
  const result = await store.appendToStream(stream, events, { expectedRevision });
  return result.nextRevision;
}
