  readonly payload: { readonly schema: string; readonly data: unknown };
  readonly publishedAt: string | null;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface TransactionalConnection {
  begin(): Promise<Transaction>;
}

export interface Transaction {
  appendToStream(
    stream: string,
    events: readonly AdSlotEvent[],
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export async function appendWithOutbox(
  stream: string,
  events: readonly AdSlotEvent[],
  outboxRows: readonly OutboxRow[],
  expectedRevision: ExpectedRevision,
  conn: TransactionalConnection,
): Promise<void> {
  const tx = await conn.begin();
  try {
    await tx.appendToStream(stream, events, { expectedRevision });
    if (outboxRows.length > 0) await tx.insertOutbox(outboxRows);
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
  // NOTE: a separate worker polls unpublished outbox rows, publishes the
  // payload, and marks `publishedAt`. That worker is not implemented here.
}
