export interface VisitRecordState {
  readonly id: string;
  readonly patientId: string;
  readonly notes: string[];
  readonly signedBy: string | null;
  readonly locale: string;
}

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3 as const;

interface V1 { id: string; patientId: string; notes: string[] }
interface V2 { id: string; patientId: string; notes: string[]; signedBy: string | null }

function v1Tov2(s: V1): V2 { return { ...s, signedBy: null }; }
function v2Tov3(s: V2): VisitRecordState { return { ...s, locale: "en-US" }; }

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<VisitRecordState> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v === 1) { state = v1Tov2(state as V1); v = 2; }
  if (v === 2) { state = v2Tov3(state as V2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error("UNSUPPORTED_SNAPSHOT_VERSION");
  return { version: CURRENT_VERSION, state: state as VisitRecordState };
}
