    case "SettlementEntryPosted": {
      const prior = view.totals[event.id] ?? 0;
      return { ...view, totals: { ...view.totals, [event.id]: prior + event.amount } };
    }
    case "SettlementClosed": return { ...view, open: view.open - 1, closed: view.closed + 1 };
    default: { const _n: never = event; return view; }
  }
}

export interface ReadStore {
  wipe(): Promise<void>;
  get(): Promise<SettlementView>;
  put(view: SettlementView): Promise<void>;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  wipeFirst: boolean;
  reader: EventStoreReader;
  store: ReadStore;
  onProgress?: (cursor: bigint, processed: number) => void;
}

export async function rebuild(options: RebuildOptions): Promise<void> {
  if (options.wipeFirst) await options.store.wipe();
  let cursor: bigint = options.from;
  let processed = 0;
  let view: SettlementView = options.from === 0n ? emptyView : await options.store.get();
  while (true) {
    const batch = await options.reader.readForward(cursor, options.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = project(view, event);
      cursor = revision + 1n;
      processed = processed + 1;
    }
    await options.store.put(view);
    if (options.onProgress) options.onProgress(cursor, processed);
  }
}
```

