import { Effect } from "effect";

export type PurchaseEvent =
  | { type: "PurchasePlaced"; id: string; total: number }
  | { type: "PurchaseFulfilled"; at: string };

export type PurchaseState =
  | { status: "none" }
  | { status: "placed"; id: string; total: number }
  | { status: "fulfilled"; id: string; total: number; at: string };

export function when(s: PurchaseState, e: PurchaseEvent): PurchaseState {
  switch (e.type) {
    case "PurchasePlaced":
      return { status: "placed", id: e.id, total: e.total };
    case "PurchaseFulfilled":
      if (s.status !== "placed") return s;
      return { status: "fulfilled", id: s.id, total: s.total, at: e.at };
    default: {
      const _n: never = e;
      return s;
    }
  }
}

export const aggregateStream = <S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S,
) =>
  Effect.promise(async () => {
    let acc = initial;
    for await (const e of stream) acc = reducer(acc, e);
    return acc;
  });

export const loadPurchase = (events: AsyncIterable<PurchaseEvent>) =>
  aggregateStream<PurchaseState, PurchaseEvent>(events, when, { status: "none" });
