export type SpecimenKitEvent =
  | { type: "SpecimenKitAssembled"; id: string }
  | { type: "SpecimenKitSealed"; id: string }
  | { type: "SpecimenKitDispatched"; id: string };

export type SpecimenKitView = { assembled: number; sealed: number; dispatched: number };
const empty: SpecimenKitView = { assembled: 0, sealed: 0, dispatched: 0 };

function project(view: SpecimenKitView, event: SpecimenKitEvent): SpecimenKitView {
  switch (event.type) {
    case "SpecimenKitAssembled":
      return { ...view, assembled: view.assembled + 1 };
    case "SpecimenKitSealed":
      return { ...view, sealed: view.sealed + 1 };
    case "SpecimenKitDispatched":
      return { ...view, dispatched: view.dispatched + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface BatchReader<E> {
  readBatch(from: bigint, size: number): Promise<{ events: E[]; nextFrom: bigint | null }>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  reader: BatchReader<SpecimenKitEvent>;
  persist: (view: SpecimenKitView, cursor: bigint) => Promise<void>;
  report: (processed: number) => void;
}): Promise<void> {
  let cursor = opts.from;
  let view = empty;
  let processed = 0;
  let done = false;
  while (!done) {
    const { events, nextFrom } = await opts.reader.readBatch(cursor, opts.batchSize);
    for (const event of events) {
      view = project(view, event);
      processed += 1;
    }
    cursor = nextFrom ?? cursor;
    await opts.persist(view, cursor);
    opts.report(processed);
    if (nextFrom === null) done = true;
  }
}
