A flat machine with guards on each transition keeps the math obvious.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { step: number; total: number };
type Ev = { type: 'NEXT' } | { type: 'PREV' } | { type: 'SKIP' } | { type: 'COMPLETE' };

export const stepper = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasNext: ({ context }) => context.step < context.total - 1,
    hasPrev: ({ context }) => context.step > 0,
    atLast: ({ context }) => context.step === context.total - 1,
  },
}).createMachine({
  id: 'stepper',
  context: { step: 0, total: 4 },
  initial: 'active',
  states: {
    active: {
      on: {
        NEXT: {
          guard: 'hasNext',
          actions: assign({ step: ({ context }) => context.step + 1 }),
        },
        PREV: {
          guard: 'hasPrev',
          actions: assign({ step: ({ context }) => context.step - 1 }),
        },
        SKIP: {
          guard: 'hasNext',
          actions: assign({ step: ({ context }) => Math.min(context.total - 1, context.step + 2) }),
        },
        COMPLETE: { guard: 'atLast', target: 'done' },
      },
    },
    done: { type: 'final' },
  },
});
