```typescript
interface StoredEvent<E> { data: E; revision: bigint }

interface EventStore<E> {
  readFromStream(stream: string, from: bigint, limit: number): Promise<StoredEvent<E>[]>;
}

export type BlockEvent = { type: "UnitOccupied" } | { type: "UnitVacated" };
export interface BlockView { occupied: number }

function project(view: BlockView, event: BlockEvent): BlockView {
  switch (event.type) {
    case "UnitOccupied":
      return { occupied: view.occupied + 1 };
    case "UnitVacated":
      return { occupied: Math.max(0, view.occupied - 1) };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  project: (v: BlockView, e: BlockEvent) => BlockView;
  persist: (v: BlockView, cursor: bigint) => Promise<void>;
}

export async function rebuild(
  store: EventStore<BlockEvent>,
  stream: string,
  options: RebuildOptions,
): Promise<void> {
  let cursor = options.from;
  let view: BlockView = { occupied: 0 };
  for (;;) {
    const batch = await store.readFromStream(stream, cursor, options.batchSize);
    if (batch.length === 0) return;
    for (const item of batch) {
      view = options.project(view, item.data);
      cursor = item.revision + 1n;
    }
    await options.persist(view, cursor);
  }
}
```

