Resume at the last checkpoint, apply each event to the read model, then persist the checkpoint. Effect.gen makes the IO sequence explicit; the pure projection stays outside.

```typescript
import { Effect } from "effect";

export type FleetVehicleEvent =
  | { type: "FleetVehicleEnrolled"; id: string; plate: string }
  | { type: "FleetVehicleAssigned"; driverId: string };

export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, p: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(p: bigint): AsyncIterable<EventEnvelope<E>>;
}

export type FleetReadModel = Readonly<{ id: string; plate: string; driverId?: string }>;

export interface Projection<V, E> {
  load(): Promise<V>;
  project(v: V, e: E): V;
  save(v: V): Promise<void>;
}

export const runSubscriptionEffect = (
  name: string,
  source: EventSource<FleetVehicleEvent>,
  checkpoints: CheckpointStore,
  projection: Projection<FleetReadModel, FleetVehicleEvent>,
) =>
  Effect.gen(function* () {
    const start = yield* Effect.promise(() => checkpoints.read(name));
    let view = yield* Effect.promise(() => projection.load());
    const drain = async (): Promise<void> => {
      for await (const { position, event } of source.readFrom(start ?? 0n)) {
        view = projection.project(view, event);
        await projection.save(view);
        await checkpoints.write(name, position);
      }
    };
    yield* Effect.promise(() => drain());
  });
```

```typescript
export type ShipmentState =
  | { status: "none" }
  | { status: "created"; id: string }
  | { status: "dispatched"; id: string; carrier: string };

export type ShipmentCommand =
  | { type: "create"; id: string }
  | { type: "dispatch"; carrier: string };

export type ShipmentEvent =
  | { type: "ShipmentCreated"; id: string }
  | { type: "ShipmentDispatched"; carrier: string };

export class DomainError extends Error {}

export const initialState: ShipmentState = { status: "none" };

export function evolve(state: ShipmentState, event: ShipmentEvent): ShipmentState {
  switch (event.type) {
    case "ShipmentCreated":
      return { status: "created", id: event.id };
    case "ShipmentDispatched":
      if (state.status !== "created") return state;
      return { status: "dispatched", id: state.id, carrier: event.carrier };
    default: { const _n: never = event; return state; }
  }
}

export function decide(c: ShipmentCommand, s: ShipmentState): ShipmentEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ShipmentCreated", id: c.id }];
    case "dispatch":
      if (s.status !== "created") throw new DomainError("NOT_CREATED");
      return [{ type: "ShipmentDispatched", carrier: c.carrier }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ShipmentEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: ShipmentEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export async function handleShipmentCommand(
  streamName: string,
  command: ShipmentCommand,
  eventStore: EventStore,
): Promise<void> {
  const { events, revision } = await eventStore.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const newEvents = decide(command, state);
  if (newEvents.length === 0) return;
  await eventStore.appendToStream(streamName, newEvents, { expectedRevision: revision ?? "no_stream" });
}
