export type CheckpointEvent =
  | { type: "CheckpointCreated"; id: string; step: number }
  | { type: "CheckpointPromoted"; stage: string };

export interface ReadResult<E> {
  readonly events: E[];
  readonly revision: bigint | "no_stream";
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(
    stream: string,
    events: E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ revision: bigint } | { conflict: true }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendChecked<E>(
  store: EventStore<E>,
  stream: string,
  events: E[],
): Promise<bigint> {
  const { revision } = await store.readStream(stream);
  const result = await store.appendToStream(stream, events, { expectedRevision: revision });
  if ("conflict" in result) {
    throw new ConcurrencyConflict(stream);
  }
  return result.revision;
}
