export type HyperparameterSweepState =
  | { status: "none" }
  | { status: "planned"; id: string; trialsBudget: number }
  | { status: "running"; id: string; trialsBudget: number; trialsDone: number }
  | { status: "finished"; id: string; bestScore: number };

export type HyperparameterSweepCommand =
  | { type: "plan"; id: string; trialsBudget: number }
  | { type: "start" }
  | { type: "recordTrial"; score: number }
  | { type: "finish"; bestScore: number };

export type HyperparameterSweepEvent =
  | { type: "SweepPlanned"; id: string; trialsBudget: number }
  | { type: "SweepStarted" }
  | { type: "SweepTrialRecorded"; score: number }
  | { type: "SweepFinished"; bestScore: number };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const sweepDecider: Decider<HyperparameterSweepCommand, HyperparameterSweepEvent, HyperparameterSweepState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.trialsBudget <= 0) throw new DomainError("BAD_BUDGET");
        return [{ type: "SweepPlanned", id: command.id, trialsBudget: command.trialsBudget }];
      case "start":
        if (state.status !== "planned") throw new DomainError("NOT_PLANNED");
        return [{ type: "SweepStarted" }];
      case "recordTrial":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        if (state.trialsDone >= state.trialsBudget) throw new DomainError("BUDGET_EXHAUSTED");
        return [{ type: "SweepTrialRecorded", score: command.score }];
      case "finish":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "SweepFinished", bestScore: command.bestScore }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SweepPlanned":
        return { status: "planned", id: event.id, trialsBudget: event.trialsBudget };
      case "SweepStarted":
        if (state.status !== "planned") return state;
        return { status: "running", id: state.id, trialsBudget: state.trialsBudget, trialsDone: 0 };
      case "SweepTrialRecorded":
        if (state.status !== "running") return state;
        return { ...state, trialsDone: state.trialsDone + 1 };
      case "SweepFinished":
        if (state.status !== "running") return state;
        return { status: "finished", id: state.id, bestScore: event.bestScore };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

