type ConversationEvent =
  | { type: 'ConversationStarted'; id: string }
  | { type: 'ParticipantAdded'; userId: string };

interface AppendResult {
  readonly nextExpectedRevision: bigint;
}

interface EventStore {
  appendToStream(
    stream: string,
    events: readonly ConversationEvent[],
    options: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<AppendResult>;
  readStream(stream: string): AsyncIterable<{ event: ConversationEvent; revision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | 'no_stream' | 'any') {
    super(`concurrency conflict on ${stream}`);
  }
}

export async function appendGuarded(
  store: EventStore,
  stream: string,
  events: readonly ConversationEvent[],
): Promise<bigint> {
  let lastRevision: bigint | 'no_stream' = 'no_stream';
  for await (const { revision } of store.readStream(stream)) {
    lastRevision = revision;
  }
  try {
    const { nextExpectedRevision } = await store.appendToStream(stream, events, {
      expectedRevision: lastRevision,
    });
    return nextExpectedRevision;
  } catch (err) {
    if ((err as { code?: string }).code === 'WrongExpectedVersion') {
      throw new ConcurrencyConflict(stream, lastRevision);
    }
    throw err;
  }
}

