```typescript
import { Effect } from "effect";

export type WorkOrderState =
  | { status: "none" }
  | { status: "raised"; id: string; requester: string }
  | { status: "inProgress"; id: string; technician: string }
  | { status: "completed"; id: string };

export type WorkOrderCommand =
  | { type: "raise"; id: string; requester: string }
  | { type: "start"; technician: string }
  | { type: "complete" };

export type WorkOrderEvent =
  | { type: "WorkOrderRaised"; id: string; requester: string }
  | { type: "WorkOrderStarted"; technician: string }
  | { type: "WorkOrderCompleted" };

export class WorkOrderError extends Error {}

export const initialState: WorkOrderState = { status: "none" };

export function evolve(s: WorkOrderState, e: WorkOrderEvent): WorkOrderState {
  switch (e.type) {
    case "WorkOrderRaised":
      return { status: "raised", id: e.id, requester: e.requester };
    case "WorkOrderStarted":
      if (s.status !== "raised") return s;
      return { status: "inProgress", id: s.id, technician: e.technician };
    case "WorkOrderCompleted":
      if (s.status !== "inProgress") return s;
      return { status: "completed", id: s.id };
    default: {
      const _n: never = e;
      return s;
    }
  }
}

export function decide(c: WorkOrderCommand, s: WorkOrderState): WorkOrderEvent[] {
  switch (c.type) {
    case "raise":
      if (s.status !== "none") throw new WorkOrderError("EXISTS");
      return [{ type: "WorkOrderRaised", id: c.id, requester: c.requester }];
    case "start":
      if (s.status !== "raised") throw new WorkOrderError("NOT_RAISED");
      return [{ type: "WorkOrderStarted", technician: c.technician }];
    case "complete":
      if (s.status !== "inProgress") throw new WorkOrderError("NOT_IN_PROGRESS");
      return [{ type: "WorkOrderCompleted" }];
    default: {
      const _n: never = c;
      throw new WorkOrderError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: WorkOrderEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: readonly WorkOrderEvent[],
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handleWorkOrder = (
  eventStore: EventStore,
  streamName: string,
  command: WorkOrderCommand,
) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => eventStore.readStream(streamName));
    const state = events.reduce(evolve, initialState);
    const produced = decide(command, state);
    if (produced.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() => eventStore.appendToStream(streamName, produced, { expectedRevision }));
  });
```

`invoke` starts an actor bound to a state's lifetime — it stops when the state exits. `spawn` creates a long-lived actor stored in context; you can spawn many (e.g. one per file) and reference them via `ActorRefFrom`. Here each START event spawns a child download actor and stores its ref; spawned actors survive across state transitions.

