export type RenewalEvent =
  | { type: "RenewalRequested"; id: string }
  | { type: "RenewalConfirmed"; id: string };

export type RenewalsView = { pending: number; confirmed: number };

const emptyView: RenewalsView = { pending: 0, confirmed: 0 };

function project(view: RenewalsView, e: RenewalEvent): RenewalsView {
  switch (e.type) {
    case "RenewalRequested": return { ...view, pending: view.pending + 1 };
    case "RenewalConfirmed": return { pending: Math.max(0, view.pending - 1), confirmed: view.confirmed + 1 };
    default: { const _n: never = e; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFromStream(stream: string, from: bigint): AsyncIterable<{ event: E; position: bigint }>;
}

export interface ViewStore {
  load(): Promise<RenewalsView | null>;
  save(view: RenewalsView): Promise<void>;
}

export async function runSubscription(
  stream: string,
  src: EventSource<RenewalEvent>,
  ckpt: CheckpointStore,
  views: ViewStore,
): Promise<void> {
  const last = (await ckpt.read(stream)) ?? 0n;
  let view = (await views.load()) ?? emptyView;
  for await (const { event, position } of src.readFromStream(stream, last)) {
    view = project(view, event);
    await views.save(view);
    await ckpt.write(stream, position);
  }
}
