export class ConcurrencyConflict extends Error {}

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(
    stream: string,
    events: E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextRevision: bigint }>;
