import { Effect } from "effect";

export type GeoFenceEvent =
  | { type: "GeoFenceDefined"; id: string; radiusM: number }
  | { type: "GeoFenceActivated" };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: GeoFenceEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: GeoFenceEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

const isConflict = (err: unknown): boolean =>
  err instanceof Error && /WrongExpectedVersion|Concurrency/i.test(err.message);

export const appendGuardedEffect = (
  store: EventStore,
  stream: string,
  events: GeoFenceEvent[],
) =>
  Effect.gen(function* () {
    const current = yield* Effect.promise(() => store.readStream(stream));
    const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision }),
      catch: (err) => (isConflict(err) ? new ConcurrencyConflict(stream) : err),
    });
    return result.nextRevision;
  });
