export interface EventStore {
  readStream(stream: string): Promise<{ revision: bigint | null }>;
  appendToStream(stream: string, events: ReferendumEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ revision: bigint; conflict?: { actual: bigint } }>;
}

export async function append(store: EventStore, stream: string, events: ReferendumEvent[]): Promise<bigint> {
  const read = await store.readStream(stream);
  const expected: ExpectedRevision = read.revision ?? "no_stream";
  const result = await store.appendToStream(stream, events, { expectedRevision: expected });
  if (result.conflict) {
    throw new ConcurrencyConflict(stream, expected, result.conflict.actual);
  }
  return result.revision;
}
