export type DisbursementState =
  | { status: "none" }
  | { status: "scheduled"; id: string; recipient: string; amount: number }
  | { status: "executed"; id: string; recipient: string; amount: number; at: string };

export type DisbursementCommand =
  | { type: "schedule"; id: string; recipient: string; amount: number }
  | { type: "execute"; at: string };

export type DisbursementEvent =
  | { type: "DisbursementScheduled"; id: string; recipient: string; amount: number }
  | { type: "DisbursementExecuted"; at: string };

export class DomainError extends Error {}

export const initialState: DisbursementState = { status: "none" };

export function evolve(s: DisbursementState, e: DisbursementEvent): DisbursementState {
  switch (e.type) {
    case "DisbursementScheduled":
      return { status: "scheduled", id: e.id, recipient: e.recipient, amount: e.amount };
    case "DisbursementExecuted":
      if (s.status !== "scheduled") return s;
      return { status: "executed", id: s.id, recipient: s.recipient, amount: s.amount, at: e.at };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: DisbursementCommand, s: DisbursementState): DisbursementEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "DisbursementScheduled", id: c.id, recipient: c.recipient, amount: c.amount }];
    case "execute":
      if (s.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
      return [{ type: "DisbursementExecuted", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: DisbursementEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: ReadonlyArray<DisbursementEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export interface CommandHandler<C> {
  handle(streamName: string, command: C): Promise<void>;
}

export function makeDisbursementHandler(store: EventStore): CommandHandler<DisbursementCommand> {
  return {
    async handle(streamName, command) {
      const { events, revision } = await store.readStream(streamName);
      const state = events.reduce(evolve, initialState);
      const produced = decide(command, state);
      if (produced.length === 0) return;
      const expectedRevision: ExpectedRevision = revision ?? "no_stream";
      await store.appendToStream(streamName, produced, { expectedRevision });
    },
  };
}
