import { Effect } from "effect";

export type HoldoutGroupState =
  | { status: "none" }
  | { status: "open"; id: string; size: number };

export type HoldoutGroupCommand =
  | { type: "register"; id: string; size: number }
  | { type: "close"; at: string };

export type HoldoutGroupEvent =
  | { type: "HoldoutGroupRegistered"; id: string; size: number }
  | { type: "HoldoutGroupClosed"; at: string };

export interface AppendOptions { expectedRevision: bigint | "no_stream" | "any"; }
export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], options: AppendOptions): Promise<{ nextRevision: bigint }>;
}

export const initialState: HoldoutGroupState = { status: "none" };

export function evolve(state: HoldoutGroupState, event: HoldoutGroupEvent): HoldoutGroupState {
  switch (event.type) {
    case "HoldoutGroupRegistered":
      return { status: "open", id: event.id, size: event.size };
    case "HoldoutGroupClosed":
      return { status: "none" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(cmd: HoldoutGroupCommand, state: HoldoutGroupState): HoldoutGroupEvent[] {
  switch (cmd.type) {
    case "register":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "HoldoutGroupRegistered", id: cmd.id, size: cmd.size }];
    case "close":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "HoldoutGroupClosed", at: cmd.at }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN");
    }
  }
}

export class StoreError { readonly _tag = "StoreError"; constructor(readonly cause: unknown) {} }

export function handle(
  command: HoldoutGroupCommand,
  deps: { streamName: string; eventStore: EventStore },
): Effect.Effect<void, StoreError> {
  return Effect.gen(function* () {
    const records = yield* Effect.tryPromise({
      try: () => deps.eventStore.readStream<HoldoutGroupEvent>(deps.streamName),
      catch: (cause) => new StoreError(cause),
    });
    const state = records.reduce<HoldoutGroupState>((s, r) => evolve(s, r.event), initialState);
    const expected: AppendOptions["expectedRevision"] =
      records.length === 0 ? "no_stream" : records[records.length - 1].revision;
    const events = decide(command, state);
    yield* Effect.tryPromise({
      try: () => deps.eventStore.appendToStream<HoldoutGroupEvent>(deps.streamName, events, { expectedRevision: expected }),
      catch: (cause) => new StoreError(cause),
    });
  });
}
