```typescript
export type CourierEventV1 =
  | { type: "CourierOnboarded"; version: 1; id: string; fullName: string }
  | { type: "CourierWentOnline"; version: 1 };

export type CourierEvent =
  | { type: "CourierOnboarded"; version: 2; id: string; firstName: string; lastName: string }
  | { type: "CourierWentOnline"; version: 1 };

export class UnknownEventError extends Error {
  constructor(public readonly raw: unknown) {
    super("unknown-event");
    this.name = "UnknownEventError";
  }
}

interface RawEvent {
  type: string;
  version: number;
  [key: string]: unknown;
}

function splitName(full: string): { firstName: string; lastName: string } {
  const [first, ...rest] = full.trim().split(/\s+/);
  return { firstName: first ?? "", lastName: rest.join(" ") };
}

export function upcast(raw: unknown): CourierEvent {
  if (!raw || typeof raw !== "object") throw new UnknownEventError(raw);
  const candidate = raw as RawEvent;
  switch (candidate.type) {
    case "CourierOnboarded": {
      if (candidate.version === 1) {
        const { firstName, lastName } = splitName(String(candidate.fullName ?? ""));
        return { type: "CourierOnboarded", version: 2, id: String(candidate.id), firstName, lastName };
      }
      if (candidate.version === 2) {
        return {
          type: "CourierOnboarded",
          version: 2,
          id: String(candidate.id),
          firstName: String(candidate.firstName ?? ""),
          lastName: String(candidate.lastName ?? ""),
        };
      }
      throw new UnknownEventError(raw);
    }
    case "CourierWentOnline":
      return { type: "CourierWentOnline", version: 1 };
    default:
      throw new UnknownEventError(raw);
  }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<unknown>;
}

export async function replay(store: EventStore, streamName: string): Promise<readonly CourierEvent[]> {
  const events: CourierEvent[] = [];
  for await (const raw of store.readStream(streamName)) {
    events.push(upcast(raw));
  }
  return events;
}
