export type RunEvent = { type: "RunScheduled"; id: string; at: string };
export type RunState = { status: "none" } | { status: "scheduled"; id: string };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const runDecider: Decider<RunCommand, RunEvent, RunState> = {
  initialState: { status: "none" },
  decide(c, s) {
    if (c.type === "schedule") {
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "RunScheduled", id: c.id, at: c.at }];
    }
    const _n: never = c.type;
    throw new Error("UNKNOWN");
  },
  evolve(s, e) {
    if (e.type === "RunScheduled") return { status: "scheduled", id: e.id };
    const _n: never = e.type;
    return s;
  },
};

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: RunEvent; revision: bigint }>;
  appendToStream(stream: string, events: RunEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handleCommand(cmd: RunCommand, ctx: { stream: string; store: EventStore }): Promise<void> {
  let state = runDecider.initialState;
  let revision: bigint | "no_stream" | "any" = "no_stream";
  for await (const { event, revision: r } of ctx.store.readStream(ctx.stream)) {
    state = runDecider.evolve(state, event);
    revision = r;
  }
  await ctx.store.appendToStream(ctx.stream, runDecider.decide(cmd, state), { expectedRevision: revision });
}

