  | { type: "quote"; id: string; premium: number }
  | { type: "activate"; at: string };

export type PolicyEvent =
  | { type: "PolicyQuoted"; id: string; premium: number }
  | { type: "PolicyActivated"; at: string };

export class PolicyError extends Error {}

const initialState: PolicyState = { status: "none" };

function decide(c: PolicyCommand, s: PolicyState): PolicyEvent[] {
  switch (c.type) {
    case "quote":
      if (s.status !== "none") throw new PolicyError("EXISTS");
      return [{ type: "PolicyQuoted", id: c.id, premium: c.premium }];
    case "activate":
      if (s.status !== "draft") throw new PolicyError("NOT_DRAFT");
      return [{ type: "PolicyActivated", at: c.at }];
    default: { const _n: never = c; throw new PolicyError("UNKNOWN"); }
  }
}

function evolve(s: PolicyState, e: PolicyEvent): PolicyState {
  switch (e.type) {
    case "PolicyQuoted":
      return { status: "draft", id: e.id, premium: e.premium };
    case "PolicyActivated":
      return s.status === "draft" ? { status: "active", id: s.id, premium: s.premium } : s;
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    stream: string,
    events: readonly E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

