  command: PolicyCommand,
  ctx: { streamName: string; eventStore: EventStore<PolicyEvent> },
): Promise<void> {
  let state = initialState;
  let revision: bigint | "no_stream" = "no_stream";
  for await (const rec of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, rec.event);
    revision = rec.revision;
  }
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: revision });
}
