export type ExpeditionState =
  | { status: "none" }
  | { status: "planned"; id: string; peak: string; members: number }
  | { status: "launched"; id: string; peak: string; members: number; launchedAt: string }
  | { status: "concluded"; id: string; concludedAt: string };

export type ExpeditionCommand =
  | { type: "plan"; id: string; peak: string }
  | { type: "enrollMember" }
  | { type: "launch"; at: string }
  | { type: "conclude"; at: string };

export type ExpeditionEvent =
  | { type: "ExpeditionPlanned"; id: string; peak: string }
  | { type: "MemberEnrolled" }
  | { type: "ExpeditionLaunched"; at: string }
  | { type: "ExpeditionConcluded"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const expeditionDecider: Decider<ExpeditionCommand, ExpeditionEvent, ExpeditionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ExpeditionPlanned", id: command.id, peak: command.peak }];
      case "enrollMember":
        if (state.status !== "planned") throw new DomainError("NOT_PLANNED");
        return [{ type: "MemberEnrolled" }];
      case "launch":
        if (state.status !== "planned") throw new DomainError("NOT_PLANNED");
        if (state.members === 0) throw new DomainError("NO_MEMBERS");
        return [{ type: "ExpeditionLaunched", at: command.at }];
      case "conclude":
        if (state.status !== "launched") throw new DomainError("NOT_LAUNCHED");
        return [{ type: "ExpeditionConcluded", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ExpeditionPlanned":
        return { status: "planned", id: event.id, peak: event.peak, members: 0 };
      case "MemberEnrolled":
        if (state.status !== "planned") return state;
        return { ...state, members: state.members + 1 };
      case "ExpeditionLaunched":
        if (state.status !== "planned") return state;
        return { status: "launched", id: state.id, peak: state.peak, members: state.members, launchedAt: event.at };
      case "ExpeditionConcluded":
        if (state.status !== "launched") return state;
        return { status: "concluded", id: state.id, concludedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
