function v2Tov3(raw: V2State): SettlementCurrentState {
  return { ...raw, currency: "USD" };
}

export class SnapshotError extends Error {}

function isV1(raw: unknown): raw is V1State {
  return typeof raw === "object" && raw !== null && "closed" in raw;
}

function isV2(raw: unknown): raw is V2State {
  return typeof raw === "object" && raw !== null && "entries" in raw && !("currency" in raw);
}

function isCurrent(raw: unknown): raw is SettlementCurrentState {
  return typeof raw === "object" && raw !== null && "currency" in raw;
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<SettlementCurrentState> {
  let version: number = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    if (!isV1(state)) throw new SnapshotError("NOT_V1");
    state = v1Tov2(state);
    version = 2;
  }
  if (version === 2) {
    if (!isV2(state)) throw new SnapshotError("NOT_V2");
    state = v2Tov3(state);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new SnapshotError("UNKNOWN_VERSION");
  if (!isCurrent(state)) throw new SnapshotError("TYPE_MISMATCH");
  return { version: CURRENT_VERSION, state };
}
