```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
import { Effect } from "effect";

export type AdSlotState =
  | { status: "closed" }
  | { status: "open"; slotId: string; floorCents: number }
  | { status: "filled"; slotId: string; advertiserId: string };

export type AdSlotCommand =
  | { type: "open"; slotId: string; floorCents: number }
  | { type: "fill"; advertiserId: string; bidCents: number }
  | { type: "close" };

export type AdSlotEvent =
  | { type: "AdSlotOpened"; slotId: string; floorCents: number }
  | { type: "AdSlotFilled"; advertiserId: string; bidCents: number }
  | { type: "AdSlotClosed" };

export const initialAdSlot: AdSlotState = { status: "closed" };

export function decide(command: AdSlotCommand, state: AdSlotState): AdSlotEvent[] {
  switch (command.type) {
    case "open":
      if (state.status !== "closed") throw new Error("ALREADY_OPEN");
      return [{ type: "AdSlotOpened", slotId: command.slotId, floorCents: command.floorCents }];
    case "fill":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      if (command.bidCents < state.floorCents) throw new Error("BELOW_FLOOR");
      return [{ type: "AdSlotFilled", advertiserId: command.advertiserId, bidCents: command.bidCents }];
    case "close":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "AdSlotClosed" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export function evolve(state: AdSlotState, event: AdSlotEvent): AdSlotState {
  switch (event.type) {
    case "AdSlotOpened":
      return { status: "open", slotId: event.slotId, floorCents: event.floorCents };
    case "AdSlotFilled":
      if (state.status !== "open") return state;
      return { status: "filled", slotId: state.slotId, advertiserId: event.advertiserId };
    case "AdSlotClosed":
      return { status: "closed" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: AdSlotEvent }>>;
  appendToStream(stream: string, events: readonly AdSlotEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export function handle(store: EventStore, stream: string, command: AdSlotCommand) {
  return Effect.gen(function* () {
    const stored = yield* Effect.promise(() => store.readStream(stream));
    const state = stored.reduce<AdSlotState>((s, { event }) => evolve(s, event), initialAdSlot);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const events = decide(command, state);
    yield* Effect.promise(() => store.appendToStream(stream, events, { expectedRevision: expected }));
  });
}
```

Oskar-style: a pure `when(currentState, event)` that accumulates into `Partial<Aggregate>`, then `aggregateStream` reduces the events and validates the final shape.

```typescript
export type CashRegisterEvent =
  | { type: "RegisterPlaced"; data: { id: string; workstation: string } }
  | { type: "ShiftOpened"; data: { cashierId: string; declared: number } }
  | { type: "DrawerAdjusted"; data: { delta: number } }
  | { type: "ShiftClosed"; data: { declared: number } };

export type CashRegister = Readonly<{
  id: string;
  workstation: string;
  float: number;
  currentCashierId: string | null;
}>;

export function when(
  current: Partial<CashRegister>,
  event: CashRegisterEvent,
): Partial<CashRegister> {
  switch (event.type) {
    case "RegisterPlaced":
      return {
        id: event.data.id,
        workstation: event.data.workstation,
        float: 0,
        currentCashierId: null,
      };
    case "ShiftOpened":
      return {
        ...current,
        currentCashierId: event.data.cashierId,
        float: (current.float ?? 0) + event.data.declared,
      };
    case "DrawerAdjusted":
      return { ...current, float: (current.float ?? 0) + event.data.delta };
    case "ShiftClosed":
      return { ...current, currentCashierId: null };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
): Partial<A> {
  return events.reduce<Partial<A>>(reducer, {});
}

export function registerFrom(events: CashRegisterEvent[]): Partial<CashRegister> {
  return aggregateStream(events, when);
}
