```typescript
export type FarmEvent =
  | { type: "FarmRegistered"; id: string; owner: string }
  | { type: "FarmCropStarted" }
  | { type: "FarmCropEnded" }
  | { type: "FarmDecommissioned"; at: string };

export interface FarmSummary {
  readonly id: string;
  readonly owner: string;
  readonly activeCrops: number;
  readonly decommissioned: boolean;
}

const empty: FarmSummary = { id: "", owner: "", activeCrops: 0, decommissioned: false };

export function project(view: FarmSummary, event: FarmEvent): FarmSummary {
  switch (event.type) {
    case "FarmRegistered":
      return { id: event.id, owner: event.owner, activeCrops: 0, decommissioned: false };
    case "FarmCropStarted":
      return { ...view, activeCrops: view.activeCrops + 1 };
    case "FarmCropEnded":
      return { ...view, activeCrops: Math.max(0, view.activeCrops - 1) };
    case "FarmDecommissioned":
      return { ...view, decommissioned: true };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface Batch<E> {
  readonly events: ReadonlyArray<E>;
  readonly nextRevision: bigint;
}

export interface EventSource<E> {
  readBatch(from: bigint, size: number): Promise<Batch<E>>;
}

export interface ReadStore<V> {
  persist(view: V): Promise<void>;
}

export interface RebuildOptions {
  readonly from: bigint;
  readonly batchSize: number;
}

export async function rebuild(
  source: EventSource<FarmEvent>,
  store: ReadStore<FarmSummary>,
  opts: RebuildOptions
): Promise<void> {
  let cursor = opts.from;
  let view: FarmSummary = empty;
  for (;;) {
    const batch = await source.readBatch(cursor, opts.batchSize);
    if (batch.events.length === 0) break;
    for (const event of batch.events) {
      view = project(view, event);
    }
    await store.persist(view);
    cursor = batch.nextRevision;
  }
}
