```typescript
export type CraftCommissionState =
  | { status: "none" }
  | { status: "quoted"; id: string; price: number }
  | { status: "accepted"; id: string; price: number };

export type CraftCommissionCommand =
  | { type: "quote"; id: string; price: number }
  | { type: "accept" };

export type CraftCommissionEvent =
  | { type: "CommissionQuoted"; id: string; price: number }
  | { type: "CommissionAccepted" };

const initialState: CraftCommissionState = { status: "none" };

function decide(
  c: CraftCommissionCommand,
  s: CraftCommissionState,
): CraftCommissionEvent[] {
  if (c.type === "quote") {
    if (s.status !== "none") throw new Error("already quoted");
    return [{ type: "CommissionQuoted", id: c.id, price: c.price }];
  }
  if (s.status !== "quoted") throw new Error("no quote");
  return [{ type: "CommissionAccepted" }];
}

function evolve(
  s: CraftCommissionState,
  e: CraftCommissionEvent,
): CraftCommissionState {
  if (e.type === "CommissionQuoted") {
    return { status: "quoted", id: e.id, price: e.price };
  }
  return s.status === "quoted"
    ? { status: "accepted", id: s.id, price: s.price }
    : s;
}

export interface EventStore {
  readStream(stream: string): Promise<{
    events: CraftCommissionEvent[];
    lastRevision: bigint | "no_stream";
  }>;
  appendToStream(
    stream: string,
    events: CraftCommissionEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export async function handle(
  command: CraftCommissionCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream(ctx.streamName);
  const state = read.events.reduce(evolve, initialState);
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, {
    expectedRevision: read.lastRevision,
  });
}
