export type RollEvent =
  | { type: "VoterRegistered"; voterId: string; party: string }
  | { type: "VoterRemoved"; voterId: string; party: string };

export type RollView = {
  voters: number;
  partyTotals: Record<string, number>;
};

export const emptyView: RollView = { voters: 0, partyTotals: {} };

export function project(view: RollView, event: RollEvent): RollView {
  switch (event.type) {
    case "VoterRegistered": {
      const prior = view.partyTotals[event.party] ?? 0;
      return {
        voters: view.voters + 1,
        partyTotals: { ...view.partyTotals, [event.party]: prior + 1 },
      };
    }
    case "VoterRemoved": {
      const prior = view.partyTotals[event.party] ?? 0;
      return {
        voters: Math.max(0, view.voters - 1),
        partyTotals: { ...view.partyTotals, [event.party]: Math.max(0, prior - 1) },
      };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function projectAll(events: RollEvent[]): RollView {
  return events.reduce(project, emptyView);
}
