export type ExhibitionState =
  | { status: "none" }
  | { status: "curated"; id: string; theme: string; pieces: number }
  | { status: "scheduled"; id: string; theme: string; startsAt: string }
  | { status: "running"; id: string; theme: string }
  | { status: "ended"; id: string; endedAt: string };

export type ExhibitionCommand =
  | { type: "curate"; id: string; theme: string; pieces: number }
  | { type: "schedule"; startsAt: string }
  | { type: "start" }
  | { type: "end"; endedAt: string };

export type ExhibitionEvent =
  | { type: "ExhibitionCurated"; id: string; theme: string; pieces: number }
  | { type: "ExhibitionScheduled"; startsAt: string }
  | { type: "ExhibitionStarted" }
  | { type: "ExhibitionEnded"; endedAt: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const exhibitionDecider: Decider<ExhibitionCommand, ExhibitionEvent, ExhibitionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "curate":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.pieces <= 0) throw new DomainError("EMPTY");
        return [{ type: "ExhibitionCurated", id: command.id, theme: command.theme, pieces: command.pieces }];
      case "schedule":
        if (state.status !== "curated") throw new DomainError("NOT_CURATED");
        return [{ type: "ExhibitionScheduled", startsAt: command.startsAt }];
      case "start":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "ExhibitionStarted" }];
      case "end":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "ExhibitionEnded", endedAt: command.endedAt }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ExhibitionCurated":
        return { status: "curated", id: event.id, theme: event.theme, pieces: event.pieces };
      case "ExhibitionScheduled":
        if (state.status !== "curated") return state;
        return { status: "scheduled", id: state.id, theme: state.theme, startsAt: event.startsAt };
      case "ExhibitionStarted":
        if (state.status !== "scheduled") return state;
        return { status: "running", id: state.id, theme: state.theme };
      case "ExhibitionEnded":
        if (state.status !== "running") return state;
        return { status: "ended", id: state.id, endedAt: event.endedAt };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

