export type FieldAgentEvent =
  | { type: "recruited"; id: string; region: string }
  | { type: "activated"; since: string }
  | { type: "retired"; at: string };

export interface FieldAgentState {
  id: string | null;
  region: string | null;
  active: boolean;
  retiredAt: string | null;
}

export const initialFieldAgent: FieldAgentState = {
  id: null,
  region: null,
  active: false,
  retiredAt: null,
};

type Handlers<S, E extends { type: string }> = {
  [K in E["type"]]: (state: S, event: Extract<E, { type: K }>) => S;
};

export function when<S, E extends { type: string }>(h: Handlers<S, E>): (s: S, e: E) => S {
  return (s, e) => (h[e.type as E["type"]] as (s: S, e: E) => S)(s, e);
}

export const evolveFieldAgent = when<FieldAgentState, FieldAgentEvent>({
  recruited: (s, e) => ({ ...s, id: e.id, region: e.region }),
  activated: (s) => ({ ...s, active: true }),
  retired: (s, e) => ({ ...s, active: false, retiredAt: e.at }),
});

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export async function loadFieldAgent(stream: AsyncIterable<FieldAgentEvent>): Promise<FieldAgentState> {
  return aggregateStream(stream, evolveFieldAgent, initialFieldAgent);
}
