export type ExperimentState =
  | { status: "none" }
  | { status: "designed"; id: string; hypothesis: string }
  | { status: "running"; id: string; hypothesis: string; launchedAt: string }
  | { status: "concluded"; id: string; verdict: "win" | "loss" | "inconclusive" };

export type ExperimentCommand =
  | { type: "design"; id: string; hypothesis: string }
  | { type: "launch"; at: string }
  | { type: "conclude"; verdict: "win" | "loss" | "inconclusive" };

export type ExperimentEvent =
  | { type: "ExperimentDesigned"; id: string; hypothesis: string }
  | { type: "ExperimentLaunched"; at: string }
  | { type: "ExperimentConcluded"; verdict: "win" | "loss" | "inconclusive" };

export class ExperimentError extends Error {
  constructor(code: string) { super(code); this.name = "ExperimentError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const experimentDecider: Decider<ExperimentCommand, ExperimentEvent, ExperimentState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "design":
        if (state.status !== "none") throw new ExperimentError("ALREADY_DESIGNED");
        if (command.hypothesis.length === 0) throw new ExperimentError("EMPTY_HYPOTHESIS");
        return [{ type: "ExperimentDesigned", id: command.id, hypothesis: command.hypothesis }];
      case "launch":
        if (state.status === "concluded") throw new ExperimentError("ALREADY_CONCLUDED");
        if (state.status !== "designed") throw new ExperimentError("NOT_DESIGNED");
        return [{ type: "ExperimentLaunched", at: command.at }];
      case "conclude":
        if (state.status !== "running") throw new ExperimentError("NOT_RUNNING");
        return [{ type: "ExperimentConcluded", verdict: command.verdict }];
      default: {
        const _never: never = command;
        throw new ExperimentError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ExperimentDesigned":
        return { status: "designed", id: event.id, hypothesis: event.hypothesis };
      case "ExperimentLaunched":
        if (state.status !== "designed") return state;
        return { status: "running", id: state.id, hypothesis: state.hypothesis, launchedAt: event.at };
      case "ExperimentConcluded":
        if (state.status !== "running") return state;
        return { status: "concluded", id: state.id, verdict: event.verdict };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
