export type SeafoodBatchEvent =
  | { type: "SeafoodBatchCreated"; id: string; weightKg: number }
  | { type: "SeafoodBatchShipped"; id: string; to: string };

type SeafoodBatchCommand =
  | { type: "create"; id: string; weightKg: number }
  | { type: "ship"; to: string };

type SeafoodBatchState =
  | { status: "none" }
  | { status: "ready"; id: string; weightKg: number }
  | { status: "shipped"; id: string; to: string };

const initial: SeafoodBatchState = { status: "none" };

function evolve(state: SeafoodBatchState, event: SeafoodBatchEvent): SeafoodBatchState {
  switch (event.type) {
    case "SeafoodBatchCreated":
      return { status: "ready", id: event.id, weightKg: event.weightKg };
    case "SeafoodBatchShipped":
      return state.status === "ready" ? { status: "shipped", id: state.id, to: event.to } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: SeafoodBatchCommand, state: SeafoodBatchState): SeafoodBatchEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "SeafoodBatchCreated", id: command.id, weightKg: command.weightKg }];
    case "ship":
      if (state.status !== "ready") throw new Error("NOT_READY");
      return [{ type: "SeafoodBatchShipped", id: state.id, to: command.to }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export interface BatchReadView {
  readonly id: string;
  readonly status: string;
  readonly destination?: string;
}

export interface BatchReadStore {
  get(id: string): Promise<BatchReadView | null>;
}

// Read model is eventually consistent with the event store.
export async function handleCommand(
  command: SeafoodBatchCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const current = await ctx.eventStore.readStream<SeafoodBatchEvent>(ctx.streamName);
  const state = current.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream<SeafoodBatchEvent>(ctx.streamName, events, { expectedRevision: current.revision });
}

export async function queryView(id: string, store: BatchReadStore): Promise<BatchReadView | null> {
  return store.get(id);
}
