```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface LeaseV1 { id: string; rent: number }
export interface LeaseV2 { id: string; rent: number; unitId: string }
export interface LeaseV3 { id: string; rent: number; unitId: string; status: "draft" | "active" | "terminated" }

export type CurrentLease = LeaseV3;
export const CURRENT_VERSION = 3 as const;

function v1Tov2(raw: LeaseV1): LeaseV2 {
  return { id: raw.id, rent: raw.rent, unitId: "unknown" };
}
function v2Tov3(raw: LeaseV2): LeaseV3 {
  return { ...raw, status: "draft" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentLease> {
  let current: unknown = snap.state;
  let version = snap.version;
  if (version === 1) {
    current = v1Tov2(current as LeaseV1);
    version = 2;
  }
  if (version === 2) {
    current = v2Tov3(current as LeaseV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`UNSUPPORTED_SNAPSHOT_VERSION:${snap.version}`);
  }
  return { version: CURRENT_VERSION, state: current as CurrentLease };
}
