export type FeatureFlagState =
  | { status: "missing" }
  | { status: "disabled"; id: string; key: string }
  | { status: "enabled"; id: string; key: string; enabledAt: string }
  | { status: "archived"; id: string };

export type FeatureFlagCommand =
  | { type: "create"; id: string; key: string }
  | { type: "enable"; at: string }
  | { type: "disable" }
  | { type: "archive" };

export type FeatureFlagEvent =
  | { type: "FeatureFlagCreated"; id: string; key: string }
  | { type: "FeatureFlagEnabled"; at: string }
  | { type: "FeatureFlagDisabled" }
  | { type: "FeatureFlagArchived" };

export class FeatureFlagError extends Error {
  constructor(code: string) { super(code); this.name = "FeatureFlagError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const featureFlagDecider: Decider<FeatureFlagCommand, FeatureFlagEvent, FeatureFlagState> = {
  initialState: { status: "missing" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "missing") throw new FeatureFlagError("EXISTS");
        return [{ type: "FeatureFlagCreated", id: command.id, key: command.key }];
      case "enable":
        if (state.status !== "disabled") throw new FeatureFlagError("CANNOT_ENABLE");
        return [{ type: "FeatureFlagEnabled", at: command.at }];
      case "disable":
        if (state.status !== "enabled") throw new FeatureFlagError("NOT_ENABLED");
        return [{ type: "FeatureFlagDisabled" }];
      case "archive":
        if (state.status === "enabled") throw new FeatureFlagError("STILL_ENABLED");
        if (state.status === "archived") throw new FeatureFlagError("ALREADY_ARCHIVED");
        return [{ type: "FeatureFlagArchived" }];
      default: {
        const _never: never = command;
        throw new FeatureFlagError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FeatureFlagCreated":
        return { status: "disabled", id: event.id, key: event.key };
      case "FeatureFlagEnabled":
        if (state.status !== "disabled") return state;
        return { status: "enabled", id: state.id, key: state.key, enabledAt: event.at };
      case "FeatureFlagDisabled":
        if (state.status !== "enabled") return state;
        return { status: "disabled", id: state.id, key: state.key };
      case "FeatureFlagArchived":
        if (state.status === "missing" || state.status === "archived") return state;
        return { status: "archived", id: state.id };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
