export class UnknownEventError extends Error {}

export type CurrentEvent =
  | { type: "GlazeTestRegistered"; version: 1; id: string }
  | {
      type: "GlazeTestScored";
      version: 2;
      rawScore: number;
      normalized: number;
    };

interface RawRegistered {
  type: "GlazeTestRegistered";
  version: 1;
  id: string;
}
interface RawScoredV1 {
  type: "GlazeTestScored";
  version: 1;
  score: number;
}
interface RawScoredV2 {
  type: "GlazeTestScored";
  version: 2;
  rawScore: number;
  normalized: number;
}

type Raw = RawRegistered | RawScoredV1 | RawScoredV2;

export function upcast(raw: unknown): CurrentEvent {
  const r = raw as Raw;
  switch (r.type) {
    case "GlazeTestRegistered":
      return r;
    case "GlazeTestScored":
      if (r.version === 1) {
        return {
          type: "GlazeTestScored",
          version: 2,
          rawScore: r.score,
          normalized: r.score / 100,
        };
      }
      return r;
    default:
      throw new UnknownEventError(JSON.stringify(raw));
  }
}

export interface EventStore {
  readStream(stream: string): Promise<unknown[]>;
}

export async function loadUpcasted(
  store: EventStore,
  stream: string,
): Promise<CurrentEvent[]> {
  const raw = await store.readStream(stream);
  return raw.map(upcast);
}
