export type TicketState =
  | { status: "none" }
  | { status: "open"; id: string; title: string; priority: "low" | "high" }
  | { status: "inProgress"; id: string; title: string; assignee: string }
  | { status: "closed"; id: string; title: string; closedAt: string };

export type TicketCommand =
  | { type: "openTicket"; id: string; title: string; priority: "low" | "high" }
  | { type: "assignTicket"; assignee: string }
  | { type: "closeTicket"; at: string };

export type TicketEvent =
  | { type: "TicketOpened"; id: string; title: string; priority: "low" | "high" }
  | { type: "TicketAssigned"; assignee: string }
  | { type: "TicketClosed"; at: string };

export class TicketError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "TicketError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const ticketDecider: Decider<TicketCommand, TicketEvent, TicketState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "openTicket":
        if (state.status !== "none") throw new TicketError("TICKET_EXISTS");
        if (command.title.length === 0) throw new TicketError("TITLE_EMPTY");
        return [{ type: "TicketOpened", id: command.id, title: command.title, priority: command.priority }];
      case "assignTicket":
        if (state.status !== "open") throw new TicketError("NOT_OPEN");
        return [{ type: "TicketAssigned", assignee: command.assignee }];
      case "closeTicket":
        if (state.status === "closed") throw new TicketError("ALREADY_CLOSED");
        if (state.status === "none") throw new TicketError("NOT_FOUND");
        return [{ type: "TicketClosed", at: command.at }];
      default: {
        const _n: never = command;
        throw new TicketError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TicketOpened":
        return { status: "open", id: event.id, title: event.title, priority: event.priority };
      case "TicketAssigned":
        if (state.status !== "open") return state;
        return { status: "inProgress", id: state.id, title: state.title, assignee: event.assignee };
      case "TicketClosed":
        if (state.status === "none" || state.status === "closed") return state;
        return { status: "closed", id: state.id, title: state.title, closedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
