import { Effect } from "effect";

export interface AppendResult {
  readonly nextExpectedRevision: bigint;
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: ReadonlyArray<E>; revision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict";
  constructor(public readonly stream: string) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export type ArtAuctionEvent =
  | { type: "ArtAuctionStarted"; lotId: string; reserve: number }
  | { type: "ArtAuctionBidPlaced"; bidder: string; amount: number };

function isConflict(err: unknown): boolean {
  return err instanceof Error && /revision|concurrency|conflict/i.test(err.message);
}

export function appendArtAuction(
  store: EventStore<ArtAuctionEvent>,
  stream: string,
  events: ReadonlyArray<ArtAuctionEvent>,
  expected: bigint | "no_stream" | "any"
): Effect.Effect<AppendResult, ConcurrencyConflict | Error> {
  return Effect.tryPromise({
    try: () => store.appendToStream(stream, events, { expectedRevision: expected }),
    catch: (err) => (isConflict(err) ? new ConcurrencyConflict(stream) : (err as Error)),
  });
}
