      origin: ({ event }) => (event.type === 'POINTER_DOWN' ? event.at : { x: 0, y: 0 }),
      current: ({ event }) => (event.type === 'POINTER_DOWN' ? event.at : { x: 0, y: 0 })
    }),
    updatePosition: assign({
      current: ({ event }) => (event.type === 'POINTER_MOVE' ? event.at : { x: 0, y: 0 })
    }),
    captureTarget: assign({
      dropTarget: ({ event }) => (event.type === 'POINTER_UP' ? event.target : null)
    }),
    clearTarget: assign({ dropTarget: () => null })
  },
  guards: {
    hasTarget: ({ context }) => context.dropTarget !== null
  }
}).createMachine({
  id: 'drag',
  context: {
    origin: { x: 0, y: 0 },
    current: { x: 0, y: 0 },
    dropTarget: null
  },
  initial: 'idle',
  states: {
    idle: {
      on: { POINTER_DOWN: { target: 'dragging', actions: 'startDrag' } }
    },
    dragging: {
      on: {
        POINTER_MOVE: { actions: 'updatePosition' },
        POINTER_UP: [
          {
            actions: 'captureTarget',
            guard: ({ event }) => event.target !== null,
            target: 'dropping'
          },
          { target: 'idle' }
        ]
      }
    },
    dropping: {
      after: { 200: { target: 'idle', actions: 'clearTarget' } }
    }
  }
