export type SupplyRestockEvent =
  | { type: "RestockScheduled"; id: string; item: string; qty: number }
  | { type: "RestockCompleted"; id: string };

export interface OutboxRow {
  id: string;
  payload: Record<string, unknown>;
  publishedAt: string | null;
}

export interface Transaction {
  insertOutbox(row: OutboxRow): Promise<void>;
  appendToStream(
    stream: string,
    events: SupplyRestockEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface Connection {
  begin(): Promise<Transaction>;
}

// A separate publisher worker polls outbox rows where publishedAt is null,
// delivers them to the bus, and marks them published. Not implemented here.
export async function appendWithOutbox(
  stream: string,
  events: SupplyRestockEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
  conn: Connection,
): Promise<void> {
  const tx = await conn.begin();
  try {
    for (const row of outboxRows) {
      await tx.insertOutbox(row);
    }
    await tx.appendToStream(stream, events, { expectedRevision });
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
