export type FeedingRegimeState =
  | { status: "none" }
  | { status: "defined"; id: string; kcalPerDay: number }
  | { status: "feeding"; id: string; kcalPerDay: number };

export type FeedingRegimeCommand =
  | { type: "define"; id: string; kcalPerDay: number }
  | { type: "startFeeding" };

export type FeedingRegimeEvent =
  | { type: "FeedingRegimeDefined"; id: string; kcalPerDay: number }
  | { type: "FeedingRegimeStarted" };

export const initialState: FeedingRegimeState = { status: "none" };

export function evolve(state: FeedingRegimeState, event: FeedingRegimeEvent): FeedingRegimeState {
  switch (event.type) {
    case "FeedingRegimeDefined":
      return { status: "defined", id: event.id, kcalPerDay: event.kcalPerDay };
    case "FeedingRegimeStarted":
      return state.status === "defined"
        ? { status: "feeding", id: state.id, kcalPerDay: state.kcalPerDay }
        : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: FeedingRegimeCommand, state: FeedingRegimeState): FeedingRegimeEvent[] {
  switch (command.type) {
    case "define":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "FeedingRegimeDefined", id: command.id, kcalPerDay: command.kcalPerDay }];
    case "startFeeding":
      if (state.status !== "defined") throw new Error("NOT_DEFINED");
      return [{ type: "FeedingRegimeStarted" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}
