The guard reads `context.dirty.size` from within `setup.guards`, so the `SAVE` transition only fires when at least one field has changed. Because the guard lives in setup, it is reused by name and keeps type inference strong.

```typescript
import { setup, assign } from 'xstate';

type Profile = { name: string; email: string };

export const profileGuardedMachine = setup({
  types: {
    context: {} as { draft: Profile; dirty: Set<keyof Profile> },
    events: {} as { type: 'CHANGE_NAME'; value: string } | { type: 'SAVE' },
  },
  guards: {
    hasChanges: ({ context }) => context.dirty.size > 0,
  },
}).createMachine({
  id: 'profileGuarded',
  initial: 'editing',
  context: { draft: { name: '', email: '' }, dirty: new Set<keyof Profile>() },
  states: {
    editing: {
      on: {
        CHANGE_NAME: {
          actions: assign({
            draft: ({ context, event }) => ({ ...context.draft, name: event.value }),
            dirty: ({ context }) => new Set(context.dirty).add('name'),
          }),
        },
        SAVE: { guard: 'hasChanges', target: 'saved' },
      },
    },
    saved: { type: 'final' },
  },
});
