A projection folds events into a denormalised view. Declare a View type, an emptyView literal, and a project reducer that switches on event.type and ignores unrelated events.

```typescript
export type WaypointEvent =
  | { type: "WaypointVisited"; waypointId: string; at: string }
  | { type: "WaypointSkipped"; waypointId: string }
  | { type: "WaypointDefined"; waypointId: string; label: string };

export interface WaypointStats {
  readonly totalVisits: number;
  readonly perWaypoint: Readonly<Record<string, { label: string; visits: number }>>;
}

export const emptyView: WaypointStats = { totalVisits: 0, perWaypoint: {} };

export function project(view: WaypointStats, event: WaypointEvent): WaypointStats {
  switch (event.type) {
    case "WaypointDefined": {
      if (view.perWaypoint[event.waypointId]) return view;
      return {
        ...view,
        perWaypoint: { ...view.perWaypoint, [event.waypointId]: { label: event.label, visits: 0 } },
      };
    }
    case "WaypointVisited": {
      const prior = view.perWaypoint[event.waypointId] ?? { label: event.waypointId, visits: 0 };
      return {
        totalVisits: view.totalVisits + 1,
        perWaypoint: { ...view.perWaypoint, [event.waypointId]: { ...prior, visits: prior.visits + 1 } },
      };
    }
    case "WaypointSkipped":
      return view;
    default: { const _n: never = event; return view; }
  }
}
