Tag the blob with a `version`, register upgraders keyed by source version, and run them in order.

```typescript
export type Snapshot<S> = { version: number; state: S };

interface PermitV1 { id: string; authority: string }
interface PermitV2 { id: string; authority: string; validUntil: string }
interface PermitV3 { id: string; authority: string; validUntil: string; amendments: number }

export type CurrentState = PermitV3;
export const CURRENT_VERSION = 3;

function v1Tov2(snap: Snapshot<PermitV1>): Snapshot<PermitV2> {
  return { version: 2, state: { ...snap.state, validUntil: '2099-12-31' } };
}
function v2Tov3(snap: Snapshot<PermitV2>): Snapshot<PermitV3> {
  return { version: 3, state: { ...snap.state, amendments: 0 } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let cur = snap as Snapshot<unknown>;
  if (cur.version === 1) cur = v1Tov2(cur as Snapshot<PermitV1>);
  if (cur.version === 2) cur = v2Tov3(cur as Snapshot<PermitV2>);
  if (cur.version !== CURRENT_VERSION) throw new Error('unsupported snapshot version');
  return cur as Snapshot<CurrentState>;
}
