export interface TranscriptView {
  readonly id: string;
  readonly locale: string;
  readonly segmentCount: number;
  readonly publishedAt: string | null;
}

export const emptyView: TranscriptView = { id: "", locale: "", segmentCount: 0, publishedAt: null };

export function project(view: TranscriptView, event: TranscriptEvent): TranscriptView {
  switch (event.type) {
    case "TranscriptStarted":
      return { ...emptyView, id: event.id, locale: event.locale };
    case "TranscriptSegmentAdded":
      return { ...view, segmentCount: view.segmentCount + 1 };
    case "TranscriptPublished":
      return { ...view, publishedAt: event.at };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface EventBatch<E> {
  readonly events: readonly E[];
  readonly nextRevision: bigint;
  readonly endOfStream: boolean;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  readBatch: (from: bigint, batchSize: number) => Promise<EventBatch<TranscriptEvent>>;
  persist: (view: TranscriptView, position: bigint) => Promise<void>;
}

export async function rebuild(opts: RebuildOptions): Promise<void> {
  let cursor = opts.from;
  let view = emptyView;
  for (;;) {
    const batch = await opts.readBatch(cursor, opts.batchSize);
    for (const event of batch.events) {
      view = project(view, event);
    }
    await opts.persist(view, batch.nextRevision);
    cursor = batch.nextRevision;
    if (batch.endOfStream) break;
  }
}
```

A receive pipeline stays in an `open` state and handles `MESSAGE.RECEIVED` events by appending the payload to a typed `messages` array. We declare the append as a named action so the transition body stays string-referenced.

```typescript
import { setup, assign } from 'xstate';

type Msg = { id: string; from: string; body: string; ts: number };
type Ctx = { messages: Msg[] };
type Ev =
  | { type: 'MESSAGE.RECEIVED'; message: Msg }
  | { type: 'CLEAR' };

export const inboxMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    appendMessage: assign({
      messages: ({ context, event }) => {
        if (event.type !== 'MESSAGE.RECEIVED') return context.messages;
        return context.messages.concat(event.message);
      }
    }),
    clear: assign({ messages: () => [] as Msg[] })
  }
}).createMachine({
  id: 'inbox',
  initial: 'open',
  context: { messages: [] },
  states: {
    open: {
      on: {
        'MESSAGE.RECEIVED': { actions: 'appendMessage' },
        CLEAR: { actions: 'clear' }
      }
    }
  }
});
