```typescript
import { Effect } from "effect";

export type IncidentState = { status: "none" } | { status: "open"; id: string };
export type IncidentCommand = { type: "open"; id: string };
export type IncidentEvent = { type: "IncidentOpened"; id: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict" as const;
}

const initial: IncidentState = { status: "none" };

function evolve(s: IncidentState, e: IncidentEvent): IncidentState {
  switch (e.type) {
    case "IncidentOpened": return { status: "open", id: e.id };
    default: { const _n: never = e.type; return s; }
  }
}

function decide(c: IncidentCommand, s: IncidentState): IncidentEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "IncidentOpened", id: c.id }];
    default: { const _n: never = c.type; throw new Error("UNKNOWN"); }
  }
}

export function handle(cmd: IncidentCommand, stream: string, store: EventStore) {
  return Effect.gen(function* () {
    const head = yield* Effect.promise(() => store.readStream<IncidentEvent>(stream));
    const state = head.events.reduce<IncidentState>(evolve, initial);
    const newEvents = decide(cmd, state);
    yield* Effect.tryPromise({
      try: () => store.appendToStream<IncidentEvent>(stream, newEvents, { expectedRevision: head.revision }),
      catch: () => new ConcurrencyConflict(),
    });
  });
}
