```typescript
export type OrderEvent =
  | { type: "OrderPlaced"; id: string; total: number }
  | { type: "OrderPaid"; id: string; at: string };

export type IntegrationEvent =
  | { schema: "order.placed.v1"; payload: { orderId: string; total: number } }
  | { schema: "order.paid.v1"; payload: { orderId: string; at: string } };

export interface OutboxRow {
  id: string;
  payload: IntegrationEvent;
  publishedAt: string | null;
}

export type ExpectedRevision = bigint | "no_stream";

export interface Transaction {
  appendToStream(stream: string, events: OrderEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<bigint>;
  insertOutbox(rows: ReadonlyArray<OutboxRow>): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface Connection {
  begin(): Promise<Transaction>;
}

function translate(event: OrderEvent): IntegrationEvent | null {
  switch (event.type) {
    case "OrderPlaced":
      return { schema: "order.placed.v1", payload: { orderId: event.id, total: event.total } };
    case "OrderPaid":
      return { schema: "order.paid.v1", payload: { orderId: event.id, at: event.at } };
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export async function appendWithOutbox(
  conn: Connection,
  stream: string,
  events: OrderEvent[],
  expectedRevision: ExpectedRevision,
  idFactory: () => string,
): Promise<bigint> {
  const tx = await conn.begin();
  try {
    const rows: OutboxRow[] = events
      .map((e) => translate(e))
      .filter((p): p is IntegrationEvent => p !== null)
      .map((payload) => ({ id: idFactory(), payload, publishedAt: null }));
    const nextRev = await tx.appendToStream(stream, events, { expectedRevision });
    if (rows.length > 0) await tx.insertOutbox(rows);
    await tx.commit();
    return nextRev;
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}

// A separate outbox publisher worker polls rows where publishedAt IS NULL,
// publishes them to the bus, and marks them published. Not implemented here.
