export function decide(
  command: FertiliserApplicationCommand,
  state: FertiliserApplicationState
): FertiliserApplicationEvent[] {
  switch (command.type) {
    case "apply":
      if (state.status !== "none") throw new InvariantError("ALREADY_APPLIED");
      if (command.kg <= 0) throw new InvariantError("NON_POSITIVE_KG");
      return [{ type: "FertiliserApplicationApplied", id: command.id, fieldId: command.fieldId, kg: command.kg }];
    case "cancel":
      if (state.status !== "applied") throw new InvariantError("NOT_APPLIED");
      return [{ type: "FertiliserApplicationCancelled", reason: command.reason }];
    default: {
      const _n: never = command;
      throw new InvariantError("UNKNOWN_COMMAND");
    }
  }
