```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export type KilnFiringState =
  | { status: "none" }
  | { status: "scheduled"; id: string; temp: number }
  | { status: "firing"; id: string; temp: number; startedAt: string }
  | { status: "complete"; id: string; endedAt: string };

export type KilnFiringCommand =
  | { type: "schedule"; id: string; temp: number }
  | { type: "ignite"; startedAt: string }
  | { type: "complete"; endedAt: string };

export type KilnFiringEvent =
  | { type: "FiringScheduled"; id: string; temp: number }
  | { type: "FiringIgnited"; startedAt: string }
  | { type: "FiringCompleted"; endedAt: string };

export class FiringError extends Error {}

const initialState: KilnFiringState = { status: "none" };

function decide(
  c: KilnFiringCommand,
  s: KilnFiringState,
): KilnFiringEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new FiringError("already scheduled");
      if (c.temp <= 0) throw new FiringError("invalid temp");
      return [{ type: "FiringScheduled", id: c.id, temp: c.temp }];
    case "ignite":
      if (s.status !== "scheduled") throw new FiringError("cannot ignite");
      return [{ type: "FiringIgnited", startedAt: c.startedAt }];
    case "complete":
      if (s.status !== "firing") throw new FiringError("not firing");
      return [{ type: "FiringCompleted", endedAt: c.endedAt }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

function evolve(
  s: KilnFiringState,
  e: KilnFiringEvent,
): KilnFiringState {
  switch (e.type) {
    case "FiringScheduled":
      return { status: "scheduled", id: e.id, temp: e.temp };
    case "FiringIgnited":
      return s.status === "scheduled"
        ? { status: "firing", id: s.id, temp: s.temp, startedAt: e.startedAt }
        : s;
    case "FiringCompleted":
      return s.status === "firing"
        ? { status: "complete", id: s.id, endedAt: e.endedAt }
        : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export const kilnFiringDecider: Decider<
  KilnFiringCommand,
  KilnFiringEvent,
  KilnFiringState
> = { initialState, decide, evolve };
```

