import { Effect } from 'effect';

type AssayEvent =
  | { type: 'AssayRegistered'; sampleId: string }
  | { type: 'GradeMeasured'; grade: number };

interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: AssayEvent; revision: bigint }>;
  appendToStream(
    stream: string,
    events: AssayEvent[],
    opts: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<void>;
}

export class ConcurrencyConflict extends Error {}

export function appendOre(store: EventStore, stream: string, events: AssayEvent[]) {
  return Effect.gen(function* () {
    const expected = yield* Effect.tryPromise({
      try: async () => {
        let rev: bigint | 'no_stream' = 'no_stream';
        for await (const { revision } of store.readStream(stream)) rev = revision;
        return rev;
      },
      catch: (e) => new Error(String(e)),
    });
    yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision: expected }),
      catch: (e) => new ConcurrencyConflict(String(e)),
    });
  });
}
