type SetlistV1 = { readonly id: string; readonly songs: readonly string[] };
type SetlistV2 = SetlistV1 & { readonly encore: readonly string[] };
type SetlistV3 = SetlistV2 & { readonly durationMin: number };

export type CurrentState = SetlistV3;
export const CURRENT_VERSION = 3 as const;

export type Snapshot<S> = { readonly version: number; readonly state: S };

function v1Tov2(prev: SetlistV1): SetlistV2 {
  return { ...prev, encore: [] };
}

function v2Tov3(prev: SetlistV2): SetlistV3 {
  return { ...prev, durationMin: prev.songs.length * 4 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as SetlistV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as SetlistV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unknown snapshot version ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
