export class DomainError extends Error {}

export type GrantAwardState =
  | { status: "none" }
  | { status: "proposed"; id: string; amount: number }
  | { status: "approved"; id: string; amount: number; approvedAt: string }
  | { status: "disbursed"; id: string; disbursedAt: string }
  | { status: "rejected"; id: string };

export type GrantAwardCommand =
  | { type: "propose"; id: string; amount: number }
  | { type: "approve"; at: string }
  | { type: "disburse"; at: string }
  | { type: "reject" };

export type GrantAwardEvent =
  | { type: "proposed"; id: string; amount: number }
  | { type: "approved"; at: string }
  | { type: "disbursed"; at: string }
  | { type: "rejected" };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const GrantAwardDecider: Decider<GrantAwardCommand, GrantAwardEvent, GrantAwardState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "propose":
        if (s.status !== "none") throw new DomainError("exists");
        if (c.amount <= 0) throw new DomainError("amount must be positive");
        return [{ type: "proposed", id: c.id, amount: c.amount }];
      case "approve":
        if (s.status !== "proposed") throw new DomainError("not proposed");
        return [{ type: "approved", at: c.at }];
      case "disburse":
        if (s.status !== "approved") throw new DomainError("not approved");
        return [{ type: "disbursed", at: c.at }];
      case "reject":
        if (s.status !== "proposed") throw new DomainError("can only reject proposals");
        return [{ type: "rejected" }];
      default: {
        const _: never = c;
        return _;
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "proposed":
        return { status: "proposed", id: e.id, amount: e.amount };
      case "approved":
        return s.status === "proposed" ? { status: "approved", id: s.id, amount: s.amount, approvedAt: e.at } : s;
      case "disbursed":
        return s.status === "approved" ? { status: "disbursed", id: s.id, disbursedAt: e.at } : s;
      case "rejected":
        return s.status === "proposed" ? { status: "rejected", id: s.id } : s;
      default: {
        const _: never = e;
        return _;
      }
    }
  },
};
