If the checkpoint is written before the projection has been applied, a crash between the two leaves the read model one event behind — on restart the subscription resumes past the unapplied event and the view is permanently wrong. Writing the checkpoint after a successful apply makes the at-least-once semantics safe: a crash replays the last event, and because projections are idempotent (or guarded by event position), the duplicate is absorbed. The rule is apply then record; never record then apply.

```typescript
export type AcclimatisationEvent =
  | { type: "AcclimatisationBegun"; climberId: string; startedAt: string }
  | { type: "RotationCompleted"; altitude: number; at: string }
  | { type: "AcclimatisationCleared"; clearedAt: string };

export interface EventEnvelope<E> {
  readonly event: E;
  readonly position: bigint;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface AcclimatisationView {
  readonly climberId: string;
  readonly rotations: number;
}

export const emptyView: AcclimatisationView = { climberId: "", rotations: 0 };

export function project(view: AcclimatisationView, event: AcclimatisationEvent): AcclimatisationView {
  switch (event.type) {
    case "AcclimatisationBegun":
      return { climberId: event.climberId, rotations: 0 };
    case "RotationCompleted":
      return { ...view, rotations: view.rotations + 1 };
    case "AcclimatisationCleared":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface AcclimatisationReadModel {
  load(): Promise<AcclimatisationView>;
  save(view: AcclimatisationView): Promise<void>;
}

export async function runSubscription(
  name: string,
  source: AsyncIterable<EventEnvelope<AcclimatisationEvent>>,
  checkpointStore: CheckpointStore,
  readModel: AcclimatisationReadModel,
): Promise<void> {
  const start = await checkpointStore.read(name);
  let view = await readModel.load();
  const consume = async (): Promise<void> => {
    for await (const envelope of source) {
      if (start !== null && envelope.position <= start) continue;
      view = project(view, envelope.event);
      await readModel.save(view);
      await checkpointStore.write(name, envelope.position);
    }
  };
  await consume();
}
