      return {
        byId: { ...view.byId, [event.signatoryId]: { ...existing, active: false, deactivatedAt: event.at } },
      };
    }
    case "SignatoryRoleChanged": {
      const existing = view.byId[event.signatoryId];
      if (!existing) return view;
      return { byId: { ...view.byId, [event.signatoryId]: { ...existing, role: event.role } } };
    }
    case "SignatoryNoted":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
