```typescript
export type StandingsEvent =
  | { type: "StandingsRecomputed"; season: string; rows: number }
  | { type: "StandingsReset"; season: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> {
  revision: bigint;
  event: E;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream<E>(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function saveStandings(
  store: EventStore,
  stream: string,
  newEvents: readonly StandingsEvent[],
): Promise<bigint> {
  const stored = await store.readStream<StandingsEvent>(stream);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  try {
    const { nextRevision } = await store.appendToStream<StandingsEvent>(stream, newEvents, { expectedRevision: expected });
    return nextRevision;
  } catch (err) {
    const rej = err as { kind?: string };
    if (rej.kind === "concurrency") throw new ConcurrencyConflict(stream);
    throw err;
  }
}
