import { Effect } from "effect";

export type PaymentState =
  | { status: "none" }
  | { status: "scheduled"; id: string; amount: number }
  | { status: "settled"; id: string; amount: number }
  | { status: "refunded"; id: string };

export type PaymentCommand =
  | { type: "schedule"; id: string; amount: number }
  | { type: "settle" }
  | { type: "refund" };

export type PaymentEvent =
  | { type: "PaymentScheduled"; id: string; amount: number }
  | { type: "PaymentSettled" }
  | { type: "PaymentRefunded" };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const paymentDecider: Decider<PaymentCommand, PaymentEvent, PaymentState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new Error("EXISTS");
        return [{ type: "PaymentScheduled", id: command.id, amount: command.amount }];
      case "settle":
        if (state.status !== "scheduled") throw new Error("NOT_SCHEDULED");
        return [{ type: "PaymentSettled" }];
      case "refund":
        if (state.status !== "settled") throw new Error("NOT_SETTLED");
        return [{ type: "PaymentRefunded" }];
      default: {
        const _never: never = command;
        return _never;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PaymentScheduled":
        return { status: "scheduled", id: event.id, amount: event.amount };
      case "PaymentSettled":
        if (state.status !== "scheduled") return state;
        return { status: "settled", id: state.id, amount: state.amount };
      case "PaymentRefunded":
        if (state.status !== "settled") return state;
        return { status: "refunded", id: state.id };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};

export const runAppend = (append: (events: PaymentEvent[]) => Promise<void>, events: PaymentEvent[]) =>
  Effect.gen(function* () {
    yield* Effect.promise(() => append(events));
  });
