export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

type ConversationEvent =
  | { type: 'ConversationStarted'; id: string; starterId: string }
  | { type: 'ParticipantAdded'; userId: string }
  | { type: 'ConversationClosed' };

type ConversationState =
  | { status: 'empty' }
  | { status: 'open'; id: string; participants: readonly string[] }
  | { status: 'closed'; id: string };

function evolve(state: ConversationState, event: ConversationEvent): ConversationState {
  switch (event.type) {
    case 'ConversationStarted':
      return { status: 'open', id: event.id, participants: [event.starterId] };
    case 'ParticipantAdded':
      return state.status === 'open'
        ? { ...state, participants: [...state.participants, event.userId] }
        : state;
    case 'ConversationClosed':
      return state.status === 'open' ? { status: 'closed', id: state.id } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function loadConversation(
  stream: AsyncIterable<ConversationEvent>,
): Promise<ConversationState> {
  return aggregateStream<ConversationState, ConversationEvent>(stream, evolve, { status: 'empty' });
}
