      return {
        schema: "loan.originated.v1",
        payload: { id: event.id, principal: event.principal },
      };
    case "LoanDisbursed":
      return { schema: "loan.disbursed.v1", payload: { id: event.id, at: event.at } };
    case "LoanClosed":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

