import { setup, assign, fromPromise } from 'xstate';

interface Change { id: string; body: string }
interface Ctx {
  queue: Change[];
  attempt: number;
  lastError: string | null;
}
type Ev =
  | { type: 'EDIT'; change: Change }
  | { type: 'SYNCED' }
  | { type: 'RETRY' };

export const cloudSyncMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    upload: fromPromise<void, { queue: Change[] }>(async ({ input }) => {
      if (input.queue.length === 0) return;
      // POST input.queue to server
    })
  },
  delays: {
    BACKOFF: ({ context }: { context: Ctx }) => Math.min(30_000, 1_000 * 2 ** context.attempt)
  },
  actions: {
    enqueue: assign({ queue: ({ context, event }) => (event.type === 'EDIT' ? [...context.queue, event.change] : context.queue) }),
    clearQueue: assign({ queue: () => [], attempt: () => 0, lastError: () => null }),
    recordError: assign({
      attempt: ({ context }) => context.attempt + 1,
      lastError: ({ event }) => ('error' in event ? String((event as { error: unknown }).error) : 'unknown')
    })
  }
}).createMachine({
  id: 'cloudSync',
  context: { queue: [], attempt: 0, lastError: null },
  initial: 'synced',
  states: {
    synced: { on: { EDIT: { target: 'queued', actions: 'enqueue' } } },
    queued: {
      on: { EDIT: { actions: 'enqueue' } },
      always: 'uploading'
    },
    uploading: {
      invoke: {
        src: 'upload',
        input: ({ context }) => ({ queue: context.queue }),
        onDone: { target: 'synced', actions: 'clearQueue' },
        onError: { target: 'error', actions: 'recordError' }
      }
    },
    error: {
      after: { BACKOFF: 'uploading' },
      on: { RETRY: 'uploading', EDIT: { target: 'queued', actions: 'enqueue' } }
    }
  }
});
```

In XState v5, `invoke.src` references an actor registered in `setup.actors`. The actor runs for the lifetime of the state; its `onDone` and `onError` fire as transitions with `event.output` and `event.error` typed. Below, `saveRecording` is a `fromPromise` actor whose input is built from context.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Ctx { blob: Blob | null; id: string | null; error: string | null; }
type Ev = { type: 'SAVE'; blob: Blob } | { type: 'RETRY' };

const saveRecording = fromPromise<string, { blob: Blob }>(async ({ input }) => {
  const res = await fetch('/videos', { method: 'POST', body: input.blob });
  if (!res.ok) throw new Error('save failed');
  return (await res.text());
});

export const videoSaveMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { saveRecording }
}).createMachine({
  id: 'videoSave',
  initial: 'idle',
  context: { blob: null, id: null, error: null },
  states: {
    idle: {
      on: {
        SAVE: {
          target: 'saving',
          actions: assign({ blob: ({ event }) => event.blob })
        }
      }
    },
    saving: {
      invoke: {
        src: 'saveRecording',
        input: ({ context }) => ({ blob: context.blob as Blob }),
        onDone: { target: 'done', actions: assign({ id: ({ event }) => event.output }) },
        onError: { target: 'failed', actions: assign({ error: ({ event }) => String(event.error) }) }
      }
    },
    failed: { on: { RETRY: 'saving' } },
    done: { type: 'final' }
  }
});
