import { setup, assign, fromCallback, emit } from 'xstate';

interface Point { x: number; y: number }

interface Ctx {
  from: number;
  over: number;
  pos: Point;
}

type Ev =
  | { type: 'START'; index: number }
  | { type: 'MOVE'; at: Point; over: number }
  | { type: 'END' };

type Emitted = { type: 'dropped'; from: number; to: number };

const noopPointer = fromCallback<Ev>(({ sendBack }) => {
  const id = setInterval(() => sendBack({ type: 'END' }), 1_000_000);
  return () => clearInterval(id);
});

export const sortableMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    emitted: {} as Emitted
  },
  actors: { noopPointer },
  actions: {
    pickUp: assign({
      from: ({ event }) => (event.type === 'START' ? event.index : -1),
      over: ({ event }) => (event.type === 'START' ? event.index : -1)
    }),
    track: assign({
      pos: ({ event }) => (event.type === 'MOVE' ? event.at : { x: 0, y: 0 }),
      over: ({ event }) => (event.type === 'MOVE' ? event.over : -1)
    }),
    announceDrop: emit(({ context }) => ({
      type: 'dropped' as const,
      from: context.from,
      to: context.over
    }))
  }
}).createMachine({
  id: 'sortable',
  context: { from: -1, over: -1, pos: { x: 0, y: 0 } },
  initial: 'idle',
  states: {
    idle: { on: { START: { target: 'dragging', actions: 'pickUp' } } },
    dragging: {
      invoke: { src: 'noopPointer' },
      on: {
        MOVE: { actions: 'track' },
        END: { target: 'idle', actions: 'announceDrop' }
      }
    }
  }
});
