export interface SegmentState {
  readonly id: string;
  readonly name: string;
  readonly memberCount: number;
  readonly closed: boolean;
}

export type SegmentEvent =
  | { type: "SegmentDefined"; id: string; name: string }
  | { type: "SegmentMemberAdded"; userId: string }
  | { type: "SegmentMemberRemoved"; userId: string }
  | { type: "SegmentClosed" };

export const initialSegment: SegmentState = { id: "", name: "", memberCount: 0, closed: false };

export function when(state: SegmentState, event: SegmentEvent): SegmentState {
  switch (event.type) {
    case "SegmentDefined":
      return { id: event.id, name: event.name, memberCount: 0, closed: false };
    case "SegmentMemberAdded":
      if (state.closed) return state;
      return { ...state, memberCount: state.memberCount + 1 };
    case "SegmentMemberRemoved":
      if (state.closed) return state;
      return { ...state, memberCount: Math.max(0, state.memberCount - 1) };
    case "SegmentClosed":
      return { ...state, closed: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function isDefined(state: SegmentState): boolean {
  return state.id !== "";
}

export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S,
  check?: (s: S) => boolean,
): Promise<S> {
  let state = initial;
  for await (const event of events) {
    state = reducer(state, event);
  }
  if (check && !check(state)) throw new Error("INVALID_STATE");
  return state;
}
