The helper is a generic async reducer: two type parameters for state and event, a `for await` inside an async function, a typed initial state, and a returned accumulator. It does not mutate the input iterable.

```typescript
export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  async function main() {
    for await (const event of events) {
      state = evolve(state, event);
    }
  }
  await main();
  return state;
}

export type PlayerEvent =
  | { type: "PlayerSigned"; id: string; name: string; club: string }
  | { type: "PlayerTransferred"; toClub: string }
  | { type: "PlayerRetired"; reason: string };

export interface PlayerState {
  id: string;
  name: string;
  club: string;
  retired: boolean;
}

export const initialPlayer: PlayerState = { id: "", name: "", club: "", retired: false };

export function when(s: PlayerState, e: PlayerEvent): PlayerState {
  switch (e.type) {
    case "PlayerSigned":
      return { id: e.id, name: e.name, club: e.club, retired: false };
    case "PlayerTransferred":
      return { ...s, club: e.toClub };
    case "PlayerRetired":
      return { ...s, retired: true };
    default: { const _n: never = e; return s; }
  }
}

export async function loadPlayer(stream: AsyncIterable<PlayerEvent>): Promise<PlayerState> {
  return aggregateStream<PlayerState, PlayerEvent>(stream, when, initialPlayer);
}
