export type ArtisanStudioState =
  | { status: "none" }
  | { status: "open"; id: string; members: number };

export type ArtisanStudioCommand =
  | { type: "open"; id: string }
  | { type: "admit"; member: string };

export type ArtisanStudioEvent =
  | { type: "StudioOpened"; id: string }
  | { type: "StudioMemberAdmitted"; member: string };

const initialState: ArtisanStudioState = { status: "none" };

function decide(
  c: ArtisanStudioCommand,
  s: ArtisanStudioState,
): ArtisanStudioEvent[] {
  if (c.type === "open") {
    if (s.status === "open") throw new Error("already open");
    return [{ type: "StudioOpened", id: c.id }];
  }
  if (s.status !== "open") throw new Error("not open");
  return [{ type: "StudioMemberAdmitted", member: c.member }];
}

function evolve(
  s: ArtisanStudioState,
  e: ArtisanStudioEvent,
): ArtisanStudioState {
  if (e.type === "StudioOpened") {
    return { status: "open", id: e.id, members: 0 };
  }
  return s.status === "open" ? { ...s, members: s.members + 1 } : s;
}

export interface EventStore {
  readStream(
    stream: string,
  ): Promise<{ events: ArtisanStudioEvent[]; lastRevision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: ArtisanStudioEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export async function handle(
  command: ArtisanStudioCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const { events, lastRevision } = await ctx.eventStore.readStream(
    ctx.streamName,
  );
  const state = events.reduce(evolve, initialState);
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, {
    expectedRevision: lastRevision,
  });
}
