  handle(command: ReleaseCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void>;
}

export const releaseHandler: CommandHandler = {
  async handle(command, { streamName, eventStore }) {
    const { events, revision } = await eventStore.readStream<ReleaseEvent>(streamName);
    const state = events.reduce<ReleaseState>(evolve, initialState);
    const newEvents = decide(command, state);
    if (newEvents.length === 0) return;
    await eventStore.appendToStream<ReleaseEvent>(streamName, newEvents, { expectedRevision: revision });
  },
