A Decider bundles `initialState`, a pure `decide(command, state)` that validates invariants and emits events, and a pure `evolve(state, event)` that folds events back into state. Because both functions are pure, replaying the event log deterministically reconstructs the aggregate.

```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type Command =
  | { type: 'StartExtraction'; rigId: string }
  | { type: 'RecordInterval'; metres: number }
  | { type: 'SealCore'; sealedBy: string };

type Event =
  | { type: 'ExtractionStarted'; rigId: string }
  | { type: 'IntervalRecorded'; metres: number }
  | { type: 'CoreSealed'; sealedBy: string };

type State =
  | { status: 'idle' }
  | { status: 'extracting'; rigId: string; metres: number }
  | { status: 'sealed'; sealedBy: string };

class InvariantError extends Error {}

export const DrillCore: Decider<Command, Event, State> = {
  initialState: { status: 'idle' },
  decide(command, state) {
    switch (command.type) {
      case 'StartExtraction':
        if (state.status !== 'idle') throw new InvariantError('already started');
        return [{ type: 'ExtractionStarted', rigId: command.rigId }];
      case 'RecordInterval':
        if (state.status !== 'extracting') throw new InvariantError('sealed or idle');
        return [{ type: 'IntervalRecorded', metres: command.metres }];
      case 'SealCore':
        if (state.status !== 'extracting') throw new InvariantError('cannot seal');
        return [{ type: 'CoreSealed', sealedBy: command.sealedBy }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'ExtractionStarted':
        return { status: 'extracting', rigId: event.rigId, metres: 0 };
      case 'IntervalRecorded':
        return state.status === 'extracting'
          ? { ...state, metres: state.metres + event.metres }
          : state;
      case 'CoreSealed':
        return { status: 'sealed', sealedBy: event.sealedBy };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
