export interface Snapshot<S> { version: number; state: S }
interface RetainerV1 { id: string; balance: number }
interface RetainerV2 { id: string; balance: number; client: string }
interface RetainerV3 { id: string; balance: number; client: string; currency: "USD" | "EUR" }
export type CurrentRetainer = RetainerV3;
export const CURRENT_VERSION = 3;
function v1Tov2(s: RetainerV1): RetainerV2 { return { ...s, client: "unknown" }; }
function v2Tov3(s: RetainerV2): RetainerV3 { return { ...s, currency: "USD" }; }
export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentRetainer> {
  let v = raw.version;
  let s: unknown = raw.state;
  if (v === 1) { s = v1Tov2(s as RetainerV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as RetainerV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`unexpected snapshot version ${v}`);
  return { version: v, state: s as CurrentRetainer };
}
export function loadSnapshot(raw: Snapshot<unknown>): CurrentRetainer {
  const snap: Snapshot<CurrentRetainer> = upgradeSnapshot(raw);
  return snap.state;
}
