```typescript
export type AgreementState = { status: "none" } | { status: "active"; id: string } | { status: "ended" };
export type AgreementCommand = { type: "start"; id: string } | { type: "end" };
export type AgreementEvent = { type: "AgreementStarted"; id: string } | { type: "AgreementEnded" };

const initial: AgreementState = { status: "none" };

function evolve(state: AgreementState, event: AgreementEvent): AgreementState {
  switch (event.type) {
    case "AgreementStarted":
      return { status: "active", id: event.id };
    case "AgreementEnded":
      if (state.status !== "active") return state;
      return { status: "ended" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(cmd: AgreementCommand, state: AgreementState): AgreementEvent[] {
  switch (cmd.type) {
    case "start":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "AgreementStarted", id: cmd.id }];
    case "end":
      if (state.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "AgreementEnded" }];
    default: {
      const _never: never = cmd;
      return _never;
    }
  }
}

export class ConcurrencyConflict extends Error { constructor(s: string) { super(`CONFLICT:${s}`); } }

interface EventStore<E> {
  readStream(s: string): Promise<{ data: E; revision: bigint }[]>;
  appendToStream(s: string, events: E[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export interface CommandHandler<C> {
  handle(command: C, ctx: { streamName: string }): Promise<void>;
}

export function makeHandler(store: EventStore<AgreementEvent>): CommandHandler<AgreementCommand> {
  return {
    async handle(command, { streamName }) {
      const stored = await store.readStream(streamName);
      const state = stored.reduce<AgreementState>((s, e) => evolve(s, e.data), initial);
      const events = decide(command, state);
      const expectedRevision: bigint | "no_stream" =
        stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
      try {
        await store.appendToStream(streamName, events, { expectedRevision });
      } catch (err) {
        if (err instanceof Error && /expected/i.test(err.message)) {
          throw new ConcurrencyConflict(streamName);
        }
        throw err;
      }
    },
  };
}
