export type MarketStallEvent =
  | { type: "StallOpened"; id: string }
  | { type: "SaleRecorded"; id: string; amount: number };

export interface StoredEvent {
  revision: bigint;
  event: MarketStallEvent;
}

interface Row {
  id: string;
  gross: number;
}
export type SalesView = Record<string, Row>;

export function project(view: SalesView, event: MarketStallEvent): SalesView {
  switch (event.type) {
    case "StallOpened":
      return { ...view, [event.id]: { id: event.id, gross: 0 } };
    case "SaleRecorded": {
      const row = view[event.id];
      if (!row) return view;
      return { ...view, [event.id]: { ...row, gross: row.gross + event.amount } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface EventReader {
  readBatch(from: bigint, size: number): Promise<StoredEvent[]>;
}

export interface RebuildOpts {
  from: bigint;
  batchSize: number;
  reader: EventReader;
  persist: (view: SalesView, cursor: bigint) => Promise<void>;
  onProgress?: (cursor: bigint, count: number) => void;
}

export async function rebuild(opts: RebuildOpts): Promise<void> {
  let cursor = opts.from;
  let view: SalesView = {};
  let total = 0;
  for (;;) {
    const batch = await opts.reader.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const se of batch) {
      view = project(view, se.event);
      cursor = se.revision + 1n;
      total += 1;
    }
    await opts.persist(view, cursor);
    opts.onProgress?.(cursor, total);
  }
}
