  conn: Conn,
  stream: string,
  events: VisitRecordEvent[],
  outbox: OutboxRow[],
  expectedRevision: ExpectedRevision,
): Promise<bigint> {
  return conn.transaction(async (tx) => {
    for (const row of outbox) {
      await tx.insertOutbox(row);
    }
    const { nextRevision } = await tx.appendToStream(stream, events, { expectedRevision });
    return nextRevision;
  });
}
