export type StaffShiftV1 = { id: string; staffId: string };
export type StaffShiftV2 = { id: string; staffId: string; breakMinutes: number };
export type StaffShiftV3 = { id: string; staffId: string; breakMinutes: number; startedAt: string };

export type CurrentStaffShift = StaffShiftV3;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 3;

function v1Tov2(snap: Snapshot<StaffShiftV1>): Snapshot<StaffShiftV2> {
  return { version: 2, state: { ...snap.state, breakMinutes: 0 } };
}

function v2Tov3(snap: Snapshot<StaffShiftV2>): Snapshot<StaffShiftV3> {
  return { version: 3, state: { ...snap.state, startedAt: "1970-01-01T00:00:00Z" } };
}

export class SnapshotError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "SnapshotError"; }
}

export function loadStaffShiftSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentStaffShift> {
  let cur: Snapshot<unknown> = raw;
  while (cur.version < CURRENT_VERSION) {
    if (cur.version === 1) cur = v1Tov2(cur as Snapshot<StaffShiftV1>);
    else if (cur.version === 2) cur = v2Tov3(cur as Snapshot<StaffShiftV2>);
    else throw new SnapshotError(`UNSUPPORTED_${cur.version}`);
  }
  if (cur.version !== CURRENT_VERSION) throw new SnapshotError(`UNSUPPORTED_${cur.version}`);
  return cur as Snapshot<CurrentStaffShift>;
}
