export type DeliveryEvent =
  | { type: "DeliveryDispatched"; id: string; courier: string }
  | { type: "DeliveryDelivered"; id: string; at: string }
  | { type: "DeliveryFailed"; id: string; reason: string };

export type DeliveryView = Readonly<{
  byId: Readonly<Record<string, { status: "dispatched" | "delivered" | "failed"; courier?: string }>>;
}>;

export const emptyView: DeliveryView = { byId: {} };

export function project(view: DeliveryView, event: DeliveryEvent): DeliveryView {
  switch (event.type) {
    case "DeliveryDispatched":
      return { byId: { ...view.byId, [event.id]: { status: "dispatched", courier: event.courier } } };
    case "DeliveryDelivered": {
      const prev = view.byId[event.id];
      if (!prev) return view;
      return { byId: { ...view.byId, [event.id]: { ...prev, status: "delivered" } } };
    }
    case "DeliveryFailed": {
      const prev = view.byId[event.id];
      if (!prev) return view;
      return { byId: { ...view.byId, [event.id]: { ...prev, status: "failed" } } };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed<E> {
  readFrom(position: bigint): AsyncIterable<{ position: bigint; event: E }>;
}

export interface ViewStore<V> {
  load(): Promise<V>;
  save(view: V): Promise<void>;
}

export async function runDeliverySubscription(
  feed: EventFeed<DeliveryEvent>,
  checkpoints: CheckpointStore,
  views: ViewStore<DeliveryView>,
  subscriptionName: string,
): Promise<void> {
  const last = await checkpoints.read(subscriptionName);
  const from: bigint = last ?? 0n;
  let view = await views.load();
  for await (const { position, event } of feed.readFrom(from)) {
    view = project(view, event);
    await views.save(view);
    await checkpoints.write(subscriptionName, position);
  }
}
