```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

```typescript
export type IrrigationCycleState =
  | { status: "idle" }
  | { status: "running"; id: string; zone: string; flowRate: number; startedAt: string }
  | { status: "stopped"; id: string; totalMinutes: number };

export type IrrigationCycleCommand =
  | { type: "start"; id: string; zone: string; flowRate: number; at: string }
  | { type: "adjust"; flowRate: number }
  | { type: "stop"; totalMinutes: number };

export type IrrigationCycleEvent =
  | { type: "IrrigationCycleStarted"; id: string; zone: string; flowRate: number; at: string }
  | { type: "IrrigationCycleAdjusted"; flowRate: number }
  | { type: "IrrigationCycleStopped"; totalMinutes: number };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const irrigationCycleDecider: Decider<IrrigationCycleCommand, IrrigationCycleEvent, IrrigationCycleState> = {
  initialState: { status: "idle" },
  decide(command, state) {
    switch (command.type) {
      case "start":
        if (state.status === "running") throw new DomainError("ALREADY_RUNNING");
        if (command.flowRate <= 0) throw new DomainError("INVALID_FLOW_RATE");
        return [{ type: "IrrigationCycleStarted", id: command.id, zone: command.zone, flowRate: command.flowRate, at: command.at }];
      case "adjust":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        if (command.flowRate <= 0) throw new DomainError("INVALID_FLOW_RATE");
        return [{ type: "IrrigationCycleAdjusted", flowRate: command.flowRate }];
      case "stop":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        if (command.totalMinutes < 0) throw new DomainError("NEGATIVE_DURATION");
        return [{ type: "IrrigationCycleStopped", totalMinutes: command.totalMinutes }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "IrrigationCycleStarted":
        return { status: "running", id: event.id, zone: event.zone, flowRate: event.flowRate, startedAt: event.at };
      case "IrrigationCycleAdjusted":
        if (state.status !== "running") return state;
        return { ...state, flowRate: event.flowRate };
      case "IrrigationCycleStopped":
        if (state.status !== "running") return state;
        return { status: "stopped", id: state.id, totalMinutes: event.totalMinutes };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
