export type ColorGradeCommand =
  | { type: "create"; id: string; shotId: string }
  | { type: "applyLut"; lut: string }
  | { type: "approve"; approvedBy: string };

export type ColorGradeEvent =
  | { type: "ColorGradeCreated"; id: string; shotId: string }
  | { type: "ColorGradeLutApplied"; lut: string }
  | { type: "ColorGradeApproved"; approvedBy: string; lut: string };

export type ColorGradeState =
  | { status: "none" }
  | { status: "draft"; id: string; shotId: string; lut: string | null }
  | { status: "approved"; id: string; shotId: string };

export const initialState: ColorGradeState = { status: "none" };

export function evolve(state: ColorGradeState, event: ColorGradeEvent): ColorGradeState {
  switch (event.type) {
    case "ColorGradeCreated":
      return { status: "draft", id: event.id, shotId: event.shotId, lut: null };
    case "ColorGradeLutApplied":
      if (state.status !== "draft") return state;
      return { ...state, lut: event.lut };
    case "ColorGradeApproved":
      if (state.status !== "draft") return state;
      return { status: "approved", id: state.id, shotId: state.shotId };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: ColorGradeCommand, state: ColorGradeState): ColorGradeEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ColorGradeCreated", id: command.id, shotId: command.shotId }];
    case "applyLut":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "ColorGradeLutApplied", lut: command.lut }];
    case "approve":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      if (state.lut === null) throw new Error("NO_LUT");
      return [{ type: "ColorGradeApproved", approvedBy: command.approvedBy, lut: state.lut }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export interface CommandHandler<C> {
  handle(command: C, args: { streamName: string }): Promise<void>;
}

export function makeHandler(store: EventStore<ColorGradeEvent>): CommandHandler<ColorGradeCommand> {
  return {
    async handle(command, { streamName }) {
      const loaded = await store.readStream(streamName);
      const state = loaded.events.reduce(evolve, initialState);
      const events = decide(command, state);
      await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
    },
  };
}
