export type VFXShotEvent =
  | { type: "VFXShotScoped"; id: string; sequence: string }
  | { type: "VFXShotRendered"; pass: string }
  | { type: "VFXShotComposited" }
  | { type: "VFXShotReviewCleared"; reviewer: string };

export type VFXShotState =
  | { status: "none" }
  | { status: "scoped"; id: string; sequence: string; renderPasses: readonly string[]; composited: boolean; cleared: boolean };

export function when(state: VFXShotState, event: VFXShotEvent): VFXShotState {
  switch (event.type) {
    case "VFXShotScoped":
      return {
        status: "scoped",
        id: event.id,
        sequence: event.sequence,
        renderPasses: [],
        composited: false,
        cleared: false,
      };
    case "VFXShotRendered":
      if (state.status !== "scoped") return state;
      return { ...state, renderPasses: [...state.renderPasses, event.pass] };
    case "VFXShotComposited":
      if (state.status !== "scoped") return state;
      return { ...state, composited: true };
    case "VFXShotReviewCleared":
      if (state.status !== "scoped") return state;
      return { ...state, cleared: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  try {
    for await (const event of stream) {
      state = evolve(state, event);
    }
  } catch (err) {
    throw err instanceof Error ? err : new Error(String(err));
  }
  return state;
}
