Define a pure `when(state, event)` fold, a discriminated event union, and a generic `aggregateStream` helper that consumes an `AsyncIterable<E>` and returns the folded state.

```typescript
export type SerialEvent =
  | { type: "SerialIssued"; id: string; sku: string }
  | { type: "SerialAttached"; crateId: string }
  | { type: "SerialScrapped"; reason: string };

export interface SerialState {
  readonly id: string;
  readonly sku: string;
  readonly crateId: string | null;
  readonly scrapped: boolean;
}

export const emptySerial: SerialState = { id: "", sku: "", crateId: null, scrapped: false };

export function when(s: SerialState, e: SerialEvent): SerialState {
  switch (e.type) {
    case "SerialIssued": return { id: e.id, sku: e.sku, crateId: null, scrapped: false };
    case "SerialAttached": return { ...s, crateId: e.crateId };
    case "SerialScrapped": return { ...s, scrapped: true };
    default: { const _n: never = e; return s; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  async function main(): Promise<void> {
    for await (const event of stream) state = fold(state, event);
  }
  await main();
  return state;
}

export async function loadSerial(events: AsyncIterable<SerialEvent>): Promise<SerialState> {
  return aggregateStream(events, when, emptySerial);
}
