import { Effect } from "effect";

export type MovementEvent =
  | { type: "SkuReceived"; sku: string; qty: number; revision: bigint }
  | { type: "SkuPicked"; sku: string; qty: number; revision: bigint }
  | { type: "SkuAdjusted"; sku: string; delta: number; revision: bigint };

export interface LedgerView { readonly onHand: Readonly<Record<string, number>>; }
export const emptyView: LedgerView = { onHand: {} };

export function project(v: LedgerView, e: MovementEvent): LedgerView {
  const current = v.onHand[e.sku] ?? 0;
  switch (e.type) {
    case "SkuReceived": return { onHand: { ...v.onHand, [e.sku]: current + e.qty } };
    case "SkuPicked": return { onHand: { ...v.onHand, [e.sku]: current - e.qty } };
    case "SkuAdjusted": return { onHand: { ...v.onHand, [e.sku]: current + e.delta } };
    default: { const _n: never = e; return v; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface LedgerStore {
  load(): Promise<LedgerView>;
  save(view: LedgerView): Promise<void>;
}

export interface MovementReader {
  readFromStream(from: bigint): AsyncIterable<MovementEvent>;
}

export const runMovementSubscription = (
  name: string,
  reader: MovementReader,
  ledger: LedgerStore,
  checkpoints: CheckpointStore,
) =>
  Effect.gen(function* () {
    const startFrom = ((yield* Effect.promise(() => checkpoints.read(name))) ?? -1n) + 1n;
    let view = yield* Effect.promise(() => ledger.load());
    const run = async (): Promise<void> => {
      for await (const event of reader.readFromStream(startFrom)) {
        view = project(view, event);
        await ledger.save(view);
        await checkpoints.write(name, event.revision);
      }
    };
    yield* Effect.promise(() => run());
  });
