```typescript
interface WarehouseV1 { id: string; code: string }
interface WarehouseV2 { id: string; code: string; bins: number }
interface WarehouseV3 { id: string; code: string; bins: number; region: string }
interface WarehouseV4 { id: string; code: string; bins: number; region: string; certified: boolean }

export type CurrentWarehouse = WarehouseV4;
export const CURRENT_VERSION = 4 as const;

export interface Snapshot<S> { readonly version: number; readonly state: S; }

function v1Tov2(p: WarehouseV1): WarehouseV2 { return { ...p, bins: 0 }; }
function v2Tov3(p: WarehouseV2): WarehouseV3 { return { ...p, region: "UNKNOWN" }; }
function v3Tov4(p: WarehouseV3): WarehouseV4 { return { ...p, certified: false }; }

function isCurrent(value: unknown): value is CurrentWarehouse {
  const v = value as Partial<CurrentWarehouse>;
  return typeof v?.id === "string"
    && typeof v?.code === "string"
    && typeof v?.bins === "number"
    && typeof v?.region === "string"
    && typeof v?.certified === "boolean";
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentWarehouse> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version > CURRENT_VERSION) throw new Error(`Snapshot from the future: v${version}`);
  if (version === 1) { state = v1Tov2(state as WarehouseV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as WarehouseV2); version = 3; }
  if (version === 3) { state = v3Tov4(state as WarehouseV3); version = 4; }
  if (version !== CURRENT_VERSION) throw new Error(`Unhandled snapshot version ${version}`);
  if (!isCurrent(state)) throw new Error("Upgraded state shape mismatch");
  return { version: CURRENT_VERSION, state };
}
```

A parallel root has independent regions that are always active together. Putting a `paused/running` region next to a `score` region lets you pause game flow without tearing down score tracking — both live side by side, and events only affect the region whose state handles them.

