}>;

export const emptyView: RemittanceSummaryView = {
  initiatedCount: 0,
  fundedCount: 0,
  settledCount: 0,
  initiatedAmount: 0,
  byCorridor: {},
};

export function project(view: RemittanceSummaryView, event: RemittanceEvent): RemittanceSummaryView {
  switch (event.type) {
    case "RemittanceInitiated": {
      const prior = view.byCorridor[event.corridor] ?? 0;
      return {
        ...view,
        initiatedCount: view.initiatedCount + 1,
        initiatedAmount: view.initiatedAmount + event.amount,
        byCorridor: { ...view.byCorridor, [event.corridor]: prior + event.amount },
      };
    }
    case "RemittanceFunded":
      return { ...view, fundedCount: view.fundedCount + 1 };
    case "RemittanceSettled":
      return { ...view, settledCount: view.settledCount + 1 };
    case "RemittanceCorrectionLogged":
      // audit-only event; not part of this summary
      return view;
    default: { const _n: never = event; return view; }
  }
}

export function remittanceSummaryFrom(events: RemittanceEvent[]): RemittanceSummaryView {
  return events.reduce(project, emptyView);
}
```

