```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let acc = initial;
  for await (const e of stream) acc = reducer(acc, e);
  return acc;
}

export type DocumentEvent =
  | { type: "DocumentCreated"; id: string; title: string }
  | { type: "DocumentTitleChanged"; title: string }
  | { type: "DocumentSubmitted"; at: string };

export interface DocumentSummary {
  readonly id: string | null;
  readonly title: string;
  readonly submitted: boolean;
  readonly submittedAt: string | null;
}

export const empty: DocumentSummary = { id: null, title: "", submitted: false, submittedAt: null };

export function when(view: DocumentSummary, event: DocumentEvent): DocumentSummary {
  switch (event.type) {
    case "DocumentCreated": return { id: event.id, title: event.title, submitted: false, submittedAt: null };
    case "DocumentTitleChanged": return { ...view, title: event.title };
    case "DocumentSubmitted": return { ...view, submitted: true, submittedAt: event.at };
    default: { const _n: never = event; return view; }
  }
}

export async function rebuildDocument(stream: AsyncIterable<DocumentEvent>): Promise<DocumentSummary> {
  return aggregateStream<DocumentSummary, DocumentEvent>(stream, when, empty);
}
