  | { type: "LotConsumed"; qty: number }
  | { type: "LotDiscarded"; reason: string };

export interface Lot {
  readonly id: string;
  readonly sku: string;
  readonly qty: number;
  readonly discarded: boolean;
}

export const emptyLot: Lot = { id: "", sku: "", qty: 0, discarded: false };

export function when(state: Lot, event: LotEvent): Lot {
  switch (event.type) {
    case "LotCreated":
      return { id: event.id, sku: event.sku, qty: event.qty, discarded: false };
    case "LotConsumed":
      return { ...state, qty: state.qty - event.qty };
    case "LotDiscarded":
      return { ...state, discarded: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregateLot(events: ReadonlyArray<LotEvent>): Lot {
  let state: Lot = emptyLot;
  for (const event of events) {
    state = when(state, event);
  }
  return state;
}
