```typescript
export type FishStockState =
  | { status: "empty" }
  | { status: "stocked"; id: string; count: number; species: string };

export type FishStockCommand =
  | { type: "seed"; id: string; species: string; count: number }
  | { type: "restock"; count: number }
  | { type: "harvest"; count: number };

export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; species: string; count: number }
  | { type: "FishStockRestocked"; count: number }
  | { type: "FishStockHarvested"; count: number };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const fishStockDecider: Decider<FishStockCommand, FishStockEvent, FishStockState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "seed":
        if (state.status !== "empty") throw new DomainError("EXISTS");
        if (command.count <= 0) throw new DomainError("BAD_COUNT");
        return [{ type: "FishStockSeeded", id: command.id, species: command.species, count: command.count }];
      case "restock":
        if (state.status !== "stocked") throw new DomainError("NOT_STOCKED");
        if (command.count <= 0) throw new DomainError("BAD_COUNT");
        return [{ type: "FishStockRestocked", count: command.count }];
      case "harvest":
        if (state.status !== "stocked") throw new DomainError("NOT_STOCKED");
        if (command.count > state.count) throw new DomainError("OVER_HARVEST");
        return [{ type: "FishStockHarvested", count: command.count }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FishStockSeeded":
        return { status: "stocked", id: event.id, species: event.species, count: event.count };
      case "FishStockRestocked":
        if (state.status !== "stocked") return state;
        return { ...state, count: state.count + event.count };
      case "FishStockHarvested":
        if (state.status !== "stocked") return state;
        return { ...state, count: state.count - event.count };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
