```typescript
import { Effect } from 'effect';

type Command = { type: 'RecordInterval'; metres: number };
type CoreEvent = { type: 'IntervalRecorded'; metres: number };
type State = { status: 'extracting'; metres: number } | { status: 'sealed' };
const initial: State = { status: 'extracting', metres: 0 };

function evolve(state: State, event: CoreEvent): State {
  switch (event.type) {
    case 'IntervalRecorded':
      return state.status === 'extracting' ? { ...state, metres: state.metres + event.metres } : state;
    default: {
      const _: never = event.type;
      return _;
    }
  }
}

function decide(cmd: Command, state: State): CoreEvent[] {
  if (state.status !== 'extracting') throw new Error('cannot record');
  return [{ type: 'IntervalRecorded', metres: cmd.metres }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: CoreEvent; revision: bigint }>;
  appendToStream(s: string, e: CoreEvent[], o: { expectedRevision: bigint | 'no_stream' }): Promise<void>;
}

export function handle(cmd: Command, ctx: { streamName: string; eventStore: EventStore }) {
  return Effect.gen(function* () {
    const loaded = yield* Effect.tryPromise({
      try: async () => {
        let state = initial;
        let rev: bigint | 'no_stream' = 'no_stream';
        for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
          state = evolve(state, event);
          rev = revision;
        }
        return { state, rev };
      },
      catch: (e) => new Error(String(e)),
    });
    const events = decide(cmd, loaded.state);
    yield* Effect.tryPromise({
      try: () => ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: loaded.rev }),
      catch: (e) => new Error(String(e)),
    });
  });
}
