```typescript
export type AttributionEvent =
  | { type: "AttributionEventCaptured"; segmentId: string; valueCents: number }
  | { type: "AttributionEventReverted"; segmentId: string; valueCents: number };

export interface SegmentConversionView {
  readonly bySegment: Readonly<Record<string, { conversions: number; valueCents: number }>>;
}

export const emptyView: SegmentConversionView = { bySegment: {} };

export function project(view: SegmentConversionView, event: AttributionEvent): SegmentConversionView {
  const id = event.segmentId;
  const prev = view.bySegment[id] ?? { conversions: 0, valueCents: 0 };
  switch (event.type) {
    case "AttributionEventCaptured":
      return { bySegment: { ...view.bySegment, [id]: { conversions: prev.conversions + 1, valueCents: prev.valueCents + event.valueCents } } };
    case "AttributionEventReverted":
      return {
        bySegment: {
          ...view.bySegment,
          [id]: { conversions: Math.max(0, prev.conversions - 1), valueCents: Math.max(0, prev.valueCents - event.valueCents) },
        },
      };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface StoredEvent {
  readonly revision: bigint;
  readonly event: AttributionEvent;
}

export interface EventSource {
  readBatch(from: bigint, limit: number): Promise<readonly StoredEvent[]>;
}

export interface ViewStore {
  load(): Promise<{ view: SegmentConversionView; revision: bigint } | null>;
  save(view: SegmentConversionView, revision: bigint): Promise<void>;
}

export async function rebuild(
  source: EventSource,
  viewStore: ViewStore,
  batchSize: number,
  onProgress?: (rev: bigint) => void,
): Promise<void> {
  const loaded = await viewStore.load();
  let view = loaded?.view ?? emptyView;
  let cursor = loaded?.revision ?? 0n;
  for (;;) {
    const batch = await source.readBatch(cursor, batchSize);
    if (batch.length === 0) return;
    for (const stored of batch) {
      view = project(view, stored.event);
      cursor = stored.revision;
    }
    await viewStore.save(view, cursor);
    onProgress?.(cursor);
    if (batch.length < batchSize) return;
  }
}
