export type CourtFilingCommand =
  | { type: "submit"; filingId: string; at: number; deadline: number }
  | { type: "accept" }
  | { type: "reject"; reason: string };
export type CourtFilingEvent =
  | { type: "submitted"; filingId: string; at: number }
  | { type: "accepted" }
  | { type: "rejected"; reason: string };
export type CourtFilingState =
  | { status: "empty" }
  | { status: "submitted"; filingId: string }
  | { status: "decided"; outcome: "accepted" | "rejected" };
export const initialState: CourtFilingState = { status: "empty" };
export function decide(cmd: CourtFilingCommand, state: CourtFilingState): CourtFilingEvent[] {
  switch (cmd.type) {
    case "submit":
      if (state.status !== "empty") throw new InvariantError("already submitted");
      if (cmd.at > cmd.deadline) throw new InvariantError("deadline passed");
      return [{ type: "submitted", filingId: cmd.filingId, at: cmd.at }];
    case "accept":
      if (state.status !== "submitted") throw new InvariantError("not submitted");
      return [{ type: "accepted" }];
    case "reject":
      if (state.status !== "submitted") throw new InvariantError("not submitted");
      return [{ type: "rejected", reason: cmd.reason }];
    default: { const _: never = cmd; return _; }
  }
}
export function evolve(s: CourtFilingState, e: CourtFilingEvent): CourtFilingState {
  switch (e.type) {
    case "submitted": return { status: "submitted", filingId: e.filingId };
    case "accepted": return { status: "decided", outcome: "accepted" };
    case "rejected": return { status: "decided", outcome: "rejected" };
    default: { const _: never = e; return _; }
  }
}
export interface Decider<C, E, S> { initialState: S; decide: (c: C, s: S) => E[]; evolve: (s: S, e: E) => S }
export const CourtFilingDecider: Decider<CourtFilingCommand, CourtFilingEvent, CourtFilingState> = { initialState, decide, evolve };
