  | { type: "MenuItemAdded"; id: string; name: string; priceCents: number }
  | { type: "MenuItemPriceChanged"; priceCents: number }
  | { type: "MenuItem86d" }
  | { type: "MenuItemUnmark86d" };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const menuItemDecider: Decider<MenuItemCommand, MenuItemEvent, MenuItemState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "addItem":
        if (s.status !== "none") throw new DomainError("ALREADY_ADDED");
        if (c.priceCents < 0) throw new DomainError("NEGATIVE_PRICE");
        return [{ type: "MenuItemAdded", id: c.id, name: c.name, priceCents: c.priceCents }];
      case "setPrice":
        if (s.status === "none") throw new DomainError("NOT_ADDED");
        if (c.priceCents < 0) throw new DomainError("NEGATIVE_PRICE");
        return [{ type: "MenuItemPriceChanged", priceCents: c.priceCents }];
      case "mark86":
        if (s.status !== "available") throw new DomainError("NOT_AVAILABLE");
        return [{ type: "MenuItem86d" }];
      case "unmark86":
        if (s.status !== "unavailable") throw new DomainError("NOT_86D");
        return [{ type: "MenuItemUnmark86d" }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "MenuItemAdded":
        return { status: "available", id: e.id, name: e.name, priceCents: e.priceCents };
      case "MenuItemPriceChanged":
        return s.status === "none" ? s : { ...s, priceCents: e.priceCents };
      case "MenuItem86d":
        return s.status === "available"
          ? { status: "unavailable", id: s.id, name: s.name, priceCents: s.priceCents }
          : s;
      case "MenuItemUnmark86d":
        return s.status === "unavailable"
          ? { status: "available", id: s.id, name: s.name, priceCents: s.priceCents }
          : s;
      default: { const _n: never = e; return s; }
    }
  },
};
