export type PortfolioState =
  | { status: "none" }
  | { status: "open"; id: string; holdings: number }
  | { status: "closed"; id: string };

export type PortfolioCommand =
  | { type: "open"; id: string }
  | { type: "addHolding"; units: number }
  | { type: "close" };

export type PortfolioEvent =
  | { type: "PortfolioOpened"; id: string }
  | { type: "HoldingAdded"; units: number }
  | { type: "PortfolioClosed" };

export class PortfolioError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const portfolioDecider: Decider<PortfolioCommand, PortfolioEvent, PortfolioState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "none") throw new PortfolioError("EXISTS");
        return [{ type: "PortfolioOpened", id: c.id }];
      case "addHolding":
        if (s.status !== "open") throw new PortfolioError("NOT_OPEN");
        if (c.units <= 0) throw new PortfolioError("INVALID_UNITS");
        return [{ type: "HoldingAdded", units: c.units }];
      case "close":
        if (s.status !== "open") throw new PortfolioError("NOT_OPEN");
        if (s.holdings !== 0) throw new PortfolioError("HAS_HOLDINGS");
        return [{ type: "PortfolioClosed" }];
      default: { const _n: never = c; throw new PortfolioError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "PortfolioOpened":
        return { status: "open", id: e.id, holdings: 0 };
      case "HoldingAdded":
        if (s.status !== "open") return s;
        return { ...s, holdings: s.holdings + e.units };
      case "PortfolioClosed":
        if (s.status !== "open") return s;
        return { status: "closed", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};

