export type AudienceSegmentState =
  | { status: "empty" }
  | { status: "drafting"; id: string; rules: string[] }
  | { status: "sealed"; id: string; rules: string[]; sealedAt: string };

export type AudienceSegmentCommand =
  | { type: "define"; id: string }
  | { type: "addRule"; rule: string }
  | { type: "removeRule"; rule: string }
  | { type: "seal"; at: string };

export type AudienceSegmentEvent =
  | { type: "AudienceSegmentDefined"; id: string }
  | { type: "AudienceSegmentRuleAdded"; rule: string }
  | { type: "AudienceSegmentRuleRemoved"; rule: string }
  | { type: "AudienceSegmentSealed"; at: string };

export class AudienceSegmentError extends Error {
  constructor(code: string) { super(code); this.name = "AudienceSegmentError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const audienceSegmentDecider: Decider<AudienceSegmentCommand, AudienceSegmentEvent, AudienceSegmentState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "define":
        if (state.status !== "empty") throw new AudienceSegmentError("EXISTS");
        return [{ type: "AudienceSegmentDefined", id: command.id }];
      case "addRule":
        if (state.status !== "drafting") throw new AudienceSegmentError("NOT_DRAFTING");
        return [{ type: "AudienceSegmentRuleAdded", rule: command.rule }];
      case "removeRule":
        if (state.status !== "drafting") throw new AudienceSegmentError("NOT_DRAFTING");
        if (!state.rules.includes(command.rule)) throw new AudienceSegmentError("NO_SUCH_RULE");
        return [{ type: "AudienceSegmentRuleRemoved", rule: command.rule }];
      case "seal":
        if (state.status !== "drafting") throw new AudienceSegmentError("NOT_DRAFTING");
        if (state.rules.length === 0) throw new AudienceSegmentError("NO_RULES");
        return [{ type: "AudienceSegmentSealed", at: command.at }];
      default: {
        const _never: never = command;
        throw new AudienceSegmentError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AudienceSegmentDefined":
        return { status: "drafting", id: event.id, rules: [] };
      case "AudienceSegmentRuleAdded":
        if (state.status !== "drafting") return state;
        return { ...state, rules: [...state.rules, event.rule] };
      case "AudienceSegmentRuleRemoved":
        if (state.status !== "drafting") return state;
        return { ...state, rules: state.rules.filter((r) => r !== event.rule) };
      case "AudienceSegmentSealed":
        if (state.status !== "drafting") return state;
        return { status: "sealed", id: state.id, rules: state.rules, sealedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
