```typescript
export type Snapshot<S> = { version: number; state: S };

export type ApprovalV1 = { id: string; requester: string };
export type ApprovalV2 = { id: string; requester: string; approverCount: number };
export type ApprovalV3 = { id: string; requester: string; approverCount: number; rejected: boolean };
export type ApprovalV4 = {
  id: string;
  requester: string;
  approverCount: number;
  status: "pending" | "approved" | "rejected";
};

export type CurrentApproval = ApprovalV4;
export const CURRENT_VERSION = 4;

export class ApprovalSnapshotError extends Error {}

const v1Tov2 = (s: ApprovalV1): ApprovalV2 => ({ ...s, approverCount: 0 });
const v2Tov3 = (s: ApprovalV2): ApprovalV3 => ({ ...s, rejected: false });
const v3Tov4 = (s: ApprovalV3): ApprovalV4 => ({
  id: s.id,
  requester: s.requester,
  approverCount: s.approverCount,
  status: s.rejected ? "rejected" : "pending",
});

const upgraders: Readonly<Record<number, (s: unknown) => unknown>> = {
  1: (s) => v1Tov2(s as ApprovalV1),
  2: (s) => v2Tov3(s as ApprovalV2),
  3: (s) => v3Tov4(s as ApprovalV3),
};

export function upgradeSnapshot(
  snap: Snapshot<unknown>,
): Snapshot<CurrentApproval> {
  let version = snap.version;
  let state: unknown = snap.state;
  while (version < CURRENT_VERSION) {
    const up = upgraders[version];
    if (!up) throw new ApprovalSnapshotError(`NO_UPGRADER_${version}`);
    state = up(state);
    version = version + 1;
  }
  if (version !== CURRENT_VERSION) throw new ApprovalSnapshotError("UPGRADE_INCOMPLETE");
  const current = state as CurrentApproval;
  if (!current.id || !current.requester || !current.status) {
    throw new ApprovalSnapshotError("SHAPE_MISMATCH");
  }
  return { version, state: current };
}
