```typescript
export type CertificateEvent =
  | { type: "CertificateIssued"; id: string; learner: string; courseId: string; at: string }
  | { type: "CertificateRevoked"; id: string; reason: string };

export type IntegrationEvent =
  | {
      schema: "certificate/issued/v1";
      payload: { certificateId: string; learner: string; courseId: string; at: string };
    }
  | {
      schema: "certificate/revoked/v1";
      payload: { certificateId: string; reason: string };
    };

export function translate(event: CertificateEvent): IntegrationEvent | null {
  switch (event.type) {
    case "CertificateIssued":
      return {
        schema: "certificate/issued/v1",
        payload: { certificateId: event.id, learner: event.learner, courseId: event.courseId, at: event.at },
      };
    case "CertificateRevoked":
      return {
        schema: "certificate/revoked/v1",
        payload: { certificateId: event.id, reason: event.reason },
      };
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface OutboxRow {
  id: string;
  payload: IntegrationEvent;
  publishedAt: string | null;
}

export interface TransactionalConnection {
  appendToStream(
    stream: string,
    events: ReadonlyArray<CertificateEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
  insertOutbox(rows: ReadonlyArray<OutboxRow>): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface ConnectionFactory {
  begin(): Promise<TransactionalConnection>;
}

// A separate outbox publisher worker polls unpublished rows, forwards them to
// the message bus, and marks each row as publishedAt once acknowledged.
export async function appendWithOutbox(
  factory: ConnectionFactory,
  stream: string,
  events: ReadonlyArray<CertificateEvent>,
  expectedRevision: ExpectedRevision,
  makeId: (event: CertificateEvent, index: number) => string,
): Promise<void> {
  const conn = await factory.begin();
  try {
    await conn.appendToStream(stream, events, { expectedRevision });
    const rows: OutboxRow[] = [];
    events.forEach((event, index) => {
      const integration = translate(event);
      if (integration !== null) {
        rows.push({ id: makeId(event, index), payload: integration, publishedAt: null });
      }
    });
    if (rows.length > 0) await conn.insertOutbox(rows);
    await conn.commit();
  } catch (error) {
    await conn.rollback();
    throw error;
  }
}
