export type ManuscriptProjEvent =
  | { type: "ManuscriptStarted"; id: string; title: string }
  | { type: "ChapterAppended"; manuscriptId: string; chapterId: string }
  | { type: "ManuscriptLocked"; id: string; at: string }
  | { type: "ManuscriptRenamed"; id: string; title: string };

export interface ManuscriptView {
  readonly id: string | null;
  readonly title: string;
  readonly chapters: ReadonlyArray<string>;
  readonly locked: boolean;
  readonly lockedAt: string | null;
}

export const emptyView: ManuscriptView = {
  id: null, title: "", chapters: [], locked: false, lockedAt: null,
};

export function project(view: ManuscriptView, event: ManuscriptProjEvent): ManuscriptView {
  switch (event.type) {
    case "ManuscriptStarted":
      return { id: event.id, title: event.title, chapters: [], locked: false, lockedAt: null };
    case "ChapterAppended":
      if (!view.id || view.id !== event.manuscriptId) return view;
      if (view.chapters.includes(event.chapterId)) return view;
      return { ...view, chapters: [...view.chapters, event.chapterId] };
    case "ManuscriptLocked":
      if (view.id !== event.id) return view;
      return { ...view, locked: true, lockedAt: event.at };
    case "ManuscriptRenamed":
      if (view.id !== event.id) return view;
      return { ...view, title: event.title };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function rebuild(events: ManuscriptProjEvent[]): ManuscriptView {
  return events.reduce(project, emptyView);
}
