```typescript
export type TurnaroundState =
  | { status: "idle" }
  | { status: "active"; id: string; pending: string[] }
  | { status: "closed"; id: string };

export type TurnaroundCommand =
  | { type: "beginTurnaround"; id: string; phases: string[] }
  | { type: "completePhase"; phase: string }
  | { type: "closeTurnaround" };

export type TurnaroundEvent =
  | { type: "TurnaroundBegun"; id: string; phases: string[] }
  | { type: "PhaseCompleted"; phase: string }
  | { type: "TurnaroundClosed" };

export class DomainError extends Error { constructor(public readonly code: string) { super(code); } }

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const turnaroundDecider: Decider<TurnaroundCommand, TurnaroundEvent, TurnaroundState> = {
  initialState: { status: "idle" },
  decide(c, s) {
    switch (c.type) {
      case "beginTurnaround":
        if (s.status !== "idle") throw new DomainError("ACTIVE");
        return [{ type: "TurnaroundBegun", id: c.id, phases: c.phases }];
      case "completePhase":
        if (s.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (!s.pending.includes(c.phase)) throw new DomainError("UNKNOWN_PHASE");
        return [{ type: "PhaseCompleted", phase: c.phase }];
      case "closeTurnaround":
        if (s.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (s.pending.length > 0) throw new DomainError("PHASES_PENDING");
        return [{ type: "TurnaroundClosed" }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "TurnaroundBegun":
        return { status: "active", id: e.id, pending: e.phases };
      case "PhaseCompleted":
        if (s.status !== "active") return s;
        return { ...s, pending: s.pending.filter((p) => p !== e.phase) };
      case "TurnaroundClosed":
        if (s.status !== "active") return s;
        return { status: "closed", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};
