import { Effect } from 'effect';

type MessageEvent =
  | { type: 'MessagePosted'; id: string; body: string }
  | { type: 'MessageEdited'; body: string };

interface EventStore {
  appendToStream(
    stream: string,
    events: readonly MessageEvent[],
    options: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<{ nextExpectedRevision: bigint }>;
  currentRevision(stream: string): Promise<bigint | 'no_stream'>;
}

export class ConcurrencyConflict {
  readonly _tag = 'ConcurrencyConflict';
  constructor(readonly stream: string) {}
}

export class AppendFailed {
  readonly _tag = 'AppendFailed';
  constructor(readonly cause: unknown) {}
}

export function appendWithRevision(
  store: EventStore,
  stream: string,
  events: readonly MessageEvent[],
) {
  return Effect.gen(function* () {
    const expectedRevision = yield* Effect.tryPromise({
      try: () => store.currentRevision(stream),
      catch: (cause) => new AppendFailed(cause),
    });
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision }),
      catch: (cause) =>
        (cause as { code?: string }).code === 'WrongExpectedVersion'
          ? new ConcurrencyConflict(stream)
          : new AppendFailed(cause),
    });
    return result.nextExpectedRevision;
  });
}
