export type TelemetryStreamEvent =
  | { type: "TelemetryStreamOpened"; id: string }
  | { type: "TelemetrySampleIngested"; value: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult { nextRevision: bigint }

export interface EventStore {
  readStream(stream: string): Promise<{ events: TelemetryStreamEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: TelemetryStreamEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: ExpectedRevision) {
    super(`CONCURRENCY_CONFLICT on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

function isConflict(err: unknown): boolean {
  return err instanceof Error && (err.message.includes("WrongExpectedVersion") || err.name === "WrongExpectedVersionError");
}

export async function appendWithGuard(
  store: EventStore,
  stream: string,
  events: TelemetryStreamEvent[],
): Promise<bigint> {
  const current = await store.readStream(stream);
  const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
  try {
    const out = await store.appendToStream(stream, events, { expectedRevision });
    return out.nextRevision;
  } catch (err) {
    if (isConflict(err)) throw new ConcurrencyConflict(stream, expectedRevision);
    throw err;
  }
}
