export interface StrategyState { id: string; active: boolean; version: number; }

export type StrategyEvent =
  | { type: "StrategyActivated" }
  | { type: "StrategyDeactivated" };

export const CURRENT_VERSION = 2;

export interface Snapshot<S> { version: number; state: S; }

interface StrategyV1 { id: string; enabled: boolean; }

function v1Tov2(prev: StrategyV1): StrategyState {
  return { id: prev.id, active: prev.enabled, version: 1 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<StrategyState> {
  if (snap.version === 1) {
    return { version: CURRENT_VERSION, state: v1Tov2(snap.state as StrategyV1) };
  }
  if (snap.version === CURRENT_VERSION) {
    return { version: CURRENT_VERSION, state: snap.state as StrategyState };
  }
  throw new Error("UNKNOWN_SNAPSHOT_VERSION");
}

export function evolve(state: StrategyState, event: StrategyEvent): StrategyState {
  switch (event.type) {
    case "StrategyActivated":
      return { ...state, active: true, version: state.version + 1 };
    case "StrategyDeactivated":
      return { ...state, active: false, version: state.version + 1 };
    default: { const _n: never = event; return state; }
  }
}

export function loadFromSnapshot(
  snap: Snapshot<unknown>,
  newerEvents: StrategyEvent[],
): StrategyState {
  const base = upgradeSnapshot(snap).state;
  return newerEvents.reduce<StrategyState>(evolve, base);
}

