An invoked promise actor iterates over selected ids, sending PROGRESS events to the parent via a fromCallback fan-in or assigning incrementally on each tick. Here we use a simpler shape: a PROGRESS event the UI emits per resolved item, and a FINISHED event for completion. Context tallies done and failed counters, and the parent transitions to complete when FINISHED arrives.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { total: number; done: number; failed: number }
type Ev = { type: 'START'; total: number } | { type: 'PROGRESS'; ok: boolean } | { type: 'FINISHED' };

export const batchProgress = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    begin: assign({ total: ({ event }) => (event.type === 'START' ? event.total : 0), done: () => 0, failed: () => 0 }),
    tick: assign({
      done: ({ context, event }) => context.done + (event.type === 'PROGRESS' && event.ok ? 1 : 0),
      failed: ({ context, event }) => context.failed + (event.type === 'PROGRESS' && !event.ok ? 1 : 0)
    })
  }
}).createMachine({
  id: 'batchProgress',
  context: { total: 0, done: 0, failed: 0 },
  initial: 'idle',
  states: {
    idle: { on: { START: { target: 'running', actions: 'begin' } } },
    running: { on: { PROGRESS: { actions: 'tick' }, FINISHED: 'done' } },
    done: { type: 'final' }
  }
});
```

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { token: string | null; user: string | null; error?: string };
type Ev =
  | { type: 'LOGIN'; username: string; password: string }
  | { type: 'LOGOUT' }
  | { type: 'EXPIRED' }
  | { type: 'REFRESH' };

const login = fromPromise<{ token: string; user: string }, { username: string; password: string }>(
  async ({ input }) => {
    const r = await fetch('/login', { method: 'POST', body: JSON.stringify(input) });
    return (await r.json()) as { token: string; user: string };
  }
);
const refresh = fromPromise<{ token: string }, { token: string }>(async ({ input }) => {
  const r = await fetch('/refresh', { method: 'POST', body: JSON.stringify(input) });
  return (await r.json()) as { token: string };
});

export const authMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { login, refresh }
}).createMachine({
  id: 'auth',
  initial: 'loggedOut',
  context: { token: null, user: null },
  states: {
    loggedOut: {
      on: { LOGIN: 'authenticating' }
    },
    authenticating: {
      invoke: {
        src: 'login',
        input: ({ event }) => {
          if (event.type !== 'LOGIN') throw new Error('bad event');
          return { username: event.username, password: event.password };
        },
        onDone: {
          target: 'loggedIn',
          actions: assign({
            token: ({ event }) => event.output.token,
            user: ({ event }) => event.output.user
          })
        },
        onError: {
          target: 'loggedOut',
          actions: assign({ error: () => 'Login failed' })
        }
      }
    },
    loggedIn: {
      on: {
        LOGOUT: { target: 'loggedOut', actions: assign({ token: () => null, user: () => null }) },
        EXPIRED: 'refreshing',
        REFRESH: 'refreshing'
      }
    },
    refreshing: {
      invoke: {
        src: 'refresh',
        input: ({ context }) => ({ token: context.token ?? '' }),
        onDone: {
          target: 'loggedIn',
          actions: assign({ token: ({ event }) => event.output.token })
        },
        onError: {
          target: 'loggedOut',
          actions: assign({ token: () => null, user: () => null })
        }
      }
    }
  }
});
