After debouncing, use an `always` transition guarded on `context.query.length === 0` to short-circuit to an `empty` state instead of invoking the promise actor.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { query: string; results: string[] };
type Ev = { type: 'CHANGE'; value: string };

export const emptySkipSearch = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { DEBOUNCE: 300 },
  actors: {
    search: fromPromise(
      async ({ input }: { input: { q: string } }): Promise<string[]> => {
        await new Promise((r) => setTimeout(r, 100));
        return [input.q];
      }
    )
  },
  guards: {
    isBlank: ({ context }) => context.query.trim().length === 0
  }
}).createMachine({
  id: 'empty-skip',
  initial: 'idle',
  context: { query: '', results: [] },
  states: {
    idle: { on: { CHANGE: { target: 'debouncing', actions: assign({ query: ({ event }) => event.value }) } } },
    debouncing: {
      on: { CHANGE: { target: 'debouncing', reenter: true, actions: assign({ query: ({ event }) => event.value }) } },
      after: { DEBOUNCE: 'decide' }
    },
    decide: {
      always: [
        { target: 'empty', guard: 'isBlank' },
        { target: 'loading' }
      ]
    },
    loading: {
      invoke: {
        src: 'search',
        input: ({ context }) => ({ q: context.query }),
        onDone: { target: 'idle', actions: assign({ results: ({ event }) => event.output }) }
      }
    },
    empty: { on: { CHANGE: { target: 'debouncing', actions: assign({ query: ({ event }) => event.value }) } } }
  }
});
