```typescript
type FanClubEvent =
  | { type: 'MemberJoined'; memberId: string }
  | { type: 'MemberLeft'; memberId: string };

type FanClubCommand =
  | { type: 'Join'; memberId: string }
  | { type: 'Leave'; memberId: string };

type FanClubState = { readonly members: readonly string[] };

const initial: FanClubState = { members: [] };

function evolve(state: FanClubState, event: FanClubEvent): FanClubState {
  switch (event.type) {
    case 'MemberJoined': return { members: [...state.members, event.memberId] };
    case 'MemberLeft': return { members: state.members.filter((m) => m !== event.memberId) };
    default: { const _e: never = event; return _e; }
  }
}

function decide(cmd: FanClubCommand, state: FanClubState): FanClubEvent[] {
  switch (cmd.type) {
    case 'Join': return state.members.includes(cmd.memberId) ? [] : [{ type: 'MemberJoined', memberId: cmd.memberId }];
    case 'Leave': return !state.members.includes(cmd.memberId) ? [] : [{ type: 'MemberLeft', memberId: cmd.memberId }];
    default: { const _e: never = cmd; return _e; }
  }
}

interface EventStore {
  readStream(s: string): AsyncIterable<FanClubEvent>;
  appendToStream(s: string, evs: readonly FanClubEvent[]): Promise<void>;
}

interface FanView { readonly id: string; readonly memberCount: number }
interface ReadStore { get(id: string): Promise<FanView | null> }

// Read side is eventually consistent — a projection feeds ReadStore from the event stream.
export async function handleCommand(id: string, cmd: FanClubCommand, store: EventStore): Promise<void> {
  let state = initial;
  for await (const ev of store.readStream(`fanclub-${id}`)) state = evolve(state, ev);
  const events = decide(cmd, state);
  if (events.length > 0) await store.appendToStream(`fanclub-${id}`, events);
}

export async function queryView(id: string, rs: ReadStore): Promise<FanView | null> {
  return rs.get(id);
}
