  | { type: 'ParkingSessionLogEnded'; at: string };
```

```typescript
export type ParkingSessionLogEvent =
  | { type: "ParkingSessionLogStarted"; id: string; zone: string }
  | { type: "ParkingSessionLogMetered"; amount: number }
  | { type: "ParkingSessionLogEnded"; at: string };

export type ParkingSessionLog = Readonly<{
  id: string;
  zone: string;
  totalCharged: number;
  endedAt?: string;
  status: "active" | "ended";
}>;

export function when(
  current: Partial<ParkingSessionLog>,
  event: ParkingSessionLogEvent,
): Partial<ParkingSessionLog> {
  switch (event.type) {
    case "ParkingSessionLogStarted":
      return { id: event.id, zone: event.zone, totalCharged: 0, status: "active" };
    case "ParkingSessionLogMetered":
      return { ...current, totalCharged: (current.totalCharged ?? 0) + event.amount };
    case "ParkingSessionLogEnded":
      return { ...current, status: "ended", endedAt: event.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

function isParkingSessionLog(v: Partial<ParkingSessionLog>): v is ParkingSessionLog {
  return !!v.id && !!v.zone && typeof v.totalCharged === "number" && !!v.status;
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const folded = events.reduce<Partial<A>>(reducer, {});
  if (!check(folded)) throw new Error("INCOMPLETE");
  return folded;
}

export function replay(events: ParkingSessionLogEvent[]): ParkingSessionLog {
  return aggregateStream<ParkingSessionLog, ParkingSessionLogEvent>(events, when, isParkingSessionLog);
}
```

