export type BOMEvent =
  | { type: "BOMRevisionDrafted"; revisionId: string; author: string }
  | { type: "BOMRevisionPublished"; revisionId: string; at: string }
  | { type: "BOMRevisionNotesAdded"; revisionId: string; notes: string };

