  revisionId: string;
  author: string;
  publishedAt: string | null;
}

export interface BOMView {
  readonly byRevision: Readonly<Record<string, BOMRow>>;
}

export const emptyView: BOMView = { byRevision: {} };

export function project(view: BOMView, event: BOMEvent): BOMView {
  switch (event.type) {
    case "BOMRevisionDrafted": {
      const row: BOMRow = { revisionId: event.revisionId, author: event.author, publishedAt: null };
      return { byRevision: { ...view.byRevision, [event.revisionId]: row } };
    }
    case "BOMRevisionPublished": {
      const row = view.byRevision[event.revisionId];
      if (!row) return view;
      return { byRevision: { ...view.byRevision, [event.revisionId]: { ...row, publishedAt: event.at } } };
    }
    case "BOMRevisionNotesAdded":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
