export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; roomId: string }
  | { type: "BidPlaced"; roomId: string; bidder: string; amount: number }
  | { type: "AuctionRoomClosed"; roomId: string; winner: string | null; amount: number };

