  | { type: "ChargeBidder"; roomId: string; bidder: string; amount: number }
  | { type: "AlertFraud"; roomId: string; bidder: string; amount: number };

const FRAUD_THRESHOLD_CENTS = 1_000_000;

export function react(event: AuctionRoomEvent): OutboundCommand | null {
  switch (event.type) {
    case "AuctionRoomOpened":
      return null;
    case "BidPlaced":
