      return null;
    case "AuctionRoomClosed":
      if (event.winner === null) return null;
      return { type: "ChargeBidder", roomId: event.roomId, bidder: event.winner, amount: event.amount };
    default: {
      const _never: never = event;
      return null;
    }
  }
