  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    loadPage: fromPromise<readonly Item[], { page: number }>(({ input }) => fetchPage(input.page))
  }
}).createMachine({
  id: 'feed',
  initial: 'idle',
  context: { items: [], page: 0 },
  states: {
    idle: { on: { LOAD: 'loading' } },
    loading: {
      invoke: {
        src: 'loadPage',
        input: ({ context }) => ({ page: context.page }),
        onDone: {
          target: 'idle',
          actions: assign({
            items: ({ context, event }) => [...context.items, ...event.output],
            page: ({ context }) => context.page + 1
          })
        },
        onError: 'error'
      }
    },
    error: { on: { RETRY: 'loading' } }
  }
