export type RevisionEvent =
  | { type: "RevisionStarted"; id: string; fromVersion: string }
  | { type: "RevisionNoteAdded"; note: string }
  | { type: "RevisionAccepted"; at: string }
  | { type: "RevisionRejected"; reason: string };

export type RevisionState =
  | { status: "none" }
  | { status: "open"; id: string; fromVersion: string; notes: string[] }
  | { status: "accepted"; id: string; fromVersion: string; acceptedAt: string }
  | { status: "rejected"; id: string; reason: string };

export function when(state: RevisionState, event: RevisionEvent): RevisionState {
  switch (event.type) {
    case "RevisionStarted":
      return { status: "open", id: event.id, fromVersion: event.fromVersion, notes: [] };
    case "RevisionNoteAdded":
      if (state.status !== "open") return state;
      return { ...state, notes: [...state.notes, event.note] };
    case "RevisionAccepted":
      if (state.status !== "open") return state;
      return { status: "accepted", id: state.id, fromVersion: state.fromVersion, acceptedAt: event.at };
    case "RevisionRejected":
      if (state.status !== "open") return state;
      return { status: "rejected", id: state.id, reason: event.reason };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>, reducer: (s: S, e: E) => S, initial: S,
): Promise<S> {
  let acc = initial;
  for await (const e of stream) acc = reducer(acc, e);
  return acc;
}

export async function loadRevision(stream: AsyncIterable<RevisionEvent>): Promise<RevisionState> {
  return aggregateStream<RevisionState, RevisionEvent>(stream, when, { status: "none" });
}
