A parent can `invoke` a child machine registered in `setup.actors`. The child declares `types.output` and emits it from a `final` state's `output` function. The parent's `onDone` transition sees a typed `event.output`.

```typescript
import { setup, assign } from 'xstate';

const counterChild = setup({
  types: {
    context: {} as { n: number },
    events: {} as { type: 'TICK' } | { type: 'FINISH' },
    output: {} as { total: number }
  }
}).createMachine({
  id: 'counterChild',
  context: { n: 0 },
  initial: 'counting',
  states: {
    counting: {
      on: {
        TICK:   { actions: assign({ n: ({ context }) => context.n + 1 }) },
        FINISH: 'done'
      }
    },
    done: { type: 'final' }
  },
  output: ({ context }) => ({ total: context.n })
});

export const parentMachine = setup({
  types: { context: {} as { total: number } },
  actors: { counter: counterChild }
}).createMachine({
  id: 'parent',
  context: { total: 0 },
  initial: 'working',
  states: {
    working: {
      invoke: {
        id: 'c',
        src: 'counter',
        onDone: { target: 'done', actions: assign({ total: ({ event }) => event.output.total }) }
      }
    },
    done: { type: 'final' }
  }
});
```

A saga is a pure reactor: it consumes domain events from multiple aggregates and returns the next command to dispatch. State, if any, lives in the event streams themselves. Because `react` is a function of the inbound event, the whole workflow is replayable and testable without infrastructure.

```typescript
export type ReactableEvent =
  | { type: "LotReleased"; lotId: string; sku: string }
  | { type: "SerialIssued"; serialId: string; lotId: string; sku: string }
  | { type: "InventoryRecorded"; serialId: string };

export type SagaCommand =
  | { type: "IssueSerial"; lotId: string; sku: string }
  | { type: "RecordInventory"; serialId: string };

export function react(event: ReactableEvent): SagaCommand | null {
  switch (event.type) {
    case "LotReleased":
      return { type: "IssueSerial", lotId: event.lotId, sku: event.sku };
    case "SerialIssued":
      return { type: "RecordInventory", serialId: event.serialId };
    case "InventoryRecorded":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface CommandHandler<C> {
  handle(stream: string, command: C): Promise<void>;
}

export async function runSaga(
  events: AsyncIterable<ReactableEvent>,
  handler: CommandHandler<SagaCommand>,
): Promise<void> {
  async function main(): Promise<void> {
    for await (const event of events) {
      const next = react(event);
      if (next === null) continue;
      const stream = next.type === "IssueSerial" ? `lot-${next.lotId}` : `serial-${next.serialId}`;
      await handler.handle(stream, next);
    }
  }
  await main();
}
```

Use two invoked actors: `callApi` first; `onError` transitions to `refreshing`; after refresh, re-enter `callingApi` via `reenter: true`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { token: string | null; payload: string | null };
type Ev = { type: 'CALL' };

const callApi = fromPromise<string, { token: string | null }>(async ({ input }) => {
  if (!input.token) throw new Error('401');
  return 'data';
});
const refresh = fromPromise<string, void>(async () => 'new-token');

export const api = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { callApi, refresh },
}).createMachine({
  id: 'api',
  context: { token: null, payload: null },
  initial: 'idle',
  states: {
    idle: { on: { CALL: 'callingApi' } },
    callingApi: {
      invoke: {
        src: 'callApi',
        input: ({ context }) => ({ token: context.token }),
        onDone: {
          target: 'idle',
          actions: assign({ payload: ({ event }) => event.output }),
        },
        onError: { target: 'refreshing' },
      },
    },
    refreshing: {
      invoke: {
        src: 'refresh',
        onDone: {
          target: 'callingApi',
          reenter: true,
          actions: assign({ token: ({ event }) => event.output }),
        },
        onError: { target: 'idle' },
      },
    },
  },
});
