  const stored = await store.readStream(stream);
  const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  await store.appendToStream(stream, [{ type: "ItineraryBooked", id: cmd.id, pax: cmd.pax }], { expectedRevision });
}

export async function queryView(id: string, reads: ItinReadStore) {
  return reads.get(id);
}
