export type TicketEvent =
  | { type: "TicketOpened"; id: string; title: string }
  | { type: "TicketClosed"; at: string };

export type OutboxRow = {
  id: string;
  schema: string;
  payload: string;
  publishedAt: string | null;
};

export type ExpectedRevision = bigint | "no_stream";

export interface Transaction {
  appendEvents(
    stream: string,
    events: ReadonlyArray<TicketEvent>,
    options: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
  insertOutboxRows(rows: ReadonlyArray<OutboxRow>): Promise<void>;
}

export interface TransactionalConnection {
  run<R>(body: (tx: Transaction) => Promise<R>): Promise<R>;
}

// A separate publisher worker polls rows where publishedAt === null, publishes
// each to the integration bus, and then updates the row's publishedAt timestamp.
// This helper only guarantees the domain events and outbox rows are written
// atomically within one unit of work.
export async function appendTicketWithOutbox(
  conn: TransactionalConnection,
  stream: string,
  expectedRevision: ExpectedRevision,
  events: ReadonlyArray<TicketEvent>,
  outboxRows: ReadonlyArray<OutboxRow>,
): Promise<bigint> {
  return conn.run(async (tx) => {
    const nextRevision = await tx.appendEvents(stream, events, { expectedRevision });
    if (outboxRows.length > 0) {
      await tx.insertOutboxRows(outboxRows);
    }
    return nextRevision;
  });
}
