import { Effect } from 'effect';

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) state = evolve(state, event);
  return state;
}

type AlbumEvent = { type: 'TrackAdded'; title: string } | { type: 'Released'; at: string };
type AlbumState = { readonly tracks: readonly string[]; readonly released: boolean };
const initial: AlbumState = { tracks: [], released: false };

function evolve(state: AlbumState, event: AlbumEvent): AlbumState {
  switch (event.type) {
    case 'TrackAdded': return { ...state, tracks: [...state.tracks, event.title] };
    case 'Released': return { ...state, released: true };
    default: { const _e: never = event; return _e; }
  }
}

interface EventStore {
  readStream(s: string): AsyncIterable<AlbumEvent>;
}

export const loadAlbum = (store: EventStore, stream: string) =>
  Effect.gen(function* () {
    const state = yield* Effect.promise(() => aggregateStream<AlbumState, AlbumEvent>(store.readStream(stream), evolve, initial));
    return state;
  });
