  readStream(stream: string): AsyncIterable<DomainEvent>;
}

export interface Outbox {
  publish(event: IntegrationEvent): Promise<void>;
}

export async function forwardIntegrationEvents(store: EventStore, outbox: Outbox, stream: string): Promise<void> {
  for await (const domain of store.readStream(stream)) {
    const integration = translate(domain);
    if (integration) await outbox.publish(integration);
