export async function safeAppend(
  store: EventStore<ApartmentEvent>,
  stream: string,
  events: ApartmentEvent[],
): Promise<bigint> {
  const lastRevision = await store.readStreamRevision(stream);
  const expectedRevision: bigint | "no_stream" = lastRevision === null ? "no_stream" : lastRevision;
  try {
    const { nextRevision } = await store.appendToStream(stream, events, { expectedRevision });
    return nextRevision;
  } catch (err) {
    if (err instanceof Error && /wrong.?expected/i.test(err.message)) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
