import { Effect } from "effect";

export type RefundState =
  | { status: "none" }
  | { status: "pending"; id: string; amount: number }
  | { status: "settled"; id: string; amount: number; settledAt: string };

export type RefundCommand =
  | { type: "initiate"; id: string; amount: number }
  | { type: "settle"; at: string };

export type RefundEvent =
  | { type: "RefundInitiated"; id: string; amount: number }
  | { type: "RefundSettled"; at: string };

export class DomainError extends Error {}

export const initialState: RefundState = { status: "none" };

export function evolve(s: RefundState, e: RefundEvent): RefundState {
  switch (e.type) {
    case "RefundInitiated": return { status: "pending", id: e.id, amount: e.amount };
    case "RefundSettled":
      if (s.status !== "pending") return s;
      return { status: "settled", id: s.id, amount: s.amount, settledAt: e.at };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: RefundCommand, s: RefundState): RefundEvent[] {
  switch (c.type) {
    case "initiate":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "RefundInitiated", id: c.id, amount: c.amount }];
    case "settle":
      if (s.status !== "pending") throw new DomainError("NOT_PENDING");
      return [{ type: "RefundSettled", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: RefundEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: ReadonlyArray<RefundEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handleRefund = (
  store: EventStore,
  streamName: string,
  command: RefundCommand,
) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => store.readStream(streamName));
    const state = events.reduce(evolve, initialState);
    const produced = decide(command, state);
    if (produced.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() =>
      store.appendToStream(streamName, produced, { expectedRevision }),
    );
  });
```

Open a transaction, insert outbox rows, appendToStream, commit. A separate worker polls the outbox and marks rows as published.

```typescript
export type PullRequestEvent =
  | { type: "PullRequestMerged"; id: string; at: string }
  | { type: "PullRequestClosed"; id: string; reason: string };

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export interface TransactionalConnection {
  begin(): Promise<Transaction>;
}

export interface Transaction {
  appendToStream(stream: string, events: PullRequestEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
  insertOutbox(rows: OutboxRow[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

// A separate worker polls unpublished outbox rows and marks publishedAt after delivery.
export async function appendWithOutbox(
  conn: TransactionalConnection,
  streamName: string,
  events: PullRequestEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<void> {
  const tx = await conn.begin();
  try {
    await tx.appendToStream(streamName, events, { expectedRevision });
    await tx.insertOutbox(outboxRows);
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
```

