import { Effect } from "effect";

export type LectureState =
  | { status: "none" }
  | { status: "scheduled"; id: string; title: string; starts: string }
  | { status: "cancelled"; id: string };

export type LectureEvent =
  | { type: "LectureScheduled"; id: string; title: string; starts: string }
  | { type: "LectureCancelled" };

export const initialState: LectureState = { status: "none" };

export function evolve(state: LectureState, event: LectureEvent): LectureState {
  switch (event.type) {
    case "LectureScheduled":
      return { status: "scheduled", id: event.id, title: event.title, starts: event.starts };
    case "LectureCancelled":
      if (state.status !== "scheduled") return state;
      return { status: "cancelled", id: state.id };
    default: { const _n: never = event; return state; }
  }
}

export interface LectureStore {
  readFromStream(streamName: string): AsyncIterable<LectureEvent>;
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let acc: S = initial;
  for await (const event of stream) {
    acc = fold(acc, event);
  }
  return acc;
}

export const loadLecture = (streamName: string, store: LectureStore) =>
  Effect.gen(function* () {
    const state = yield* Effect.promise(() =>
      aggregateStream(store.readFromStream(streamName), evolve, initialState),
    );
    return state;
  });
