export type LedgerAccountEvent =
  | { type: "LedgerAccountOpened"; id: string; owner: string; openingBalance: number }
  | { type: "LedgerCredited"; amount: number; at: string }
  | { type: "LedgerDebited"; amount: number; at: string }
  | { type: "LedgerClosed"; at: string };

export type LedgerAccount = Readonly<{
  id: string;
  owner: string;
  balance: number;
  txCount: number;
  closedAt: string | null;
}>;

export const emptyAccount: LedgerAccount = {
  id: "",
  owner: "",
  balance: 0,
  txCount: 0,
  closedAt: null,
};

export function when(state: LedgerAccount, event: LedgerAccountEvent): LedgerAccount {
  switch (event.type) {
    case "LedgerAccountOpened":
      return { id: event.id, owner: event.owner, balance: event.openingBalance, txCount: 0, closedAt: null };
    case "LedgerCredited":
      return { ...state, balance: state.balance + event.amount, txCount: state.txCount + 1 };
    case "LedgerDebited":
      return { ...state, balance: state.balance - event.amount, txCount: state.txCount + 1 };
    case "LedgerClosed":
      return { ...state, closedAt: event.at };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregate(events: LedgerAccountEvent[]): LedgerAccount {
  return events.reduce(when, emptyAccount);
}
