              return next.length > MAX ? next.slice(next.length - MAX) : next;
            },
            value: ({ event }) => event.value
          })
        },
        UNDO: {
          guard: 'hasHistory',
          actions: assign({
            value: ({ context }) => context.history[context.history.length - 1] ?? context.value,
            history: ({ context }) => context.history.slice(0, -1)
          })
        }
      }
    }
  }
});
