        case 1:
          return { type: "PullRequestOpened", id: raw.id, branch: raw.branch, author: "unknown", baseBranch: "main" };
        case 2:
          return { type: "PullRequestOpened", id: raw.id, branch: raw.branch, author: raw.author, baseBranch: "main" };
