        default: {
          const _never: never = raw;
          throw new UnknownEventError(JSON.stringify(raw));
        }
      }
    case "PullRequestMerged":
      return { type: "PullRequestMerged", id: raw.id, at: raw.at };
    default: {
      const _never: never = raw;
      throw new UnknownEventError(JSON.stringify(raw));
