export type MovementEvent =
  | { type: "SkuReceived"; sku: string; qty: number; revision: bigint }
  | { type: "SkuPicked"; sku: string; qty: number; revision: bigint };

export interface MovementView { readonly totals: Readonly<Record<string, number>>; }
export const emptyView: MovementView = { totals: {} };

export function project(v: MovementView, e: MovementEvent): MovementView {
  const cur = v.totals[e.sku] ?? 0;
  switch (e.type) {
    case "SkuReceived": return { totals: { ...v.totals, [e.sku]: cur + e.qty } };
    case "SkuPicked": return { totals: { ...v.totals, [e.sku]: cur - e.qty } };
    default: { const _n: never = e; return v; }
  }
}

export interface EventReader {
  readStream(opts: { from: bigint; batchSize: number }): AsyncIterable<ReadonlyArray<MovementEvent>>;
}

export interface ViewStore {
  persist(view: MovementView, throughRevision: bigint): Promise<void>;
}

export interface RebuildOptions {
  readonly from: bigint;
  readonly batchSize: number;
  readonly onProgress?: (cursor: bigint, applied: number) => void;
}

export async function rebuild(reader: EventReader, store: ViewStore, opts: RebuildOptions): Promise<void> {
  let view: MovementView = emptyView;
  let cursor: bigint = opts.from;
  let applied = 0;
  async function main(): Promise<void> {
    for await (const batch of reader.readStream({ from: cursor, batchSize: opts.batchSize })) {
      for (const event of batch) {
        view = project(view, event);
        cursor = event.revision;
        applied += 1;
      }
      await store.persist(view, cursor);
      opts.onProgress?.(cursor, applied);
    }
  }
  await main();
}
