  | { type: "BuildRunFinished"; runId: string }
  | { type: "BuildRunFailed"; runId: string; reason: string };

export interface EventEnvelope<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface ReadModel<V, E> {
  load(): Promise<V>;
  persist(view: V): Promise<void>;
  project(view: V, event: E): V;
}

export interface EventFeed<E> {
  readFrom(position: bigint | null): AsyncIterable<EventEnvelope<E>>;
}

export async function runFeed<V extends object>(
  name: string,
  checkpoints: CheckpointStore,
  feed: EventFeed<BuildRunEvent>,
  readModel: ReadModel<V, BuildRunEvent>,
): Promise<void> {
  const start = await checkpoints.read(name);
  let view: V = await readModel.load();
  for await (const envelope of feed.readFrom(start)) {
    view = readModel.project(view, envelope.event);
    await readModel.persist(view);
    await checkpoints.write(name, envelope.position);
  }
}
