export const CURRENT_VERSION = 3;

export interface FarmStateV1 {
  readonly id: string;
  readonly owner: string;
}

export interface FarmStateV2 {
  readonly id: string;
  readonly owner: string;
  readonly hectares: number;
}

export interface FarmStateV3 {
  readonly id: string;
  readonly owner: string;
  readonly hectares: number;
  readonly activeCrops: number;
}

export type FarmCurrentState = FarmStateV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(s: FarmStateV1): FarmStateV2 {
  return { ...s, hectares: 0 };
}

function v2Tov3(s: FarmStateV2): FarmStateV3 {
  return { ...s, activeCrops: 0 };
}

function isV1(s: unknown): s is FarmStateV1 {
  return typeof s === "object" && s !== null && "id" in s && "owner" in s;
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<FarmCurrentState> {
  if (raw.version === CURRENT_VERSION) {
    return { version: CURRENT_VERSION, state: raw.state as FarmCurrentState };
  }
  let version = raw.version;
  let state: unknown = raw.state;
  if (version === 1) {
    if (!isV1(state)) throw new Error("CORRUPT_V1_STATE");
    state = v1Tov2(state);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as FarmStateV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${raw.version}`);
  return { version: CURRENT_VERSION, state: state as FarmCurrentState };
}
