export type AttestationState =
  | { status: "none" }
  | { status: "issued"; id: string; subject: string; by: string }
  | { status: "countersigned"; id: string; subject: string; by: string; countersignedBy: string }
  | { status: "revoked"; id: string; reason: string };

export type AttestationCommand =
  | { type: "issue"; id: string; subject: string; by: string }
  | { type: "countersign"; by: string }
  | { type: "revoke"; reason: string };

export type AttestationEvent =
  | { type: "AttestationIssued"; id: string; subject: string; by: string }
  | { type: "AttestationCountersigned"; by: string }
  | { type: "AttestationRevoked"; reason: string };

export class AttestationError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "AttestationError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const attestationDecider: Decider<AttestationCommand, AttestationEvent, AttestationState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "issue":
        if (state.status !== "none") throw new AttestationError("EXISTS");
        return [{ type: "AttestationIssued", id: command.id, subject: command.subject, by: command.by }];
      case "countersign":
        if (state.status === "revoked") throw new AttestationError("REVOKED");
        if (state.status !== "issued") throw new AttestationError("NOT_ISSUED");
        if (state.by === command.by) throw new AttestationError("SELF_SIGN");
        return [{ type: "AttestationCountersigned", by: command.by }];
      case "revoke":
        if (state.status === "revoked") return [];
        if (state.status === "none") throw new AttestationError("NOT_FOUND");
        return [{ type: "AttestationRevoked", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new AttestationError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AttestationIssued":
        return { status: "issued", id: event.id, subject: event.subject, by: event.by };
      case "AttestationCountersigned":
        if (state.status !== "issued") return state;
        return { status: "countersigned", id: state.id, subject: state.subject, by: state.by, countersignedBy: event.by };
      case "AttestationRevoked":
        if (state.status === "none") return state;
        return { status: "revoked", id: "id" in state ? state.id : "", reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
