export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface DailyRushV1 {
  readonly id: string;
  readonly clips: string[];
}

export interface DailyRushV2 {
  readonly id: string;
  readonly clips: string[];
  readonly approved: boolean;
}

export interface DailyRushV3 {
  readonly id: string;
  readonly clips: string[];
  readonly approved: boolean;
  readonly runtime: number;
}

export type CurrentDailyRush = DailyRushV3;
export const CURRENT_VERSION = 3;

const upgraders: Record<number, (s: unknown) => unknown> = {
  1: (s) => {
    const v1 = s as DailyRushV1;
    const out: DailyRushV2 = { ...v1, approved: false };
    return out;
  },
  2: (s) => {
    const v2 = s as DailyRushV2;
    const out: DailyRushV3 = { ...v2, runtime: 0 };
    return out;
  },
};

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDailyRush> {
  let version = snap.version;
  let state: unknown = snap.state;
  while (version < CURRENT_VERSION) {
    const step = upgraders[version];
    if (!step) throw new Error(`NO_UPGRADER_${version}`);
    state = step(state);
    version += 1;
  }
  if (version !== CURRENT_VERSION) throw new Error(`BAD_VERSION_${version}`);
  return { version, state: state as CurrentDailyRush };
}
