export type TicketEvent =
  | { type: "TicketOpened"; id: string; title: string }
  | { type: "TicketClosed"; at: string };

export type TicketState = { status: "none" } | { status: "open"; id: string; title: string };
export type TicketCommand =
  | { type: "openTicket"; id: string; title: string }
  | { type: "closeTicket"; at: string };

export class TicketError extends Error {}

export function evolve(s: TicketState, e: TicketEvent): TicketState {
  switch (e.type) {
    case "TicketOpened":
      return { status: "open", id: e.id, title: e.title };
    case "TicketClosed":
      return { status: "none" };
    default: {
      const _n: never = e;
      return s;
    }
  }
}

export function decide(c: TicketCommand, s: TicketState): TicketEvent[] {
  switch (c.type) {
    case "openTicket":
      if (s.status !== "none") throw new TicketError("EXISTS");
      return [{ type: "TicketOpened", id: c.id, title: c.title }];
    case "closeTicket":
      if (s.status !== "open") throw new TicketError("NOT_OPEN");
      return [{ type: "TicketClosed", at: c.at }];
    default: {
      const _n: never = c;
      throw new TicketError("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream(s: string): Promise<{ events: TicketEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: readonly TicketEvent[], o: { expectedRevision: bigint | "no_stream" }): Promise<bigint>;
}

export type TicketListingView = Readonly<{ id: string; title: string; status: "open" | "closed" }>;

export interface ReadStore {
  getById(id: string): Promise<TicketListingView | null>;
}

// write side
export async function handleCommand(
  store: EventStore,
  streamName: string,
  command: TicketCommand,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, { status: "none" } as TicketState);
  const produced = decide(command, state);
  if (produced.length === 0) return;
  await store.appendToStream(streamName, produced, { expectedRevision: revision ?? "no_stream" });
}

// read side - eventually consistent with the event store, populated by a subscription
export async function queryView(read: ReadStore, id: string): Promise<TicketListingView | null> {
  return read.getById(id);
}
