  const tx = await conn.begin();
  try {
    await tx.appendToStream(stream, events, { expectedRevision: "no_stream" });
    for (const row of outboxRows) await tx.insertOutbox(row);
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
