// read store is eventually consistent with the event store.
export type RunArtifactCommand =
  | { type: "register"; id: string; uri: string }
  | { type: "supersede"; by: string };

export type RunArtifactEvent =
  | { type: "RunArtifactRegistered"; id: string; uri: string }
  | { type: "RunArtifactSuperseded"; by: string };

type WriteState =
  | { status: "none" }
  | { status: "active"; id: string; uri: string }
  | { status: "superseded"; id: string; by: string };

const initial: WriteState = { status: "none" };

function evolve(state: WriteState, event: RunArtifactEvent): WriteState {
  switch (event.type) {
    case "RunArtifactRegistered":
      return { status: "active", id: event.id, uri: event.uri };
    case "RunArtifactSuperseded":
      return state.status === "active" ? { status: "superseded", id: state.id, by: event.by } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: RunArtifactCommand, state: WriteState): RunArtifactEvent[] {
  switch (command.type) {
    case "register":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "RunArtifactRegistered", id: command.id, uri: command.uri }];
    case "supersede":
      if (state.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "RunArtifactSuperseded", by: command.by }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export type RunArtifactView = { id: string; uri: string; active: boolean };
export interface ReadStore { get(id: string): Promise<RunArtifactView | null>; }

export async function handleCommand(command: RunArtifactCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  const read = await ctx.eventStore.readStream<RunArtifactEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
}

export async function queryRunArtifact(id: string, store: ReadStore): Promise<RunArtifactView | null> {
  return store.get(id);
}
