```typescript
export type OrderEvent =
  | { type: "OrderPlaced"; id: string; total: number }
  | { type: "OrderPaid"; id: string; at: string }
  | { type: "OrderCancelled"; id: string; reason: string };

export type OrderDashboard = Readonly<{
  totalPlaced: number;
  totalPaid: number;
  totalCancelled: number;
  revenue: number;
}>;

export const emptyDashboard: OrderDashboard = { totalPlaced: 0, totalPaid: 0, totalCancelled: 0, revenue: 0 };

export function project(view: OrderDashboard, event: OrderEvent): OrderDashboard {
  switch (event.type) {
    case "OrderPlaced":
      return { ...view, totalPlaced: view.totalPlaced + 1, revenue: view.revenue + event.total };
    case "OrderPaid":
      return { ...view, totalPaid: view.totalPaid + 1 };
    case "OrderCancelled":
      return { ...view, totalCancelled: view.totalCancelled + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface BatchReader<E> {
  readBatch(from: bigint, size: number): Promise<ReadonlyArray<{ position: bigint; event: E }>>;
}

export interface DashboardStore {
  wipe(): Promise<void>;
  save(view: OrderDashboard, cursor: bigint): Promise<void>;
}

export async function rebuildOrderDashboard(
  reader: BatchReader<OrderEvent>,
  store: DashboardStore,
  options: { from: bigint; batchSize: number; onProgress?: (cursor: bigint) => void },
): Promise<bigint> {
  if (options.from === 0n) await store.wipe();
  let view = emptyDashboard;
  let cursor = options.from;
  while (true) {
    const batch = await reader.readBatch(cursor, options.batchSize);
    if (batch.length === 0) return cursor;
    for (const { position, event } of batch) {
      view = project(view, event);
      cursor = position + 1n;
    }
    await store.save(view, cursor);
    options.onProgress?.(cursor);
    if (batch.length < options.batchSize) return cursor;
  }
}
