```typescript
export type ManuscriptState =
  | { status: "empty" }
  | { status: "open"; id: string; chapters: string[] }
  | { status: "locked"; id: string; chapters: string[]; lockedAt: string };

export type ManuscriptCommand =
  | { type: "start"; id: string }
  | { type: "addChapter"; chapterId: string }
  | { type: "lock"; at: string };

export type ManuscriptEvent =
  | { type: "ManuscriptStarted"; id: string }
  | { type: "ChapterAppended"; chapterId: string }
  | { type: "ManuscriptLocked"; at: string };

export class ManuscriptError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "ManuscriptError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const manuscriptDecider: Decider<ManuscriptCommand, ManuscriptEvent, ManuscriptState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "start":
        if (state.status !== "empty") throw new ManuscriptError("EXISTS");
        return [{ type: "ManuscriptStarted", id: command.id }];
      case "addChapter":
        if (state.status === "locked") throw new ManuscriptError("LOCKED");
        if (state.status !== "open") throw new ManuscriptError("NOT_STARTED");
        if (state.chapters.includes(command.chapterId)) throw new ManuscriptError("DUPLICATE");
        return [{ type: "ChapterAppended", chapterId: command.chapterId }];
      case "lock":
        if (state.status !== "open") throw new ManuscriptError("NOT_OPEN");
        if (state.chapters.length === 0) throw new ManuscriptError("EMPTY");
        return [{ type: "ManuscriptLocked", at: command.at }];
      default: {
        const _n: never = command;
        throw new ManuscriptError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ManuscriptStarted":
        return { status: "open", id: event.id, chapters: [] };
      case "ChapterAppended":
        if (state.status !== "open") return state;
        return { ...state, chapters: [...state.chapters, event.chapterId] };
      case "ManuscriptLocked":
        if (state.status !== "open") return state;
        return { status: "locked", id: state.id, chapters: state.chapters, lockedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
