export type TranscriptCommand =
  | { type: "start"; id: string; locale: string }
  | { type: "addSegment"; tStart: number; tEnd: number; text: string }
  | { type: "publish"; at: string };

export type TranscriptEvent =
  | { type: "TranscriptStarted"; id: string; locale: string }
  | { type: "TranscriptSegmentAdded"; tStart: number; tEnd: number; text: string }
  | { type: "TranscriptPublished"; at: string };

export type TranscriptState =
  | { status: "none" }
  | { status: "drafting"; id: string; locale: string; segments: number }
  | { status: "published"; id: string; locale: string; segments: number; publishedAt: string };

export const initialState: TranscriptState = { status: "none" };

export function evolve(state: TranscriptState, event: TranscriptEvent): TranscriptState {
  switch (event.type) {
    case "TranscriptStarted":
      return { status: "drafting", id: event.id, locale: event.locale, segments: 0 };
    case "TranscriptSegmentAdded":
      if (state.status !== "drafting") return state;
      return { ...state, segments: state.segments + 1 };
    case "TranscriptPublished":
      if (state.status !== "drafting") return state;
      return { status: "published", id: state.id, locale: state.locale, segments: state.segments, publishedAt: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: TranscriptCommand, state: TranscriptState): TranscriptEvent[] {
  switch (command.type) {
    case "start":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "TranscriptStarted", id: command.id, locale: command.locale }];
    case "addSegment":
      if (state.status !== "drafting") throw new Error("NOT_DRAFTING");
      if (command.tEnd <= command.tStart) throw new Error("BAD_RANGE");
      return [{ type: "TranscriptSegmentAdded", tStart: command.tStart, tEnd: command.tEnd, text: command.text }];
    case "publish":
      if (state.status !== "drafting") throw new Error("NOT_DRAFTING");
      if (state.segments === 0) throw new Error("EMPTY");
      return [{ type: "TranscriptPublished", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export async function handle(
  store: EventStore<TranscriptEvent>,
  streamName: string,
  command: TranscriptCommand,
): Promise<void> {
  const loaded = await store.readStream(streamName);
  const state = loaded.events.reduce(evolve, initialState);
  const events = decide(command, state);
  await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
}
