```typescript
import { Effect } from "effect";

export type PantryStockState =
  | { status: "none" }
  | { status: "tracking"; id: string; grams: number };

export type PantryStockCommand =
  | { type: "open"; id: string }
  | { type: "stock"; grams: number }
  | { type: "draw"; grams: number };

export type PantryStockEvent =
  | { type: "PantryStockOpened"; id: string }
  | { type: "PantryStocked"; grams: number }
  | { type: "PantryDrawn"; grams: number };

export const initialPantry: PantryStockState = { status: "none" };

export function decide(c: PantryStockCommand, s: PantryStockState): PantryStockEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "PantryStockOpened", id: c.id }];
    case "stock":
      if (s.status !== "tracking") throw new Error("NOT_TRACKING");
      if (c.grams <= 0) throw new Error("BAD_GRAMS");
      return [{ type: "PantryStocked", grams: c.grams }];
    case "draw":
      if (s.status !== "tracking") throw new Error("NOT_TRACKING");
      if (c.grams > s.grams) throw new Error("INSUFFICIENT");
      return [{ type: "PantryDrawn", grams: c.grams }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: PantryStockState, e: PantryStockEvent): PantryStockState {
  switch (e.type) {
    case "PantryStockOpened":
      return { status: "tracking", id: e.id, grams: 0 };
    case "PantryStocked":
      if (s.status !== "tracking") return s;
      return { ...s, grams: s.grams + e.grams };
    case "PantryDrawn":
      if (s.status !== "tracking") return s;
      return { ...s, grams: s.grams - e.grams };
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: PantryStockEvent }>>;
  appendToStream(stream: string, events: readonly PantryStockEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export function handle(store: EventStore, stream: string, command: PantryStockCommand) {
  return Effect.gen(function* () {
    const stored = yield* Effect.promise(() => store.readStream(stream));
    const state = stored.reduce<PantryStockState>((s, { event }) => evolve(s, event), initialPantry);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const events = decide(command, state);
    yield* Effect.promise(() => store.appendToStream(stream, events, { expectedRevision: expected }));
  });
}

