Pause is just a transition from `uploading` to `paused`; because the chunk counter lives in context, resuming re-invokes the actor starting from the saved index. The running chunk is cancelled automatically when `uploading` is exited.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { uploaded: number; total: number };
type Ev = { type: 'START' } | { type: 'PAUSE' } | { type: 'RESUME' };

export const pauseResume = setup({
  types: { context: {} as Ctx, events: {} as Ev, input: {} as { total: number } },
  actors: {
    chunk: fromPromise(async ({ input }: { input: { index: number } }) => {
      await new Promise((r) => setTimeout(r, 30));
      return input.index;
    })
  },
  guards: {
    hasMore: ({ context }) => context.uploaded < context.total
  }
}).createMachine({
  id: 'pause-resume',
  initial: 'uploading',
  context: ({ input }) => ({ uploaded: 0, total: input.total }),
  states: {
    uploading: {
      invoke: {
        src: 'chunk',
        input: ({ context }) => ({ index: context.uploaded }),
        onDone: [
          {
            target: 'uploading',
            guard: 'hasMore',
            reenter: true,
            actions: assign({ uploaded: ({ context }) => context.uploaded + 1 })
          },
          { target: 'done', actions: assign({ uploaded: ({ context }) => context.uploaded + 1 }) }
        ]
      },
      on: { PAUSE: 'paused' }
    },
    paused: { on: { RESUME: 'uploading' } },
    done: { type: 'final' }
  }
});
