Refactor this v5 machine to use named guards and actions declared in setup:

```typescript
import { setup, assign } from 'xstate';

export const m = setup({
  types: { context: {} as { n: number }, events: {} as { type: 'INC' } }
}).createMachine({
  id: 'm',
  context: { n: 0 },
  initial: 'a',
  states: {
    a: {
      on: {
        INC: {
          guard: ({ context }) => context.n < 10,
          actions: assign({ n: ({ context }) => context.n + 1 })
        }
      }
    }
  }
});
```

Lift the inline guard and action into `setup.guards` and `setup.actions`, then reference them by string. This gives better inference and reuse.

```typescript
import { setup, assign } from 'xstate';

export const m = setup({
  types: { context: {} as { n: number }, events: {} as { type: 'INC' } },
  guards: {
    underLimit: ({ context }) => context.n < 10
  },
  actions: {
    bump: assign({ n: ({ context }) => context.n + 1 })
  }
}).createMachine({
  id: 'm',
  context: { n: 0 },
  initial: 'a',
  states: {
    a: {
      on: {
        INC: {
          guard: 'underLimit',
          actions: 'bump'
        }
      }
    }
  }
});
```

```typescript
export type PaintingEvent =
  | { type: "PaintingCatalogued"; id: string; artist: string }
  | { type: "PaintingAuthenticated"; id: string; cert: string }
  | { type: "PaintingRejected"; id: string; reason: string };

export interface PaintingView {
  readonly authenticated: number;
  readonly rejected: number;
}

const empty: PaintingView = { authenticated: 0, rejected: 0 };

function project(view: PaintingView, event: PaintingEvent): PaintingView {
  switch (event.type) {
    case "PaintingCatalogued":
      return view;
    case "PaintingAuthenticated":
      return { ...view, authenticated: view.authenticated + 1 };
    case "PaintingRejected":
      return { ...view, rejected: view.rejected + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventCursor<E> {
  from(position: bigint | null): AsyncIterable<{ position: bigint; event: E }>;
}

export async function runSubscription(
  name: string,
  cursor: EventCursor<PaintingEvent>,
  checkpoints: CheckpointStore,
  save: (view: PaintingView) => Promise<void>
): Promise<void> {
  const start = await checkpoints.read(name);
  let view = empty;
  for await (const { position, event } of cursor.from(start)) {
    view = project(view, event);
    await save(view);
    await checkpoints.write(name, position);
  }
}
