```typescript
import { Effect } from "effect";

export type PackingState =
  | { status: "idle" }
  | { status: "packing"; id: string; items: number };

export type PackingCommand =
  | { type: "start"; id: string }
  | { type: "scan"; sku: string };

export type PackingEvent =
  | { type: "PackingStarted"; id: string }
  | { type: "PackingItemScanned"; sku: string };

export class PackingError extends Error {}
export const initialState: PackingState = { status: "idle" };

export function evolve(s: PackingState, e: PackingEvent): PackingState {
  switch (e.type) {
    case "PackingStarted": return { status: "packing", id: e.id, items: 0 };
    case "PackingItemScanned":
      if (s.status !== "packing") return s;
      return { ...s, items: s.items + 1 };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: PackingCommand, s: PackingState): PackingEvent[] {
  switch (c.type) {
    case "start":
      if (s.status !== "idle") throw new PackingError("BUSY");
      return [{ type: "PackingStarted", id: c.id }];
    case "scan":
      if (s.status !== "packing") throw new PackingError("NOT_PACKING");
      return [{ type: "PackingItemScanned", sku: c.sku }];
    default: { const _n: never = c; throw new PackingError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<PackingEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<PackingEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handlePackingCommand = (
  stream: string,
  command: PackingCommand,
  store: EventStore,
) =>
  Effect.gen(function* () {
    const slice = yield* Effect.promise(() => store.readStream(stream));
    const state = slice.events.reduce(evolve, initialState);
    const out = decide(command, state);
    if (out.length === 0) return slice.revision ?? -1n;
    return yield* Effect.promise(() =>
      store.appendToStream(stream, out, { expectedRevision: slice.revision ?? "no_stream" }),
    );
  });
```

```typescript
export type MatchState =
  | { status: "none" }
  | { status: "scheduled"; id: string; home: string; away: string }
  | { status: "live"; id: string; home: string; away: string; homeGoals: number; awayGoals: number }
  | { status: "final"; id: string; home: string; away: string; homeGoals: number; awayGoals: number };

export type MatchCommand =
  | { type: "schedule"; id: string; home: string; away: string }
  | { type: "kickoff" }
  | { type: "goal"; side: "home" | "away" };

export type MatchEvent =
  | { type: "MatchScheduled"; id: string; home: string; away: string }
  | { type: "MatchKickedOff" }
  | { type: "MatchGoalScored"; side: "home" | "away" };

export const initialMatch: MatchState = { status: "none" };

export function decide(c: MatchCommand, s: MatchState): MatchEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "MatchScheduled", id: c.id, home: c.home, away: c.away }];
    case "kickoff":
      if (s.status !== "scheduled") throw new Error("NOT_SCHEDULED");
      return [{ type: "MatchKickedOff" }];
    case "goal":
      if (s.status !== "live") throw new Error("NOT_LIVE");
      return [{ type: "MatchGoalScored", side: c.side }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: MatchState, e: MatchEvent): MatchState {
  switch (e.type) {
    case "MatchScheduled":
      return { status: "scheduled", id: e.id, home: e.home, away: e.away };
    case "MatchKickedOff":
      if (s.status !== "scheduled") return s;
      return { status: "live", id: s.id, home: s.home, away: s.away, homeGoals: 0, awayGoals: 0 };
    case "MatchGoalScored":
      if (s.status !== "live") return s;
      return e.side === "home"
        ? { ...s, homeGoals: s.homeGoals + 1 }
        : { ...s, awayGoals: s.awayGoals + 1 };
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: MatchEvent }>>;
  appendToStream(stream: string, events: readonly MatchEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export class CommandHandler {
  constructor(private readonly store: EventStore) {}
  async handle(streamName: string, command: MatchCommand): Promise<void> {
    const stored = await this.store.readStream(streamName);
    const state = stored.reduce<MatchState>((s, { event }) => evolve(s, event), initialMatch);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const events = decide(command, state);
    await this.store.appendToStream(streamName, events, { expectedRevision: expected });
  }
}
```

```typescript
export type TestEvent =
  | { type: "TestSuiteResultReported"; runId: string; cases: { name: string; outcome: "pass" | "fail" }[] }
  | { type: "TestSuiteRegistered"; id: string; name: string; testCount: number }
  | { type: "TestSuiteRunStarted"; runId: string; at: string };

export interface TestStats {
  readonly passes: number;
  readonly failures: number;
}

export interface FlakeView {
  readonly perTest: Record<string, TestStats>;
}

export const emptyView: FlakeView = { perTest: {} };

function mergeStats(view: FlakeView, name: string, pass: boolean): FlakeView {
  const prev = view.perTest[name] ?? { passes: 0, failures: 0 };
  const next: TestStats = {
    passes: prev.passes + (pass ? 1 : 0),
    failures: prev.failures + (pass ? 0 : 1),
  };
  return { perTest: { ...view.perTest, [name]: next } };
}

export function project(view: FlakeView, event: TestEvent): FlakeView {
  switch (event.type) {
    case "TestSuiteResultReported":
      return event.cases.reduce<FlakeView>(
        (acc, c) => mergeStats(acc, c.name, c.outcome === "pass"),
        view,
      );
    case "TestSuiteRegistered":
      return view;
    case "TestSuiteRunStarted":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function flakeRate(view: FlakeView, name: string): number {
  const s = view.perTest[name];
  if (!s) return 0;
  const total = s.passes + s.failures;
  return total === 0 ? 0 : s.failures / total;
}
```

