```typescript
export type AuditState =
  | { status: "none" }
  | { status: "active"; id: string; findings: number }
  | { status: "concluded"; id: string; findings: number; conclusion: string };

export type AuditCommand =
  | { type: "start"; id: string }
  | { type: "recordFinding"; detail: string }
  | { type: "conclude"; conclusion: string };

export type AuditEvent =
  | { type: "AuditStarted"; id: string }
  | { type: "FindingRecorded"; detail: string }
  | { type: "AuditConcluded"; conclusion: string };

export class AuditError extends Error {
  constructor(public readonly code: string) { super(code); }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const auditDecider: Decider<AuditCommand, AuditEvent, AuditState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "none") throw new AuditError("STARTED");
        return [{ type: "AuditStarted", id: c.id }];
      case "recordFinding":
        if (s.status !== "active") throw new AuditError("NOT_ACTIVE");
        if (c.detail.length === 0) throw new AuditError("EMPTY_DETAIL");
        return [{ type: "FindingRecorded", detail: c.detail }];
      case "conclude":
        if (s.status !== "active") throw new AuditError("NOT_ACTIVE");
        if (s.findings === 0) throw new AuditError("NO_FINDINGS");
        return [{ type: "AuditConcluded", conclusion: c.conclusion }];
      default: { const _n: never = c; throw new AuditError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "AuditStarted":
        return { status: "active", id: e.id, findings: 0 };
      case "FindingRecorded":
        if (s.status !== "active") return s;
        return { ...s, findings: s.findings + 1 };
      case "AuditConcluded":
        if (s.status !== "active") return s;
        return { status: "concluded", id: s.id, findings: s.findings, conclusion: e.conclusion };
      default: { const _n: never = e; return s; }
    }
  },
};

