```typescript
export type ExperimentState =
  | { status: "none" }
  | { status: "designed"; id: string }
  | { status: "running"; id: string };

export type ExperimentCommand =
  | { type: "design"; id: string; hypothesis: string }
  | { type: "launch"; at: string };

export type ExperimentEvent =
  | { type: "ExperimentDesigned"; id: string; hypothesis: string }
  | { type: "ExperimentLaunched"; at: string };

export interface AppendOptions {
  expectedRevision: bigint | "no_stream" | "any";
}

export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], options: AppendOptions): Promise<{ nextRevision: bigint }>;
}

export const initialState: ExperimentState = { status: "none" };

export function evolve(state: ExperimentState, event: ExperimentEvent): ExperimentState {
  switch (event.type) {
    case "ExperimentDesigned":
      return { status: "designed", id: event.id };
    case "ExperimentLaunched":
      if (state.status !== "designed") return state;
      return { status: "running", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: ExperimentCommand, state: ExperimentState): ExperimentEvent[] {
  switch (command.type) {
    case "design":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ExperimentDesigned", id: command.id, hypothesis: command.hypothesis }];
    case "launch":
      if (state.status !== "designed") throw new Error("NOT_DESIGNED");
      return [{ type: "ExperimentLaunched", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export async function handle(
  command: ExperimentCommand,
  deps: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const records = await deps.eventStore.readStream<ExperimentEvent>(deps.streamName);
  const state = records.reduce<ExperimentState>((s, r) => evolve(s, r.event), initialState);
  const expectedRevision: AppendOptions["expectedRevision"] =
    records.length === 0 ? "no_stream" : records[records.length - 1].revision;
  const events = decide(command, state);
  await deps.eventStore.appendToStream<ExperimentEvent>(deps.streamName, events, { expectedRevision });
}
```

