```typescript
export class DomainError extends Error {}

export type OutreachVisitState =
  | { status: "none" }
  | { status: "scheduled"; id: string; at: string }
  | { status: "inProgress"; id: string; startedAt: string }
  | { status: "done"; id: string; endedAt: string }
  | { status: "cancelled"; id: string };

export type OutreachVisitCommand =
  | { type: "schedule"; id: string; at: string }
  | { type: "start"; at: string }
  | { type: "complete"; at: string; notes: string }
  | { type: "cancel" };

export type OutreachVisitEvent =
  | { type: "scheduled"; id: string; at: string }
  | { type: "started"; at: string }
  | { type: "completed"; at: string; notes: string }
  | { type: "cancelled" };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const OutreachVisitDecider: Decider<OutreachVisitCommand, OutreachVisitEvent, OutreachVisitState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "schedule":
        if (s.status !== "none") throw new DomainError("exists");
        return [{ type: "scheduled", id: c.id, at: c.at }];
      case "start":
        if (s.status !== "scheduled") throw new DomainError("not scheduled");
        return [{ type: "started", at: c.at }];
      case "complete":
        if (s.status !== "inProgress") throw new DomainError("not started");
        return [{ type: "completed", at: c.at, notes: c.notes }];
      case "cancel":
        if (s.status === "done" || s.status === "cancelled") throw new DomainError("final");
        return [{ type: "cancelled" }];
      default: {
        const _: never = c;
        return _;
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "scheduled":
        return { status: "scheduled", id: e.id, at: e.at };
      case "started":
        return s.status === "scheduled" ? { status: "inProgress", id: s.id, startedAt: e.at } : s;
      case "completed":
        return s.status === "inProgress" ? { status: "done", id: s.id, endedAt: e.at } : s;
      case "cancelled":
        return s.status !== "none" && s.status !== "done" ? { status: "cancelled", id: "id" in s ? s.id : "" } : s;
      default: {
        const _: never = e;
        return _;
      }
    }
  },
};
