export type RecipeTestState =
  | { status: "none" }
  | { status: "running"; testId: string; recipeId: string; ratingsCollected: number }
  | { status: "ended"; testId: string };

export type RecipeTestCommand =
  | { type: "start"; testId: string; recipeId: string }
  | { type: "rate"; rating: number }
  | { type: "end"; at: string };

export type RecipeTestEvent =
  | { type: "RecipeTestStarted"; testId: string; recipeId: string }
  | { type: "RecipeTestRated"; rating: number }
  | { type: "RecipeTestEnded"; at: string };

export class InvariantError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "InvariantError";
  }
}

export function decide(command: RecipeTestCommand, state: RecipeTestState): RecipeTestEvent[] {
  switch (command.type) {
    case "start":
      if (state.status !== "none") throw new InvariantError("EXISTS");
      return [{ type: "RecipeTestStarted", testId: command.testId, recipeId: command.recipeId }];
    case "rate":
      if (state.status !== "running") throw new InvariantError("NOT_RUNNING");
      if (command.rating < 1 || command.rating > 5) throw new InvariantError("BAD_RATING");
      return [{ type: "RecipeTestRated", rating: command.rating }];
    case "end":
      if (state.status !== "running") throw new InvariantError("NOT_RUNNING");
      if (state.ratingsCollected === 0) throw new InvariantError("NO_RATINGS");
      return [{ type: "RecipeTestEnded", at: command.at }];
    default: {
      const _n: never = command;
      throw new InvariantError("UNKNOWN");
    }
  }
}

export function evolve(state: RecipeTestState, event: RecipeTestEvent): RecipeTestState {
  switch (event.type) {
    case "RecipeTestStarted":
      return { status: "running", testId: event.testId, recipeId: event.recipeId, ratingsCollected: 0 };
    case "RecipeTestRated":
      if (state.status !== "running") return state;
      return { ...state, ratingsCollected: state.ratingsCollected + 1 };
    case "RecipeTestEnded":
      if (state.status !== "running") return state;
      return { status: "ended", testId: state.testId };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

