The handler is pure orchestration: load state by folding the stream, call `decide`, and append the resulting events. The business rules stay inside `decide`/`evolve`.

```typescript
export type GoalState =
  | { status: "none" }
  | { status: "recorded"; id: string; scorer: string; minute: number; matchId: string };

export type GoalCommand = { type: "record"; id: string; scorer: string; minute: number; matchId: string };

export type GoalEvent = { type: "GoalRecorded"; id: string; scorer: string; minute: number; matchId: string };

export const initialGoal: GoalState = { status: "none" };

export function decide(c: GoalCommand, s: GoalState): GoalEvent[] {
  if (c.type !== "record") { const _n: never = c.type; throw new Error("UNKNOWN"); }
  if (s.status !== "none") throw new Error("ALREADY_RECORDED");
  if (c.minute < 0) throw new Error("INVALID_MINUTE");
  return [{ type: "GoalRecorded", id: c.id, scorer: c.scorer, minute: c.minute, matchId: c.matchId }];
}

export function evolve(s: GoalState, e: GoalEvent): GoalState {
  if (e.type !== "GoalRecorded") { const _n: never = e.type; return s; }
  return { status: "recorded", id: e.id, scorer: e.scorer, minute: e.minute, matchId: e.matchId };
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: GoalEvent }>>;
  appendToStream(stream: string, events: readonly GoalEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handleGoal(store: EventStore, stream: string, command: GoalCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<GoalState>((s, { event }) => evolve(s, event), initialGoal);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  const events = decide(command, state);
  await store.appendToStream(stream, events, { expectedRevision: expected });
}
