export function decide(command: MessageCommand, state: MessageState): MessageEvent[] {
  switch (command.type) {
    case 'PostMessage':
      if (state.status !== 'draft') throw new MessageRuleBroken('already posted');
      return [{ type: 'MessagePosted', id: command.id, authorId: command.authorId, body: command.body, postedAt: command.postedAt }];
    case 'EditMessage':
      if (state.status !== 'live') throw new MessageRuleBroken('cannot edit');
      return [{ type: 'MessageEdited', body: command.body, editedAt: command.editedAt }];
    case 'DeleteMessage':
      if (state.status !== 'live') throw new MessageRuleBroken('cannot delete');
      return [{ type: 'MessageDeleted', deletedAt: command.deletedAt }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: MessageState, event: MessageEvent): MessageState {
  switch (event.type) {
    case 'MessagePosted':
      return { status: 'live', id: event.id, authorId: event.authorId, body: event.body };
    case 'MessageEdited':
      return state.status === 'live' ? { ...state, body: event.body } : state;
    case 'MessageDeleted':
      return state.status === 'live' ? { status: 'deleted', id: state.id } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}
