import { setup, assign, fromPromise } from 'xstate';

type Status = 'pending' | 'sent' | 'failed';
type Msg = { id: string; body: string; status: Status };
type Ctx = { queue: Msg[] };
type Ev =
  | { type: 'ENQUEUE'; body: string }
  | { type: 'RETRY_LAST' };

export const outboxMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    transmit: fromPromise(
      async ({ input }: { input: { id: string; body: string } }) => {
        await new Promise((r) => setTimeout(r, 100));
        if (input.body === 'boom') throw new Error('server');
        return { id: input.id };
      }
    )
  },
  actions: {
    enqueue: assign({
      queue: ({ context, event }) => {
        if (event.type !== 'ENQUEUE') return context.queue;
        return context.queue.concat({ id: String(Date.now()), body: event.body, status: 'pending' });
      }
    }),
    markSent: assign({
      queue: ({ context }) =>
        context.queue.map((m) => (m.status === 'pending' ? { ...m, status: 'sent' as const } : m))
    })
  }
}).createMachine({
  id: 'outbox',
  initial: 'idle',
  context: { queue: [] },
  states: {
    idle: {
      on: {
        ENQUEUE: { target: 'sending', actions: 'enqueue' },
        RETRY_LAST: {
          target: 'sending',
          guard: ({ context }) => context.queue.some((m) => m.status === 'failed'),
          actions: assign({
            queue: ({ context }) =>
              context.queue.map((m) => (m.status === 'failed' ? { ...m, status: 'pending' as const } : m))
          })
        }
      }
    },
    sending: {
      invoke: {
        id: 'tx',
        src: 'transmit',
        input: ({ context }) => {
          const p = context.queue.find((m) => m.status === 'pending');
          return { id: p?.id ?? '', body: p?.body ?? '' };
        },
        onDone: { target: 'idle', actions: 'markSent' },
        onError: {
          target: 'idle',
          actions: assign({
            queue: ({ context }) =>
              context.queue.map((m) => (m.status === 'pending' ? { ...m, status: 'failed' as const } : m))
          })
        }
      }
    }
  }
});
