export type TournamentState =
  | { status: "none" }
  | { status: "draft"; id: string; name: string; teams: string[] }
  | { status: "running"; id: string; name: string; teams: string[]; startedAt: string }
  | { status: "finished"; id: string; name: string; champion: string };

export type TournamentCommand =
  | { type: "create"; id: string; name: string }
  | { type: "enrol"; team: string }
  | { type: "start"; at: string }
  | { type: "finish"; champion: string };

export type TournamentEvent =
  | { type: "TournamentCreated"; id: string; name: string }
  | { type: "TournamentTeamEnrolled"; team: string }
  | { type: "TournamentStarted"; at: string }
  | { type: "TournamentFinished"; champion: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const tournamentDecider: Decider<TournamentCommand, TournamentEvent, TournamentState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("ALREADY_EXISTS");
        return [{ type: "TournamentCreated", id: command.id, name: command.name }];
      case "enrol":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (state.teams.includes(command.team)) throw new DomainError("DUPLICATE_TEAM");
        return [{ type: "TournamentTeamEnrolled", team: command.team }];
      case "start":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (state.teams.length < 2) throw new DomainError("NEED_TWO_TEAMS");
        return [{ type: "TournamentStarted", at: command.at }];
      case "finish":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "TournamentFinished", champion: command.champion }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TournamentCreated":
        return { status: "draft", id: event.id, name: event.name, teams: [] };
      case "TournamentTeamEnrolled":
        if (state.status !== "draft") return state;
        return { ...state, teams: [...state.teams, event.team] };
      case "TournamentStarted":
        if (state.status !== "draft") return state;
        return { status: "running", id: state.id, name: state.name, teams: state.teams, startedAt: event.at };
      case "TournamentFinished":
        if (state.status !== "running") return state;
        return { status: "finished", id: state.id, name: state.name, champion: event.champion };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
