export type LeaseState = { status: "empty" } | { status: "draft"; id: string } | { status: "active"; id: string; at: string };
export type LeaseCommand = { type: "draft"; id: string } | { type: "sign"; at: string };
export type LeaseEvent = { type: "LeaseDrafted"; id: string } | { type: "LeaseSigned"; at: string };

const initialState: LeaseState = { status: "empty" };

export function evolve(state: LeaseState, event: LeaseEvent): LeaseState {
  switch (event.type) {
    case "LeaseDrafted":
      return { status: "draft", id: event.id };
    case "LeaseSigned":
      if (state.status !== "draft") return state;
      return { status: "active", id: state.id, at: event.at };
    default: {
      const _never: never = event;
      return state;
    }
