export function decide(cmd: LeaseCommand, state: LeaseState): LeaseEvent[] {
  switch (cmd.type) {
    case "draft":
      if (state.status !== "empty") throw new Error("LEASE_EXISTS");
      return [{ type: "LeaseDrafted", id: cmd.id }];
    case "sign":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "LeaseSigned", at: cmd.at }];
    default: {
      const _never: never = cmd;
      return _never;
    }
  }
}

interface StoredEvent<E> { data: E; revision: bigint }
interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(stream: string, events: E[], options: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export interface CommandHandler<C> {
  handle(command: C, ctx: { streamName: string }): Promise<void>;
}

export function makeLeaseHandler(store: EventStore<LeaseEvent>): CommandHandler<LeaseCommand> {
  return {
    async handle(command, { streamName }) {
      const stored = await store.readStream(streamName);
      const state = stored.reduce<LeaseState>((s, e) => evolve(s, e.data), initialState);
      const events = decide(command, state);
      const expectedRevision: bigint | "no_stream" =
        stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
      await store.appendToStream(streamName, events, { expectedRevision });
    },
  };
}
