export type DocumentState =
  | { status: "empty" }
  | { status: "drafting"; id: string; title: string };

export type DocumentCommand =
  | { type: "create"; id: string; title: string };

export type DocumentEvent =
  | { type: "DocumentCreated"; id: string; title: string };

export const initialState: DocumentState = { status: "empty" };

export function decide(cmd: DocumentCommand, state: DocumentState): DocumentEvent[] {
  if (cmd.type === "create") {
    if (state.status !== "empty") throw new Error("EXISTS");
    return [{ type: "DocumentCreated", id: cmd.id, title: cmd.title }];
  }
  const _n: never = cmd.type;
  return [];
}

export function evolve(state: DocumentState, event: DocumentEvent): DocumentState {
  switch (event.type) {
    case "DocumentCreated":
      return { status: "drafting", id: event.id, title: event.title };
    default: {
      const _n: never = event.type;
      return state;
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";
export interface Env { readonly revision: bigint; readonly event: DocumentEvent; }
export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<Env>>;
  appendToStream(s: string, e: DocumentEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export interface CommandHandler<C> {
  handle(cmd: C, ctx: { streamName: string; eventStore: EventStore }): Promise<void>;
}

export const documentHandler: CommandHandler<DocumentCommand> = {
  async handle(cmd, { streamName, eventStore }) {
    const envs = await eventStore.readStream(streamName);
    const state = envs.map((e) => e.event).reduce(evolve, initialState);
    const expected: ExpectedRevision = envs.length === 0 ? "no_stream" : envs[envs.length - 1]!.revision;
    const newEvents = decide(cmd, state);
    if (newEvents.length > 0) {
      await eventStore.appendToStream(streamName, newEvents, { expectedRevision: expected });
    }
  },
};
