import { Effect } from "effect";

type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(s: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(s: string, e: readonly E[], o: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export type CourierState = { status: "pending" } | { status: "offline"; id: string } | { status: "online"; id: string };
export type CourierCommand = { type: "onboard"; id: string } | { type: "goOnline" };
export type CourierEvent = { type: "CourierOnboarded"; id: string } | { type: "CourierWentOnline" };

function evolve(s: CourierState, e: CourierEvent): CourierState {
  switch (e.type) {
    case "CourierOnboarded": return { status: "offline", id: e.id };
    case "CourierWentOnline":
      if (s.status !== "offline") return s;
      return { status: "online", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: CourierCommand, s: CourierState): CourierEvent[] {
  switch (c.type) {
    case "onboard":
      if (s.status !== "pending") throw new Error("EXISTS");
      return [{ type: "CourierOnboarded", id: c.id }];
    case "goOnline":
      if (s.status !== "offline") throw new Error("NOT_OFFLINE");
      return [{ type: "CourierWentOnline" }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface CourierRow { id: string; name: string; status: "offline" | "online" }
export interface ReadModel { find(id: string): Promise<CourierRow | null> }

export const handleCommand = (store: EventStore<CourierEvent>, stream: string, command: CourierCommand) =>
  Effect.gen(function* () {
    const loaded = yield* Effect.promise(async () => {
      let state: CourierState = { status: "pending" };
      let revision: bigint | undefined;
      for await (const { event, revision: r } of store.readStream(stream)) {
        state = evolve(state, event);
        revision = r;
      }
      return { state, revision };
    });
    const events = decide(command, loaded.state);
    if (events.length === 0) return;
    yield* Effect.promise(() => store.appendToStream(stream, events, { expectedRevision: loaded.revision ?? "no_stream" }));
  });

// Reads are eventually consistent with writes; the projection worker catches them up.
export const queryCourier = (read: ReadModel, id: string) => Effect.promise(() => read.find(id));
```

A pure reducer: `evolve(state, event) => newState`. Switch exhaustively on `event.type` and finish with a `never` guard. Wrap it in an `aggregate(events)` that calls `events.reduce(evolve, initialState)`.

```typescript
export type CommitEvent =
  | { type: "CommitRecorded"; sha: string; author: string; at: string }
  | { type: "CommitReverted"; sha: string; revertedBy: string; at: string };

export interface CommitState {
  readonly sha?: string;
  readonly author?: string;
  readonly recordedAt?: string;
  readonly reverted: boolean;
  readonly revertedBy?: string;
}

export const initialState: CommitState = { reverted: false };

export function evolve(state: CommitState, event: CommitEvent): CommitState {
  switch (event.type) {
    case "CommitRecorded":
      return { ...state, sha: event.sha, author: event.author, recordedAt: event.at };
    case "CommitReverted":
      if (!state.sha || state.sha !== event.sha) return state;
      return { ...state, reverted: true, revertedBy: event.revertedBy };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: CommitEvent[]): CommitState {
  return events.reduce(evolve, initialState);
}
```

