export type TenantEvent =
  | { type: "TenantOnboarded"; id: string; name: string }
  | { type: "SeatAllocated"; userId: string }
  | { type: "TenantSuspended"; reason: string };

export type TenantState =
  | { status: "none" }
  | { status: "active"; id: string; name: string; seats: number }
  | { status: "suspended"; id: string; name: string; seats: number; reason: string };

export type TenantCommand =
  | { type: "onboard"; id: string; name: string }
  | { type: "allocateSeat"; userId: string }
  | { type: "suspend"; reason: string };

export class DomainError extends Error {}

export function evolve(state: TenantState, event: TenantEvent): TenantState {
  switch (event.type) {
    case "TenantOnboarded":
      return { status: "active", id: event.id, name: event.name, seats: 0 };
    case "SeatAllocated":
      if (state.status === "none") return state;
      return { ...state, seats: state.seats + 1 };
    case "TenantSuspended":
      if (state.status !== "active") return state;
      return { status: "suspended", id: state.id, name: state.name, seats: state.seats, reason: event.reason };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(c: TenantCommand, s: TenantState): TenantEvent[] {
  switch (c.type) {
    case "onboard":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "TenantOnboarded", id: c.id, name: c.name }];
    case "allocateSeat":
      if (s.status !== "active") throw new DomainError("NOT_ACTIVE");
      return [{ type: "SeatAllocated", userId: c.userId }];
    case "suspend":
      if (s.status !== "active") throw new DomainError("NOT_ACTIVE");
      return [{ type: "TenantSuspended", reason: c.reason }];
    default: {
      const _n: never = c;
      throw new DomainError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: TenantEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: TenantEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export type TenantDirectoryView = Readonly<{
  id: string;
  name: string;
  seats: number;
  status: "active" | "suspended";
}>;

export interface ViewStore {
  getById(id: string): Promise<TenantDirectoryView | null>;
}

export async function handleCommand(
  store: EventStore,
  streamName: string,
  command: TenantCommand,
): Promise<bigint | null> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, { status: "none" } as TenantState);
  const newEvents = decide(command, state);
  if (newEvents.length === 0) return revision;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  return store.appendToStream(streamName, newEvents, { expectedRevision });
}

// Reads are eventually consistent with the event store; the view is
// populated by a separate projection subscription.
export async function queryView(
  views: ViewStore,
  tenantId: string,
): Promise<TenantDirectoryView | null> {
  return views.getById(tenantId);
}
