  | { type: "Opened" }
  | { type: "Closed"; on: string };

export type LBState = { id: string; code: string; open: boolean };
const initialLB: LBState = { id: "", code: "", open: false };

export function when(state: LBState, event: LBEvent): LBState {
  switch (event.type) {
    case "Planned":
      return { id: event.id, code: event.code, open: false };
    case "Opened":
      return { ...state, open: true };
    case "Closed":
      return { ...state, open: false };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = fold(state, event);
  }
  return state;
}

export async function loadBranch(stream: AsyncIterable<LBEvent>): Promise<LBState> {
  return aggregateStream<LBState, LBEvent>(stream, when, initialLB);
}
