type ConcertEvent = { type: 'TicketsSold'; qty: number } | { type: 'Started' };
type ConcertState = { readonly sold: number; readonly started: boolean };

export type Snapshot<S> = { readonly version: number; readonly revision: bigint; readonly state: S };

function evolve(state: ConcertState, event: ConcertEvent): ConcertState {
  switch (event.type) {
    case 'TicketsSold': return { ...state, sold: state.sold + event.qty };
    case 'Started': return { ...state, started: true };
    default: { const _e: never = event; return _e; }
  }
}

interface EventStore {
  readStream(s: string, fromRev: bigint): AsyncIterable<{ event: ConcertEvent; revision: bigint }>;
  appendToStream(s: string, evs: readonly ConcertEvent[], opts: { expectedRevision: bigint | 'no_stream' | 'any' }): Promise<void>;
}

interface SnapshotStore {
  load(s: string): Promise<Snapshot<ConcertState> | null>;
  save(s: string, snap: Snapshot<ConcertState>): Promise<void>;
}

export async function handleWithSnapshot(
  stream: string,
  store: EventStore,
  snaps: SnapshotStore,
  cmd: ConcertEvent,
): Promise<void> {
  const snap = await snaps.load(stream);
  let state: ConcertState = snap?.state ?? { sold: 0, started: false };
  let rev: bigint | 'no_stream' = snap ? snap.revision : 'no_stream';
  for await (const { event, revision } of store.readStream(stream, snap?.revision ?? 0n)) {
    state = evolve(state, event);
    rev = revision;
  }
  await store.appendToStream(stream, [cmd], { expectedRevision: rev });
}
```

A Decider is pure: `(command, state) => events`. A CommandHandler orchestrates IO around the decider - it loads the stream, folds events into state, calls `decide`, and appends the produced events with `expectedRevision`. The handler holds no business logic; it wires the pure core to the event store.

```typescript
import { Effect } from "effect";

export type EntryState =
  | { status: "none" }
  | { status: "draft"; id: string; text: string }
  | { status: "posted"; id: string; text: string; postedAt: string };

export type EntryCommand =
  | { type: "draft"; id: string; text: string }
  | { type: "edit"; text: string }
  | { type: "post"; at: string };

export type EntryEvent =
  | { type: "EntryDrafted"; id: string; text: string }
  | { type: "EntryEdited"; text: string }
  | { type: "EntryPosted"; at: string };

export class EntryError extends Error {}

export const initialState: EntryState = { status: "none" };

export function evolve(s: EntryState, e: EntryEvent): EntryState {
  switch (e.type) {
    case "EntryDrafted":
      return { status: "draft", id: e.id, text: e.text };
    case "EntryEdited":
      if (s.status !== "draft") return s;
      return { ...s, text: e.text };
    case "EntryPosted":
      if (s.status !== "draft") return s;
      return { status: "posted", id: s.id, text: s.text, postedAt: e.at };
    default: {
      const _n: never = e;
      return s;
    }
  }
}

export function decide(c: EntryCommand, s: EntryState): EntryEvent[] {
  switch (c.type) {
    case "draft":
      if (s.status !== "none") throw new EntryError("EXISTS");
      return [{ type: "EntryDrafted", id: c.id, text: c.text }];
    case "edit":
      if (s.status !== "draft") throw new EntryError("NOT_DRAFT");
      return [{ type: "EntryEdited", text: c.text }];
    case "post":
      if (s.status !== "draft") throw new EntryError("NOT_DRAFT");
      return [{ type: "EntryPosted", at: c.at }];
    default: {
      const _n: never = c;
      throw new EntryError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: EntryEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: readonly EntryEvent[],
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handleEntry = (
  eventStore: EventStore,
  streamName: string,
  command: EntryCommand,
) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => eventStore.readStream(streamName));
    const state = events.reduce(evolve, initialState);
    const produced = decide(command, state);
    if (produced.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() => eventStore.appendToStream(streamName, produced, { expectedRevision }));
  });
