```typescript
type LegacyCrateEvent =
  | { type: "CrateLoaded"; version: 1; id: string; weightKg: number }
  | { type: "CrateSealed"; version: 1; id: string; at: number }
  | { type: "CrateDispatched"; version: 1; id: string; dest: string };

export type CrateEvent =
  | { type: "CrateLoaded"; version: 2; id: string; weight: number; unit: "kg" }
  | { type: "CrateSealed"; version: 2; id: string; at: string }
  | { type: "CrateDispatched"; version: 2; id: string; destination: string };

export class UnknownEventError extends Error {
  constructor(public readonly raw: unknown) {
    super("UNKNOWN_EVENT");
    this.name = "UnknownEventError";
  }
}

function hasType(raw: unknown): raw is { type: string; version: number } {
  return typeof raw === "object" && raw !== null
    && typeof (raw as { type?: unknown }).type === "string"
    && typeof (raw as { version?: unknown }).version === "number";
}

export function upcast(raw: unknown): CrateEvent {
  if (!hasType(raw)) throw new UnknownEventError(raw);
  const keyed = raw as { type: string; version: number } & Record<string, unknown>;
  const key = `${keyed.type}@v${keyed.version}`;
  switch (key) {
    case "CrateLoaded@v1": {
      const src = raw as LegacyCrateEvent & { type: "CrateLoaded" };
      return { type: "CrateLoaded", version: 2, id: src.id, weight: src.weightKg, unit: "kg" };
    }
    case "CrateLoaded@v2":
      return raw as CrateEvent;
    case "CrateSealed@v1": {
      const src = raw as LegacyCrateEvent & { type: "CrateSealed" };
      return { type: "CrateSealed", version: 2, id: src.id, at: new Date(src.at).toISOString() };
    }
    case "CrateSealed@v2":
      return raw as CrateEvent;
    case "CrateDispatched@v1": {
      const src = raw as LegacyCrateEvent & { type: "CrateDispatched" };
      return { type: "CrateDispatched", version: 2, id: src.id, destination: src.dest };
    }
    case "CrateDispatched@v2":
      return raw as CrateEvent;
    default:
      throw new UnknownEventError(raw);
  }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<unknown>;
}

export async function readUpcasted(store: EventStore, stream: string): Promise<CrateEvent[]> {
  const out: CrateEvent[] = [];
  async function main(): Promise<void> {
    for await (const raw of store.readStream(stream)) out.push(upcast(raw));
  }
  await main();
  return out;
}
