  switch (event.type) {
    case "InspectionScheduled": return { ...state, scheduled: true };
    case "InspectorAssigned": return { ...state, assigned: true };
    case "ReportFiled": return { ...state, reported: true };
    case "InspectionClosed": return { ...state, closed: true };
