export type DomainEvent = Readonly<{ type: string; data: Readonly<Record<string, unknown>> }>;

export type OutboxRow = Readonly<{
  id: string;
  payload: string;
  publishedAt: string | null;
}>;

export type ExpectedRevision = bigint | "no_stream";

export interface Transaction {
  appendEvents(
    stream: string,
    events: ReadonlyArray<DomainEvent>,
    options: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
  insertOutboxRows(rows: ReadonlyArray<OutboxRow>): Promise<void>;
}

export interface TransactionalConnection {
  run<R>(body: (tx: Transaction) => Promise<R>): Promise<R>;
}

// A separate publisher worker polls rows where publishedAt IS NULL, delivers them to
// the integration bus, and then marks them published. That loop is not implemented
// here. This helper only guarantees atomic persistence of events and outbox rows.
export async function appendWithOutbox(
  conn: TransactionalConnection,
  stream: string,
  expectedRevision: ExpectedRevision,
  events: ReadonlyArray<DomainEvent>,
  outboxRows: ReadonlyArray<OutboxRow>,
): Promise<bigint> {
  return conn.run(async (tx) => {
    const nextRevision = await tx.appendEvents(stream, events, { expectedRevision });
    if (outboxRows.length > 0) {
      await tx.insertOutboxRows(outboxRows);
    }
    return nextRevision;
  });
}
```

A Decider bundles three things for one aggregate: `initialState`, a pure `decide(command, state): Event[]` that validates invariants and emits events, and a pure `evolve(state, event): State` that folds events back into state. Because both functions are pure, the same event stream always rebuilds the same state, and commands can be tested without any IO. The event store becomes the only mutable boundary; the aggregate itself is a value.

```typescript
export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type PoolState = { readonly balanceCents: number; readonly frozen: boolean };

type PoolCommand =
  | { type: 'Contribute'; amountCents: number }
  | { type: 'Payout'; amountCents: number }
  | { type: 'Freeze' };

type PoolEvent =
  | { type: 'Contributed'; amountCents: number }
  | { type: 'PaidOut'; amountCents: number }
  | { type: 'Frozen' };

export class InvariantError extends Error {}

export const royaltyDecider: Decider<PoolCommand, PoolEvent, PoolState> = {
  initialState: { balanceCents: 0, frozen: false },
  decide(cmd, state) {
    switch (cmd.type) {
      case 'Contribute':
        if (state.frozen) throw new InvariantError('frozen');
        return [{ type: 'Contributed', amountCents: cmd.amountCents }];
      case 'Payout':
        if (state.frozen) throw new InvariantError('frozen');
        if (cmd.amountCents > state.balanceCents) throw new InvariantError('insufficient');
        return [{ type: 'PaidOut', amountCents: cmd.amountCents }];
      case 'Freeze':
        return state.frozen ? [] : [{ type: 'Frozen' }];
      default: { const _e: never = cmd; return _e; }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'Contributed': return { ...state, balanceCents: state.balanceCents + event.amountCents };
      case 'PaidOut': return { ...state, balanceCents: state.balanceCents - event.amountCents };
      case 'Frozen': return { ...state, frozen: true };
      default: { const _e: never = event; return _e; }
    }
  },
};
