export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const dietPlanDecider: Decider<DietPlanCommand, DietPlanEvent, DietPlanState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "draft":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "DietPlanDrafted", id: command.id }];
      case "addDays":
        if (state.status !== "drafted") throw new DomainError("NOT_DRAFTED");
        if (command.count <= 0) throw new DomainError("BAD_COUNT");
        return [{ type: "DietPlanDaysAdded", count: command.count }];
      case "activate":
        if (state.status !== "drafted") throw new DomainError("NOT_DRAFTED");
        if (state.days === 0) throw new DomainError("NO_DAYS");
        return [{ type: "DietPlanActivated", at: command.at }];
      case "extend":
        if (state.status === "expired") throw new DomainError("EXPIRED");
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.count <= 0) throw new DomainError("BAD_COUNT");
        return [{ type: "DietPlanExtended", count: command.count }];
      case "expire":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "DietPlanExpired", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DietPlanDrafted":
        return { status: "drafted", id: event.id, days: 0 };
      case "DietPlanDaysAdded":
        if (state.status !== "drafted") return state;
        return { ...state, days: state.days + event.count };
      case "DietPlanActivated":
        if (state.status !== "drafted") return state;
        return { status: "active", id: state.id, days: state.days, activatedAt: event.at };
      case "DietPlanExtended":
        if (state.status !== "active") return state;
        return { ...state, days: state.days + event.count };
      case "DietPlanExpired":
        if (state.status !== "active") return state;
        return { status: "expired", id: state.id, expiredAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

