export type SagaState =
  | { status: "idle" }
  | { status: "awaitingMilestone"; projectId: string; milestoneId: string }
  | { status: "milestoneReached"; projectId: string; milestoneId: string }
  | { status: "failed"; projectId: string; reason: string };

export type IncomingEvent =
  | { type: "ProjectStarted"; projectId: string; initialMilestoneId: string }
  | { type: "MilestoneReached"; projectId: string; milestoneId: string }
  | { type: "MilestoneMissed"; projectId: string; milestoneId: string; reason: string };

export type OutgoingCommand =
  | { type: "CreateMilestone"; projectId: string; milestoneId: string }
  | { type: "AnnounceMilestone"; projectId: string; milestoneId: string }
  | { type: "EscalateMissedMilestone"; projectId: string; reason: string };

export type SagaStep = { nextState: SagaState; command: OutgoingCommand | null };

export const initialState: SagaState = { status: "idle" };

export function step(state: SagaState, event: IncomingEvent): SagaStep {
  switch (event.type) {
    case "ProjectStarted":
      if (state.status !== "idle") return { nextState: state, command: null };
      return {
        nextState: { status: "awaitingMilestone", projectId: event.projectId, milestoneId: event.initialMilestoneId },
        command: { type: "CreateMilestone", projectId: event.projectId, milestoneId: event.initialMilestoneId },
      };
    case "MilestoneReached":
      if (state.status !== "awaitingMilestone") return { nextState: state, command: null };
      return {
        nextState: { status: "milestoneReached", projectId: state.projectId, milestoneId: event.milestoneId },
        command: { type: "AnnounceMilestone", projectId: state.projectId, milestoneId: event.milestoneId },
      };
    case "MilestoneMissed":
      if (state.status !== "awaitingMilestone") return { nextState: state, command: null };
      return {
        nextState: { status: "failed", projectId: state.projectId, reason: event.reason },
        command: { type: "EscalateMissedMilestone", projectId: state.projectId, reason: event.reason },
      };
    default: {
      const _n: never = event;
      return { nextState: state, command: null };
    }
  }
}

export function evolve(state: SagaState, event: IncomingEvent): SagaState {
  return step(state, event).nextState;
}

export function aggregate(events: IncomingEvent[]): SagaState {
  return events.reduce(evolve, initialState);
}
