export type ResearchStudyEvent =
  | { type: "ResearchStudyRegistered"; id: string; pi: string }
  | { type: "ResearchStudyParticipantEnrolled"; id: string }
  | { type: "ResearchStudyClosed"; id: string };

export type ConsentCommand = { type: "draft"; studyId: string };
export type ReleaseCommand = { type: "prepare"; datasetId: string };

export type SagaCommand = ConsentCommand | ReleaseCommand;

export function react(event: ResearchStudyEvent): SagaCommand | null {
  switch (event.type) {
    case "ResearchStudyRegistered":
      return { type: "draft", studyId: event.id };
    case "ResearchStudyParticipantEnrolled":
      return null;
    case "ResearchStudyClosed":
      return { type: "prepare", datasetId: event.id };
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export interface CommandBus {
  send(command: SagaCommand): Promise<void>;
}

export interface EventStore {
  readStream(stream: string): Promise<ResearchStudyEvent[]>;
}

export async function runSaga(store: EventStore, bus: CommandBus, stream: string): Promise<void> {
  const events = await store.readStream(stream);
  for (const event of events) {
    const next = react(event);
    if (next !== null) await bus.send(next);
  }
}
