export interface CurrentPaintingState {
  readonly id: string;
  readonly artist: string;
  readonly medium: string;
  readonly appraisedValue: number;
  readonly currency: string;
}

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3;

interface V1 { id: string; artist: string; }
interface V2 { id: string; artist: string; medium: string; appraisedValue: number; }

function v1Tov2(snap: Snapshot<V1>): Snapshot<V2> {
  return { version: 2, state: { ...snap.state, medium: "unknown", appraisedValue: 0 } };
}

function v2Tov3(snap: Snapshot<V2>): Snapshot<CurrentPaintingState> {
  return { version: 3, state: { ...snap.state, currency: "USD" } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentPaintingState> {
  let working: Snapshot<unknown> = raw;
  if (working.version === 1) working = v1Tov2(working as Snapshot<V1>);
  if (working.version === 2) working = v2Tov3(working as Snapshot<V2>);
  if (working.version !== CURRENT_VERSION) {
    throw new Error(`Cannot upgrade Painting snapshot from v${raw.version}`);
  }
  return working as Snapshot<CurrentPaintingState>;
}
