import { Effect } from "effect";

export type ClaimEvent =
  | { type: "ClaimFiled"; id: string; amount: number }
  | { type: "ClaimApproved"; at: string };

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    stream: string,
    events: readonly E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict {
  readonly _tag = "ConcurrencyConflict";
  constructor(readonly stream: string) {}
}

export const appendClaim = (
  store: EventStore<ClaimEvent>,
  stream: string,
  events: readonly ClaimEvent[],
) =>
  Effect.gen(function* () {
    const expected = yield* Effect.promise(async () => {
      let rev: bigint | "no_stream" = "no_stream";
      for await (const rec of store.readStream(stream)) rev = rec.revision;
      return rev;
    });
    return yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision: expected }),
      catch: () => new ConcurrencyConflict(stream),
    });
  });
