An `after` transition can be an array of guarded entries just like an `on`. XState checks them top to bottom when the delay elapses. That lets one `after` fire either shortBreak or longBreak, keyed off a cycle counter in context.

```typescript
import { setup, assign } from 'xstate';

export const breakPickerMachine = setup({
  types: {
    context: {} as { cycles: number },
    events: {} as { type: 'START' },
  },
  delays: { WORK: 25 * 60_000 },
  guards: {
    fourth: ({ context }) => (context.cycles + 1) % 4 === 0,
  },
}).createMachine({
  id: 'breakPicker',
  initial: 'idle',
  context: { cycles: 0 },
  states: {
    idle: { on: { START: 'work' } },
    work: {
      after: {
        WORK: [
          {
            guard: 'fourth',
            target: 'longBreak',
            actions: assign({ cycles: ({ context }) => context.cycles + 1 }),
          },
          {
            target: 'shortBreak',
            actions: assign({ cycles: ({ context }) => context.cycles + 1 }),
          },
        ],
      },
    },
    shortBreak: {},
    longBreak: {},
  },
});
```

Put the check into `setup.guards`, reference it by name on the transition, and XState will drop the event when the guard returns false.

```typescript
import { setup, assign } from 'xstate';

export const voteOnceMachine = setup({
  types: {
    context: {} as { voted: Set<string> },
    events: {} as { type: 'VOTE'; voter: string },
  },
  guards: {
    notVoted: ({ context, event }) =>
      event.type === 'VOTE' && !context.voted.has(event.voter),
  },
}).createMachine({
  id: 'voteOnce',
  context: { voted: new Set<string>() },
  on: {
    VOTE: {
      guard: 'notVoted',
      actions: assign({
        voted: ({ context, event }) => {
          const next = new Set(context.voted);
          if (event.type === 'VOTE') next.add(event.voter);
          return next;
        },
      }),
    },
  },
});
