import { Effect } from "effect";

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface ReadResult<E> { readonly revision: bigint; readonly events: E[] }
export interface AppendResult { readonly nextRevision: bigint }

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export type DispenseState =
  | { status: "none" }
  | { status: "queued"; id: string; drug: string }
  | { status: "dispensed"; id: string; at: string };

export type DispenseCommand =
  | { type: "queue"; id: string; drug: string }
  | { type: "dispense"; at: string };

export type DispenseEvent =
  | { type: "DispenseQueued"; id: string; drug: string }
  | { type: "Dispensed"; at: string };

const initialState: DispenseState = { status: "none" };

export function evolve(s: DispenseState, e: DispenseEvent): DispenseState {
  switch (e.type) {
    case "DispenseQueued": return { status: "queued", id: e.id, drug: e.drug };
    case "Dispensed":
      if (s.status !== "queued") return s;
      return { status: "dispensed", id: s.id, at: e.at };
    default: { const _never: never = e; return s; }
  }
}

export function decide(c: DispenseCommand, s: DispenseState): DispenseEvent[] {
  switch (c.type) {
    case "queue":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "DispenseQueued", id: c.id, drug: c.drug }];
    case "dispense":
      if (s.status !== "queued") throw new Error("NOT_QUEUED");
      return [{ type: "Dispensed", at: c.at }];
    default: { const _never: never = c; throw new Error("UNKNOWN"); }
  }
}

export const handleDispense = (
  store: EventStore<DispenseEvent>,
  streamName: string,
  command: DispenseCommand,
) =>
  Effect.gen(function* () {
    const read = yield* Effect.tryPromise({
      try: () => store.readStream(streamName),
      catch: (e) => new Error(String(e)),
    });
    const state = read.events.reduce(evolve, initialState);
    const events = decide(command, state);
    const expectedRevision: ExpectedRevision = read.events.length === 0 ? "no_stream" : read.revision;
    const appended = yield* Effect.tryPromise({
      try: () => store.appendToStream(streamName, events, { expectedRevision }),
      catch: (e) => new Error(String(e)),
    });
    return appended.nextRevision;
  });
