export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type Command =
  | { type: 'Schedule'; shotPoint: string }
  | { type: 'Fire'; at: string; charge: number }
  | { type: 'Cancel'; reason: string };

type Event =
  | { type: 'ShotScheduled'; shotPoint: string }
  | { type: 'ShotFired'; at: string; charge: number }
  | { type: 'ShotCancelled'; reason: string };

type State =
  | { status: 'unscheduled' }
  | { status: 'scheduled'; shotPoint: string }
  | { status: 'fired' }
  | { status: 'cancelled' };

class InvariantError extends Error {}

export const SeismicShot: Decider<Command, Event, State> = {
  initialState: { status: 'unscheduled' },
  decide(command, state) {
    switch (command.type) {
      case 'Schedule':
        if (state.status !== 'unscheduled') throw new InvariantError('cannot reschedule');
        return [{ type: 'ShotScheduled', shotPoint: command.shotPoint }];
      case 'Fire':
        if (state.status !== 'scheduled') throw new InvariantError('not scheduled');
        return [{ type: 'ShotFired', at: command.at, charge: command.charge }];
      case 'Cancel':
        if (state.status !== 'scheduled') throw new InvariantError('cannot cancel');
        return [{ type: 'ShotCancelled', reason: command.reason }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'ShotScheduled':
        return { status: 'scheduled', shotPoint: event.shotPoint };
      case 'ShotFired':
        return { status: 'fired' };
      case 'ShotCancelled':
        return { status: 'cancelled' };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
