  | { type: 'MessagePosted'; channelId: string; messageId: string; at: string }
  | { type: 'ChannelJoined'; channelId: string; userId: string; at: string }
  | { type: 'ChannelLeft'; channelId: string; userId: string; at: string };

type ChannelFeedView = Readonly<{
  channelId: string;
  name: string;
  messageCount: number;
  participantCount: number;
  lastActivityAt: string | null;
}>;

