  channelId: '',
  name: '',
  messageCount: 0,
  participantCount: 0,
  lastActivityAt: null,
};

export function project(view: ChannelFeedView, event: FeedEvent): ChannelFeedView {
  switch (event.type) {
    case 'ChannelCreated':
      return { ...view, channelId: event.channelId, name: event.name, lastActivityAt: event.at };
    case 'MessagePosted':
      return { ...view, messageCount: view.messageCount + 1, lastActivityAt: event.at };
    case 'ChannelJoined':
      return { ...view, participantCount: view.participantCount + 1, lastActivityAt: event.at };
    case 'ChannelLeft':
      return {
        ...view,
        participantCount: Math.max(0, view.participantCount - 1),
        lastActivityAt: event.at,
      };
    default: {
      const _: never = event;
      return _;
    }
  }
}
