export type InvoiceState = { status: "empty" } | { status: "draft"; id: string; amount: number };
export type InvoiceCommand = { type: "draft"; id: string; amount: number };
export type InvoiceEvent = { type: "InvoiceDrafted"; id: string; amount: number };

export class DomainError extends Error {}

export const initialState: InvoiceState = { status: "empty" };

export function evolve(state: InvoiceState, event: InvoiceEvent): InvoiceState {
  switch (event.type) {
    case "InvoiceDrafted":
      return { status: "draft", id: event.id, amount: event.amount };
    default: { const _n: never = event.type; return state; }
  }
}

export function decide(command: InvoiceCommand, state: InvoiceState): InvoiceEvent[] {
  switch (command.type) {
    case "draft":
      if (state.status !== "empty") throw new DomainError("EXISTS");
      if (command.amount <= 0) throw new DomainError("INVALID");
      return [{ type: "InvoiceDrafted", id: command.id, amount: command.amount }];
    default: { const _n: never = command.type; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<{ events: InvoiceEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: InvoiceEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handleEffect = (
  command: InvoiceCommand,
  ctx: { streamName: string; eventStore: EventStore },
) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = events.reduce(evolve, initialState);
    const newEvents = decide(command, state);
    if (newEvents.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    const nextRev = yield* Effect.promise(() =>
      ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision }),
    );
    return nextRev;
  });
```

The machine invokes a `fromCallback` actor that owns the websocket. The actor calls `sendBack` whenever a peer cursor update arrives and listens via `receive` for outbound updates to publish. Cleanup closes the socket when the state exits.

```typescript
import { setup, assign, fromCallback } from 'xstate';

interface Cursor { peerId: string; line: number; col: number }
interface Ctx { cursors: Cursor[] }

type Ev =
  | { type: 'REMOTE_CURSOR'; cursor: Cursor }
  | { type: 'LOCAL_CURSOR'; line: number; col: number };

type InEv = { type: 'PUBLISH'; line: number; col: number };

const socketActor = fromCallback<InEv>(({ sendBack, receive }) => {
  const onMessage = (c: Cursor) => sendBack({ type: 'REMOTE_CURSOR', cursor: c });
  receive((ev) => {
    if (ev.type === 'PUBLISH') {
      void ev.line;
    }
  });
  const id = setInterval(() => onMessage({ peerId: 'p1', line: 0, col: 0 }), 1000);
  return () => clearInterval(id);
});

export const cursorMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { socketActor }
}).createMachine({
  id: 'cursorStream',
  context: { cursors: [] },
  invoke: { id: 'sock', src: 'socketActor' },
  on: {
    REMOTE_CURSOR: {
      actions: assign({
        cursors: ({ context, event }) => [
          ...context.cursors.filter((c) => c.peerId !== event.cursor.peerId),
          event.cursor
        ]
      })
    },
    LOCAL_CURSOR: { actions: () => undefined }
  }
});
```

A rebuild is a chunked loop over the event store. Each iteration reads a batch, projects it, persists the view plus the cursor, and advances. A `from` option lets the next crash resume at the last persisted revision so rebuilds do not have to restart.

```typescript
export type DCEvent = { type: "CopyAdded"; id: string } | { type: "CopyRemoved"; id: string };
export type DCView = { active: Set<string> };
export const empty: DCView = { active: new Set<string>() };

export function project(view: DCView, event: DCEvent): DCView {
  switch (event.type) {
    case "CopyAdded": {
      const next = new Set(view.active);
      next.add(event.id);
      return { active: next };
    }
    case "CopyRemoved": {
      const next = new Set(view.active);
      next.delete(event.id);
      return { active: next };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface BatchReader<E> {
  readBatch(from: bigint, size: number): Promise<{ events: ReadonlyArray<{ event: E; revision: bigint }>; done: boolean }>;
}

export async function rebuild(options: {
  from: bigint;
  batchSize: number;
  reader: BatchReader<DCEvent>;
  persist: (view: DCView, cursor: bigint) => Promise<void>;
  onProgress?: (cursor: bigint) => void;
}): Promise<void> {
  let view = empty;
  let cursor = options.from;
  while (true) {
    const batch = await options.reader.readBatch(cursor, options.batchSize);
    for (const { event, revision } of batch.events) {
      view = project(view, event);
      cursor = revision;
    }
    await options.persist(view, cursor);
    options.onProgress?.(cursor);
    if (batch.done) return;
  }
}
```

```typescript
export class UnknownEventError extends Error {
  constructor(readonly raw: unknown) { super("UNKNOWN"); this.name = "UnknownEventError"; }
}

export interface StoredEnvelope {
  readonly type: string;
  readonly version: number;
  readonly data: unknown;
}

export type ToolingEventCurrent =
  | { type: "RequestSubmitted"; data: { tool: string } }
  | { type: "RequestApproved"; data: { by: string } };

export function upcast(raw: StoredEnvelope): ToolingEventCurrent {
  if (raw.type === "RequestSubmitted" && raw.version === 1) {
    const d = raw.data as { item: string };
    return { type: "RequestSubmitted", data: { tool: d.item } };
  }
  if (raw.type === "RequestSubmitted" && raw.version === 2) {
    return { type: "RequestSubmitted", data: raw.data as { tool: string } };
  }
  if (raw.type === "RequestApproved" && raw.version === 1) {
    return { type: "RequestApproved", data: raw.data as { by: string } };
  }
  throw new UnknownEventError(raw);
}

export interface ToolingState { submitted: number; approved: number; }

export function evolve(state: ToolingState, event: ToolingEventCurrent): ToolingState {
  switch (event.type) {
    case "RequestSubmitted": return { ...state, submitted: state.submitted + 1 };
    case "RequestApproved": return { ...state, approved: state.approved + 1 };
    default: { const _n: never = event; return state; }
  }
}

export function loadFromRaw(envs: StoredEnvelope[]): ToolingState {
  return envs.map(upcast).reduce<ToolingState>((s, e) => evolve(s, e), { submitted: 0, approved: 0 });
}
