```typescript
import { Effect } from "effect";

export type AquaticFarmEvent =
  | { type: "AquaticFarmProvisioned"; id: string; region: string }
  | { type: "AquaticFarmActivated"; at: string };

export interface AquaticFarmState {
  readonly status: "none" | "provisioned" | "active";
  readonly id: string | null;
  readonly region: string | null;
}

const initial: AquaticFarmState = { status: "none", id: null, region: null };

export function evolve(state: AquaticFarmState, event: AquaticFarmEvent): AquaticFarmState {
  switch (event.type) {
    case "AquaticFarmProvisioned":
      return { status: "provisioned", id: event.id, region: event.region };
    case "AquaticFarmActivated":
      return state.status === "provisioned" ? { ...state, status: "active" } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export const aggregateStream = <S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initialState: S,
) =>
  Effect.gen(function* () {
    return yield* Effect.promise(async () => {
      let acc: S = initialState;
      for await (const event of stream) {
        acc = reducer(acc, event);
      }
      return acc;
    });
  });

export const loadFarm = (stream: AsyncIterable<AquaticFarmEvent>) =>
  aggregateStream<AquaticFarmState, AquaticFarmEvent>(stream, evolve, initial);
```

A Decider exposes initialState plus two pure functions. decide(command, state) validates invariants (e.g. you cannot publish an issue that was never added) and returns the resulting events. evolve(state, event) folds one event into the next state. Because both are pure, tests are trivial and the verifier can replay any event stream deterministically.

```typescript
export type PeriodicalState = {
  id: string;
  title: string;
  issues: Record<string, "added" | "published">;
};

export type PeriodicalCommand =
  | { type: "register"; id: string; title: string }
  | { type: "addIssue"; issueId: string }
  | { type: "publishIssue"; issueId: string };

export type PeriodicalEvent =
  | { type: "Registered"; id: string; title: string }
  | { type: "IssueAdded"; issueId: string }
  | { type: "IssuePublished"; issueId: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const periodicalDecider: Decider<PeriodicalCommand, PeriodicalEvent, PeriodicalState> = {
  initialState: { id: "", title: "", issues: {} },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.id !== "") throw new DomainError("already registered");
        return [{ type: "Registered", id: command.id, title: command.title }];
      case "addIssue":
        if (state.id === "") throw new DomainError("not registered");
        if (state.issues[command.issueId]) throw new DomainError("duplicate issue");
        return [{ type: "IssueAdded", issueId: command.issueId }];
      case "publishIssue":
        if (state.issues[command.issueId] !== "added") throw new DomainError("issue not added");
        return [{ type: "IssuePublished", issueId: command.issueId }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Registered":
        return { id: event.id, title: event.title, issues: {} };
      case "IssueAdded":
        return { ...state, issues: { ...state.issues, [event.issueId]: "added" } };
      case "IssuePublished":
        return { ...state, issues: { ...state.issues, [event.issueId]: "published" } };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
```

