```typescript
export type UnitState =
  | { status: "empty" }
  | { status: "registered"; id: string; address: string; bedrooms: number }
  | { status: "renovating"; id: string; address: string; bedrooms: number; since: string }
  | { status: "decommissioned"; id: string; at: string };

export type UnitCommand =
  | { type: "register"; id: string; address: string; bedrooms: number }
  | { type: "startRenovation"; at: string }
  | { type: "finishRenovation"; at: string }
  | { type: "decommission"; at: string };

export type UnitEvent =
  | { type: "UnitRegistered"; id: string; address: string; bedrooms: number }
  | { type: "RenovationStarted"; at: string }
  | { type: "RenovationFinished"; at: string }
  | { type: "UnitDecommissioned"; at: string };

export class UnitError extends Error {
  constructor(public readonly code: string) { super(code); }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const unitDecider: Decider<UnitCommand, UnitEvent, UnitState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "empty") throw new UnitError("EXISTS");
        return [{ type: "UnitRegistered", id: command.id, address: command.address, bedrooms: command.bedrooms }];
      case "startRenovation":
        if (state.status !== "registered") throw new UnitError("NOT_REGISTERED");
        return [{ type: "RenovationStarted", at: command.at }];
      case "finishRenovation":
        if (state.status !== "renovating") throw new UnitError("NOT_RENOVATING");
        return [{ type: "RenovationFinished", at: command.at }];
      case "decommission":
        if (state.status === "decommissioned" || state.status === "empty") throw new UnitError("INVALID");
        return [{ type: "UnitDecommissioned", at: command.at }];
      default: {
        const _never: never = command;
        return _never;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "UnitRegistered":
        return { status: "registered", id: event.id, address: event.address, bedrooms: event.bedrooms };
      case "RenovationStarted":
        if (state.status !== "registered") return state;
        return { status: "renovating", id: state.id, address: state.address, bedrooms: state.bedrooms, since: event.at };
      case "RenovationFinished":
        if (state.status !== "renovating") return state;
        return { status: "registered", id: state.id, address: state.address, bedrooms: state.bedrooms };
      case "UnitDecommissioned":
        if (state.status === "empty" || state.status === "decommissioned") return state;
        return { status: "decommissioned", id: state.id, at: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

aggregateStream is the generic folder that sits between your event-store cursor and an aggregate's state. It takes an AsyncIterable of events, a pure evolve, and an initial literal, then walks the stream event by event, accumulating state. Because evolve is pure and deterministic, replaying the same stream always lands on the same state, which is the core guarantee event sourcing relies on for audits, migrations, and read-model rebuilds.

```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type ApartmentState = { status: "none" } | { status: "listed"; id: string; rent: number } | { status: "occupied"; id: string; rent: number; by: string };
export type ApartmentEvent =
  | { type: "ApartmentListed"; id: string; rent: number }
  | { type: "ApartmentOccupied"; by: string };

export function evolve(state: ApartmentState, event: ApartmentEvent): ApartmentState {
  switch (event.type) {
    case "ApartmentListed":
      return { status: "listed", id: event.id, rent: event.rent };
    case "ApartmentOccupied":
      if (state.status !== "listed") return state;
      return { status: "occupied", id: state.id, rent: state.rent, by: event.by };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function loadApartment(stream: AsyncIterable<ApartmentEvent>): Promise<ApartmentState> {
  return aggregateStream(stream, evolve, { status: "none" });
}
