type Ev =
  | { type: 'PICK_IN' }
  | { type: 'PICK_OUT' }
  | { type: 'SET'; ms: number }
  | { type: 'COMMIT' };

export const trimToggleMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    bothSet: ({ context }) => context.inMs !== null && context.outMs !== null
  }
}).createMachine({
  id: 'trimToggle',
  context: { inMs: null, outMs: null },
  initial: 'selectingIn',
  states: {
    selectingIn: {
      on: {
        SET: { actions: assign({ inMs: ({ event }) => event.ms }) },
        PICK_OUT: 'selectingOut',
        COMMIT: [{ guard: 'bothSet', target: 'previewing' }]
      }
    },
    selectingOut: {
      on: {
        SET: { actions: assign({ outMs: ({ event }) => event.ms }) },
        PICK_IN: 'selectingIn',
        COMMIT: [{ guard: 'bothSet', target: 'previewing' }]
      }
    },
    previewing: { type: 'final' }
  }
});
