A single GOTO event has three transition candidates — jump, snap to last page, and ignore. The array form with named guards evaluates top-down: if the requested page is in range we jump, if it exceeds total we snap, otherwise we fall through to the unguarded ignore.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { page: number; total: number }
type Ev = { type: 'GOTO'; page: number };

export const pageGuardMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    inRange: ({ context, event }) => event.page >= 1 && event.page <= context.total,
    tooHigh: ({ context, event }) => event.page > context.total
  },
  actions: {
    jump: assign({ page: ({ event }) => event.page }),
    snapLast: assign({ page: ({ context }) => context.total })
  }
}).createMachine({
  id: 'pageGuard',
  context: { page: 1, total: 20 },
  initial: 'viewing',
  states: {
    viewing: {
      on: {
        GOTO: [
          { guard: 'inRange', actions: 'jump' },
          { guard: 'tooHigh', actions: 'snapLast' },
          {}
        ]
      }
    }
  }
});
```

