export type RenderJobCommand =
  | { type: "queue"; id: string; sourceId: string }
  | { type: "finish"; outputUri: string };

export type RenderJobEvent =
  | { type: "RenderJobQueued"; id: string; sourceId: string }
  | { type: "RenderJobFinished"; outputUri: string };

export type RenderJobState =
  | { status: "none" }
  | { status: "queued"; id: string }
  | { status: "finished"; id: string };

export const initialState: RenderJobState = { status: "none" };

export function evolve(state: RenderJobState, event: RenderJobEvent): RenderJobState {
  switch (event.type) {
    case "RenderJobQueued":
      return { status: "queued", id: event.id };
    case "RenderJobFinished":
      if (state.status !== "queued") return state;
      return { status: "finished", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: RenderJobCommand, state: RenderJobState): RenderJobEvent[] {
  switch (command.type) {
    case "queue":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "RenderJobQueued", id: command.id, sourceId: command.sourceId }];
    case "finish":
      if (state.status !== "queued") throw new Error("NOT_QUEUED");
      return [{ type: "RenderJobFinished", outputUri: command.outputUri }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface RenderJobQueueItem {
  readonly id: string;
  readonly sourceId: string;
  readonly outputUri: string | null;
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export interface QueueView {
  list(): Promise<readonly RenderJobQueueItem[]>;
}

// The QueueView is eventually consistent with the event stream.
export async function handleCommand(
  store: EventStore<RenderJobEvent>,
  streamName: string,
  command: RenderJobCommand,
): Promise<void> {
  const loaded = await store.readStream(streamName);
  const state = loaded.events.reduce(evolve, initialState);
  const events = decide(command, state);
  await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
}

export async function queryView(view: QueueView): Promise<readonly RenderJobQueueItem[]> {
  return view.list();
}
