```typescript
export type VariantState =
  | { status: "new" }
  | { status: "registered"; id: string; key: string; traffic: number }
  | { status: "paused"; id: string; key: string; traffic: number };

export type VariantCommand =
  | { type: "register"; id: string; key: string }
  | { type: "allocateTraffic"; percent: number }
  | { type: "pause"; reason: string };

export type VariantEvent =
  | { type: "VariantRegistered"; id: string; key: string }
  | { type: "VariantTrafficAllocated"; percent: number }
  | { type: "VariantPaused"; reason: string };

export class VariantError extends Error {
  constructor(code: string) { super(code); this.name = "VariantError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const variantDecider: Decider<VariantCommand, VariantEvent, VariantState> = {
  initialState: { status: "new" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "new") throw new VariantError("EXISTS");
        if (command.key.length === 0) throw new VariantError("EMPTY_KEY");
        return [{ type: "VariantRegistered", id: command.id, key: command.key }];
      case "allocateTraffic":
        if (state.status === "new") throw new VariantError("NOT_REGISTERED");
        if (command.percent < 0 || command.percent > 100) throw new VariantError("BAD_PERCENT");
        return [{ type: "VariantTrafficAllocated", percent: command.percent }];
      case "pause":
        if (state.status !== "registered") throw new VariantError("CANNOT_PAUSE");
        return [{ type: "VariantPaused", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new VariantError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "VariantRegistered":
        return { status: "registered", id: event.id, key: event.key, traffic: 0 };
      case "VariantTrafficAllocated":
        if (state.status === "new") return state;
        return { ...state, traffic: event.percent };
      case "VariantPaused":
        if (state.status !== "registered") return state;
        return { status: "paused", id: state.id, key: state.key, traffic: state.traffic };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
