export interface OutboxRow { id: string; payload: unknown; publishedAt: Date | null; }

export interface TxConn {
  insertOutbox(rows: OutboxRow[]): Promise<void>;
  appendToStream(name: string, events: unknown[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface Transactional {
  begin(): Promise<TxConn>;
}

/**
 * Publisher worker (not implemented here): polls outbox WHERE publishedAt IS NULL,
 * publishes each row to the message bus, then marks publishedAt = now() in its
 * own transaction. Idempotency is the consumer's problem.
 */
export async function appendWithOutbox(
  tx: Transactional,
  stream: string,
  events: unknown[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<void> {
  const conn = await tx.begin();
  try {
    await conn.insertOutbox(outboxRows);
    await conn.appendToStream(stream, events, { expectedRevision });
    await conn.commit();
  } catch (err) {
    await conn.rollback();
    throw err;
  }
}
