export type ExpectedRevision = bigint | "no_stream" | "any";

export type PatientDomainEvent =
  | { type: "PatientRegistered"; id: string; mrn: string; name: string }
  | { type: "PatientAdmitted"; id: string; ward: string; at: string }
  | { type: "PatientDischarged"; id: string; at: string }
  | { type: "InternalFlagRaised"; id: string; reason: string };

export type IntegrationEvent =
  | { schema: "emr.patient.registered/v1"; payload: { id: string; mrn: string; name: string } }
  | { schema: "emr.patient.admitted/v1"; payload: { id: string; ward: string; at: string } }
  | { schema: "emr.patient.discharged/v1"; payload: { id: string; at: string } };

export function translate(event: PatientDomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "PatientRegistered":
      return { schema: "emr.patient.registered/v1", payload: { id: event.id, mrn: event.mrn, name: event.name } };
    case "PatientAdmitted":
      return { schema: "emr.patient.admitted/v1", payload: { id: event.id, ward: event.ward, at: event.at } };
    case "PatientDischarged":
      return { schema: "emr.patient.discharged/v1", payload: { id: event.id, at: event.at } };
    case "InternalFlagRaised":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface OutboxRow { readonly id: string; readonly payload: IntegrationEvent; readonly publishedAt: string | null }
export interface Tx {
  insertOutbox(row: OutboxRow): Promise<void>;
  appendToStream(stream: string, events: PatientDomainEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}
export interface Conn { transaction<T>(fn: (tx: Tx) => Promise<T>): Promise<T> }

export async function appendWithOutbox(
  conn: Conn,
  stream: string,
  events: PatientDomainEvent[],
  expectedRevision: ExpectedRevision,
  newId: (seed: number) => string,
): Promise<bigint> {
  return conn.transaction(async (tx) => {
    let seed = 0;
    for (const event of events) {
      const integration = translate(event);
      if (integration) {
        await tx.insertOutbox({ id: newId(seed++), payload: integration, publishedAt: null });
      }
    }
    const { nextRevision } = await tx.appendToStream(stream, events, { expectedRevision });
    return nextRevision;
  });
}
