export type ExhibitEvent = { type: "exhibitAdded"; packageId: string; exhibitId: string } | { type: "packageSealed"; packageId: string };
export type ExhibitView = { packageId: string; exhibits: number; sealed: boolean };
export function project(v: ExhibitView, e: ExhibitEvent): ExhibitView {
  switch (e.type) {
    case "exhibitAdded": return { ...v, exhibits: v.exhibits + 1 };
    case "packageSealed": return { ...v, sealed: true };
    default: { const _: never = e; return v; }
  }
}
export interface Stored<E> { revision: bigint; event: E }
export interface EventStore<E> { readBatch(from: bigint, size: number): Promise<Stored<E>[]> }
export interface ReadStore { save(id: string, v: ExhibitView): Promise<void> }
export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStore<ExhibitEvent>;
  reads: ReadStore;
  onProgress: (processed: bigint) => void;
}): Promise<void> {
  let cursor = opts.from;
  let processed = 0n;
  const views = new Map<string, ExhibitView>();
  while (true) {
    const batch = await opts.store.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      const id = event.packageId;
      const cur = views.get(id) ?? { packageId: id, exhibits: 0, sealed: false };
      const next = project(cur, event);
      views.set(id, next);
      await opts.reads.save(id, next);
      cursor = revision + 1n;
      processed += 1n;
    }
    opts.onProgress(processed);
  }
}
