export type AttributionEvent =
  | { type: "AttributionEventCaptured"; segmentId: string; userId: string; valueCents: number }
  | { type: "AttributionEventReverted"; segmentId: string; userId: string; valueCents: number }
  | { type: "AttributionEventFlagged"; segmentId: string; reason: string };

export interface SegmentRow {
  readonly conversions: number;
  readonly valueCents: number;
  readonly flags: number;
}

export interface SegmentConversionView {
  readonly bySegment: Readonly<Record<string, SegmentRow>>;
}

export const emptyView: SegmentConversionView = { bySegment: {} };

function merge(
  view: SegmentConversionView,
  id: string,
  delta: Partial<SegmentRow>,
): SegmentConversionView {
  const prev = view.bySegment[id] ?? { conversions: 0, valueCents: 0, flags: 0 };
  const next: SegmentRow = {
    conversions: Math.max(0, prev.conversions + (delta.conversions ?? 0)),
    valueCents: Math.max(0, prev.valueCents + (delta.valueCents ?? 0)),
    flags: prev.flags + (delta.flags ?? 0),
  };
  return { bySegment: { ...view.bySegment, [id]: next } };
}

export function project(view: SegmentConversionView, event: AttributionEvent): SegmentConversionView {
  switch (event.type) {
    case "AttributionEventCaptured":
      return merge(view, event.segmentId, { conversions: 1, valueCents: event.valueCents });
    case "AttributionEventReverted":
      return merge(view, event.segmentId, { conversions: -1, valueCents: -event.valueCents });
    case "AttributionEventFlagged":
      return merge(view, event.segmentId, { flags: 1 });
    default: {
      const _never: never = event;
      return view;
    }
  }
}
