    case "schedule":
      if (s.status !== "empty") throw new DomainError("exists");
      return [{ type: "scheduled", recordId: c.recordId, deponent: c.deponent }];
    case "uploadTranscript":
      if (s.status !== "active") throw new DomainError("not active");
      if (c.pages <= 0) throw new DomainError("no pages");
      return [{ type: "transcriptUploaded", pages: c.pages }];
    case "seal":
      if (s.status !== "active") throw new DomainError("not active");
      if (s.pages === 0) throw new DomainError("no transcript");
      return [{ type: "sealed" }];
    default: { const _: never = c; return _; }
  }
}
