  switch (e.type) {
    case "scheduled": return { status: "active", recordId: e.recordId, pages: 0 };
    case "transcriptUploaded": return s.status === "active" ? { ...s, pages: s.pages + e.pages } : s;
    case "sealed": return s.status === "active" ? { status: "sealed", recordId: s.recordId } : s;
    default: { const _: never = e; return _; }
  }
}
