}

export interface EventStore {
  readStream(stream: string): AsyncIterable<SagaEvent>;
}

export async function driveSaga(store: EventStore, streamName: string, dispatch: (c: SagaCommand) => Promise<void>): Promise<void> {
  for await (const event of store.readStream(streamName)) {
    const command = react(event);
    if (command) await dispatch(command);
  }
}
