export type DiningTableEvent =
  | { type: "TableOpened"; tableNo: number; seats: number }
  | { type: "PartySeated"; guests: number }
  | { type: "PartyLeft" };

export type DiningTable = Readonly<{
  tableNo: number;
  seats: number;
  currentGuests: number;
}>;

function when(state: Partial<DiningTable>, event: DiningTableEvent): Partial<DiningTable> {
  switch (event.type) {
    case "TableOpened":
      return { tableNo: event.tableNo, seats: event.seats, currentGuests: 0 };
    case "PartySeated":
      return { ...state, currentGuests: event.guests };
    case "PartyLeft":
      return { ...state, currentGuests: 0 };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function isDiningTable(v: Partial<DiningTable>): v is DiningTable {
  return (
    typeof v.tableNo === "number" &&
    typeof v.seats === "number" &&
    typeof v.currentGuests === "number"
  );
}

export class InvariantError extends Error {
  constructor(m: string) { super(m); this.name = "InvariantError"; }
}

export async function aggregateStream(events: AsyncIterable<DiningTableEvent>): Promise<DiningTable> {
  let state: Partial<DiningTable> = {};
  for await (const event of events) {
    state = when(state, event);
  }
  if (!isDiningTable(state)) throw new InvariantError("DINING_TABLE_INCOMPLETE");
  return state;
}
