```typescript
export type InventoryCommand =
  | { type: "receive"; sku: string; qty: number }
  | { type: "reserve"; sku: string; qty: number }
  | { type: "release"; sku: string; qty: number };

export type InventoryEvent =
  | { type: "StockReceived"; sku: string; qty: number }
  | { type: "StockReserved"; sku: string; qty: number }
  | { type: "StockReleased"; sku: string; qty: number };

export type InventoryState = Readonly<{
  onHand: Readonly<Record<string, number>>;
  reserved: Readonly<Record<string, number>>;
}>;

export const initialInventory: InventoryState = { onHand: {}, reserved: {} };

export class InventoryError extends Error {}

export function decide(command: InventoryCommand, state: InventoryState): InventoryEvent[] {
  switch (command.type) {
    case "receive":
      if (command.qty <= 0) throw new InventoryError("NON_POSITIVE");
      return [{ type: "StockReceived", sku: command.sku, qty: command.qty }];
    case "reserve": {
      const onHand = state.onHand[command.sku] ?? 0;
      const reserved = state.reserved[command.sku] ?? 0;
      if (command.qty > onHand - reserved) throw new InventoryError("INSUFFICIENT");
      return [{ type: "StockReserved", sku: command.sku, qty: command.qty }];
    }
    case "release": {
      const reserved = state.reserved[command.sku] ?? 0;
      if (command.qty > reserved) throw new InventoryError("OVER_RELEASE");
      return [{ type: "StockReleased", sku: command.sku, qty: command.qty }];
    }
    default: {
      const _n: never = command;
      throw new InventoryError("UNKNOWN");
    }
  }
}

export function evolve(state: InventoryState, event: InventoryEvent): InventoryState {
  switch (event.type) {
    case "StockReceived": {
      const prev = state.onHand[event.sku] ?? 0;
      return { ...state, onHand: { ...state.onHand, [event.sku]: prev + event.qty } };
    }
    case "StockReserved": {
      const prev = state.reserved[event.sku] ?? 0;
      return { ...state, reserved: { ...state.reserved, [event.sku]: prev + event.qty } };
    }
    case "StockReleased": {
      const prev = state.reserved[event.sku] ?? 0;
      return { ...state, reserved: { ...state.reserved, [event.sku]: prev - event.qty } };
    }
    default: {
      const _n: never = event;
      return state;
    }
  }
}
