export const CURRENT_VERSION = 3;

export interface ServicingV1 { id: string; open: string[]; }
export interface ServicingV2 { id: string; open: string[]; passed: string[]; }
export interface ServicingV3 { id: string; open: string[]; passed: string[]; signedBy: string | null; }

export type CurrentServicing = ServicingV3;

export interface Snapshot<S> { version: number; state: S; }

function v1Tov2(s: ServicingV1): ServicingV2 { return { ...s, passed: [] }; }
function v2Tov3(s: ServicingV2): ServicingV3 { return { ...s, signedBy: null }; }

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentServicing> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v === 1) { state = v1Tov2(state as ServicingV1); v = 2; }
  if (v === 2) { state = v2Tov3(state as ServicingV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error("SNAPSHOT_VERSION_UNSUPPORTED");
  return { version: CURRENT_VERSION, state: state as CurrentServicing };
}

export function loadServicing(snap: Snapshot<unknown> | null): CurrentServicing {
  if (!snap) return { id: "", open: [], passed: [], signedBy: null };
  return upgradeSnapshot(snap).state;
}
