A Decider packages three pure pieces for CookingSession: initialState literal, decide that returns events or throws, and evolve that folds events back to state. No I/O, no clocks; timestamps travel on events.

```typescript
export type CookingSessionState =
  | { status: "none" }
  | { status: "running"; id: string; chef: string; stepsDone: number }
  | { status: "paused"; id: string; chef: string; stepsDone: number }
  | { status: "finished"; id: string; finishedAt: string };

export type CookingSessionCommand =
  | { type: "start"; id: string; chef: string }
  | { type: "logStep" }
  | { type: "pause" }
  | { type: "resume" }
  | { type: "finish"; at: string };

export type CookingSessionEvent =
  | { type: "CookingSessionStarted"; id: string; chef: string }
  | { type: "CookingStepLogged" }
  | { type: "CookingSessionPaused" }
  | { type: "CookingSessionResumed" }
  | { type: "CookingSessionFinished"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const cookingSessionDecider: Decider<CookingSessionCommand, CookingSessionEvent, CookingSessionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "start":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "CookingSessionStarted", id: command.id, chef: command.chef }];
      case "logStep":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "CookingStepLogged" }];
      case "pause":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "CookingSessionPaused" }];
      case "resume":
        if (state.status !== "paused") throw new DomainError("NOT_PAUSED");
        return [{ type: "CookingSessionResumed" }];
      case "finish":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        if (state.stepsDone === 0) throw new DomainError("NO_STEPS");
        return [{ type: "CookingSessionFinished", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CookingSessionStarted":
        return { status: "running", id: event.id, chef: event.chef, stepsDone: 0 };
      case "CookingStepLogged":
        if (state.status !== "running") return state;
        return { ...state, stepsDone: state.stepsDone + 1 };
      case "CookingSessionPaused":
        if (state.status !== "running") return state;
        return { status: "paused", id: state.id, chef: state.chef, stepsDone: state.stepsDone };
      case "CookingSessionResumed":
        if (state.status !== "paused") return state;
        return { status: "running", id: state.id, chef: state.chef, stepsDone: state.stepsDone };
      case "CookingSessionFinished":
        if (state.status !== "running") return state;
        return { status: "finished", id: state.id, finishedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

```

Every mutating transition pushes the current selection onto a `history` stack and clears the `future` stack. UNDO pops from `history` and pushes onto `future`; REDO is the mirror. Guards gate each action on non-empty stacks so the machine stays well-formed.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { value: string; history: readonly string[]; future: readonly string[] };
type Ev = { type: 'SET'; value: string } | { type: 'UNDO' } | { type: 'REDO' };

export const undoable = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasHistory: ({ context }) => context.history.length > 0,
    hasFuture: ({ context }) => context.future.length > 0
  }
}).createMachine({
  id: 'undoable',
  initial: 'idle',
  context: { value: '', history: [], future: [] },
  states: {
    idle: {
      on: {
        SET: {
          actions: assign({
            history: ({ context }) => [...context.history, context.value],
            value: ({ event }) => event.value,
            future: () => [] as readonly string[]
          })
        },
        UNDO: {
          guard: 'hasHistory',
          actions: assign({
            value: ({ context }) => context.history[context.history.length - 1] ?? context.value,
            history: ({ context }) => context.history.slice(0, -1),
            future: ({ context }) => [context.value, ...context.future]
          })
        },
        REDO: {
          guard: 'hasFuture',
          actions: assign({
            value: ({ context }) => context.future[0] ?? context.value,
            history: ({ context }) => [...context.history, context.value],
            future: ({ context }) => context.future.slice(1)
          })
        }
      }
    }
  }
});
