export type CampaignStopState =
  | { status: "none" }
  | { status: "planned"; id: string; city: string }
  | { status: "confirmed"; id: string; city: string; date: string }
  | { status: "executed"; id: string; at: string };

export type CampaignStopCommand =
  | { type: "plan"; id: string; city: string }
  | { type: "confirm"; date: string }
  | { type: "execute"; at: string };

export type CampaignStopEvent =
  | { type: "planned"; id: string; city: string }
  | { type: "confirmed"; date: string }
  | { type: "executed"; at: string };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const CampaignStopDecider: Decider<CampaignStopCommand, CampaignStopEvent, CampaignStopState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "plan":
        if (s.status !== "none") throw new DomainError("exists");
        return [{ type: "planned", id: c.id, city: c.city }];
      case "confirm":
        if (s.status !== "planned") throw new DomainError("must be planned first");
        return [{ type: "confirmed", date: c.date }];
      case "execute":
        if (s.status !== "confirmed") throw new DomainError("not confirmed");
        return [{ type: "executed", at: c.at }];
      default: {
        const _: never = c;
        return _;
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "planned":
        return { status: "planned", id: e.id, city: e.city };
      case "confirmed":
        return s.status === "planned" ? { status: "confirmed", id: s.id, city: s.city, date: e.date } : s;
      case "executed":
        return s.status === "confirmed" ? { status: "executed", id: s.id, at: e.at } : s;
      default: {
        const _: never = e;
        return _;
      }
    }
  },
};
