export type TerritoryMapEvent =
  | { type: "created"; id: string }
  | { type: "districtAdded" }
  | { type: "sealed" };

export interface TerritoryMapState {
  id: string | null;
  districts: number;
  sealed: boolean;
}

export const emptyState: TerritoryMapState = { id: null, districts: 0, sealed: false };

type Handlers<S, E extends { type: string }> = {
  [K in E["type"]]: (state: S, event: Extract<E, { type: K }>) => S;
};

export function when<S, E extends { type: string }>(
  handlers: Handlers<S, E>,
): (state: S, event: E) => S {
  return (state, event) => {
    const handler = handlers[event.type as E["type"]] as (state: S, event: E) => S;
    return handler(state, event);
  };
}

export const evolveTerritoryMap = when<TerritoryMapState, TerritoryMapEvent>({
  created: (s, e) => ({ ...s, id: e.id }),
  districtAdded: (s) => ({ ...s, districts: s.districts + 1 }),
  sealed: (s) => ({ ...s, sealed: true }),
});

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}
