```typescript
export type ExpeditionEvent =
  | { type: "ExpeditionPlanned"; id: string; peak: string }
  | { type: "MemberEnrolled" }
  | { type: "ExpeditionLaunched"; at: string };

export interface ExpeditionState {
  readonly status: "none" | "planned" | "launched";
  readonly id: string;
  readonly peak: string;
  readonly members: number;
}

export const initialState: ExpeditionState = { status: "none", id: "", peak: "", members: 0 };

export function evolve(state: ExpeditionState, event: ExpeditionEvent): ExpeditionState {
  switch (event.type) {
    case "ExpeditionPlanned":
      return { status: "planned", id: event.id, peak: event.peak, members: 0 };
    case "MemberEnrolled":
      return { ...state, members: state.members + 1 };
    case "ExpeditionLaunched":
      return { ...state, status: "launched" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolveFn: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  const consume = async (): Promise<void> => {
    for await (const event of stream) {
      state = evolveFn(state, event);
    }
  };
  await consume();
  return state;
}

export async function loadExpedition(
  stream: AsyncIterable<ExpeditionEvent>,
): Promise<ExpeditionState> {
  return aggregateStream(stream, evolve, initialState);
}
```

`aggregateStream` is a pure async fold: it starts with the aggregate's initial state, iterates events in order, and hands each event to `evolve` to produce the next state. The initial state must be a literal so reconstruction is deterministic; `evolve` stays pure and total via an exhaustive `never` default.

```typescript
export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  async function main() {
    for await (const event of events) state = evolve(state, event);
  }
  await main();
  return state;
}

export type TeamRosterEvent =
  | { type: "TeamRosterFormed"; id: string }
  | { type: "TeamRosterPlayerAdded"; playerId: string }
  | { type: "TeamRosterPlayerReleased"; playerId: string }
  | { type: "TeamRosterCaptainSet"; playerId: string };

export interface TeamRosterState {
  id: string;
  players: string[];
  captain: string | null;
}

export const initialRoster: TeamRosterState = { id: "", players: [], captain: null };

export function evolveRoster(s: TeamRosterState, e: TeamRosterEvent): TeamRosterState {
  switch (e.type) {
    case "TeamRosterFormed":
      return { id: e.id, players: [], captain: null };
    case "TeamRosterPlayerAdded":
      return { ...s, players: [...s.players, e.playerId] };
    case "TeamRosterPlayerReleased":
      return {
        ...s,
        players: s.players.filter((p) => p !== e.playerId),
        captain: s.captain === e.playerId ? null : s.captain,
      };
    case "TeamRosterCaptainSet":
      return { ...s, captain: e.playerId };
    default: { const _n: never = e; return s; }
  }
}

export async function rebuildRoster(stream: AsyncIterable<TeamRosterEvent>): Promise<TeamRosterState> {
  return aggregateStream<TeamRosterState, TeamRosterEvent>(stream, evolveRoster, initialRoster);
}
