```typescript
export const CURRENT_VERSION = 3 as const;

export interface Snapshot<S> { readonly version: number; readonly state: S; }

interface DraftV1 { id: string; body: string; }
interface DraftV2 { id: string; body: string; revisions: number; }
export interface DraftCurrent {
  readonly id: string;
  readonly body: string;
  readonly revisions: number;
  readonly published: boolean;
}

function v1Tov2(s: DraftV1): DraftV2 { return { ...s, revisions: 0 }; }
function v2Tov3(s: DraftV2): DraftCurrent { return { ...s, published: false }; }

function isCurrent(value: unknown): value is DraftCurrent {
  if (!value || typeof value !== "object") return false;
  const v = value as Record<string, unknown>;
  return typeof v.id === "string"
    && typeof v.body === "string"
    && typeof v.revisions === "number"
    && typeof v.published === "boolean";
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<DraftCurrent> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as DraftV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as DraftV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED:${version}`);
  if (!isCurrent(state)) throw new Error("SHAPE_MISMATCH");
  return { version: CURRENT_VERSION, state };
}
```

A Decider is a trio: pure `decide(command, state): Event[]` for intent, pure `evolve(state, event): State` for truth, and a literal `initialState`. The handler loads events, folds via `evolve`, calls `decide`, and appends the produced events. All I/O lives outside.

```typescript
export type GeoFenceState =
  | { status: "none" }
  | { status: "defined"; id: string; radiusM: number }
  | { status: "active"; id: string; radiusM: number }
  | { status: "breached"; id: string; radiusM: number; at: string };

export type GeoFenceCommand =
  | { type: "define"; id: string; radiusM: number }
  | { type: "activate" }
  | { type: "breach"; at: string; by: string };

export type GeoFenceEvent =
  | { type: "GeoFenceDefined"; id: string; radiusM: number }
  | { type: "GeoFenceActivated" }
  | { type: "GeoFenceBreached"; at: string; by: string };

export class GeoFenceError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const geoFenceDecider: Decider<GeoFenceCommand, GeoFenceEvent, GeoFenceState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "define":
        if (state.status !== "none") throw new GeoFenceError("EXISTS");
        if (command.radiusM <= 0) throw new GeoFenceError("BAD_RADIUS");
        return [{ type: "GeoFenceDefined", id: command.id, radiusM: command.radiusM }];
      case "activate":
        if (state.status !== "defined") throw new GeoFenceError("NOT_DEFINED");
        return [{ type: "GeoFenceActivated" }];
      case "breach":
        if (state.status !== "active") throw new GeoFenceError("NOT_ACTIVE");
        return [{ type: "GeoFenceBreached", at: command.at, by: command.by }];
      default: { const _n: never = command; throw new GeoFenceError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "GeoFenceDefined":
        return { status: "defined", id: event.id, radiusM: event.radiusM };
      case "GeoFenceActivated":
        if (state.status !== "defined") return state;
        return { status: "active", id: state.id, radiusM: state.radiusM };
      case "GeoFenceBreached":
        if (state.status !== "active") return state;
        return { status: "breached", id: state.id, radiusM: state.radiusM, at: event.at };
      default: { const _n: never = event; return state; }
    }
  },
};
```

