export interface Snapshot<S> {
  readonly version: number;
  readonly streamRevision: bigint;
  readonly state: S;
}

export interface BidderState {
  readonly id: string;
  readonly balanceCents: number;
  readonly suspended: boolean;
}

export type BidderEvent =
  | { type: "BidderRegistered"; id: string; openingBalanceCents: number }
  | { type: "BidderBidPlaced"; amountCents: number }
  | { type: "BidderSuspended" }
  | { type: "BidderReinstated" };

export const CURRENT_VERSION = 1 as const;
export const SNAPSHOT_EVERY = 100 as const;

export const initialBidder: BidderState = { id: "", balanceCents: 0, suspended: false };

export function evolve(state: BidderState, event: BidderEvent): BidderState {
  switch (event.type) {
    case "BidderRegistered":
      return { id: event.id, balanceCents: event.openingBalanceCents, suspended: false };
    case "BidderBidPlaced":
      return { ...state, balanceCents: state.balanceCents - event.amountCents };
    case "BidderSuspended":
      return { ...state, suspended: true };
    case "BidderReinstated":
      return { ...state, suspended: false };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function rehydrate(
  snapshot: Snapshot<BidderState> | null,
  tail: readonly BidderEvent[],
): { state: BidderState; fromRevision: bigint } {
  const start = snapshot?.state ?? initialBidder;
  const fromRevision = snapshot?.streamRevision ?? 0n;
  const state = tail.reduce(evolve, start);
  return { state, fromRevision };
}

export function shouldSnapshot(eventsSinceLastSnapshot: number): boolean {
  return eventsSinceLastSnapshot >= SNAPSHOT_EVERY;
}

export function buildSnapshot(state: BidderState, streamRevision: bigint): Snapshot<BidderState> {
  return { version: CURRENT_VERSION, streamRevision, state };
}
