import { Effect } from "effect";
export type BillablePeriodCommand = { type: "start"; periodId: string; matter: string } | { type: "log"; hours: number };
export type BillablePeriodEvent = { type: "started"; periodId: string; matter: string } | { type: "logged"; hours: number };
export type BillablePeriodState = { status: "none" } | { status: "open"; periodId: string; total: number };
export const initialState: BillablePeriodState = { status: "none" };
export function evolve(s: BillablePeriodState, e: BillablePeriodEvent): BillablePeriodState {
  switch (e.type) {
    case "started": return { status: "open", periodId: e.periodId, total: 0 };
    case "logged": return s.status === "open" ? { ...s, total: s.total + e.hours } : s;
    default: { const _: never = e; return s; }
  }
}
export function decide(c: BillablePeriodCommand, s: BillablePeriodState): BillablePeriodEvent[] {
  switch (c.type) {
    case "start": return s.status === "none" ? [{ type: "started", periodId: c.periodId, matter: c.matter }] : [];
    case "log": return s.status === "open" ? [{ type: "logged", hours: c.hours }] : [];
    default: { const _: never = c; return []; }
  }
}
export interface EventStore<E> {
  read(stream: string): Effect.Effect<E[]>;
  append(stream: string, events: E[], rev: bigint | "no_stream"): Effect.Effect<void>;
}
export const handleCommand = (
  store: EventStore<BillablePeriodEvent>,
  streamName: string,
  command: BillablePeriodCommand,
): Effect.Effect<void> =>
  Effect.gen(function* () {
    const events = yield* store.read(streamName);
    const state = events.reduce<BillablePeriodState>(evolve, initialState);
    const toAppend = decide(command, state);
    yield* store.append(streamName, toAppend, "no_stream");
  });
