Track the previous column before moving, invoke a save actor, and restore on error.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Card = { id: string; column: string };

export const k = setup({
  types: {
    context: {} as { cards: Card[]; pending: { id: string; from: string } | null },
    events: {} as { type: 'MOVE'; id: string; column: string },
  },
  actors: {
    saveMove: fromPromise<void, { id: string; column: string }>(async ({ input }) => {
      const r = await fetch(`/cards/${input.id}`, {
        method: 'PUT',
        body: JSON.stringify({ column: input.column }),
      });
      if (!r.ok) throw new Error('save failed');
    }),
  },
}).createMachine({
  id: 'k',
  initial: 'idle',
  context: { cards: [], pending: null },
  states: {
    idle: {
      on: {
        MOVE: {
          target: 'saving',
          actions: assign({
            pending: ({ context, event }) => {
              const card = context.cards.find((c) => c.id === event.id);
              return card ? { id: event.id, from: card.column } : null;
            },
            cards: ({ context, event }) =>
              context.cards.map((c) => (c.id === event.id ? { ...c, column: event.column } : c)),
          }),
        },
      },
    },
    saving: {
      invoke: {
        src: 'saveMove',
        input: ({ context }) => {
          const id = context.pending?.id ?? '';
          const card = context.cards.find((c) => c.id === id);
          return { id, column: card?.column ?? '' };
        },
        onDone: {
          target: 'idle',
          actions: assign({ pending: () => null }),
        },
        onError: {
          target: 'idle',
          actions: assign({
            cards: ({ context }) =>
              context.pending
                ? context.cards.map((c) =>
                    c.id === context.pending!.id ? { ...c, column: context.pending!.from } : c,
                  )
                : context.cards,
            pending: () => null,
          }),
        },
      },
    },
  },
});
