A snapshot is a periodic serialization of aggregate state tagged with a schema version. On load, if the stored version is older than the current one, upgrade functions keyed by source version run in order to transform the state into the current shape. This lets the stream stay append-only while the state model evolves.

```typescript
export const CURRENT_VERSION = 3 as const;

interface V1 { id: string; balance: number }
interface V2 { id: string; balance: number; name: string }
interface V3 { id: string; balance: number; name: string; currency: string }

export type CurrentState = V3;

export interface Snapshot<S> {
  version: number;
  state: S;
}

function v1Tov2(s: V1): V2 {
  return { ...s, name: "(unnamed)" };
}
function v2Tov3(s: V2): V3 {
  return { ...s, currency: "USD" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let version = snap.version;
  let state = snap.state as unknown;
  if (version === 1) {
    state = v1Tov2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`unknown version ${version}`);
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
```

