  switch (event.type) {
    case 'ConversationStarted':
      return { status: 'open', id: event.id, participants: [] };
    case 'ParticipantAdded':
      return state.status === 'open'
        ? { ...state, participants: [...state.participants, event.userId] }
        : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

interface EventStore {
  readStream(s: string): Promise<ConversationEvent[]>;
}

export class ReadFailed {
  readonly _tag = 'ReadFailed';
  constructor(readonly cause: unknown) {}
}

export function loadConversation(store: EventStore, streamName: string) {
  return Effect.gen(function* () {
    const events = yield* Effect.tryPromise({
      try: () => store.readStream(streamName),
      catch: (cause) => new ReadFailed(cause),
    });
    return events.reduce(evolve, initial);
  });
}
