```typescript
export type FoodInspectionEvent =
  | { type: "FoodInspectionScheduled"; id: string; facility: string }
  | { type: "FoodInspectionConducted"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult {
  readonly nextRevision: bigint;
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: E }>>;
  appendToStream(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: ExpectedRevision) {
    super(`concurrency conflict on ${stream} (expected ${String(expected)})`);
    this.name = "ConcurrencyConflict";
  }
}

export async function safeAppend(
  store: EventStore<FoodInspectionEvent>,
  stream: string,
  events: readonly FoodInspectionEvent[],
): Promise<bigint> {
  const stored = await store.readStream(stream);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  try {
    const result = await store.appendToStream(stream, events, { expectedRevision: expected });
    return result.nextRevision;
  } catch (err) {
    if (err instanceof Error && /wrong.?expected.?version/i.test(err.message)) {
      throw new ConcurrencyConflict(stream, expected);
    }
    throw err;
  }
}

