```typescript
export type NutritionProfileState =
  | { status: "none" }
  | { status: "editing"; id: string; calories: number; protein: number; entries: number }
  | { status: "locked"; id: string; lockedAt: string };

export type NutritionProfileCommand =
  | { type: "open"; id: string }
  | { type: "declare"; calories: number; protein: number }
  | { type: "lock"; at: string };

export type NutritionProfileEvent =
  | { type: "NutritionProfileOpened"; id: string }
  | { type: "NutritionMacrosDeclared"; calories: number; protein: number }
  | { type: "NutritionProfileLocked"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const nutritionProfileDecider: Decider<NutritionProfileCommand, NutritionProfileEvent, NutritionProfileState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "NutritionProfileOpened", id: command.id }];
      case "declare":
        if (state.status !== "editing") throw new DomainError("NOT_EDITING");
        if (command.calories < 0 || command.protein < 0) throw new DomainError("NEGATIVE");
        return [{ type: "NutritionMacrosDeclared", calories: command.calories, protein: command.protein }];
      case "lock":
        if (state.status !== "editing") throw new DomainError("NOT_EDITING");
        if (state.entries === 0) throw new DomainError("EMPTY");
        return [{ type: "NutritionProfileLocked", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "NutritionProfileOpened":
        return { status: "editing", id: event.id, calories: 0, protein: 0, entries: 0 };
      case "NutritionMacrosDeclared":
        if (state.status !== "editing") return state;
        return { ...state, calories: state.calories + event.calories, protein: state.protein + event.protein, entries: state.entries + 1 };
      case "NutritionProfileLocked":
        if (state.status !== "editing") return state;
        return { status: "locked", id: state.id, lockedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

