```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
export interface EventStore {
  readRevision(stream: string): Promise<bigint | null>;
  appendToStream(stream: string, events: unknown[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`concurrency conflict: ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendTurnaround(
  store: EventStore,
  stream: string,
  events: unknown[],
): Promise<bigint> {
  const rev = await store.readRevision(stream);
  const expectedRevision: bigint | "no_stream" = rev === null ? "no_stream" : rev;
  try {
    return await store.appendToStream(stream, events, { expectedRevision });
  } catch (err) {
    const message = err instanceof Error ? err.message : "";
    if (message.includes("WrongExpectedVersion") || message.includes("revision_mismatch")) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
```

Read the current revision, pass it as `expectedRevision`, and map any conflict signal from the store onto a typed domain error. This keeps retries explicit at the call site.

```typescript
export type OutboundEvent =
  | { type: "OutboundPrepared"; id: string; destination: string }
  | { type: "OutboundLoaded"; crateId: string }
  | { type: "OutboundDispatched"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: ReadonlyArray<OutboundEvent>; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<OutboundEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<{ ok: true; revision: bigint } | { ok: false; actual: bigint | null }>;
}

export class ConcurrencyConflict extends Error {}

export async function writeOutbound(
  store: EventStore,
  stream: string,
  events: ReadonlyArray<OutboundEvent>,
): Promise<bigint> {
  const slice = await store.readStream(stream);
  const expectedRevision: ExpectedRevision = slice.revision ?? "no_stream";
  const res = await store.appendToStream(stream, events, { expectedRevision });
  if (!res.ok) throw new ConcurrencyConflict(`conflict on ${stream} actual=${String(res.actual)}`);
  return res.revision;
}
