```typescript
export type SummitAttemptEvent =
  | { type: "SummitAttemptStarted"; id: string; peak: string }
  | { type: "CheckpointReached"; name: string }
  | { type: "SummitReached"; at: string };

export interface SummitAttemptState {
  readonly status: "none" | "climbing" | "summited";
  readonly id: string;
  readonly peak: string;
  readonly checkpoints: number;
}

export const initialState: SummitAttemptState = { status: "none", id: "", peak: "", checkpoints: 0 };

export function when(state: SummitAttemptState, event: SummitAttemptEvent): SummitAttemptState {
  switch (event.type) {
    case "SummitAttemptStarted":
      return { status: "climbing", id: event.id, peak: event.peak, checkpoints: 0 };
    case "CheckpointReached":
      return { ...state, checkpoints: state.checkpoints + 1 };
    case "SummitReached":
      return { ...state, status: "summited" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  whenFn: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  const consume = async (): Promise<void> => {
    for await (const event of stream) {
      state = whenFn(state, event);
    }
  };
  await consume();
  return state;
}

export async function loadSummitAttempt(
  stream: AsyncIterable<SummitAttemptEvent>,
): Promise<SummitAttemptState> {
  return aggregateStream(stream, when, initialState);
}
```

