```typescript
export type DisbursementEvent =
  | { type: "DisbursementScheduled"; id: string; recipient: string; amount: number }
  | { type: "DisbursementExecuted"; id: string; at: string }
  | { type: "DisbursementCancelled"; id: string; reason: string };

export type DisbursementLedgerView = Readonly<{
  byId: Readonly<Record<string, {
    recipient: string;
    amount: number;
    status: "scheduled" | "executed" | "cancelled";
  }>>;
}>;

export const emptyView: DisbursementLedgerView = { byId: {} };

export function project(view: DisbursementLedgerView, event: DisbursementEvent): DisbursementLedgerView {
  switch (event.type) {
    case "DisbursementScheduled":
      return { byId: { ...view.byId, [event.id]: {
        recipient: event.recipient, amount: event.amount, status: "scheduled",
      } } };
    case "DisbursementExecuted": {
      const prior = view.byId[event.id];
      if (!prior) return view;
      return { byId: { ...view.byId, [event.id]: { ...prior, status: "executed" } } };
    }
    case "DisbursementCancelled": {
      const prior = view.byId[event.id];
      if (!prior) return view;
      return { byId: { ...view.byId, [event.id]: { ...prior, status: "cancelled" } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface Reader {
  readBatch(from: bigint, size: number): Promise<ReadonlyArray<{ revision: bigint; event: DisbursementEvent }>>;
}

export interface Store {
  wipe(): Promise<void>;
  save(view: DisbursementLedgerView): Promise<void>;
}

export async function rebuildDisbursementLedger(
  reader: Reader,
  store: Store,
  options: { from: bigint; batchSize: number },
): Promise<DisbursementLedgerView> {
  if (options.from === 0n) await store.wipe();
  let cursor: bigint = options.from;
  let view: DisbursementLedgerView = emptyView;
  while (true) {
    const batch = await reader.readBatch(cursor, options.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = project(view, event);
      cursor = revision + 1n;
    }
    await store.save(view);
  }
  return view;
}
```

