export const CURRENT_VERSION = 3 as const;

export interface Snapshot<S> {
  version: number;
  state: S;
}

interface ShiftV1 { id: string; hours: number }
interface ShiftV2 { id: string; hours: number; volunteerId: string }
interface ShiftV3 { id: string; hours: number; volunteerId: string; role: string }

export type CurrentShift = ShiftV3;

function v1Tov2(s: ShiftV1): ShiftV2 {
  return { ...s, volunteerId: "unknown" };
}

function v2Tov3(s: ShiftV2): ShiftV3 {
  return { ...s, role: "general" };
}

export function loadSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentShift> {
  let v = raw.version;
  let s: unknown = raw.state;
  if (v === 1) {
    s = v1Tov2(s as ShiftV1);
    v = 2;
  }
  if (v === 2) {
    s = v2Tov3(s as ShiftV2);
    v = 3;
  }
  if (v !== CURRENT_VERSION) throw new Error(`snapshot version ${v} not supported`);
  const state = s as CurrentShift;
  return { version: CURRENT_VERSION, state };
}
