  | { status: 'draft'; tracks: readonly Track[] }
  | { status: 'released'; tracks: readonly Track[]; releasedAt: string };

type AlbumCommand =
  | { type: 'AddTrack'; track: Track }
  | { type: 'Release'; releasedAt: string };

