```typescript
export type FleetVehicleEvent =
  | { type: "FleetVehicleEnrolled"; id: string; plate: string }
  | { type: "FleetVehicleAssigned"; driverId: string }
  | { type: "FleetVehicleRetired" };

export type FleetView = Readonly<{ id: string; plate: string; driverId?: string; retired: boolean }>;

export const emptyView: FleetView = { id: "", plate: "", retired: false };

export function project(view: FleetView, event: FleetVehicleEvent): FleetView {
  switch (event.type) {
    case "FleetVehicleEnrolled":
      return { id: event.id, plate: event.plate, retired: false };
    case "FleetVehicleAssigned":
      return { ...view, driverId: event.driverId };
    case "FleetVehicleRetired":
      return { ...view, retired: true };
    default: { const _n: never = event; return view; }
  }
}

export type Batch<E> = Readonly<{ events: ReadonlyArray<{ position: bigint; event: E }>; next: bigint | null }>;

export interface EventStoreReader<E> {
  readBatch(from: bigint, size: number): Promise<Batch<E>>;
}

export interface ReadStore<V> {
  persist(view: V): Promise<void>;
  writeCursor(name: string, position: bigint): Promise<void>;
}

export async function rebuild(opts: {
  name: string;
  from: bigint;
  batchSize: number;
  reader: EventStoreReader<FleetVehicleEvent>;
  store: ReadStore<FleetView>;
}): Promise<void> {
  let cursor = opts.from;
  let view: FleetView = emptyView;
  const loop = async (): Promise<void> => {
    for (;;) {
      const batch = await opts.reader.readBatch(cursor, opts.batchSize);
      if (batch.events.length === 0) return;
      for (const env of batch.events) {
        view = project(view, env.event);
      }
      await opts.store.persist(view);
      const last = batch.events[batch.events.length - 1];
      cursor = last.position + 1n;
      await opts.store.writeCursor(opts.name, cursor);
      if (batch.next === null) return;
    }
  };
  await loop();
}
