import { Effect } from "effect";

export type SeasonEvent =
  | { type: "SeasonOpened"; id: string; year: number }
  | { type: "SeasonMatchScheduled"; matchId: string }
  | { type: "SeasonClosed"; champion: string };

export interface SeasonState {
  id: string;
  year: number;
  matches: string[];
  champion: string | null;
  closed: boolean;
}

export const initialSeason: SeasonState = { id: "", year: 0, matches: [], champion: null, closed: false };

export function evolve(s: SeasonState, e: SeasonEvent): SeasonState {
  switch (e.type) {
    case "SeasonOpened":
      return { id: e.id, year: e.year, matches: [], champion: null, closed: false };
    case "SeasonMatchScheduled":
      return { ...s, matches: [...s.matches, e.matchId] };
    case "SeasonClosed":
      return { ...s, champion: e.champion, closed: true };
    default: { const _n: never = e; return s; }
  }
}

export function rebuild(events: readonly SeasonEvent[]): SeasonState {
  return events.reduce(evolve, initialSeason);
}

export interface SeasonReader {
  readAll(stream: string): Promise<readonly SeasonEvent[]>;
}

export function loadSeason(reader: SeasonReader, stream: string) {
  return Effect.gen(function* () {
    const events = yield* Effect.promise(() => reader.readAll(stream));
    return rebuild(events);
  });
}

export async function aggregateStream(stream: AsyncIterable<SeasonEvent>): Promise<SeasonState> {
  let state = initialSeason;
  async function main() {
    for await (const e of stream) state = evolve(state, e);
  }
  await main();
  return state;
}
```

A router machine models each route as a state and exposes a single `NAVIGATE` event whose `to` payload picks the target via guarded transitions. Declaring guards in `setup.guards` keeps them reusable across routes.

```typescript
import { setup, assign } from 'xstate';

type Route = 'home' | 'profile' | 'settings';
type Ctx = { path: Route; authed: boolean };
type Ev =
  | { type: 'NAVIGATE'; to: Route }
  | { type: 'LOGIN' }
  | { type: 'LOGOUT' };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canEnterSettings: ({ context, event }) =>
      event.type === 'NAVIGATE' && (event.to !== 'settings' || context.authed),
  },
  actions: {
    setPath: assign({
      path: ({ event }) => (event.type === 'NAVIGATE' ? event.to : 'home'),
    }),
  },
}).createMachine({
  id: 'router',
  context: { path: 'home', authed: false },
  initial: 'home',
  on: {
    LOGIN: { actions: assign({ authed: () => true }) },
    LOGOUT: { actions: assign({ authed: () => false }) },
  },
  states: {
    home: {
      on: {
        NAVIGATE: [
          { guard: 'canEnterSettings', target: 'settings', actions: 'setPath' },
          { target: 'profile', actions: 'setPath' },
        ],
      },
    },
    profile: {
      on: {
        NAVIGATE: [
          { guard: 'canEnterSettings', target: 'settings', actions: 'setPath' },
          { target: 'home', actions: 'setPath' },
        ],
      },
    },
    settings: {
      on: { NAVIGATE: { target: 'home', actions: 'setPath' } },
    },
  },
});
```

