export class UnknownEventError extends Error {}

type RawPledgeEvent =
  | { type: "pledged"; version: 1; amount: number; donor: string }
  | { type: "pledged"; version: 2; pledgedAmount: number; donor: string; currency: string }
  | { type: "withdrawn"; version: 1; donor: string };

export type PledgeEvent =
  | { type: "pledged"; pledgedAmount: number; donor: string; currency: string }
  | { type: "withdrawn"; donor: string };

export function upcast(raw: RawPledgeEvent): PledgeEvent {
  switch (raw.type) {
    case "pledged":
      if (raw.version === 1) {
        return { type: "pledged", pledgedAmount: raw.amount, donor: raw.donor, currency: "USD" };
      }
      return { type: "pledged", pledgedAmount: raw.pledgedAmount, donor: raw.donor, currency: raw.currency };
    case "withdrawn":
      return { type: "withdrawn", donor: raw.donor };
    default: {
      const _: never = raw;
      throw new UnknownEventError(JSON.stringify(_));
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<E[]>;
}

export async function readUpcasted(
  store: EventStore<RawPledgeEvent>,
  stream: string,
): Promise<PledgeEvent[]> {
  const raw = await store.readStream(stream);
  return raw.map(upcast);
}
