export type PenaltyBoxEvent =
  | { type: "SanctionIssued"; matchId: string; playerId: string; minutes: number; at: string }
  | { type: "SanctionServed"; matchId: string; playerId: string; at: string }
  | { type: "MatchFullTime"; matchId: string };

export interface PenaltyBoxRow {
  matchId: string;
  playerId: string;
  minutesRemaining: number;
  servedAt: string | null;
}

export type PenaltyBoxView = Record<string, PenaltyBoxRow>;

export const emptyPenaltyBox: PenaltyBoxView = {};

function key(matchId: string, playerId: string): string {
  return `${matchId}:${playerId}`;
}

export function project(view: PenaltyBoxView, event: PenaltyBoxEvent): PenaltyBoxView {
  switch (event.type) {
    case "SanctionIssued": {
      const k = key(event.matchId, event.playerId);
      return {
        ...view,
        [k]: { matchId: event.matchId, playerId: event.playerId, minutesRemaining: event.minutes, servedAt: null },
      };
    }
    case "SanctionServed": {
      const k = key(event.matchId, event.playerId);
      const existing = view[k];
      if (!existing) return view;
      return { ...view, [k]: { ...existing, minutesRemaining: 0, servedAt: event.at } };
    }
    case "MatchFullTime": {
      const filtered: PenaltyBoxView = {};
      for (const [k, row] of Object.entries(view)) {
        if (row.matchId !== event.matchId) filtered[k] = row;
      }
      return filtered;
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
