Add a cancel command to this SupplyRestock Decider skeleton so that scheduled restocks can be cancelled but completed ones cannot.

```typescript
export type SupplyRestockState =
  | { status: "scheduled"; id: string }
  | { status: "complete"; id: string };
```

```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export type SupplyRestockState =
  | { status: "none" }
  | { status: "scheduled"; id: string; item: string; qty: number }
  | { status: "complete"; id: string }
  | { status: "cancelled"; id: string };

export type SupplyRestockCommand =
  | { type: "schedule"; id: string; item: string; qty: number }
  | { type: "complete" }
  | { type: "cancel"; reason: string };

export type SupplyRestockEvent =
  | { type: "RestockScheduled"; id: string; item: string; qty: number }
  | { type: "RestockCompleted" }
  | { type: "RestockCancelled"; reason: string };

export class RestockError extends Error {}

const initialState: SupplyRestockState = { status: "none" };

function decide(
  c: SupplyRestockCommand,
  s: SupplyRestockState,
): SupplyRestockEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new RestockError("already scheduled");
      return [
        { type: "RestockScheduled", id: c.id, item: c.item, qty: c.qty },
      ];
    case "complete":
      if (s.status !== "scheduled") throw new RestockError("cannot complete");
      return [{ type: "RestockCompleted" }];
    case "cancel":
      if (s.status !== "scheduled")
        throw new RestockError("cannot cancel");
      return [{ type: "RestockCancelled", reason: c.reason }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

function evolve(
  s: SupplyRestockState,
  e: SupplyRestockEvent,
): SupplyRestockState {
  switch (e.type) {
    case "RestockScheduled":
      return { status: "scheduled", id: e.id, item: e.item, qty: e.qty };
    case "RestockCompleted":
      return s.status === "scheduled" ? { status: "complete", id: s.id } : s;
    case "RestockCancelled":
      return s.status === "scheduled"
        ? { status: "cancelled", id: s.id }
        : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export const supplyRestockDecider: Decider<
  SupplyRestockCommand,
  SupplyRestockEvent,
  SupplyRestockState
> = { initialState, decide, evolve };
```

```typescript
export type AlertStateV1 = { id: string; raised: boolean };
export type AlertStateV2 = { id: string; raised: boolean; level: number };
export type AlertStateV3 = { id: string; status: "quiet" | "raised" | "cleared"; level: number };

export type CurrentAlertState = AlertStateV3;

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3;

function v1Tov2(s: AlertStateV1): AlertStateV2 {
  return { id: s.id, raised: s.raised, level: 0 };
}

function v2Tov3(s: AlertStateV2): AlertStateV3 {
  return { id: s.id, status: s.raised ? "raised" : "quiet", level: s.level };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentAlertState> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as AlertStateV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as AlertStateV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_${v}`);
  return { version: CURRENT_VERSION, state: s as CurrentAlertState };
}

export function serialise(state: CurrentAlertState): Snapshot<CurrentAlertState> {
  return { version: CURRENT_VERSION, state };
}

export function load(raw: Snapshot<unknown>): CurrentAlertState {
  const snap = upgradeSnapshot(raw);
  if (snap.version !== CURRENT_VERSION) throw new Error("UPGRADE_FAILED");
  return snap.state;
}
