export const CURRENT_VERSION = 2;

export interface HerdV1 {
  readonly id: string;
  readonly species: string;
  readonly count: number;
}

export interface HerdV2 {
  readonly id: string;
  readonly species: string;
  readonly headCount: number;
  readonly tags: ReadonlyArray<string>;
}

export type HerdCurrent = HerdV2;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(prev: HerdV1): HerdV2 {
  return { id: prev.id, species: prev.species, headCount: prev.count, tags: [] };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<HerdCurrent> {
  if (raw.version === CURRENT_VERSION) {
    return { version: CURRENT_VERSION, state: raw.state as HerdCurrent };
  }
  if (raw.version === 1) {
    const next = v1Tov2(raw.state as HerdV1);
    return { version: CURRENT_VERSION, state: next };
  }
  throw new Error(`UNSUPPORTED_VERSION_${raw.version}`);
}
