export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  async function main() {
    for await (const event of stream) {
      state = evolve(state, event);
    }
  }
  await main();
  return state;
}

export type PenaltyBoxEvent =
  | { type: "PenaltyBoxEntered"; playerId: string; minutes: number; at: string }
  | { type: "PenaltyBoxServed"; playerId: string; at: string }
  | { type: "PenaltyBoxReleased"; playerId: string };

export interface PenaltyBoxState {
  active: Record<string, { minutes: number; since: string }>;
  released: string[];
}

export const initialBox: PenaltyBoxState = { active: {}, released: [] };

export function evolveBox(s: PenaltyBoxState, e: PenaltyBoxEvent): PenaltyBoxState {
  switch (e.type) {
    case "PenaltyBoxEntered":
      return { ...s, active: { ...s.active, [e.playerId]: { minutes: e.minutes, since: e.at } } };
    case "PenaltyBoxServed": {
      const next: Record<string, { minutes: number; since: string }> = {};
      for (const [k, v] of Object.entries(s.active)) if (k !== e.playerId) next[k] = v;
      return { ...s, active: next };
    }
    case "PenaltyBoxReleased":
      return { ...s, released: [...s.released, e.playerId] };
    default: { const _n: never = e; return s; }
  }
}

export async function rebuildPenaltyBox(stream: AsyncIterable<PenaltyBoxEvent>): Promise<PenaltyBoxState> {
  return aggregateStream<PenaltyBoxState, PenaltyBoxEvent>(stream, evolveBox, initialBox);
}
