export type OutlineState =
  | { status: "empty" }
  | { status: "drafted"; id: string; sections: ReadonlyArray<string> }
  | { status: "approved"; id: string; sections: ReadonlyArray<string>; approvedAt: string };

export type OutlineCommand =
  | { type: "draft"; id: string; sections: ReadonlyArray<string> }
  | { type: "reorder"; sections: ReadonlyArray<string> }
  | { type: "approve"; at: string };

export type OutlineEvent =
  | { type: "OutlineDrafted"; id: string; sections: ReadonlyArray<string> }
  | { type: "OutlineReordered"; sections: ReadonlyArray<string> }
  | { type: "OutlineApproved"; at: string };

export class OutlineError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "OutlineError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const outlineDecider: Decider<OutlineCommand, OutlineEvent, OutlineState> = {
  initialState: { status: "empty" },
  decide(c, s) {
    switch (c.type) {
      case "draft":
        if (s.status !== "empty") throw new OutlineError("EXISTS");
        if (c.sections.length === 0) throw new OutlineError("EMPTY");
        return [{ type: "OutlineDrafted", id: c.id, sections: c.sections }];
      case "reorder":
        if (s.status === "approved") throw new OutlineError("APPROVED");
        if (s.status !== "drafted") throw new OutlineError("NOT_DRAFTED");
        return [{ type: "OutlineReordered", sections: c.sections }];
      case "approve":
        if (s.status !== "drafted") throw new OutlineError("NOT_DRAFTED");
        return [{ type: "OutlineApproved", at: c.at }];
      default: { const _n: never = c; throw new OutlineError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "OutlineDrafted": return { status: "drafted", id: e.id, sections: e.sections };
      case "OutlineReordered": return s.status === "drafted" ? { ...s, sections: e.sections } : s;
      case "OutlineApproved":
        if (s.status !== "drafted") return s;
        return { status: "approved", id: s.id, sections: s.sections, approvedAt: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
