export type ReworkState = { status: "none" } | { status: "open"; id: string } | { status: "closed"; id: string };
export type ReworkCommand = { type: "open"; id: string } | { type: "close"; at: string };
export type ReworkEvent = { type: "ReworkOpened"; id: string } | { type: "ReworkClosed"; at: string };

export function evolve(s: ReworkState, e: ReworkEvent): ReworkState {
  switch (e.type) {
    case "ReworkOpened": return { status: "open", id: e.id };
    case "ReworkClosed":
      if (s.status !== "open") return s;
      return { status: "closed", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: ReworkCommand, s: ReworkState): ReworkEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "ReworkOpened", id: c.id }];
    case "close":
      if (s.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "ReworkClosed", at: c.at }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export class ConcurrencyConflict extends Error {
  constructor(readonly stream: string) { super("CONFLICT"); this.name = "ConcurrencyConflict"; }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: ReworkEvent; revision: bigint }>;
  appendToStream(stream: string, events: ReworkEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ ok: boolean }>;
}

export async function handleRework(command: ReworkCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  let state: ReworkState = { status: "none" };
  let revision: ExpectedRevision = "no_stream";
  for await (const { event, revision: r } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    revision = r;
  }
  const out = decide(command, state);
  const res = await ctx.eventStore.appendToStream(ctx.streamName, out, { expectedRevision: revision });
  if (!res.ok) throw new ConcurrencyConflict(ctx.streamName);
}
```

Use `enqueueActions` on the SAMPLE handler — assign the new value, then conditionally enqueue a `raise({ type: 'OVERHEAT' })` when the guarded check passes.

```typescript
import { setup, assign, enqueueActions } from 'xstate';

interface Ctx { current: number }
type Ev = { type: 'SAMPLE'; value: number } | { type: 'OVERHEAT' };

export const overheatMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    over: ({ context }) => context.current > 90
  }
}).createMachine({
  id: 'overheat',
  context: { current: 20 },
  initial: 'ok',
  states: {
    ok: {
      on: {
        SAMPLE: {
          actions: enqueueActions(({ enqueue, check, event }) => {
            if (event.type !== 'SAMPLE') return;
            enqueue.assign({ current: event.value });
            if (check('over')) enqueue.raise({ type: 'OVERHEAT' });
          })
        },
        OVERHEAT: 'tripped'
      }
    },
    tripped: {
      on: { SAMPLE: { actions: assign({ current: ({ event }) => (event.type === 'SAMPLE' ? event.value : 0) }) } }
    }
  }
});
```

