export type CurrentConsentPackage = {
  id: string;
  subjectId: string;
  subjectName: string;
  clauseCount: number;
};

export const CURRENT_VERSION = 3;

export type Snapshot<S> = { version: number; state: S };

type V1 = { id: string; subjectName: string };
type V2 = { id: string; subjectId: string; subjectName: string };

function v1ToV2(raw: V1): V2 {
  const slug = raw.subjectName.toLowerCase().replace(/[^a-z0-9]+/g, "-");
  return { id: raw.id, subjectId: slug, subjectName: raw.subjectName };
}

function v2ToV3(raw: V2): CurrentConsentPackage {
  return { ...raw, clauseCount: 0 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentConsentPackage> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1ToV2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2ToV3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`Unsupported version ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentConsentPackage };
}
