```typescript
// Eventual consistency: read store is updated by a separate projection worker.
export type DataReleaseCommand =
  | { type: "prepare"; id: string; datasetId: string }
  | { type: "publish"; at: string };

export type DataReleaseEvent =
  | { type: "DataReleasePrepared"; id: string; datasetId: string }
  | { type: "DataReleasePublished"; at: string };

type WriteState =
  | { status: "none" }
  | { status: "prepared"; id: string; datasetId: string }
  | { status: "published"; id: string; publishedAt: string };

const initial: WriteState = { status: "none" };

function evolve(state: WriteState, event: DataReleaseEvent): WriteState {
  switch (event.type) {
    case "DataReleasePrepared":
      return { status: "prepared", id: event.id, datasetId: event.datasetId };
    case "DataReleasePublished":
      return state.status === "prepared" ? { status: "published", id: state.id, publishedAt: event.at } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: DataReleaseCommand, state: WriteState): DataReleaseEvent[] {
  switch (command.type) {
    case "prepare":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "DataReleasePrepared", id: command.id, datasetId: command.datasetId }];
    case "publish":
      if (state.status !== "prepared") throw new Error("NOT_PREPARED");
      return [{ type: "DataReleasePublished", at: command.at }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export type DataReleaseReadView = { id: string; datasetId: string; published: boolean };
export interface ReadStore { get(id: string): Promise<DataReleaseReadView | null>; }

export async function handleCommand(command: DataReleaseCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  const read = await ctx.eventStore.readStream<DataReleaseEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
}

export async function queryDataRelease(id: string, store: ReadStore): Promise<DataReleaseReadView | null> {
  return store.get(id);
}
