export type ReferendumEvent =
  | { type: "Published"; id: string; at: string }
  | { type: "Opened"; at: string };

export type OutboxRow = {
  id: string;
  schema: string;
  payload: string;
  publishedAt: string | null;
};

export interface Tx {
  appendToStream(stream: string, events: ReferendumEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
  insertOutbox(rows: OutboxRow[]): Promise<void>;
}

export interface Conn {
  transact<T>(fn: (tx: Tx) => Promise<T>): Promise<T>;
}

export function toOutbox(event: ReferendumEvent, id: string): OutboxRow {
  switch (event.type) {
    case "Published":
      return {
        id: `${id}-published`,
        schema: "referendum.published.v1",
        payload: JSON.stringify({ id: event.id, at: event.at }),
        publishedAt: null,
      };
    case "Opened":
      return {
        id: `${id}-opened`,
        schema: "referendum.opened.v1",
        payload: JSON.stringify({ at: event.at }),
        publishedAt: null,
      };
    default: {
      const _: never = event;
      return _;
    }
  }
}

// A separate worker polls outbox rows with publishedAt == null,
// publishes them to the broker, then sets publishedAt = now().
export async function appendWithOutbox(
  conn: Conn,
  stream: string,
  id: string,
  events: ReferendumEvent[],
  expectedRevision: bigint | "no_stream",
): Promise<void> {
  await conn.transact(async (tx) => {
    await tx.appendToStream(stream, events, { expectedRevision });
    const rows = events.map((e) => toOutbox(e, id));
    await tx.insertOutbox(rows);
  });
}
