`fromCallback` returns a cleanup function. When the invoking state exits — whether by transition, cancellation, or machine stop — v5 calls that cleanup. That is the only hook you need to release timers, workers, or sockets; you don't manage it from the machine body.

```typescript
import { setup, assign, fromCallback } from 'xstate';

interface Ctx { readonly pct: number; readonly url: string | null }
type Ev = { type: 'UPLOAD' } | { type: 'PROGRESS'; pct: number } | { type: 'DONE'; url: string } | { type: 'CANCEL' };

export const compressor = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    transcode: fromCallback<Ev, void>(({ sendBack }) => {
      const worker = { stopped: false };
      let pct = 0;
      const h = setInterval(() => {
        if (worker.stopped) return;
        pct += 25;
        if (pct >= 100) { sendBack({ type: 'DONE', url: 'blob://x' }); clearInterval(h); }
        else sendBack({ type: 'PROGRESS', pct });
      }, 100);
      return () => { worker.stopped = true; clearInterval(h); };
    })
  }
}).createMachine({
  id: 'c',
  initial: 'idle',
  context: { pct: 0, url: null },
  states: {
    idle: { on: { UPLOAD: 'transcoding' } },
    transcoding: {
      invoke: { src: 'transcode' },
      on: {
        PROGRESS: { actions: assign({ pct: ({ event }) => event.pct }) },
        DONE: { target: 'ready', actions: assign({ url: ({ event }) => event.url }) },
        CANCEL: 'idle'
      }
    },
    ready: {}
  }
});
