```typescript
export type GearCheckState =
  | { status: "none" }
  | { status: "inProgress"; id: string; items: number; failed: number };

export type GearCheckCommand =
  | { type: "begin"; id: string }
  | { type: "inspectItem"; passed: boolean };

export type GearCheckEvent =
  | { type: "GearCheckBegun"; id: string }
  | { type: "ItemInspected"; passed: boolean };

export const initialState: GearCheckState = { status: "none" };

export function evolve(state: GearCheckState, event: GearCheckEvent): GearCheckState {
  switch (event.type) {
    case "GearCheckBegun":
      return { status: "inProgress", id: event.id, items: 0, failed: 0 };
    case "ItemInspected":
      if (state.status !== "inProgress") return state;
      return { ...state, items: state.items + 1, failed: state.failed + (event.passed ? 0 : 1) };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: GearCheckCommand, state: GearCheckState): GearCheckEvent[] {
  switch (command.type) {
    case "begin":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "GearCheckBegun", id: command.id }];
    case "inspectItem":
      if (state.status !== "inProgress") throw new Error("NOT_IN_PROGRESS");
      return [{ type: "ItemInspected", passed: command.passed }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: ReadonlyArray<E>; revision: ExpectedRevision }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
}

export class CommandHandler<C, E, S> {
  constructor(
    private readonly store: EventStore<E>,
    private readonly evolveFn: (state: S, event: E) => S,
    private readonly decideFn: (command: C, state: S) => E[],
    private readonly initial: S,
  ) {}

  async handle(streamName: string, command: C): Promise<void> {
    const loaded = await this.store.readStream(streamName);
    let state = this.initial;
    for (const event of loaded.events) {
      state = this.evolveFn(state, event);
    }
    const events = this.decideFn(command, state);
    await this.store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
  }
}
