type Command = { type: 'Catalogue'; catalogueId: string };
type SampleEvent = { type: 'SampleCatalogued'; catalogueId: string };
type State = { status: 'collected' } | { status: 'catalogued' };
const initial: State = { status: 'collected' };

function evolve(state: State, event: SampleEvent): State {
  switch (event.type) {
    case 'SampleCatalogued':
      return { status: 'catalogued' };
    default: {
      const _: never = event.type;
      return _;
    }
  }
}

function decide(cmd: Command, state: State): SampleEvent[] {
  if (state.status === 'catalogued') throw new Error('already catalogued');
  return [{ type: 'SampleCatalogued', catalogueId: cmd.catalogueId }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: SampleEvent; revision: bigint }>;
  appendToStream(s: string, e: SampleEvent[], o: { expectedRevision: bigint | 'no_stream' }): Promise<void>;
}

export async function handleCatalogue(
  cmd: Command,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initial;
  let rev: bigint | 'no_stream' = 'no_stream';
  for await (const entry of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, entry.event);
    rev = entry.revision;
  }
  await ctx.eventStore.appendToStream(ctx.streamName, decide(cmd, state), { expectedRevision: rev });
}
