        ],
      }),
    },
    EDIT: {
      actions: assign({
        tabs: ({ context, event }) =>
          context.tabs.map((t) =>
            t.id === event.id ? { ...t, content: event.value, dirty: true } : t,
          ),
      }),
    },
    SAVE: {
      actions: assign({
        tabs: ({ context, event }) =>
          context.tabs.map((t) => (t.id === event.id ? { ...t, dirty: false } : t)),
      }),
    },
    CLOSE_ALL: {
      guard: 'anyDirty',
      actions: assign({ tabs: () => [] }),
    },
  },
