type ClaimEvent =
  | { type: 'ClaimStaked'; holder: string }
  | { type: 'ClaimTransferred'; to: string };

interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: ClaimEvent; revision: bigint }>;
  appendToStream(
    stream: string,
    events: ClaimEvent[],
    opts: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<void>;
}

export class ConcurrencyConflict extends Error {}

export async function writeClaim(
  store: EventStore,
  stream: string,
  events: ClaimEvent[],
): Promise<void> {
  let expected: bigint | 'no_stream' = 'no_stream';
  for await (const entry of store.readStream(stream)) {
    expected = entry.revision;
  }
  try {
    await store.appendToStream(stream, events, { expectedRevision: expected });
  } catch (err) {
    if (err instanceof Error && /expected/i.test(err.message)) {
      throw new ConcurrencyConflict('stale revision for ' + stream);
    }
    throw err;
  }
}
