export type ReleaseCommand = { type: "plan"; id: string; version: string };
export type ReleaseEvent = { type: "ReleasePlanned"; id: string; version: string };
export type ReleaseState = { status: "empty" } | { status: "planned"; id: string };
export type ReleaseView = { id: string; version: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export interface ViewStore {
  get(id: string): Promise<ReleaseView | null>;
}

const initial: ReleaseState = { status: "empty" };

function evolve(s: ReleaseState, e: ReleaseEvent): ReleaseState {
  switch (e.type) {
    case "ReleasePlanned": return { status: "planned", id: e.id };
    default: { const _n: never = e.type; return s; }
  }
}

function decide(c: ReleaseCommand, s: ReleaseState): ReleaseEvent[] {
  switch (c.type) {
    case "plan":
      if (s.status !== "empty") throw new Error("EXISTS");
      return [{ type: "ReleasePlanned", id: c.id, version: c.version }];
    default: { const _n: never = c.type; throw new Error("UNKNOWN"); }
  }
}

// Read store is eventually consistent with the event store — the projection runs async.
export async function handleCommand(cmd: ReleaseCommand, stream: string, store: EventStore): Promise<void> {
  const { events, revision } = await store.readStream<ReleaseEvent>(stream);
  const state = events.reduce<ReleaseState>(evolve, initial);
  const newEvents = decide(cmd, state);
  await store.appendToStream<ReleaseEvent>(stream, newEvents, { expectedRevision: revision });
}

export async function queryView(id: string, views: ViewStore): Promise<ReleaseView | null> {
  return views.get(id);
}
