export type GradeEvent =
  | { type: "GradeRecorded"; id: string; learner: string; course: string; score: number }
  | { type: "GradeCorrected"; id: string; score: number }
  | { type: "GradeVoided"; id: string; reason: string }
  | { type: "GradeNotePrivate"; id: string; note: string };

export type IntegrationEvent =
  | {
      schema: "grade/recorded/v1";
      payload: { gradeId: string; learner: string; course: string; score: number };
    }
  | {
      schema: "grade/voided/v1";
      payload: { gradeId: string; reason: string };
    };

export function translate(event: GradeEvent): IntegrationEvent | null {
  switch (event.type) {
    case "GradeRecorded":
      return {
        schema: "grade/recorded/v1",
        payload: { gradeId: event.id, learner: event.learner, course: event.course, score: event.score },
      };
    case "GradeCorrected":
      // Corrections are internal refinements; downstream consumers only see the net effect.
      return null;
    case "GradeVoided":
      return {
        schema: "grade/voided/v1",
        payload: { gradeId: event.id, reason: event.reason },
      };
    case "GradeNotePrivate":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

// Fold a batch of domain events into the integration-event projection the
// outbox publisher will forward.
export function project(events: ReadonlyArray<GradeEvent>): IntegrationEvent[] {
  return events.reduce<IntegrationEvent[]>((acc, event) => {
    const mapped = translate(event);
    return mapped === null ? acc : [...acc, mapped];
  }, []);
}
