export class ConcurrencyConflict extends Error {}
export type PrivilegeReviewEvent =
  | { type: "reviewStarted"; docId: string }
  | { type: "privilegeAsserted" }
  | { type: "reviewCompleted" };
export type PrivilegeReviewState =
  | { status: "none" }
  | { status: "inReview"; docId: string; privileged: boolean }
  | { status: "completed" };
export type PrivilegeReviewCommand = { type: "start"; docId: string } | { type: "assert" } | { type: "complete" };
export function evolve(s: PrivilegeReviewState, e: PrivilegeReviewEvent): PrivilegeReviewState {
  switch (e.type) {
    case "reviewStarted": return { status: "inReview", docId: e.docId, privileged: false };
    case "privilegeAsserted": return s.status === "inReview" ? { ...s, privileged: true } : s;
    case "reviewCompleted": return { status: "completed" };
    default: { const _: never = e; return s; }
  }
}
export function decide(c: PrivilegeReviewCommand, s: PrivilegeReviewState): PrivilegeReviewEvent[] {
  switch (c.type) {
    case "start": return s.status === "none" ? [{ type: "reviewStarted", docId: c.docId }] : [];
    case "assert": return s.status === "inReview" ? [{ type: "privilegeAsserted" }] : [];
    case "complete": return s.status === "inReview" ? [{ type: "reviewCompleted" }] : [];
    default: { const _: never = c; return []; }
  }
}
