export interface EventStore<E> {
  readStream(s: string): AsyncIterable<Read<E>>;
  appendToStream(s: string, evts: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ nextRevision: bigint }>;
}
export async function handle(store: EventStore<PrivilegeReviewEvent>, stream: string, cmd: PrivilegeReviewCommand): Promise<bigint> {
  let state: PrivilegeReviewState = { status: "none" };
  let rev: bigint | "no_stream" = "no_stream";
  for await (const r of store.readStream(stream)) { state = evolve(state, r.event); rev = r.revision; }
  const events = decide(cmd, state);
  try {
    const { nextRevision } = await store.appendToStream(stream, events, { expectedRevision: rev });
    return nextRevision;
  } catch (err) { throw new ConcurrencyConflict((err as Error).message); }
