export type KitchenOrderEvent =
  | { type: "TicketQueued"; id: string }
  | { type: "CookingStarted" }
  | { type: "OrderReady" };

export type KitchenOrder = Readonly<{
  id: string;
  queued: boolean;
  cooking: boolean;
  ready: boolean;
}>;

const initial: KitchenOrder = { id: "", queued: false, cooking: false, ready: false };

export function when(state: KitchenOrder, event: KitchenOrderEvent): KitchenOrder {
  switch (event.type) {
    case "TicketQueued": return { ...state, id: event.id, queued: true };
    case "CookingStarted": return { ...state, cooking: true };
    case "OrderReady": return { ...state, ready: true };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  fold: (s: S, e: E) => S,
  seed: S
): Promise<S> {
  let s: S = seed;
  for await (const e of events) s = fold(s, e);
  return s;
}

export function rebuildKitchenOrder(events: AsyncIterable<KitchenOrderEvent>): Promise<KitchenOrder> {
  return aggregateStream(events, when, initial);
}
