export type ReleaseCandidateEvent =
  | { type: "RCStaged"; id: string; version: string }
  | { type: "RCPromoted"; env: string }
  | { type: "RCBurned"; reason: string };

export type ReleaseCandidateState =
  | { status: "none" }
  | { status: "staged"; id: string; version: string; envs: string[] }
  | { status: "burned"; id: string; reason: string };

export const initialState: ReleaseCandidateState = { status: "none" };

export function evolve(state: ReleaseCandidateState, event: ReleaseCandidateEvent): ReleaseCandidateState {
  switch (event.type) {
    case "RCStaged":
      return { status: "staged", id: event.id, version: event.version, envs: [] };
    case "RCPromoted":
      if (state.status !== "staged") return state;
      return { ...state, envs: [...state.envs, event.env] };
    case "RCBurned":
      if (state.status === "burned") return state;
      if (state.status === "none") return { status: "burned", id: "unknown", reason: event.reason };
      return { status: "burned", id: state.id, reason: event.reason };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: ReleaseCandidateEvent[]): ReleaseCandidateState {
  return events.reduce(evolve, initialState);
}
