A CommandHandler orchestrates: load current state via readStream+reduce(evolve, initial), run pure decide(command, state), and appendToStream the resulting events with expectedRevision. No business logic lives in the handler.

```typescript
export type CandidateState =
  | { status: "none" }
  | { status: "nominated"; id: string; name: string };

export type CandidateCommand =
  | { type: "nominate"; id: string; name: string };

export type CandidateEvent =
  | { type: "Nominated"; id: string; name: string };

export class DomainError extends Error {}

export const initialState: CandidateState = { status: "none" };

export function decide(cmd: CandidateCommand, s: CandidateState): CandidateEvent[] {
  switch (cmd.type) {
    case "nominate":
      if (s.status !== "none") throw new DomainError("already nominated");
      return [{ type: "Nominated", id: cmd.id, name: cmd.name }];
    default: {
      const _: never = cmd.type;
      return _;
    }
  }
}

export function evolve(s: CandidateState, e: CandidateEvent): CandidateState {
  switch (e.type) {
    case "Nominated":
      return { status: "nominated", id: e.id, name: e.name };
    default: {
      const _: never = e.type;
      return _;
    }
  }
}

type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): AsyncIterable<CandidateEvent>;
  appendToStream(stream: string, events: CandidateEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
  currentRevision(stream: string): Promise<bigint | null>;
}

export async function handle(
  command: CandidateCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initialState;
  for await (const e of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, e);
  }
  const events = decide(command, state);
  const rev = await ctx.eventStore.currentRevision(ctx.streamName);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: rev ?? "no_stream" });
}
```

