A when function is the pure fold step: given the previous state and an event, it returns the next state. aggregateStream walks an async iterable of events, calling when on each one, and yields final state. Because when has no I/O, it is trivially testable and deterministic.

```typescript
export type WaterQualityEvent =
  | { type: "WaterQualityLogOpened"; id: string }
  | { type: "WaterQualityReadingRecorded"; ph: number }
  | { type: "WaterQualityLogClosed"; at: string };

export interface WaterQualityState {
  readonly status: "none" | "open" | "closed";
  readonly id: string | null;
  readonly readings: number;
}

const initial: WaterQualityState = { status: "none", id: null, readings: 0 };

export function when(state: WaterQualityState, event: WaterQualityEvent): WaterQualityState {
  switch (event.type) {
    case "WaterQualityLogOpened":
      return { status: "open", id: event.id, readings: 0 };
    case "WaterQualityReadingRecorded":
      return state.status === "open" ? { ...state, readings: state.readings + 1 } : state;
    case "WaterQualityLogClosed":
      return state.status === "open" ? { ...state, status: "closed" } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initialState: S,
): Promise<S> {
  let acc: S = initialState;
  for await (const event of stream) {
    acc = reducer(acc, event);
  }
  return acc;
}

export async function loadLog(stream: AsyncIterable<WaterQualityEvent>): Promise<WaterQualityState> {
  return aggregateStream<WaterQualityState, WaterQualityEvent>(stream, when, initial);
}
