```typescript
export type RescueOperationEvent =
  | { type: "RescueRequested"; id: string; peak: string }
  | { type: "RescuerDispatched"; rescuerId: string }
  | { type: "RescueConcluded"; at: string };

export interface RescueView {
  readonly id: string;
  readonly rescuers: number;
  readonly status: "requested" | "concluded";
}

export const emptyView: RescueView = { id: "", rescuers: 0, status: "requested" };

export function project(view: RescueView, event: RescueOperationEvent): RescueView {
  switch (event.type) {
    case "RescueRequested":
      return { id: event.id, rescuers: 0, status: "requested" };
    case "RescuerDispatched":
      return { ...view, rescuers: view.rescuers + 1 };
    case "RescueConcluded":
      return { ...view, status: "concluded" };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface EventBatch<E> {
  readonly events: ReadonlyArray<E>;
  readonly nextRevision: bigint;
}

export interface EventStore<E> {
  readStream(from: bigint, batchSize: number): Promise<EventBatch<E>>;
}

export interface Reporter {
  report(revision: bigint, count: number): void;
}

export async function rebuild(
  store: EventStore<RescueOperationEvent>,
  persist: (view: RescueView) => Promise<void>,
  reporter: Reporter,
  from: bigint = 0n,
  batchSize: number = 500,
): Promise<void> {
  let cursor = from;
  let view = emptyView;
  let total = 0;
  let done = false;
  while (!done) {
    const batch = await store.readStream(cursor, batchSize);
    if (batch.events.length === 0) {
      done = true;
      break;
    }
    for (const event of batch.events) {
      view = project(view, event);
      total += 1;
    }
    await persist(view);
    reporter.report(batch.nextRevision, total);
    cursor = batch.nextRevision;
  }
}
```

```typescript
export interface ReworkEvent { type: string; revision: bigint; payload: unknown; }

export interface ReworkView { open: number; closed: number; lastRevision: bigint; }

export const emptyView: ReworkView = { open: 0, closed: 0, lastRevision: -1n };

export function project(view: ReworkView, event: ReworkEvent): ReworkView {
  if (event.type === "ReworkOpened") return { ...view, open: view.open + 1, lastRevision: event.revision };
  if (event.type === "ReworkClosed") return { ...view, open: Math.max(0, view.open - 1), closed: view.closed + 1, lastRevision: event.revision };
  return { ...view, lastRevision: event.revision };
}

export interface EventStoreIterator {
  readBatch(from: bigint, size: number): Promise<ReworkEvent[]>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStoreIterator;
  persist: (view: ReworkView) => Promise<void>;
  onProgress?: (revision: bigint) => void;
}): Promise<void> {
  let cursor = opts.from;
  let view: ReworkView = emptyView;
  while (true) {
    const batch = await opts.store.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const event of batch) {
      view = project(view, event);
    }
    await opts.persist(view);
    const last = batch[batch.length - 1].revision;
    cursor = last + 1n;
    opts.onProgress?.(last);
  }
}
```

