```typescript
type ReplyCommand =
  | { type: 'PostReply'; id: string; parentId: string; body: string }
  | { type: 'RetractReply' };

type ReplyEvent =
  | { type: 'ReplyPosted'; id: string; parentId: string; body: string }
  | { type: 'ReplyRetracted' };

type ReplyState = { status: 'absent' } | { status: 'live' } | { status: 'retracted' };

const initialState: ReplyState = { status: 'absent' };

function evolve(state: ReplyState, event: ReplyEvent): ReplyState {
  switch (event.type) {
    case 'ReplyPosted':
      return { status: 'live' };
    case 'ReplyRetracted':
      return { status: 'retracted' };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(command: ReplyCommand, state: ReplyState): ReplyEvent[] {
  switch (command.type) {
    case 'PostReply':
      if (state.status !== 'absent') throw new Error('already replied');
      return [{ type: 'ReplyPosted', id: command.id, parentId: command.parentId, body: command.body }];
    case 'RetractReply':
      if (state.status !== 'live') throw new Error('cannot retract');
      return [{ type: 'ReplyRetracted' }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

interface EventStore {
  readStream(s: string): AsyncIterable<ReplyEvent>;
  appendToStream(s: string, events: readonly ReplyEvent[]): Promise<void>;
}

export async function handleReply(
  store: EventStore,
  streamName: string,
  command: ReplyCommand,
): Promise<void> {
  let state = initialState;
  for await (const event of store.readStream(streamName)) {
    state = evolve(state, event);
  }
  await store.appendToStream(streamName, decide(command, state));
}
```

