import { z, ZodSchema } from 'zod';

export async function typedFetch<T>(
  url: string,
  schema: ZodSchema<T>,
  init?: RequestInit,
): Promise<T> {
  const res = await fetch(url, init);
  if (!res.ok) {
    throw new Error(`HTTP ${res.status} for ${url}`);
  }
  const body = await res.json();
  return schema.parse(body); // throws ZodError on mismatch
}
```

`ZodSchema<T>` flows the inferred type to the return. `parse` throws a `ZodError` on mismatch — the caller can catch it and inspect `err.issues` for field-level detail. Use `safeParse` if the caller prefers discriminated-union handling.

```typescript
import { Effect, Data } from "effect";

export type KilnFiringState =
  | { status: "idle" }
  | { status: "scheduled"; id: string };

export type KilnFiringCommand =
  | { type: "schedule"; id: string }
  | { type: "ignite" };

export type KilnFiringEvent =
  | { type: "FiringScheduled"; id: string }
  | { type: "FiringIgnited" };

const initialState: KilnFiringState = { status: "idle" };

function decide(
  c: KilnFiringCommand,
  s: KilnFiringState,
): KilnFiringEvent[] {
  if (c.type === "schedule") {
    if (s.status !== "idle") throw new Error("busy");
    return [{ type: "FiringScheduled", id: c.id }];
  }
  if (s.status !== "scheduled") throw new Error("not scheduled");
  return [{ type: "FiringIgnited" }];
}

function evolve(
  s: KilnFiringState,
  e: KilnFiringEvent,
): KilnFiringState {
  if (e.type === "FiringScheduled") return { status: "scheduled", id: e.id };
  return s;
}

export class DomainError extends Data.TaggedError("DomainError")<{
  cause: string;
}> {}
export class ConcurrencyConflict extends Data.TaggedError(
  "ConcurrencyConflict",
)<{ stream: string }> {}

export interface EventStore {
  readStream(stream: string): Promise<{
    events: KilnFiringEvent[];
    lastRevision: bigint | "no_stream";
  }>;
  appendToStream(
    stream: string,
    events: KilnFiringEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export const handle = (
  command: KilnFiringCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Effect.Effect<void, DomainError | ConcurrencyConflict> =>
  Effect.gen(function* () {
    const read = yield* Effect.tryPromise({
      try: () => ctx.eventStore.readStream(ctx.streamName),
      catch: (e) => new DomainError({ cause: String(e) }),
    });
    const state = read.events.reduce(evolve, initialState);
    const events = yield* Effect.try({
      try: () => decide(command, state),
      catch: (e) => new DomainError({ cause: String(e) }),
    });
    yield* Effect.tryPromise({
      try: () =>
        ctx.eventStore.appendToStream(ctx.streamName, events, {
          expectedRevision: read.lastRevision,
        }),
      catch: () => new ConcurrencyConflict({ stream: ctx.streamName }),
    });
  });
```

