```typescript
export type GateCommand = { type: "assign"; id: string; gate: string } | { type: "release"; id: string };
export type GateEvent = { type: "GateAssigned"; id: string; gate: string } | { type: "GateReleased"; id: string };

interface AggregateState { status: "none" | "assigned"; gate: string | null; }
const initialState: AggregateState = { status: "none", gate: null };

function evolve(s: AggregateState, e: GateEvent): AggregateState {
  switch (e.type) {
    case "GateAssigned": return { status: "assigned", gate: e.gate };
    case "GateReleased": return { status: "none", gate: null };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: GateCommand, s: AggregateState): GateEvent[] {
  switch (c.type) {
    case "assign":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "GateAssigned", id: c.id, gate: c.gate }];
    case "release":
      if (s.status !== "assigned") throw new Error("NOT_ASSIGNED");
      return [{ type: "GateReleased", id: c.id }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(name: string): Promise<{ revision: bigint; data: GateEvent }[]>;
  appendToStream(name: string, events: GateEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

// Read store is eventually consistent with the event store.
export interface GateReadStore {
  getByGate(gate: string): Promise<{ id: string; since: string } | null>;
}

export async function handleCommand(cmd: GateCommand, deps: { streamName: string; store: EventStore }): Promise<void> {
  const stored = await deps.store.readStream(deps.streamName);
  const state = stored.reduce<AggregateState>((s, r) => evolve(s, r.data), initialState);
  const events = decide(cmd, state);
  const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  await deps.store.appendToStream(deps.streamName, events, { expectedRevision });
}

export async function queryView(gate: string, reads: GateReadStore) {
  return reads.getByGate(gate);
}
