Internal transitions (v5 default) keep entry/exit actions from re-firing — perfect for zoom-level updates within the `zoomed` state. A `reenter: true` transition is used when closing back to `full` so that entry animations run again.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { zoom: number };
type Ev = { type: 'ZOOM_IN' } | { type: 'ZOOM_OUT' } | { type: 'CLOSE' };

export const zoomMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'zoom',
  initial: 'full',
  context: { zoom: 1 },
  states: {
    full: {
      entry: assign({ zoom: () => 1 }),
      on: { ZOOM_IN: 'zoomed' }
    },
    zoomed: {
      on: {
        ZOOM_IN: { actions: assign({ zoom: ({ context }) => Math.min(context.zoom + 1, 5) }) },
        ZOOM_OUT: { actions: assign({ zoom: ({ context }) => Math.max(context.zoom - 1, 1) }) },
        CLOSE: { target: 'full', reenter: true }
      }
    }
  }
});
