export type WaterQualityState =
  | { status: "none" }
  | { status: "open"; id: string; readings: number }
  | { status: "closed"; id: string };

export type WaterQualityCommand =
  | { type: "open"; id: string }
  | { type: "record"; ph: number; tempC: number; at: string }
  | { type: "close"; at: string };

export type WaterQualityEvent =
  | { type: "WaterQualityLogOpened"; id: string }
  | { type: "WaterQualityReadingRecorded"; ph: number; tempC: number; at: string }
  | { type: "WaterQualityLogClosed"; at: string };

const initial: WaterQualityState = { status: "none" };

function evolve(state: WaterQualityState, event: WaterQualityEvent): WaterQualityState {
  switch (event.type) {
    case "WaterQualityLogOpened":
      return { status: "open", id: event.id, readings: 0 };
    case "WaterQualityReadingRecorded":
      return state.status === "open" ? { ...state, readings: state.readings + 1 } : state;
    case "WaterQualityLogClosed":
      return state.status === "open" ? { status: "closed", id: state.id } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: WaterQualityCommand, state: WaterQualityState): WaterQualityEvent[] {
  switch (command.type) {
    case "open":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "WaterQualityLogOpened", id: command.id }];
    case "record":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "WaterQualityReadingRecorded", ph: command.ph, tempC: command.tempC, at: command.at }];
    case "close":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "WaterQualityLogClosed", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export class CommandHandler {
  constructor(private readonly store: EventStore) {}
  async handle(command: WaterQualityCommand, streamName: string): Promise<void> {
    const current = await this.store.readStream<WaterQualityEvent>(streamName);
    const state = current.events.reduce(evolve, initial);
    const events = decide(command, state);
    await this.store.appendToStream<WaterQualityEvent>(streamName, events, { expectedRevision: current.revision });
  }
}
