```typescript
export type RawSherpaEvent =
  | { type: "SherpaHired"; version: 1; data: { id: string; personName: string } }
  | { type: "SherpaHired"; version: 2; data: { id: string; name: string } }
  | { type: "SherpaAssigned"; version: 1; data: { expeditionId: string } };

export type SherpaEvent =
  | { type: "SherpaHired"; id: string; name: string }
  | { type: "SherpaAssigned"; expeditionId: string };

export class UnknownEventError extends Error {
  constructor(public readonly rawType: string, public readonly rawVersion: number) {
    super(`unknown event ${rawType} v${rawVersion}`);
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: RawSherpaEvent): SherpaEvent {
  switch (raw.type) {
    case "SherpaHired":
      if (raw.version === 1) {
        return { type: "SherpaHired", id: raw.data.id, name: raw.data.personName };
      }
      if (raw.version === 2) {
        return { type: "SherpaHired", id: raw.data.id, name: raw.data.name };
      }
      throw new UnknownEventError("SherpaHired", 0);
    case "SherpaAssigned":
      return { type: "SherpaAssigned", expeditionId: raw.data.expeditionId };
    default: {
      const _never: never = raw;
      throw new UnknownEventError("unknown", 0);
    }
  }
}

export function evolve(events: ReadonlyArray<RawSherpaEvent>): SherpaEvent[] {
  return events.map(upcast);
}
```

```typescript
export type EndowmentFundEvent =
  | { type: "opened"; fundId: string; name: string }
  | { type: "contributed"; fundId: string; amount: number }
  | { type: "distributed"; fundId: string; amount: number }
  | { type: "closed"; fundId: string };

export interface EndowmentFundRow {
  fundId: string;
  name: string;
  balance: number;
  open: boolean;
}

export type EndowmentFundView = Record<string, EndowmentFundRow>;

export const emptyView: EndowmentFundView = {};

export function project(view: EndowmentFundView, event: EndowmentFundEvent): EndowmentFundView {
  switch (event.type) {
    case "opened":
      return { ...view, [event.fundId]: { fundId: event.fundId, name: event.name, balance: 0, open: true } };
    case "contributed": {
      const row = view[event.fundId];
      if (!row) return view;
      return { ...view, [event.fundId]: { ...row, balance: row.balance + event.amount } };
    }
    case "distributed": {
      const row = view[event.fundId];
      if (!row) return view;
      return { ...view, [event.fundId]: { ...row, balance: row.balance - event.amount } };
    }
    case "closed": {
      const row = view[event.fundId];
      if (!row) return view;
      return { ...view, [event.fundId]: { ...row, open: false } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}
