  readonly patientId: string | null;
  readonly notes: string[];
  readonly signedBy: string | null;
}

export const initialVisit: VisitRecordState = { id: null, patientId: null, notes: [], signedBy: null };

export function when(state: VisitRecordState, event: VisitRecordEvent): VisitRecordState {
  switch (event.type) {
    case "VisitRecordStarted":
      return { ...state, id: event.id, patientId: event.patientId };
    case "NoteAppended":
      return { ...state, notes: [...state.notes, event.note] };
    case "VisitRecordSigned":
      return { ...state, signedBy: event.by };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: VisitRecordEvent[]): VisitRecordState {
  return events.reduce(when, initialVisit);
}
