Parallel states let one machine run two independent regions at the same time. Here the root is `type: 'parallel'` with two regions: `auth` tracks loggedOut/loggedIn, and `heartbeat` polls on an `after` delay while loggedIn. Each region has its own `initial` and transitions and ignores events it doesn't declare.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { token: string | null; lastPing: number };
type Ev =
  | { type: 'LOGIN'; token: string }
  | { type: 'LOGOUT' }
  | { type: 'PING' };

export const sessionMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'session',
  type: 'parallel',
  context: { token: null, lastPing: 0 },
  states: {
    auth: {
      initial: 'loggedOut',
      states: {
        loggedOut: {
          on: {
            LOGIN: { target: 'loggedIn', actions: assign({ token: ({ event }) => event.token }) }
          }
        },
        loggedIn: {
          on: { LOGOUT: { target: 'loggedOut', actions: assign({ token: () => null }) } }
        }
      }
    },
    heartbeat: {
      initial: 'idle',
      states: {
        idle: {
          after: { 15000: { target: 'pinging' } }
        },
        pinging: {
          entry: assign({ lastPing: () => Date.now() }),
          on: { PING: { target: 'idle' } },
          after: { 2000: { target: 'idle' } }
        }
      }
    }
  }
});
```

