Optimistic concurrency relies on the client passing the stream revision it last observed when appending. If another writer has appended meanwhile, the store's actual revision differs and it rejects the append. The client surfaces this as a typed error so the caller can reload state and retry. No locking is involved.

```typescript
export class ConcurrencyConflict extends Error {}

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(
    stream: string,
    events: E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextRevision: bigint }>;
}

export type TerritoryMapEvent =
  | { type: "created"; id: string }
  | { type: "districtAdded" };

export async function append(
  store: EventStore<TerritoryMapEvent>,
  stream: string,
  events: TerritoryMapEvent[],
): Promise<bigint> {
  const existing = await store.readStream(stream);
  const expectedRevision: bigint | "no_stream" =
    existing.length === 0 ? "no_stream" : existing[existing.length - 1].revision;
  try {
    const { nextRevision } = await store.appendToStream(stream, events, { expectedRevision });
    return nextRevision;
  } catch (err) {
    throw new ConcurrencyConflict(`append conflict on ${stream}: ${String(err)}`);
  }
}
```

