export type SagaState =
  | { status: "awaitingMatch"; rideId: string }
  | { status: "awaitingPickup"; rideId: string; driverId: string }
  | { status: "completed"; rideId: string }
  | { status: "failed"; rideId: string; reason: string };

export type SagaEvent =
  | { type: "RideShareMatched"; rideId: string; driverId: string }
  | { type: "PickupConfirmed"; rideId: string }
  | { type: "PickupFailed"; rideId: string; reason: string };

export type SagaCommand =
  | { type: "SendPickupInstructions"; rideId: string; driverId: string }
  | { type: "MarkRideCompleted"; rideId: string }
  | { type: "ReopenRide"; rideId: string };

export interface Step { nextState: SagaState; command: SagaCommand | null }

export function step(state: SagaState, event: SagaEvent): Step {
  switch (event.type) {
    case "RideShareMatched":
      if (state.status !== "awaitingMatch" || state.rideId !== event.rideId) return { nextState: state, command: null };
      return {
        nextState: { status: "awaitingPickup", rideId: state.rideId, driverId: event.driverId },
        command: { type: "SendPickupInstructions", rideId: state.rideId, driverId: event.driverId },
      };
    case "PickupConfirmed":
      if (state.status !== "awaitingPickup" || state.rideId !== event.rideId) return { nextState: state, command: null };
      return {
        nextState: { status: "completed", rideId: state.rideId },
        command: { type: "MarkRideCompleted", rideId: state.rideId },
      };
    case "PickupFailed":
      if (state.status !== "awaitingPickup" || state.rideId !== event.rideId) return { nextState: state, command: null };
      return {
        nextState: { status: "failed", rideId: state.rideId, reason: event.reason },
        command: { type: "ReopenRide", rideId: state.rideId },
      };
    default: { const _n: never = event; return { nextState: state, command: null }; }
  }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<SagaEvent>;
}

export async function replay(store: EventStore, streamName: string, rideId: string): Promise<SagaState> {
  let state: SagaState = { status: "awaitingMatch", rideId };
  for await (const event of store.readStream(streamName)) {
    state = step(state, event).nextState;
  }
  return state;
}
```

Internal (default) self-transitions keep you in the same state without firing entry or exit actions — they're useful when an event only needs to mutate context. External self-transitions (`reenter: true`) re-fire entry and exit on the state node, which is handy for restarting timers or resetting per-entry side effects.

```typescript
import { setup, assign } from 'xstate';

export const search = setup({
  types: {
    context: {} as { query: string; debouncedAt: number },
    events: {} as { type: 'TYPE'; q: string } | { type: 'CLEAR' },
  },
}).createMachine({
  id: 'search',
  initial: 'active',
  context: { query: '', debouncedAt: 0 },
  states: {
    active: {
      entry: assign({ debouncedAt: () => Date.now() }),
      on: {
        TYPE: {
          // internal: update query without restarting the debounce timestamp
          actions: assign({ query: ({ event }) => event.q }),
        },
        CLEAR: {
          // external self-transition: entry fires, debouncedAt resets
          target: 'active',
          reenter: true,
          actions: assign({ query: () => '' }),
        },
      },
    },
  },
});
```

A Decider is a pure triple of initialState, decide(command, state) returning events, and evolve(state, event) returning the next state. No IO. Commands either emit events or throw domain errors; events are the source of truth.

```typescript
export type VersionState =
  | { status: "none" }
  | { status: "tagged"; id: string; label: string; at: string }
  | { status: "superseded"; id: string; by: string };

export type VersionCommand =
  | { type: "tag"; id: string; label: string; at: string }
  | { type: "supersede"; by: string };

export type VersionEvent =
  | { type: "VersionTagged"; id: string; label: string; at: string }
  | { type: "VersionSuperseded"; by: string };

export class VersionError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "VersionError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const versionDecider: Decider<VersionCommand, VersionEvent, VersionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "tag":
        if (state.status !== "none") throw new VersionError("EXISTS");
        if (!command.label) throw new VersionError("EMPTY_LABEL");
        return [{ type: "VersionTagged", id: command.id, label: command.label, at: command.at }];
      case "supersede":
        if (state.status !== "tagged") throw new VersionError("NOT_TAGGED");
        if (command.by === state.id) throw new VersionError("SELF_SUPERSEDE");
        return [{ type: "VersionSuperseded", by: command.by }];
      default: {
        const _n: never = command;
        throw new VersionError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "VersionTagged":
        return { status: "tagged", id: event.id, label: event.label, at: event.at };
      case "VersionSuperseded":
        if (state.status !== "tagged") return state;
        return { status: "superseded", id: state.id, by: event.by };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

