export type AuditState =
  | { status: "none" }
  | { status: "active"; id: string; findings: number };

export type AuditCommand =
  | { type: "start"; id: string }
  | { type: "recordFinding"; detail: string };

export type AuditEvent =
  | { type: "AuditStarted"; id: string }
  | { type: "FindingRecorded"; detail: string };

export class AuditError extends Error {}

export const initialState: AuditState = { status: "none" };

export function decide(c: AuditCommand, s: AuditState): AuditEvent[] {
  switch (c.type) {
    case "start":
      if (s.status !== "none") throw new AuditError("STARTED");
      return [{ type: "AuditStarted", id: c.id }];
    case "recordFinding":
      if (s.status !== "active") throw new AuditError("NOT_ACTIVE");
      return [{ type: "FindingRecorded", detail: c.detail }];
    default: { const _n: never = c; throw new AuditError("UNKNOWN"); }
  }
}

export function evolve(s: AuditState, e: AuditEvent): AuditState {
  switch (e.type) {
    case "AuditStarted":
      return { status: "active", id: e.id, findings: 0 };
    case "FindingRecorded":
      if (s.status !== "active") return s;
      return { ...s, findings: s.findings + 1 };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ revision: bigint; events: AuditEvent[] }>;
  appendToStream(
    stream: string,
    events: AuditEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export interface CommandHandler<C> {
  (command: C, ctx: { streamName: string; eventStore: EventStore }): Promise<void>;
}

export const handle: CommandHandler<AuditCommand> = async (command, { streamName, eventStore }) => {
  const { revision, events } = await eventStore.readStream(streamName);
  const state = events.reduce<AuditState>(evolve, initialState);
  const produced = decide(command, state);
  const expectedRevision: bigint | "no_stream" = events.length === 0 ? "no_stream" : revision;
  await eventStore.appendToStream(streamName, produced, { expectedRevision });
};

