```typescript
interface StoredEvent<E> { data: E; revision: bigint }

interface EventStore<E> {
  readFromStream(stream: string, from: bigint, limit: number): Promise<StoredEvent<E>[]>;
}

export type TicketEvent =
  | { type: "TicketOpened" }
  | { type: "TicketResolved" };

export interface TicketCounts { opened: number; resolved: number }

function project(v: TicketCounts, e: TicketEvent): TicketCounts {
  switch (e.type) {
    case "TicketOpened":
      return { ...v, opened: v.opened + 1 };
    case "TicketResolved":
      return { ...v, resolved: v.resolved + 1 };
    default: {
      const _never: never = e;
      return v;
    }
  }
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  persist: (v: TicketCounts, cursor: bigint) => Promise<void>;
  onProgress?: (processed: number, cursor: bigint) => void;
}

export async function rebuild(
  store: EventStore<TicketEvent>,
  stream: string,
  opts: RebuildOptions,
): Promise<void> {
  let cursor = opts.from;
  let counts: TicketCounts = { opened: 0, resolved: 0 };
  let processed = 0;
  for (;;) {
    const batch = await store.readFromStream(stream, cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const s of batch) {
      counts = project(counts, s.data);
      cursor = s.revision + 1n;
      processed += 1;
    }
    await opts.persist(counts, cursor);
    opts.onProgress?.(processed, cursor);
  }
}
```

```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

