```typescript
import { Effect } from "effect";

interface StoredEvent<E> { data: E; revision: bigint }

interface AppendOptions { expectedRevision: bigint | "no_stream" | "any" }

interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(stream: string, events: E[], options: AppendOptions): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) { super(`CONCURRENCY_CONFLICT:${stream}`); }
}

export type PaymentEvent =
  | { type: "PaymentScheduled"; id: string; amount: number }
  | { type: "PaymentSettled"; at: string };

export const appendWithRetry = (
  store: EventStore<PaymentEvent>,
  stream: string,
  produce: (existing: PaymentEvent[]) => PaymentEvent[],
  attempts = 3,
) =>
  Effect.gen(function* () {
    for (let i = 0; i < attempts; i++) {
      const stored = yield* Effect.promise(() => store.readStream(stream));
      const events = produce(stored.map((s) => s.data));
      const expectedRevision: bigint | "no_stream" =
        stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
      try {
        const r = yield* Effect.promise(() =>
          store.appendToStream(stream, events, { expectedRevision }),
        );
        return r.nextRevision;
      } catch (err) {
        if (err instanceof Error && /expected/i.test(err.message)) {
          if (i === attempts - 1) throw new ConcurrencyConflict(stream);
          continue;
        }
        throw err;
      }
    }
    throw new ConcurrencyConflict(stream);
  });
