export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type BallotEvent =
  | { type: "Issued"; id: string; voterId: string }
  | { type: "Marked"; choice: string }
  | { type: "Submitted"; at: string };

export type BallotState =
  | { status: "issued"; id: string; voterId: string }
  | { status: "marked"; id: string; voterId: string; choice: string }
  | { status: "submitted"; id: string; submittedAt: string };

export const initial: BallotState = { status: "issued", id: "", voterId: "" };

export function evolve(state: BallotState, event: BallotEvent): BallotState {
  switch (event.type) {
    case "Issued":
      return { status: "issued", id: event.id, voterId: event.voterId };
    case "Marked":
      return state.status === "issued" ? { status: "marked", id: state.id, voterId: state.voterId, choice: event.choice } : state;
    case "Submitted":
      return state.status === "marked" ? { status: "submitted", id: state.id, submittedAt: event.at } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function loadBallot(stream: AsyncIterable<BallotEvent>): Promise<BallotState> {
  return aggregateStream(stream, evolve, initial);
}
