```typescript
export type TicketState =
  | { status: "none" }
  | { status: "open"; id: string; title: string };

export type TicketCommand =
  | { type: "openTicket"; id: string; title: string }
  | { type: "closeTicket"; at: string };

export type TicketEvent =
  | { type: "TicketOpened"; id: string; title: string }
  | { type: "TicketClosed"; at: string };

export class TicketError extends Error {}

export const initialState: TicketState = { status: "none" };

export function evolve(state: TicketState, event: TicketEvent): TicketState {
  switch (event.type) {
    case "TicketOpened":
      return { status: "open", id: event.id, title: event.title };
    case "TicketClosed":
      return { status: "none" };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(command: TicketCommand, state: TicketState): TicketEvent[] {
  switch (command.type) {
    case "openTicket":
      if (state.status !== "none") throw new TicketError("EXISTS");
      return [{ type: "TicketOpened", id: command.id, title: command.title }];
    case "closeTicket":
      if (state.status !== "open") throw new TicketError("NOT_OPEN");
      return [{ type: "TicketClosed", at: command.at }];
    default: {
      const _n: never = command;
      throw new TicketError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: TicketEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: readonly TicketEvent[],
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export async function handleTicketCommand(
  streamName: string,
  command: TicketCommand,
  eventStore: EventStore,
): Promise<void> {
  const { events, revision } = await eventStore.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const produced = decide(command, state);
  if (produced.length === 0) return;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  await eventStore.appendToStream(streamName, produced, { expectedRevision });
}
