import { Effect } from "effect";

export type RRProjectionEvent =
  | { type: "RequestOpened"; id: string; topic: string }
  | { type: "RequestAnswered"; id: string };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventSource<E> {
  from(position: bigint | null): AsyncIterable<{ event: E; position: bigint }>;
}

export type OpenDeskView = { open: number; answered: number };
export const empty: OpenDeskView = { open: 0, answered: 0 };

export function project(view: OpenDeskView, event: RRProjectionEvent): OpenDeskView {
  switch (event.type) {
    case "RequestOpened":
      return { ...view, open: view.open + 1 };
    case "RequestAnswered":
      return { open: Math.max(0, view.open - 1), answered: view.answered + 1 };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function runSubscription(
  name: string,
  checkpoints: CheckpointStore,
  source: EventSource<RRProjectionEvent>,
  persist: (view: OpenDeskView) => Promise<void>,
) {
  return Effect.gen(function* () {
    const start = yield* Effect.promise(() => checkpoints.read(name));
    yield* Effect.promise(async () => {
      let view = empty;
      for await (const { event, position } of source.from(start)) {
        view = project(view, event);
        await persist(view);
        await checkpoints.write(name, position);
      }
    });
  });
}
