export type AlertEvent =
  | { type: "AlertRaised"; id: string }
  | { type: "AlertCleared"; id: string };

export type AlertDashboard = { raisedIds: string[] };

const emptyDashboard: AlertDashboard = { raisedIds: [] };

function project(view: AlertDashboard, e: AlertEvent): AlertDashboard {
  switch (e.type) {
    case "AlertRaised":
      return { raisedIds: view.raisedIds.includes(e.id) ? view.raisedIds : [...view.raisedIds, e.id] };
    case "AlertCleared":
      return { raisedIds: view.raisedIds.filter((id) => id !== e.id) };
    default: { const _n: never = e; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFromStream(stream: string, from: bigint): AsyncIterable<{ event: E; position: bigint }>;
}

export interface ReadModelStore {
  load(): Promise<AlertDashboard>;
  save(view: AlertDashboard): Promise<void>;
}

export async function runAlertSubscription(
  stream: string,
  ckpt: CheckpointStore,
  source: EventSource<AlertEvent>,
  store: ReadModelStore,
): Promise<void> {
  const last = (await ckpt.read(stream)) ?? 0n;
  let view = (await store.load()) ?? emptyDashboard;
  for await (const { event, position } of source.readFromStream(stream, last)) {
    view = project(view, event);
    await store.save(view);
    await ckpt.write(stream, position);
  }
}
