```typescript
export type WarehouseEvent =
  | { type: "WarehouseOpened"; id: string; code: string; capacity: number }
  | { type: "WarehouseExpanded"; id: string; addedBins: number }
  | { type: "BinFilled"; warehouseId: string; qty: number }
  | { type: "BinEmptied"; warehouseId: string; qty: number }
  | { type: "WarehouseDecommissioned"; id: string };

export interface OccupancyView {
  byWarehouse: Readonly<Record<string, { code: string; capacity: number; stored: number; active: boolean }>>;
}

export const emptyView: OccupancyView = { byWarehouse: {} };

export function project(view: OccupancyView, event: WarehouseEvent): OccupancyView {
  switch (event.type) {
    case "WarehouseOpened":
      return {
        byWarehouse: {
          ...view.byWarehouse,
          [event.id]: { code: event.code, capacity: event.capacity, stored: 0, active: true },
        },
      };
    case "WarehouseExpanded": {
      const row = view.byWarehouse[event.id];
      if (!row) return view;
      return {
        byWarehouse: {
          ...view.byWarehouse,
          [event.id]: { ...row, capacity: row.capacity + event.addedBins },
        },
      };
    }
    case "BinFilled": {
      const row = view.byWarehouse[event.warehouseId];
      if (!row) return view;
      return {
        byWarehouse: {
          ...view.byWarehouse,
          [event.warehouseId]: { ...row, stored: row.stored + event.qty },
        },
      };
    }
    case "BinEmptied": {
      const row = view.byWarehouse[event.warehouseId];
      if (!row) return view;
      return {
        byWarehouse: {
          ...view.byWarehouse,
          [event.warehouseId]: { ...row, stored: Math.max(0, row.stored - event.qty) },
        },
      };
    }
    case "WarehouseDecommissioned": {
      const row = view.byWarehouse[event.id];
      if (!row) return view;
      return {
        byWarehouse: {
          ...view.byWarehouse,
          [event.id]: { ...row, active: false },
