export type OncallShiftEvent =
  | { type: "ShiftStarted"; engineer: string; at: number }
  | { type: "ShiftEnded"; engineer: string; at: number }
  | { type: "BreakTaken"; minutes: number }
  | { type: "ScheduleUpdated"; rotation: string };

export type OncallView = {
  engineer: string;
  minutesOnCall: number;
  openStartedAt: number | null;
};

export const emptyOncallView: OncallView = {
  engineer: "",
  minutesOnCall: 0,
  openStartedAt: null,
};

export function project(view: OncallView, event: OncallShiftEvent): OncallView {
  switch (event.type) {
    case "ShiftStarted":
      return { engineer: event.engineer, minutesOnCall: view.minutesOnCall, openStartedAt: event.at };
    case "ShiftEnded": {
      if (view.openStartedAt === null) return view;
      const mins = Math.max(0, Math.floor((event.at - view.openStartedAt) / 60000));
      return { ...view, minutesOnCall: view.minutesOnCall + mins, openStartedAt: null };
    }
    case "BreakTaken":
      return { ...view, minutesOnCall: Math.max(0, view.minutesOnCall - event.minutes) };
    case "ScheduleUpdated":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
