export class ConcurrencyConflict extends Error {}
export interface StoredEvent<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ nextRevision: bigint }>;
}
export type LegalCaseEvent = { type: "opened"; caseId: string } | { type: "closed" };
export async function appendWithConcurrency(
  store: EventStore<LegalCaseEvent>,
  stream: string,
  toAppend: LegalCaseEvent[],
): Promise<bigint> {
  let last: bigint | "no_stream" = "no_stream";
  for await (const { revision } of store.readStream(stream)) { last = revision; }
  try {
    const { nextRevision } = await store.appendToStream(stream, toAppend, { expectedRevision: last });
    return nextRevision;
  } catch (err) {
    throw new ConcurrencyConflict((err as Error).message);
  }
}
