import { Effect } from "effect";

export type HarvestWindowEvent =
  | { type: "HarvestWindowOpened"; id: string; startsAt: string; endsAt: string }
  | { type: "HarvestWindowClosed"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`conflict ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export const safeAppend = (
  store: EventStore,
  stream: string,
  events: HarvestWindowEvent[],
) =>
  Effect.gen(function* () {
    const current = yield* Effect.promise(() => store.readStream<HarvestWindowEvent>(stream));
    const nextRev = yield* Effect.tryPromise({
      try: () => store.appendToStream<HarvestWindowEvent>(stream, events, { expectedRevision: current.revision }),
      catch: (err) => new ConcurrencyConflict(stream),
    });
    return nextRev;
  });
