```typescript
export type HarvestWindowEvent =
  | { type: "HarvestWindowOpened"; id: string; farmId: string }
  | { type: "HarvestWindowClosed"; id: string; farmId: string };

export interface Batch<E> {
  readonly events: readonly { revision: bigint; payload: E }[];
  readonly nextFrom: bigint;
  readonly done: boolean;
}

export interface EventStore {
  readForward<E>(from: bigint, batchSize: number): Promise<Batch<E>>;
}

export interface WindowView {
  readonly openByFarm: Readonly<Record<string, number>>;
}

export interface ReadStore {
  wipe(): Promise<void>;
  persist(view: WindowView): Promise<void>;
}

export function project(view: WindowView, event: HarvestWindowEvent): WindowView {
  switch (event.type) {
    case "HarvestWindowOpened": {
      const prev = view.openByFarm[event.farmId] ?? 0;
      return { openByFarm: { ...view.openByFarm, [event.farmId]: prev + 1 } };
    }
    case "HarvestWindowClosed": {
      const prev = view.openByFarm[event.farmId] ?? 0;
      return { openByFarm: { ...view.openByFarm, [event.farmId]: Math.max(0, prev - 1) } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStore;
  read: ReadStore;
}): Promise<void> {
  if (opts.from === 0n) await opts.read.wipe();
  let view: WindowView = { openByFarm: {} };
  let cursor = opts.from;
  let done = false;
  while (!done) {
    const batch = await opts.store.readForward<HarvestWindowEvent>(cursor, opts.batchSize);
    for (const env of batch.events) {
      view = project(view, env.payload);
    }
    await opts.read.persist(view);
    cursor = batch.nextFrom;
    done = batch.done;
  }
}
