```typescript
export type ReferendumCommand =
  | { type: "propose"; id: string; question: string }
  | { type: "vote"; yes: boolean };

export type ReferendumEvent =
  | { type: "Proposed"; id: string; question: string }
  | { type: "Voted"; yes: boolean };

export type WriteState =
  | { status: "none" }
  | { status: "open"; id: string; question: string; yes: number; no: number };

export class DomainError extends Error {}

export const initial: WriteState = { status: "none" };

export function decide(cmd: ReferendumCommand, s: WriteState): ReferendumEvent[] {
  switch (cmd.type) {
    case "propose":
      if (s.status !== "none") throw new DomainError("already proposed");
      return [{ type: "Proposed", id: cmd.id, question: cmd.question }];
    case "vote":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "Voted", yes: cmd.yes }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export function evolve(s: WriteState, e: ReferendumEvent): WriteState {
  switch (e.type) {
    case "Proposed":
      return { status: "open", id: e.id, question: e.question, yes: 0, no: 0 };
    case "Voted":
      return s.status === "open" ? { ...s, yes: s.yes + (e.yes ? 1 : 0), no: s.no + (e.yes ? 0 : 1) } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<ReferendumEvent[]>;
  appendToStream(stream: string, events: ReferendumEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
  currentRevision(stream: string): Promise<bigint | null>;
}

export type ReadView = { id: string; question: string; yesPct: number };
export interface ReadStore {
  find(id: string): Promise<ReadView | null>;
}

export async function handleCommand(
  store: EventStore,
  streamName: string,
  cmd: ReferendumCommand,
): Promise<void> {
  const events = await store.readStream(streamName);
  const state = events.reduce(evolve, initial);
  const next = decide(cmd, state);
  const rev = await store.currentRevision(streamName);
  await store.appendToStream(streamName, next, { expectedRevision: rev ?? "no_stream" });
}

// The read store is eventually consistent with the event store.
export async function queryView(reads: ReadStore, id: string): Promise<ReadView | null> {
  return reads.find(id);
}
