export type PublicationDraftState =
  | { status: "none" }
  | { status: "drafting"; id: string; author: string }
  | { status: "inReview"; id: string; reviewerId: string }
  | { status: "accepted"; id: string; decidedAt: string }
  | { status: "rejected"; id: string; reason: string };

export type PublicationDraftCommand =
  | { type: "start"; id: string; author: string }
  | { type: "submit"; reviewerId: string }
  | { type: "accept"; at: string }
  | { type: "reject"; reason: string };

export type PublicationDraftEvent =
  | { type: "PublicationDraftStarted"; id: string; author: string }
  | { type: "PublicationDraftSubmitted"; reviewerId: string }
  | { type: "PublicationDraftAccepted"; at: string }
  | { type: "PublicationDraftRejected"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const publicationDraftDecider: Decider<PublicationDraftCommand, PublicationDraftEvent, PublicationDraftState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "start":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "PublicationDraftStarted", id: command.id, author: command.author }];
      case "submit":
        if (state.status !== "drafting") throw new DomainError("NOT_DRAFTING");
        return [{ type: "PublicationDraftSubmitted", reviewerId: command.reviewerId }];
      case "accept":
        if (state.status !== "inReview") throw new DomainError("NOT_IN_REVIEW");
        return [{ type: "PublicationDraftAccepted", at: command.at }];
      case "reject":
        if (state.status !== "inReview") throw new DomainError("NOT_IN_REVIEW");
        return [{ type: "PublicationDraftRejected", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PublicationDraftStarted":
        return { status: "drafting", id: event.id, author: event.author };
      case "PublicationDraftSubmitted":
        if (state.status !== "drafting") return state;
        return { status: "inReview", id: state.id, reviewerId: event.reviewerId };
      case "PublicationDraftAccepted":
        if (state.status !== "inReview") return state;
        return { status: "accepted", id: state.id, decidedAt: event.at };
      case "PublicationDraftRejected":
        if (state.status !== "inReview") return state;
        return { status: "rejected", id: state.id, reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
