Define the event union and a `when` reducer, then pipe the async event stream through `aggregateStream` with the initial state literal.

```typescript
export type CodeReviewEvent =
  | { type: "CodeReviewRequested"; id: string; author: string }
  | { type: "CodeReviewCommented"; text: string }
  | { type: "CodeReviewSubmitted"; verdict: "approve" | "changes" };

export interface CodeReviewState {
  readonly id?: string;
  readonly author?: string;
  readonly comments: number;
  readonly verdict?: "approve" | "changes";
}

export const initial: CodeReviewState = { comments: 0 };

export function when(state: CodeReviewState, event: CodeReviewEvent): CodeReviewState {
  switch (event.type) {
    case "CodeReviewRequested":
      return { ...state, id: event.id, author: event.author };
    case "CodeReviewCommented":
      return { ...state, comments: state.comments + 1 };
    case "CodeReviewSubmitted":
      return { ...state, verdict: event.verdict };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initialState: S,
): Promise<S> {
  let state: S = initialState;
  for await (const event of events) {
    state = reducer(state, event);
  }
  return state;
}

export async function loadReview(stream: AsyncIterable<CodeReviewEvent>): Promise<CodeReviewState> {
  return aggregateStream(stream, when, initial);
}
```

