export type AlertState =
  | { status: "quiet" }
  | { status: "raised"; id: string; level: number }
  | { status: "suppressed"; id: string; level: number; until: string }
  | { status: "cleared"; id: string; at: string };

export type AlertCommand =
  | { type: "raise"; id: string; level: number }
  | { type: "suppress"; until: string }
  | { type: "clear"; at: string };

export type AlertEvent =
  | { type: "AlertRaised"; id: string; level: number }
  | { type: "AlertSuppressed"; until: string }
  | { type: "AlertCleared"; at: string };

export class AlertError extends Error {
  constructor(code: string) { super(code); this.name = "AlertError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const alertDecider: Decider<AlertCommand, AlertEvent, AlertState> = {
  initialState: { status: "quiet" },
  decide(c, s) {
    switch (c.type) {
      case "raise":
        if (s.status === "raised") throw new AlertError("ALREADY_RAISED");
        if (c.level < 0 || c.level > 5) throw new AlertError("LEVEL_RANGE");
        return [{ type: "AlertRaised", id: c.id, level: c.level }];
      case "suppress":
        if (s.status !== "raised") throw new AlertError("NOT_RAISED");
        return [{ type: "AlertSuppressed", until: c.until }];
      case "clear":
        if (s.status === "suppressed") throw new AlertError("SUPPRESSED");
        if (s.status !== "raised") throw new AlertError("NOT_RAISED");
        return [{ type: "AlertCleared", at: c.at }];
      default: { const _n: never = c; throw new AlertError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "AlertRaised":
        return { status: "raised", id: e.id, level: e.level };
      case "AlertSuppressed":
        if (s.status !== "raised") return s;
        return { status: "suppressed", id: s.id, level: s.level, until: e.until };
      case "AlertCleared":
        if (s.status === "quiet") return s;
        return { status: "cleared", id: "id" in s ? s.id : "", at: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
