export type ArtifactState =
  | { status: "none" }
  | { status: "available"; id: string; provenance: string }
  | { status: "loaned"; id: string; provenance: string; borrower: string }
  | { status: "decommissioned"; id: string; at: string };

export type ArtifactEvent =
  | { type: "ArtifactAccessioned"; id: string; provenance: string }
  | { type: "ArtifactLoanedOut"; borrower: string }
  | { type: "ArtifactReturned" }
  | { type: "ArtifactDecommissioned"; at: string };

export const initialArtifact: ArtifactState = { status: "none" };

export function when(state: ArtifactState, event: ArtifactEvent): ArtifactState {
  switch (event.type) {
    case "ArtifactAccessioned":
      return { status: "available", id: event.id, provenance: event.provenance };
    case "ArtifactLoanedOut":
      if (state.status !== "available") return state;
      return { status: "loaned", id: state.id, provenance: state.provenance, borrower: event.borrower };
    case "ArtifactReturned":
      if (state.status !== "loaned") return state;
      return { status: "available", id: state.id, provenance: state.provenance };
    case "ArtifactDecommissioned":
      if (state.status === "none" || state.status === "decommissioned") return state;
      return { status: "decommissioned", id: state.id, at: event.at };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregate(events: ArtifactEvent[]): ArtifactState {
  return events.reduce(when, initialArtifact);
}
