Write the checkpoint only AFTER the projection has been applied; otherwise a crash between apply and save of the checkpoint would skip events. Keep the checkpoint store separate from the read model so a rebuild can reset one without the other.

```typescript
export type GoalEvent =
  | { type: "GoalScored"; scorer: string; matchId: string; minute: number };

export interface LeaderboardRow {
  player: string;
  goals: number;
}

export type LeaderboardView = Record<string, LeaderboardRow>;

export function project(view: LeaderboardView, e: GoalEvent): LeaderboardView {
  const prev = view[e.scorer] ?? { player: e.scorer, goals: 0 };
  return { ...view, [e.scorer]: { ...prev, goals: prev.goals + 1 } };
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface ReadModelStore {
  load(): Promise<LeaderboardView>;
  save(view: LeaderboardView): Promise<void>;
}

export interface StreamSource {
  iterate(from: bigint): AsyncIterable<{ position: bigint; event: GoalEvent }>;
}

export async function runLeaderboard(
  name: string,
  source: StreamSource,
  cp: CheckpointStore,
  rm: ReadModelStore,
): Promise<void> {
  const from = (await cp.read(name)) ?? 0n;
  let view = await rm.load();
  async function main() {
    for await (const { position, event } of source.iterate(from)) {
      view = project(view, event);
      await rm.save(view);
      await cp.write(name, position);
    }
  }
  await main();
}
```

```typescript
export type CandidateEvent =
  | { type: "Nominated"; id: string; name: string; party: string }
  | { type: "Verified"; at: string }
  | { type: "SteppedDown"; at: string };

type ExpectedRevision = bigint | "no_stream" | "any";

export class ConcurrencyConflict extends Error {
  constructor(public stream: string, public expected: ExpectedRevision) {
    super(`concurrency conflict on ${stream}`);
  }
}

export interface AppendResult { revision: bigint }
export interface ReadResult { revision: bigint | null }

export interface EventStore {
  appendToStream(stream: string, events: CandidateEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
  readStream(stream: string): Promise<ReadResult>;
}

export class StoreConflictSignal extends Error {}

export async function appendGuarded(
  store: EventStore,
  stream: string,
  events: CandidateEvent[],
): Promise<bigint> {
  const { revision } = await store.readStream(stream);
  const expected: ExpectedRevision = revision ?? "no_stream";
  try {
    const result = await store.appendToStream(stream, events, { expectedRevision: expected });
    return result.revision;
  } catch (err) {
    if (err instanceof StoreConflictSignal) {
      throw new ConcurrencyConflict(stream, expected);
    }
    throw err;
  }
}
