After a snooze expires the machine raises an internal `RING` event via `raise(...)` in the exit action of the snoozed state. This keeps the external API clean: callers only fire `DISMISS` or `SNOOZE`, and the machine self-transitions back to `ringing`.

```typescript
import { setup, assign, raise } from 'xstate';

interface Ctx { snoozeMs: number; count: number }

type Ev = { type: 'RING' } | { type: 'DISMISS' } | { type: 'SNOOZE'; minutes: number };

export const raisingReminderMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { SNOOZE_FOR: ({ context }) => context.snoozeMs }
}).createMachine({
  id: 'raisingReminder',
  context: { snoozeMs: 300_000, count: 0 },
  initial: 'ringing',
  states: {
    ringing: {
      entry: assign({ count: ({ context }) => context.count + 1 }),
      on: {
        DISMISS: 'done',
        SNOOZE: { target: 'snoozed', actions: assign({ snoozeMs: ({ event }) => event.minutes * 60_000 }) }
      }
    },
    snoozed: {
      after: { SNOOZE_FOR: { target: 'ringing', actions: raise({ type: 'RING' }) } },
      on: { DISMISS: 'done' }
    },
    done: { type: 'final' }
  }
});
