```typescript
export type ArtefactState =
  | { status: "none" }
  | { status: "published"; id: string; sha256: string; sizeBytes: number; signed: boolean }
  | { status: "retracted"; id: string; reason: string };

export type ArtefactCommand =
  | { type: "publish"; id: string; sha256: string; sizeBytes: number }
  | { type: "sign"; signer: string }
  | { type: "retract"; reason: string };

export type ArtefactEvent =
  | { type: "ArtefactPublished"; id: string; sha256: string; sizeBytes: number }
  | { type: "ArtefactSigned"; signer: string }
  | { type: "ArtefactRetracted"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const artefactDecider: Decider<ArtefactCommand, ArtefactEvent, ArtefactState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "publish":
        if (state.status !== "none") throw new DomainError("ALREADY_PUBLISHED");
        if (command.sizeBytes <= 0) throw new DomainError("EMPTY_ARTEFACT");
        return [{ type: "ArtefactPublished", id: command.id, sha256: command.sha256, sizeBytes: command.sizeBytes }];
      case "sign":
        if (state.status === "retracted") throw new DomainError("RETRACTED");
        if (state.status === "none") throw new DomainError("NOT_PUBLISHED");
        if (state.signed) throw new DomainError("ALREADY_SIGNED");
        return [{ type: "ArtefactSigned", signer: command.signer }];
      case "retract":
        if (state.status !== "published") throw new DomainError("NOT_PUBLISHED");
        return [{ type: "ArtefactRetracted", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ArtefactPublished":
        return { status: "published", id: event.id, sha256: event.sha256, sizeBytes: event.sizeBytes, signed: false };
      case "ArtefactSigned":
        if (state.status !== "published") return state;
        return { ...state, signed: true };
      case "ArtefactRetracted":
        if (state.status !== "published") return state;
        return { status: "retracted", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

Retry in v5 is modelled as a loop between `uploading` and `waiting` states. The `waiting` state uses `after` with a named delay that reads `context.attempt` to compute the backoff. When the max attempt count is exceeded a guard sends the machine to a terminal `failed` state.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Ctx { attempt: number; error: string | null; }
type Ev = { type: 'UPLOAD' };

const upload = fromPromise<void, { attempt: number }>(async ({ input }) => {
  if (input.attempt < 2) throw new Error('flaky network');
});

export const retryUploadMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { upload },
  delays: {
    backoff: ({ context }) => Math.min(30_000, 500 * 2 ** context.attempt)
  },
  guards: { overLimit: ({ context }) => context.attempt >= 5 }
}).createMachine({
  id: 'retryUpload',
  initial: 'idle',
  context: { attempt: 0, error: null },
  states: {
    idle: { on: { UPLOAD: 'uploading' } },
    uploading: {
      invoke: {
        src: 'upload',
        input: ({ context }) => ({ attempt: context.attempt }),
        onDone: 'done',
        onError: {
          target: 'waiting',
          actions: assign({
            attempt: ({ context }) => context.attempt + 1,
            error: ({ event }) => String(event.error)
          })
        }
      }
    },
    waiting: {
      always: { guard: 'overLimit', target: 'failed' },
      after: { backoff: 'uploading' }
    },
    failed: { type: 'final' },
    done: { type: 'final' }
  }
});
```

```typescript
export type SoilReadingEvent =
  | { type: "SoilReadingTaken"; fieldId: string; moisture: number }
  | { type: "SoilReadingInvalidated"; fieldId: string };

export interface MoistureView {
  readonly byField: Readonly<Record<string, number>>;
}

const empty: MoistureView = { byField: {} };

export function project(view: MoistureView, event: SoilReadingEvent): MoistureView {
  switch (event.type) {
    case "SoilReadingTaken":
      return { byField: { ...view.byField, [event.fieldId]: event.moisture } };
    case "SoilReadingInvalidated": {
      const copy = { ...view.byField };
      delete copy[event.fieldId];
      return { byField: copy };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface Batch<E> {
  readonly events: ReadonlyArray<E>;
  readonly nextRevision: bigint;
}

export interface EventSource<E> {
  readBatch(from: bigint, size: number): Promise<Batch<E>>;
}

export interface ReadStore<V> {
  persist(view: V): Promise<void>;
}

export async function rebuildMoistureView(
  source: EventSource<SoilReadingEvent>,
  store: ReadStore<MoistureView>,
  options: { from: bigint; batchSize: number }
): Promise<void> {
  let cursor = options.from;
  let view: MoistureView = empty;
  for (;;) {
    const batch = await source.readBatch(cursor, options.batchSize);
    if (batch.events.length === 0) break;
    for (const event of batch.events) {
      view = project(view, event);
    }
    await store.persist(view);
    cursor = batch.nextRevision;
  }
}
