export type LabState =
  | { status: "inactive" }
  | { status: "registered"; id: string; name: string; seats: number }
  | { status: "decommissioned"; id: string };

export type LabEvent =
  | { type: "LabRegistered"; id: string; name: string; seats: number }
  | { type: "LabSeatsChanged"; seats: number }
  | { type: "LabDecommissioned" };

export const initialLabState: LabState = { status: "inactive" };

export function evolve(state: LabState, event: LabEvent): LabState {
  switch (event.type) {
    case "LabRegistered":
      return { status: "registered", id: event.id, name: event.name, seats: event.seats };
    case "LabSeatsChanged":
      if (state.status !== "registered") return state;
      return { ...state, seats: event.seats };
    case "LabDecommissioned":
      if (state.status !== "registered") return state;
      return { status: "decommissioned", id: state.id };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let accumulator: S = initial;
  for await (const event of stream) {
    accumulator = fold(accumulator, event);
  }
  return accumulator;
}

export async function labFromStream(stream: AsyncIterable<LabEvent>): Promise<LabState> {
  return aggregateStream(stream, evolve, initialLabState);
}
