```typescript
export type EpicEvent =
  | { type: "EpicCreated"; id: string; title: string; ownerId: string }
  | { type: "EpicChildLinked"; childId: string }
  | { type: "EpicChildUnlinked"; childId: string }
  | { type: "EpicOwnerChanged"; ownerId: string }
  | { type: "EpicFinalized"; at: string };

export type Epic = Readonly<{
  id: string;
  title: string;
  ownerId: string;
  children: readonly string[];
  finalizedAt: string | null;
}>;

export const initialEpic: Epic = {
  id: "",
  title: "",
  ownerId: "",
  children: [],
  finalizedAt: null,
};

export function evolve(state: Epic, event: EpicEvent): Epic {
  switch (event.type) {
    case "EpicCreated":
      return { id: event.id, title: event.title, ownerId: event.ownerId, children: [], finalizedAt: null };
    case "EpicChildLinked":
      if (state.children.includes(event.childId)) return state;
      return { ...state, children: [...state.children, event.childId] };
    case "EpicChildUnlinked":
      return { ...state, children: state.children.filter((c) => c !== event.childId) };
    case "EpicOwnerChanged":
      return { ...state, ownerId: event.ownerId };
    case "EpicFinalized":
      return { ...state, finalizedAt: event.at };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregate(events: EpicEvent[]): Epic {
  return events.reduce(evolve, initialEpic);
}
