```typescript
export type VariantCommand =
  | { type: "register"; id: string; key: string }
  | { type: "allocateTraffic"; percent: number };

export type VariantEvent =
  | { type: "VariantRegistered"; id: string; key: string }
  | { type: "VariantTrafficAllocated"; percent: number };

export type WriteState =
  | { status: "new" }
  | { status: "ready"; id: string; key: string; traffic: number };

export interface VariantReadRow {
  id: string;
  key: string;
  trafficPercent: number;
}

export const initialState: WriteState = { status: "new" };

export function evolve(state: WriteState, event: VariantEvent): WriteState {
  switch (event.type) {
    case "VariantRegistered":
      return { status: "ready", id: event.id, key: event.key, traffic: 0 };
    case "VariantTrafficAllocated":
      if (state.status !== "ready") return state;
      return { ...state, traffic: event.percent };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(cmd: VariantCommand, state: WriteState): VariantEvent[] {
  switch (cmd.type) {
    case "register":
      if (state.status !== "new") throw new Error("EXISTS");
      return [{ type: "VariantRegistered", id: cmd.id, key: cmd.key }];
    case "allocateTraffic":
      if (state.status !== "ready") throw new Error("NOT_READY");
      if (cmd.percent < 0 || cmd.percent > 100) throw new Error("BAD_PERCENT");
      return [{ type: "VariantTrafficAllocated", percent: cmd.percent }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN");
    }
  }
}

export interface AppendOptions { expectedRevision: bigint | "no_stream" | "any"; }
export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], opts: AppendOptions): Promise<void>;
}

export interface ReadStore {
  getVariant(id: string): Promise<VariantReadRow | null>;
}

// Read store lags the event store; queries are eventually consistent.

export async function handleCommand(
  cmd: VariantCommand,
  deps: { stream: string; store: EventStore },
): Promise<void> {
  const records = await deps.store.readStream<VariantEvent>(deps.stream);
  const state = records.reduce<WriteState>((s, r) => evolve(s, r.event), initialState);
  const events = decide(cmd, state);
  const expected: AppendOptions["expectedRevision"] =
    records.length === 0 ? "no_stream" : records[records.length - 1].revision;
  await deps.store.appendToStream<VariantEvent>(deps.stream, events, { expectedRevision: expected });
}

export async function queryView(id: string, read: ReadStore): Promise<VariantReadRow | null> {
  return read.getVariant(id);
}
```

