export type RawRestaurantEvent =
  | { type: "RestaurantOpened"; version: 1; openedAt: string; id: string }
  | { type: "RestaurantOpened"; version: 2; shiftStartedAt: string; id: string }
  | { type: "RestaurantClosed"; version: 1; closedAt: string };

export type RestaurantEvent =
  | { type: "RestaurantOpened"; id: string; shiftStartedAt: string }
  | { type: "RestaurantClosed"; closedAt: string };

export class UnknownEventError extends Error {
  constructor(public readonly raw: unknown) {
    super("unknown event");
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: RawRestaurantEvent): RestaurantEvent {
  switch (raw.type) {
    case "RestaurantOpened": {
      if (raw.version === 1) {
        return { type: "RestaurantOpened", id: raw.id, shiftStartedAt: raw.openedAt };
      }
      if (raw.version === 2) {
        return { type: "RestaurantOpened", id: raw.id, shiftStartedAt: raw.shiftStartedAt };
      }
      throw new UnknownEventError(raw);
    }
    case "RestaurantClosed":
      return { type: "RestaurantClosed", closedAt: raw.closedAt };
    default: {
      const _n: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

// Minimal evolve so callers can fold upcasted events into state.
export type RestaurantState = Readonly<{ id: string; isOpen: boolean; shiftStartedAt: string | null }>;

export function evolve(state: RestaurantState, event: RestaurantEvent): RestaurantState {
  switch (event.type) {
    case "RestaurantOpened":
      return { id: event.id, isOpen: true, shiftStartedAt: event.shiftStartedAt };
    case "RestaurantClosed":
      return { ...state, isOpen: false };
    default: {
      const _n: never = event;
      return state;
    }
  }
}
