export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface InspectionV1 { id: string }
export interface InspectionV2 { id: string; score: number }
export interface InspectionV3 { id: string; score: number; notes: string }

export type CurrentInspection = InspectionV3;
export const CURRENT_VERSION = 3 as const;

function v1Tov2(raw: InspectionV1): InspectionV2 {
  return { ...raw, score: 0 };
}
function v2Tov3(raw: InspectionV2): InspectionV3 {
  return { ...raw, notes: "" };
}

export function load(snap: Snapshot<unknown>): Snapshot<CurrentInspection> {
  let state: unknown = snap.state;
  let version = snap.version;
  if (version === 1) { state = v1Tov2(state as InspectionV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as InspectionV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`BAD_VERSION:${snap.version}`);
  return { version: CURRENT_VERSION, state: state as CurrentInspection };
}
