type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: ExpectedRevision) {
    super(`Concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export type RouteEvent =
  | { type: "RoutePlanned"; id: string; label: string }
  | { type: "RouteActivated"; at: string };

export async function appendRouteEvents(
  store: EventStore<RouteEvent>,
  streamName: string,
  events: readonly RouteEvent[],
): Promise<bigint> {
  let lastRevision: bigint | undefined = undefined;
  for await (const stored of store.readStream(streamName)) {
    lastRevision = stored.revision;
  }
  const expected: ExpectedRevision = lastRevision === undefined ? "no_stream" : lastRevision;
  try {
    const result = await store.appendToStream(streamName, events, { expectedRevision: expected });
    return result.nextRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("revision")) {
      throw new ConcurrencyConflict(streamName, expected);
    }
    throw err;
  }
}
