type ReactionEvent =
  | { type: 'ReactionAdded'; userId: string; emoji: string }
  | { type: 'ReactionChanged'; emoji: string }
  | { type: 'ReactionRemoved' };

type ReactionState =
  | { status: 'none' }
  | { status: 'active'; userId: string; emoji: string };

export function when(state: ReactionState, event: ReactionEvent): ReactionState {
  switch (event.type) {
    case 'ReactionAdded':
      return { status: 'active', userId: event.userId, emoji: event.emoji };
    case 'ReactionChanged':
      return state.status === 'active' ? { ...state, emoji: event.emoji } : state;
    case 'ReactionRemoved':
      return { status: 'none' };
    default: {
      const _: never = event;
      return _;
    }
  }
}

const initial: ReactionState = { status: 'none' };

// Direct invocation (not via reduce): step the state machine one event at a time.
const afterAdd = when(initial, { type: 'ReactionAdded', userId: 'u1', emoji: ':+1:' });
const afterChange = when(afterAdd, { type: 'ReactionChanged', emoji: ':heart:' });
const afterRemove = when(afterChange, { type: 'ReactionRemoved' });

export const finalState = afterRemove;
