import { Effect } from "effect";

export type DatasetVersionState =
  | { status: "none" }
  | { status: "building"; id: string; rows: number }
  | { status: "published"; id: string };

export type DatasetVersionCommand =
  | { type: "start"; id: string }
  | { type: "addRows"; count: number }
  | { type: "publish" };

export type DatasetVersionEvent =
  | { type: "DatasetVersionStarted"; id: string }
  | { type: "DatasetVersionRowsAdded"; count: number }
  | { type: "DatasetVersionPublished" };

const initial: DatasetVersionState = { status: "none" };

function evolve(state: DatasetVersionState, event: DatasetVersionEvent): DatasetVersionState {
  switch (event.type) {
    case "DatasetVersionStarted":
      return { status: "building", id: event.id, rows: 0 };
    case "DatasetVersionRowsAdded":
      return state.status === "building" ? { ...state, rows: state.rows + event.count } : state;
    case "DatasetVersionPublished":
      return state.status === "building" ? { status: "published", id: state.id } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: DatasetVersionCommand, state: DatasetVersionState): DatasetVersionEvent[] {
  switch (command.type) {
    case "start":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "DatasetVersionStarted", id: command.id }];
    case "addRows":
      if (state.status !== "building") throw new Error("NOT_BUILDING");
      return [{ type: "DatasetVersionRowsAdded", count: command.count }];
    case "publish":
      if (state.status !== "building") throw new Error("NOT_BUILDING");
      if (state.rows === 0) throw new Error("EMPTY");
      return [{ type: "DatasetVersionPublished" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export const handle = (
  command: DatasetVersionCommand,
  ctx: { streamName: string; eventStore: EventStore },
) =>
  Effect.gen(function* () {
    const read = yield* Effect.promise(() => ctx.eventStore.readStream<DatasetVersionEvent>(ctx.streamName));
    const state = read.events.reduce(evolve, initial);
    const events = decide(command, state);
    yield* Effect.promise(() => ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision }));
  });
