export type PrerequisiteState =
  | { status: "none" }
  | { status: "declared"; courseId: string; requires: ReadonlyArray<string> }
  | { status: "retired"; courseId: string };

export type PrerequisiteEvent =
  | { type: "PrerequisiteDeclared"; courseId: string }
  | { type: "PrerequisiteAdded"; prerequisiteId: string }
  | { type: "PrerequisiteRemoved"; prerequisiteId: string }
  | { type: "PrerequisiteRetired" };

export const initialState: PrerequisiteState = { status: "none" };

export function when(state: PrerequisiteState, event: PrerequisiteEvent): PrerequisiteState {
  switch (event.type) {
    case "PrerequisiteDeclared":
      return { status: "declared", courseId: event.courseId, requires: [] };
    case "PrerequisiteAdded":
      if (state.status !== "declared") return state;
      if (state.requires.includes(event.prerequisiteId)) return state;
      return { ...state, requires: [...state.requires, event.prerequisiteId] };
    case "PrerequisiteRemoved":
      if (state.status !== "declared") return state;
      return { ...state, requires: state.requires.filter((id) => id !== event.prerequisiteId) };
    case "PrerequisiteRetired":
      if (state.status !== "declared") return state;
      return { status: "retired", courseId: state.courseId };
    default: { const _n: never = event; return state; }
  }
}

export function aggregate(events: ReadonlyArray<PrerequisiteEvent>): PrerequisiteState {
  return events.reduce(when, initialState);
}
