```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

interface AuctionRoomV1 {
  readonly id: string;
  readonly highBid: number;
}

interface AuctionRoomV2 {
  readonly id: string;
  readonly highBid: number;
  readonly highBidder: string | null;
}

interface AuctionRoomV3 {
  readonly id: string;
  readonly highBid: number;
  readonly highBidder: string | null;
  readonly reservePrice: number;
}

export type CurrentAuctionRoom = AuctionRoomV3;
export const CURRENT_VERSION = 3 as const;

function v1Tov2(prev: AuctionRoomV1): AuctionRoomV2 {
  return { ...prev, highBidder: null };
}

function v2Tov3(prev: AuctionRoomV2): AuctionRoomV3 {
  return { ...prev, reservePrice: prev.highBid };
}

const upgraders: Record<number, (prev: unknown) => unknown> = {
  1: (s) => v1Tov2(s as AuctionRoomV1),
  2: (s) => v2Tov3(s as AuctionRoomV2),
};

export function loadSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentAuctionRoom> {
  let version = snap.version;
  let state: unknown = snap.state;
  while (version < CURRENT_VERSION) {
    const step = upgraders[version];
    if (!step) throw new Error(`No upgrader for version ${version}`);
    state = step(state);
    version += 1;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`Unsupported version: ${snap.version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentAuctionRoom };
}
