export type DeploymentEvent =
  | { type: "DeploymentStarted"; id: string }
  | { type: "DeploymentSucceeded"; id: string; at: string }
  | { type: "DeploymentRolledBack"; id: string; reason: string };

export type Command =
  | { type: "NotifyOncall"; deploymentId: string; at: string }
  | { type: "OpenIncident"; sourceDeploymentId: string; reason: string };

export function react(event: DeploymentEvent): Command | null {
  switch (event.type) {
    case "DeploymentStarted":
      return null;
    case "DeploymentSucceeded":
      return { type: "NotifyOncall", deploymentId: event.id, at: event.at };
    case "DeploymentRolledBack":
      return { type: "OpenIncident", sourceDeploymentId: event.id, reason: event.reason };
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export function projection(events: DeploymentEvent[]): Command[] {
  const out: Command[] = [];
  for (const e of events) {
    const c = react(e);
    if (c) out.push(c);
  }
  return out;
}
