```typescript
export type GradeState =
  | { status: "none" }
  | { status: "recorded"; id: string; learner: string; course: string; score: number }
  | { status: "voided"; id: string };

export type GradeCommand =
  | { type: "record"; id: string; learner: string; course: string; score: number }
  | { type: "correct"; score: number }
  | { type: "void"; reason: string };

export type GradeEvent =
  | { type: "GradeRecorded"; id: string; learner: string; course: string; score: number }
  | { type: "GradeCorrected"; score: number }
  | { type: "GradeVoided"; reason: string };

export class DomainError extends Error {}

export const initialState: GradeState = { status: "none" };

export function evolve(state: GradeState, event: GradeEvent): GradeState {
  switch (event.type) {
    case "GradeRecorded":
      return { status: "recorded", id: event.id, learner: event.learner, course: event.course, score: event.score };
    case "GradeCorrected":
      if (state.status !== "recorded") return state;
      return { ...state, score: event.score };
    case "GradeVoided":
      if (state.status === "none") return state;
      return { status: "voided", id: "id" in state ? state.id : "" };
    default: { const _n: never = event; return state; }
  }
}

export function decide(c: GradeCommand, s: GradeState): GradeEvent[] {
  switch (c.type) {
    case "record":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "GradeRecorded", id: c.id, learner: c.learner, course: c.course, score: c.score }];
    case "correct":
      if (s.status !== "recorded") throw new DomainError("NOT_RECORDED");
      return [{ type: "GradeCorrected", score: c.score }];
    case "void":
      if (s.status !== "recorded") throw new DomainError("NOT_RECORDED");
      return [{ type: "GradeVoided", reason: c.reason }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<GradeEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<GradeEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export async function handleGradeCommand(
  streamName: string,
  command: GradeCommand,
  eventStore: EventStore,
): Promise<void> {
  const { events, revision } = await eventStore.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const next = decide(command, state);
  if (next.length === 0) return;
  await eventStore.appendToStream(streamName, next, { expectedRevision: revision ?? "no_stream" });
}
