export type StatementEvent =
  | { type: "StatementOpened"; id: string; account: string }
  | { type: "StatementLinePosted"; id: string; amount: number }
  | { type: "StatementClosed"; id: string; at: string };

export type EventEnvelope = Readonly<{ position: bigint; event: StatementEvent }>;

export interface EventIterator {
  iterate(from: bigint): AsyncIterable<EventEnvelope>;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export type StatementView = Readonly<{
  byId: Readonly<Record<string, { account: string; total: number; closed: boolean }>>;
}>;

export const emptyView: StatementView = { byId: {} };

export function project(view: StatementView, event: StatementEvent): StatementView {
  switch (event.type) {
    case "StatementOpened":
      return { byId: { ...view.byId, [event.id]: { account: event.account, total: 0, closed: false } } };
    case "StatementLinePosted": {
      const prior = view.byId[event.id];
      if (!prior) return view;
      return { byId: { ...view.byId, [event.id]: { ...prior, total: prior.total + event.amount } } };
    }
    case "StatementClosed": {
      const prior = view.byId[event.id];
      if (!prior) return view;
      return { byId: { ...view.byId, [event.id]: { ...prior, closed: true } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface ViewStore {
  load(): Promise<StatementView>;
  save(view: StatementView): Promise<void>;
}

export async function runSubscription(
  name: string,
  iterator: EventIterator,
  checkpoints: CheckpointStore,
  views: ViewStore,
): Promise<void> {
  const last = await checkpoints.read(name);
  const from = last === null ? 0n : last + 1n;
  let view = await views.load();
  for await (const { position, event } of iterator.iterate(from)) {
    view = project(view, event);
    await views.save(view);
    await checkpoints.write(name, position);
  }
}
