import { Effect } from "effect";

export type SculptureEvent =
  | { type: "SculptureReceived"; id: string; title: string }
  | { type: "SculptureDisplayed"; id: string; hall: string }
  | { type: "SculptureDeaccessioned"; id: string; at: string };

export interface SculptureView {
  readonly displayed: number;
  readonly deaccessioned: number;
}

const empty: SculptureView = { displayed: 0, deaccessioned: 0 };

function project(view: SculptureView, event: SculptureEvent): SculptureView {
  switch (event.type) {
    case "SculptureReceived":
      return view;
    case "SculptureDisplayed":
      return { ...view, displayed: view.displayed + 1 };
    case "SculptureDeaccessioned":
      return { ...view, deaccessioned: view.deaccessioned + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface Cursor<E> { [Symbol.asyncIterator](): AsyncIterator<{ position: bigint; event: E }>; }

export const runSubscription = (
  name: string,
  cursor: Cursor<SculptureEvent>,
  checkpoints: CheckpointStore,
  save: (v: SculptureView) => Promise<void>,
) =>
  Effect.gen(function* () {
    let view = empty;
    const iter = cursor[Symbol.asyncIterator]();
    while (true) {
      const step = yield* Effect.promise(() => iter.next());
      if (step.done) break;
      const { position, event } = step.value;
      view = project(view, event);
      yield* Effect.promise(() => save(view));
      yield* Effect.promise(() => checkpoints.write(name, position));
    }
  });
