export type ClaimEvent =
  | { type: "ClaimFiled"; id: string; amount: number }
  | { type: "ClaimApproved"; id: string; at: string };

export type ClaimsView = Readonly<{ filed: number; approved: number }>;

export const emptyView: ClaimsView = { filed: 0, approved: 0 };

export function project(view: ClaimsView, event: ClaimEvent): ClaimsView {
  switch (event.type) {
    case "ClaimFiled":
      return { ...view, filed: view.filed + 1 };
    case "ClaimApproved":
      return { ...view, approved: view.approved + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface RangeReader {
  read(from: bigint, batch: number): AsyncIterable<{ revision: bigint; event: ClaimEvent }>;
}

export interface ReadStore {
  save(view: ClaimsView, cursor: bigint): Promise<void>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  reader: RangeReader;
  store: ReadStore;
  onProgress?: (processed: number, cursor: bigint) => void;
}): Promise<void> {
  let view = emptyView;
  let cursor = opts.from;
  let processed = 0;
  for await (const rec of opts.reader.read(opts.from, opts.batchSize)) {
    view = project(view, rec.event);
    cursor = rec.revision + 1n;
    processed += 1;
    if (processed % opts.batchSize === 0) {
      await opts.store.save(view, cursor);
      opts.onProgress?.(processed, cursor);
    }
  }
  await opts.store.save(view, cursor);
}
