    case "CampaignEnded":
      return { type: "CampaignEnded", id: raw.data.id };
    default: { const _n: never = raw; throw new UnknownEventError("unknown event"); }
  }
}

export function aggregate(raws: RawCampaignEvent[]): CampaignEvent[] {
  return raws.map(upcast);
