```typescript
export type Snapshot<S> = { version: number; state: S };

export type JournalV1 = { id: string; entries: number };
export type JournalV2 = { id: string; entries: number; lastEntryAt: string | null };
export type JournalV3 = {
  id: string;
  entries: number;
  lastEntryAt: string | null;
  status: "open" | "closed";
};

export type CurrentJournal = JournalV3;
export const CURRENT_VERSION = 3;

export class JournalSnapshotError extends Error {}

function v1Tov2(s: JournalV1): JournalV2 {
  return { ...s, lastEntryAt: null };
}

function v2Tov3(s: JournalV2): JournalV3 {
  return { ...s, status: "open" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentJournal> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new JournalSnapshotError(`UNSUPPORTED_VERSION_${version}`);
  }
  if (version === 1) {
    state = v1Tov2(state as JournalV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as JournalV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new JournalSnapshotError("UPGRADE_INCOMPLETE");
  }
  const upgraded = state as CurrentJournal;
  if (typeof upgraded.id !== "string" || typeof upgraded.entries !== "number") {
    throw new JournalSnapshotError("SHAPE_MISMATCH");
  }
  return { version, state: upgraded };
}

export function loadJournal(raw: Snapshot<unknown>): CurrentJournal {
  return upgradeSnapshot(raw).state;
}
```

```typescript
export type Snapshot<S> = { version: number; state: S };

export type CourseV1 = { id: string; title: string };
export type CourseV2 = { id: string; title: string; capacity: number };
export type CourseV3 = {
  id: string;
  title: string;
  capacity: number;
  status: "draft" | "open" | "scheduled" | "closed";
};

export type CurrentCourse = CourseV3;
export const CURRENT_VERSION = 3;

export class UpgradeError extends Error {}

function v1Tov2(s: CourseV1): CourseV2 {
  return { ...s, capacity: 0 };
}

function v2Tov3(s: CourseV2): CourseV3 {
  return { ...s, status: "draft" };
}

type UpgradeStep = { from: number; to: number; run: (raw: unknown) => unknown };

const pipeline: ReadonlyArray<UpgradeStep> = [
  { from: 1, to: 2, run: (raw) => v1Tov2(raw as CourseV1) },
  { from: 2, to: 3, run: (raw) => v2Tov3(raw as CourseV2) },
];

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentCourse> {
  let version = snap.version;
  let state: unknown = snap.state;
  for (const step of pipeline) {
    if (version === step.from) {
      state = step.run(state);
      version = step.to;
    }
  }
  if (version !== CURRENT_VERSION) throw new UpgradeError("UNKNOWN_VERSION");
  const current = state as CurrentCourse;
  if (!current.id || !current.title) throw new UpgradeError("SHAPE_MISMATCH");
  return { version, state: current };
}
