A combobox has two concerns that evolve together: the input box (idle, typing, fetching) and the listbox (closed, open). Modeling them as sibling regions under `type: 'parallel'` lets each progress without blocking the other — the listbox can stay open while a new fetch is in flight.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { query: string; items: string[] };
type Ev =
  | { type: 'FOCUS' }
  | { type: 'BLUR' }
  | { type: 'INPUT'; text: string }
  | { type: 'RESULTS'; items: string[] };

export const combobox = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'combobox',
  context: { query: '', items: [] },
  type: 'parallel',
  states: {
    input: {
      initial: 'idle',
      states: {
        idle: { on: { INPUT: { target: 'typing', actions: assign({ query: ({ event }) => event.text }) } } },
        typing: {
          on: {
            INPUT: { target: 'typing', reenter: true, actions: assign({ query: ({ event }) => event.text }) },
            RESULTS: { target: 'idle', actions: assign({ items: ({ event }) => event.items }) },
          },
        },
      },
    },
    listbox: {
      initial: 'closed',
      states: {
        closed: { on: { FOCUS: 'open' } },
        open: { on: { BLUR: 'closed' } },
      },
    },
  },
});
