```typescript
export type ProvisioningEvent =
  | { type: "ProvisioningOpened"; id: string; required: number }
  | { type: "StockRecorded"; quantity: number };

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface Transaction {
  insertOutbox(rows: ReadonlyArray<OutboxRow>): Promise<void>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<ProvisioningEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface EventStore<E> {
  begin(): Promise<Transaction>;
  readStreamRevision(stream: string): Promise<ExpectedRevision>;
}

// A separate publisher polls the outbox table and marks publishedAt
// after successfully forwarding each row to the message bus.
export async function appendWithOutbox(
  store: EventStore<ProvisioningEvent>,
  stream: string,
  events: ReadonlyArray<ProvisioningEvent>,
  outboxRows: ReadonlyArray<OutboxRow>,
): Promise<void> {
  const tx = await store.begin();
  try {
    const expectedRevision = await store.readStreamRevision(stream);
    await tx.appendToStream(stream, events, { expectedRevision });
    await tx.insertOutbox(outboxRows);
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err instanceof Error ? err : new Error(String(err));
  }
}
