type ClaimEvent =
  | { type: 'ClaimStaked'; claimId: string; holder: string }
  | { type: 'ClaimTransferred'; claimId: string; to: string }
  | { type: 'ClaimRelinquished'; claimId: string; at: string };

type View = Readonly<{ claimId: string; holder: string; active: boolean }>;

interface EventStore {
  readAllFrom(from: bigint, batchSize: number): AsyncIterable<{ event: ClaimEvent; revision: bigint }>;
}

interface ReadStore {
  persist(view: View): Promise<void>;
  clear(): Promise<void>;
}

function project(view: View, event: ClaimEvent): View {
  switch (event.type) {
    case 'ClaimStaked':
      return { claimId: event.claimId, holder: event.holder, active: true };
    case 'ClaimTransferred':
      return { ...view, holder: event.to };
    case 'ClaimRelinquished':
      return { ...view, active: false };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  eventStore: EventStore;
  readStore: ReadStore;
}): Promise<void> {
  if (opts.from === 0n) await opts.readStore.clear();
  let view: View = { claimId: '', holder: '', active: false };
  for await (const { event } of opts.eventStore.readAllFrom(opts.from, opts.batchSize)) {
    view = project(view, event);
    await opts.readStore.persist(view);
  }
}
