```typescript
export interface ArtefactV1 {
  readonly id: string;
  readonly sha256: string;
  readonly sizeBytes: number;
}

export interface ArtefactV2 extends ArtefactV1 {
  readonly signed: boolean;
}

export interface ArtefactV3 extends ArtefactV2 {
  readonly publishedAt: string;
}

export type CurrentArtefact = ArtefactV3;
export const CURRENT_VERSION = 3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function isArtefactV3(state: unknown): state is ArtefactV3 {
  if (!state || typeof state !== "object") return false;
  const s = state as Record<string, unknown>;
  return (
    typeof s.id === "string" &&
    typeof s.sha256 === "string" &&
    typeof s.sizeBytes === "number" &&
    typeof s.signed === "boolean" &&
    typeof s.publishedAt === "string"
  );
}

function v1Tov2(state: ArtefactV1): ArtefactV2 {
  return { ...state, signed: false };
}

function v2Tov3(state: ArtefactV2): ArtefactV3 {
  return { ...state, publishedAt: "1970-01-01T00:00:00Z" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentArtefact> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as ArtefactV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as ArtefactV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION || !isArtefactV3(state)) {
    throw new Error(`unsupported snapshot version ${snap.version}`);
  }
  return { version: CURRENT_VERSION, state };
}
