  name: string,
  source: EventStore,
  checkpoints: CheckpointStore,
  model: RouteReadModel,
) =>
  Effect.gen(function* () {
    const last = yield* Effect.promise(() => checkpoints.read(name));
    yield* Effect.promise(async () => {
      for await (const { position, event } of source.subscribe(last)) {
        switch (event.type) {
          case "RoutePlanned": await model.applyPlanned(event.id); break;
          case "RouteActivated": await model.applyActivated(); break;
          case "RouteClosed": await model.applyClosed(); break;
          default: { const _n: never = event; }
        }
        await checkpoints.write(name, position);
      }
    });
  });
