export type EscrowState =
  | { status: "none" }
  | { status: "funded"; id: string; payer: string; payee: string; amount: number }
  | { status: "released"; id: string; payee: string; amount: number; releasedAt: string }
  | { status: "refunded"; id: string; payer: string; amount: number };

export type EscrowCommand =
  | { type: "fund"; id: string; payer: string; payee: string; amount: number }
  | { type: "release"; at: string }
  | { type: "refundToPayer"; reason: string };

export type EscrowEvent =
  | { type: "EscrowFunded"; id: string; payer: string; payee: string; amount: number }
  | { type: "EscrowReleased"; at: string }
  | { type: "EscrowRefundedToPayer"; reason: string };

export class EscrowError extends Error {
  constructor(public readonly code: string) { super(code); }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const escrowDecider: Decider<EscrowCommand, EscrowEvent, EscrowState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "fund":
        if (state.status !== "none") throw new EscrowError("EXISTS");
        if (command.amount <= 0) throw new EscrowError("INVALID_AMOUNT");
        return [{
          type: "EscrowFunded",
          id: command.id,
          payer: command.payer,
          payee: command.payee,
          amount: command.amount,
        }];
      case "release":
        if (state.status === "refunded") throw new EscrowError("ALREADY_REFUNDED");
        if (state.status !== "funded") throw new EscrowError("NOT_FUNDED");
        return [{ type: "EscrowReleased", at: command.at }];
      case "refundToPayer":
        if (state.status === "released") throw new EscrowError("ALREADY_RELEASED");
        if (state.status !== "funded") throw new EscrowError("NOT_FUNDED");
        return [{ type: "EscrowRefundedToPayer", reason: command.reason }];
      default: { const _n: never = command; throw new EscrowError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "EscrowFunded":
        return { status: "funded", id: event.id, payer: event.payer, payee: event.payee, amount: event.amount };
      case "EscrowReleased":
        if (state.status !== "funded") return state;
        return { status: "released", id: state.id, payee: state.payee, amount: state.amount, releasedAt: event.at };
      case "EscrowRefundedToPayer":
        if (state.status !== "funded") return state;
        return { status: "refunded", id: state.id, payer: state.payer, amount: state.amount };
      default: { const _n: never = event; return state; }
    }
  },
};
