```typescript
export type PatientState =
  | { status: "none" }
  | { status: "registered"; id: string; mrn: string }
  | { status: "admitted"; id: string; mrn: string; ward: string; since: string }
  | { status: "discharged"; id: string; mrn: string; at: string };

export type PatientCommand =
  | { type: "register"; id: string; mrn: string }
  | { type: "admit"; ward: string; at: string }
  | { type: "discharge"; at: string };

export type PatientEvent =
  | { type: "PatientRegistered"; id: string; mrn: string }
  | { type: "PatientAdmitted"; ward: string; at: string }
  | { type: "PatientDischarged"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const patientDecider: Decider<PatientCommand, PatientEvent, PatientState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("ALREADY_REGISTERED");
        return [{ type: "PatientRegistered", id: command.id, mrn: command.mrn }];
      case "admit":
        if (state.status === "admitted") throw new DomainError("ALREADY_ADMITTED");
        if (state.status === "none") throw new DomainError("NOT_REGISTERED");
        return [{ type: "PatientAdmitted", ward: command.ward, at: command.at }];
      case "discharge":
        if (state.status !== "admitted") throw new DomainError("NOT_ADMITTED");
        return [{ type: "PatientDischarged", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PatientRegistered":
        return { status: "registered", id: event.id, mrn: event.mrn };
      case "PatientAdmitted":
        if (state.status !== "registered" && state.status !== "discharged") return state;
        return { status: "admitted", id: state.id, mrn: state.mrn, ward: event.ward, since: event.at };
      case "PatientDischarged":
        if (state.status !== "admitted") return state;
        return { status: "discharged", id: state.id, mrn: state.mrn, at: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
