export type ConsentFormState =
  | { status: "none" }
  | { status: "granted"; id: string; subject: string; scope: string[]; at: string }
  | { status: "revoked"; id: string; at: string }
  | { status: "expired"; id: string; at: string };

export type ConsentFormCommand =
  | { type: "grant"; id: string; subject: string; scope: string[]; at: string }
  | { type: "revoke"; at: string }
  | { type: "expire"; at: string };

export type ConsentFormEvent =
  | { type: "ConsentGranted"; id: string; subject: string; scope: string[]; at: string }
  | { type: "ConsentRevoked"; at: string }
  | { type: "ConsentExpired"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const consentFormDecider: Decider<ConsentFormCommand, ConsentFormEvent, ConsentFormState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "grant":
        if (s.status !== "none") throw new DomainError("EXISTS");
        if (c.scope.length === 0) throw new DomainError("SCOPE_EMPTY");
        return [{ type: "ConsentGranted", id: c.id, subject: c.subject, scope: c.scope, at: c.at }];
      case "revoke":
        if (s.status !== "granted") throw new DomainError("NOT_GRANTED");
        return [{ type: "ConsentRevoked", at: c.at }];
      case "expire":
        if (s.status !== "granted") throw new DomainError("NOT_GRANTED");
        return [{ type: "ConsentExpired", at: c.at }];
      default: {
        const _never: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ConsentGranted":
        return { status: "granted", id: e.id, subject: e.subject, scope: e.scope, at: e.at };
      case "ConsentRevoked":
        if (s.status !== "granted") return s;
        return { status: "revoked", id: s.id, at: e.at };
      case "ConsentExpired":
        if (s.status !== "granted") return s;
        return { status: "expired", id: s.id, at: e.at };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
