Use a single transaction that both appends to the stream and inserts the outbox row. A separate worker polls the outbox table, publishes each row, and marks it published.

```typescript
export type ContainerEvent =
  | { type: "ContainerSealed"; id: string; seal: string }
  | { type: "ContainerDispatched"; id: string; destination: string };

export interface OutboxRow {
  readonly id: string;
  readonly payload: { schema: string; data: Record<string, unknown> };
  readonly publishedAt: string | null;
}

export interface Transaction {
  appendToStream(stream: string, events: ReadonlyArray<ContainerEvent>, expectedRevision: bigint | "no_stream"): Promise<bigint>;
  insertOutbox(row: OutboxRow): Promise<void>;
}

export interface Connection {
  transaction<T>(work: (tx: Transaction) => Promise<T>): Promise<T>;
}

// Publisher runs elsewhere: polls outbox rows where publishedAt IS NULL,
// forwards the payload to the bus, then sets publishedAt.
export async function appendWithOutbox(
  stream: string,
  events: ReadonlyArray<ContainerEvent>,
  outboxRows: ReadonlyArray<OutboxRow>,
  conn: Connection,
  expectedRevision: bigint | "no_stream",
): Promise<bigint> {
  return conn.transaction(async (tx) => {
    const revision = await tx.appendToStream(stream, events, expectedRevision);
    for (const row of outboxRows) {
      await tx.insertOutbox(row);
    }
    return revision;
  });
}
```

