  | { type: "LoanOriginated"; id: string; principal: number }
  | { type: "LoanDisbursed"; at: string }
  | { type: "LoanClosed"; reason: string };

export class LoanError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "LoanError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const loanDecider: Decider<LoanCommand, LoanEvent, LoanState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "originate":
        if (state.status !== "none") throw new LoanError("LOAN_EXISTS");
        if (command.principal <= 0) throw new LoanError("PRINCIPAL_INVALID");
        return [{ type: "LoanOriginated", id: command.id, principal: command.principal }];
      case "disburse":
        if (state.status === "closed") throw new LoanError("LOAN_CLOSED");
        if (state.status !== "originated") throw new LoanError("NOT_ORIGINATED");
        return [{ type: "LoanDisbursed", at: command.at }];
      case "close":
        if (state.status === "none") throw new LoanError("NOT_FOUND");
        if (state.status === "closed") return [];
        return [{ type: "LoanClosed", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new LoanError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "LoanOriginated":
        return { status: "originated", id: event.id, principal: event.principal };
      case "LoanDisbursed":
        if (state.status !== "originated") return state;
        return { status: "disbursed", id: state.id, principal: state.principal, disbursedAt: event.at };
      case "LoanClosed":
        if (state.status === "none") return state;
        return { status: "closed", id: "id" in state ? state.id : "" };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

