A GuardrailMetric evolve reducer stays pure: it turns an append-only stream of observations into a running summary (count, sum, last-breach). Because it is a plain function over a discriminated union, the same stream always rebuilds the same stats, which is what makes event-sourced metrics reproducible.

```typescript
export type GuardrailMetricEvent =
  | { type: "GuardrailMetricInitialized"; metricId: string; threshold: number }
  | { type: "GuardrailMetricSampled"; value: number }
  | { type: "GuardrailMetricBreached"; at: string };

export type GuardrailMetricState = Readonly<{
  metricId?: string;
  threshold: number;
  count: number;
  sum: number;
  lastBreachAt?: string;
}>;

export const initialState: GuardrailMetricState = { threshold: Number.POSITIVE_INFINITY, count: 0, sum: 0 };

export function evolve(state: GuardrailMetricState, event: GuardrailMetricEvent): GuardrailMetricState {
  switch (event.type) {
    case "GuardrailMetricInitialized":
      return { ...state, metricId: event.metricId, threshold: event.threshold };
    case "GuardrailMetricSampled":
      return { ...state, count: state.count + 1, sum: state.sum + event.value };
    case "GuardrailMetricBreached":
      return { ...state, lastBreachAt: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregateStream(events: GuardrailMetricEvent[]): GuardrailMetricState {
  return events.reduce<GuardrailMetricState>(evolve, initialState);
}
```

The upgrader chain runs functions keyed on the source version until state reaches CURRENT_VERSION. Each step is a pure transformation of one shape into the next.

```typescript
export const CURRENT_VERSION = 3;

export interface FeedingRegimeV1 {
  readonly id: string;
  readonly kcalPerDay: number;
}

export interface FeedingRegimeV2 {
  readonly id: string;
  readonly kcalPerDay: number;
  readonly feedingsPerDay: number;
}

export interface FeedingRegimeV3 {
  readonly id: string;
  readonly kcalPerDay: number;
  readonly feedingsPerDay: number;
  readonly startedAt: string | null;
}

export type FeedingRegimeCurrent = FeedingRegimeV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(s: FeedingRegimeV1): FeedingRegimeV2 {
  return { ...s, feedingsPerDay: 2 };
}

function v2Tov3(s: FeedingRegimeV2): FeedingRegimeV3 {
  return { ...s, startedAt: null };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<FeedingRegimeCurrent> {
  let version = raw.version;
  let state: unknown = raw.state;
  if (version === 1) {
    state = v1Tov2(state as FeedingRegimeV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as FeedingRegimeV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${raw.version}`);
  return { version: CURRENT_VERSION, state: state as FeedingRegimeCurrent };
}
```

A Decider groups three deterministic ingredients: an initialState literal, a decide(command, state) function that turns an intent into events (or throws a typed error on invariant violation), and an evolve(state, event) function that folds events back into state. Purity means no I/O, no clocks, no randomness — every timestamp or identifier enters as command/event data. The orchestrator (a CommandHandler) reads the stream, folds with evolve, calls decide, and appends the resulting events; decide itself never knows a store exists.

```typescript
export type SherpaState =
  | { status: "none" }
  | { status: "available"; id: string; name: string }
  | { status: "assigned"; id: string; name: string; expeditionId: string }
  | { status: "discharged"; id: string };

export type SherpaCommand =
  | { type: "hire"; id: string; name: string }
  | { type: "assign"; expeditionId: string }
  | { type: "release" }
  | { type: "discharge" };

export type SherpaEvent =
  | { type: "SherpaHired"; id: string; name: string }
  | { type: "SherpaAssigned"; expeditionId: string }
  | { type: "SherpaReleased" }
  | { type: "SherpaDischarged" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const sherpaDecider: Decider<SherpaCommand, SherpaEvent, SherpaState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "hire":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "SherpaHired", id: command.id, name: command.name }];
      case "assign":
        if (state.status !== "available") throw new DomainError("NOT_AVAILABLE");
        return [{ type: "SherpaAssigned", expeditionId: command.expeditionId }];
      case "release":
        if (state.status !== "assigned") throw new DomainError("NOT_ASSIGNED");
        return [{ type: "SherpaReleased" }];
      case "discharge":
        if (state.status === "none" || state.status === "discharged") throw new DomainError("INVALID");
        return [{ type: "SherpaDischarged" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SherpaHired":
        return { status: "available", id: event.id, name: event.name };
      case "SherpaAssigned":
        if (state.status !== "available") return state;
        return { status: "assigned", id: state.id, name: state.name, expeditionId: event.expeditionId };
      case "SherpaReleased":
        if (state.status !== "assigned") return state;
        return { status: "available", id: state.id, name: state.name };
      case "SherpaDischarged":
        if (state.status === "none" || state.status === "discharged") return state;
        return { status: "discharged", id: state.id };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
