```typescript
export type TrialPhaseEvent =
  | { type: "TrialPhaseOpened"; trialId: string; phase: string }
  | { type: "TrialPhaseAdvanced"; trialId: string; phase: string }
  | { type: "TrialPhaseClosed"; trialId: string };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventEnvelope<E> {
  event: E;
  position: bigint;
}

export interface EventFeed<E> {
  subscribe(fromPosition: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface TrialPhaseView {
  byTrial: Record<string, { phase: string } | undefined>;
}

export function project(view: TrialPhaseView, event: TrialPhaseEvent): TrialPhaseView {
  switch (event.type) {
    case "TrialPhaseOpened":
    case "TrialPhaseAdvanced":
      return { byTrial: { ...view.byTrial, [event.trialId]: { phase: event.phase } } };
    case "TrialPhaseClosed": {
      const next = { ...view.byTrial };
      delete next[event.trialId];
      return { byTrial: next };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export async function runSubscription(
  name: string,
  feed: EventFeed<TrialPhaseEvent>,
  checkpoints: CheckpointStore,
  apply: (event: TrialPhaseEvent) => Promise<void>,
): Promise<void> {
  const last = (await checkpoints.read(name)) ?? 0n;
  for await (const envelope of feed.subscribe(last)) {
    await apply(envelope.event);
    await checkpoints.write(name, envelope.position);
  }
}
