import { Effect } from "effect";

export type DataReleaseEvent =
  | { type: "DataReleasePublished"; id: string; at: string }
  | { type: "DataReleaseEmbargoed"; id: string; until: string };

export type DataReleaseView = { published: number; embargoed: number };
const empty: DataReleaseView = { published: 0, embargoed: 0 };

function project(view: DataReleaseView, event: DataReleaseEvent): DataReleaseView {
  switch (event.type) {
    case "DataReleasePublished":
      return { ...view, published: view.published + 1 };
    case "DataReleaseEmbargoed":
      return { ...view, embargoed: view.embargoed + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface Cursor<E> {
  [Symbol.asyncIterator](): AsyncIterator<{ position: bigint; event: E }>;
}

export const runSubscription = (
  name: string,
  cursor: Cursor<DataReleaseEvent>,
  checkpoints: CheckpointStore,
  save: (v: DataReleaseView) => Promise<void>,
) =>
  Effect.gen(function* () {
    let view = empty;
    const iter = cursor[Symbol.asyncIterator]();
    while (true) {
      const step = yield* Effect.promise(() => iter.next());
      if (step.done) break;
      const { position, event } = step.value;
      view = project(view, event);
      yield* Effect.promise(() => save(view));
      yield* Effect.promise(() => checkpoints.write(name, position));
    }
  });
