```typescript
export type PickListState =
  | { status: "empty" }
  | { status: "open"; id: string; picker: string; lines: number }
  | { status: "completed"; id: string; lines: number; completedAt: string };

export type PickListCommand =
  | { type: "create"; id: string; picker: string }
  | { type: "add-line"; sku: string; qty: number }
  | { type: "complete"; at: string };

export type PickListEvent =
  | { type: "PickListCreated"; id: string; picker: string }
  | { type: "PickListLineAdded"; sku: string; qty: number }
  | { type: "PickListCompleted"; at: string };

class PickError extends Error {}

const initialState: PickListState = { status: "empty" };

function evolve(s: PickListState, e: PickListEvent): PickListState {
  switch (e.type) {
    case "PickListCreated": return { status: "open", id: e.id, picker: e.picker, lines: 0 };
    case "PickListLineAdded":
      if (s.status !== "open") return s;
      return { ...s, lines: s.lines + 1 };
    case "PickListCompleted":
      if (s.status !== "open") return s;
      return { status: "completed", id: s.id, lines: s.lines, completedAt: e.at };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: PickListCommand, s: PickListState): PickListEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "empty") throw new PickError("EXISTS");
      return [{ type: "PickListCreated", id: c.id, picker: c.picker }];
    case "add-line":
      if (s.status !== "open") throw new PickError("NOT_OPEN");
      return [{ type: "PickListLineAdded", sku: c.sku, qty: c.qty }];
    case "complete":
      if (s.status !== "open") throw new PickError("NOT_OPEN");
      return [{ type: "PickListCompleted", at: c.at }];
    default: { const _n: never = c; throw new PickError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";
export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<PickListEvent>; revision: bigint | null }>;
  appendToStream(s: string, events: ReadonlyArray<PickListEvent>, opts: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

// Read-side projection shape — intentionally different from PickListState.
export interface PickListRow { readonly id: string; readonly picker: string; readonly open: boolean; readonly lineCount: number; }
export interface ReadStore { find(id: string): Promise<PickListRow | null>; }

export async function handleCommand(stream: string, cmd: PickListCommand, store: EventStore): Promise<bigint> {
  const slice = await store.readStream(stream);
  const state = slice.events.reduce(evolve, initialState);
  const events = decide(cmd, state);
  if (events.length === 0) return slice.revision ?? -1n;
  return store.appendToStream(stream, events, { expectedRevision: slice.revision ?? "no_stream" });
}

export async function queryView(id: string, read: ReadStore): Promise<PickListRow | null> {
  return read.find(id);
}
