      invoke: {
        src: 'push',
        input: ({ context }) => ({ n: context.attempts }),
        onDone: { target: 'synced', actions: 'clear' },
        onError: [
          { guard: 'hitCap', target: 'failed', actions: 'setError' },
          { target: 'retrying', actions: ['bump', 'setError'] }
        ]
      }
    },
    retrying: {
      on: {
        RETRY: [{ guard: 'canRetry', target: 'uploading' }, { target: 'failed' }]
      }
    },
    failed: {
      on: { ACK: { target: 'synced', actions: 'clear' } }
