`ZodSchema<T>` flows the inferred type to the return. `parse` throws a `ZodError` on mismatch — the caller can catch it and inspect `err.issues` for field-level detail. Use `safeParse` if the caller prefers discriminated-union handling.

```typescript
export type DataReleaseState =
  | { status: "none" }
  | { status: "prepared"; id: string; datasetId: string }
  | { status: "approved"; id: string; datasetId: string; approver: string }
  | { status: "embargoed"; id: string; until: string }
  | { status: "published"; id: string; publishedAt: string };

export type DataReleaseCommand =
  | { type: "prepare"; id: string; datasetId: string }
  | { type: "approve"; approver: string }
  | { type: "embargo"; until: string }
  | { type: "publish"; at: string };

export type DataReleaseEvent =
  | { type: "DataReleasePrepared"; id: string; datasetId: string }
  | { type: "DataReleaseApproved"; approver: string }
  | { type: "DataReleaseEmbargoed"; until: string }
  | { type: "DataReleasePublished"; at: string };

export class InvariantError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "InvariantError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const dataReleaseDecider: Decider<DataReleaseCommand, DataReleaseEvent, DataReleaseState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "prepare":
        if (state.status !== "none") throw new InvariantError("EXISTS");
        return [{ type: "DataReleasePrepared", id: command.id, datasetId: command.datasetId }];
      case "approve":
        if (state.status !== "prepared") throw new InvariantError("NOT_PREPARED");
        return [{ type: "DataReleaseApproved", approver: command.approver }];
      case "embargo":
        if (state.status !== "approved") throw new InvariantError("NOT_APPROVED");
        return [{ type: "DataReleaseEmbargoed", until: command.until }];
      case "publish":
        if (state.status === "embargoed") throw new InvariantError("UNDER_EMBARGO");
        if (state.status !== "approved") throw new InvariantError("NOT_APPROVED");
        return [{ type: "DataReleasePublished", at: command.at }];
      default: {
        const _n: never = command;
        throw new InvariantError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DataReleasePrepared":
        return { status: "prepared", id: event.id, datasetId: event.datasetId };
      case "DataReleaseApproved":
        if (state.status !== "prepared") return state;
        return { status: "approved", id: state.id, datasetId: state.datasetId, approver: event.approver };
      case "DataReleaseEmbargoed":
        if (state.status !== "approved") return state;
        return { status: "embargoed", id: state.id, until: event.until };
      case "DataReleasePublished":
        if (state.status !== "approved") return state;
        return { status: "published", id: state.id, publishedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

```typescript
export type GuestCheckState =
  | { status: "none" }
  | { status: "open"; id: string; seen: ReadonlyArray<string> };

export type GuestCheckCommand =
  | { type: "openCheck"; id: string; idempotencyKey: string }
  | { type: "pay"; idempotencyKey: string; at: string };

export type GuestCheckEvent =
  | { type: "CheckOpened"; id: string; idempotencyKey: string }
  | { type: "CheckPaid"; at: string; idempotencyKey: string };

const initial: GuestCheckState = { status: "none" };

function evolve(s: GuestCheckState, e: GuestCheckEvent): GuestCheckState {
  switch (e.type) {
    case "CheckOpened":
      return { status: "open", id: e.id, seen: [e.idempotencyKey] };
    case "CheckPaid":
      return s.status === "open" ? { ...s, seen: [...s.seen, e.idempotencyKey] } : s;
    default: { const _n: never = e; return s; }
  }
}

export class DomainError extends Error { constructor(m: string) { super(m); this.name = "DomainError"; } }

function decide(c: GuestCheckCommand, s: GuestCheckState): GuestCheckEvent[] {
  if (s.status === "open" && s.seen.includes(c.idempotencyKey)) return [];
  switch (c.type) {
    case "openCheck":
      if (s.status !== "none") throw new DomainError("ALREADY_OPEN");
      return [{ type: "CheckOpened", id: c.id, idempotencyKey: c.idempotencyKey }];
    case "pay":
      if (s.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "CheckPaid", at: c.at, idempotencyKey: c.idempotencyKey }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(s: string): AsyncIterable<{ revision: bigint; event: GuestCheckEvent }>;
  appendToStream(s: string, ev: GuestCheckEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export async function handleGuestCheck(
  cmd: GuestCheckCommand,
  ctx: { streamName: string; eventStore: EventStore }
): Promise<void> {
  let state = initial;
  let rev: bigint | "no_stream" = "no_stream";
  for await (const { revision, event } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  const events = decide(cmd, state);
  if (events.length === 0) return;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: rev });
}
