v5 replaces v4's `cancel` action with a typed `cancel(id)` and schedules sends with `sendTo(..., { id, delay })` or `raise(..., { id, delay })`. When the user answers early, the transition lists `cancel('autoSubmit')` as an action so the delayed event is invalidated before it fires.

```typescript
import { setup, assign, raise, cancel } from 'xstate';

interface Ctx { answer: string | null }

type Ev = { type: 'ANSWER'; value: string } | { type: 'AUTO_SUBMIT' } | { type: 'START' };

export const cancellableQuizTimerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'cancellableQuiz',
  context: { answer: null },
  initial: 'idle',
  states: {
    idle: { on: { START: 'ticking' } },
    ticking: {
      entry: raise({ type: 'AUTO_SUBMIT' }, { id: 'autoSubmit', delay: 15_000 }),
      on: {
        ANSWER: {
          target: 'submitted',
          actions: [cancel('autoSubmit'), assign({ answer: ({ event }) => event.value })]
        },
        AUTO_SUBMIT: 'timedOut'
      }
    },
    submitted: { type: 'final' },
    timedOut: { type: 'final' }
  }
});
```

The handler is infrastructure: it loads the stream, calls the pure `decide`, and appends. The domain logic lives in `decide` / `evolve` only.

```typescript
export interface BidderState {
  readonly id: string;
  readonly balanceCents: number;
  readonly suspended: boolean;
}

export const initialBidder: BidderState = { id: "", balanceCents: 0, suspended: false };

export type BidderCommand =
  | { type: "register"; id: string; openingBalanceCents: number }
  | { type: "placeBid"; amountCents: number };

export type BidderEvent =
  | { type: "BidderRegistered"; id: string; openingBalanceCents: number }
  | { type: "BidderBidPlaced"; amountCents: number };

export function decide(cmd: BidderCommand, state: BidderState): BidderEvent[] {
  switch (cmd.type) {
    case "register":
      if (state.id !== "") throw new Error("ALREADY_REGISTERED");
      return [{ type: "BidderRegistered", id: cmd.id, openingBalanceCents: cmd.openingBalanceCents }];
    case "placeBid":
      if (state.id === "") throw new Error("NOT_REGISTERED");
      if (state.suspended) throw new Error("SUSPENDED");
      if (cmd.amountCents > state.balanceCents) throw new Error("INSUFFICIENT_FUNDS");
      return [{ type: "BidderBidPlaced", amountCents: cmd.amountCents }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export function evolve(state: BidderState, event: BidderEvent): BidderState {
  switch (event.type) {
    case "BidderRegistered":
      return { id: event.id, balanceCents: event.openingBalanceCents, suspended: false };
    case "BidderBidPlaced":
      return { ...state, balanceCents: state.balanceCents - event.amountCents };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<{ revision: bigint; event: BidderEvent }>>;
  appendToStream(s: string, events: readonly BidderEvent[], o: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handle(store: EventStore, stream: string, cmd: BidderCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<BidderState>((s, { event }) => evolve(s, event), initialBidder);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, decide(cmd, state), { expectedRevision: expected });
}
