export const CURRENT_VERSION = 2 as const;

export interface Snapshot<S> { readonly version: number; readonly state: S; }

interface ManuscriptV1 { id: string; chapters: string[]; }
export interface ManuscriptCurrent {
  readonly id: string;
  readonly chapters: ReadonlyArray<string>;
  readonly locked: boolean;
  readonly lockedAt: string | null;
}

function v1Tov2(s: ManuscriptV1): ManuscriptCurrent {
  return { id: s.id, chapters: s.chapters, locked: false, lockedAt: null };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<ManuscriptCurrent> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as ManuscriptV1); version = 2; }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED:${version}`);
  return { version: CURRENT_VERSION, state: state as ManuscriptCurrent };
}

export interface SnapshotStore {
  read(key: string): Promise<Snapshot<unknown> | null>;
  write(key: string, snap: Snapshot<ManuscriptCurrent>): Promise<void>;
}

export async function loadManuscriptSnapshot(store: SnapshotStore, key: string): Promise<ManuscriptCurrent | null> {
  const raw = await store.read(key);
  if (!raw) return null;
  return upgradeSnapshot(raw).state;
}
