import { setup, assign, fromCallback } from 'xstate';

interface File { readonly name: string; readonly bytes: number }
interface Ctx { readonly file: File | null; readonly progress: number; readonly error: string | null; readonly url: string | null }
type Ev =
  | { type: 'UPLOAD'; file: File }
  | { type: 'PROGRESS'; pct: number }
  | { type: 'DONE'; url: string }
  | { type: 'FAIL'; reason: string }
  | { type: 'RESET' };

export const compressor = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    transcode: fromCallback<Ev, { file: File }>(({ sendBack }) => {
      let pct = 0;
      const h = setInterval(() => {
        pct += 10;
        if (pct >= 100) {
          sendBack({ type: 'DONE', url: 'blob://result' });
          clearInterval(h);
        } else {
          sendBack({ type: 'PROGRESS', pct });
        }
      }, 200);
      return () => clearInterval(h);
    })
  }
}).createMachine({
  id: 'compress',
  initial: 'idle',
  context: { file: null, progress: 0, error: null, url: null },
  states: {
    idle: {
      on: { UPLOAD: { target: 'transcoding', actions: assign({ file: ({ event }) => event.file, progress: () => 0 }) } }
    },
    transcoding: {
      invoke: { src: 'transcode', input: ({ context }) => ({ file: context.file as File }) },
      on: {
        PROGRESS: { actions: assign({ progress: ({ event }) => event.pct }) },
        DONE: { target: 'ready', actions: assign({ url: ({ event }) => event.url }) },
        FAIL: { target: 'failed', actions: assign({ error: ({ event }) => event.reason }) }
      }
    },
    ready: { on: { RESET: 'idle' } },
    failed: { on: { RESET: 'idle' } }
  }
});
