export type RestaurantDomainEvent =
  | { type: "RestaurantOpened"; id: string; at: string }
  | { type: "GuestsSeated"; id: string; count: number }
  | { type: "RestaurantClosed"; id: string; at: string }
  | { type: "RestaurantAudited"; id: string; auditor: string };

export type IntegrationEvent = Readonly<{
  schema: string;
  payload: Readonly<Record<string, unknown>>;
}>;

export function translate(event: RestaurantDomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "RestaurantOpened":
      return { schema: "restaurant.opened.v1", payload: { restaurantId: event.id, at: event.at } };
    case "GuestsSeated":
      return { schema: "restaurant.guests_seated.v1", payload: { restaurantId: event.id, count: event.count } };
    case "RestaurantClosed":
      return { schema: "restaurant.closed.v1", payload: { restaurantId: event.id, at: event.at } };
    case "RestaurantAudited":
      // Internal audit trail — do not publish.
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

// Publish each translated integration event via an outbox-backed projection.
export interface OutboxSink {
  enqueue(row: IntegrationEvent): Promise<void>;
}

export async function project(
  events: AsyncIterable<RestaurantDomainEvent>,
  sink: OutboxSink
): Promise<void> {
  for await (const ev of events) {
    const out = translate(ev);
    if (out !== null) await sink.enqueue(out);
  }
}
