```typescript
import { setup, assign } from 'xstate';

type Selection = readonly string[];
type Ctx = { selection: Selection; history: readonly Selection[]; future: readonly Selection[] };
type Ev =
  | { type: 'SELECT'; id: string }
  | { type: 'DESELECT'; id: string }
  | { type: 'RANGE_SELECT'; ids: readonly string[] }
  | { type: 'UNDO' }
  | { type: 'REDO' };

export const multiSelect = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasHistory: ({ context }) => context.history.length > 0,
    hasFuture: ({ context }) => context.future.length > 0
  },
  actions: {
    select: assign(({ context, event }) => {
      if (event.type !== 'SELECT') return context;
      if (context.selection.includes(event.id)) return context;
      return {
        history: [...context.history, context.selection],
        selection: [...context.selection, event.id],
        future: []
      };
    }),
    deselect: assign(({ context, event }) => {
      if (event.type !== 'DESELECT') return context;
      return {
        history: [...context.history, context.selection],
        selection: context.selection.filter((i) => i !== event.id),
        future: []
      };
    }),
    rangeSelect: assign(({ context, event }) => {
      if (event.type !== 'RANGE_SELECT') return context;
      return {
        history: [...context.history, context.selection],
        selection: event.ids,
        future: []
      };
    }),
    undo: assign(({ context }) => {
      const prev = context.history[context.history.length - 1];
      if (prev === undefined) return context;
      return {
        history: context.history.slice(0, -1),
        selection: prev,
        future: [context.selection, ...context.future]
      };
    }),
    redo: assign(({ context }) => {
      const next = context.future[0];
      if (next === undefined) return context;
      return {
        history: [...context.history, context.selection],
        selection: next,
        future: context.future.slice(1)
      };
    })
  }
}).createMachine({
  id: 'multiSelect',
  initial: 'idle',
  context: { selection: [], history: [], future: [] },
  states: {
    idle: {
      on: {
        SELECT: { actions: 'select' },
        DESELECT: { actions: 'deselect' },
        RANGE_SELECT: { actions: 'rangeSelect' },
        UNDO: { guard: 'hasHistory', actions: 'undo' },
        REDO: { guard: 'hasFuture', actions: 'redo' }
      }
    }
  }
});
