export interface CurrentSculptureState {
  readonly id: string;
  readonly title: string;
  readonly hall: string | null;
  readonly status: "received" | "cleaned" | "displayed" | "deaccessioned";
}

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3;

interface V1 { id: string; title: string; }
interface V2 { id: string; title: string; status: string; }

function v1Tov2(snap: Snapshot<V1>): Snapshot<V2> {
  return { version: 2, state: { ...snap.state, status: "received" } };
}

function toStatus(input: string): CurrentSculptureState["status"] {
  switch (input) {
    case "cleaned":
    case "displayed":
    case "deaccessioned":
      return input;
    default:
      return "received";
  }
}

function v2Tov3(snap: Snapshot<V2>): Snapshot<CurrentSculptureState> {
  return {
    version: 3,
    state: { id: snap.state.id, title: snap.state.title, hall: null, status: toStatus(snap.state.status) },
  };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentSculptureState> {
  let working: Snapshot<unknown> = raw;
  if (working.version === 1) working = v1Tov2(working as Snapshot<V1>);
  if (working.version === 2) working = v2Tov3(working as Snapshot<V2>);
  if (working.version !== CURRENT_VERSION) {
    throw new Error(`Cannot upgrade Sculpture snapshot from v${raw.version}`);
  }
  return working as Snapshot<CurrentSculptureState>;
}
