export type InspectionState = Readonly<{
  id: string;
  unitId: string;
  score: number;
  status: "scheduled" | "completed";
}>;

export type InspectionEvent =
  | { type: "InspectionScheduled"; id: string; unitId: string }
  | { type: "InspectionCompleted"; score: number };

export function when(
  current: Partial<InspectionState>,
  event: InspectionEvent,
): Partial<InspectionState> {
  switch (event.type) {
    case "InspectionScheduled":
      return { id: event.id, unitId: event.unitId, score: 0, status: "scheduled" };
    case "InspectionCompleted":
      return { ...current, score: event.score, status: "completed" };
    default: {
      const _never: never = event;
      return current;
    }
  }
}

export function aggregateStream<A, E>(
  events: E[],
  fold: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const state = events.reduce<Partial<A>>(fold, {});
  if (!check(state)) throw new Error("INVALID_STATE");
  return state;
}

function isInspection(s: Partial<InspectionState>): s is InspectionState {
  return !!s.id && !!s.unitId && typeof s.score === "number" && s.status !== undefined;
}

export function loadInspection(events: InspectionEvent[]): InspectionState {
  return aggregateStream<InspectionState, InspectionEvent>(events, when, isInspection);
}
