```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

```typescript
export type RestaurantState =
  | { status: "none" }
  | { status: "open"; id: string }
  | { status: "closed"; id: string };

export type RestaurantCommand =
  | { type: "openRestaurant"; id: string; at: string }
  | { type: "closeRestaurant"; at: string };

export type RestaurantEvent =
  | { type: "RestaurantOpened"; id: string; at: string }
  | { type: "RestaurantClosed"; at: string };

const initial: RestaurantState = { status: "none" };

function evolve(s: RestaurantState, e: RestaurantEvent): RestaurantState {
  switch (e.type) {
    case "RestaurantOpened": return { status: "open", id: e.id };
    case "RestaurantClosed":
      return s.status === "open" ? { status: "closed", id: s.id } : s;
    default: { const _n: never = e; return s; }
  }
}

export class DomainError extends Error { constructor(msg: string) { super(msg); this.name = "DomainError"; } }

function decide(c: RestaurantCommand, s: RestaurantState): RestaurantEvent[] {
  switch (c.type) {
    case "openRestaurant":
      if (s.status === "open") throw new DomainError("ALREADY_OPEN");
      return [{ type: "RestaurantOpened", id: c.id, at: c.at }];
    case "closeRestaurant":
      if (s.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "RestaurantClosed", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export interface StoredEvent { readonly revision: bigint; readonly event: RestaurantEvent }

export interface EventStore {
  readStream(stream: string): AsyncIterable<StoredEvent>;
  appendToStream(stream: string, events: RestaurantEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export async function handle(
  command: RestaurantCommand,
  ctx: { streamName: string; eventStore: EventStore }
): Promise<void> {
  let state = initial;
  let revision: bigint | "no_stream" = "no_stream";
  for await (const { revision: r, event } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    revision = r;
  }
  const events = decide(command, state);
  if (events.length === 0) return;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: revision });
}
