export type CampaignEvent =
  | { type: "CampaignLaunched"; id: string; name: string }
  | { type: "ImpressionRecorded"; id: string; count: number };

export interface EventEnvelope { readonly revision: bigint; readonly event: CampaignEvent; }

export interface EventStoreIterator {
  readForward(from: bigint, batchSize: number): Promise<EventEnvelope[]>;
}

export interface CampaignRow { readonly name: string; readonly impressions: number; }
export type CampaignView = Readonly<Record<string, CampaignRow>>;

export const emptyView: CampaignView = {};

export function project(view: CampaignView, event: CampaignEvent): CampaignView {
  switch (event.type) {
    case "CampaignLaunched":
      return { ...view, [event.id]: { name: event.name, impressions: 0 } };
    case "ImpressionRecorded": {
      const row = view[event.id];
      if (!row) return view;
      return { ...view, [event.id]: { ...row, impressions: row.impressions + event.count } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface RebuildOptions {
  readonly from: bigint;
  readonly batchSize: number;
  readonly store: EventStoreIterator;
  readonly persist: (view: CampaignView, cursor: bigint) => Promise<void>;
  readonly onProgress?: (cursor: bigint, processed: number) => void;
}

export async function rebuild(opts: RebuildOptions): Promise<void> {
  let cursor = opts.from;
  let view: CampaignView = emptyView;
  let processed = 0;
  for (;;) {
    const batch = await opts.store.readForward(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const env of batch) {
      view = project(view, env.event);
      cursor = env.revision;
      processed += 1;
    }
    await opts.persist(view, cursor);
    opts.onProgress?.(cursor, processed);
  }
}

