    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: NotebookCommand, state: NotebookState): NotebookEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "NotebookCreated", id: command.id, owner: command.owner }];
    case "publish":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "NotebookPublished", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export type NotebookView = { id: string; owner: string; published: boolean };
export interface ReadStore { get(id: string): Promise<NotebookView | null>; }

export async function handleCommand(
  command: NotebookCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream<NotebookEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
}

export async function queryView(id: string, store: ReadStore): Promise<NotebookView | null> {
  return store.get(id);
}
```

Declare the child with its own `setup().createMachine` (including a `types.output` and a final state's `output`), register it in the parent's `setup.actors`, then invoke with typed `input` and read `event.output` on `onDone`.

```typescript
import { setup, assign } from 'xstate';

const wizardChild = setup({
  types: {
    context: {} as { step: number },
    events: {} as { type: 'NEXT' },
    input: {} as { initialStep: number },
    output: {} as { finalStep: number }
  }
}).createMachine({
  id: 'child',
  context: ({ input }) => ({ step: input.initialStep }),
  initial: 'going',
  states: {
    going: {
      on: {
        NEXT: [
          { target: 'done', guard: ({ context }) => context.step >= 2 },
          { actions: assign({ step: ({ context }) => context.step + 1 }) }
        ]
      }
    },
    done: { type: 'final' }
  },
  output: ({ context }) => ({ finalStep: context.step })
});

export const parentMachine = setup({
  types: { context: {} as { last: number } },
  actors: { wizard: wizardChild }
}).createMachine({
  id: 'parent',
  context: { last: -1 },
  initial: 'running',
  states: {
    running: {
      invoke: {
        src: 'wizard',
        input: { initialStep: 0 },
        onDone: { target: 'done', actions: assign({ last: ({ event }) => event.output.finalStep }) }
      }
    },
    done: { type: 'final' }
  }
});
```

```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

