Load current revision, decide, then append with expectedRevision set to the observed revision. Convert the store's mismatch signal into a typed error at the boundary.

```typescript
export type PullRequestEvent = { type: "PullRequestOpened" | "PullRequestMerged"; data: Record<string, string> };

export interface EventStore {
  readStream(stream: string): Promise<{ events: PullRequestEvent[]; revision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: PullRequestEvent[],
    opts: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextRevision: bigint; conflict: boolean }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string) {
    super(`concurrency conflict on ${streamName}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendWithOcc(
  store: EventStore,
  streamName: string,
  decideFn: (events: PullRequestEvent[]) => PullRequestEvent[],
): Promise<bigint> {
  const loaded = await store.readStream(streamName);
  const newEvents = decideFn(loaded.events);
  const result = await store.appendToStream(streamName, newEvents, { expectedRevision: loaded.revision });
  if (result.conflict) throw new ConcurrencyConflict(streamName);
  return result.nextRevision;
}
```

```typescript
import { Effect } from "effect";

export type FarmState =
  | { status: "none" }
  | { status: "operating"; id: string; owner: string }
  | { status: "decommissioned"; id: string };

export type FarmCommand =
  | { type: "register"; id: string; owner: string }
  | { type: "decommission"; at: string };

export type FarmEvent =
  | { type: "FarmRegistered"; id: string; owner: string }
  | { type: "FarmDecommissioned"; at: string };

export const initialState: FarmState = { status: "none" };

export function evolve(state: FarmState, event: FarmEvent): FarmState {
  switch (event.type) {
    case "FarmRegistered":
      return { status: "operating", id: event.id, owner: event.owner };
    case "FarmDecommissioned":
      if (state.status !== "operating") return state;
      return { status: "decommissioned", id: state.id };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(command: FarmCommand, state: FarmState): FarmEvent[] {
  switch (command.type) {
    case "register":
      if (state.status !== "none") throw new Error("FARM_EXISTS");
      return [{ type: "FarmRegistered", id: command.id, owner: command.owner }];
    case "decommission":
      if (state.status !== "operating") throw new Error("NOT_OPERATING");
      return [{ type: "FarmDecommissioned", at: command.at }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: E }>>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export interface CommandHandler<C> {
  handle(command: C, ctx: { streamName: string; store: EventStore<FarmEvent> }): Effect.Effect<void, Error>;
}

export const farmCommandHandler: CommandHandler<FarmCommand> = {
  handle(command, ctx) {
    return Effect.gen(function* () {
      const stored = yield* Effect.tryPromise(() => ctx.store.readStream(ctx.streamName));
      const state = stored.reduce<FarmState>((s, r) => evolve(s, r.event), initialState);
      const events = decide(command, state);
      const expected: bigint | "no_stream" =
        stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
      yield* Effect.tryPromise(() =>
        ctx.store.appendToStream(ctx.streamName, events, { expectedRevision: expected })
      );
    });
  },
};
```

