aggregateStream is a generic async fold with two type parameters. when is the pure reducer. Keep `when` small and put all branching inside it; the helper just moves the loop plumbing out of the aggregate.

```typescript
export type BLEvent =
  | { type: "CheckedOut"; id: string; patron: string }
  | { type: "Returned"; on: string };

export type BLState = { id: string; patron: string; returned: boolean };
export const initialBL: BLState = { id: "", patron: "", returned: false };

export function when(state: BLState, event: BLEvent): BLState {
  switch (event.type) {
    case "CheckedOut":
      return { id: event.id, patron: event.patron, returned: false };
    case "Returned":
      return { ...state, returned: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = fold(state, event);
  }
  return state;
}

export async function loadLoan(stream: AsyncIterable<BLEvent>): Promise<BLState> {
  return aggregateStream<BLState, BLEvent>(stream, when, initialBL);
}
