export type ElectionRollEvent =
  | { type: "ElectionRollOpened"; id: string }
  | { type: "VoterAdded"; voterId: string }
  | { type: "VoterRemoved"; voterId: string }
  | { type: "ElectionRollClosed" };

export type ElectionRoll = {
  id: string;
  voters: number;
  closed: boolean;
};

export function when(current: Partial<ElectionRoll>, event: ElectionRollEvent): Partial<ElectionRoll> {
  switch (event.type) {
    case "ElectionRollOpened":
      return { id: event.id, voters: 0, closed: false };
    case "VoterAdded":
      return { ...current, voters: (current.voters ?? 0) + 1 };
    case "VoterRemoved":
      return { ...current, voters: Math.max(0, (current.voters ?? 0) - 1) };
    case "ElectionRollClosed":
      return { ...current, closed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function aggregate(events: ElectionRollEvent[]): Partial<ElectionRoll> {
  return events.reduce<Partial<ElectionRoll>>(when, {});
}
