```typescript
export interface RunEvent { type: string; data: unknown; }

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult {
  readonly ok: boolean;
  readonly conflict?: { actual: bigint | "no_stream"; expected: ExpectedRevision };
  readonly nextRevision?: bigint;
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: RunEvent; revision: bigint }>;
  appendToStream(stream: string, events: RunEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(readonly stream: string, readonly expected: ExpectedRevision, readonly actual: bigint | "no_stream") {
    super(`CONFLICT ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendRun(store: EventStore, stream: string, events: RunEvent[]): Promise<bigint> {
  let expected: ExpectedRevision = "no_stream";
  for await (const entry of store.readStream(stream)) {
    expected = entry.revision;
  }
  const result = await store.appendToStream(stream, events, { expectedRevision: expected });
  if (!result.ok || result.conflict) {
    const conflict = result.conflict ?? { actual: "no_stream" as const, expected };
    throw new ConcurrencyConflict(stream, expected, conflict.actual);
  }
  if (result.nextRevision === undefined) throw new Error("NO_REVISION");
  return result.nextRevision;
}
```

