type SurveyEvent = { type: 'SurveyStarted'; surveyor: string } | { type: 'SurveyClosed'; at: string };

interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: SurveyEvent; revision: bigint }>;
  appendToStream(
    stream: string,
    events: SurveyEvent[],
    opts: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {}

export async function appendWithRevision(
  store: EventStore,
  stream: string,
  toAppend: SurveyEvent[],
): Promise<bigint> {
  let expected: bigint | 'no_stream' = 'no_stream';
  for await (const { revision } of store.readStream(stream)) {
    expected = revision;
  }
  try {
    const res = await store.appendToStream(stream, toAppend, { expectedRevision: expected });
    return res.nextRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes('WrongExpectedVersion')) {
      throw new ConcurrencyConflict(err.message);
    }
    throw err;
  }
}
