```typescript
export type QuoteState = { status: "none" } | { status: "prepared"; id: string; total: number };
export type QuoteCommand = { type: "prepare"; id: string; total: number };
export type QuoteEvent = { type: "QuotePrepared"; id: string; total: number };

const initial: QuoteState = { status: "none" };

function decide(c: QuoteCommand, s: QuoteState): QuoteEvent[] {
  switch (c.type) {
    case "prepare":
      if (s.status !== "none") throw new Error("EXISTS");
      if (c.total <= 0) throw new Error("TOTAL");
      return [{ type: "QuotePrepared", id: c.id, total: c.total }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

function evolve(s: QuoteState, e: QuoteEvent): QuoteState {
  switch (e.type) {
    case "QuotePrepared":
      return { status: "prepared", id: e.id, total: e.total };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    s: string, e: readonly E[], o: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export async function handle(
  command: QuoteCommand,
  ctx: { streamName: string; eventStore: EventStore<QuoteEvent> },
): Promise<void> {
  let state = initial;
  let rev: bigint | "no_stream" = "no_stream";
  for await (const rec of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, rec.event);
    rev = rec.revision;
  }
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: rev });
}
