export type CurationEvent =
  | { type: "CurationProposed"; id: string; curator: string }
  | { type: "CurationApproved"; by: string }
  | { type: "CurationRetracted"; reason: string };

export type CurationState =
  | { status: "none" }
  | { status: "proposed"; id: string; curator: string }
  | { status: "approved"; id: string; by: string };

const initial: CurationState = { status: "none" };

export function evolve(state: CurationState, event: CurationEvent): CurationState {
  switch (event.type) {
    case "CurationProposed":
      return { status: "proposed", id: event.id, curator: event.curator };
    case "CurationApproved":
      if (state.status !== "proposed") return state;
      return { status: "approved", id: state.id, by: event.by };
    case "CurationRetracted":
      if (state.status !== "proposed") return state;
      return { status: "none" };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  step: (state: S, event: E) => S,
  initialState: S
): Promise<S> {
  let state = initialState;
  for await (const event of stream) state = step(state, event);
  return state;
}

export const loadCuration = (stream: AsyncIterable<CurationEvent>): Promise<CurationState> =>
  aggregateStream(stream, evolve, initial);
```

evolve reconstructs one aggregate's state from its own events and is used on the write side.  A projection folds a subset of events across aggregates into a denormalised, query-friendly view on the read side; it should ignore events it does not care about by returning the view unchanged.  The example keeps a per-title subscriber count.

```typescript
export type PeriodicalProjectionEvent =
  | { type: "PeriodicalRegistered"; titleId: string; name: string }
  | { type: "SubscriberJoined"; titleId: string; subscriberId: string }
  | { type: "SubscriberLeft"; titleId: string; subscriberId: string }
  | { type: "IssuePublished"; titleId: string; issueId: string };

export type PeriodicalSubscribersView = Readonly<{
  titles: Record<string, { name: string; subscribers: number }>;
}>;

export const emptyView: PeriodicalSubscribersView = { titles: {} };

export function project(
  view: PeriodicalSubscribersView,
  event: PeriodicalProjectionEvent,
): PeriodicalSubscribersView {
  switch (event.type) {
    case "PeriodicalRegistered":
      return { titles: { ...view.titles, [event.titleId]: { name: event.name, subscribers: 0 } } };
    case "SubscriberJoined": {
      const row = view.titles[event.titleId] ?? { name: "", subscribers: 0 };
      return { titles: { ...view.titles, [event.titleId]: { ...row, subscribers: row.subscribers + 1 } } };
    }
    case "SubscriberLeft": {
      const row = view.titles[event.titleId];
      if (!row) return view;
      const next = Math.max(0, row.subscribers - 1);
      return { titles: { ...view.titles, [event.titleId]: { ...row, subscribers: next } } };
    }
    case "IssuePublished":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
