      return [{ type: "LegCompleted", at: command.at }];
    case "abort":
      if (state.status === "completed") throw new LegError("ALREADY_COMPLETED");
      if (state.status === "aborted") return [];
      return [{ type: "LegAborted", reason: command.reason }];
    default: { const _n: never = command; throw new LegError("UNKNOWN"); }
