  switch (event.type) {
    case "LegCompleted":
      if (state.status !== "scheduled") return state;
      return { status: "completed", id: state.id, at: event.at };
    case "LegAborted":
      if (state.status === "completed") return state;
      return { status: "aborted", id: state.id, reason: event.reason };
    default: { const _n: never = event; return state; }
  }
