```typescript
export type SagaState =
  | { status: "waiting" }
  | { status: "shippedPending"; shipmentId: string }
  | { status: "invoiced"; shipmentId: string; invoiceId: string }
  | { status: "failed"; reason: string };

export type IncomingEvent =
  | { type: "ShipmentDispatched"; shipmentId: string }
  | { type: "InvoiceIssued"; shipmentId: string; invoiceId: string }
  | { type: "InvoiceFailed"; shipmentId: string; reason: string };

export type OutgoingCommand =
  | { type: "CreateInvoice"; shipmentId: string }
  | { type: "MarkShipmentInvoiced"; shipmentId: string; invoiceId: string }
  | { type: "EscalateFailure"; shipmentId: string; reason: string };

export type SagaStep = {
  nextState: SagaState;
  command: OutgoingCommand | null;
};

export const initialState: SagaState = { status: "waiting" };

export function step(state: SagaState, event: IncomingEvent): SagaStep {
  switch (event.type) {
    case "ShipmentDispatched":
      if (state.status !== "waiting") return { nextState: state, command: null };
      return {
        nextState: { status: "shippedPending", shipmentId: event.shipmentId },
        command: { type: "CreateInvoice", shipmentId: event.shipmentId },
      };
    case "InvoiceIssued":
      if (state.status !== "shippedPending") return { nextState: state, command: null };
      return {
        nextState: { status: "invoiced", shipmentId: state.shipmentId, invoiceId: event.invoiceId },
        command: { type: "MarkShipmentInvoiced", shipmentId: state.shipmentId, invoiceId: event.invoiceId },
      };
    case "InvoiceFailed":
      if (state.status !== "shippedPending") return { nextState: state, command: null };
      return {
        nextState: { status: "failed", reason: event.reason },
        command: { type: "EscalateFailure", shipmentId: state.shipmentId, reason: event.reason },
      };
    default: {
      const _n: never = event;
      return { nextState: state, command: null };
    }
  }
}

export function evolve(state: SagaState, event: IncomingEvent): SagaState {
  return step(state, event).nextState;
}

export function aggregate(events: IncomingEvent[]): SagaState {
  return events.reduce(evolve, initialState);
}
