export type ProductionLineState =
  | { status: "none" }
  | { status: "idle"; id: string; capacity: number }
  | { status: "running"; id: string; capacity: number; startedAt: string }
  | { status: "decommissioned"; id: string };

export type ProductionLineCommand =
  | { type: "commission"; id: string; capacity: number }
  | { type: "start"; at: string }
  | { type: "stop"; at: string }
  | { type: "decommission" };

export type ProductionLineEvent =
  | { type: "LineCommissioned"; id: string; capacity: number }
  | { type: "LineStarted"; at: string }
  | { type: "LineStopped"; at: string }
  | { type: "LineDecommissioned" };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const productionLineDecider: Decider<ProductionLineCommand, ProductionLineEvent, ProductionLineState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "commission":
