export type DocumentEvent =
  | { type: "DocumentCreated"; id: string; title: string }
  | { type: "DocumentApproved"; id: string; at: string };

export interface View {
  readonly total: number;
  readonly approved: number;
}

export const emptyView: View = { total: 0, approved: 0 };

export function project(view: View, event: DocumentEvent): View {
  switch (event.type) {
    case "DocumentCreated": return { ...view, total: view.total + 1 };
    case "DocumentApproved": return { ...view, approved: view.approved + 1 };
    default: { const _n: never = event; return view; }
  }
}

export interface Batch<E> { events: ReadonlyArray<E>; nextCursor: bigint; done: boolean; }
export interface EventStore<E> { readBatch(from: bigint, size: number): Promise<Batch<E>>; }
export interface ReadStore { wipe(): Promise<void>; persist(v: View, cursor: bigint): Promise<void>; }

export interface RebuildOptions {
  from: bigint; batchSize: number;
  store: EventStore<DocumentEvent>;
  readStore: ReadStore;
  onProgress?: (cursor: bigint, total: number) => void;
}

export async function rebuild(opts: RebuildOptions): Promise<void> {
  if (opts.from === 0n) await opts.readStore.wipe();
  let view: View = emptyView;
  let cursor = opts.from;
  for (;;) {
    const batch = await opts.store.readBatch(cursor, opts.batchSize);
    for (const e of batch.events) view = project(view, e);
    cursor = batch.nextCursor;
    await opts.readStore.persist(view, cursor);
    opts.onProgress?.(cursor, view.total);
    if (batch.done) return;
  }
}
