export type CohortRegisterState =
  | { status: "none" }
  | { status: "open"; id: string; members: number }
  | { status: "locked"; id: string; members: number };

export type CohortRegisterCommand =
  | { type: "create"; id: string }
  | { type: "addMember" }
  | { type: "lock" };

export type CohortRegisterEvent =
  | { type: "CohortRegisterCreated"; id: string }
  | { type: "CohortRegisterMemberAdded" }
  | { type: "CohortRegisterLocked" };

const initial: CohortRegisterState = { status: "none" };

function evolve(state: CohortRegisterState, event: CohortRegisterEvent): CohortRegisterState {
  switch (event.type) {
    case "CohortRegisterCreated":
      return { status: "open", id: event.id, members: 0 };
    case "CohortRegisterMemberAdded":
      return state.status === "open" ? { ...state, members: state.members + 1 } : state;
    case "CohortRegisterLocked":
      return state.status === "open" ? { status: "locked", id: state.id, members: state.members } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: CohortRegisterCommand, state: CohortRegisterState): CohortRegisterEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "CohortRegisterCreated", id: command.id }];
    case "addMember":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "CohortRegisterMemberAdded" }];
    case "lock":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "CohortRegisterLocked" }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict";
  constructor(public readonly stream: string) { super(`conflict on ${stream}`); this.name = "ConcurrencyConflict"; }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ ok: boolean }>;
}

export async function handle(
  command: CohortRegisterCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream<CohortRegisterEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  const result = await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
  if (!result.ok) throw new ConcurrencyConflict(ctx.streamName);
}
