export type TableReservationState =
  | { status: "none" }
  | { status: "pending"; id: string; partySize: number }
  | { status: "confirmed"; id: string; partySize: number; tableNo: number }
  | { status: "seated"; id: string; tableNo: number; seatedAt: string }
  | { status: "completed"; id: string; completedAt: string }
  | { status: "cancelled"; id: string; cancelledAt: string };

export type TableReservationCommand =
  | { type: "request"; id: string; partySize: number }
  | { type: "confirm"; tableNo: number }
  | { type: "seat"; at: string }
  | { type: "complete"; at: string }
  | { type: "cancel"; at: string };

export type TableReservationEvent =
  | { type: "ReservationRequested"; id: string; partySize: number }
  | { type: "ReservationConfirmed"; tableNo: number }
  | { type: "ReservationSeated"; at: string }
  | { type: "ReservationCompleted"; at: string }
  | { type: "ReservationCancelled"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const tableReservationDecider: Decider<TableReservationCommand, TableReservationEvent, TableReservationState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "request":
        if (s.status !== "none") throw new DomainError("ALREADY_REQUESTED");
        if (c.partySize <= 0) throw new DomainError("INVALID_PARTY");
        return [{ type: "ReservationRequested", id: c.id, partySize: c.partySize }];
      case "confirm":
        if (s.status !== "pending") throw new DomainError("NOT_PENDING");
        return [{ type: "ReservationConfirmed", tableNo: c.tableNo }];
      case "seat":
        if (s.status !== "confirmed") throw new DomainError("NOT_CONFIRMED");
        return [{ type: "ReservationSeated", at: c.at }];
      case "complete":
        if (s.status !== "seated") throw new DomainError("NOT_SEATED");
        return [{ type: "ReservationCompleted", at: c.at }];
      case "cancel":
        if (s.status === "seated" || s.status === "completed" || s.status === "cancelled")
          throw new DomainError("CANNOT_CANCEL");
        if (s.status === "none") throw new DomainError("NOT_REQUESTED");
        return [{ type: "ReservationCancelled", at: c.at }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ReservationRequested":
        return { status: "pending", id: e.id, partySize: e.partySize };
      case "ReservationConfirmed":
        return s.status === "pending"
          ? { status: "confirmed", id: s.id, partySize: s.partySize, tableNo: e.tableNo }
          : s;
      case "ReservationSeated":
        return s.status === "confirmed"
          ? { status: "seated", id: s.id, tableNo: s.tableNo, seatedAt: e.at }
          : s;
      case "ReservationCompleted":
        return s.status === "seated" ? { status: "completed", id: s.id, completedAt: e.at } : s;
      case "ReservationCancelled":
        return s.status === "pending" || s.status === "confirmed"
          ? { status: "cancelled", id: s.id === undefined ? "" : s.id, cancelledAt: e.at }
          : s;
      default: { const _n: never = e; return s; }
    }
  },
};
