  | { type: "RenewalRequested"; id: string; term: number }
  | { type: "RenewalConfirmed"; at: string }
  | { type: "RenewalDeclined"; reason: string };

export class RenewalError extends Error {
  constructor(code: string) { super(code); this.name = "RenewalError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const renewalDecider: Decider<RenewalCommand, RenewalEvent, RenewalState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "request":
        if (s.status !== "none") throw new RenewalError("EXISTS");
        if (c.term <= 0) throw new RenewalError("TERM_RANGE");
        return [{ type: "RenewalRequested", id: c.id, term: c.term }];
      case "confirm":
        if (s.status === "declined") throw new RenewalError("DECLINED");
        if (s.status !== "requested") throw new RenewalError("NOT_REQUESTED");
        return [{ type: "RenewalConfirmed", at: c.at }];
      case "decline":
        if (s.status === "confirmed") throw new RenewalError("CONFIRMED");
        if (s.status !== "requested") throw new RenewalError("NOT_REQUESTED");
        return [{ type: "RenewalDeclined", reason: c.reason }];
      default: { const _n: never = c; throw new RenewalError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "RenewalRequested":
        return { status: "requested", id: e.id, term: e.term };
      case "RenewalConfirmed":
        if (s.status !== "requested") return s;
        return { status: "confirmed", id: s.id, term: s.term, at: e.at };
      case "RenewalDeclined":
        if (s.status !== "requested") return s;
        return { status: "declined", id: s.id, reason: e.reason };
      default: { const _n: never = e; return s; }
    }
  },
};
