The prior code mutated a shared view object. Below, project takes and returns a fresh view so callers can fold it with reduce or feed it to a subscription loop without aliasing bugs.

```typescript
export type CatalogProjEvent =
  | { type: "TitleAdded"; titleId: string; genre: string }
  | { type: "TitleRemoved"; titleId: string; genre: string }
  | { type: "CatalogPublished" };

export type CatalogProjView = Readonly<{
  titles: Readonly<Record<string, string>>;
  perGenre: Readonly<Record<string, number>>;
}>;

export const emptyView: CatalogProjView = Object.freeze({ titles: {}, perGenre: {} });

function adjust(map: Readonly<Record<string, number>>, key: string, delta: number): Record<string, number> {
  const next = (map[key] ?? 0) + delta;
  if (next <= 0) {
    const { [key]: _drop, ...rest } = map;
    return rest;
  }
  return { ...map, [key]: next };
}

export function project(view: CatalogProjView, event: CatalogProjEvent): CatalogProjView {
  switch (event.type) {
    case "TitleAdded":
      return {
        titles: { ...view.titles, [event.titleId]: event.genre },
        perGenre: adjust(view.perGenre, event.genre, +1),
      };
    case "TitleRemoved": {
      const { [event.titleId]: _drop, ...rest } = view.titles;
      return { titles: rest, perGenre: adjust(view.perGenre, event.genre, -1) };
    }
    case "CatalogPublished":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
