```typescript
interface StoredEvent { readonly type: string; readonly data: unknown }
interface AppendOpts { readonly expectedRevision: bigint | 'no_stream' | 'any' }
interface AppendResult { readonly nextRevision: bigint }

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: StoredEvent; revision: bigint }>;
  appendToStream(s: string, evs: readonly StoredEvent[], opts: AppendOpts): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {}

interface Conflict { readonly kind: 'conflict' }
function isConflict(e: unknown): e is Conflict {
  return typeof e === 'object' && e !== null && (e as { kind?: unknown }).kind === 'conflict';
}

export async function appendBooking(
  store: EventStore,
  stream: string,
  events: readonly StoredEvent[],
): Promise<bigint> {
  let latest: bigint | 'no_stream' = 'no_stream';
  for await (const { revision } of store.readStream(stream)) latest = revision;
  try {
    const res = await store.appendToStream(stream, events, { expectedRevision: latest });
    return res.nextRevision;
  } catch (err) {
    if (isConflict(err)) throw new ConcurrencyConflict('venue booking moved');
    throw err;
  }
}
