export type EvaluationEvent =
  | { type: "EvaluationPassed"; modelId: string; score: number }
  | { type: "EvaluationFailed"; modelId: string; reason: string };

export type LeaderboardView = { leader: string | null; score: number };
const emptyView: LeaderboardView = { leader: null, score: -Infinity };

function project(view: LeaderboardView, event: EvaluationEvent): LeaderboardView {
  switch (event.type) {
    case "EvaluationPassed":
      return event.score > view.score ? { leader: event.modelId, score: event.score } : view;
    case "EvaluationFailed":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed<E> {
  from(pos: bigint): AsyncIterable<{ position: bigint; event: E }>;
}

export interface ViewStore<V> {
  save(v: V): Promise<void>;
}

export async function runSubscription(
  name: string,
  feed: EventFeed<EvaluationEvent>,
  checkpoints: CheckpointStore,
  views: ViewStore<LeaderboardView>,
): Promise<void> {
  const last = (await checkpoints.read(name)) ?? 0n;
  let view = emptyView;
  const iter = feed.from(last);
  for await (const entry of iter) {
    view = project(view, entry.event);
    await views.save(view);
    await checkpoints.write(name, entry.position);
  }
}
