}).createMachine({
  id: 'parAccordion',
  type: 'parallel',
  states: {
    a: {
      initial: 'closed',
      states: {
        closed: { on: { TOGGLE_A: 'open' } },
        open: { on: { TOGGLE_A: 'closed' } }
      }
    },
    b: {
      initial: 'closed',
      states: {
        closed: { on: { TOGGLE_B: 'open' } },
