export type SagaEvent =
  | { type: "IncidentOpened"; id: string; severity: "low" | "high" }
  | { type: "OncallPaged"; incidentId: string }
  | { type: "MitigationStarted"; incidentId: string; runbook: string }
  | { type: "IncidentResolved"; incidentId: string };

export type SagaCommand =
  | { type: "PageOncall"; incidentId: string; severity: "low" | "high" }
  | { type: "StartMitigation"; incidentId: string; runbook: string };

export function react(event: SagaEvent): SagaCommand | null {
  switch (event.type) {
    case "IncidentOpened":
      return { type: "PageOncall", incidentId: event.id, severity: event.severity };
    case "OncallPaged":
      return { type: "StartMitigation", incidentId: event.incidentId, runbook: "default" };
    case "MitigationStarted":
      return null;
    case "IncidentResolved":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export function projection(events: SagaEvent[]): SagaCommand[] {
  const commands: SagaCommand[] = [];
  for (const e of events) {
    const c = react(e);
    if (c) commands.push(c);
  }
  return commands;
}
