`fromCallback` turns an imperative event source (DOM listeners, WebSocket messages, timers) into an actor whose outbound events arrive via `sendBack`. The cleanup function returned by the callback runs automatically when the parent state exits, so there are no leaked listeners.

```typescript
import { setup, fromCallback } from 'xstate';

type Ev = { type: 'RESIZE'; width: number } | { type: 'STOP' };
type ResizeOut = { type: 'RESIZE'; width: number };

const resizeSource = fromCallback<ResizeOut, void>(({ sendBack }) => {
  const onResize = () => sendBack({ type: 'RESIZE', width: window.innerWidth });
  window.addEventListener('resize', onResize);
  return () => window.removeEventListener('resize', onResize);
});

export const virtualList = setup({
  types: { events: {} as Ev },
  actors: { resizeSource }
}).createMachine({
  id: 'virtualList',
  initial: 'watching',
  states: {
    watching: {
      invoke: { src: 'resizeSource' },
      on: {
        RESIZE: 'watching',
        STOP: 'done'
      }
    },
    done: { type: 'final' }
  }
});
```

```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

```typescript
import { Effect } from "effect";

export type CurrentCatalog = {
  id: string;
  name: string;
  titles: ReadonlyArray<string>;
  lastRebuiltAt: string;
};

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 2 as const;

type V1 = Snapshot<{ id: string; name: string; titles: ReadonlyArray<string> }>;
type V2 = Snapshot<CurrentCatalog>;

export class UnsupportedSnapshotVersion extends Error {}

function v1Tov2(snap: V1): V2 {
  return { version: 2, state: { ...snap.state, lastRebuiltAt: "1970-01-01T00:00:00Z" } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentCatalog> {
  let current: Snapshot<unknown> = snap;
  if (current.version === 1) current = v1Tov2(current as V1);
  if (current.version !== CURRENT_VERSION) {
    throw new UnsupportedSnapshotVersion(`unknown version ${current.version}`);
  }
  return current as Snapshot<CurrentCatalog>;
}

export interface SnapshotStore {
  read(streamName: string): Promise<Snapshot<unknown> | null>;
}

export function loadCatalogSnapshot(store: SnapshotStore, streamName: string) {
  return Effect.gen(function* () {
    const raw = yield* Effect.promise(() => store.read(streamName));
    if (raw === null) return null;
    return upgradeSnapshot(raw);
  });
}
