```typescript
export type SlotEvent = { type: "SlotGranted"; airport: string } | { type: "SlotReleased"; airport: string };

export interface View { granted: Record<string, number>; }

export function project(view: View, event: SlotEvent): View {
  switch (event.type) {
    case "SlotGranted": return { granted: { ...view.granted, [event.airport]: (view.granted[event.airport] ?? 0) + 1 } };
    case "SlotReleased": {
      const n = view.granted[event.airport] ?? 0;
      if (n <= 0) return view;
      return { granted: { ...view.granted, [event.airport]: n - 1 } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface StoredEvent { revision: bigint; data: SlotEvent; }

export interface Reader {
  readBatch(from: bigint, size: number): Promise<StoredEvent[]>;
}

export async function rebuild(opts: { from: bigint; batchSize: number; reader: Reader; persist: (v: View, pos: bigint) => Promise<void> }): Promise<void> {
  let cursor = opts.from;
  let view: View = { granted: {} };
  for (;;) {
    const batch = await opts.reader.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const ev of batch) {
      view = project(view, ev.data);
      cursor = ev.revision;
    }
    await opts.persist(view, cursor);
  }
}
```

Crash safety in a subscription means: apply the projection first, then write the checkpoint. If the process dies between, the worst case is re-applying the last event on restart (idempotent by nature, since the projection is deterministic).

```typescript
export type SessionEvent =
  | { type: "VoteCast"; sessionId: string; position: bigint }
  | { type: "Closed"; sessionId: string; position: bigint };

export type Turnout = Record<string, number>;
export const emptyTurnout: Turnout = {};

export function project(view: Turnout, event: SessionEvent): Turnout {
  switch (event.type) {
    case "VoteCast":
      return { ...view, [event.sessionId]: (view[event.sessionId] ?? 0) + 1 };
    case "Closed":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed {
  since(pos: bigint): AsyncIterable<SessionEvent>;
}

export interface ReadStore {
  persist(turnout: Turnout): Promise<void>;
}

export async function runSubscription(
  name: string,
  feed: EventFeed,
  cp: CheckpointStore,
  store: ReadStore,
): Promise<void> {
  const start = (await cp.read(name)) ?? 0n;
  let turnout: Turnout = emptyTurnout;
  for await (const event of feed.since(start)) {
    turnout = project(turnout, event);
    await store.persist(turnout);
    await cp.write(name, event.position);
  }
}
```

```typescript
export type HoldingEvent =
  | { type: "HoldingOpened"; id: string; symbol: string; units: number }
  | { type: "UnitsAdded"; units: number }
  | { type: "UnitsRemoved"; units: number }
  | { type: "HoldingClosed" };

export type HoldingState =
  | { status: "none" }
  | { status: "open"; id: string; symbol: string; units: number }
  | { status: "closed"; id: string };

// `decide` consumes a Command and current state; it validates invariants and
// returns Events. `evolve` consumes one Event and returns the next state. Only
// `evolve` is used when folding a stream; `decide` is used when accepting new
// commands. Both must be pure functions.
export const initialState: HoldingState = { status: "none" };

export function evolve(state: HoldingState, event: HoldingEvent): HoldingState {
  switch (event.type) {
    case "HoldingOpened":
      return { status: "open", id: event.id, symbol: event.symbol, units: event.units };
    case "UnitsAdded":
      if (state.status !== "open") return state;
      return { ...state, units: state.units + event.units };
    case "UnitsRemoved":
      if (state.status !== "open") return state;
      return { ...state, units: state.units - event.units };
    case "HoldingClosed":
      if (state.status !== "open") return state;
      return { status: "closed", id: state.id };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

```

Omit `target` (or target the same node without `reenter: true`) for internal transitions — entry/exit actions do not run again. Set `reenter: true` to fire entry/exit on the same state node.

```typescript
import { setup, assign } from 'xstate';

export const demo = setup({
  types: {
    context: {} as { entries: number; actions: number },
    events: {} as { type: 'BUMP' } | { type: 'RESTART' },
  },
}).createMachine({
  id: 'demo',
  initial: 'active',
  context: { entries: 0, actions: 0 },
  states: {
    active: {
      entry: assign({ entries: ({ context }) => context.entries + 1 }),
      on: {
        BUMP: {
          // internal: entry does NOT run again
          actions: assign({ actions: ({ context }) => context.actions + 1 }),
        },
        RESTART: {
          // external self-transition: entry DOES run again
          target: 'active',
          reenter: true,
        },
      },
    },
  },
});
