```typescript
export type GradeEvent =
  | { type: "GradeRecorded"; learner: string; course: string; score: number }
  | { type: "GradeCorrected"; learner: string; course: string; score: number }
  | { type: "GradeVoided"; learner: string; course: string }
  | { type: "LearnerNoteAdded"; learner: string; note: string };

export type GradebookView = Readonly<{
  entries: Readonly<Record<string, Readonly<Record<string, number>>>>;
}>;

export const emptyView: GradebookView = { entries: {} };

function put(
  view: GradebookView,
  learner: string,
  course: string,
  score: number,
): GradebookView {
  const forLearner = view.entries[learner] ?? {};
  return {
    entries: { ...view.entries, [learner]: { ...forLearner, [course]: score } },
  };
}

function remove(view: GradebookView, learner: string, course: string): GradebookView {
  const forLearner = view.entries[learner];
  if (!forLearner) return view;
  const next: Record<string, number> = { ...forLearner };
  delete next[course];
  return { entries: { ...view.entries, [learner]: next } };
}

export function project(view: GradebookView, event: GradeEvent): GradebookView {
  switch (event.type) {
    case "GradeRecorded":
      return put(view, event.learner, event.course, event.score);
    case "GradeCorrected":
      return put(view, event.learner, event.course, event.score);
    case "GradeVoided":
      return remove(view, event.learner, event.course);
    case "LearnerNoteAdded":
      return view;
    default: { const _n: never = event; return view; }
  }
}

export function gradebookFrom(events: ReadonlyArray<GradeEvent>): GradebookView {
  return events.reduce(project, emptyView);
}
