```typescript
export type CandidateEvent =
  | { type: "Nominated"; id: string; name: string; party: string }
  | { type: "Verified"; at: string }
  | { type: "Withdrawn"; at: string };

export type CandidateState =
  | { status: "none" }
  | { status: "nominated"; id: string; name: string; party: string }
  | { status: "verified"; id: string; name: string; party: string }
  | { status: "withdrawn"; id: string };

export const initial: CandidateState = { status: "none" };

export function evolve(s: CandidateState, e: CandidateEvent): CandidateState {
  switch (e.type) {
    case "Nominated":
      return { status: "nominated", id: e.id, name: e.name, party: e.party };
    case "Verified":
      return s.status === "nominated" ? { status: "verified", id: s.id, name: s.name, party: s.party } : s;
    case "Withdrawn":
      return s.status === "nominated" || s.status === "verified" ? { status: "withdrawn", id: s.id } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolveFn: (s: S, e: E) => S,
  initialState: S,
): Promise<S> {
  let state: S = initialState;
  for await (const event of stream) {
    state = evolveFn(state, event);
  }
  return state;
}

export function isRegistered(s: CandidateState): s is Exclude<CandidateState, { status: "none" }> {
  return s.status !== "none";
}

export async function loadCandidate(stream: AsyncIterable<CandidateEvent>): Promise<CandidateState> {
  const state = await aggregateStream(stream, evolve, initial);
  if (!isRegistered(state)) throw new Error("candidate stream empty");
  return state;
}
```

Reactions are small but require a rule: only one active emoji per user per post. The decider tracks presence/absence and lets a change emit a single `ReactionChanged` event.

```typescript
type ReactionCommand =
  | { type: 'AddReaction'; userId: string; postId: string; emoji: string }
  | { type: 'ChangeReaction'; emoji: string }
  | { type: 'RemoveReaction' };

type ReactionEvent =
  | { type: 'ReactionAdded'; userId: string; postId: string; emoji: string }
  | { type: 'ReactionChanged'; emoji: string }
  | { type: 'ReactionRemoved' };

type ReactionState =
  | { status: 'none' }
  | { status: 'active'; userId: string; postId: string; emoji: string };

class ReactionRuleError extends Error {}

export function decide(command: ReactionCommand, state: ReactionState): ReactionEvent[] {
  switch (command.type) {
    case 'AddReaction':
      if (state.status === 'active') throw new ReactionRuleError('already reacted');
      return [{ type: 'ReactionAdded', userId: command.userId, postId: command.postId, emoji: command.emoji }];
    case 'ChangeReaction':
      if (state.status !== 'active') throw new ReactionRuleError('no reaction');
      if (state.emoji === command.emoji) return [];
      return [{ type: 'ReactionChanged', emoji: command.emoji }];
    case 'RemoveReaction':
      if (state.status !== 'active') return [];
      return [{ type: 'ReactionRemoved' }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: ReactionState, event: ReactionEvent): ReactionState {
  switch (event.type) {
    case 'ReactionAdded':
      return { status: 'active', userId: event.userId, postId: event.postId, emoji: event.emoji };
    case 'ReactionChanged':
      return state.status === 'active' ? { ...state, emoji: event.emoji } : state;
    case 'ReactionRemoved':
      return { status: 'none' };
    default: {
      const _: never = event;
      return _;
    }
  }
}
