  | { type: 'UPLOAD' }
  | { type: 'DISCARD' }
  | { type: 'RETRY' };

const upload = fromPromise<void, { audio: Blob }>(async ({ input }) => {
  const res = await fetch('/memos', { method: 'POST', body: input.audio });
  if (!res.ok) throw new Error('upload failed');
});

export const voiceMemoMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { upload },
  guards: { canRetry: ({ context }) => context.retries < 3 }
}).createMachine({
  id: 'voiceMemo',
  initial: 'idle',
  context: { audio: null, retries: 0, error: null },
  states: {
    idle: { on: { START: 'recording' } },
    recording: {
      on: {
        STOP: {
          target: 'review',
          actions: assign({ audio: ({ event }) => event.audio })
        }
      }
    },
    review: {
      on: {
        UPLOAD: 'uploading',
        DISCARD: { target: 'idle', actions: assign({ audio: null, retries: 0 }) }
      }
    },
    uploading: {
      invoke: {
        src: 'upload',
        input: ({ context }) => ({ audio: context.audio as Blob }),
        onDone: 'done',
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => String(event.error),
            retries: ({ context }) => context.retries + 1
          })
        }
      }
    },
    failed: {
      on: {
        RETRY: { guard: 'canRetry', target: 'uploading' },
        DISCARD: 'idle'
      }
    },
    done: { type: 'final' }
  }
});
```

A projection reduces events to a query-optimised read model, denormalised for the view's needs. `evolve` rebuilds the aggregate's write-side state; a projection keeps the read side eventually consistent and can ignore events it does not care about.

```typescript
export type ClinicalTrialEvent =
  | { type: "TrialOpened"; id: string; title: string; capacity: number }
  | { type: "ParticipantEnrolled"; id: string; participantId: string }
  | { type: "ParticipantWithdrawn"; id: string; participantId: string }
  | { type: "TrialClosed"; id: string; at: string };

export interface TrialRow {
  readonly id: string;
  readonly title: string;
  readonly capacity: number;
  readonly enrolled: number;
  readonly closed: boolean;
}

export interface TrialView {
  readonly trials: Record<string, TrialRow>;
}

export const emptyView: TrialView = { trials: {} };

export function project(view: TrialView, event: ClinicalTrialEvent): TrialView {
  switch (event.type) {
    case "TrialOpened":
      return { trials: { ...view.trials, [event.id]: { id: event.id, title: event.title, capacity: event.capacity, enrolled: 0, closed: false } } };
    case "ParticipantEnrolled": {
      const row = view.trials[event.id];
      if (!row) return view;
      return { trials: { ...view.trials, [event.id]: { ...row, enrolled: row.enrolled + 1 } } };
    }
    case "ParticipantWithdrawn": {
      const row = view.trials[event.id];
      if (!row) return view;
      return { trials: { ...view.trials, [event.id]: { ...row, enrolled: Math.max(0, row.enrolled - 1) } } };
    }
    case "TrialClosed": {
      const row = view.trials[event.id];
      if (!row) return view;
      return { trials: { ...view.trials, [event.id]: { ...row, closed: true } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
