export type CalibrationState =
  | { status: "none" }
  | { status: "active"; instrumentId: string; performed: number; failed: number };

export type CalibrationEvent =
  | { type: "InstrumentRegistered"; instrumentId: string }
  | { type: "CalibrationPerformed"; at: string }
  | { type: "CalibrationFailed"; reason: string };

export function when(state: CalibrationState, event: CalibrationEvent): CalibrationState {
  switch (event.type) {
    case "InstrumentRegistered":
      return { status: "active", instrumentId: event.instrumentId, performed: 0, failed: 0 };
    case "CalibrationPerformed":
      if (state.status !== "active") return state;
      return { ...state, performed: state.performed + 1 };
    case "CalibrationFailed":
      if (state.status !== "active") return state;
      return { ...state, failed: state.failed + 1 };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S
): Promise<S> {
  let state = initial;
  for await (const e of stream) {
    state = reducer(state, e);
  }
  return state;
}

export async function loadCalibration(stream: AsyncIterable<CalibrationEvent>): Promise<CalibrationState> {
  return aggregateStream(stream, when, { status: "none" });
}
