```typescript
export type EditSessionState =
  | { status: "none" }
  | { status: "open"; id: string; editor: string; pendingCuts: number }
  | { status: "committed"; id: string; editor: string; totalCuts: number }
  | { status: "discarded"; id: string };

export type EditSessionCommand =
  | { type: "open"; id: string; editor: string }
  | { type: "stageCut" }
  | { type: "commit"; at: string }
  | { type: "discard" };

export type EditSessionEvent =
  | { type: "EditSessionOpened"; id: string; editor: string }
  | { type: "EditSessionCutStaged" }
  | { type: "EditSessionCommitted"; at: string; totalCuts: number }
  | { type: "EditSessionDiscarded" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const editSessionDecider: Decider<EditSessionCommand, EditSessionEvent, EditSessionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "EditSessionOpened", id: command.id, editor: command.editor }];
      case "stageCut":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "EditSessionCutStaged" }];
      case "commit":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (state.pendingCuts === 0) throw new DomainError("EMPTY");
        return [{ type: "EditSessionCommitted", at: command.at, totalCuts: state.pendingCuts }];
      case "discard":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "EditSessionDiscarded" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "EditSessionOpened":
        return { status: "open", id: event.id, editor: event.editor, pendingCuts: 0 };
      case "EditSessionCutStaged":
        if (state.status !== "open") return state;
        return { ...state, pendingCuts: state.pendingCuts + 1 };
      case "EditSessionCommitted":
        if (state.status !== "open") return state;
        return { status: "committed", id: state.id, editor: state.editor, totalCuts: event.totalCuts };
      case "EditSessionDiscarded":
        if (state.status !== "open") return state;
        return { status: "discarded", id: state.id };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

A Decider bundles pure decide and evolve functions plus an initial state. decide produces events from a command without I/O; evolve folds events into state. Invariants (like double-acknowledgement) are checked inside decide and surface as typed domain errors.

```typescript
export class InvariantError extends Error {}
export type DiscoveryRequestCommand =
  | { type: "issue"; requestId: string; topic: string }
  | { type: "acknowledge"; by: string }
  | { type: "produce"; documentId: string };
export type DiscoveryRequestEvent =
  | { type: "issued"; requestId: string; topic: string }
  | { type: "acknowledged"; by: string }
  | { type: "produced"; documentId: string };
export type DiscoveryRequestState =
  | { status: "none" }
  | { status: "issued"; requestId: string; acknowledgedBy: string | null; produced: number };
export const initialState: DiscoveryRequestState = { status: "none" };
export interface Decider<C, E, S> { initialState: S; decide: (c: C, s: S) => E[]; evolve: (s: S, e: E) => S }
export function decide(c: DiscoveryRequestCommand, s: DiscoveryRequestState): DiscoveryRequestEvent[] {
  switch (c.type) {
    case "issue":
      if (s.status !== "none") throw new InvariantError("already issued");
      return [{ type: "issued", requestId: c.requestId, topic: c.topic }];
    case "acknowledge":
      if (s.status !== "issued") throw new InvariantError("not issued");
      if (s.acknowledgedBy !== null) throw new InvariantError("already acknowledged");
      return [{ type: "acknowledged", by: c.by }];
    case "produce":
      if (s.status !== "issued") throw new InvariantError("not issued");
      return [{ type: "produced", documentId: c.documentId }];
    default: { const _: never = c; return _; }
  }
}
export function evolve(s: DiscoveryRequestState, e: DiscoveryRequestEvent): DiscoveryRequestState {
  switch (e.type) {
    case "issued": return { status: "issued", requestId: e.requestId, acknowledgedBy: null, produced: 0 };
    case "acknowledged": return s.status === "issued" ? { ...s, acknowledgedBy: e.by } : s;
    case "produced": return s.status === "issued" ? { ...s, produced: s.produced + 1 } : s;
    default: { const _: never = e; return _; }
  }
}
export const DiscoveryRequestDecider: Decider<DiscoveryRequestCommand, DiscoveryRequestEvent, DiscoveryRequestState> = { initialState, decide, evolve };
```

Read events one by one with `for await` and reassign a local `state` variable. Never mutate the incoming iterable — just accumulate.

```typescript
export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; roomId: string; reservePrice: number }
  | { type: "BidPlaced"; bidder: string; amount: number }
  | { type: "AuctionRoomClosed" };

export interface AuctionRoomState {
  readonly roomId: string;
  readonly highBid: number;
  readonly leader: string | null;
  readonly closed: boolean;
}

export const initialRoom: AuctionRoomState = { roomId: "", highBid: 0, leader: null, closed: false };

export function evolve(state: AuctionRoomState, event: AuctionRoomEvent): AuctionRoomState {
  switch (event.type) {
    case "AuctionRoomOpened":
      return { roomId: event.roomId, highBid: event.reservePrice, leader: null, closed: false };
    case "BidPlaced":
      if (state.closed || event.amount <= state.highBid) return state;
      return { ...state, highBid: event.amount, leader: event.bidder };
    case "AuctionRoomClosed":
      return { ...state, closed: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export async function loadRoom(stream: AsyncIterable<AuctionRoomEvent>): Promise<AuctionRoomState> {
  return aggregateStream(stream, evolve, initialRoom);
}
```

