export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export async function aggregateStreamChecked<S, E, A extends S>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
  check: (state: S) => state is A,
): Promise<A> {
  const state = await aggregateStream(stream, evolve, initial);
  if (!check(state)) throw new Error("AGGREGATE_NOT_VALID");
  return state;
}

export interface ReadStream<E> {
  readAll(streamName: string): AsyncIterable<E>;
}

export async function loadAggregate<S, E>(
  reader: ReadStream<E>,
  streamName: string,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  return aggregateStream(reader.readAll(streamName), evolve, initial);
}
