export type CurrentFeatureFlagEvent =
  | { type: "FeatureFlagCreated"; id: string; key: string; rolloutKey: string }
  | { type: "FeatureFlagEnabled" };

type RawEvent =
  | { type: "flag-created"; version: 1; id: string; key: string }
  | { type: "FeatureFlagCreated"; version: 2; id: string; key: string; rolloutKey: string }
  | { type: "FeatureFlagEnabled"; version: 1 };

export class UnknownEventError extends Error {
  constructor(public readonly raw: unknown) {
    super("UNKNOWN_EVENT");
    this.name = "UnknownEventError";
  }
}

function isRaw(v: unknown): v is RawEvent {
  return typeof v === "object" && v !== null && "type" in v && "version" in v;
}

export function upcast(raw: unknown): CurrentFeatureFlagEvent {
  if (!isRaw(raw)) throw new UnknownEventError(raw);
  switch (raw.type) {
    case "flag-created":
      if (raw.version === 1) {
        return { type: "FeatureFlagCreated", id: raw.id, key: raw.key, rolloutKey: "default" };
      }
      throw new UnknownEventError(raw);
    case "FeatureFlagCreated":
      if (raw.version === 2) {
        return { type: "FeatureFlagCreated", id: raw.id, key: raw.key, rolloutKey: raw.rolloutKey };
      }
      throw new UnknownEventError(raw);
    case "FeatureFlagEnabled":
      if (raw.version === 1) return { type: "FeatureFlagEnabled" };
      throw new UnknownEventError(raw);
    default: {
      const _never: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}
```

