export type SceneShotCommand =
  | { type: "log"; id: string; sceneId: string }
  | { type: "recordTake" };

export type SceneShotEvent =
  | { type: "SceneShotLogged"; id: string; sceneId: string }
  | { type: "SceneShotTakeRecorded" };

export type SceneShotState =
  | { status: "none" }
  | { status: "logged"; id: string; takes: number };

export const initialState: SceneShotState = { status: "none" };

export function evolve(state: SceneShotState, event: SceneShotEvent): SceneShotState {
  switch (event.type) {
    case "SceneShotLogged":
      return { status: "logged", id: event.id, takes: 0 };
    case "SceneShotTakeRecorded":
      if (state.status !== "logged") return state;
      return { ...state, takes: state.takes + 1 };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: SceneShotCommand, state: SceneShotState): SceneShotEvent[] {
  switch (command.type) {
    case "log":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "SceneShotLogged", id: command.id, sceneId: command.sceneId }];
    case "recordTake":
      if (state.status !== "logged") throw new Error("NOT_LOGGED");
      return [{ type: "SceneShotTakeRecorded" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export async function handle(
  command: SceneShotCommand,
  args: { streamName: string; eventStore: EventStore<SceneShotEvent> },
): Promise<void> {
  const loaded = await args.eventStore.readStream(args.streamName);
  const state = loaded.events.reduce(evolve, initialState);
  const events = decide(command, state);
  await args.eventStore.appendToStream(args.streamName, events, { expectedRevision: loaded.revision });
}
