  | { type: 'ParticipantAdded'; conversationId: string; userId: string }
  | { type: 'ParticipantRemoved'; conversationId: string; userId: string };

type ParticipantsView = Readonly<{
  conversationId: string;
  members: readonly string[];
}>;

interface EventStoreCursor {
  read(from: bigint, batchSize: number): Promise<{ events: { event: ConversationEvent; revision: bigint }[]; nextFrom: bigint | null }>;
}

interface ReadStore {
  loadView(id: string): Promise<ParticipantsView | null>;
  saveBatch(views: readonly ParticipantsView[]): Promise<void>;
  saveCursor(cursor: bigint): Promise<void>;
}

function project(view: ParticipantsView, event: ConversationEvent): ParticipantsView {
  switch (event.type) {
    case 'ConversationStarted':
      return { conversationId: event.conversationId, members: [event.starterId] };
    case 'ParticipantAdded':
      return view.members.includes(event.userId) ? view : { ...view, members: [...view.members, event.userId] };
    case 'ParticipantRemoved':
      return { ...view, members: view.members.filter((m) => m !== event.userId) };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  events: EventStoreCursor;
  store: ReadStore;
}): Promise<void> {
  let cursor: bigint | null = opts.from;
  while (cursor !== null) {
    const { events, nextFrom } = await opts.events.read(cursor, opts.batchSize);
    const map = new Map<string, ParticipantsView>();
    for (const { event } of events) {
      const existing =
        map.get(event.conversationId) ??
        (await opts.store.loadView(event.conversationId)) ??
        { conversationId: event.conversationId, members: [] };
      map.set(event.conversationId, project(existing, event));
    }
    await opts.store.saveBatch(Array.from(map.values()));
    const last = events[events.length - 1];
    if (last) await opts.store.saveCursor(last.revision);
    cursor = nextFrom;
  }
}
```

