```typescript
export type TelemetryStreamState =
  | { status: "none" }
  | { status: "open"; id: string; samples: number };

export type TelemetryStreamCommand =
  | { type: "open"; id: string }
  | { type: "ingest"; value: number };

export type TelemetryStreamEvent =
  | { type: "TelemetryStreamOpened"; id: string }
  | { type: "TelemetrySampleIngested"; value: number };

export class DomainError extends Error {}

export const initialState: TelemetryStreamState = { status: "none" };

export function evolve(state: TelemetryStreamState, event: TelemetryStreamEvent): TelemetryStreamState {
  switch (event.type) {
    case "TelemetryStreamOpened":
      return { status: "open", id: event.id, samples: 0 };
    case "TelemetrySampleIngested":
      if (state.status !== "open") return state;
      return { ...state, samples: state.samples + 1 };
    default: { const _n: never = event; return state; }
  }
}

export function decide(command: TelemetryStreamCommand, state: TelemetryStreamState): TelemetryStreamEvent[] {
  switch (command.type) {
    case "open":
      if (state.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "TelemetryStreamOpened", id: command.id }];
    case "ingest":
      if (state.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "TelemetrySampleIngested", value: command.value }];
    default: { const _n: never = command; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: TelemetryStreamEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: TelemetryStreamEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextRevision: bigint }>;
}

export interface CommandHandler<C> {
  handle(command: C, ctx: { streamName: string; eventStore: EventStore }): Promise<void>;
}

export const telemetryStreamHandler: CommandHandler<TelemetryStreamCommand> = {
  async handle(command, { streamName, eventStore }) {
    const current = await eventStore.readStream(streamName);
    const state = current.events.reduce(evolve, initialState);
    const events = decide(command, state);
    if (events.length === 0) return;
    const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
    await eventStore.appendToStream(streamName, events, { expectedRevision });
  },
};
