export type MovementEvent =
  | { type: "SkuReceived"; sku: string; qty: number }
  | { type: "SkuPicked"; sku: string; qty: number }
  | { type: "SkuAdjusted"; sku: string; delta: number; reason: string }
  | { type: "SkuDiscontinued"; sku: string };

export interface LedgerRow {
  readonly opening: number;
  readonly inQty: number;
  readonly outQty: number;
  readonly onHand: number;
  readonly active: boolean;
}

export interface LedgerView {
  readonly bySku: Readonly<Record<string, LedgerRow>>;
}

export const emptyView: LedgerView = { bySku: {} };

const zero: LedgerRow = { opening: 0, inQty: 0, outQty: 0, onHand: 0, active: true };

export function project(view: LedgerView, event: MovementEvent): LedgerView {
  const row = view.bySku[event.sku] ?? zero;
  switch (event.type) {
    case "SkuReceived":
      return {
        bySku: {
          ...view.bySku,
          [event.sku]: { ...row, inQty: row.inQty + event.qty, onHand: row.onHand + event.qty },
        },
      };
    case "SkuPicked":
      return {
        bySku: {
          ...view.bySku,
          [event.sku]: { ...row, outQty: row.outQty + event.qty, onHand: row.onHand - event.qty },
        },
      };
    case "SkuAdjusted":
      return {
        bySku: {
          ...view.bySku,
          [event.sku]: { ...row, onHand: row.onHand + event.delta },
        },
      };
    case "SkuDiscontinued":
      return {
        bySku: { ...view.bySku, [event.sku]: { ...row, active: false } },
      };
    default: { const _n: never = event; return view; }
  }
}
