export type RemittanceEvent =
  | { type: "RemittanceInitiated"; id: string; amount: number; corridor: string }
  | { type: "RemittanceFunded"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult {
  readonly ok: true;
  readonly newRevision: bigint;
}

export interface ConflictResult {
  readonly ok: false;
  readonly reason: "revision_mismatch";
  readonly actualRevision: bigint | null;
}

export interface EventStore {
  readStream(stream: string): Promise<{ events: RemittanceEvent[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<RemittanceEvent>,
    options: { expectedRevision: ExpectedRevision },
  ): Promise<AppendResult | ConflictResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly actualRevision: bigint | null) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendWithConcurrencyCheck(
  store: EventStore,
  stream: string,
  newEvents: ReadonlyArray<RemittanceEvent>,
): Promise<bigint> {
  const { revision } = await store.readStream(stream);
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  const result = await store.appendToStream(stream, newEvents, { expectedRevision });
  if (result.ok) return result.newRevision;
  throw new ConcurrencyConflict(stream, result.actualRevision);
}
