```typescript
export type CIJobState =
  | { status: "queued"; id: string }
  | { status: "running"; id: string; runner: string }
  | { status: "done"; id: string; outcome: "pass" | "fail" }
  | { status: "none" };

export type CIJobCommand =
  | { type: "enqueue"; id: string }
  | { type: "start"; runner: string }
  | { type: "complete"; outcome: "pass" | "fail" };

export type CIJobEvent =
  | { type: "CIJobEnqueued"; id: string }
  | { type: "CIJobStarted"; runner: string }
  | { type: "CIJobCompleted"; outcome: "pass" | "fail" };

export const initialState: CIJobState = { status: "none" };

export function evolve(state: CIJobState, event: CIJobEvent): CIJobState {
  switch (event.type) {
    case "CIJobEnqueued":
      return { status: "queued", id: event.id };
    case "CIJobStarted":
      if (state.status !== "queued") return state;
      return { status: "running", id: state.id, runner: event.runner };
    case "CIJobCompleted":
      if (state.status !== "running") return state;
      return { status: "done", id: state.id, outcome: event.outcome };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: CIJobCommand, state: CIJobState): CIJobEvent[] {
  switch (command.type) {
    case "enqueue":
      if (state.status !== "none") throw new Error("ALREADY_QUEUED");
      return [{ type: "CIJobEnqueued", id: command.id }];
    case "start":
      if (state.status !== "queued") throw new Error("NOT_QUEUED");
      return [{ type: "CIJobStarted", runner: command.runner }];
    case "complete":
      if (state.status !== "running") throw new Error("NOT_RUNNING");
      return [{ type: "CIJobCompleted", outcome: command.outcome }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface CommandHandler<C, Ctx> {
  handle(command: C, ctx: Ctx): Promise<void>;
}

export function createHandler(store: EventStore<CIJobEvent>): CommandHandler<CIJobCommand, { streamName: string }> {
  return {
    async handle(command, ctx) {
      const loaded = await store.readStream(ctx.streamName);
      const state = loaded.events.reduce(evolve, initialState);
      const events = decide(command, state);
      await store.appendToStream(ctx.streamName, events, { expectedRevision: loaded.revision });
    },
  };
}
