export interface CurrentArtAuctionState {
  readonly id: string;
  readonly status: "open" | "closed";
  readonly high: number;
  readonly leader: string | null;
  readonly currency: string;
}

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3;

interface V1State { id: string; status: string; high: number; }
interface V2State { id: string; status: string; high: number; leader: string | null; }

function v1Tov2(snap: Snapshot<V1State>): Snapshot<V2State> {
  return { version: 2, state: { ...snap.state, leader: null } };
}

function v2Tov3(snap: Snapshot<V2State>): Snapshot<CurrentArtAuctionState> {
  const status: "open" | "closed" = snap.state.status === "closed" ? "closed" : "open";
  return { version: 3, state: { ...snap.state, status, currency: "USD" } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentArtAuctionState> {
  let working: Snapshot<unknown> = raw;
  if (working.version === 1) working = v1Tov2(working as Snapshot<V1State>);
  if (working.version === 2) working = v2Tov3(working as Snapshot<V2State>);
  if (working.version !== CURRENT_VERSION) {
    throw new Error(`Cannot upgrade snapshot from v${raw.version}`);
  }
  return working as Snapshot<CurrentArtAuctionState>;
}
