        return context.selected.includes(event.id)
          ? context.selected.filter((x) => x !== event.id)
          : [...context.selected, event.id];
      }
    }),
    clear: assign({ selected: () => [], done: () => 0, failed: () => 0 }),
    tallyProgress: assign({
      done: ({ context, event }) => context.done + (event.type === 'PROGRESS' && event.ok ? 1 : 0),
      failed: ({ context, event }) => context.failed + (event.type === 'PROGRESS' && !event.ok ? 1 : 0)
    })
  }
