        CLEAR: { actions: 'clear' },
        CONFIRM: { guard: 'hasSelection', target: 'confirming' }
      }
    },
    confirming: { on: { START: 'executing', CANCEL: 'selecting' } },
    executing: { on: { PROGRESS: { actions: 'tallyProgress' }, FINISHED: 'complete' } },
