A Decider bundles three pure pieces: initialState, decide(command, state) returning events or throwing, and evolve(state, event) folding events into state. It has no I/O, which makes dispatch lifecycles trivially testable.

```typescript
export type DispatchState =
  | { status: "open"; id: string }
  | { status: "assigned"; id: string; driverId: string }
  | { status: "finalized"; id: string; driverId: string; at: string };

export type DispatchCommand =
  | { type: "assign"; driverId: string }
  | { type: "release" }
  | { type: "finalize"; at: string };

export type DispatchEvent =
  | { type: "DispatchAssigned"; driverId: string }
  | { type: "DispatchReleased" }
  | { type: "DispatchFinalized"; at: string };

export class DispatchError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const makeDispatchDecider = (id: string): Decider<DispatchCommand, DispatchEvent, DispatchState> => ({
  initialState: { status: "open", id },
  decide(c, s) {
    switch (c.type) {
      case "assign":
        if (s.status !== "open") throw new DispatchError("NOT_OPEN");
        return [{ type: "DispatchAssigned", driverId: c.driverId }];
      case "release":
        if (s.status !== "assigned") throw new DispatchError("NOT_ASSIGNED");
        return [{ type: "DispatchReleased" }];
      case "finalize":
        if (s.status !== "assigned") throw new DispatchError("NOT_ASSIGNED");
        return [{ type: "DispatchFinalized", at: c.at }];
      default: { const _n: never = c; throw new DispatchError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "DispatchAssigned":
        if (s.status !== "open") return s;
        return { status: "assigned", id: s.id, driverId: e.driverId };
      case "DispatchReleased":
        if (s.status !== "assigned") return s;
        return { status: "open", id: s.id };
      case "DispatchFinalized":
        if (s.status !== "assigned") return s;
        return { status: "finalized", id: s.id, driverId: s.driverId, at: e.at };
      default: { const _n: never = e; return s; }
    }
  },
});
