```typescript
import { Effect } from "effect";

export type FoodInspectionEvent =
  | { type: "FoodInspectionReported"; id: string; score: number; at: string };

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export type ExpectedRevision = bigint | "no_stream";

export interface TxEventStore {
  appendToStream(stream: string, events: readonly FoodInspectionEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export interface TxOutbox {
  insert(row: OutboxRow): Promise<void>;
}

export interface Transaction {
  readonly store: TxEventStore;
  readonly outbox: TxOutbox;
}

export interface UnitOfWork {
  run<T>(body: (tx: Transaction) => Promise<T>): Promise<T>;
}

// Publisher (out of scope) polls the outbox, publishes each row to a broker,
// and marks publishedAt once the broker acknowledges delivery.
export function appendWithOutbox(
  uow: UnitOfWork,
  stream: string,
  events: readonly FoodInspectionEvent[],
  outboxRows: readonly OutboxRow[],
  expectedRevision: ExpectedRevision,
) {
  return Effect.gen(function* () {
    yield* Effect.promise(() =>
      uow.run(async (tx) => {
        await tx.store.appendToStream(stream, events, { expectedRevision });
        for (const row of outboxRows) {
          await tx.outbox.insert(row);
        }
      }),
    );
  });
}

