```typescript
export type RenderJobEvent =
  | { type: "RenderJobQueued"; id: string; sourceId: string }
  | { type: "RenderJobFinished"; id: string; outputUri: string };

export interface OutboxRow {
  readonly id: string;
  readonly schema: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export interface TxConnection<E> {
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface ConnectionPool<E> {
  begin(): Promise<TxConnection<E>>;
}

// A separate poller scans the outbox for rows where publishedAt is null,
// publishes them to the integration bus, and stamps publishedAt. It is NOT
// implemented here; this function only keeps the event append and the outbox
// insert atomic.
export async function appendWithOutbox(
  pool: ConnectionPool<RenderJobEvent>,
  streamName: string,
  events: readonly RenderJobEvent[],
  outboxRows: readonly OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<bigint> {
  const tx = await pool.begin();
  try {
    const rev = await tx.appendToStream(streamName, [...events], { expectedRevision });
    await tx.insertOutbox(outboxRows);
    await tx.commit();
    return rev;
  } catch (err) {
    await tx.rollback();
    throw err instanceof Error ? err : new Error(String(err));
  }
}
