```typescript
export type Snapshot<S> = { version: number; state: S };

export type FlightV1 = { id: string; gate: string };
export type FlightV2 = { id: string; gate: string; boarded: number };
export type FlightV3 = { id: string; gate: string; boarded: number; airline: string };
export type FlightV4 = {
  id: string;
  gate: string;
  boarded: number;
  airline: string;
  status: "scheduled" | "boarding" | "airborne" | "landed";
};

export type CurrentFlight = FlightV4;
export const CURRENT_VERSION = 4;

export class SnapshotUpgradeError extends Error {}

const v1Tov2 = (s: FlightV1): FlightV2 => ({ ...s, boarded: 0 });
const v2Tov3 = (s: FlightV2): FlightV3 => ({ ...s, airline: "unknown" });
const v3Tov4 = (s: FlightV3): FlightV4 => ({ ...s, status: "scheduled" });

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentFlight> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new SnapshotUpgradeError(`UNSUPPORTED_${version}`);
  }
  if (version === 1) { state = v1Tov2(state as FlightV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as FlightV2); version = 3; }
  if (version === 3) { state = v3Tov4(state as FlightV3); version = 4; }
  if (version !== CURRENT_VERSION) throw new SnapshotUpgradeError("INCOMPLETE");
  const upgraded = state as CurrentFlight;
  if (typeof upgraded.id !== "string" || typeof upgraded.status !== "string") {
    throw new SnapshotUpgradeError("SHAPE_MISMATCH");
  }
  return { version, state: upgraded };
}

export function loadFlight(raw: Snapshot<unknown>): CurrentFlight {
  return upgradeSnapshot(raw).state;
}
