```typescript
export type ArtAppraisalCommand =
  | { type: "request"; id: string; pieceId: string }
  | { type: "assign"; appraiser: string }
  | { type: "submit"; value: number };

export type ArtAppraisalEvent =
  | { type: "ArtAppraisalRequested"; id: string; pieceId: string }
  | { type: "ArtAppraisalAssigned"; appraiser: string }
  | { type: "ArtAppraisalSubmitted"; value: number };

type ArtAppraisalState =
  | { status: "none" }
  | { status: "requested"; id: string; pieceId: string }
  | { status: "assigned"; id: string; appraiser: string }
  | { status: "submitted"; id: string; value: number };

const initial: ArtAppraisalState = { status: "none" };

function evolve(state: ArtAppraisalState, event: ArtAppraisalEvent): ArtAppraisalState {
  switch (event.type) {
    case "ArtAppraisalRequested":
      return { status: "requested", id: event.id, pieceId: event.pieceId };
    case "ArtAppraisalAssigned":
      if (state.status !== "requested") return state;
      return { status: "assigned", id: state.id, appraiser: event.appraiser };
    case "ArtAppraisalSubmitted":
      if (state.status !== "assigned") return state;
      return { status: "submitted", id: state.id, value: event.value };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: ArtAppraisalCommand, state: ArtAppraisalState): ArtAppraisalEvent[] {
  switch (command.type) {
    case "request":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ArtAppraisalRequested", id: command.id, pieceId: command.pieceId }];
    case "assign":
      if (state.status !== "requested") throw new Error("NOT_REQUESTED");
      return [{ type: "ArtAppraisalAssigned", appraiser: command.appraiser }];
    case "submit":
      if (state.status !== "assigned") throw new Error("NOT_ASSIGNED");
      return [{ type: "ArtAppraisalSubmitted", value: command.value }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface CommandHandlerContext<E> {
  readonly streamName: string;
  readonly eventStore: {
    readStream(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
    appendToStream(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
  };
}

export async function handleArtAppraisal(
  command: ArtAppraisalCommand,
  ctx: CommandHandlerContext<ArtAppraisalEvent>
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initial);
  const out = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, out, { expectedRevision: revision });
}
