```typescript
export type RawEvent =
  | { type: "DeploymentStarted"; version: 1; data: { id: string } }
  | { type: "DeploymentStarted"; version: 2; data: { id: string; target: string } }
  | { type: "DeploymentSucceeded"; version: 1; data: { at: string } };

export type Event =
  | { type: "DeploymentStarted"; id: string; target: string }
  | { type: "DeploymentSucceeded"; at: string };

export class UnknownEventError extends Error {
  constructor(msg: string) { super(msg); this.name = "UnknownEventError"; }
}

export function upcast(raw: RawEvent): Event {
  switch (raw.type) {
    case "DeploymentStarted":
      switch (raw.version) {
        case 1:
          return { type: "DeploymentStarted", id: raw.data.id, target: "unknown" };
        case 2:
          return { type: "DeploymentStarted", id: raw.data.id, target: raw.data.target };
        default: { const _n: never = raw; throw new UnknownEventError("UNKNOWN"); }
      }
    case "DeploymentSucceeded":
      return { type: "DeploymentSucceeded", at: raw.data.at };
    default: { const _n: never = raw; throw new UnknownEventError("UNKNOWN_TYPE"); }
  }
}

export function aggregate(raws: RawEvent[]): Event[] {
  return raws.map(upcast);
}
