Aggregate state is just a fold of the event stream through a pure reducer. Because `evolve` is pure and total, feeding the same events in the same order always produces the same state — we can rebuild at any time by replaying from the beginning.

```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type PipelineState =
  | { status: "none" }
  | { status: "running"; id: string; stages: number }
  | { status: "archived"; id: string };

export type PipelineEvent =
  | { type: "PipelineCreated"; id: string }
  | { type: "StageAdded" }
  | { type: "PipelineArchived" };

const initial: PipelineState = { status: "none" };

function evolve(s: PipelineState, e: PipelineEvent): PipelineState {
  switch (e.type) {
    case "PipelineCreated": return { status: "running", id: e.id, stages: 0 };
    case "StageAdded":
      if (s.status !== "running") return s;
      return { status: "running", id: s.id, stages: s.stages + 1 };
    case "PipelineArchived":
      if (s.status !== "running") return s;
      return { status: "archived", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export async function load(stream: AsyncIterable<PipelineEvent>): Promise<PipelineState> {
  return aggregateStream<PipelineState, PipelineEvent>(stream, evolve, initial);
}
