A process manager is just a pure function (event) => Command | null.  The saga stays stateless by relying on the downstream aggregates' streams to carry state; events it does not care about return null.

```typescript
export type FlowEvent =
  | { type: "RequestSubmitted"; id: string; title: string }
  | { type: "LenderConfirmed"; id: string; lender: string }
  | { type: "ItemShipped"; id: string }
  | { type: "ItemReceived"; id: string };

export type FlowCommand =
  | { type: "FindLender"; id: string; title: string }
  | { type: "BookDelivery"; id: string; lender: string }
  | { type: "NotifyPatron"; id: string };

export function react(event: FlowEvent): FlowCommand | null {
  switch (event.type) {
    case "RequestSubmitted":
      return { type: "FindLender", id: event.id, title: event.title };
    case "LenderConfirmed":
      return { type: "BookDelivery", id: event.id, lender: event.lender };
    case "ItemShipped":
      return null;
    case "ItemReceived":
      return { type: "NotifyPatron", id: event.id };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: FlowEvent }>;
}

export async function collectSagaCommands(store: EventStore, streamName: string): Promise<FlowCommand[]> {
  const cmds: FlowCommand[] = [];
  for await (const { event } of store.readStream(streamName)) {
    const next = react(event);
    if (next !== null) cmds.push(next);
  }
  return cmds;
}
