Pattern match on `{type, version}` of the raw stored event, and return the current shape. Provide defaults for fields added in newer versions. Downstream, the pure evolve reducer only sees the current-shape events.

```typescript
export type RawEvent =
  | { type: "BuildRunStarted"; version: 1; id: string; commit: string }
  | { type: "BuildRunStarted"; version: 2; id: string; commit: string; runner: string }
  | { type: "BuildRunFinished"; version: 1; id: string; at: string };

export type CurrentEvent =
  | { type: "BuildRunStarted"; id: string; commit: string; runner: string }
  | { type: "BuildRunFinished"; id: string; at: string; artefactId: string | null };

export interface BuildRunView {
  readonly id?: string;
  readonly commit?: string;
  readonly runner?: string;
  readonly finishedAt?: string;
}

export const initialState: BuildRunView = {};

export class UnknownEventError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: RawEvent): CurrentEvent {
  switch (raw.type) {
    case "BuildRunStarted":
      if (raw.version === 1) return { type: "BuildRunStarted", id: raw.id, commit: raw.commit, runner: "unknown" };
      if (raw.version === 2) return { type: "BuildRunStarted", id: raw.id, commit: raw.commit, runner: raw.runner };
      throw new UnknownEventError(`BuildRunStarted v${(raw as { version: number }).version}`);
    case "BuildRunFinished":
      return { type: "BuildRunFinished", id: raw.id, at: raw.at, artefactId: null };
    default: {
      const _never: never = raw;
      throw new UnknownEventError("unreachable");
    }
  }
}

export function evolve(state: BuildRunView, event: CurrentEvent): BuildRunView {
  switch (event.type) {
    case "BuildRunStarted":
      return { id: event.id, commit: event.commit, runner: event.runner };
    case "BuildRunFinished":
      return { ...state, finishedAt: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}
