export type LedgerEntryEvent =
  | { type: "EntryRecorded"; id: string; amount: number; at: string }
  | { type: "EntryCorrected"; id: string; newAmount: number }
  | { type: "EntryVoided"; id: string; reason: string }
  | { type: "EntryRestored"; id: string };

export type LedgerEntry = Readonly<{
  id: string;
  amount: number;
  voided: boolean;
  voidReason: string | null;
  lastTouchedAt: string;
}>;

export const initialEntry: LedgerEntry = {
  id: "",
  amount: 0,
  voided: false,
  voidReason: null,
  lastTouchedAt: "",
};

export function evolve(state: LedgerEntry, event: LedgerEntryEvent): LedgerEntry {
  switch (event.type) {
    case "EntryRecorded":
      return { id: event.id, amount: event.amount, voided: false, voidReason: null, lastTouchedAt: event.at };
    case "EntryCorrected":
      if (state.voided) return state;
      return { ...state, amount: event.newAmount };
    case "EntryVoided":
      return { ...state, voided: true, voidReason: event.reason };
    case "EntryRestored":
      if (!state.voided) return state;
      return { ...state, voided: false, voidReason: null };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregate(events: LedgerEntryEvent[]): LedgerEntry {
  return events.reduce(evolve, initialEntry);
}
