A CommandHandler is pure orchestration: read stream, fold to state, decide, append. Keep business rules inside `decide`; keep IO inside the handler. Wrapping the two IO calls in `Effect.gen` makes the failure and retry surface explicit while the pure core stays untouched.

```typescript
import { Effect } from "effect";

export type EnrolmentState =
  | { status: "none" }
  | { status: "registered"; id: string; learner: string }
  | { status: "confirmed"; id: string; learner: string };

export type EnrolmentCommand =
  | { type: "register"; id: string; learner: string }
  | { type: "confirm" };

export type EnrolmentEvent =
  | { type: "EnrolmentRegistered"; id: string; learner: string }
  | { type: "EnrolmentConfirmed" };

export class DomainError extends Error {}

export const initialState: EnrolmentState = { status: "none" };

export function evolve(s: EnrolmentState, e: EnrolmentEvent): EnrolmentState {
  switch (e.type) {
    case "EnrolmentRegistered":
      return { status: "registered", id: e.id, learner: e.learner };
    case "EnrolmentConfirmed":
      if (s.status !== "registered") return s;
      return { status: "confirmed", id: s.id, learner: s.learner };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: EnrolmentCommand, s: EnrolmentState): EnrolmentEvent[] {
  switch (c.type) {
    case "register":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "EnrolmentRegistered", id: c.id, learner: c.learner }];
    case "confirm":
      if (s.status !== "registered") throw new DomainError("NOT_REGISTERED");
      return [{ type: "EnrolmentConfirmed" }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<EnrolmentEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<EnrolmentEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handleEnrolmentCommandEffect = (
  streamName: string,
  command: EnrolmentCommand,
  store: EventStore,
) =>
  Effect.gen(function* () {
    const slice = yield* Effect.promise(() => store.readStream(streamName));
    const state = slice.events.reduce(evolve, initialState);
    const next = decide(command, state);
    if (next.length === 0) return slice.revision ?? 0n;
    const revision = yield* Effect.promise(() =>
      store.appendToStream(streamName, next, { expectedRevision: slice.revision ?? "no_stream" }),
    );
    return revision;
  });
```

```typescript
export type DeliveryState =
  | { status: "none" }
  | { status: "dispatched"; id: string; courier: string }
  | { status: "delivered"; id: string; courier: string; deliveredAt: string }
  | { status: "failed"; id: string; reason: string };

export type DeliveryCommand =
  | { type: "dispatch"; id: string; courier: string }
  | { type: "deliver"; at: string }
  | { type: "fail"; reason: string };

export type DeliveryEvent =
  | { type: "DeliveryDispatched"; id: string; courier: string }
  | { type: "DeliveryDelivered"; at: string }
  | { type: "DeliveryFailed"; reason: string };

export class DeliveryError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const deliveryDecider: Decider<DeliveryCommand, DeliveryEvent, DeliveryState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "dispatch":
        if (state.status !== "none") throw new DeliveryError("ALREADY_DISPATCHED");
        if (command.courier.length === 0) throw new DeliveryError("NO_COURIER");
        return [{ type: "DeliveryDispatched", id: command.id, courier: command.courier }];
      case "deliver":
        if (state.status === "failed") throw new DeliveryError("ALREADY_FAILED");
        if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
        return [{ type: "DeliveryDelivered", at: command.at }];
      case "fail":
        if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
        return [{ type: "DeliveryFailed", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new DeliveryError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DeliveryDispatched":
        return { status: "dispatched", id: event.id, courier: event.courier };
      case "DeliveryDelivered":
        if (state.status !== "dispatched") return state;
        return { status: "delivered", id: state.id, courier: state.courier, deliveredAt: event.at };
      case "DeliveryFailed":
        if (state.status !== "dispatched") return state;
        return { status: "failed", id: state.id, reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
