}

export interface Transaction {
  readonly appendToStream: (stream: string, events: ReadonlyArray<HarvestEvent>, opts: { expectedRevision: bigint | "no_stream" | "any" }) => Promise<void>;
  readonly insertOutbox: (row: OutboxRow) => Promise<void>;
}

export interface TransactionalConn {
  readonly runInTransaction: <T>(fn: (tx: Transaction) => Promise<T>) => Promise<T>;
}

export async function appendWithOutbox(
  conn: TransactionalConn,
  stream: string,
  events: ReadonlyArray<HarvestEvent>,
  outboxRows: ReadonlyArray<OutboxRow>,
  expectedRevision: bigint | "no_stream" | "any"
): Promise<void> {
  // The publisher worker polls unpublished outbox rows, emits them to the
  // message broker, and marks publishedAt on success. It is intentionally
  // not implemented here -- this function only guarantees the atomic write.
  await conn.runInTransaction(async (tx) => {
    await tx.appendToStream(stream, events, { expectedRevision });
    for (const row of outboxRows) {
      await tx.insertOutbox(row);
    }
  });
}
