      | { type: 'CHOOSE'; choice: Choice }
      | { type: 'SUBMIT' }
      | { type: 'RESET' },
  },
  guards: {
    notVoted: ({ context, event }) =>
      event.type === 'START_VOTE' && !context.voted.has(event.voter),
  },
}).createMachine({
  id: 'poll',
  initial: 'pending',
  context: {
    voted: new Set<string>(),
    tally: { a: 0, b: 0, c: 0 },
    currentVoter: null,
    currentChoice: null,
  },
  states: {
    pending: {
      on: {
        START_VOTE: {
          guard: 'notVoted',
          target: 'voting',
          actions: assign({ currentVoter: ({ event }) => event.voter }),
        },
      },
    },
    voting: {
      on: {
        CHOOSE: {
          actions: assign({ currentChoice: ({ event }) => event.choice }),
        },
        SUBMIT: {
          target: 'submitted',
          actions: assign({
            tally: ({ context }) => {
              if (!context.currentChoice) return context.tally;
              const next = { ...context.tally };
              next[context.currentChoice] += 1;
              return next;
            },
            voted: ({ context }) => {
              const next = new Set(context.voted);
              if (context.currentVoter) next.add(context.currentVoter);
              return next;
            },
          }),
        },
      },
    },
    submitted: { on: { RESET: 'pending' } },
  },
});
