type NotificationEvent =
  | { type: 'NotificationDelivered'; recipientId: string; deliveredAt: string }
  | { type: 'NotificationRead'; recipientId: string; readAt: string }
  | { type: 'NotificationMuted'; recipientId: string };

type InboxView = Readonly<{
  recipientId: string;
  unreadCount: number;
  lastAt: string | null;
  muted: boolean;
}>;

export const emptyView: InboxView = {
  recipientId: '',
  unreadCount: 0,
  lastAt: null,
  muted: false,
};

export function project(view: InboxView, event: NotificationEvent): InboxView {
  switch (event.type) {
    case 'NotificationDelivered':
      if (view.muted) return { ...view, recipientId: event.recipientId, lastAt: event.deliveredAt };
      return {
        ...view,
        recipientId: event.recipientId,
        unreadCount: view.unreadCount + 1,
        lastAt: event.deliveredAt,
      };
    case 'NotificationRead':
      return {
        ...view,
        recipientId: event.recipientId,
        unreadCount: Math.max(0, view.unreadCount - 1),
      };
    case 'NotificationMuted':
      return { ...view, recipientId: event.recipientId, muted: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function buildInbox(events: NotificationEvent[]): InboxView {
  return events.reduce(project, emptyView);
}
