```typescript
type ChannelCommand =
  | { type: 'CreateChannel'; id: string; name: string }
  | { type: 'JoinChannel'; userId: string }
  | { type: 'LeaveChannel'; userId: string }
  | { type: 'LockChannel' };

type ChannelEvent =
  | { type: 'ChannelCreated'; id: string; name: string }
  | { type: 'ChannelJoined'; userId: string }
  | { type: 'ChannelLeft'; userId: string }
  | { type: 'ChannelLocked' };

type ChannelState =
  | { status: 'empty' }
  | { status: 'active'; id: string; members: readonly string[]; locked: boolean };

class ChannelRuleError extends Error {}

export function decide(command: ChannelCommand, state: ChannelState): ChannelEvent[] {
  switch (command.type) {
    case 'CreateChannel':
      if (state.status !== 'empty') throw new ChannelRuleError('exists');
      return [{ type: 'ChannelCreated', id: command.id, name: command.name }];
    case 'JoinChannel':
      if (state.status !== 'active') throw new ChannelRuleError('no channel');
      if (state.locked) throw new ChannelRuleError('locked');
      if (state.members.includes(command.userId)) return [];
      return [{ type: 'ChannelJoined', userId: command.userId }];
    case 'LeaveChannel':
      if (state.status !== 'active' || !state.members.includes(command.userId)) return [];
      return [{ type: 'ChannelLeft', userId: command.userId }];
    case 'LockChannel':
      if (state.status !== 'active' || state.locked) return [];
      return [{ type: 'ChannelLocked' }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: ChannelState, event: ChannelEvent): ChannelState {
  switch (event.type) {
    case 'ChannelCreated':
      return { status: 'active', id: event.id, members: [], locked: false };
    case 'ChannelJoined':
      return state.status === 'active' ? { ...state, members: [...state.members, event.userId] } : state;
    case 'ChannelLeft':
      return state.status === 'active' ? { ...state, members: state.members.filter((m) => m !== event.userId) } : state;
    case 'ChannelLocked':
      return state.status === 'active' ? { ...state, locked: true } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}
