export type LedgerEvent =
  | { type: "AccountOpened"; accountId: string; owner: string }
  | { type: "FundsCredited"; accountId: string; amount: number }
  | { type: "FundsDebited"; accountId: string; amount: number }
  | { type: "AccountFrozen"; accountId: string }
  | { type: "AccountClosed"; accountId: string };

export type LedgerView = Readonly<{
  balances: Readonly<Record<string, number>>;
  owners: Readonly<Record<string, string>>;
  frozen: Readonly<Record<string, boolean>>;
}>;

export const emptyLedger: LedgerView = {
  balances: {},
  owners: {},
  frozen: {},
};

export function project(view: LedgerView, event: LedgerEvent): LedgerView {
  switch (event.type) {
    case "AccountOpened":
      return {
        balances: { ...view.balances, [event.accountId]: 0 },
        owners: { ...view.owners, [event.accountId]: event.owner },
        frozen: { ...view.frozen, [event.accountId]: false },
      };
    case "FundsCredited": {
      const current = view.balances[event.accountId] ?? 0;
      return { ...view, balances: { ...view.balances, [event.accountId]: current + event.amount } };
    }
    case "FundsDebited": {
      const current = view.balances[event.accountId] ?? 0;
      return { ...view, balances: { ...view.balances, [event.accountId]: current - event.amount } };
    }
    case "AccountFrozen":
      return { ...view, frozen: { ...view.frozen, [event.accountId]: true } };
    case "AccountClosed": {
      const balances: Record<string, number> = { ...view.balances };
      delete balances[event.accountId];
      const owners: Record<string, string> = { ...view.owners };
      delete owners[event.accountId];
      const frozen: Record<string, boolean> = { ...view.frozen };
      delete frozen[event.accountId];
      return { balances, owners, frozen };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function ledgerFrom(events: LedgerEvent[]): LedgerView {
  return events.reduce(project, emptyLedger);
}
