  | { type: "IncidentReportAssigned"; assignee: string }
  | { type: "IncidentReportResolved"; at: string };

export type IncidentView = Readonly<{
  id: string;
  severity: "low" | "high";
  assignee?: string;
  resolvedAt?: string;
  status: "open" | "resolved";
}>;

export const emptyIncident: IncidentView = { id: "", severity: "low", status: "open" };

export function project(view: IncidentView, event: IncidentReportEvent): IncidentView {
  switch (event.type) {
    case "IncidentReportOpened":
      return { id: event.id, severity: event.severity, status: "open" };
    case "IncidentReportAssigned":
      return { ...view, assignee: event.assignee };
    case "IncidentReportResolved":
      return { ...view, status: "resolved", resolvedAt: event.at };
    default: { const _n: never = event; return view; }
  }
}

export interface EventStoreReader<E> {
  readBatch(from: bigint, size: number): Promise<ReadonlyArray<{ position: bigint; event: E }>>;
}

export interface ReadStore<V> {
  save(view: V): Promise<void>;
  writeCursor(name: string, pos: bigint): Promise<void>;
}

export async function rebuild(opts: {
  name: string;
  from: bigint;
  batchSize: number;
  reader: EventStoreReader<IncidentReportEvent>;
  store: ReadStore<IncidentView>;
}): Promise<void> {
  let cursor = opts.from;
  let view: IncidentView = emptyIncident;
  const run = async (): Promise<void> => {
    for (;;) {
      const batch = await opts.reader.readBatch(cursor, opts.batchSize);
      if (batch.length === 0) return;
      for (const { event } of batch) {
        view = project(view, event);
      }
      await opts.store.save(view);
      cursor = batch[batch.length - 1].position + 1n;
      await opts.store.writeCursor(opts.name, cursor);
    }
  };
