A single typed `MOVE { id, column, order }` event both changes the card's column and slots it at the requested position. Renumbering every card in the affected column after the move keeps order values dense and avoids drift. The renumbering happens inside one `assign` so the whole transition is atomic.

```typescript
import { setup, assign } from 'xstate';

type Card = { id: string; column: string; order: number };

export const reorderKanban = setup({
  types: {
    context: {} as { cards: Card[] },
    events: {} as { type: 'MOVE'; id: string; column: string; order: number },
  },
}).createMachine({
  id: 'kanban',
  context: { cards: [] },
  on: {
    MOVE: {
      actions: assign({
        cards: ({ context, event }) => {
          const moved = context.cards.map((c) =>
            c.id === event.id ? { ...c, column: event.column, order: event.order } : c,
          );
          const byCol = new Map<string, Card[]>();
          for (const c of moved) {
            const list = byCol.get(c.column) ?? [];
            list.push(c);
            byCol.set(c.column, list);
          }
          const out: Card[] = [];
          for (const [, list] of byCol) {
            list.sort((a, b) => a.order - b.order);
            list.forEach((c, i) => out.push({ ...c, order: i }));
          }
          return out;
        },
      }),
    },
  },
});
```

Read the stream to learn the current revision, append with expectedRevision set to that revision, and convert the store's mismatch error into a typed ConcurrencyConflict at your boundary.

```typescript
type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    stream: string,
    events: readonly E[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  readonly stream: string;
  readonly expected: ExpectedRevision;
  constructor(stream: string, expected: ExpectedRevision) {
    super("concurrency-conflict");
    this.stream = stream;
    this.expected = expected;
    this.name = "ConcurrencyConflict";
  }
}

export type DispatchEvent =
  | { type: "DispatchAssigned"; driverId: string }
  | { type: "DispatchReleased" };

export async function safeAppend(
  store: EventStore<DispatchEvent>,
  stream: string,
  events: readonly DispatchEvent[],
): Promise<bigint> {
  let revision: bigint | undefined;
  for await (const ev of store.readStream(stream)) revision = ev.revision;
  const expected: ExpectedRevision = revision ?? "no_stream";
  try {
    const { nextRevision } = await store.appendToStream(stream, events, { expectedRevision: expected });
    return nextRevision;
  } catch (e) {
    if ((e as { code?: string }).code === "WRONG_EXPECTED_REVISION") {
      throw new ConcurrencyConflict(stream, expected);
    }
    throw e;
  }
}
```

Declare the bound-check as a named guard in `setup.guards` and reference it by string on each transition. Keep the cursor update as a separate `assign` so the guard can veto without mutating context.

