```typescript
export type DiningTableEvent =
  | { type: "TableOpened"; tableNo: number; seats: number }
  | { type: "PartySeated"; tableNo: number; guests: number }
  | { type: "PartyLeft"; tableNo: number }
  | { type: "TableClosed"; tableNo: number };

export type TableInfo = Readonly<{
  tableNo: number;
  seats: number;
  occupied: boolean;
  currentGuests: number;
}>;

export type DiningTableView = Readonly<{
  tables: Readonly<Record<number, TableInfo>>;
  totalSeated: number;
}>;

export const emptyView: DiningTableView = { tables: {}, totalSeated: 0 };

export function project(view: DiningTableView, event: DiningTableEvent): DiningTableView {
  switch (event.type) {
    case "TableOpened": {
      const info: TableInfo = {
        tableNo: event.tableNo,
        seats: event.seats,
        occupied: false,
        currentGuests: 0,
      };
      return { ...view, tables: { ...view.tables, [event.tableNo]: info } };
    }
    case "PartySeated": {
      const existing = view.tables[event.tableNo];
      if (!existing) return view;
      const updated: TableInfo = { ...existing, occupied: true, currentGuests: event.guests };
      return {
        tables: { ...view.tables, [event.tableNo]: updated },
        totalSeated: view.totalSeated + event.guests,
      };
    }
    case "PartyLeft": {
      const existing = view.tables[event.tableNo];
      if (!existing) return view;
      const updated: TableInfo = { ...existing, occupied: false, currentGuests: 0 };
      return {
        tables: { ...view.tables, [event.tableNo]: updated },
        totalSeated: view.totalSeated - existing.currentGuests,
      };
    }
    case "TableClosed": {
      const next = { ...view.tables };
      delete next[event.tableNo];
      return { ...view, tables: next };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function projectAll(events: DiningTableEvent[]): DiningTableView {
  return events.reduce(project, emptyView);
}
