export type BenefactorRegistryEvent =
  | { type: "registered"; benefactorId: string; name: string }
  | { type: "honored"; benefactorId: string; tier: string };

export interface StoredEvent<E> { globalPosition: bigint; event: E }

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventStreamSource<E> {
  readFromStream(from: bigint): AsyncIterable<StoredEvent<E>>;
}

export interface BenefactorReadStore {
  upsert(id: string, name: string): Promise<void>;
  setTier(id: string, tier: string): Promise<void>;
}

export async function runSubscription(
  name: string,
  source: EventStreamSource<BenefactorRegistryEvent>,
  store: BenefactorReadStore,
  checkpoints: CheckpointStore,
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? 0n;
  for await (const stored of source.readFromStream(start)) {
    const event = stored.event;
    switch (event.type) {
      case "registered":
        await store.upsert(event.benefactorId, event.name);
        break;
      case "honored":
        await store.setTier(event.benefactorId, event.tier);
        break;
      default: {
        const _: never = event;
        return _;
      }
    }
    await checkpoints.write(name, stored.globalPosition);
  }
}
