```typescript
export interface DefectEvent { type: string; body: unknown; }

export type ExpectedRevision = bigint | "no_stream" | "any";

export type AppendOutcome =
  | { kind: "ok"; nextRevision: bigint }
  | { kind: "WrongExpectedVersion"; actual: bigint | "no_stream" };

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: DefectEvent; revision: bigint }>;
  appendToStream(
    stream: string,
    events: DefectEvent[],
    opts: { expectedRevision: ExpectedRevision }
  ): Promise<AppendOutcome>;
}

export class ConcurrencyConflict extends Error {
  constructor(
    readonly stream: string,
    readonly expected: ExpectedRevision,
    readonly actual: bigint | "no_stream"
  ) {
    super("CONFLICT");
    this.name = "ConcurrencyConflict";
  }
}

export async function appendDefectEvents(
  store: EventStore,
  stream: string,
  events: DefectEvent[]
): Promise<bigint> {
  let expected: ExpectedRevision = "no_stream";
  for await (const entry of store.readStream(stream)) {
    expected = entry.revision;
  }
  const outcome = await store.appendToStream(stream, events, { expectedRevision: expected });
  if (outcome.kind === "WrongExpectedVersion") {
    throw new ConcurrencyConflict(stream, expected, outcome.actual);
  }
  return outcome.nextRevision;
}
