```typescript
import { Effect } from "effect";

export type CheckpointState =
  | { status: "none" }
  | { status: "created"; id: string }
  | { status: "promoted"; id: string; stage: string };

export type CheckpointCommand =
  | { type: "create"; id: string }
  | { type: "promote"; stage: string };

export type CheckpointEvent =
  | { type: "CheckpointCreated"; id: string }
  | { type: "CheckpointPromoted"; stage: string };

const initial: CheckpointState = { status: "none" };

function evolve(state: CheckpointState, event: CheckpointEvent): CheckpointState {
  switch (event.type) {
    case "CheckpointCreated":
      return { status: "created", id: event.id };
    case "CheckpointPromoted":
      return state.status === "created" ? { status: "promoted", id: state.id, stage: event.stage } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: CheckpointCommand, state: CheckpointState): CheckpointEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "CheckpointCreated", id: command.id }];
    case "promote":
      if (state.status !== "created") throw new Error("BAD_STATE");
      return [{ type: "CheckpointPromoted", stage: command.stage }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export class ConcurrencyConflict extends Error { readonly _tag = "ConcurrencyConflict"; }

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ ok: boolean }>;
}

export const handle = (command: CheckpointCommand, ctx: { streamName: string; eventStore: EventStore }) =>
  Effect.gen(function* () {
    const read = yield* Effect.promise(() => ctx.eventStore.readStream<CheckpointEvent>(ctx.streamName));
    const state = read.events.reduce(evolve, initial);
    const events = decide(command, state);
    const result = yield* Effect.promise(() => ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision }));
    if (!result.ok) yield* Effect.fail(new ConcurrencyConflict("conflict"));
  });
