export class DomainError extends Error {}

export type FieldAgentState =
  | { status: "none" }
  | { status: "recruited"; id: string; region: string }
  | { status: "active"; id: string; region: string; since: string }
  | { status: "retired"; id: string; retiredAt: string };

export type FieldAgentCommand =
  | { type: "recruit"; id: string; region: string }
  | { type: "activate"; since: string }
  | { type: "retire"; at: string };

export type FieldAgentEvent =
  | { type: "recruited"; id: string; region: string }
  | { type: "activated"; since: string }
  | { type: "retired"; at: string };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const FieldAgentDecider: Decider<FieldAgentCommand, FieldAgentEvent, FieldAgentState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "recruit":
        if (s.status !== "none") throw new DomainError("exists");
        return [{ type: "recruited", id: c.id, region: c.region }];
      case "activate":
        if (s.status === "retired") throw new DomainError("retired");
        if (s.status !== "recruited") throw new DomainError("must be recruited");
        return [{ type: "activated", since: c.since }];
      case "retire":
        if (s.status === "retired" || s.status === "none") throw new DomainError("invalid");
        return [{ type: "retired", at: c.at }];
      default: {
        const _: never = c;
        return _;
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "recruited":
        return { status: "recruited", id: e.id, region: e.region };
      case "activated":
        return s.status === "recruited" ? { status: "active", id: s.id, region: s.region, since: e.since } : s;
      case "retired":
        if (s.status === "active" || s.status === "recruited") return { status: "retired", id: s.id, retiredAt: e.at };
        return s;
      default: {
        const _: never = e;
        return _;
      }
    }
  },
};
