```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

A rebuild wipes the read model and replays events from revision 0 through the current head in batches, persisting the folded view and a cursor after each chunk. The `from` option lets the operator resume a partially-completed rebuild without starting over.

```typescript
export interface YieldEvent { type: string; revision: bigint; payload: unknown; }
export interface YieldView { totalEntries: number; finalized: number; lastRevision: bigint; }

export const emptyView: YieldView = { totalEntries: 0, finalized: 0, lastRevision: -1n };

export function project(view: YieldView, event: YieldEvent): YieldView {
  if (event.type === "EntryRecorded") return { ...view, totalEntries: view.totalEntries + 1, lastRevision: event.revision };
  if (event.type === "ReportFinalized") return { ...view, finalized: view.finalized + 1, lastRevision: event.revision };
  return { ...view, lastRevision: event.revision };
}

export interface EventStoreIterator {
  readBatch(from: bigint, size: number): Promise<YieldEvent[]>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStoreIterator;
  persist: (view: YieldView) => Promise<void>;
  initial: YieldView;
}): Promise<void> {
  let cursor = opts.from;
  let view = opts.initial;
  while (true) {
    const batch = await opts.store.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const event of batch) {
      view = project(view, event);
    }
    await opts.persist(view);
    cursor = batch[batch.length - 1].revision + 1n;
  }
}
```

A projection is a distinct fold from the aggregate `evolve`: it denormalises events into a query-friendly shape and returns the view unchanged for events outside its interest.

