export interface NotarisationEvent {
  readonly type: "NotarisationRequested" | "NotarisationCompleted";
  readonly notarisationId: string;
  readonly position: bigint;
}

export interface View { readonly pending: ReadonlyArray<string>; readonly completed: number; }
export const emptyView: View = { pending: [], completed: 0 };

export function project(view: View, event: NotarisationEvent): View {
  switch (event.type) {
    case "NotarisationRequested":
      if (view.pending.includes(event.notarisationId)) return view;
      return { ...view, pending: [...view.pending, event.notarisationId] };
    case "NotarisationCompleted":
      return {
        pending: view.pending.filter((id) => id !== event.notarisationId),
        completed: view.completed + 1,
      };
    default: { const _n: never = event.type; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed { readFrom(pos: bigint | null): AsyncIterable<NotarisationEvent>; }
export interface ViewStore { read(): Promise<View>; write(v: View): Promise<void>; }

export async function runSubscription(
  name: string, feed: EventFeed, checkpoints: CheckpointStore, store: ViewStore,
): Promise<void> {
  async function main(): Promise<void> {
    const from = await checkpoints.read(name);
    let view = await store.read();
    for await (const event of feed.readFrom(from)) {
      view = project(view, event);
      await store.write(view);
      await checkpoints.write(name, event.position);
    }
  }
  await main();
}
