export function project(view: PayoutLedgerView, event: PayoutEvent): PayoutLedgerView {
  switch (event.type) {
    case "PayoutRequested": {
      const row: PayoutLedgerRow = {
        id: event.id,
        amount: event.amount,
        requestedBy: event.requestedBy,
        approver: null,
        approvedAt: null,
        executedAt: null,
        reference: null,
      };
      return { rows: { ...view.rows, [event.id]: row } };
    }
    case "PayoutApproved": {
      const row = view.rows[event.id];
      if (!row) return view;
      return { rows: { ...view.rows, [event.id]: { ...row, approver: event.approver, approvedAt: event.at } } };
