      return { rows: { ...view.rows, [event.id]: { ...row, executedAt: event.executedAt, reference: event.reference } } };
    }
    case "PayoutMemoAdded":
      // memos are surfaced by another view
      return view;
    default: { const _n: never = event; return view; }
  }
}
