export type NutritionProfileEvent =
  | { type: "NutritionProfileOpened"; id: string }
  | { type: "NutritionMacrosDeclared"; id: string; calories: number };

export interface NutritionView {
  readonly id: string;
  readonly totalCalories: number;
  readonly entries: number;
}

export function project(view: NutritionView, event: NutritionProfileEvent): NutritionView {
  switch (event.type) {
    case "NutritionProfileOpened":
      return { id: event.id, totalCalories: 0, entries: 0 };
    case "NutritionMacrosDeclared":
      return { ...view, id: event.id, totalCalories: view.totalCalories + event.calories, entries: view.entries + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface EventPage<E> {
  readonly events: ReadonlyArray<{ position: bigint; event: E }>;
  readonly nextCursor: bigint | null;
}

export interface EventStore<E> {
  readBatch(from: bigint, batchSize: number): Promise<EventPage<E>>;
}

export interface ReadStore {
  upsert(id: string, view: NutritionView): Promise<void>;
  get(id: string): Promise<NutritionView | null>;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  store: EventStore<NutritionProfileEvent>;
  read: ReadStore;
  onProgress?: (cursor: bigint) => void;
}

export async function rebuild(opts: RebuildOptions): Promise<void> {
  let cursor: bigint | null = opts.from;
  while (cursor !== null) {
    const page = await opts.store.readBatch(cursor, opts.batchSize);
    for (const { event } of page.events) {
      const id = "id" in event ? event.id : "";
      const current = (await opts.read.get(id)) ?? { id, totalCalories: 0, entries: 0 };
      const next = project(current, event);
      await opts.read.upsert(id, next);
    }
    if (page.events.length > 0) opts.onProgress?.(page.events[page.events.length - 1]!.position);
    cursor = page.nextCursor;
  }
}

