```typescript
export type ManifestCommand =
  | { type: "open"; id: string; carrier: string }
  | { type: "addParcel"; parcelId: string; weight: number }
  | { type: "seal"; at: string };

export type ManifestEvent =
  | { type: "ManifestOpened"; id: string; carrier: string }
  | { type: "ParcelAdded"; parcelId: string; weight: number }
  | { type: "ManifestSealed"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(s: string): Promise<{ events: ManifestEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: ManifestEvent[], o: { expectedRevision: ExpectedRevision }): Promise<{ ok: true; nextRevision: bigint } | { ok: false }>;
}

export class ConcurrencyConflict extends Error {}
export class ManifestError extends Error {}

function decide(command: ManifestCommand, events: ManifestEvent[]): ManifestEvent[] {
  const opened = events.some((e) => e.type === "ManifestOpened");
  const sealed = events.some((e) => e.type === "ManifestSealed");
  switch (command.type) {
    case "open":
      if (opened) throw new ManifestError("ALREADY_OPEN");
      return [{ type: "ManifestOpened", id: command.id, carrier: command.carrier }];
    case "addParcel":
      if (!opened) throw new ManifestError("NOT_OPEN");
      if (sealed) throw new ManifestError("ALREADY_SEALED");
      return [{ type: "ParcelAdded", parcelId: command.parcelId, weight: command.weight }];
    case "seal":
      if (!opened) throw new ManifestError("NOT_OPEN");
      if (sealed) throw new ManifestError("ALREADY_SEALED");
      return [{ type: "ManifestSealed", at: command.at }];
    default: {
      const _n: never = command;
      throw new ManifestError("UNKNOWN");
    }
  }
}

export async function handle(
  store: EventStore,
  stream: string,
  command: ManifestCommand,
): Promise<bigint> {
  const { events, revision } = await store.readStream(stream);
  const newEvents = decide(command, events);
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  const result = await store.appendToStream(stream, newEvents, { expectedRevision });
  if (!result.ok) throw new ConcurrencyConflict();
  return result.nextRevision;
}
