import { Effect } from "effect";

export type CertificateState =
  | { status: "none" }
  | { status: "issued"; id: string; learner: string; courseId: string; at: string }
  | { status: "revoked"; id: string; reason: string };

export type CertificateCommand =
  | { type: "issue"; id: string; learner: string; courseId: string; at: string }
  | { type: "revoke"; reason: string };

export type CertificateEvent =
  | { type: "CertificateIssued"; id: string; learner: string; courseId: string; at: string }
  | { type: "CertificateRevoked"; reason: string };

export class CertificateError extends Error {}

export const initialState: CertificateState = { status: "none" };

export function evolve(s: CertificateState, e: CertificateEvent): CertificateState {
  switch (e.type) {
    case "CertificateIssued":
      return { status: "issued", id: e.id, learner: e.learner, courseId: e.courseId, at: e.at };
    case "CertificateRevoked":
      if (s.status !== "issued") return s;
      return { status: "revoked", id: s.id, reason: e.reason };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: CertificateCommand, s: CertificateState): CertificateEvent[] {
  switch (c.type) {
    case "issue":
      if (s.status !== "none") throw new CertificateError("EXISTS");
      return [{ type: "CertificateIssued", id: c.id, learner: c.learner, courseId: c.courseId, at: c.at }];
    case "revoke":
      if (s.status !== "issued") throw new CertificateError("NOT_ISSUED");
      return [{ type: "CertificateRevoked", reason: c.reason }];
    default: { const _n: never = c; throw new CertificateError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<CertificateEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<CertificateEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handleCertificateCommand = (
  streamName: string,
  command: CertificateCommand,
  store: EventStore,
) =>
  Effect.gen(function* () {
    const slice = yield* Effect.promise(() => store.readStream(streamName));
    const state = slice.events.reduce(evolve, initialState);
    const next = decide(command, state);
    if (next.length === 0) return slice.revision ?? 0n;
    const revision = yield* Effect.promise(() =>
      store.appendToStream(streamName, next, { expectedRevision: slice.revision ?? "no_stream" }),
    );
    return revision;
  });
