export interface FormularyState {
  readonly drugs: Record<string, { code: string; name: string; tier: number; active: boolean }>;
}

interface V1 { drugs: Record<string, { code: string; name: string }> }
interface V2 { drugs: Record<string, { code: string; name: string; tier: number }> }

export interface Snapshot<S> { readonly version: number; readonly state: S }
export const CURRENT_VERSION = 3 as const;

function v1Tov2(s: V1): V2 {
  const out: V2["drugs"] = {};
  for (const code of Object.keys(s.drugs)) {
    const d = s.drugs[code];
    out[code] = { ...d, tier: 3 };
  }
  return { drugs: out };
}

function v2Tov3(s: V2): FormularyState {
  const out: FormularyState["drugs"] = {};
  for (const code of Object.keys(s.drugs)) {
    out[code] = { ...s.drugs[code], active: true };
  }
  return { drugs: out };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<FormularyState> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v === 1) { state = v1Tov2(state as V1); v = 2; }
  if (v === 2) { state = v2Tov3(state as V2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION:${snap.version}`);
  return { version: CURRENT_VERSION, state: state as FormularyState };
}
