import { Effect } from "effect";

export class DomainError extends Error {}

export type OutreachVisitState =
  | { status: "none" }
  | { status: "scheduled"; id: string }
  | { status: "inProgress"; id: string };

export type OutreachVisitCommand =
  | { type: "schedule"; id: string; at: string }
  | { type: "start"; at: string };

export type OutreachVisitEvent =
  | { type: "scheduled"; id: string; at: string }
  | { type: "started"; at: string };

const initialState: OutreachVisitState = { status: "none" };

function evolve(s: OutreachVisitState, e: OutreachVisitEvent): OutreachVisitState {
  switch (e.type) {
    case "scheduled":
      return { status: "scheduled", id: e.id };
    case "started":
      return s.status === "scheduled" ? { status: "inProgress", id: s.id } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: OutreachVisitCommand, s: OutreachVisitState): OutreachVisitEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new DomainError("exists");
      return [{ type: "scheduled", id: c.id, at: c.at }];
    case "start":
      if (s.status !== "scheduled") throw new DomainError("not scheduled");
      return [{ type: "started", at: c.at }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface StoredEvent<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(s: string): Promise<StoredEvent<E>[]>;
  appendToStream(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export function handle(
  command: OutreachVisitCommand,
  ctx: { streamName: string; eventStore: EventStore<OutreachVisitEvent> },
): Effect.Effect<void, Error, never> {
  return Effect.gen(function* () {
    const stored = yield* Effect.promise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = stored.reduce<OutreachVisitState>((s, r) => evolve(s, r.event), initialState);
    const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
    const newEvents = decide(command, state);
    yield* Effect.promise(() => ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision }));
  });
}
