  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | null }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<bigint>;
