export type FlightCommand =
  | { type: "schedule"; id: string; gate: string }
  | { type: "takeoff"; at: string };

export type FlightEvent =
  | { type: "FlightScheduled"; id: string; gate: string }
  | { type: "FlightDeparted"; at: string };

export type FlightState =
  | { status: "none" }
  | { status: "scheduled"; id: string; gate: string }
  | { status: "airborne"; id: string; at: string };

export class FlightError extends Error {}

export const flightDecider: Decider<FlightCommand, FlightEvent, FlightState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new FlightError("EXISTS");
        return [{ type: "FlightScheduled", id: command.id, gate: command.gate }];
      case "takeoff":
        if (state.status !== "scheduled") throw new FlightError("NOT_READY");
        return [{ type: "FlightDeparted", at: command.at }];
      default: {
        const _n: never = command;
        throw new FlightError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FlightScheduled":
        return { status: "scheduled", id: event.id, gate: event.gate };
      case "FlightDeparted":
        if (state.status !== "scheduled") return state;
        return { status: "airborne", id: state.id, at: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

export const handleFlight = (store: EventStore<FlightEvent>) => (stream: string, command: FlightCommand) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => store.readStream(stream));
    const state = events.reduce(flightDecider.evolve, flightDecider.initialState);
    const newEvents = flightDecider.decide(command, state);
    if (newEvents.length === 0) return revision;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() => store.appendToStream(stream, newEvents, { expectedRevision }));
  });
