import { Effect } from "effect";

export type VotingCommand =
  | { type: "open"; id: string; at: string }
  | { type: "castVote"; id: string };

export type VotingEvent =
  | { type: "Opened"; id: string; at: string }
  | { type: "VoteCast"; id: string };

export type WriteState =
  | { status: "none" }
  | { status: "open"; id: string; votes: number };

export class DomainError extends Error {}
export class ConcurrencyConflict extends Error {}

export const initial: WriteState = { status: "none" };

export function decide(cmd: VotingCommand, s: WriteState): VotingEvent[] {
  switch (cmd.type) {
    case "open":
      if (s.status !== "none") throw new DomainError("already open");
      return [{ type: "Opened", id: cmd.id, at: cmd.at }];
    case "castVote":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "VoteCast", id: cmd.id }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export function evolve(s: WriteState, e: VotingEvent): WriteState {
  switch (e.type) {
    case "Opened":
      return { status: "open", id: e.id, votes: 0 };
    case "VoteCast":
      return s.status === "open" ? { ...s, votes: s.votes + 1 } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<VotingEvent[]>;
  appendToStream(stream: string, events: VotingEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
  currentRevision(stream: string): Promise<bigint | null>;
}

export type SessionSummary = { id: string; totalVotes: number };
export interface ReadStore { find(id: string): Promise<SessionSummary | null> }

export function handleCommand(store: EventStore, streamName: string, cmd: VotingCommand): Effect.Effect<void, DomainError | ConcurrencyConflict> {
  return Effect.gen(function* () {
    const events = yield* Effect.promise(() => store.readStream(streamName));
    const state = events.reduce(evolve, initial);
    const next = decide(cmd, state);
    const rev = yield* Effect.promise(() => store.currentRevision(streamName));
    yield* Effect.tryPromise({
      try: () => store.appendToStream(streamName, next, { expectedRevision: rev ?? "no_stream" }),
      catch: () => new ConcurrencyConflict(),
    });
  });
}

// The read store is eventually consistent with the event store.
export function queryView(reads: ReadStore, id: string): Effect.Effect<SessionSummary | null> {
  return Effect.promise(() => reads.find(id));
}
