        return [{ type: "HarvestWindowOpened", id: command.id, startsAt: command.startsAt, endsAt: command.endsAt }];
      case "extend":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "HarvestWindowExtended", newEndsAt: command.newEndsAt }];
      case "close":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "HarvestWindowClosed", at: command.at }];
      case "cancel":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "HarvestWindowCancelled", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "HarvestWindowOpened":
        return { status: "open", id: event.id, startsAt: event.startsAt, endsAt: event.endsAt };
      case "HarvestWindowExtended":
        if (state.status !== "open") return state;
        return { ...state, endsAt: event.newEndsAt };
      case "HarvestWindowClosed":
        if (state.status !== "open") return state;
        return { status: "closed", id: state.id, closedAt: event.at };
