export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type Command =
  | { type: 'Issue'; authority: string; validUntil: string }
  | { type: 'Amend'; clause: string }
  | { type: 'Revoke'; reason: string };

type Event =
  | { type: 'PermitIssued'; authority: string; validUntil: string }
  | { type: 'PermitAmended'; clause: string }
  | { type: 'PermitRevoked'; reason: string };

type State =
  | { status: 'pending' }
  | { status: 'active'; authority: string; amendments: number }
  | { status: 'revoked'; reason: string };

class InvariantError extends Error {}

export const EnvironmentalPermit: Decider<Command, Event, State> = {
  initialState: { status: 'pending' },
  decide(command, state) {
    switch (command.type) {
      case 'Issue':
        if (state.status !== 'pending') throw new InvariantError('not pending');
        return [{ type: 'PermitIssued', authority: command.authority, validUntil: command.validUntil }];
      case 'Amend':
        if (state.status !== 'active') throw new InvariantError('must be active');
        return [{ type: 'PermitAmended', clause: command.clause }];
      case 'Revoke':
        if (state.status !== 'active') throw new InvariantError('cannot revoke');
        return [{ type: 'PermitRevoked', reason: command.reason }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'PermitIssued':
        return { status: 'active', authority: event.authority, amendments: 0 };
      case 'PermitAmended':
        return state.status === 'active' ? { ...state, amendments: state.amendments + 1 } : state;
      case 'PermitRevoked':
        return { status: 'revoked', reason: event.reason };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
