export interface EventRecord<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface EventFeed<E> {
  subscribe(from: bigint): AsyncIterable<EventRecord<E>>;
}

export interface AllergenIndex {
  add(recipeId: string, allergen: string): Promise<void>;
  remove(recipeId: string, allergen: string): Promise<void>;
}

export type IndexAction =
  | { op: "add"; recipeId: string; allergen: string }
  | { op: "remove"; recipeId: string; allergen: string };

export function project(event: AllergenTagEvent): IndexAction {
  switch (event.type) {
    case "AllergenTagged":
      return { op: "add", recipeId: event.recipeId, allergen: event.allergen };
    case "AllergenRemoved":
      return { op: "remove", recipeId: event.recipeId, allergen: event.allergen };
    default: {
      const _n: never = event;
      throw new Error("unknown event");
    }
  }
}

export async function runAllergenSubscription(
  name: string,
  feed: EventFeed<AllergenTagEvent>,
  index: AllergenIndex,
  checkpoints: CheckpointStore,
): Promise<void> {
  const from: bigint = (await checkpoints.read(name)) ?? 0n;
  async function main(): Promise<void> {
    for await (const { position, event } of feed.subscribe(from)) {
      const action = project(event);
      if (action.op === "add") await index.add(action.recipeId, action.allergen);
      else await index.remove(action.recipeId, action.allergen);
      await checkpoints.write(name, position);
    }
  }
