type PoolEvent =
  | { type: 'FundsContributed'; amount: number }
  | { type: 'PayoutMade'; amount: number };

type PoolView = { readonly balance: number };

function project(view: PoolView, event: PoolEvent): PoolView {
  switch (event.type) {
    case 'FundsContributed': return { balance: view.balance + event.amount };
    case 'PayoutMade': return { balance: view.balance - event.amount };
    default: { const _e: never = event; return _e; }
  }
}

interface Cursor {
  readBatch(from: bigint, size: number): Promise<{ events: readonly PoolEvent[]; nextFrom: bigint; done: boolean }>;
}

interface CheckpointStore {
  read(): Promise<bigint>;
  write(pos: bigint): Promise<void>;
}

export async function rebuild(cursor: Cursor, checkpoints: CheckpointStore, batchSize: number): Promise<PoolView> {
  let view: PoolView = { balance: 0 };
  let from = await checkpoints.read();
  for (;;) {
    const batch = await cursor.readBatch(from, batchSize);
    for (const ev of batch.events) view = project(view, ev);
    from = batch.nextFrom;
    await checkpoints.write(from);
    if (batch.done) return view;
  }
}
