```typescript
export type Snapshot<S> = { version: number; state: S };

export type GuestStayV1 = { id: string; guest: string };
export type GuestStayV2 = { id: string; guest: string; nights: number };
export type GuestStayV3 = { id: string; guest: string; nights: number; totalCents: number };

export type CurrentGuestStay = GuestStayV3;
export const CURRENT_VERSION = 3;

export class SnapshotUpgradeError extends Error {}

function v1Tov2(s: GuestStayV1): GuestStayV2 {
  return { ...s, nights: 0 };
}

function v2Tov3(s: GuestStayV2): GuestStayV3 {
  return { ...s, totalCents: 0 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentGuestStay> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new SnapshotUpgradeError(`UNSUPPORTED_VERSION_${version}`);
  }
  if (version === 1) {
    state = v1Tov2(state as GuestStayV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as GuestStayV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new SnapshotUpgradeError("UPGRADE_INCOMPLETE");
  }
  const upgraded = state as CurrentGuestStay;
  if (typeof upgraded.id !== "string" || typeof upgraded.nights !== "number") {
    throw new SnapshotUpgradeError("SHAPE_MISMATCH");
  }
  return { version, state: upgraded };
}

export function loadGuestStay(raw: Snapshot<unknown>): CurrentGuestStay {
  return upgradeSnapshot(raw).state;
}
