  | { type: "RefundInitiated"; id: string; amount: number }
  | { type: "RefundSettled" };

export const initialState: RefundState = { status: "none" };

export function evolve(state: RefundState, event: RefundEvent): RefundState {
  switch (event.type) {
    case "RefundInitiated":
      return { status: "pending", id: event.id, amount: event.amount };
    case "RefundSettled":
      if (state.status !== "pending") return state;
      return { status: "settled", id: state.id, amount: state.amount };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregate(events: ReadonlyArray<RefundEvent>): RefundState {
  return events.reduce(evolve, initialState);
}
