export type OrderState =
  | { status: "none" }
  | { status: "placed"; id: string; total: number }
  | { status: "paid"; id: string; total: number; paidAt: string }
  | { status: "fulfilled"; id: string; total: number };

export type OrderCommand =
  | { type: "place"; id: string; total: number }
  | { type: "pay"; at: string }
  | { type: "fulfil" };

export type OrderEvent =
  | { type: "OrderPlaced"; id: string; total: number }
  | { type: "OrderPaid"; at: string }
  | { type: "OrderFulfilled" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const orderDecider: Decider<OrderCommand, OrderEvent, OrderState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "place":
        if (state.status !== "none") throw new DomainError("ALREADY_PLACED");
        if (command.total <= 0) throw new DomainError("NON_POSITIVE_TOTAL");
        return [{ type: "OrderPlaced", id: command.id, total: command.total }];
      case "pay":
        if (state.status !== "placed") throw new DomainError("NOT_PLACED");
        return [{ type: "OrderPaid", at: command.at }];
      case "fulfil":
        if (state.status !== "paid") throw new DomainError("NOT_PAID");
        return [{ type: "OrderFulfilled" }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "OrderPlaced":
        return { status: "placed", id: event.id, total: event.total };
      case "OrderPaid":
        if (state.status !== "placed") return state;
        return { status: "paid", id: state.id, total: state.total, paidAt: event.at };
      case "OrderFulfilled":
        if (state.status !== "paid") return state;
        return { status: "fulfilled", id: state.id, total: state.total };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
