An `invoke` in v5 is scoped to the state that owns it. Leaving that state stops the invoked actor automatically — any promise is abandoned and its `onDone`/`onError` won't fire. So the cancel semantics come for free: a transition out of the `printing` state is the cancel.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Job { readonly id: string }
interface Ctx { readonly queue: readonly Job[]; readonly current: Job | null }
type Ev = { type: 'ENQUEUE'; job: Job } | { type: 'CANCEL' };

export const printer = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { print: fromPromise<void, { job: Job }>(async () => undefined) }
}).createMachine({
  id: 'p',
  initial: 'idle',
  context: { queue: [], current: null },
  states: {
    idle: {
      on: {
        ENQUEUE: {
          target: 'printing',
          actions: assign({
            current: ({ event }) => event.job,
            queue: ({ context, event }) => [...context.queue, event.job].slice(1)
          })
        }
      }
    },
    printing: {
      invoke: {
        src: 'print',
        input: ({ context }) => ({ job: context.current as Job }),
        onDone: 'idle'
      },
      on: { CANCEL: { target: 'idle', actions: assign({ current: () => null }) } }
    }
  }
});
