```typescript
export type PortfolioEvent =
  | { type: "PortfolioOpened"; id: string }
  | { type: "HoldingAdded"; units: number };

export interface EventStore {
  readStream(stream: string): Promise<{ revision: bigint; events: PortfolioEvent[] }>;
  appendToStream(
    stream: string,
    events: PortfolioEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) { super(`Conflict on ${stream}`); }
}

export async function appendWithRetry(
  store: EventStore,
  stream: string,
  build: (events: PortfolioEvent[]) => PortfolioEvent[],
  maxAttempts = 3,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    const { revision, events } = await store.readStream(stream);
    const expectedRevision: bigint | "no_stream" = events.length === 0 ? "no_stream" : revision;
    const newEvents = build(events);
    try {
      const r = await store.appendToStream(stream, newEvents, { expectedRevision });
      return r.nextExpectedRevision;
    } catch (err) {
      const e = err as { code?: string };
      if (e.code !== "WrongExpectedVersion") throw err;
      attempt += 1;
    }
  }
  throw new ConcurrencyConflict(stream);
}

```

```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

Writing the checkpoint before the projection risks losing an event: if the projection throws, the checkpoint has already advanced and the runner will skip the failed event on restart. Persist side effects first, then commit the cursor — crash-safe replay depends on exactly that ordering.

```typescript
export type RecipeTestEvent =
  | { type: "RecipeTestStarted"; testId: string; recipeId: string }
  | { type: "RecipeTestRated"; testId: string; rating: number };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventRecord<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface EventFeed<E> {
  subscribe(from: bigint): AsyncIterable<EventRecord<E>>;
}

export interface RecipeTestRow {
  readonly testId: string;
  readonly recipeId: string;
  readonly rating: number | null;
}

export interface ReadStore {
  upsert(row: RecipeTestRow): Promise<void>;
  get(id: string): Promise<RecipeTestRow | null>;
}

export function project(
  existing: RecipeTestRow | null,
  event: RecipeTestEvent,
): RecipeTestRow | null {
  switch (event.type) {
    case "RecipeTestStarted":
      return { testId: event.testId, recipeId: event.recipeId, rating: null };
    case "RecipeTestRated":
      return existing ? { ...existing, rating: event.rating } : null;
    default: {
      const _n: never = event;
      return existing;
    }
  }
}

export async function runSubscription(
  name: string,
  feed: EventFeed<RecipeTestEvent>,
  read: ReadStore,
  checkpoints: CheckpointStore,
): Promise<void> {
  const from = (await checkpoints.read(name)) ?? 0n;
  async function main(): Promise<void> {
    for await (const { position, event } of feed.subscribe(from)) {
      const existing = await read.get(event.testId);
      const next = project(existing, event);
      if (next) await read.upsert(next);
      await checkpoints.write(name, position);
    }
  }
  await main();
}

