import { Effect } from "effect";

export interface AppendOptions {
  expectedRevision: bigint | "no_stream" | "any";
}

export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], options: AppendOptions): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict {
  readonly _tag = "ConcurrencyConflict";
  constructor(readonly stream: string) {}
}

export class StoreError {
  readonly _tag = "StoreError";
  constructor(readonly cause: unknown) {}
}

export type AudienceSegmentEvent =
  | { type: "AudienceSegmentDefined"; id: string }
  | { type: "AudienceSegmentRuleAdded"; rule: string };

export function appendAudienceSegment(
  store: EventStore,
  stream: string,
  events: AudienceSegmentEvent[],
  expectedRevision: bigint | "no_stream" | "any",
): Effect.Effect<bigint, ConcurrencyConflict | StoreError> {
  return Effect.gen(function* () {
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream<AudienceSegmentEvent>(stream, events, { expectedRevision }),
      catch: (cause) => {
        if (cause instanceof Error && cause.message.includes("WrongExpectedVersion")) {
          return new ConcurrencyConflict(stream);
        }
        return new StoreError(cause);
      },
    });
    return result.nextRevision;
  });
}
