```typescript
export type SummitAttemptEvent =
  | { type: "SummitAttemptStarted"; id: string; peak: string; idempotencyKey: string }
  | { type: "CheckpointReached"; name: string; idempotencyKey: string };

export type SummitAttemptState = {
  readonly keys: ReadonlySet<string>;
  readonly started: boolean;
};

export const initialState: SummitAttemptState = { keys: new Set(), started: false };

export function evolve(state: SummitAttemptState, event: SummitAttemptEvent): SummitAttemptState {
  switch (event.type) {
    case "SummitAttemptStarted":
      return { keys: new Set([...state.keys, event.idempotencyKey]), started: true };
    case "CheckpointReached":
      return { keys: new Set([...state.keys, event.idempotencyKey]), started: state.started };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export interface StartCommand {
  readonly type: "start";
  readonly id: string;
  readonly peak: string;
  readonly idempotencyKey: string;
}

export function decide(command: StartCommand, state: SummitAttemptState): SummitAttemptEvent[] {
  if (state.keys.has(command.idempotencyKey)) return [];
  if (state.started) throw new Error("ALREADY_STARTED");
  return [
    {
      type: "SummitAttemptStarted",
      id: command.id,
      peak: command.peak,
      idempotencyKey: command.idempotencyKey,
    },
  ];
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: ReadonlyArray<E>; revision: ExpectedRevision }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
}

export async function handle(
  store: EventStore<SummitAttemptEvent>,
  streamName: string,
  command: StartCommand,
): Promise<void> {
  const loaded = await store.readStream(streamName);
  let state = initialState;
  for (const event of loaded.events) {
    state = evolve(state, event);
  }
  const events = decide(command, state);
  if (events.length === 0) return;
  await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
}
```

