Apply the event to the projection, persist the view, then write the checkpoint - in that order. A crash between any two steps replays at most one event.

```typescript
import { Effect } from "effect";

export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, p: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(position: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface Projection<V, E> {
  load(): Promise<V>;
  apply(v: V, e: E): Promise<V>;
  save(v: V): Promise<void>;
}

export const runSubscriptionEffect = <V, E>(
  name: string,
  source: EventSource<E>,
  checkpoints: CheckpointStore,
  projection: Projection<V, E>,
) =>
  Effect.gen(function* () {
    const start = yield* Effect.promise(() => checkpoints.read(name));
    const from: bigint = start ?? 0n;
    let view = yield* Effect.promise(() => projection.load());
    const run = async (): Promise<void> => {
      for await (const { position, event } of source.readFrom(from)) {
        view = await projection.apply(view, event);
        await projection.save(view);
        await checkpoints.write(name, position);
      }
    };
    yield* Effect.promise(() => run());
  });
```

