Snapshots persist aggregate state with a version tag. On load the loader runs upgraders from the stored version up to CURRENT_VERSION, so rolling schema changes never require rewriting the event stream.

```typescript
export interface CourierProfile {
  readonly id: string;
  readonly name: string;
  readonly status: "online" | "offline" | "offboarded";
  readonly vehicleId: string | null;
}

export type Snapshot<S> = { version: number; state: S };
export const CURRENT_VERSION = 3;

interface CourierV1 { id: string; name: string; online: boolean }
interface CourierV2 { id: string; name: string; status: "online" | "offline" | "offboarded" }

function v1Tov2(snap: Snapshot<CourierV1>): Snapshot<CourierV2> {
  return { version: 2, state: { id: snap.state.id, name: snap.state.name, status: snap.state.online ? "online" : "offline" } };
}

function v2Tov3(snap: Snapshot<CourierV2>): Snapshot<CourierProfile> {
  return { version: 3, state: { ...snap.state, vehicleId: null } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CourierProfile> {
  let s: Snapshot<unknown> = raw;
  if (s.version === 1) s = v1Tov2(s as Snapshot<CourierV1>);
  if (s.version === 2) s = v2Tov3(s as Snapshot<CourierV2>);
  if (s.version !== CURRENT_VERSION) throw new Error("bad-version");
  return s as Snapshot<CourierProfile>;
}
```

The write side decides on strict domain invariants; the read side optimises for queries. Sharing the event DU keeps them in sync, but sharing state would couple query shape to invariants, making evolution painful. The read store is eventually consistent, populated by a projection subscription.

```typescript
export type TelemetryStreamEvent =
  | { type: "TelemetryStreamOpened"; id: string }
  | { type: "TelemetrySampleIngested"; value: number }
  | { type: "TelemetryStreamSealed"; at: string };

export type TelemetryStreamState =
  | { status: "none" }
  | { status: "open"; id: string; samples: number }
  | { status: "sealed"; id: string };

export type TelemetryStreamCommand =
  | { type: "open"; id: string }
  | { type: "ingest"; value: number };

export class DomainError extends Error {}

export function evolve(s: TelemetryStreamState, e: TelemetryStreamEvent): TelemetryStreamState {
  switch (e.type) {
    case "TelemetryStreamOpened": return { status: "open", id: e.id, samples: 0 };
    case "TelemetrySampleIngested":
      if (s.status !== "open") return s;
      return { ...s, samples: s.samples + 1 };
    case "TelemetryStreamSealed":
      if (s.status !== "open") return s;
      return { status: "sealed", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: TelemetryStreamCommand, s: TelemetryStreamState): TelemetryStreamEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "TelemetryStreamOpened", id: c.id }];
    case "ingest":
      if (s.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "TelemetrySampleIngested", value: c.value }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: TelemetryStreamEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: TelemetryStreamEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export type TelemetryStreamView = Readonly<{ id: string; samples: number; sealed: boolean }>;

export interface ReadStore {
  get(id: string): Promise<TelemetryStreamView | null>;
}

export async function handleCommand(
  c: TelemetryStreamCommand,
  ctx: { stream: string; store: EventStore },
): Promise<void> {
  const current = await ctx.store.readStream(ctx.stream);
  const state = current.events.reduce(evolve, { status: "none" } as TelemetryStreamState);
  const events = decide(c, state);
  if (events.length === 0) return;
  const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
  await ctx.store.appendToStream(ctx.stream, events, { expectedRevision });
}

export async function queryView(id: string, reads: ReadStore): Promise<TelemetryStreamView | null> {
  return reads.get(id);
}
