A CommandHandler is the orchestrator, not the decision-maker. It reads the stream, folds events into state via evolve, delegates to decide for new events, then appends them with an expectedRevision to keep the write consistent. No business logic leaks here.

```typescript
export type TurnaroundState = { status: "idle" } | { status: "active"; id: string };
export type TurnaroundCommand = { type: "begin"; id: string } | { type: "close" };
export type TurnaroundEvent = { type: "TurnaroundBegun"; id: string } | { type: "TurnaroundClosed" };

export const initialState: TurnaroundState = { status: "idle" };

export function evolve(s: TurnaroundState, e: TurnaroundEvent): TurnaroundState {
  switch (e.type) {
    case "TurnaroundBegun": return { status: "active", id: e.id };
    case "TurnaroundClosed": return { status: "idle" };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: TurnaroundCommand, s: TurnaroundState): TurnaroundEvent[] {
  switch (c.type) {
    case "begin":
      if (s.status !== "idle") throw new Error("ACTIVE");
      return [{ type: "TurnaroundBegun", id: c.id }];
    case "close":
      if (s.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "TurnaroundClosed" }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(name: string): Promise<{ revision: bigint; data: TurnaroundEvent }[]>;
  appendToStream(name: string, events: TurnaroundEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handle(cmd: TurnaroundCommand, deps: { streamName: string; eventStore: EventStore }): Promise<void> {
  const stored = await deps.eventStore.readStream(deps.streamName);
  const state = stored.reduce<TurnaroundState>((s, r) => evolve(s, r.data), initialState);
  const events = decide(cmd, state);
  const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  await deps.eventStore.appendToStream(deps.streamName, events, { expectedRevision });
}
```

```typescript
export type DonationDriveEvent =
  | { type: "launched"; id: string; goal: number; causationId: string }
  | { type: "pledged"; amount: number; causationId: string };

export type DonationDriveCommand =
  | { type: "launch"; id: string; goal: number; causationId: string }
  | { type: "pledge"; amount: number; causationId: string };

export type DonationDriveState = { status: "none" } | { status: "open"; id: string; raised: number };
const initialState: DonationDriveState = { status: "none" };

function evolve(s: DonationDriveState, e: DonationDriveEvent): DonationDriveState {
  switch (e.type) {
    case "launched":
      return { status: "open", id: e.id, raised: 0 };
    case "pledged":
      return s.status === "open" ? { ...s, raised: s.raised + e.amount } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: DonationDriveCommand, s: DonationDriveState): DonationDriveEvent[] {
  switch (c.type) {
    case "launch":
      if (s.status !== "none") return [];
      return [{ type: "launched", id: c.id, goal: c.goal, causationId: c.causationId }];
    case "pledge":
      if (s.status !== "open") throw new Error("not open");
      return [{ type: "pledged", amount: c.amount, causationId: c.causationId }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface StoredEvent<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(s: string): Promise<StoredEvent<E>[]>;
  appendToStream(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" }): Promise<{ nextRevision: bigint }>;
}

export async function handle(
  command: DonationDriveCommand,
  ctx: { streamName: string; eventStore: EventStore<DonationDriveEvent> },
): Promise<void> {
  const stored = await ctx.eventStore.readStream(ctx.streamName);
  if (stored.some((r) => r.event.causationId === command.causationId)) return;
  const state = stored.reduce<DonationDriveState>((s, r) => evolve(s, r.event), initialState);
  const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  const events = decide(command, state);
  if (events.length === 0) return;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision });
}
```

Rebuild is a chunked read-fold-persist loop that takes `from` for resume. Each batch advances the cursor only after the projection has been applied and the read store has accepted the write.

```typescript
export type StationEvent =
  | { type: "StationOpened"; stationId: string; position: bigint }
  | { type: "BallotCast"; stationId: string; position: bigint }
  | { type: "StationClosed"; stationId: string; position: bigint };

export type Turnout = Record<string, { ballots: number; open: boolean }>;
export const emptyTurnout: Turnout = {};

export function project(view: Turnout, event: StationEvent): Turnout {
  switch (event.type) {
    case "StationOpened":
      return { ...view, [event.stationId]: { ballots: 0, open: true } };
    case "BallotCast": {
      const cur = view[event.stationId] ?? { ballots: 0, open: true };
      return { ...view, [event.stationId]: { ...cur, ballots: cur.ballots + 1 } };
    }
    case "StationClosed": {
      const cur = view[event.stationId] ?? { ballots: 0, open: true };
      return { ...view, [event.stationId]: { ...cur, open: false } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface Source { fetch(from: bigint, size: number): Promise<StationEvent[]> }
export interface Sink { save(v: Turnout, cursor: bigint): Promise<void> }

export type Opts = { from: bigint; batchSize: number; source: Source; sink: Sink };

export async function rebuild(opts: Opts): Promise<bigint> {
  let cursor = opts.from;
  let view: Turnout = emptyTurnout;
  for (;;) {
    const batch = await opts.source.fetch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const event of batch) {
      view = project(view, event);
      cursor = event.position;
    }
    await opts.sink.save(view, cursor);
  }
  return cursor;
}
```

Upcasting runs at read time and returns the current shape. The stored stream is never rewritten - the aggregate only ever sees the current event shape.

```typescript
export type RawEvent =
  | { type: "TicketOpened"; version: 1; id: string; title: string; reporter: string }
  | { type: "TicketOpened"; version: 2; id: string; title: string; reporter: { id: string; displayName: string } }
  | { type: "TicketAssigned"; version: 1; assignee: string }
  | { type: "TicketClosed"; version: 1; at: string };

export type CurrentEvent =
  | { type: "TicketOpened"; version: 2; id: string; title: string; reporter: { id: string; displayName: string } }
  | { type: "TicketAssigned"; version: 1; assignee: string }
  | { type: "TicketClosed"; version: 1; at: string };

export class UnknownEventError extends Error {}

function assertRaw(raw: unknown): asserts raw is RawEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError("NOT_OBJECT");
}

export function upcast(raw: unknown): CurrentEvent {
  assertRaw(raw);
  switch (raw.type) {
    case "TicketOpened":
      if (raw.version === 1) {
        return {
          type: "TicketOpened",
          version: 2,
          id: raw.id,
          title: raw.title,
          reporter: { id: raw.reporter, displayName: raw.reporter },
        };
      }
      return raw;
    case "TicketAssigned":
    case "TicketClosed":
      return raw;
    default: {
      const _n: never = raw;
      throw new UnknownEventError("UNKNOWN_TYPE");
    }
  }
}

export type TicketView = Readonly<{
  id: string;
  title: string;
  reporterName: string;
  assignee: string | null;
  closedAt: string | null;
}>;

export const emptyView: TicketView = { id: "", title: "", reporterName: "", assignee: null, closedAt: null };

export function project(view: TicketView, event: CurrentEvent): TicketView {
  switch (event.type) {
    case "TicketOpened":
      return { id: event.id, title: event.title, reporterName: event.reporter.displayName, assignee: null, closedAt: null };
    case "TicketAssigned":
      return { ...view, assignee: event.assignee };
    case "TicketClosed":
      return { ...view, closedAt: event.at };
    default: {
      const _n: never = event;
      return view;
    }
  }
}
