export const initialState: DepositionRecordState = { status: "empty" };
export function evolve(s: DepositionRecordState, e: DepositionRecordEvent): DepositionRecordState {
  switch (e.type) {
    case "scheduled": return { status: "active", recordId: e.recordId };
    case "sealed": return { status: "sealed" };
    default: { const _: never = e; return s; }
  }
}
export function decide(c: DepositionRecordCommand, s: DepositionRecordState): DepositionRecordEvent[] {
  switch (c.type) {
    case "schedule": return s.status === "empty" ? [{ type: "scheduled", recordId: c.recordId, deponent: c.deponent }] : [];
    case "seal": return s.status === "active" ? [{ type: "sealed" }] : [];
    default: { const _: never = c; return []; }
  }
