export type CraftCommissionCommand =
  | { type: "quote"; id: string; price: number }
  | { type: "accept" };

export type CraftCommissionEvent =
  | { type: "CommissionQuoted"; id: string; price: number }
  | { type: "CommissionAccepted" };

type State =
  | { status: "none" }
  | { status: "quoted"; id: string; price: number }
  | { status: "accepted"; id: string; price: number };

const initial: State = { status: "none" };

function decide(c: CraftCommissionCommand, s: State): CraftCommissionEvent[] {
  if (c.type === "quote") {
    if (s.status !== "none") throw new Error("already quoted");
    return [{ type: "CommissionQuoted", id: c.id, price: c.price }];
  }
  if (s.status !== "quoted") throw new Error("no quote");
  return [{ type: "CommissionAccepted" }];
}

function evolve(s: State, e: CraftCommissionEvent): State {
  if (e.type === "CommissionQuoted") {
    return { status: "quoted", id: e.id, price: e.price };
  }
  return s.status === "quoted"
    ? { status: "accepted", id: s.id, price: s.price }
    : s;
}

export interface EventStore {
  readStream(stream: string): Promise<{
    events: CraftCommissionEvent[];
    lastRevision: bigint | "no_stream";
  }>;
  appendToStream(
    stream: string,
    events: CraftCommissionEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export interface CommissionView {
  id: string;
  status: "quoted" | "accepted";
  price: number;
}
export interface ReadStore {
  get(id: string): Promise<CommissionView | null>;
}

// Note: ReadStore lags behind EventStore; queries are eventually consistent.
export async function handleCommand(
  command: CraftCommissionCommand,
  ctx: { stream: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream(ctx.stream);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.stream, events, {
    expectedRevision: read.lastRevision,
  });
}

export async function queryView(
  reads: ReadStore,
  id: string,
): Promise<CommissionView | null> {
  return reads.get(id);
}
