A Decider bundles three pure ingredients: an initial state literal, a decide(command, state) function that returns the events to append, and an evolve(state, event) function that folds events into state. The two functions never touch I/O — the decide function validates invariants and produces events, while evolve rebuilds state from the event stream. Because both are pure, tests are trivially deterministic.

```typescript
export type StaffShiftState =
  | { status: "none" }
  | { status: "clockedIn"; id: string; staffId: string; startedAt: string; breakMinutes: number }
  | { status: "onBreak"; id: string; staffId: string; breakStartedAt: string; breakMinutes: number }
  | { status: "clockedOut"; id: string; endedAt: string };

export type StaffShiftCommand =
  | { type: "clockIn"; id: string; staffId: string; at: string }
  | { type: "startBreak"; at: string }
  | { type: "endBreak"; at: string; minutes: number }
  | { type: "clockOut"; at: string };

export type StaffShiftEvent =
  | { type: "ShiftClockedIn"; id: string; staffId: string; at: string }
  | { type: "BreakStarted"; at: string }
  | { type: "BreakEnded"; at: string; minutes: number }
  | { type: "ShiftClockedOut"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const staffShiftDecider: Decider<StaffShiftCommand, StaffShiftEvent, StaffShiftState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "clockIn":
        if (s.status !== "none") throw new DomainError("ALREADY_CLOCKED_IN");
        return [{ type: "ShiftClockedIn", id: c.id, staffId: c.staffId, at: c.at }];
      case "startBreak":
        if (s.status !== "clockedIn") throw new DomainError("NOT_WORKING");
        return [{ type: "BreakStarted", at: c.at }];
      case "endBreak":
        if (s.status !== "onBreak") throw new DomainError("NOT_ON_BREAK");
        return [{ type: "BreakEnded", at: c.at, minutes: c.minutes }];
      case "clockOut":
        if (s.status !== "clockedIn") throw new DomainError("NOT_WORKING");
        return [{ type: "ShiftClockedOut", at: c.at }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ShiftClockedIn":
        return { status: "clockedIn", id: e.id, staffId: e.staffId, startedAt: e.at, breakMinutes: 0 };
      case "BreakStarted":
        return s.status === "clockedIn"
          ? { status: "onBreak", id: s.id, staffId: s.staffId, breakStartedAt: e.at, breakMinutes: s.breakMinutes }
          : s;
      case "BreakEnded":
        return s.status === "onBreak"
          ? { status: "clockedIn", id: s.id, staffId: s.staffId, startedAt: s.breakStartedAt, breakMinutes: s.breakMinutes + e.minutes }
          : s;
      case "ShiftClockedOut":
        return s.status === "clockedIn"
          ? { status: "clockedOut", id: s.id, endedAt: e.at }
          : s;
      default: { const _n: never = e; return s; }
    }
  },
};
```

```typescript
export const CURRENT_VERSION = 3 as const;

export interface Snapshot<S> { readonly version: number; readonly state: S; }

interface DocV1 { id: string; status: "open" | "closed"; }
interface DocV2 { id: string; status: "drafting" | "approved"; approvedAt?: string; }
export interface DocumentCurrent {
  readonly id: string;
  readonly status: "drafting" | "submitted" | "approved";
  readonly approvedAt: string | null;
  readonly submittedAt: string | null;
}

function v1Tov2(s: DocV1): DocV2 {
  return { id: s.id, status: s.status === "closed" ? "approved" : "drafting", approvedAt: undefined };
}

function v2Tov3(s: DocV2): DocumentCurrent {
  return {
    id: s.id,
    status: s.status,
    approvedAt: s.approvedAt ?? null,
    submittedAt: null,
  };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<DocumentCurrent> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as DocV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as DocV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION:${version}`);
  const current = state as DocumentCurrent;
  return { version: CURRENT_VERSION, state: current };
}

export function loadSnapshot(raw: { version: number; state: unknown }): DocumentCurrent {
  return upgradeSnapshot(raw).state;
}
```

