```typescript
export type PeriodicalState = { id: string; issues: Record<string, "added" | "published"> };
export type PeriodicalCommand =
  | { type: "register"; id: string }
  | { type: "addIssue"; issueId: string }
  | { type: "publishIssue"; issueId: string };
export type PeriodicalEvent =
  | { type: "Registered"; id: string }
  | { type: "IssueAdded"; issueId: string }
  | { type: "IssuePublished"; issueId: string };

const initialState: PeriodicalState = { id: "", issues: {} };

export class DomainError extends Error {}

function decide(command: PeriodicalCommand, state: PeriodicalState): PeriodicalEvent[] {
  switch (command.type) {
    case "register":
      if (state.id !== "") throw new DomainError("already registered");
      return [{ type: "Registered", id: command.id }];
    case "addIssue":
      if (state.id === "") throw new DomainError("not registered");
      return [{ type: "IssueAdded", issueId: command.issueId }];
    case "publishIssue":
      if (state.issues[command.issueId] !== "added") throw new DomainError("not added");
      return [{ type: "IssuePublished", issueId: command.issueId }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

function evolve(state: PeriodicalState, event: PeriodicalEvent): PeriodicalState {
  switch (event.type) {
    case "Registered":
      return { id: event.id, issues: {} };
    case "IssueAdded":
      return { ...state, issues: { ...state.issues, [event.issueId]: "added" } };
    case "IssuePublished":
      return { ...state, issues: { ...state.issues, [event.issueId]: "published" } };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: PeriodicalEvent; revision: bigint }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<PeriodicalEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export async function handle(
  command: PeriodicalCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initialState;
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision: expected });
}
```

Each node owns a small state machine with `collapsed`, `loading`, `expanded`, `failed`. Entering `loading` `invoke`s a `fromPromise` actor with typed `input` derived from the node id. `onDone` writes the fetched children to context and transitions to `expanded`; `onError` falls back to `failed`. Because children load only on expand, the tree can be huge without upfront cost.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Child = { id: string; label: string };

export const treeNodeMachine = setup({
  types: {
    context: {} as { id: string; children: Child[]; error: string | null },
    events: {} as { type: 'EXPAND' } | { type: 'COLLAPSE' },
  },
  actors: {
    fetchKids: fromPromise<Child[], { id: string }>(async ({ input }) => {
      const r = await fetch(`/api/children?parent=${input.id}`);
      return r.json();
    }),
  },
}).createMachine({
  id: 'treeNode',
  initial: 'collapsed',
  context: { id: 'root', children: [], error: null },
  states: {
    collapsed: { on: { EXPAND: 'loading' } },
    loading: {
      invoke: {
        src: 'fetchKids',
        input: ({ context }) => ({ id: context.id }),
        onDone: {
          target: 'expanded',
          actions: assign({ children: ({ event }) => event.output }),
        },
        onError: {
          target: 'failed',
          actions: assign({ error: ({ event }) => String(event.error) }),
        },
      },
    },
    expanded: { on: { COLLAPSE: 'collapsed' } },
    failed: { on: { EXPAND: 'loading' } },
  },
});
```

```typescript
export type VotingSessionState =
  | { status: "scheduled"; id: string; opensAt: string }
  | { status: "open"; id: string; openedAt: string; votes: number }
  | { status: "closed"; id: string; closedAt: string; votes: number };

export type VotingSessionCommand =
  | { type: "schedule"; id: string; opensAt: string }
  | { type: "open"; at: string }
  | { type: "castVote" }
  | { type: "close"; at: string };

export type VotingSessionEvent =
  | { type: "Scheduled"; id: string; opensAt: string }
  | { type: "Opened"; at: string }
  | { type: "VoteCast" }
  | { type: "Closed"; at: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const initialState: VotingSessionState = { status: "scheduled", id: "", opensAt: "" };

export function decide(command: VotingSessionCommand, state: VotingSessionState): VotingSessionEvent[] {
  switch (command.type) {
    case "schedule":
      return [{ type: "Scheduled", id: command.id, opensAt: command.opensAt }];
    case "open":
      if (state.status === "closed") throw new DomainError("session closed");
      if (state.status === "open") throw new DomainError("already open");
      return [{ type: "Opened", at: command.at }];
    case "castVote":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "VoteCast" }];
    case "close":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "Closed", at: command.at }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: VotingSessionState, event: VotingSessionEvent): VotingSessionState {
  switch (event.type) {
    case "Scheduled":
      return { status: "scheduled", id: event.id, opensAt: event.opensAt };
    case "Opened":
      return state.status === "scheduled" ? { status: "open", id: state.id, openedAt: event.at, votes: 0 } : state;
    case "VoteCast":
      return state.status === "open" ? { ...state, votes: state.votes + 1 } : state;
    case "Closed":
      return state.status === "open" ? { status: "closed", id: state.id, closedAt: event.at, votes: state.votes } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const votingSessionDecider: Decider<VotingSessionCommand, VotingSessionEvent, VotingSessionState> = {
  initialState,
  decide,
  evolve,
};
```

