```typescript
export type LabSampleState =
  | { status: "none" }
  | { status: "received"; id: string }
  | { status: "processed"; id: string }
  | { status: "archived"; id: string };

export type LabSampleCommand =
  | { type: "receive"; id: string }
  | { type: "process" }
  | { type: "archive" };

export type LabSampleEvent =
  | { type: "LabSampleReceived"; id: string }
  | { type: "LabSampleProcessed" }
  | { type: "LabSampleArchived" };

const initial: LabSampleState = { status: "none" };

function evolve(state: LabSampleState, event: LabSampleEvent): LabSampleState {
  switch (event.type) {
    case "LabSampleReceived":
      return { status: "received", id: event.id };
    case "LabSampleProcessed":
      return state.status === "received" ? { status: "processed", id: state.id } : state;
    case "LabSampleArchived":
      return state.status === "processed" ? { status: "archived", id: state.id } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: LabSampleCommand, state: LabSampleState): LabSampleEvent[] {
  switch (command.type) {
    case "receive":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "LabSampleReceived", id: command.id }];
    case "process":
      if (state.status !== "received") throw new Error("NOT_RECEIVED");
      return [{ type: "LabSampleProcessed" }];
    case "archive":
      if (state.status !== "processed") throw new Error("NOT_PROCESSED");
      return [{ type: "LabSampleArchived" }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handle(
  command: LabSampleCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream<LabSampleEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
}
