export type FishStockState =
  | { status: "empty" }
  | { status: "stocked"; id: string; count: number; audits: number };

export type FishStockCommand =
  | { type: "seed"; id: string; count: number }
  | { type: "harvest"; count: number }
  | { type: "audit"; by: string };

export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; count: number }
  | { type: "FishStockHarvested"; count: number }
  | { type: "FishStockAudited"; by: string; at: string };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const fishStockDecider: Decider<FishStockCommand & { at?: string }, FishStockEvent, FishStockState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "seed":
        if (state.status !== "empty") throw new Error("EXISTS");
        return [{ type: "FishStockSeeded", id: command.id, count: command.count }];
      case "harvest":
        if (state.status !== "stocked") throw new Error("NOT_STOCKED");
        return [{ type: "FishStockHarvested", count: command.count }];
      case "audit":
        if (state.status !== "stocked") throw new Error("NOT_STOCKED");
        return [{ type: "FishStockAudited", by: command.by, at: command.at ?? "" }];
      default: {
        const _never: never = command;
        throw new Error("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FishStockSeeded":
        return { status: "stocked", id: event.id, count: event.count, audits: 0 };
      case "FishStockHarvested":
        return state.status === "stocked" ? { ...state, count: state.count - event.count } : state;
      case "FishStockAudited":
        return state.status === "stocked" ? { ...state, audits: state.audits + 1 } : state;
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
