import { Effect } from "effect";

export type MembershipState = { status: "none" } | { status: "active"; id: string; tier: "basic" | "pro" };
export type MembershipCommand = { type: "enroll"; id: string; tier: "basic" | "pro" };
export type MembershipEvent = { type: "MembershipEnrolled"; id: string; tier: "basic" | "pro" };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

const initial: MembershipState = { status: "none" };

function evolve(s: MembershipState, e: MembershipEvent): MembershipState {
  switch (e.type) {
    case "MembershipEnrolled": return { status: "active", id: e.id, tier: e.tier };
    default: { const _n: never = e.type; return s; }
  }
}

function decide(c: MembershipCommand, s: MembershipState): MembershipEvent[] {
  switch (c.type) {
    case "enroll":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "MembershipEnrolled", id: c.id, tier: c.tier }];
    default: { const _n: never = c.type; throw new Error("UNKNOWN"); }
  }
}

export function handle(cmd: MembershipCommand, stream: string, store: EventStore) {
  return Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => store.readStream<MembershipEvent>(stream));
    const state = events.reduce<MembershipState>(evolve, initial);
    const next = decide(cmd, state);
    yield* Effect.promise(() =>
      store.appendToStream<MembershipEvent>(stream, next, { expectedRevision: revision }),
    );
  });
}
