export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  when: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let acc = initial;
  for await (const event of events) acc = when(acc, event);
  return acc;
}
export type LegalCaseEvent = { type: "opened"; caseId: string } | { type: "closed" };
export type LegalCaseState = { status: "none" } | { status: "open"; caseId: string } | { status: "closed"; caseId: string };
export function evolve(s: LegalCaseState, e: LegalCaseEvent): LegalCaseState {
  switch (e.type) {
    case "opened": return { status: "open", caseId: e.caseId };
    case "closed": return s.status === "open" ? { status: "closed", caseId: s.caseId } : s;
    default: { const _: never = e; return s; }
  }
}
export async function reconstruct(events: AsyncIterable<LegalCaseEvent>): Promise<LegalCaseState> {
  return aggregateStream<LegalCaseState, LegalCaseEvent>(events, evolve, { status: "none" });
}
