export const CURRENT_VERSION = 2;

export interface ItineraryV1 { id: string; pax: string; legs: number; }
export interface ItineraryV2 { id: string; pax: string; legs: number; cancellationReason: string | null; }

export type CurrentItinerary = ItineraryV2;

export interface Snapshot<S> { version: number; state: S; }

function v1Tov2(s: ItineraryV1): ItineraryV2 {
  return { ...s, cancellationReason: null };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentItinerary> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v === 1) { state = v1Tov2(state as ItineraryV1); v = 2; }
  if (v !== CURRENT_VERSION) throw new Error("VERSION_UNSUPPORTED");
  return { version: CURRENT_VERSION, state: state as CurrentItinerary };
}
