export type Tier = "basic" | "pro" | "enterprise";

export type MembershipState =
  | { status: "none" }
  | { status: "active"; id: string; tier: Tier }
  | { status: "expired"; id: string; at: string };

export type MembershipCommand =
  | { type: "enroll"; id: string; tier: Tier }
  | { type: "upgrade"; tier: Tier }
  | { type: "expire"; at: string };

export type MembershipEvent =
  | { type: "MembershipEnrolled"; id: string; tier: Tier }
  | { type: "MembershipUpgraded"; tier: Tier }
  | { type: "MembershipExpired"; at: string };

export class MembershipError extends Error {
  constructor(code: string) { super(code); this.name = "MembershipError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

const rank: Record<Tier, number> = { basic: 1, pro: 2, enterprise: 3 };

export const membershipDecider: Decider<MembershipCommand, MembershipEvent, MembershipState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "enroll":
        if (s.status !== "none") throw new MembershipError("ALREADY");
        return [{ type: "MembershipEnrolled", id: c.id, tier: c.tier }];
      case "upgrade":
        if (s.status === "expired") throw new MembershipError("EXPIRED");
        if (s.status !== "active") throw new MembershipError("NOT_ACTIVE");
        if (rank[c.tier] <= rank[s.tier]) throw new MembershipError("NOT_UPGRADE");
        return [{ type: "MembershipUpgraded", tier: c.tier }];
      case "expire":
        if (s.status !== "active") throw new MembershipError("NOT_ACTIVE");
        return [{ type: "MembershipExpired", at: c.at }];
      default: { const _n: never = c; throw new MembershipError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "MembershipEnrolled":
        return { status: "active", id: e.id, tier: e.tier };
      case "MembershipUpgraded":
        if (s.status !== "active") return s;
        return { status: "active", id: s.id, tier: e.tier };
      case "MembershipExpired":
        if (s.status !== "active") return s;
        return { status: "expired", id: s.id, at: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
