// The read side is eventually consistent with the event store.

type Command = { type: 'Catalogue'; catalogueId: string };
type SampleEvent = { type: 'SampleCatalogued'; catalogueId: string };
type WriteState = { status: 'collected' } | { status: 'catalogued' };
const initial: WriteState = { status: 'collected' };

function evolve(state: WriteState, event: SampleEvent): WriteState {
  switch (event.type) {
    case 'SampleCatalogued':
      return { status: 'catalogued' };
    default: {
      const _: never = event.type;
      return _;
    }
  }
}

function decide(cmd: Command, state: WriteState): SampleEvent[] {
  if (state.status === 'catalogued') throw new Error('already catalogued');
  return [{ type: 'SampleCatalogued', catalogueId: cmd.catalogueId }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: SampleEvent; revision: bigint }>;
  appendToStream(s: string, e: SampleEvent[], o: { expectedRevision: bigint | 'no_stream' }): Promise<void>;
}

type ReadRow = Readonly<{ sampleId: string; catalogueId: string | null }>;
interface ReadStore { get(id: string): Promise<ReadRow | null> }

export async function handleCommand(
  cmd: Command,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initial;
  let rev: bigint | 'no_stream' = 'no_stream';
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  await ctx.eventStore.appendToStream(ctx.streamName, decide(cmd, state), { expectedRevision: rev });
}

export async function queryView(id: string, readStore: ReadStore): Promise<ReadRow | null> {
  return readStore.get(id);
}
