```typescript
import { Effect } from "effect";

export type RunState = { status: "none" } | { status: "scheduled"; id: string } | { status: "active"; id: string };
export type RunCommand = { type: "schedule"; id: string } | { type: "start" };
export type RunEvent = { type: "RunScheduled"; id: string } | { type: "RunStarted" };

export function evolve(s: RunState, e: RunEvent): RunState {
  switch (e.type) {
    case "RunScheduled": return { status: "scheduled", id: e.id };
    case "RunStarted":
      if (s.status !== "scheduled") return s;
      return { status: "active", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: RunCommand, s: RunState): RunEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "RunScheduled", id: c.id }];
    case "start":
      if (s.status !== "scheduled") throw new Error("NOT_SCHEDULED");
      return [{ type: "RunStarted" }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: RunEvent[]; revision: ExpectedRevision }>;
  appendToStream(stream: string, events: RunEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export function handleRun(command: RunCommand, ctx: { streamName: string; eventStore: EventStore }): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const page = yield* Effect.tryPromise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = page.events.reduce<RunState>(evolve, { status: "none" });
    const produced = decide(command, state);
    yield* Effect.tryPromise(() => ctx.eventStore.appendToStream(ctx.streamName, produced, { expectedRevision: page.revision }));
  });
}
