export type ReworkDomainEvent =
  | { type: "ReworkOrderOpened"; id: string; part: string }
  | { type: "ReworkOrderAssigned"; id: string; technician: string }
  | { type: "ReworkOrderClosed"; id: string; at: string }
  | { type: "ReworkOrderNotesAdded"; id: string; notes: string };

export interface IntegrationEvent {
  readonly schema: string;
  readonly payload: unknown;
}

export function translate(event: ReworkDomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "ReworkOrderOpened":
      return { schema: "rework.opened.v1", payload: { id: event.id, part: event.part } };
    case "ReworkOrderClosed":
      return { schema: "rework.closed.v1", payload: { id: event.id, closedAt: event.at } };
    case "ReworkOrderAssigned":
      return { schema: "rework.assigned.v1", payload: { id: event.id, technician: event.technician } };
    case "ReworkOrderNotesAdded":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export interface OutboxSink { publish(env: IntegrationEvent): Promise<void>; }

export async function project(events: ReworkDomainEvent[], sink: OutboxSink): Promise<number> {
  let sent = 0;
  for (const e of events) {
    const out = translate(e);
    if (out) { await sink.publish(out); sent++; }
  }
  return sent;
}
