A CommandHandler is the orchestration layer between a command and the event store. It has no business rules of its own: it reads the aggregate's stream, folds the stored events through evolve to reconstruct current state, delegates to decide for the actual rule enforcement, then appends the resulting events with an expected revision so concurrent writers get a typed conflict. Keeping the handler thin means you can swap the store implementation (in-memory, Postgres, EventStoreDB) without re-testing the rules.

```typescript
export type TicketState = { status: "none" } | { status: "open"; id: string } | { status: "resolved"; id: string };
export type TicketCommand = { type: "open"; id: string } | { type: "resolve" };
export type TicketEvent = { type: "TicketOpened"; id: string } | { type: "TicketResolved" };

export const initialState: TicketState = { status: "none" };

export function evolve(state: TicketState, event: TicketEvent): TicketState {
  switch (event.type) {
    case "TicketOpened":
      return { status: "open", id: event.id };
    case "TicketResolved":
      if (state.status !== "open") return state;
      return { status: "resolved", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(cmd: TicketCommand, state: TicketState): TicketEvent[] {
  switch (cmd.type) {
    case "open":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "TicketOpened", id: cmd.id }];
    case "resolve":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "TicketResolved" }];
    default: {
      const _never: never = cmd;
      return _never;
    }
  }
}

interface EventStore<E> {
  readStream(s: string): Promise<{ data: E; revision: bigint }[]>;
  appendToStream(s: string, events: E[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export async function handle(
  command: TicketCommand,
  ctx: { streamName: string; eventStore: EventStore<TicketEvent> },
): Promise<void> {
  const stored = await ctx.eventStore.readStream(ctx.streamName);
  const state = stored.reduce<TicketState>((s, e) => evolve(s, e.data), initialState);
  const events = decide(command, state);
  const expectedRevision: bigint | "no_stream" =
    stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision });
}
```

