interface Ctx { nextAt: number }
type Ev = { type: 'DISMISS' } | { type: 'FIRE' };

const DAY = 24 * 60 * 60 * 1000;

export const dailyAlarm = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: {
    TIL_NEXT: ({ context }: { context: Ctx }) => Math.max(0, context.nextAt - Date.now())
  },
  actions: {
    scheduleNext: assign({ nextAt: ({ context }) => context.nextAt + DAY })
  }
}).createMachine({
  id: 'dailyAlarm',
  context: { nextAt: Date.now() + DAY },
  initial: 'waiting',
  states: {
    waiting: {
      after: { TIL_NEXT: 'ringing' }
    },
    ringing: {
      on: { DISMISS: { target: 'waiting', actions: 'scheduleNext' } }
    }
  }
});
