```typescript
interface RawV1ImpressionRecorded {
  readonly type: "ImpressionRecorded";
  readonly version: 1;
  readonly campaignId: string;
  readonly at: string;
}

interface RawV2ImpressionRecorded {
  readonly type: "ImpressionRecorded";
  readonly version: 2;
  readonly advertisementId: string;
  readonly campaignFlightId: string;
  readonly at: string;
}

interface RawImpressionInvalidated {
  readonly type: "ImpressionInvalidated";
  readonly version: 1;
  readonly advertisementId: string;
  readonly reason: string;
}

export type RawImpressionEvent = RawV1ImpressionRecorded | RawV2ImpressionRecorded | RawImpressionInvalidated;

export type ImpressionEvent =
  | { type: "ImpressionRecorded"; advertisementId: string; campaignFlightId: string; at: string }
  | { type: "ImpressionInvalidated"; advertisementId: string; reason: string };

export class UnknownEventError extends Error {
  constructor(raw: unknown) {
    super(`Unknown event: ${JSON.stringify(raw)}`);
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: RawImpressionEvent): ImpressionEvent {
  switch (raw.type) {
    case "ImpressionRecorded":
      if (raw.version === 1) {
        return {
          type: "ImpressionRecorded",
          advertisementId: raw.campaignId,
          campaignFlightId: raw.campaignId,
          at: raw.at,
        };
      }
      return {
        type: "ImpressionRecorded",
        advertisementId: raw.advertisementId,
        campaignFlightId: raw.campaignFlightId,
        at: raw.at,
      };
    case "ImpressionInvalidated":
      return {
        type: "ImpressionInvalidated",
        advertisementId: raw.advertisementId,
        reason: raw.reason,
      };
    default: {
      const _never: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<RawImpressionEvent>;
}

export async function loadUpcast(store: EventStore, stream: string): Promise<ImpressionEvent[]> {
  const out: ImpressionEvent[] = [];
  for await (const raw of store.readStream(stream)) {
    out.push(upcast(raw));
  }
  return out;
}
