Create a fromCallback actor that subscribes to the canvas pointer events and forwards them as typed machine events via sendBack, returning a cleanup closure.

```typescript
import { setup, fromCallback } from 'xstate';

type Ev = { type: 'STROKE'; x: number; y: number } | { type: 'END' };

const canvasEvents = fromCallback<Ev, { el: HTMLCanvasElement }>(({ sendBack, input }) => {
  const onMove = (e: PointerEvent) => sendBack({ type: 'STROKE', x: e.offsetX, y: e.offsetY });
  const onEnd = () => sendBack({ type: 'END' });
  input.el.addEventListener('pointermove', onMove);
  input.el.addEventListener('pointerup', onEnd);
  return () => {
    input.el.removeEventListener('pointermove', onMove);
    input.el.removeEventListener('pointerup', onEnd);
  };
});

