  id: 'padSkeleton',
  initial: 'listening',
  states: {
    listening: {
      invoke: { src: 'canvasEvents', input: ({ event: _event, self: _self }) => ({ el: document.createElement('canvas') }) },
      on: { STROKE: {}, END: 'done' }
    },
    done: { type: 'final' }
  }
});
