export type InvoiceEvent =
  | { type: "InvoiceIssued"; customerId: string; invoiceId: string; amount: number }
  | { type: "InvoicePartiallyPaid"; invoiceId: string; amount: number }
  | { type: "InvoicePaid"; invoiceId: string }
  | { type: "InvoiceVoided"; invoiceId: string };

export type LedgerView = Readonly<{
  outstandingByCustomer: Readonly<Record<string, number>>;
  invoiceCustomer: Readonly<Record<string, string>>;
  invoiceRemaining: Readonly<Record<string, number>>;
}>;

export const emptyLedger: LedgerView = {
  outstandingByCustomer: {},
  invoiceCustomer: {},
  invoiceRemaining: {},
};

export function project(view: LedgerView, event: InvoiceEvent): LedgerView {
  switch (event.type) {
    case "InvoiceIssued":
      return {
        outstandingByCustomer: {
          ...view.outstandingByCustomer,
          [event.customerId]: (view.outstandingByCustomer[event.customerId] ?? 0) + event.amount,
        },
        invoiceCustomer: { ...view.invoiceCustomer, [event.invoiceId]: event.customerId },
        invoiceRemaining: { ...view.invoiceRemaining, [event.invoiceId]: event.amount },
      };
    case "InvoicePartiallyPaid": {
      const customerId = view.invoiceCustomer[event.invoiceId];
      if (!customerId) return view;
      const remaining = (view.invoiceRemaining[event.invoiceId] ?? 0) - event.amount;
      return {
        ...view,
        outstandingByCustomer: {
          ...view.outstandingByCustomer,
          [customerId]: (view.outstandingByCustomer[customerId] ?? 0) - event.amount,
        },
        invoiceRemaining: { ...view.invoiceRemaining, [event.invoiceId]: remaining },
      };
    }
    case "InvoicePaid": {
      const customerId = view.invoiceCustomer[event.invoiceId];
      if (!customerId) return view;
      const remaining = view.invoiceRemaining[event.invoiceId] ?? 0;
      return {
        ...view,
        outstandingByCustomer: {
          ...view.outstandingByCustomer,
          [customerId]: (view.outstandingByCustomer[customerId] ?? 0) - remaining,
        },
        invoiceRemaining: { ...view.invoiceRemaining, [event.invoiceId]: 0 },
      };
    }
    case "InvoiceVoided":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
