```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

```typescript
type ChannelEvent =
  | { type: 'ChannelCreated'; id: string; name: string }
  | { type: 'ChannelJoined'; userId: string };

interface EventStore {
  appendToStream(
    stream: string,
    events: readonly ChannelEvent[],
    options: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<{ revision: bigint }>;
  readStream(
    stream: string,
  ): AsyncIterable<{ event: ChannelEvent; revision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  readonly _tag = 'ConcurrencyConflict' as const;
  constructor(public readonly stream: string, public readonly expected: bigint | 'no_stream') {
    super('channel revision mismatch');
  }
}

export async function writeChannel(
  store: EventStore,
  stream: string,
  events: readonly ChannelEvent[],
): Promise<bigint> {
  let currentRevision: bigint | 'no_stream' = 'no_stream';
  for await (const { revision } of store.readStream(stream)) {
    currentRevision = revision;
  }
  try {
    const { revision } = await store.appendToStream(stream, events, {
      expectedRevision: currentRevision,
    });
    return revision;
  } catch (err) {
    if ((err as { code?: string }).code === 'WrongExpectedVersion') {
      throw new ConcurrencyConflict(stream, currentRevision);
    }
    throw err;
  }
}

async function main(): Promise<void> {
  // wire into HTTP handler here
}

void main;
