  club,
  played: 0,
  points: 0,
  gf: 0,
  ga: 0,
});

export function when(state: StandingsRow, event: StandingsEvent): StandingsRow {
  switch (event.type) {
    case "home-win":
      return {
        ...state,
        played: state.played + 1,
        points: state.points + 3,
        gf: state.gf + event.gf,
        ga: state.ga + event.ga,
      };
    case "away-win":
      return {
        ...state,
        played: state.played + 1,
        gf: state.gf + event.gf,
        ga: state.ga + event.ga,
      };
    case "draw":
      return {
        ...state,
        played: state.played + 1,
        points: state.points + 1,
        gf: state.gf + event.gf,
        ga: state.ga + event.ga,
      };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function foldRow(events: readonly StandingsEvent[], club: string): StandingsRow {
  return events.reduce(when, emptyRow(club));
