export type FishStockState =
  | { status: "empty" }
  | { status: "stocked"; id: string; count: number };

export type FishStockCommand =
  | { type: "seed"; id: string; count: number }
  | { type: "harvest"; count: number };

export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; count: number }
  | { type: "FishStockHarvested"; count: number };

const initial: FishStockState = { status: "empty" };

function evolve(state: FishStockState, event: FishStockEvent): FishStockState {
  switch (event.type) {
    case "FishStockSeeded":
      return { status: "stocked", id: event.id, count: event.count };
    case "FishStockHarvested":
      return state.status === "stocked" ? { ...state, count: state.count - event.count } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: FishStockCommand, state: FishStockState): FishStockEvent[] {
  switch (command.type) {
    case "seed":
      if (state.status !== "empty") throw new Error("EXISTS");
      return [{ type: "FishStockSeeded", id: command.id, count: command.count }];
    case "harvest":
      if (state.status !== "stocked") throw new Error("NOT_STOCKED");
      if (command.count > state.count) throw new Error("OVER_HARVEST");
      return [{ type: "FishStockHarvested", count: command.count }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handle(
  command: FishStockCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const current = await ctx.eventStore.readStream<FishStockEvent>(ctx.streamName);
  const state = current.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream<FishStockEvent>(ctx.streamName, events, {
    expectedRevision: current.revision,
  });
}
