Convert this XState v4 retry machine to v5. It has a RETRY event that users can fire manually and an automatic retry with guard:

```js
const m = Machine({
  id: 'retry',
  initial: 'loading',
  context: { tries: 0 },
  states: {
    loading: {
      invoke: {
        src: 'load',
        onDone: 'ok',
        onError: 'failed'
      }
    },
    failed: {
      on: {
        RETRY: { target: 'loading', actions: assign({ tries: (c) => c.tries + 1 }) }
      },
      after: {
        3000: { target: 'loading', cond: (c) => c.tries < 2, actions: assign({ tries: (c) => c.tries + 1 }) }
      }
    },
    ok: { type: 'final' }
  }
}, {
  services: { load: () => fetch('/x').then(r => r.json()) }
});
