export type HarvestEvent =
  | { type: "HarvestScheduled"; id: string; cropId: string }
  | { type: "HarvestStarted"; id: string; at: string }
  | { type: "HarvestCompleted"; id: string; yieldKg: number };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface StoredEvent<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface HarvestEventSource {
  from(position: bigint | null): AsyncIterable<StoredEvent<HarvestEvent>>;
}

export interface HarvestReadModel {
  apply(event: HarvestEvent): Promise<void>;
}

export async function runHarvestSubscription(
  name: string,
  source: HarvestEventSource,
  projection: HarvestReadModel,
  checkpoints: CheckpointStore
): Promise<void> {
  const start = await checkpoints.read(name);
  for await (const stored of source.from(start)) {
    // Apply first, then write the checkpoint -- crash-safe: on a crash
    // before write, the same event will be re-applied on restart.
    await projection.apply(stored.event);
    await checkpoints.write(name, stored.position);
  }
}
