export function evolve(state: ClearingEntryState, event: ClearingEntryEvent): ClearingEntryState {
  switch (event.type) {
    case "EntryPosted":
      return { status: "posted", id: event.id, amount: event.amount, reference: event.reference };
    case "EntryReversed":
      if (state.status !== "posted") return state;
      return {
        status: "reversed",
        id: state.id,
        amount: state.amount,
        reference: state.reference,
        reason: event.reason,
      };
    default: { const _n: never = event; return state; }
  }
}

export function aggregate(events: ReadonlyArray<ClearingEntryEvent>): ClearingEntryState {
  return events.reduce(evolve, initialState);
}

export function when(state: ClearingEntryState, event: ClearingEntryEvent): ClearingEntryState {
  return evolve(state, event);
}
