// the grading side should execute.
export function project(events: ReadonlyArray<SubmissionEvent>): GradeCommand[] {
  return events.reduce<GradeCommand[]>((acc, event) => {
    const cmd = react(event);
    return cmd === null ? acc : [...acc, cmd];
  }, []);
