type Ev = { type: 'KEY'; combo: string };

export const dispatcher = setup({
  types: {
    context: {} as Record<string, never>,
    events: {} as Ev
  },
  actions: {
    save: () => {},
    quit: () => {},
    noop: () => {}
  },
  guards: {
    isSave: ({ event }) => event.combo === 'C-s',
    isQuit: ({ event }) => event.combo === 'C-q'
  }
}).createMachine({
  id: 'dispatcher',
  initial: 'listening',
  context: {},
  states: {
    listening: {
      on: {
        KEY: [
          { guard: 'isSave', actions: 'save' },
          { guard: 'isQuit', actions: 'quit' },
          { actions: 'noop' }
        ]
      }
    }
  }
});
