The CQRS boundary separates the model that protects invariants (the write side) from the model tuned for queries (the read side). Writes go through decide + appendToStream against an aggregate state; reads use a projection view denormalised for whatever the UI asks for. The two sides share the event union — it is the contract — but nothing else. The read store is eventually consistent with the event store, which is the price you pay for being able to evolve each side independently.

```typescript
export type BaseCampEvent =
  | { type: "BaseCampPitched"; id: string; altitude: number }
  | { type: "BaseCampStruck"; at: string };

export type BaseCampState =
  | { status: "none" }
  | { status: "pitched"; id: string; altitude: number };

export type BaseCampCommand =
  | { type: "pitch"; id: string; altitude: number }
  | { type: "strike"; at: string };

export const initialState: BaseCampState = { status: "none" };

export function evolve(state: BaseCampState, event: BaseCampEvent): BaseCampState {
  switch (event.type) {
    case "BaseCampPitched":
      return { status: "pitched", id: event.id, altitude: event.altitude };
    case "BaseCampStruck":
      return { status: "none" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: BaseCampCommand, state: BaseCampState): BaseCampEvent[] {
  switch (command.type) {
    case "pitch":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "BaseCampPitched", id: command.id, altitude: command.altitude }];
    case "strike":
      if (state.status !== "pitched") throw new Error("NOT_PITCHED");
      return [{ type: "BaseCampStruck", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: ReadonlyArray<E>; revision: ExpectedRevision }>;
  appendToStream(stream: string, events: ReadonlyArray<E>, opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handleCommand(
  store: EventStore<BaseCampEvent>,
  streamName: string,
  command: BaseCampCommand,
): Promise<void> {
  const loaded = await store.readStream(streamName);
  let state = initialState;
  for (const event of loaded.events) {
    state = evolve(state, event);
  }
  const events = decide(command, state);
  await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
}

