`fromEventObservable` wraps a `Subscribable<TEvent>` so its emitted events become events sent to the invoking parent machine. XState's own `Subscribable` type is RxJS-compatible but has no RxJS dependency — you can construct one directly. Completion triggers an `xstate.done.*` internal event; errors trigger `xstate.error.*`. Typed `input` lets you parametrize the subscription.

```typescript
import { setup, assign, fromEventObservable, type Subscribable } from 'xstate';

type Cursor = { readonly x: number; readonly y: number };
type Ctx = { cursor: Cursor };
type Ev = { type: 'MOVE'; cursor: Cursor };
type MoveEv = { type: 'MOVE'; cursor: Cursor };

const cursorStream = fromEventObservable<MoveEv, { rate: number }>(({ input }): Subscribable<MoveEv> => ({
  subscribe(observer) {
    const obs = typeof observer === 'function' ? { next: observer } : observer;
    let i = 0;
    const id = setInterval(() => obs.next?.({ type: 'MOVE', cursor: { x: i, y: i } }), input.rate);
    i += 1;
    return { unsubscribe: () => clearInterval(id) };
  }
}));

export const cursorMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { cursorStream }
}).createMachine({
  id: 'cursorMachine',
  initial: 'active',
  context: { cursor: { x: 0, y: 0 } },
  states: {
    active: {
      invoke: { src: 'cursorStream', input: { rate: 100 } },
      on: {
        MOVE: { actions: assign({ cursor: ({ event }) => event.cursor }) }
      }
    }
  }
});
```

