export type TreatmentEvent =
  | { type: "TreatmentAssigned"; treatmentId: string; subjectId: string }
  | { type: "TreatmentCompleted"; treatmentId: string; subjectId: string };

export interface OutboxRow {
  id: string;
  payload: { schema: string; data: Record<string, string> };
  publishedAt: string | null;
}

export interface AppendOptions {
  expectedRevision: bigint | "no_stream" | "any";
}

export interface TransactionalConnection {
  appendToStream<E>(stream: string, events: E[], opts: AppendOptions): Promise<void>;
  insertOutbox(rows: OutboxRow[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface ConnectionFactory {
  begin(): Promise<TransactionalConnection>;
}

// A separate background worker polls unpublished outbox rows, publishes them
// to the broker, and marks them published. That worker is intentionally out of
// scope here: this function only guarantees the atomic write.

export async function appendWithOutbox(
  factory: ConnectionFactory,
  stream: string,
  events: TreatmentEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<void> {
  const conn = await factory.begin();
  try {
    await conn.appendToStream<TreatmentEvent>(stream, events, { expectedRevision });
    await conn.insertOutbox(outboxRows);
    await conn.commit();
  } catch (err) {
    await conn.rollback();
    throw err;
  }
}
