```typescript
import { Effect } from "effect";

export type ConsentPackageState =
  | { status: "none" }
  | { status: "draft"; id: string }
  | { status: "signed"; id: string; signedAt: string };

export type ConsentPackageCommand =
  | { type: "draft"; id: string }
  | { type: "sign"; at: string };

export type ConsentPackageEvent =
  | { type: "ConsentPackageDrafted"; id: string }
  | { type: "ConsentPackageSigned"; at: string };

const initial: ConsentPackageState = { status: "none" };

function evolve(state: ConsentPackageState, event: ConsentPackageEvent): ConsentPackageState {
  switch (event.type) {
    case "ConsentPackageDrafted":
      return { status: "draft", id: event.id };
    case "ConsentPackageSigned":
      return state.status === "draft" ? { status: "signed", id: state.id, signedAt: event.at } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: ConsentPackageCommand, state: ConsentPackageState): ConsentPackageEvent[] {
  switch (command.type) {
    case "draft":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ConsentPackageDrafted", id: command.id }];
    case "sign":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "ConsentPackageSigned", at: command.at }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export const handle = (
  command: ConsentPackageCommand,
  ctx: { streamName: string; eventStore: EventStore },
) =>
  Effect.gen(function* () {
    const read = yield* Effect.promise(() => ctx.eventStore.readStream<ConsentPackageEvent>(ctx.streamName));
    const state = read.events.reduce(evolve, initial);
    const events = decide(command, state);
    yield* Effect.promise(() => ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision }));
  });
