Tag every snapshot with a numeric version and a CURRENT_VERSION constant. Write a pure upgrader per source version. The loader runs them in order and a final type assertion ensures the output conforms to the current shape.

```typescript
export type CurrentDigitalCopy = {
  id: string;
  format: "pdf" | "epub";
  pages: number;
  checksum: string;
};

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3 as const;

type V1 = Snapshot<{ id: string; pages: number }>;
type V2 = Snapshot<{ id: string; format: "pdf" | "epub"; pages: number }>;
type V3 = Snapshot<CurrentDigitalCopy>;

function v1Tov2(snap: V1): V2 {
  return { version: 2, state: { id: snap.state.id, format: "pdf", pages: snap.state.pages } };
}

function v2Tov3(snap: V2): V3 {
  return { version: 3, state: { ...snap.state, checksum: "" } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDigitalCopy> {
  let current: Snapshot<unknown> = snap;
  if (current.version === 1) current = v1Tov2(current as V1);
  if (current.version === 2) current = v2Tov3(current as V2);
  if (current.version !== CURRENT_VERSION) throw new Error("unsupported snapshot version");
  return current as Snapshot<CurrentDigitalCopy>;
}
```

Persist the stream position only AFTER the read model has been updated. If the process dies between them you re-apply the last event on restart, which is safe because the projection is idempotent.

```typescript
export type PackingEvent =
  | { type: "PackingStarted"; id: string; revision: bigint }
  | { type: "PackingSealed"; id: string; at: string; revision: bigint };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface PackingView { readonly open: number; readonly sealed: number; }
export const emptyView: PackingView = { open: 0, sealed: 0 };

export function project(v: PackingView, e: PackingEvent): PackingView {
  switch (e.type) {
    case "PackingStarted": return { ...v, open: v.open + 1 };
    case "PackingSealed": return { open: v.open - 1, sealed: v.sealed + 1 };
    default: { const _n: never = e; return v; }
  }
}

export interface EventReader {
  readFromStream(name: string, from: bigint): AsyncIterable<PackingEvent>;
}

export interface ViewStore {
  load(): Promise<PackingView>;
  save(v: PackingView): Promise<void>;
}

export async function runPackingSubscription(
  name: string,
  reader: EventReader,
  views: ViewStore,
  checkpoints: CheckpointStore,
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? -1n;
  let view = await views.load();
  async function main(): Promise<void> {
    for await (const event of reader.readFromStream("packing-*", start + 1n)) {
      view = project(view, event);
      await views.save(view);
      await checkpoints.write(name, event.revision);
    }
  }
  await main();
}
```

```typescript
export type Snapshot<S> = { version: number; state: S };

export type DeliveryV1 = { id: string; courier: string };
export type DeliveryV2 = { id: string; courier: string; status: "dispatched" | "delivered" };
export type DeliveryV3 = {
  id: string;
  courier: string;
  status: "dispatched" | "delivered" | "failed";
  attempts: number;
};

export type CurrentDelivery = DeliveryV3;
export const CURRENT_VERSION = 3;

export class SnapshotUpgradeError extends Error {}

function v1Tov2(s: DeliveryV1): DeliveryV2 {
  return { ...s, status: "dispatched" };
}

function v2Tov3(s: DeliveryV2): DeliveryV3 {
  return { ...s, attempts: 1 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDelivery> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new SnapshotUpgradeError(`UNSUPPORTED_${version}`);
  }
  if (version === 1) {
    state = v1Tov2(state as DeliveryV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as DeliveryV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new SnapshotUpgradeError("INCOMPLETE");
  const upgraded = state as CurrentDelivery;
  if (typeof upgraded.id !== "string" || typeof upgraded.attempts !== "number") {
    throw new SnapshotUpgradeError("SHAPE_MISMATCH");
  }
  return { version, state: upgraded };
}

export function loadDelivery(raw: Snapshot<unknown>): CurrentDelivery {
  return upgradeSnapshot(raw).state;
}
```

