CQRS splits the model: the write side lives on the stream, enforces invariants via `decide`, and appends events through the event store. The read side is a projection populated by a subscription; queries never touch the write model. The two sides share the event DU but not the state type -- the write state carries invariants, while the read view carries denormalised, query-friendly fields. The read store is eventually consistent with the event store.

```typescript
export type HarvestCommand = { type: "schedule"; id: string; cropId: string; at: string } | { type: "complete"; id: string; yieldKg: number };
export type HarvestEvent = { type: "HarvestScheduled"; id: string; cropId: string; at: string } | { type: "HarvestCompleted"; id: string; yieldKg: number };

type WriteState = { status: "none" } | { status: "scheduled"; id: string } | { status: "completed"; id: string; yieldKg: number };
const initial: WriteState = { status: "none" };

function evolve(state: WriteState, event: HarvestEvent): WriteState {
  switch (event.type) {
    case "HarvestScheduled": return { status: "scheduled", id: event.id };
    case "HarvestCompleted": if (state.status !== "scheduled") return state; return { status: "completed", id: state.id, yieldKg: event.yieldKg };
    default: { const _n: never = event; return state; }
  }
}

function decide(cmd: HarvestCommand, state: WriteState): HarvestEvent[] {
  switch (cmd.type) {
    case "schedule": if (state.status !== "none") throw new Error("EXISTS"); return [{ type: "HarvestScheduled", id: cmd.id, cropId: cmd.cropId, at: cmd.at }];
    case "complete": if (state.status !== "scheduled") throw new Error("NOT_SCHEDULED"); return [{ type: "HarvestCompleted", id: cmd.id, yieldKg: cmd.yieldKg }];
    default: { const _n: never = cmd; throw new Error("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: HarvestEvent }>>;
  appendToStream(stream: string, events: ReadonlyArray<HarvestEvent>, opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface HarvestView { readonly id: string; readonly cropId: string; readonly yieldKg: number | null; }
export interface ReadStore { getHarvest(id: string): Promise<HarvestView | null>; }

export async function handleCommand(cmd: HarvestCommand, store: EventStore): Promise<void> {
  const stream = `harvest-${cmd.id}`;
  const stored = await store.readStream(stream);
  const state = stored.reduce<WriteState>((s, r) => evolve(s, r.event), initial);
  const events = decide(cmd, state);
  const expected: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, events, { expectedRevision: expected });
}

export async function queryView(id: string, reads: ReadStore): Promise<HarvestView | null> {
  return reads.getHarvest(id);
}
```

