```typescript
export type EventEnvelope<E> = { revision: bigint; event: E };

export interface EventStoreReader<E> {
  readForward(from: bigint, batchSize: number): Promise<ReadonlyArray<EventEnvelope<E>>>;
}

export interface ReadModelStore<V> {
  wipe(): Promise<void>;
  get(): Promise<V>;
  put(view: V): Promise<void>;
}

export interface RebuildOptions<V, E> {
  from: bigint;
  batchSize: number;
  project: (view: V, event: E) => V;
  persist: (view: V) => Promise<void>;
  onProgress?: (cursor: bigint, processed: number) => void;
  wipeFirst: boolean;
  emptyView: V;
  reader: EventStoreReader<E>;
  store: ReadModelStore<V>;
}

export async function rebuild<V, E>(options: RebuildOptions<V, E>): Promise<void> {
  if (options.wipeFirst) await options.store.wipe();
  let cursor: bigint = options.from;
  let processed = 0;
  let view: V = options.from === 0n ? options.emptyView : await options.store.get();
  while (true) {
    const batch = await options.reader.readForward(cursor, options.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = options.project(view, event);
      cursor = revision + 1n;
      processed = processed + 1;
    }
    await options.persist(view);
    if (options.onProgress) options.onProgress(cursor, processed);
  }
}
