A typed append boundary keeps the domain free of client imports, lets tests inject fakes, and uses a single discriminated event union so every call site enjoys exhaustive checking.

```typescript
type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStoreDB<E> {
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: E }>;
}

export type LoadAssignmentEvent =
  | { type: "LoadAssignmentCreated"; id: string; routeId: string }
  | { type: "LoadAssignmentAccepted"; driverId: string; at: string }
  | { type: "LoadAssignmentRejected"; reason: string };

export async function appendLoadAssignmentEvents(
  store: EventStoreDB<LoadAssignmentEvent>,
  streamName: string,
  events: readonly LoadAssignmentEvent[],
  expected: ExpectedRevision,
): Promise<bigint> {
  const { nextRevision } = await store.appendToStream(streamName, events, { expectedRevision: expected });
  return nextRevision;
}

export async function hydrate(
  store: EventStoreDB<LoadAssignmentEvent>,
  streamName: string,
): Promise<readonly LoadAssignmentEvent[]> {
  const out: LoadAssignmentEvent[] = [];
  for await (const { event } of store.readStream(streamName)) {
    out.push(event);
  }
  return out;
}
```

```typescript
import { Effect } from "effect";

export class DomainError extends Error {}

export type FieldAgentState = { status: "none" } | { status: "recruited"; id: string } | { status: "active"; id: string };
export type FieldAgentCommand = { type: "recruit"; id: string } | { type: "activate" };
export type FieldAgentEvent = { type: "recruited"; id: string } | { type: "activated" };

const initialState: FieldAgentState = { status: "none" };

function evolve(s: FieldAgentState, e: FieldAgentEvent): FieldAgentState {
  switch (e.type) {
    case "recruited":
      return { status: "recruited", id: e.id };
    case "activated":
      return s.status === "recruited" ? { status: "active", id: s.id } : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: FieldAgentCommand, s: FieldAgentState): FieldAgentEvent[] {
  switch (c.type) {
    case "recruit":
      if (s.status !== "none") throw new DomainError("exists");
      return [{ type: "recruited", id: c.id }];
    case "activate":
      if (s.status !== "recruited") throw new DomainError("not recruited");
      return [{ type: "activated" }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" }): Promise<{ nextRevision: bigint }>;
}

export function handle(
  command: FieldAgentCommand,
  ctx: { streamName: string; eventStore: EventStore<FieldAgentEvent> },
): Effect.Effect<void, Error, never> {
  return Effect.gen(function* () {
    const stored = yield* Effect.promise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = stored.reduce<FieldAgentState>((s, r) => evolve(s, r.event), initialState);
    const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
    const newEvents = decide(command, state);
    yield* Effect.promise(() => ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision }));
  });
}
```

```typescript
export type AssignmentEvent =
  | { type: "AssignmentAssigned"; id: string; learner: string }
  | { type: "AssignmentSubmitted"; at: string }
  | { type: "AssignmentGraded"; score: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export type AppendResult =
  | { ok: true; nextRevision: bigint }
  | { ok: false; actualRevision: bigint | null };

export interface EventStore {
  readStreamRevision(stream: string): Promise<bigint | null>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<AssignmentEvent>,
    options: { expectedRevision: ExpectedRevision },
  ): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(
    public readonly stream: string,
    public readonly expected: ExpectedRevision,
    public readonly actual: bigint | null,
  ) {
    super("CONCURRENCY_CONFLICT");
    this.name = "ConcurrencyConflict";
  }
}

export async function appendAssignmentEvents(
  store: EventStore,
  stream: string,
  events: ReadonlyArray<AssignmentEvent>,
): Promise<bigint> {
  const current = await store.readStreamRevision(stream);
  const expectedRevision: ExpectedRevision = current ?? "no_stream";
  const result = await store.appendToStream(stream, events, { expectedRevision });
  if (!result.ok) {
    throw new ConcurrencyConflict(stream, expectedRevision, result.actualRevision);
  }
  return result.nextRevision;
}
