```typescript
export type ChapterState =
  | { status: "none" }
  | { status: "open"; id: string; title: string; wordCount: number }
  | { status: "final"; id: string; title: string; wordCount: number };

export type ChapterCommand =
  | { type: "add"; id: string; title: string }
  | { type: "rename"; title: string }
  | { type: "finalize"; wordCount: number };

export type ChapterEvent =
  | { type: "ChapterAdded"; id: string; title: string }
  | { type: "ChapterRenamed"; title: string }
  | { type: "ChapterFinalized"; wordCount: number };

export class ChapterError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "ChapterError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const chapterDecider: Decider<ChapterCommand, ChapterEvent, ChapterState> = {
  initialState: { status: "none" },
  decide(command, state) {
    if (state.status === "final") throw new ChapterError("FINALIZED");
    switch (command.type) {
      case "add":
        if (state.status !== "none") throw new ChapterError("EXISTS");
        return [{ type: "ChapterAdded", id: command.id, title: command.title }];
      case "rename":
        if (state.status !== "open") throw new ChapterError("NOT_OPEN");
        return [{ type: "ChapterRenamed", title: command.title }];
      case "finalize":
        if (state.status !== "open") throw new ChapterError("NOT_OPEN");
        if (command.wordCount <= 0) throw new ChapterError("EMPTY");
        return [{ type: "ChapterFinalized", wordCount: command.wordCount }];
      default:
        throw new ChapterError("UNKNOWN");
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ChapterAdded":
        return { status: "open", id: event.id, title: event.title, wordCount: 0 };
      case "ChapterRenamed":
        if (state.status !== "open") return state;
        return { ...state, title: event.title };
      case "ChapterFinalized":
        if (state.status !== "open") return state;
        return { status: "final", id: state.id, title: state.title, wordCount: event.wordCount };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
