type DomainEvent =
  | { type: 'ConversationClosed'; conversationId: string; closedAt: string }
  | { type: 'NotificationDelivered'; recipientId: string; deliveredAt: string; channel: string }
  | { type: 'ParticipantAdded'; conversationId: string; userId: string }; // internal

