        payload: {
          recipientId: domainEvent.recipientId,
          deliveredAt: domainEvent.deliveredAt,
          channel: domainEvent.channel,
        },
      };
    case 'ParticipantAdded':
      return null; // internal-only; never leaves the boundary
    default: {
      const _: never = domainEvent;
      return _;
    }
  }
