        return [{ type: "AmenityAdded", id: command.id, name: command.name }];
      case "retire":
        if (state.status !== "active") throw new AmenityError("NOT_ACTIVE");
        return [{ type: "AmenityRetired", at: command.at }];
      default: {
        const _never: never = command;
        return _never;
