import { setup, assign } from 'xstate';

interface Ctx {
  past: string[];
  present: string;
  future: string[];
}

type Ev =
  | { type: 'SET'; v: string }
  | { type: 'UNDO' }
  | { type: 'REDO' };

export const refactoredHistory = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    applySet: assign(({ context, event }) => {
      if (event.type !== 'SET') return {};
      return {
        past: [...context.past, context.present],
        present: event.v,
        future: [] as string[]
      };
    }),
    applyUndo: assign(({ context }) => ({
      past: context.past.slice(0, -1),
      present: context.past[context.past.length - 1] ?? context.present,
      future: [context.present, ...context.future]
    })),
    applyRedo: assign(({ context }) => ({
      past: [...context.past, context.present],
      present: context.future[0] ?? context.present,
      future: context.future.slice(1)
    }))
  },
  guards: {
    canUndo: ({ context }) => context.past.length > 0,
    canRedo: ({ context }) => context.future.length > 0
  }
}).createMachine({
  id: 'history',
  context: { past: [], present: '', future: [] },
  on: {
    SET: { actions: 'applySet' },
    UNDO: { guard: 'canUndo', actions: 'applyUndo' },
    REDO: { guard: 'canRedo', actions: 'applyRedo' }
  }
});
