export const CURRENT_VERSION = 3 as const;

export interface CurrentState {
  id: string;
  price: number;
  currency: string;
  deposit: number;
}

export interface Snapshot<S> {
  version: number;
  state: S;
}

interface V1 {
  id: string;
  price: number;
}
interface V2 {
  id: string;
  price: number;
  currency: string;
}

function v1Tov2(s: V1): V2 {
  return { ...s, currency: "USD" };
}

function v2Tov3(s: V2): CurrentState {
  return { ...s, deposit: 0 };
}

export function upgradeSnapshot(
  snap: Snapshot<unknown>,
): Snapshot<CurrentState> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) {
    s = v1Tov2(s as V1);
    v = 2;
  }
  if (v === 2) {
    s = v2Tov3(s as V2);
    v = 3;
  }
  if (v !== CURRENT_VERSION) throw new Error(`bad version ${v}`);
  return { version: CURRENT_VERSION, state: s as CurrentState };
}
