export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type NotebookState =
  | { status: "none" }
  | { status: "draft"; id: string; cells: number }
  | { status: "published"; id: string };

export type NotebookEvent =
  | { type: "NotebookCreated"; id: string }
  | { type: "NotebookCellAppended" }
  | { type: "NotebookPublished" };

const emptyNotebook: NotebookState = { status: "none" };

function when(state: NotebookState, event: NotebookEvent): NotebookState {
  switch (event.type) {
    case "NotebookCreated":
      return { status: "draft", id: event.id, cells: 0 };
    case "NotebookCellAppended":
      return state.status === "draft" ? { ...state, cells: state.cells + 1 } : state;
    case "NotebookPublished":
      return state.status === "draft" ? { status: "published", id: state.id } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function loadNotebook(stream: AsyncIterable<NotebookEvent>): Promise<NotebookState> {
  return aggregateStream(stream, when, emptyNotebook);
