type NotifViewV1 = Readonly<{ userId: string; count: number }>;
type NotifViewV2 = Readonly<{ userId: string; unreadCount: number }>;

export type CurrentNotifView = NotifViewV2;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 2 as const;

function isV1(state: unknown): state is NotifViewV1 {
  return (
    typeof state === 'object' &&
    state !== null &&
    'count' in state &&
    typeof (state as { count: unknown }).count === 'number'
  );
}

function v1Tov2(s: NotifViewV1): NotifViewV2 {
  return { userId: s.userId, unreadCount: s.count };
}

export function upgrade(snap: Snapshot<unknown>): Snapshot<CurrentNotifView> {
  if (snap.version === CURRENT_VERSION) {
    return { version: CURRENT_VERSION, state: snap.state as CurrentNotifView };
  }
  if (snap.version === 1 && isV1(snap.state)) {
    return { version: CURRENT_VERSION, state: v1Tov2(snap.state) };
  }
  throw new Error(`unsupported version ${snap.version}`);
}
