export type RawEvent =
  | { type: "AlertRaised"; version: 1; data: { id: string } }
  | { type: "AlertRaised"; version: 2; data: { id: string; level: number } }
  | { type: "AlertCleared"; version: 1; data: { id: string; at: string } };

export type Event =
  | { type: "AlertRaised"; id: string; level: number }
  | { type: "AlertCleared"; id: string; at: string };

export class UnknownEventError extends Error {
  constructor(public readonly raw: RawEvent) {
    super(`UNKNOWN_EVENT:${raw.type}:${raw.version}`);
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: RawEvent): Event {
  switch (raw.type) {
    case "AlertRaised":
      switch (raw.version) {
        case 1:
          return { type: "AlertRaised", id: raw.data.id, level: 0 };
        case 2:
          return { type: "AlertRaised", id: raw.data.id, level: raw.data.level };
        default: { const _n: never = raw; throw new UnknownEventError(raw); }
      }
    case "AlertCleared":
      return { type: "AlertCleared", id: raw.data.id, at: raw.data.at };
    default: { const _n: never = raw; throw new UnknownEventError(raw); }
  }
}

export function aggregate(raws: RawEvent[]): Event[] {
  return raws.map(upcast);
}
