// Write side: command -> decide -> appendToStream.
// Read side: queryView reads a VendorDirectory built by a projection.
// The read store is eventually consistent with the event store.

export type VendorState = { status: "none" } | { status: "onboarded"; id: string; name: string };
export type VendorCommand = { type: "onboard"; id: string; name: string };
export type VendorEvent = { type: "VendorOnboarded"; id: string; name: string };

const initial: VendorState = { status: "none" };

function decide(c: VendorCommand, s: VendorState): VendorEvent[] {
  switch (c.type) {
    case "onboard":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "VendorOnboarded", id: c.id, name: c.name }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

function evolve(s: VendorState, e: VendorEvent): VendorState {
  switch (e.type) {
    case "VendorOnboarded":
      return { status: "onboarded", id: e.id, name: e.name };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore<E> {
  readStream(s: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    s: string, e: readonly E[], o: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export type VendorEntry = Readonly<{ id: string; name: string }>;
export interface VendorDirectory {
  find(id: string): Promise<VendorEntry | null>;
}

export async function handleCommand(
  cmd: VendorCommand,
  ctx: { streamName: string; eventStore: EventStore<VendorEvent> },
): Promise<void> {
  let state = initial;
  let rev: bigint | "no_stream" = "no_stream";
  for await (const rec of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, rec.event);
    rev = rec.revision;
  }
  await ctx.eventStore.appendToStream(ctx.streamName, decide(cmd, state), { expectedRevision: rev });
}

export async function queryView(id: string, dir: VendorDirectory): Promise<VendorEntry | null> {
  return dir.find(id);
}
