```typescript
export type NotebookState =
  | { status: "none" }
  | { status: "draft"; id: string; cells: number }
  | { status: "published"; id: string };

export type NotebookCommand =
  | { type: "create"; id: string }
  | { type: "appendCell" }
  | { type: "publish"; at: string };

export type NotebookEvent =
  | { type: "NotebookCreated"; id: string }
  | { type: "NotebookCellAppended" }
  | { type: "NotebookPublished"; at: string };

const initial: NotebookState = { status: "none" };

function evolve(state: NotebookState, event: NotebookEvent): NotebookState {
  switch (event.type) {
    case "NotebookCreated":
      return { status: "draft", id: event.id, cells: 0 };
    case "NotebookCellAppended":
      return state.status === "draft" ? { ...state, cells: state.cells + 1 } : state;
    case "NotebookPublished":
      return state.status === "draft" ? { status: "published", id: state.id } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: NotebookCommand, state: NotebookState): NotebookEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "NotebookCreated", id: command.id }];
    case "appendCell":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "NotebookCellAppended" }];
    case "publish":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "NotebookPublished", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(stream: string, events: E[], options: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handle(
  command: NotebookCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream<NotebookEvent>(ctx.streamName);
  const state = events.reduce(evolve, initial);
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision: revision });
}
