export interface AppendOk {
  readonly nextExpectedRevision: bigint;
  readonly ok: true;
}

export interface AppendConflict {
  readonly ok: false;
  readonly reason: "revision_mismatch";
}

export type AppendOutcome = AppendOk | AppendConflict;

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: ReadonlyArray<E>; revision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<AppendOutcome>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export type DonorEvent =
  | { type: "DonorRegistered"; id: string; name: string }
  | { type: "DonorGiftRecorded"; id: string; amount: number; at: string };

export async function appendDonorEvents(
  store: EventStore<DonorEvent>,
  stream: string,
  events: ReadonlyArray<DonorEvent>
): Promise<bigint> {
  const { revision } = await store.readStream(stream);
  const outcome = await store.appendToStream(stream, events, { expectedRevision: revision });
  if (!outcome.ok) throw new ConcurrencyConflict(stream, revision);
  return outcome.nextExpectedRevision;
}
