export type DonorEvent =
  | { type: "DonorRegistered"; id: string; name: string }
  | { type: "DonorGiftRecorded"; id: string; amount: number; at: string }
  | { type: "DonorGiftRefunded"; id: string; amount: number }
  | { type: "DonorDeactivated"; id: string };

export interface DonorTotalsView {
  readonly totalsById: Readonly<Record<string, number>>;
  readonly namesById: Readonly<Record<string, string>>;
  readonly lastGiftAt: string | null;
}

export const emptyView: DonorTotalsView = { totalsById: {}, namesById: {}, lastGiftAt: null };

export function project(view: DonorTotalsView, event: DonorEvent): DonorTotalsView {
  switch (event.type) {
    case "DonorRegistered":
      return { ...view, namesById: { ...view.namesById, [event.id]: event.name } };
    case "DonorGiftRecorded": {
      const prev = view.totalsById[event.id] ?? 0;
      return {
        ...view,
        totalsById: { ...view.totalsById, [event.id]: prev + event.amount },
        lastGiftAt: event.at,
      };
    }
    case "DonorGiftRefunded": {
      const prev = view.totalsById[event.id] ?? 0;
      return { ...view, totalsById: { ...view.totalsById, [event.id]: Math.max(0, prev - event.amount) } };
    }
    case "DonorDeactivated":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
