```typescript
export type TransferEvent =
  | { type: "TransferRequested"; id: string; from: string; to: string; amount: number }
  | { type: "TransferCompleted"; id: string; at: string }
  | { type: "TransferFailed"; id: string; reason: string };

export type TransferView = Readonly<{
  byId: Readonly<Record<string, {
    from: string;
    to: string;
    amount: number;
    status: "pending" | "completed" | "failed";
  }>>;
}>;

export const emptyView: TransferView = { byId: {} };

export function project(view: TransferView, event: TransferEvent): TransferView {
  switch (event.type) {
    case "TransferRequested":
      return {
        byId: { ...view.byId, [event.id]: {
          from: event.from, to: event.to, amount: event.amount, status: "pending",
        } },
      };
    case "TransferCompleted": {
      const prior = view.byId[event.id];
      if (!prior) return view;
      return { byId: { ...view.byId, [event.id]: { ...prior, status: "completed" } } };
    }
    case "TransferFailed": {
      const prior = view.byId[event.id];
      if (!prior) return view;
      return { byId: { ...view.byId, [event.id]: { ...prior, status: "failed" } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventIterator {
  iterate(from: bigint): AsyncIterable<Readonly<{ position: bigint; event: TransferEvent }>>;
}

export interface ViewStore {
  load(): Promise<TransferView>;
  save(view: TransferView): Promise<void>;
}

export async function runSubscription(
  name: string,
  iterator: EventIterator,
  checkpoints: CheckpointStore,
  views: ViewStore,
): Promise<void> {
  const last = await checkpoints.read(name);
  const from = last === null ? 0n : last + 1n;
  let view = await views.load();
  for await (const { position, event } of iterator.iterate(from)) {
    view = project(view, event);
    await views.save(view);
    await checkpoints.write(name, position);
  }
}
