export type CohortState =
  | { status: "none" }
  | { status: "forming"; id: string; capacity: number; members: ReadonlyArray<string> }
  | { status: "sealed"; id: string; members: ReadonlyArray<string> };

export type CohortCommand =
  | { type: "form"; id: string; capacity: number }
  | { type: "admit"; learner: string }
  | { type: "seal" };

export type CohortEvent =
  | { type: "CohortFormed"; id: string; capacity: number }
  | { type: "LearnerAdmitted"; learner: string }
  | { type: "CohortSealed" };

export class CohortError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const cohortDecider: Decider<CohortCommand, CohortEvent, CohortState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "form":
        if (s.status !== "none") throw new CohortError("ALREADY_FORMED");
        if (c.capacity <= 0) throw new CohortError("CAPACITY_INVALID");
        return [{ type: "CohortFormed", id: c.id, capacity: c.capacity }];
      case "admit":
        if (s.status !== "forming") throw new CohortError("NOT_FORMING");
        if (s.members.includes(c.learner)) throw new CohortError("DUPLICATE_LEARNER");
        if (s.members.length >= s.capacity) throw new CohortError("CAPACITY_REACHED");
        return [{ type: "LearnerAdmitted", learner: c.learner }];
      case "seal":
        if (s.status !== "forming") throw new CohortError("NOT_FORMING");
        if (s.members.length === 0) throw new CohortError("NO_MEMBERS");
        return [{ type: "CohortSealed" }];
      default: { const _n: never = c; throw new CohortError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "CohortFormed":
        return { status: "forming", id: e.id, capacity: e.capacity, members: [] };
      case "LearnerAdmitted":
        if (s.status !== "forming") return s;
        return { status: "forming", id: s.id, capacity: s.capacity, members: [...s.members, e.learner] };
      case "CohortSealed":
        if (s.status !== "forming") return s;
        return { status: "sealed", id: s.id, members: s.members };
      default: { const _n: never = e; return s; }
    }
  },
};
