import { setup, assign, fromPromise } from 'xstate';

interface Job { id: string }

interface Ctx {
  queue: Job[];
  inFlight: number;
  done: number;
  limit: number;
}

type Ev =
  | { type: 'ENQUEUE'; job: Job }
  | { type: 'RUN' }
  | { type: 'FINISH' };

const worker = fromPromise<string, { job: Job }>(async ({ input }) => {
  await new Promise((r) => setTimeout(r, 5));
  return input.job.id;
});

export const concurrencyQueueMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { worker },
  guards: {
    hasSlot: ({ context }) =>
      context.inFlight < context.limit && context.queue.length > 0
  },
  actions: {
    enqueue: assign({
      queue: ({ context, event }) =>
        event.type === 'ENQUEUE' ? [...context.queue, event.job] : context.queue
    }),
    startOne: assign({
      inFlight: ({ context }) => context.inFlight + 1,
      queue: ({ context }) => context.queue.slice(1)
    }),
    finishOne: assign({
      inFlight: ({ context }) => context.inFlight - 1,
      done: ({ context }) => context.done + 1
    })
  }
}).createMachine({
  id: 'pool',
  context: { queue: [], inFlight: 0, done: 0, limit: 3 },
  on: {
    ENQUEUE: { actions: 'enqueue' },
    RUN: { guard: 'hasSlot', actions: 'startOne' },
    FINISH: { actions: 'finishOne' }
  }
});
