type Ev = { type: 'PAUSE' } | { type: 'RESUME' } | { type: 'NEXT' } | { type: 'BACK' };

export const wizardHistory = setup({
  types: { events: {} as Ev }
}).createMachine({
  id: 'wizardHistory',
  initial: 'editing',
  states: {
    editing: {
      initial: 'step1',
      on: { PAUSE: 'paused' },
      states: {
        step1: { on: { NEXT: 'step2' } },
        step2: { on: { NEXT: 'step3', BACK: 'step1' } },
        step3: { on: { BACK: 'step2' } },
        hist: { type: 'history', history: 'shallow' }
      }
    },
    paused: {
      on: { RESUME: '#wizardHistory.editing.hist' }
    }
  }
});
