```typescript
export type IngredientState =
  | { status: "none" }
  | { status: "active"; id: string; name: string; grams: number }
  | { status: "discontinued"; id: string; reason: string };

export type IngredientCommand =
  | { type: "register"; id: string; name: string }
  | { type: "restock"; grams: number }
  | { type: "consume"; grams: number }
  | { type: "discontinue"; reason: string };

export type IngredientEvent =
  | { type: "IngredientRegistered"; id: string; name: string }
  | { type: "IngredientRestocked"; grams: number }
  | { type: "IngredientConsumed"; grams: number }
  | { type: "IngredientDiscontinued"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const ingredientDecider: Decider<IngredientCommand, IngredientEvent, IngredientState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "IngredientRegistered", id: command.id, name: command.name }];
      case "restock":
        if (state.status === "discontinued") throw new DomainError("DISCONTINUED");
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.grams <= 0) throw new DomainError("BAD_GRAMS");
        return [{ type: "IngredientRestocked", grams: command.grams }];
      case "consume":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.grams > state.grams) throw new DomainError("INSUFFICIENT");
        return [{ type: "IngredientConsumed", grams: command.grams }];
      case "discontinue":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "IngredientDiscontinued", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "IngredientRegistered":
        return { status: "active", id: event.id, name: event.name, grams: 0 };
      case "IngredientRestocked":
        if (state.status !== "active") return state;
        return { ...state, grams: state.grams + event.grams };
      case "IngredientConsumed":
        if (state.status !== "active") return state;
        return { ...state, grams: state.grams - event.grams };
      case "IngredientDiscontinued":
        if (state.status !== "active") return state;
        return { status: "discontinued", id: state.id, reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

```

Store the current column and direction in context. On `SORT`, branch by whether it's the same column: clicking the active column advances `asc → desc → none`, clicking a different column resets to `asc`. Keeping the transition logic in a single `assign` keeps the state chart flat.

```typescript
import { setup, assign } from 'xstate';

type Col = 'name' | 'price';
type Dir = 'asc' | 'desc' | null;
type Ctx = { col: Col | null; dir: Dir };
type Ev = { type: 'SORT'; column: Col };

export const sortMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'sort',
  context: { col: null, dir: null },
  initial: 'idle',
  states: {
    idle: {
      on: {
        SORT: {
          actions: assign(({ context, event }) => {
            if (context.col !== event.column) {
              return { col: event.column, dir: 'asc' as Dir };
            }
            const next: Dir = context.dir === 'asc' ? 'desc' : context.dir === 'desc' ? null : 'asc';
            return { col: next === null ? null : event.column, dir: next };
          }),
        },
      },
    },
  },
});
```

The offending code couples a domain state machine to XState. Event-sourcing wants the state transitions to live in a pure `evolve` reducer and the guards in a pure `decide`. Replace the machine with a Decider record.

```typescript
type MessageCommand =
  | { type: 'PostMessage'; id: string; body: string }
  | { type: 'EditMessage'; body: string };

type MessageEvent =
  | { type: 'MessagePosted'; id: string; body: string }
  | { type: 'MessageEdited'; body: string };

type MessageState =
  | { status: 'draft' }
  | { status: 'live'; id: string; body: string };

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const MessageDecider: Decider<MessageCommand, MessageEvent, MessageState> = {
  initialState: { status: 'draft' },
  decide(command, state) {
    switch (command.type) {
      case 'PostMessage':
        if (state.status !== 'draft') throw new Error('already posted');
        return [{ type: 'MessagePosted', id: command.id, body: command.body }];
      case 'EditMessage':
        if (state.status !== 'live') throw new Error('not live');
        return [{ type: 'MessageEdited', body: command.body }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'MessagePosted':
        return { status: 'live', id: event.id, body: event.body };
      case 'MessageEdited':
        return state.status === 'live' ? { ...state, body: event.body } : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
