```typescript
export type ClaimEvent =
  | { type: "ClaimFiled"; id: string; amount: number }
  | { type: "ClaimApproved"; id: string; at: string }
  | { type: "ClaimRejected"; id: string; reason: string };

export type ClaimStats = Readonly<{
  filedCount: number;
  approvedTotal: number;
  rejectedCount: number;
  averageClaim: number;
}>;

export const emptyView: ClaimStats = {
  filedCount: 0,
  approvedTotal: 0,
  rejectedCount: 0,
  averageClaim: 0,
};

const amounts = new Map<string, number>();

export function project(view: ClaimStats, event: ClaimEvent): ClaimStats {
  switch (event.type) {
    case "ClaimFiled": {
      amounts.set(event.id, event.amount);
      const nextCount = view.filedCount + 1;
      const nextAvg =
        (view.averageClaim * view.filedCount + event.amount) / nextCount;
      return { ...view, filedCount: nextCount, averageClaim: nextAvg };
    }
    case "ClaimApproved": {
      const amt = amounts.get(event.id) ?? 0;
      return { ...view, approvedTotal: view.approvedTotal + amt };
    }
    case "ClaimRejected":
      return { ...view, rejectedCount: view.rejectedCount + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function aggregate(events: ClaimEvent[]): ClaimStats {
  return events.reduce<ClaimStats>(project, emptyView);
}
```

```typescript
export type CropEvent =
  | { type: "CropPlanted"; id: string; variety: string; at: string }
  | { type: "CropGrowthAdvanced"; days: number }
  | { type: "CropHarvested"; yieldKg: number };

export interface StoredEvent<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function writeCropEvents(
  store: EventStore<CropEvent>,
  stream: string,
  events: ReadonlyArray<CropEvent>
): Promise<bigint> {
  const stored = await store.readStream(stream);
  const expected: bigint | "no_stream" =
    stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  try {
    const result = await store.appendToStream(stream, events, { expectedRevision: expected });
    return result.nextExpectedRevision;
  } catch (err) {
    if (err instanceof Error && /revision|concurrency/i.test(err.message)) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
