```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

Write the checkpoint AFTER projecting the event so a crash mid-batch replays the last event on restart, not before.

```typescript
type ShotEvent = { type: 'ShotScheduled'; shotPoint: string } | { type: 'ShotFired'; at: string };

interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

interface EventStore {
  readFromStream(stream: string, from: bigint): AsyncIterable<{ event: ShotEvent; revision: bigint }>;
}

type View = { scheduled: number; fired: number };
const emptyView: View = { scheduled: 0, fired: 0 };

function project(view: View, event: ShotEvent): View {
  switch (event.type) {
    case 'ShotScheduled':
      return { ...view, scheduled: view.scheduled + 1 };
    case 'ShotFired':
      return { ...view, fired: view.fired + 1 };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function runSubscription(
  store: EventStore,
  cp: CheckpointStore,
  stream: string,
  name: string,
): Promise<void> {
  const start = (await cp.read(name)) ?? 0n;
  let view = emptyView;
  for await (const { event, revision } of store.readFromStream(stream, start)) {
    view = project(view, event);
    await cp.write(name, revision);
  }
  void view;
}
```

