  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "receive":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "SculptureReceived", id: command.id, title: command.title }];
      case "clean":
        if (state.status !== "received") throw new DomainError("NOT_RECEIVED");
        return [{ type: "SculptureCleaned", at: command.at }];
      case "display":
        if (state.status !== "cleaned") throw new DomainError("NOT_CLEANED");
        return [{ type: "SculptureDisplayed", hall: command.hall }];
      case "deaccession":
        if (state.status === "deaccessioned" || state.status === "none") throw new DomainError("CANNOT_DEACCESSION");
        return [{ type: "SculptureDeaccessioned", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SculptureReceived":
        return { status: "received", id: event.id, title: event.title };
      case "SculptureCleaned":
        if (state.status !== "received") return state;
        return { status: "cleaned", id: state.id, title: state.title, cleanedAt: event.at };
      case "SculptureDisplayed":
        if (state.status !== "cleaned") return state;
        return { status: "displayed", id: state.id, title: state.title, hall: event.hall };
      case "SculptureDeaccessioned":
        if (state.status === "none" || state.status === "deaccessioned") return state;
        return { status: "deaccessioned", id: state.id, at: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
