import { setup, assign, fromPromise } from 'xstate';

interface Job { readonly id: string }
interface Ctx { readonly current: Job | null; readonly lastError: string | null }
type Ev = { type: 'ENQUEUE'; job: Job } | { type: 'RETRY' };

export const printer = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    print: fromPromise<void, { job: Job }>(async () => { throw new Error('paper jam'); })
  }
}).createMachine({
