export class StreamReadError { readonly _tag = "StreamReadError" as const; constructor(public readonly cause: unknown) {} }

export interface EventStoreDB {
  readFromStream: (stream: string) => Promise<TailEvent[]>;
}

export const loadTail = (store: EventStoreDB, stream: string) =>
  Effect.gen(function* () {
    const events = yield* Effect.tryPromise({
      try: () => store.readFromStream(stream),
      catch: (e) => new StreamReadError(e),
    });
    return events.reduce<TailState>(when, initial);
  });
