export function project(view: ActiveExhibitionsView, event: ExhibitionEvent): ActiveExhibitionsView {
  switch (event.type) {
    case "ExhibitionCurated":
      return { ...view, totalEver: view.totalEver + 1 };
    case "ExhibitionScheduled":
      return view;
    case "ExhibitionStarted": {
      const existing = view.running[event.id];
      if (existing) return view;
      return { ...view, running: { ...view.running, [event.id]: { theme: "", pieces: 0 } } };
    }
    case "ExhibitionEnded": {
      const copy = { ...view.running };
      delete copy[event.id];
      return { ...view, running: copy };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}
