import { setup, assign } from 'xstate';

interface EditorContext {
  past: string[];
  present: string;
  future: string[];
  limit: number;
}

type EditorEvent =
  | { type: 'EDIT'; value: string }
  | { type: 'UNDO' }
  | { type: 'REDO' };

export const boundedEditorMachine = setup({
  types: {
    context: {} as EditorContext,
    events: {} as EditorEvent
  },
  guards: {
    canUndo: ({ context }) => context.past.length > 0,
    canRedo: ({ context }) => context.future.length > 0
  },
  actions: {
    pushEdit: assign(({ context, event }) => {
      if (event.type !== 'EDIT') return {};
      const next = [...context.past, context.present];
      return {
        past: next.length > context.limit ? next.slice(next.length - context.limit) : next,
        present: event.value,
        future: [] as string[]
      };
    }),
    popUndo: assign(({ context }) => ({
      past: context.past.slice(0, -1),
      present: context.past[context.past.length - 1] ?? context.present,
      future: [context.present, ...context.future]
    })),
    popRedo: assign(({ context }) => ({
      past: [...context.past, context.present],
      present: context.future[0] ?? context.present,
      future: context.future.slice(1)
    }))
  }
}).createMachine({
  id: 'editor',
  context: { past: [], present: '', future: [], limit: 50 },
  on: {
    EDIT: { actions: 'pushEdit' },
    UNDO: { guard: 'canUndo', actions: 'popUndo' },
    REDO: { guard: 'canRedo', actions: 'popRedo' }
  }
});
