export type ArtefactEvent =
  | { type: "ArtefactPublished"; id: string; sha256: string; sizeBytes: number }
  | { type: "ArtefactSigned"; signer: string }
  | { type: "ArtefactRetracted"; reason: string };

export interface ArtefactState {
  readonly id?: string;
  readonly sha256?: string;
  readonly sizeBytes?: number;
  readonly signed: boolean;
  readonly retracted: boolean;
}

export const initial: ArtefactState = { signed: false, retracted: false };

export function when(state: ArtefactState, event: ArtefactEvent): ArtefactState {
  switch (event.type) {
    case "ArtefactPublished":
      return { ...state, id: event.id, sha256: event.sha256, sizeBytes: event.sizeBytes };
    case "ArtefactSigned":
      return { ...state, signed: true };
    case "ArtefactRetracted":
      return { ...state, retracted: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  reducer: (state: S, event: E) => S,
  initialState: S,
): Promise<S> {
  let state: S = initialState;
  for await (const event of events) {
    state = reducer(state, event);
  }
  return state;
}

export async function loadArtefact(stream: AsyncIterable<ArtefactEvent>): Promise<ArtefactState> {
  return aggregateStream(stream, when, initial);
}
