  | { type: 'ModerateMessage'; messageId: string; body: string }
  | { type: 'BroadcastMessage'; messageId: string }
  | { type: 'NotifyAuthor'; authorId: string; reason: string };

export function react(event: DomainEvent): DomainCommand | null {
  switch (event.type) {
    case 'MessagePosted':
      return { type: 'ModerateMessage', messageId: event.messageId, body: event.body };
    case 'MessageApproved':
      return { type: 'BroadcastMessage', messageId: event.messageId };
    case 'MessageRejected':
      return { type: 'NotifyAuthor', authorId: event.authorId, reason: event.reason };
    case 'OtherEvent':
      return null;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface CommandHandler {
  handle(command: DomainCommand): Promise<void>;
}

export async function runSaga(event: DomainEvent, handler: CommandHandler): Promise<void> {
  const next = react(event);
  if (next !== null) await handler.handle(next);
