export type AudienceSegmentEvent =
  | { type: "AudienceSegmentDefined"; id: string; name: string }
  | { type: "AudienceSegmentRuleAdded"; id: string; rule: string }
  | { type: "AudienceSegmentSealed"; id: string };

export interface EventRecord<E> { event: E; revision: bigint; }

export interface EventStore {
  readBatch<E>(opts: { from: bigint; batchSize: number }): Promise<EventRecord<E>[]>;
}

export interface View {
  bySegment: Record<string, { name: string; rules: string[]; sealed: boolean } | undefined>;
}

export function project(view: View, event: AudienceSegmentEvent): View {
  switch (event.type) {
    case "AudienceSegmentDefined":
      return { bySegment: { ...view.bySegment, [event.id]: { name: event.name, rules: [], sealed: false } } };
    case "AudienceSegmentRuleAdded": {
      const prev = view.bySegment[event.id] ?? { name: "", rules: [], sealed: false };
      return { bySegment: { ...view.bySegment, [event.id]: { ...prev, rules: [...prev.rules, event.rule] } } };
    }
    case "AudienceSegmentSealed": {
      const prev = view.bySegment[event.id] ?? { name: "", rules: [], sealed: false };
      return { bySegment: { ...view.bySegment, [event.id]: { ...prev, sealed: true } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStore;
  persist: (view: View, cursor: bigint) => Promise<void>;
}): Promise<void> {
  let cursor = opts.from;
  let view: View = { bySegment: {} };
  for (;;) {
    const batch = await opts.store.readBatch<AudienceSegmentEvent>({ from: cursor, batchSize: opts.batchSize });
    if (batch.length === 0) return;
    for (const rec of batch) {
      view = project(view, rec.event);
      cursor = rec.revision + 1n;
    }
    await opts.persist(view, cursor);
  }
}
