export type CoverageEvent =
  | { type: "CoverageAdded"; policyId: string; amount: number }
  | { type: "CoverageRemoved"; policyId: string; amount: number }
  | { type: "CoverageExpired"; policyId: string };

export type CoverageView = Readonly<{
  activeCount: number;
  totalAmount: number;
  expiredCount: number;
}>;

export const emptyView: CoverageView = {
  activeCount: 0,
  totalAmount: 0,
  expiredCount: 0,
};

export function project(view: CoverageView, event: CoverageEvent): CoverageView {
  switch (event.type) {
    case "CoverageAdded":
      return {
        ...view,
        activeCount: view.activeCount + 1,
        totalAmount: view.totalAmount + event.amount,
      };
    case "CoverageRemoved":
      return {
        ...view,
        activeCount: Math.max(0, view.activeCount - 1),
        totalAmount: Math.max(0, view.totalAmount - event.amount),
      };
    case "CoverageExpired":
      return {
        ...view,
        activeCount: Math.max(0, view.activeCount - 1),
        expiredCount: view.expiredCount + 1,
      };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function aggregate(events: readonly CoverageEvent[]): CoverageView {
  return events.reduce<CoverageView>(project, emptyView);
}
