Upcasting runs at read time. Each stored event carries a `version`; the upcaster switches on `{ type, version }` and returns the canonical current shape. The projection consumes only the current shape, so it never sees legacy payloads.

```typescript
export type RawDispatchBeaconEvent =
  | { type: "DispatchBeaconArmed"; version: 1; id: string }
  | { type: "DispatchBeaconArmed"; version: 2; id: string; priority: "low" | "high" }
  | { type: "DispatchBeaconPulsed"; version: 1 }
  | { type: "DispatchBeaconFired"; version: 1; at: string };

export type DispatchBeaconEvent =
  | { type: "DispatchBeaconArmed"; id: string; priority: "low" | "high" }
  | { type: "DispatchBeaconPulsed" }
  | { type: "DispatchBeaconFired"; at: string };

export type DispatchBeaconView = Readonly<{
  id: string;
  priority: "low" | "high";
  pulses: number;
  firedAt?: string;
}>;

export const emptyBeaconView: DispatchBeaconView = { id: "", priority: "low", pulses: 0 };

export class UnknownEventError extends Error {}

export function upcast(raw: RawDispatchBeaconEvent): DispatchBeaconEvent {
  switch (raw.type) {
    case "DispatchBeaconArmed":
      if (raw.version === 1) return { type: "DispatchBeaconArmed", id: raw.id, priority: "low" };
      if (raw.version === 2) return { type: "DispatchBeaconArmed", id: raw.id, priority: raw.priority };
      throw new UnknownEventError(`Armed:${(raw as { version: number }).version}`);
    case "DispatchBeaconPulsed":
      if (raw.version === 1) return { type: "DispatchBeaconPulsed" };
      throw new UnknownEventError(`Pulsed:${(raw as { version: number }).version}`);
    case "DispatchBeaconFired":
      if (raw.version === 1) return { type: "DispatchBeaconFired", at: raw.at };
      throw new UnknownEventError(`Fired:${(raw as { version: number }).version}`);
    default: {
      const _n: never = raw;
      throw new UnknownEventError("UNKNOWN_TYPE");
    }
  }
}

export function project(view: DispatchBeaconView, event: DispatchBeaconEvent): DispatchBeaconView {
  switch (event.type) {
    case "DispatchBeaconArmed":
      return { id: event.id, priority: event.priority, pulses: 0 };
    case "DispatchBeaconPulsed":
      return { ...view, pulses: view.pulses + 1 };
    case "DispatchBeaconFired":
      return { ...view, firedAt: event.at };
    default: { const _n: never = event; return view; }
  }
}

export function viewFromRaw(raws: RawDispatchBeaconEvent[]): DispatchBeaconView {
  let view: DispatchBeaconView = emptyBeaconView;
  for (const raw of raws) {
    view = project(view, upcast(raw));
  }
  return view;
}
```

