import { setup, assign, enqueueActions, fromPromise } from 'xstate';

type Ctx = { query: string; cache: Record<string, string[]>; results: string[] };
type Ev = { type: 'INPUT'; text: string } | { type: 'CLEAR' };

const search = fromPromise<string[], { q: string }>(async ({ input }) => [input.q + '-a', input.q + '-b']);

export const combobox = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: {
    DEBOUNCE: () => 300,
  },
  actors: { search },
  actions: {
    cacheAndShow: enqueueActions(({ enqueue, context, event }) => {
      if (event.type !== 'INPUT') return;
      const hit = context.cache[event.text];
      if (hit) {
        enqueue.assign({ results: hit });
      }
    }),
    storeInput: assign({ query: ({ event }) => (event.type === 'INPUT' ? event.text : '') }),
    clearAll: assign({ query: () => '', results: () => [] }),
  },
}).createMachine({
  id: 'combobox',
  context: { query: '', cache: {}, results: [] },
  initial: 'idle',
  states: {
    idle: {
      on: {
        INPUT: { target: 'debouncing', actions: ['storeInput', 'cacheAndShow'] },
        CLEAR: { actions: 'clearAll' },
      },
    },
    debouncing: {
      on: {
        INPUT: {
          target: 'debouncing',
          reenter: true,
          actions: ['storeInput', 'cacheAndShow'],
        },
      },
      after: { DEBOUNCE: 'fetching' },
    },
    fetching: {
      invoke: {
        src: 'search',
        input: ({ context }) => ({ q: context.query }),
        onDone: {
          target: 'idle',
          actions: assign({
            results: ({ event }) => event.output,
            cache: ({ context, event }) => ({ ...context.cache, [context.query]: event.output }),
          }),
        },
        onError: { target: 'idle' },
      },
    },
  },
});
