export type ReceivingDockEvent =
  | { type: "DockOpened"; id: string; code: string }
  | { type: "TruckArrived"; truckId: string; at: string }
  | { type: "TruckReleased"; truckId: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: ReadonlyArray<ReceivingDockEvent>; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<ReceivingDockEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<{ kind: "ok"; revision: bigint } | { kind: "conflict" }>;
}

export class ConcurrencyConflict extends Error {}

export async function appendWithRetry(
  store: EventStore,
  stream: string,
  compute: (events: ReadonlyArray<ReceivingDockEvent>) => ReadonlyArray<ReceivingDockEvent>,
): Promise<bigint> {
  for (let attempt = 0; attempt < 2; attempt++) {
    const slice = await store.readStream(stream);
    const toAppend = compute(slice.events);
    if (toAppend.length === 0) return slice.revision ?? -1n;
    const expectedRevision: ExpectedRevision = slice.revision ?? "no_stream";
    const result = await store.appendToStream(stream, toAppend, { expectedRevision });
    if (result.kind === "ok") return result.revision;
  }
  throw new ConcurrencyConflict(`Could not append to ${stream} after retry`);
}
