```typescript
export type PEvent =
  | { type: "Registered"; id: string; title: string }
  | { type: "IssuePublished"; id: string; issueId: string };
export type PCommand =
  | { type: "register"; id: string; title: string }
  | { type: "publishIssue"; id: string; issueId: string };
export type PState = { id: string; title: string; issues: ReadonlyArray<string> };

const initial: PState = { id: "", title: "", issues: [] };
export class DomainError extends Error {}

function evolve(state: PState, event: PEvent): PState {
  switch (event.type) {
    case "Registered":
      return { id: event.id, title: event.title, issues: [] };
    case "IssuePublished":
      return { ...state, issues: [...state.issues, event.issueId] };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(cmd: PCommand, state: PState): PEvent[] {
  switch (cmd.type) {
    case "register":
      return state.id ? [] : [{ type: "Registered", id: cmd.id, title: cmd.title }];
    case "publishIssue":
      if (!state.id) throw new DomainError("not registered");
      return [{ type: "IssuePublished", id: cmd.id, issueId: cmd.issueId }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export interface EventStore {
  readStream(n: string): AsyncIterable<{ event: PEvent; revision: bigint }>;
  appendToStream(n: string, e: ReadonlyArray<PEvent>, o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export type QueryView = { id: string; title: string; issueCount: number };
export interface ReadStore {
  get(id: string): Promise<QueryView | null>;
}

export async function handleCommand(command: PCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  let state = initial;
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  const events = decide(command, state);
  if (events.length) await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}

// NOTE: the read store is eventually consistent with the event store; a write
// may not appear in queryView until the projection subscription catches up.
export async function queryView(store: ReadStore, id: string): Promise<QueryView | null> {
  return store.get(id);
}
