interface Ctx {
  past: number[];
  present: number;
  future: number[];
}

type Ev =
  | { type: 'SET'; value: number }
  | { type: 'UNDO' }
  | { type: 'REDO' };

export const numberHistoryMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasPast: ({ context }) => context.past.length > 0,
    hasFuture: ({ context }) => context.future.length > 0
  },
