    commit: assign(({ context, event }) => {
      if (event.type !== 'SET') return {};
      return {
        past: [...context.past, context.present],
        present: event.value,
        future: [] as number[]
      };
    }),
    stepBack: assign(({ context }) => ({
      past: context.past.slice(0, -1),
      present: context.past[context.past.length - 1] ?? context.present,
      future: [context.present, ...context.future]
    })),
    stepForward: assign(({ context }) => ({
      past: [...context.past, context.present],
      present: context.future[0] ?? context.present,
      future: context.future.slice(1)
    }))
  }
}).createMachine({
  id: 'numHistory',
  context: { past: [], present: 0, future: [] },
  on: {
    SET: { actions: 'commit' },
    UNDO: { guard: 'hasPast', actions: 'stepBack' },
    REDO: { guard: 'hasFuture', actions: 'stepForward' }
  }
});
