export type AirlineItineraryState =
  | { status: "none" }
  | { status: "booked"; id: string; legs: number }
  | { status: "confirmed"; id: string };

export type AirlineItineraryCommand =
  | { type: "bookItinerary"; id: string; pax: string }
  | { type: "addLeg"; from: string; to: string }
  | { type: "confirm" };

export type AirlineItineraryEvent =
  | { type: "ItineraryBooked"; id: string; pax: string }
  | { type: "LegAdded"; from: string; to: string }
  | { type: "ItineraryConfirmed" };

export class DomainError extends Error { constructor(public readonly code: string) { super(code); } }

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const itineraryDecider: Decider<AirlineItineraryCommand, AirlineItineraryEvent, AirlineItineraryState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "bookItinerary":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ItineraryBooked", id: c.id, pax: c.pax }];
      case "addLeg":
        if (s.status !== "booked") throw new DomainError("NOT_BOOKED");
        return [{ type: "LegAdded", from: c.from, to: c.to }];
      case "confirm":
        if (s.status !== "booked") throw new DomainError("NOT_BOOKED");
        if (s.legs === 0) throw new DomainError("NO_LEGS");
        return [{ type: "ItineraryConfirmed" }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ItineraryBooked": return { status: "booked", id: e.id, legs: 0 };
      case "LegAdded":
        if (s.status !== "booked") return s;
        return { ...s, legs: s.legs + 1 };
      case "ItineraryConfirmed":
        if (s.status !== "booked") return s;
        return { status: "confirmed", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};
