type PlaylistEvent =
  | { type: 'PlaylistStarted'; id: string; owner: string }
  | { type: 'SongAdded'; songId: string; position: number }
  | { type: 'SongRemovedAt'; position: number };

type PlaylistState = {
  readonly id: string;
  readonly owner: string;
  readonly songs: readonly string[];
};

const initial: PlaylistState = { id: '', owner: '', songs: [] };

export function evolve(state: PlaylistState, event: PlaylistEvent): PlaylistState {
  switch (event.type) {
    case 'PlaylistStarted':
      return { id: event.id, owner: event.owner, songs: [] };
    case 'SongAdded': {
      const next = state.songs.slice();
      next.splice(event.position, 0, event.songId);
      return { ...state, songs: next };
    }
    case 'SongRemovedAt': {
      const next = state.songs.slice();
      next.splice(event.position, 1);
      return { ...state, songs: next };
    }
    default: {
      const _exhaustive: never = event;
      return _exhaustive;
    }
  }
}

export function aggregate(events: readonly PlaylistEvent[]): PlaylistState {
  return events.reduce(evolve, initial);
}
