Writes go through `decide` -> `appendToStream`; reads go through a projection-backed read store. The two sides share the event union but each maintains its own shape: the write side needs invariants, the read side needs denormalised query fields. The read side always lags the event store.

```typescript
export type AdvertisementEvent =
  | { type: "AdvertisementSubmitted"; id: string; headline: string }
  | { type: "AdvertisementApproved"; at: string };

export type AdvertisementCommand = { type: "submit"; id: string; headline: string } | { type: "approve"; at: string };

interface WriteState {
  readonly status: "empty" | "draft" | "approved";
  readonly id: string;
  readonly headline: string;
}

const initialWrite: WriteState = { status: "empty", id: "", headline: "" };

function evolve(state: WriteState, event: AdvertisementEvent): WriteState {
  switch (event.type) {
    case "AdvertisementSubmitted":
      return { status: "draft", id: event.id, headline: event.headline };
    case "AdvertisementApproved":
      if (state.status !== "draft") return state;
      return { ...state, status: "approved" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(cmd: AdvertisementCommand, state: WriteState): AdvertisementEvent[] {
  switch (cmd.type) {
    case "submit":
      if (state.status !== "empty") throw new Error("ALREADY_SUBMITTED");
      return [{ type: "AdvertisementSubmitted", id: cmd.id, headline: cmd.headline }];
    case "approve":
      if (state.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "AdvertisementApproved", at: cmd.at }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<{ revision: bigint; event: AdvertisementEvent }>>;
  appendToStream(s: string, events: readonly AdvertisementEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export interface ReadRow {
  readonly id: string;
  readonly headline: string;
  readonly approved: boolean;
}

export interface ReadStore {
  get(id: string): Promise<ReadRow | null>;
}

export async function handleCommand(store: EventStore, stream: string, cmd: AdvertisementCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<WriteState>((s, { event }) => evolve(s, event), initialWrite);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, decide(cmd, state), { expectedRevision: expected });
}

export async function queryView(readStore: ReadStore, id: string): Promise<ReadRow | null> {
  return readStore.get(id);
}
```

