export type SerialState =
  | { status: "new" }
  | { status: "issued"; id: string; sku: string }
  | { status: "attached"; id: string; sku: string; crateId: string }
  | { status: "scrapped"; id: string };

export type SerialCommand =
  | { type: "issue"; id: string; sku: string }
  | { type: "attach-to-crate"; crateId: string }
  | { type: "scrap"; reason: string };

export type SerialEvent =
  | { type: "SerialIssued"; id: string; sku: string }
  | { type: "SerialAttached"; crateId: string }
  | { type: "SerialScrapped"; reason: string };

export class SerialError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const serialDecider: Decider<SerialCommand, SerialEvent, SerialState> = {
  initialState: { status: "new" },
  decide(c, s) {
    switch (c.type) {
      case "issue":
        if (s.status !== "new") throw new SerialError("ALREADY_ISSUED");
        return [{ type: "SerialIssued", id: c.id, sku: c.sku }];
      case "attach-to-crate":
        if (s.status === "scrapped") throw new SerialError("SCRAPPED");
        if (s.status !== "issued") throw new SerialError("NOT_ISSUED");
        return [{ type: "SerialAttached", crateId: c.crateId }];
      case "scrap":
        if (s.status === "scrapped") throw new SerialError("ALREADY_SCRAPPED");
        if (s.status === "new") throw new SerialError("NOT_ISSUED");
        return [{ type: "SerialScrapped", reason: c.reason }];
      default: { const _n: never = c; throw new SerialError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "SerialIssued":
        return { status: "issued", id: e.id, sku: e.sku };
      case "SerialAttached":
        if (s.status !== "issued") return s;
        return { status: "attached", id: s.id, sku: s.sku, crateId: e.crateId };
      case "SerialScrapped":
        if (s.status === "new" || s.status === "scrapped") return s;
        return { status: "scrapped", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};
