  | { type: "Issued"; id: string; voterId: string }
  | { type: "Marked"; choice: string }
  | { type: "Submitted"; at: string };

type ExpectedRevision = bigint | "no_stream" | "any";

export class ConcurrencyConflict extends Error {
  constructor(public stream: string, public expected: ExpectedRevision, public actual: bigint) {
    super(`conflict on ${stream}`);
  }
}

export interface EventStore {
  appendToStream(stream: string, events: BallotEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ revision: bigint }>;
  readStreamRevision(stream: string): Promise<bigint | null>;
}

export function appendWithGuard(
  store: EventStore,
  stream: string,
  events: BallotEvent[],
): Effect.Effect<bigint, ConcurrencyConflict> {
  return Effect.gen(function* () {
    const current = yield* Effect.promise(() => store.readStreamRevision(stream));
    const expected: ExpectedRevision = current ?? "no_stream";
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision: expected }),
      catch: () => new ConcurrencyConflict(stream, expected, current ?? -1n),
    });
    return result.revision;
  });
}
