```typescript
import { Effect } from "effect";

interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

interface StoredEvent<E> { data: E; revision: bigint }

interface EventStore<E> {
  subscribeFrom(stream: string, from: bigint): AsyncIterable<StoredEvent<E>>;
}

type PaymentEvent =
  | { type: "PaymentScheduled"; amount: number }
  | { type: "PaymentSettled"; amount: number };

interface View { scheduled: number; settled: number }

function project(view: View, event: PaymentEvent): View {
  switch (event.type) {
    case "PaymentScheduled":
      return { ...view, scheduled: view.scheduled + event.amount };
    case "PaymentSettled":
      return { ...view, settled: view.settled + event.amount };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export const runSubscription = (
  name: string,
  store: EventStore<PaymentEvent>,
  cps: CheckpointStore,
  persist: (v: View) => Promise<void>,
) =>
  Effect.gen(function* () {
    const last = yield* Effect.promise(() => cps.read(name));
    const iter = store.subscribeFrom("payment-events", last ?? 0n);
    yield* Effect.promise(async () => {
      let view: View = { scheduled: 0, settled: 0 };
      for await (const stored of iter) {
        view = project(view, stored.data);
        await persist(view);
        await cps.write(name, stored.revision);
      }
    });
  });
