```typescript
export type ConstituencyState =
  | { status: "draft"; id: string; code: string }
  | { status: "bounded"; id: string; code: string; boundary: string }
  | { status: "staffed"; id: string; code: string; boundary: string; stations: number }
  | { status: "final"; id: string; code: string };

export type ConstituencyCommand =
  | { type: "define"; id: string; code: string }
  | { type: "setBoundary"; boundary: string }
  | { type: "assignStation" }
  | { type: "finalize" };

export type ConstituencyEvent =
  | { type: "Defined"; id: string; code: string }
  | { type: "BoundarySet"; boundary: string }
  | { type: "StationAssigned" }
  | { type: "Finalized" };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const constituencyDecider: Decider<ConstituencyCommand, ConstituencyEvent, ConstituencyState> = {
  initialState: { status: "draft", id: "", code: "" },
  decide(command, state) {
    switch (command.type) {
      case "define":
        return [{ type: "Defined", id: command.id, code: command.code }];
      case "setBoundary":
        if (state.status === "final") throw new DomainError("finalized");
        return [{ type: "BoundarySet", boundary: command.boundary }];
      case "assignStation":
        if (state.status !== "bounded" && state.status !== "staffed") throw new DomainError("boundary first");
        return [{ type: "StationAssigned" }];
      case "finalize":
        if (state.status !== "staffed") throw new DomainError("need stations");
        return [{ type: "Finalized" }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Defined":
        return { status: "draft", id: event.id, code: event.code };
      case "BoundarySet":
        return state.status === "draft" || state.status === "bounded" || state.status === "staffed"
          ? { status: "bounded", id: state.id, code: state.code, boundary: event.boundary }
          : state;
      case "StationAssigned":
        return state.status === "bounded"
          ? { status: "staffed", id: state.id, code: state.code, boundary: state.boundary, stations: 1 }
          : state.status === "staffed"
            ? { ...state, stations: state.stations + 1 }
            : state;
      case "Finalized":
        return state.status === "staffed" ? { status: "final", id: state.id, code: state.code } : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
```

Invoke the child machine with `onDone` on the state that hosts it. When the child reaches a `final` state with `output`, the parent's `onDone` fires and you transition away — no manual `sendParent` needed.

