  switch (event.type) {
    case "PullRequestOpened": {
      const row: OpenPullRequestRow = {
        id: event.id,
        branch: event.branch,
        author: event.author,
        openedAt: event.at,
        approvals: 0,
      };
      return { ...view, open: { ...view.open, [event.id]: row } };
    }
    case "PullRequestApproved": {
      const current = view.open[event.id];
      if (!current) return view;
      const updated: OpenPullRequestRow = { ...current, approvals: current.approvals + 1 };
      return { ...view, open: { ...view.open, [event.id]: updated } };
    }
    case "PullRequestMerged": {
      if (!view.open[event.id]) return view;
      const { [event.id]: _removed, ...rest } = view.open;
      return { ...view, open: rest, mergedCount: view.mergedCount + 1 };
    }
    case "PullRequestClosed": {
      if (!view.open[event.id]) return view;
      const { [event.id]: _removed, ...rest } = view.open;
      return { ...view, open: rest, closedCount: view.closedCount + 1 };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
