When replaying from a stream, use `AsyncIterable`. The helper stays generic over state and event type; the `for await` loop drains the iterable, and `evolve` stays pure.

```typescript
export type TelemetryStreamEvent =
  | { type: "TelemetryStreamOpened"; id: string }
  | { type: "TelemetrySampleIngested"; value: number }
  | { type: "TelemetryStreamSealed"; at: string };

export type TelemetryStreamState =
  | { status: "none" }
  | { status: "open"; id: string; samples: number; lastValue?: number }
  | { status: "sealed"; id: string; samples: number; sealedAt: string };

export function evolve(state: TelemetryStreamState, event: TelemetryStreamEvent): TelemetryStreamState {
  switch (event.type) {
    case "TelemetryStreamOpened":
      return { status: "open", id: event.id, samples: 0 };
    case "TelemetrySampleIngested":
      if (state.status !== "open") return state;
      return { ...state, samples: state.samples + 1, lastValue: event.value };
    case "TelemetryStreamSealed":
      if (state.status !== "open") return state;
      return { status: "sealed", id: state.id, samples: state.samples, sealedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  const consume = async (): Promise<void> => {
    for await (const event of stream) {
      state = reducer(state, event);
    }
  };
  await consume();
  return state;
}

export function telemetryStreamFrom(stream: AsyncIterable<TelemetryStreamEvent>): Promise<TelemetryStreamState> {
  return aggregateStream(stream, evolve, { status: "none" } as TelemetryStreamState);
}
```

A ready-check is a guarded transition: each player toggles their own `ready` flag in context, and the START event's guard asks "are all players ready?" before transitioning to the starting state. Declaring the guard in `setup.guards` keeps the machine body string-referenced and typed.

```typescript
