  day: "",
  gross: 0,
  refunds: 0,
  closed: false,
};

export function project(view: SalesView, event: MarketStallEvent): SalesView {
  switch (event.type) {
    case "StallOpened":
      return { ...view, id: event.id, day: event.day };
    case "SaleRecorded":
      return { ...view, gross: view.gross + event.amount };
    case "RefundIssued":
      return { ...view, refunds: view.refunds + event.amount };
    case "StallClosed":
      return { ...view, closed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function foldSales(events: MarketStallEvent[]): SalesView {
  return events.reduce(project, emptyView);
