import { Effect } from "effect";

export type AttestationState = { status: "none" } | { status: "issued"; id: string; by: string };
export type AttestationCommand = { type: "issue"; id: string; by: string };
export type AttestationEvent = { type: "AttestationIssued"; id: string; by: string };

export const initialState: AttestationState = { status: "none" };

export function decide(c: AttestationCommand, s: AttestationState): AttestationEvent[] {
  if (c.type === "issue") {
    if (s.status !== "none") throw new Error("EXISTS");
    return [{ type: "AttestationIssued", id: c.id, by: c.by }];
  }
  const _n: never = c.type;
  return [];
}

export function evolve(s: AttestationState, e: AttestationEvent): AttestationState {
  switch (e.type) {
    case "AttestationIssued": return { status: "issued", id: e.id, by: e.by };
    default: { const _n: never = e.type; return s; }
  }
}

export interface Env { readonly revision: bigint; readonly event: AttestationEvent; }
export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<Env>>;
  appendToStream(s: string, e: AttestationEvent[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ nextRevision: bigint }>;
}

export interface CommandHandler<C> {
  handle(cmd: C, stream: string, store: EventStore): Effect.Effect<void, Error>;
}

export const attestationHandler: CommandHandler<AttestationCommand> = {
  handle: (cmd, stream, store) =>
    Effect.gen(function* () {
      const envs = yield* Effect.promise(() => store.readStream(stream));
      const state = envs.map((e) => e.event).reduce(evolve, initialState);
      const expected = envs.length === 0 ? ("no_stream" as const) : envs[envs.length - 1]!.revision;
      const events = decide(cmd, state);
      if (events.length === 0) return;
      yield* Effect.promise(() => store.appendToStream(stream, events, { expectedRevision: expected }));
    }),
};
