export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type FanClubState = { readonly members: readonly string[] };

type FanClubCommand =
  | { type: 'Join'; memberId: string }
  | { type: 'Leave'; memberId: string };

type FanClubEvent =
  | { type: 'Joined'; memberId: string }
  | { type: 'Left'; memberId: string };

export const fanClubDecider: Decider<FanClubCommand, FanClubEvent, FanClubState> = {
  initialState: { members: [] },
  decide(command, state) {
    switch (command.type) {
      case 'Join':
        if (state.members.includes(command.memberId)) return [];
        return [{ type: 'Joined', memberId: command.memberId }];
      case 'Leave':
        if (!state.members.includes(command.memberId)) return [];
        return [{ type: 'Left', memberId: command.memberId }];
      default: { const _e: never = command; return _e; }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'Joined': return { members: [...state.members, event.memberId] };
      case 'Left': return { members: state.members.filter((m) => m !== event.memberId) };
      default: { const _e: never = event; return _e; }
    }
  },
};
