    case 'CoreSealed':
      return { ...view, sealed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  eventStore: EventStore;
  readStore: ReadStore;
}): Promise<bigint> {
  if (opts.from === 0n) await opts.readStore.clear();
  let cursor = opts.from;
  let view: View = { coreId: '', rigId: '', metres: 0, sealed: false };
  for await (const { event, revision } of opts.eventStore.readAllFrom(opts.from, opts.batchSize)) {
