type ConversationCommand =
  | { type: 'StartConversation'; id: string; starterId: string }
  | { type: 'AddParticipant'; userId: string };

type ConversationEvent =
  | { type: 'ConversationStarted'; id: string; starterId: string }
  | { type: 'ParticipantAdded'; userId: string };

type ConversationState =
  | { status: 'empty' }
  | { status: 'open'; id: string; participants: readonly string[] };

const initialState: ConversationState = { status: 'empty' };

function evolve(state: ConversationState, event: ConversationEvent): ConversationState {
  switch (event.type) {
    case 'ConversationStarted':
      return { status: 'open', id: event.id, participants: [event.starterId] };
    case 'ParticipantAdded':
      return state.status === 'open'
        ? { ...state, participants: [...state.participants, event.userId] }
        : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(command: ConversationCommand, state: ConversationState): ConversationEvent[] {
  switch (command.type) {
    case 'StartConversation':
      return [{ type: 'ConversationStarted', id: command.id, starterId: command.starterId }];
    case 'AddParticipant':
      if (state.status !== 'open') throw new Error('not open');
      return [{ type: 'ParticipantAdded', userId: command.userId }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: ConversationEvent; revision: bigint }>;
  appendToStream(
    stream: string,
    events: readonly ConversationEvent[],
    options: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<void>;
}

export async function handle(
  command: ConversationCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initialState;
  let expectedRevision: bigint | 'no_stream' = 'no_stream';
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expectedRevision = revision;
  }
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision });
}
