      on: {
        EXTEND: { guard: 'canExtend', target: 'holding', reenter: true, actions: 'extend' },
        CONFIRM: 'confirmed',
        EXPIRE: 'expired'
      }
    },
    confirmed: { type: 'final' },
    expired: { type: 'final' }
