export type MealSwapEvent =
  | { type: "MealSwapRequested"; swapId: string; userId: string }
  | { type: "MealSwapConfirmed"; swapId: string; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: E }>>;
  appendToStream(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function append(
  store: EventStore<MealSwapEvent>,
  stream: string,
  events: readonly MealSwapEvent[],
  expectedRevision: ExpectedRevision,
): Promise<void> {
  try {
    await store.appendToStream(stream, events, { expectedRevision });
  } catch (err) {
    if (err instanceof Error && err.message.includes("WrongExpectedVersion")) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}

export async function appendSafely(
  store: EventStore<MealSwapEvent>,
  stream: string,
  events: readonly MealSwapEvent[],
): Promise<void> {
  const stored = await store.readStream(stream);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await append(store, stream, events, expected);
}

