export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  async function main(): Promise<void> {
    for await (const event of stream) {
      state = evolve(state, event);
    }
  }
  await main();
  return state;
}

export type WarehouseEvent =
  | { type: "WarehouseOpened"; id: string; code: string }
  | { type: "WarehouseExpanded"; addedBins: number };

export type WarehouseState =
  | { status: "empty" }
  | { status: "operational"; id: string; code: string; bins: number };

export const initialWarehouse: WarehouseState = { status: "empty" };

export function evolveWarehouse(s: WarehouseState, e: WarehouseEvent): WarehouseState {
  switch (e.type) {
    case "WarehouseOpened":
      return { status: "operational", id: e.id, code: e.code, bins: 0 };
    case "WarehouseExpanded":
      if (s.status !== "operational") return s;
      return { ...s, bins: s.bins + e.addedBins };
    default: { const _n: never = e; return s; }
  }
}

export async function loadWarehouse(stream: AsyncIterable<WarehouseEvent>): Promise<WarehouseState> {
  return aggregateStream(stream, evolveWarehouse, initialWarehouse);
}
