export type LotCommand = { type: "open"; id: string } | { type: "produce"; units: number };
export type LotEvent = { type: "LotOpened"; id: string } | { type: "LotProduced"; units: number };

export function evolve(state: LotState, event: LotEvent): LotState {
  switch (event.type) {
    case "LotOpened": return { status: "open", id: event.id, units: 0 };
    case "LotProduced":
      if (state.status !== "open") return state;
      return { ...state, units: state.units + event.units };
    default: { const _n: never = event; return state; }
  }
}

export function decide(command: LotCommand, state: LotState): LotEvent[] {
  switch (command.type) {
    case "open":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "LotOpened", id: command.id }];
    case "produce":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "LotProduced", units: command.units }];
    default: { const _n: never = command; throw new Error("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: LotEvent; revision: bigint }>;
  appendToStream(stream: string, events: LotEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

