  let state: LotState = { status: "none" };
  let revision: ExpectedRevision = "no_stream";
  for await (const { event, revision: r } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    revision = r;
  }
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: revision });
}
