The `scoring` state only exists to mutate context (bump the score, advance the index). An `always` array then fires without waiting for an event, routing to either the next question or the final `done` state based on a guard.

```typescript
import { setup, assign } from 'xstate';

export const quizAlwaysMachine = setup({
  types: {
    context: {} as { total: number; index: number; score: number },
    events: {} as { type: 'ANSWER'; correct: boolean },
  },
  guards: {
    more: ({ context }) => context.index < context.total - 1,
  },
}).createMachine({
  id: 'quizAlways',
  initial: 'asking',
  context: { total: 3, index: 0, score: 0 },
  states: {
    asking: {
      on: {
        ANSWER: {
          target: 'scoring',
          actions: assign({
            score: ({ context, event }) => context.score + (event.correct ? 1 : 0),
          }),
        },
      },
    },
    scoring: {
      always: [
        {
          guard: 'more',
          target: 'asking',
          actions: assign({ index: ({ context }) => context.index + 1 }),
        },
        { target: 'done' },
      ],
    },
    done: { type: 'final' },
  },
});
