```typescript
export type ScheduleState =
  | { status: "none" }
  | { status: "proposed"; id: string; date: string }
  | { status: "approved"; id: string; date: string; approvedAt: string }
  | { status: "cancelled"; id: string };

export type ScheduleCommand =
  | { type: "propose"; id: string; date: string }
  | { type: "approve"; at: string }
  | { type: "reschedule"; date: string }
  | { type: "cancel" };

export type ScheduleEvent =
  | { type: "SchedulePropose"; id: string; date: string }
  | { type: "ScheduleApproved"; at: string }
  | { type: "ScheduleRescheduled"; date: string }
  | { type: "ScheduleCancelled" };

export class ScheduleError extends Error {
  constructor(code: string) { super(code); this.name = "ScheduleError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const scheduleDecider: Decider<ScheduleCommand, ScheduleEvent, ScheduleState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "propose":
        if (s.status !== "none") throw new ScheduleError("EXISTS");
        return [{ type: "SchedulePropose", id: c.id, date: c.date }];
      case "approve":
        if (s.status === "cancelled") throw new ScheduleError("CANCELLED");
        if (s.status !== "proposed") throw new ScheduleError("NOT_PROPOSED");
        return [{ type: "ScheduleApproved", at: c.at }];
      case "reschedule":
        if (s.status === "cancelled") throw new ScheduleError("CANCELLED");
        if (s.status === "none") throw new ScheduleError("NOT_FOUND");
        return [{ type: "ScheduleRescheduled", date: c.date }];
      case "cancel":
        if (s.status === "cancelled") return [];
        if (s.status === "none") throw new ScheduleError("NOT_FOUND");
        return [{ type: "ScheduleCancelled" }];
      default: { const _n: never = c; throw new ScheduleError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "SchedulePropose":
        return { status: "proposed", id: e.id, date: e.date };
      case "ScheduleApproved":
        if (s.status !== "proposed") return s;
        return { status: "approved", id: s.id, date: s.date, approvedAt: e.at };
      case "ScheduleRescheduled":
        if (s.status === "none" || s.status === "cancelled") return s;
        return { ...s, date: e.date };
      case "ScheduleCancelled":
        if (s.status === "none") return s;
        return { status: "cancelled", id: "id" in s ? s.id : "" };
      default: { const _n: never = e; return s; }
    }
  },
};
```

Each region has its own final state. When all regions reach final, the parent compound state itself emits onDone, which you can use from a wrapping state to target a completed state. The types.output type describes what the machine or a state returns when finalised.

