```typescript
export type FeatureStoreEvent =
  | { type: "FeatureStoreCreated"; id: string }
  | { type: "FeatureAdded"; name: string }
  | { type: "FeatureStoreSealed" };

export type FeatureStoreView = { id: string; features: string[]; sealed: boolean };
const empty: FeatureStoreView = { id: "", features: [], sealed: false };

function project(view: FeatureStoreView, event: FeatureStoreEvent): FeatureStoreView {
  switch (event.type) {
    case "FeatureStoreCreated":
      return { id: event.id, features: [], sealed: false };
    case "FeatureAdded":
      return { ...view, features: [...view.features, event.name] };
    case "FeatureStoreSealed":
      return { ...view, sealed: true };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface BatchReader<E> {
  readBatch(from: bigint, size: number): Promise<{ events: E[]; nextFrom: bigint | null }>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  reader: BatchReader<FeatureStoreEvent>;
  persist: (v: FeatureStoreView, cursor: bigint) => Promise<void>;
  report: (processed: number) => void;
}): Promise<void> {
  let cursor = opts.from;
  let processed = 0;
  let view = empty;
  let done = false;
  while (!done) {
    const { events, nextFrom } = await opts.reader.readBatch(cursor, opts.batchSize);
    for (const event of events) {
      view = project(view, event);
      processed += 1;
    }
    cursor = nextFrom ?? cursor;
    await opts.persist(view, cursor);
    opts.report(processed);
    if (nextFrom === null) done = true;
  }
}
