```typescript
import { Effect } from "effect";

export class ConcurrencyConflict {
  readonly _tag = "ConcurrencyConflict" as const;
  constructor(public readonly stream: string) {}
}

export interface EventStoreDB {
  readRevision: (stream: string) => Promise<bigint | null>;
  appendToStream: (
    stream: string,
    events: unknown[],
    opts: { expectedRevision: bigint | "no_stream" | "any" },
  ) => Promise<bigint>;
}

export const appendTailEvents = (store: EventStoreDB, stream: string, events: unknown[]) =>
  Effect.gen(function* () {
    const rev = yield* Effect.promise(() => store.readRevision(stream));
    const expectedRevision: bigint | "no_stream" = rev === null ? "no_stream" : rev;
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision }),
      catch: (e) => {
        const msg = e instanceof Error ? e.message : "";
        if (msg.includes("WrongExpectedVersion")) return new ConcurrencyConflict(stream);
        return new Error(msg);
      },
    });
    return result;
  });
