import { Effect } from "effect";

export type SeafoodBatchEvent =
  | { type: "SeafoodBatchCreated"; id: string; weightKg: number }
  | { type: "SeafoodBatchShipped"; id: string; to: string };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventEnvelope<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface EventSource {
  subscribe(from: bigint | null): AsyncIterable<EventEnvelope<SeafoodBatchEvent>>;
}

export interface BatchStore {
  upsert(id: string, payload: Readonly<Record<string, string | number>>): Promise<void>;
}

// projection that writes into the read store
async function project(store: BatchStore, event: SeafoodBatchEvent): Promise<void> {
  switch (event.type) {
    case "SeafoodBatchCreated":
      await store.upsert(event.id, { status: "created", weightKg: event.weightKg });
      return;
    case "SeafoodBatchShipped":
      await store.upsert(event.id, { status: "shipped", to: event.to });
      return;
    default: {
      const _never: never = event;
      return;
    }
  }
}

export const runSubscription = (
  name: string,
  source: EventSource,
  checkpoints: CheckpointStore,
  store: BatchStore,
) =>
  Effect.gen(function* () {
    const last = yield* Effect.promise(() => checkpoints.read(name));
    yield* Effect.promise(async () => {
      for await (const envelope of source.subscribe(last)) {
        await project(store, envelope.event);
        await checkpoints.write(name, envelope.position);
      }
    });
  });
```

Use `types.output` to type the shape, mark the terminal state as `type: 'final'`, and supply a machine-level `output` function that reads `context`. After the actor stops, `actor.getSnapshot().output` yields the computed score.

