type ChannelEvent =
  | { type: 'ChannelCreated'; channelId: string; name: string }
  | { type: 'ChannelLocked'; channelId: string };

export interface OutboxRow {
  id: string;
  payload: string;
  publishedAt: string | null;
}

interface Tx {
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
  appendToStream(
    stream: string,
    events: readonly ChannelEvent[],
    options: { expectedRevision: bigint | 'no_stream' },
  ): Promise<void>;
}

interface Connection {
  inTransaction<T>(fn: (tx: Tx) => Promise<T>): Promise<T>;
}

export async function appendWithOutbox(
  conn: Connection,
  stream: string,
  events: readonly ChannelEvent[],
  outboxRows: readonly OutboxRow[],
  expectedRevision: bigint | 'no_stream',
): Promise<void> {
  // Single unit of work: outbox rows + stream append commit together.
  await conn.inTransaction(async (tx) => {
    await tx.insertOutbox(outboxRows);
    await tx.appendToStream(stream, events, { expectedRevision });
  });
  // A separate publisher worker polls `outbox WHERE published_at IS NULL`,
  // pushes each row to the message bus, and sets published_at on success.
}
