  | { type: "open" }
  | { type: "admitVisitor" }
  | { type: "close" };

export type GalleryShowEvent =
  | { type: "GalleryShowPlanned"; id: string; title: string; rooms: number }
  | { type: "GalleryShowOpened" }
  | { type: "GalleryShowVisitorAdmitted" }
  | { type: "GalleryShowClosed"; totalVisitors: number };

type GalleryShowState =
  | { status: "none" }
  | { status: "open"; id: string; title: string; visitors: number }
  | { status: "planned"; id: string; title: string; rooms: number }
  | { status: "closed"; id: string; title: string; totalVisitors: number };

const initial: GalleryShowState = { status: "none" };

function evolve(state: GalleryShowState, event: GalleryShowEvent): GalleryShowState {
  switch (event.type) {
    case "GalleryShowPlanned":
      return { status: "planned", id: event.id, title: event.title, rooms: event.rooms };
    case "GalleryShowOpened":
      if (state.status !== "planned") return state;
      return { status: "open", id: state.id, title: state.title, visitors: 0 };
    case "GalleryShowVisitorAdmitted":
      if (state.status !== "open") return state;
      return { ...state, visitors: state.visitors + 1 };
    case "GalleryShowClosed":
      if (state.status !== "open") return state;
      return { status: "closed", id: state.id, title: state.title, totalVisitors: event.totalVisitors };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: GalleryShowCommand, state: GalleryShowState): GalleryShowEvent[] {
  switch (command.type) {
    case "plan":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "GalleryShowPlanned", id: command.id, title: command.title, rooms: command.rooms }];
    case "open":
      if (state.status !== "planned") throw new Error("NOT_PLANNED");
      return [{ type: "GalleryShowOpened" }];
    case "admitVisitor":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "GalleryShowVisitorAdmitted" }];
    case "close":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "GalleryShowClosed", totalVisitors: state.visitors }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface GalleryShowView {
  readonly id: string;
  readonly title: string;
  readonly status: "planned" | "open" | "closed";
  readonly visitors: number;
}

export interface ReadStore {
  load(id: string): Promise<GalleryShowView | null>;
}

// The read store is eventually consistent with the event stream.
export async function handleCommand(
  command: GalleryShowCommand,
  ctx: { streamName: string; eventStore: EventStore<GalleryShowEvent> }
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initial);
  const out = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, out, { expectedRevision: revision });
}

export async function queryView(reader: ReadStore, id: string): Promise<GalleryShowView | null> {
  return reader.load(id);
}
```

```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

Convert this XState v4 machine to v5 using setup().createMachine — it uses services:

```js
const fetchUser = Machine({
  id: 'user',
  initial: 'loading',
  context: { data: null },
  states: {
    loading: {
      invoke: {
        src: 'fetchUser',
        onDone: { target: 'ready', actions: assign({ data: (_, e) => e.data }) },
        onError: 'failed'
      }
    },
    ready: {},
    failed: {}
  }
}, {
  services: {
    fetchUser: () => fetch('/api/user').then(r => r.json())
  }
});
```

The external `services: {}` bag is gone in v5 — actors are registered in `setup.actors`, and async work is wrapped in `fromPromise`. The `onDone` payload is read via `event.output`.

```typescript
