export type TrainingJobEvent =
  | { type: "TrainingJobSubmitted"; day: string }
  | { type: "TrainingJobStarted"; day: string }
  | { type: "TrainingJobCompleted"; day: string }
  | { type: "TrainingJobFailed"; day: string };

