Upcasting translates a persisted event shape into the current shape at read time, so the stream never needs to be rewritten. The upcaster pattern matches on { type, version } and returns the current event, throwing UnknownEventError for unsupported combinations.

```typescript
export interface RawFishStockSeededV1 {
  readonly type: "FishStockSeeded";
  readonly version: 1;
  readonly id: string;
  readonly count: number;
}

export interface RawFishStockSeededV2 {
  readonly type: "FishStockSeeded";
  readonly version: 2;
  readonly id: string;
  readonly species: string;
  readonly count: number;
}

export type RawFishStockEvent = RawFishStockSeededV1 | RawFishStockSeededV2;

export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; species: string; count: number };

export class UnknownEventError extends Error {
  constructor() {
    super("UNKNOWN_EVENT");
    this.name = "UnknownEventError";
  }
}

export function upcast(raw: RawFishStockEvent): FishStockEvent {
  switch (raw.type) {
    case "FishStockSeeded":
      if (raw.version === 1) {
        return { type: "FishStockSeeded", id: raw.id, species: "unknown", count: raw.count };
      }
      if (raw.version === 2) {
        return { type: "FishStockSeeded", id: raw.id, species: raw.species, count: raw.count };
      }
      throw new UnknownEventError();
    default: {
      const _never: never = raw.type;
      throw new UnknownEventError();
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<RawFishStockEvent[]>;
}

export async function readAndUpcast(store: EventStore, stream: string): Promise<FishStockEvent[]> {
  const raw = await store.readStream(stream);
  return raw.map(upcast);
}
