```typescript
export type PolicyEvent =
  | { type: "PolicyQuoted"; id: string; premium: number }
  | { type: "PolicyActivated"; id: string; at: string }
  | { type: "PolicyLapsed"; id: string; reason: string };

export type PremiumOverview = Readonly<{
  totalQuoted: number;
  totalActive: number;
  activeCount: number;
  lapsedCount: number;
}>;

export const emptyView: PremiumOverview = {
  totalQuoted: 0,
  totalActive: 0,
  activeCount: 0,
  lapsedCount: 0,
};

const premiums = new Map<string, number>();

export function project(view: PremiumOverview, event: PolicyEvent): PremiumOverview {
  switch (event.type) {
    case "PolicyQuoted":
      premiums.set(event.id, event.premium);
      return { ...view, totalQuoted: view.totalQuoted + event.premium };
    case "PolicyActivated": {
      const p = premiums.get(event.id) ?? 0;
      return {
        ...view,
        totalActive: view.totalActive + p,
        activeCount: view.activeCount + 1,
      };
    }
    case "PolicyLapsed": {
      const p = premiums.get(event.id) ?? 0;
      return {
        ...view,
        totalActive: view.totalActive - p,
        activeCount: Math.max(0, view.activeCount - 1),
        lapsedCount: view.lapsedCount + 1,
      };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function aggregate(events: PolicyEvent[]): PremiumOverview {
  return events.reduce<PremiumOverview>(project, emptyView);
}
