Convert this XState v4 survey form to v5 with typed setup. Questions are answered in order, each validated:

```js
const survey = Machine({
  id: 'survey',
  initial: 'q1',
  context: { q1: '', q2: 0, q3: false },
  states: {
    q1: {
      on: {
        ANSWER: { actions: assign({ q1: (_, e) => e.text }) },
        NEXT: { target: 'q2', cond: (c) => c.q1.length > 0 }
      }
    },
    q2: {
      on: {
        ANSWER: { actions: assign({ q2: (_, e) => e.rating }) },
        NEXT: { target: 'q3', cond: (c) => c.q2 >= 1 && c.q2 <= 5 },
        BACK: 'q1'
      }
    },
    q3: {
      on: {
        ANSWER: { actions: assign({ q3: () => true }) },
        DONE: { target: 'finished', cond: (c) => c.q3 },
        BACK: 'q2'
      }
    },
    finished: { type: 'final' }
  }
});
```

v5 requires a discriminated event union because `ANSWER` varies by step. Split it into `ANSWER_Q1`, `ANSWER_Q2`, `AGREE_Q3` so each step is statically typed.

```typescript
import { setup, assign } from 'xstate';

type Ev =
  | { type: 'ANSWER_Q1'; text: string }
  | { type: 'ANSWER_Q2'; rating: number }
  | { type: 'AGREE_Q3' }
  | { type: 'NEXT' }
  | { type: 'BACK' }
  | { type: 'DONE' };

export const surveyMachine = setup({
  types: {
    context: {} as { q1: string; q2: number; q3: boolean },
    events: {} as Ev
  },
  guards: {
    q1Valid: ({ context }) => context.q1.length > 0,
    q2Valid: ({ context }) => context.q2 >= 1 && context.q2 <= 5,
    q3Valid: ({ context }) => context.q3
  }
}).createMachine({
  id: 'survey',
  initial: 'q1',
  context: { q1: '', q2: 0, q3: false },
  states: {
    q1: {
      on: {
        ANSWER_Q1: { actions: assign({ q1: ({ event }) => event.text }) },
        NEXT:      { target: 'q2', guard: 'q1Valid' }
      }
    },
    q2: {
      on: {
        ANSWER_Q2: { actions: assign({ q2: ({ event }) => event.rating }) },
        NEXT:      { target: 'q3', guard: 'q2Valid' },
        BACK:      'q1'
      }
    },
    q3: {
      on: {
        AGREE_Q3: { actions: assign({ q3: () => true }) },
        DONE:     { target: 'finished', guard: 'q3Valid' },
        BACK:     'q2'
      }
    },
    finished: { type: 'final' }
  }
});
