```typescript
export interface Schedule {
  readonly id: string;
  readonly date: string;
  readonly status: "proposed" | "approved" | "cancelled";
  readonly tzOffsetMinutes: number;
  readonly createdBy: string;
}

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3;

interface SchedulesV1 { id: string; date: string; status: string }
interface SchedulesV2 { id: string; date: string; status: "proposed" | "approved" | "cancelled"; tzOffsetMinutes: number }

function v1Tov2(snap: Snapshot<SchedulesV1>): Snapshot<SchedulesV2> {
  const status = snap.state.status === "approved" || snap.state.status === "cancelled" ? snap.state.status : "proposed";
  return { version: 2, state: { id: snap.state.id, date: snap.state.date, status, tzOffsetMinutes: 0 } };
}

function v2Tov3(snap: Snapshot<SchedulesV2>): Snapshot<Schedule> {
  return { version: 3, state: { ...snap.state, createdBy: "system" } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<Schedule> {
  let current = snap;
  if (current.version === 1) current = v1Tov2(current as Snapshot<SchedulesV1>);
  if (current.version === 2) current = v2Tov3(current as Snapshot<SchedulesV2>);
  if (current.version !== CURRENT_VERSION) throw new Error(`Unsupported snapshot version ${current.version}`);
  return current as Snapshot<Schedule>;
}

export function loadSchedule(raw: Snapshot<unknown>): Schedule {
  const upgraded: Snapshot<Schedule> = upgradeSnapshot(raw);
  return upgraded.state;
}
