export type LectureEvent =
  | { type: "LectureScheduled"; id: string; title: string; starts: string }
  | { type: "LearnerCheckedIn"; lectureId: string; learner: string }
  | { type: "LearnerCheckedOut"; lectureId: string; learner: string }
  | { type: "LectureCancelled"; id: string };

export type LectureView = Readonly<{
  id: string;
  title: string;
  starts: string;
  cancelled: boolean;
  present: ReadonlyArray<string>;
}>;

export type LectureBoard = Readonly<{
  lectures: Readonly<Record<string, LectureView>>;
}>;

export const emptyView: LectureBoard = { lectures: {} };

function updateLecture(
  view: LectureBoard,
  id: string,
  mapper: (v: LectureView) => LectureView,
): LectureBoard {
  const current = view.lectures[id];
  if (!current) return view;
  return { lectures: { ...view.lectures, [id]: mapper(current) } };
}

export function project(view: LectureBoard, event: LectureEvent): LectureBoard {
  switch (event.type) {
    case "LectureScheduled":
      return {
        lectures: {
          ...view.lectures,
          [event.id]: { id: event.id, title: event.title, starts: event.starts, cancelled: false, present: [] },
        },
      };
    case "LearnerCheckedIn":
      return updateLecture(view, event.lectureId, (v) =>
        v.present.includes(event.learner) ? v : { ...v, present: [...v.present, event.learner] });
    case "LearnerCheckedOut":
      return updateLecture(view, event.lectureId, (v) => ({
        ...v,
        present: v.present.filter((l) => l !== event.learner),
      }));
    case "LectureCancelled":
      return updateLecture(view, event.id, (v) => ({ ...v, cancelled: true }));
    default: { const _n: never = event; return view; }
  }
}

export function lectureBoardFrom(events: ReadonlyArray<LectureEvent>): LectureBoard {
  return events.reduce(project, emptyView);
}
