Keep decide and evolve pure; put the IO boundary inside Effect.gen. The event store calls become yielded effects. This keeps the domain deterministic while gaining Effect's structured errors.

```typescript
import { Effect } from "effect";

type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export type DispatchState =
  | { status: "open"; id: string }
  | { status: "assigned"; id: string; driverId: string };

export type DispatchCommand = { type: "assign"; driverId: string };
export type DispatchEvent = { type: "DispatchAssigned"; driverId: string };

function evolve(s: DispatchState, e: DispatchEvent): DispatchState {
  if (e.type === "DispatchAssigned") return { status: "assigned", id: s.id, driverId: e.driverId };
  const _n: never = e.type;
  return s;
}

function decide(c: DispatchCommand, s: DispatchState): DispatchEvent[] {
  if (c.type !== "assign") { const _n: never = c.type; throw new Error("UNKNOWN"); }
  if (s.status !== "open") throw new Error("NOT_OPEN");
  return [{ type: "DispatchAssigned", driverId: c.driverId }];
}

export const handleDispatch = (store: EventStore<DispatchEvent>, streamName: string, id: string, command: DispatchCommand) =>
  Effect.gen(function* () {
    const loaded = yield* Effect.promise(async () => {
      let state: DispatchState = { status: "open", id };
      let revision: bigint | undefined = undefined;
      for await (const { event, revision: r } of store.readStream(streamName)) {
        state = evolve(state, event);
        revision = r;
      }
      return { state, revision };
    });
    const events = decide(command, loaded.state);
    if (events.length === 0) return;
    const expected: ExpectedRevision = loaded.revision ?? "no_stream";
    yield* Effect.promise(() => store.appendToStream(streamName, events, { expectedRevision: expected }));
  });
```

Writes and reads share the event definition but not the state type. Writes use Decider + eventStore.appendToStream; reads use a denormalised view stored in a read-side DB populated by a projection. The two sides are independent functions connected only by the event log.

```typescript
export type CatalogWriteEvent = { type: "TitleAdded"; id: string } | { type: "TitleRemoved"; id: string };
export type CatalogCommand = { type: "addTitle"; id: string } | { type: "removeTitle"; id: string };

export interface EventStore {
  readStream(n: string): AsyncIterable<{ event: CatalogWriteEvent; revision: bigint }>;
  appendToStream(
    n: string,
    e: ReadonlyArray<CatalogWriteEvent>,
    o: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

function decide(cmd: CatalogCommand): CatalogWriteEvent[] {
  switch (cmd.type) {
    case "addTitle":
      return [{ type: "TitleAdded", id: cmd.id }];
    case "removeTitle":
      return [{ type: "TitleRemoved", id: cmd.id }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export async function handleCommand(command: CatalogCommand, streamName: string, eventStore: EventStore): Promise<void> {
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { revision } of eventStore.readStream(streamName)) expected = revision;
  await eventStore.appendToStream(streamName, decide(command), { expectedRevision: expected });
}

// The read store below is updated asynchronously by a projection subscription
// and is only eventually consistent with the event store.
export type CatalogRow = { id: string };
export interface ReadStore {
  list(): Promise<ReadonlyArray<CatalogRow>>;
}

export async function queryView(store: ReadStore): Promise<ReadonlyArray<CatalogRow>> {
  return store.list();
}
