```typescript
export type ArtAppraisalState =
  | { status: "none" }
  | { status: "requested"; id: string; pieceId: string }
  | { status: "assigned"; id: string; pieceId: string; appraiser: string }
  | { status: "submitted"; id: string; value: number }
  | { status: "countersigned"; id: string; value: number; by: string };

export type ArtAppraisalCommand =
  | { type: "request"; id: string; pieceId: string }
  | { type: "assign"; appraiser: string }
  | { type: "submit"; value: number }
  | { type: "countersign"; by: string };

export type ArtAppraisalEvent =
  | { type: "ArtAppraisalRequested"; id: string; pieceId: string }
  | { type: "ArtAppraisalAssigned"; appraiser: string }
  | { type: "ArtAppraisalSubmitted"; value: number }
  | { type: "ArtAppraisalCountersigned"; by: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const artAppraisalDecider: Decider<ArtAppraisalCommand, ArtAppraisalEvent, ArtAppraisalState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "request":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ArtAppraisalRequested", id: command.id, pieceId: command.pieceId }];
      case "assign":
        if (state.status !== "requested") throw new DomainError("NOT_REQUESTED");
        return [{ type: "ArtAppraisalAssigned", appraiser: command.appraiser }];
      case "submit":
        if (state.status !== "assigned") throw new DomainError("NOT_ASSIGNED");
        if (command.value <= 0) throw new DomainError("INVALID_VALUE");
        return [{ type: "ArtAppraisalSubmitted", value: command.value }];
      case "countersign":
        if (state.status !== "submitted") throw new DomainError("NOT_SUBMITTED");
        return [{ type: "ArtAppraisalCountersigned", by: command.by }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ArtAppraisalRequested":
        return { status: "requested", id: event.id, pieceId: event.pieceId };
      case "ArtAppraisalAssigned":
        if (state.status !== "requested") return state;
        return { status: "assigned", id: state.id, pieceId: state.pieceId, appraiser: event.appraiser };
      case "ArtAppraisalSubmitted":
        if (state.status !== "assigned") return state;
        return { status: "submitted", id: state.id, value: event.value };
      case "ArtAppraisalCountersigned":
        if (state.status !== "submitted") return state;
        return { status: "countersigned", id: state.id, value: state.value, by: event.by };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

