```typescript
import { Effect } from "effect";

export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(position: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface Handler<V, E> {
  load(): Promise<V>;
  project(view: V, event: E): V;
  save(view: V): Promise<void>;
}

export const runSubscription = <V, E>(
  name: string,
  source: EventSource<E>,
  checkpoints: CheckpointStore,
  handler: Handler<V, E>,
) =>
  Effect.gen(function* () {
    const startAt = yield* Effect.promise(() => checkpoints.read(name));
    const from: bigint = startAt ?? 0n;
    let view = yield* Effect.promise(() => handler.load());
    const loop = async (): Promise<void> => {
      for await (const { position, event } of source.readFrom(from)) {
        view = handler.project(view, event);
        await handler.save(view);
        await checkpoints.write(name, position);
      }
    };
    yield* Effect.promise(() => loop());
  });
