export type RefCampaignState =
  | { status: "draft"; id: string }
  | { status: "active"; id: string; budget: number; spent: number }
  | { status: "closed"; id: string; finalSpend: number };

export type RefCampaignCommand =
  | { type: "kickoff"; id: string }
  | { type: "allocate"; amount: number }
  | { type: "spend"; amount: number }
  | { type: "conclude" };

export type RefCampaignEvent =
  | { type: "KickedOff"; id: string }
  | { type: "Allocated"; amount: number }
  | { type: "Spent"; amount: number }
  | { type: "Concluded" };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const refCampaignDecider: Decider<RefCampaignCommand, RefCampaignEvent, RefCampaignState> = {
  initialState: { status: "draft", id: "" },
  decide(command, state) {
    switch (command.type) {
      case "kickoff":
        return [{ type: "KickedOff", id: command.id }];
      case "allocate":
        if (state.status === "closed") throw new DomainError("closed");
        if (command.amount <= 0) throw new DomainError("positive only");
        return [{ type: "Allocated", amount: command.amount }];
      case "spend":
        if (state.status !== "active") throw new DomainError("not active");
        if (state.spent + command.amount > state.budget) throw new DomainError("over budget");
        return [{ type: "Spent", amount: command.amount }];
      case "conclude":
        if (state.status !== "active") throw new DomainError("not active");
        return [{ type: "Concluded" }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "KickedOff":
        return { status: "draft", id: event.id };
      case "Allocated":
        return state.status === "draft"
          ? { status: "active", id: state.id, budget: event.amount, spent: 0 }
          : state.status === "active"
            ? { ...state, budget: state.budget + event.amount }
            : state;
      case "Spent":
        return state.status === "active" ? { ...state, spent: state.spent + event.amount } : state;
      case "Concluded":
        return state.status === "active" ? { status: "closed", id: state.id, finalSpend: state.spent } : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
```

A multi-step form in XState v5 models each step as a child state inside a parent compound state. `setup({ types })` locks context and events, guards gate NEXT transitions, and BACK transitions return to the previous step. A `final` state marks completion and can emit `output` consumed by the invoking parent.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { name: string; plan: 'free' | 'pro'; tos: boolean };
type Ev =
  | { type: 'SET_NAME'; value: string }
  | { type: 'SET_PLAN'; value: 'free' | 'pro' }
  | { type: 'ACCEPT_TOS' }
  | { type: 'NEXT' }
  | { type: 'BACK' };

export const wizardMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev, output: {} as { user: Ctx } },
  guards: {
    hasName: ({ context }) => context.name.trim().length > 0,
    tosOk: ({ context }) => context.tos
  }
}).createMachine({
  id: 'wizard',
  initial: 'name',
  context: { name: '', plan: 'free', tos: false },
  output: ({ context }) => ({ user: context }),
  states: {
    name: {
      on: {
        SET_NAME: { actions: assign({ name: ({ event }) => event.value }) },
        NEXT: { target: 'plan', guard: 'hasName' }
      }
    },
    plan: {
      on: {
        SET_PLAN: { actions: assign({ plan: ({ event }) => event.value }) },
        NEXT: 'review',
        BACK: 'name'
      }
    },
    review: {
      on: {
        ACCEPT_TOS: { actions: assign({ tos: () => true }) },
        NEXT: { target: 'done', guard: 'tosOk' },
        BACK: 'plan'
      }
    },
    done: { type: 'final' }
  }
});
