Store each snapshot with `{ version, state }`. On load, run upgraders in sequence until you reach CURRENT_VERSION, then assert the final shape. Never mutate the stored blob; produce a new one each step.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type ReservationV1 = { id: string; guests: number };
export type ReservationV2 = { id: string; guests: number; nights: number };
export type ReservationV3 = {
  id: string;
  guests: number;
  nights: number;
  status: "pending" | "confirmed" | "cancelled";
};

export type CurrentReservation = ReservationV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: ReservationV1): ReservationV2 {
  return { ...s, nights: 1 };
}

function v2Tov3(s: ReservationV2): ReservationV3 {
  return { ...s, status: "pending" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentReservation> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as ReservationV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as ReservationV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED");
  const out = s as CurrentReservation;
  if (!out.id || typeof out.guests !== "number") throw new UpgradeError("SHAPE");
  return { version: v, state: out };
}
```

```typescript
export type RouteEvent =
  | { type: "RoutePlanned"; version: 2; id: string; stops: number }
  | { type: "RouteActivated"; version: 1; at: string }
  | { type: "RouteClosed"; version: 1; at: string };

export class UnknownEventError extends Error {
  constructor(public readonly raw: unknown) {
    super("unknown-raw-event");
    this.name = "UnknownEventError";
  }
}

interface RawEvent { type: string; version: number; [k: string]: unknown }

function parseStops(raw: unknown): number {
  if (typeof raw === "number") return raw;
  if (typeof raw === "string") {
    const count = raw.split(",").map((s) => s.trim()).filter(Boolean).length;
    return count;
  }
  return 0;
}

export function upcast(raw: unknown): RouteEvent {
  if (!raw || typeof raw !== "object") throw new UnknownEventError(raw);
  const e = raw as RawEvent;
  switch (e.type) {
    case "RoutePlanned": {
      if (e.version === 1) {
        return { type: "RoutePlanned", version: 2, id: String(e.id), stops: parseStops(e.stops) };
      }
      if (e.version === 2) {
        return { type: "RoutePlanned", version: 2, id: String(e.id), stops: Number(e.stops) };
      }
      throw new UnknownEventError(raw);
    }
    case "RouteActivated":
      return { type: "RouteActivated", version: 1, at: String(e.at ?? "") };
    case "RouteClosed":
      return { type: "RouteClosed", version: 1, at: String(e.at ?? "") };
    default:
      throw new UnknownEventError(raw);
  }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<unknown>;
}

export async function readAllUpcast(store: EventStore, streamName: string): Promise<readonly RouteEvent[]> {
  const out: RouteEvent[] = [];
  for await (const raw of store.readStream(streamName)) {
    out.push(upcast(raw));
  }
  return out;
}
