type Command = { type: 'Amend'; clause: string };
type PermitEvent = { type: 'PermitAmended'; clause: string };
type State = { status: 'active'; amendments: number } | { status: 'revoked' };
const initial: State = { status: 'active', amendments: 0 };

function evolve(state: State, event: PermitEvent): State {
  switch (event.type) {
    case 'PermitAmended':
      return state.status === 'active' ? { ...state, amendments: state.amendments + 1 } : state;
    default: {
      const _: never = event.type;
      return _;
    }
  }
}

function decide(cmd: Command, state: State): PermitEvent[] {
  if (state.status !== 'active') throw new Error('cannot amend revoked permit');
  return [{ type: 'PermitAmended', clause: cmd.clause }];
}

interface EventStore {
  readStream(s: string): AsyncIterable<{ event: PermitEvent; revision: bigint }>;
  appendToStream(s: string, e: PermitEvent[], o: { expectedRevision: bigint | 'no_stream' }): Promise<void>;
}

export async function handleAmend(
  command: Command,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initial;
  let rev: bigint | 'no_stream' = 'no_stream';
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    rev = revision;
  }
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: rev });
}
