export type CreativeState =
  | { status: "empty" }
  | { status: "uploaded"; id: string; assetUrl: string }
  | { status: "reviewed"; id: string; assetUrl: string; reviewer: string }
  | { status: "published"; id: string; assetUrl: string; publishedAt: string };

export type CreativeCommand =
  | { type: "upload"; id: string; assetUrl: string }
  | { type: "review"; reviewer: string }
  | { type: "publish"; at: string };

export type CreativeEvent =
  | { type: "CreativeUploaded"; id: string; assetUrl: string }
  | { type: "CreativeReviewed"; reviewer: string }
  | { type: "CreativePublished"; at: string };

export const initialCreative: CreativeState = { status: "empty" };

export function decide(command: CreativeCommand, state: CreativeState): CreativeEvent[] {
  switch (command.type) {
    case "upload":
      if (state.status !== "empty") throw new Error("ALREADY_UPLOADED");
      return [{ type: "CreativeUploaded", id: command.id, assetUrl: command.assetUrl }];
    case "review":
      if (state.status !== "uploaded") throw new Error("NOT_UPLOADED");
      return [{ type: "CreativeReviewed", reviewer: command.reviewer }];
    case "publish":
      if (state.status !== "reviewed") throw new Error("NOT_REVIEWED");
      return [{ type: "CreativePublished", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export function evolve(state: CreativeState, event: CreativeEvent): CreativeState {
  switch (event.type) {
    case "CreativeUploaded":
      return { status: "uploaded", id: event.id, assetUrl: event.assetUrl };
    case "CreativeReviewed":
      if (state.status !== "uploaded") return state;
      return { status: "reviewed", id: state.id, assetUrl: state.assetUrl, reviewer: event.reviewer };
    case "CreativePublished":
      if (state.status !== "reviewed") return state;
      return { status: "published", id: state.id, assetUrl: state.assetUrl, publishedAt: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: CreativeEvent }>>;
  appendToStream(stream: string, events: readonly CreativeEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export interface CommandHandlerDeps {
  readonly streamName: string;
  readonly eventStore: EventStore;
}

export async function handle(command: CreativeCommand, deps: CommandHandlerDeps): Promise<void> {
  const stored = await deps.eventStore.readStream(deps.streamName);
  const state = stored.reduce<CreativeState>((s, { event }) => evolve(s, event), initialCreative);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  const events = decide(command, state);
  if (events.length === 0) return;
  await deps.eventStore.appendToStream(deps.streamName, events, { expectedRevision: expected });
}
