A stateful process manager is a pure step function over a small saga state: incoming events drive transitions and optionally emit a follow-up command. Persistence of the saga state is the caller's responsibility.

```typescript
export type SagaState =
  | { phase: "awaiting_release" }
  | { phase: "reserving"; releaseId: string }
  | { phase: "seeding"; releaseId: string; penId: string }
  | { phase: "done"; releaseId: string };

export type SagaEvent =
  | { type: "SmoltReleaseRequested"; releaseId: string }
  | { type: "NetPenReserved"; releaseId: string; penId: string }
  | { type: "FishStockSeeded"; releaseId: string };

export type SagaCommand =
  | { type: "ReserveNetPen"; releaseId: string }
  | { type: "SeedStock"; releaseId: string; penId: string };

export function step(
  state: SagaState,
  event: SagaEvent,
): { nextState: SagaState; command: SagaCommand | null } {
  switch (event.type) {
    case "SmoltReleaseRequested":
      return {
        nextState: { phase: "reserving", releaseId: event.releaseId },
        command: { type: "ReserveNetPen", releaseId: event.releaseId },
      };
    case "NetPenReserved":
      if (state.phase !== "reserving") return { nextState: state, command: null };
      return {
        nextState: { phase: "seeding", releaseId: state.releaseId, penId: event.penId },
        command: { type: "SeedStock", releaseId: state.releaseId, penId: event.penId },
      };
    case "FishStockSeeded":
      if (state.phase !== "seeding") return { nextState: state, command: null };
      return {
        nextState: { phase: "done", releaseId: state.releaseId },
        command: null,
      };
    default: {
      const _never: never = event;
      return { nextState: state, command: null };
    }
  }
}

export interface CommandHandler {
  dispatch(cmd: SagaCommand): Promise<void>;
}

export async function runSaga(initial: SagaState, events: SagaEvent[], handler: CommandHandler): Promise<SagaState> {
  let state = initial;
  for (const event of events) {
    const { nextState, command } = step(state, event);
    state = nextState;
    if (command !== null) await handler.dispatch(command);
  }
  return state;
}
