export type ChargeEvent =
  | { type: "ChargeAuthorized"; id: string; amount: number; authorizedAt: string }
  | { type: "ChargeCaptured"; id: string; at: string }
  | { type: "ChargeVoided"; id: string; reason: string }
  | { type: "ChargeReceiptEmailed"; id: string; to: string };

export type ChargeDashboardRow = Readonly<{
  id: string;
  amount: number;
  authorizedAt: string;
  capturedAt: string | null;
  voided: boolean;
  voidReason: string | null;
}>;

export type ChargeDashboardView = Readonly<{
  rows: Readonly<Record<string, ChargeDashboardRow>>;
}>;

export const emptyView: ChargeDashboardView = { rows: {} };

export function project(view: ChargeDashboardView, event: ChargeEvent): ChargeDashboardView {
  switch (event.type) {
    case "ChargeAuthorized": {
      const row: ChargeDashboardRow = {
        id: event.id,
        amount: event.amount,
        authorizedAt: event.authorizedAt,
        capturedAt: null,
        voided: false,
        voidReason: null,
      };
      return { rows: { ...view.rows, [event.id]: row } };
    }
    case "ChargeCaptured": {
      const prior = view.rows[event.id];
      if (!prior) return view;
      return { rows: { ...view.rows, [event.id]: { ...prior, capturedAt: event.at } } };
    }
    case "ChargeVoided": {
      const prior = view.rows[event.id];
      if (!prior) return view;
      return { rows: { ...view.rows, [event.id]: { ...prior, voided: true, voidReason: event.reason } } };
    }
    case "ChargeReceiptEmailed":
      // not part of this view
      return view;
    default: { const _n: never = event; return view; }
  }
}

export function aggregateStream<V, E>(events: E[], reducer: (v: V, e: E) => V, initial: V): V {
  return events.reduce(reducer, initial);
}

export function chargeDashboardFrom(events: ChargeEvent[]): ChargeDashboardView {
  return aggregateStream(events, project, emptyView);
}
