Use a single `decide`/`evolve` pair and reject re-cataloguing by inspecting state.

```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type Command =
  | { type: 'Collect'; by: string; at: string }
  | { type: 'Catalogue'; catalogueId: string; at: string };

type Event =
  | { type: 'SampleCollected'; by: string; at: string }
  | { type: 'SampleCatalogued'; catalogueId: string; at: string };

type State =
  | { status: 'fresh' }
  | { status: 'collected'; by: string }
  | { status: 'catalogued'; catalogueId: string };

class InvariantError extends Error {}

export const GeologicSample: Decider<Command, Event, State> = {
  initialState: { status: 'fresh' },
  decide(command, state) {
    switch (command.type) {
      case 'Collect':
        if (state.status !== 'fresh') throw new InvariantError('not fresh');
        return [{ type: 'SampleCollected', by: command.by, at: command.at }];
      case 'Catalogue':
        if (state.status === 'catalogued') throw new InvariantError('already catalogued');
        if (state.status === 'fresh') throw new InvariantError('must collect first');
        return [{ type: 'SampleCatalogued', catalogueId: command.catalogueId, at: command.at }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'SampleCollected':
        return { status: 'collected', by: event.by };
      case 'SampleCatalogued':
        return { status: 'catalogued', catalogueId: event.catalogueId };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
