}

export type SweepState =
  | { status: "none" }
  | { status: "running"; id: string; trials: number }
  | { status: "finished"; id: string; best: number };

export type SweepEvent =
  | { type: "SweepStarted"; id: string }
  | { type: "SweepTrialRecorded" }
  | { type: "SweepFinished"; best: number };

const empty: SweepState = { status: "none" };

function when(state: SweepState, event: SweepEvent): SweepState {
  switch (event.type) {
    case "SweepStarted":
      return { status: "running", id: event.id, trials: 0 };
    case "SweepTrialRecorded":
      return state.status === "running" ? { ...state, trials: state.trials + 1 } : state;
    case "SweepFinished":
      return state.status === "running" ? { status: "finished", id: state.id, best: event.best } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function loadSweep(stream: AsyncIterable<SweepEvent>): Promise<SweepState> {
  return aggregateStream(stream, when, empty);
}
