```typescript
import { Effect } from "effect";

export type ObserverReportEvent =
  | { type: "ReportFiled"; stationId: string; position: bigint }
  | { type: "IssueRaised"; stationId: string; severity: "low" | "high"; position: bigint }
  | { type: "ReportClosed"; stationId: string; position: bigint };

export type ObserverView = Record<string, { reports: number; highIssues: number; open: number }>;
export const emptyView: ObserverView = {};

export function project(v: ObserverView, e: ObserverReportEvent): ObserverView {
  switch (e.type) {
    case "ReportFiled": {
      const cur = v[e.stationId] ?? { reports: 0, highIssues: 0, open: 0 };
      return { ...v, [e.stationId]: { ...cur, reports: cur.reports + 1, open: cur.open + 1 } };
    }
    case "IssueRaised": {
      const cur = v[e.stationId] ?? { reports: 0, highIssues: 0, open: 0 };
      return { ...v, [e.stationId]: { ...cur, highIssues: cur.highIssues + (e.severity === "high" ? 1 : 0) } };
    }
    case "ReportClosed": {
      const cur = v[e.stationId] ?? { reports: 0, highIssues: 0, open: 0 };
      return { ...v, [e.stationId]: { ...cur, open: Math.max(0, cur.open - 1) } };
    }
    default: {
      const _: never = e;
      return _;
    }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}
export interface EventFeed {
  fetchBatch(from: bigint, size: number): Promise<ObserverReportEvent[]>;
}
export interface ViewStore {
  save(v: ObserverView): Promise<void>;
}

export function runSubscription(
  name: string,
  feed: EventFeed,
  cp: CheckpointStore,
  store: ViewStore,
  batchSize: number,
): Effect.Effect<void> {
  return Effect.gen(function* () {
    const start = yield* Effect.promise(() => cp.read(name));
    let pos = start ?? 0n;
    let view: ObserverView = emptyView;
    const batch = yield* Effect.promise(() => feed.fetchBatch(pos, batchSize));
    for (const event of batch) {
      view = project(view, event);
      yield* Effect.promise(() => store.save(view));
      yield* Effect.promise(() => cp.write(name, event.position));
      pos = event.position;
    }
  });
}
