export type CurrentTrainingJob = {
  id: string;
  epoch: number;
  imageDigest: string;
};

export const CURRENT_VERSION = 3;

export type Snapshot<S> = { version: number; state: S };

type V1 = { id: string; epochs: string };
type V2 = { id: string; epoch: number };

function v1ToV2(raw: V1): V2 {
  const parsed = Number.parseInt(raw.epochs, 10);
  return { id: raw.id, epoch: Number.isNaN(parsed) ? 0 : parsed };
}

function v2ToV3(raw: V2): CurrentTrainingJob {
  return { ...raw, imageDigest: "unknown" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentTrainingJob> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1ToV2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2ToV3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`Unsupported snapshot version ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentTrainingJob };
}
