export type DeploymentStateV1 = { id: string; done: boolean };
export type DeploymentStateV2 = { id: string; done: boolean; target: string };
export type DeploymentStateV3 = { id: string; status: "running" | "done"; target: string };

export type CurrentDeploymentState = DeploymentStateV3;

