  return { id: s.id, status: s.done ? "done" : "running", target: s.target };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDeploymentState> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as DeploymentStateV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as DeploymentStateV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_SNAPSHOT_${v}`);
  return { version: CURRENT_VERSION, state: s as CurrentDeploymentState };
}

export function loadState(raw: Snapshot<unknown>): CurrentDeploymentState {
  return upgradeSnapshot(raw).state;
