export type WaterQualityLogState =
  | { status: "none" }
  | { status: "open"; id: string; readings: number }
  | { status: "closed"; id: string; readings: number };

export type WaterQualityCommand =
  | { type: "open"; id: string }
  | { type: "record"; ph: number; tempC: number; at: string }
  | { type: "close"; at: string };

export type WaterQualityEvent =
  | { type: "WaterQualityLogOpened"; id: string }
  | { type: "WaterQualityReadingRecorded"; ph: number; tempC: number; at: string }
  | { type: "WaterQualityLogClosed"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const waterQualityLogDecider: Decider<WaterQualityCommand, WaterQualityEvent, WaterQualityLogState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "WaterQualityLogOpened", id: command.id }];
      case "record":
        if (state.status === "closed") throw new DomainError("CLOSED");
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "WaterQualityReadingRecorded", ph: command.ph, tempC: command.tempC, at: command.at }];
      case "close":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "WaterQualityLogClosed", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "WaterQualityLogOpened":
        return { status: "open", id: event.id, readings: 0 };
      case "WaterQualityReadingRecorded":
        if (state.status !== "open") return state;
        return { ...state, readings: state.readings + 1 };
      case "WaterQualityLogClosed":
        if (state.status !== "open") return state;
        return { status: "closed", id: state.id, readings: state.readings };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

Snapshots avoid re-folding long event streams by persisting state plus a version tag. When the schema evolves, a loader runs the right chain of upgraders in order so older snapshots are migrated at read time without rewriting any events. The decider keeps its pure contract; the upgrade logic lives entirely at the storage boundary.

```typescript
export interface Snapshot<S> {
  version: number;
  state: S;
}

export const CURRENT_VERSION = 2 as const;

export interface SeasonV1 {
  id: string;
  year: number;
  matches: string[];
}

export interface SeasonV2 {
  id: string;
  year: number;
  matches: string[];
  champion: string | null;
}

export type CurrentState = SeasonV2;

function v1Tov2(snap: Snapshot<SeasonV1>): Snapshot<SeasonV2> {
  return { version: 2, state: { ...snap.state, champion: null } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentState> {
  let s: Snapshot<unknown> = raw;
  if (s.version === 1) s = v1Tov2(s as Snapshot<SeasonV1>);
  if (s.version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED:${s.version}`);
  return s as Snapshot<CurrentState>;
}

export function loadSeason(raw: unknown): CurrentState {
  if (typeof raw !== "object" || raw === null) throw new Error("INVALID");
  const snap = raw as Snapshot<unknown>;
  if (typeof snap.version !== "number") throw new Error("MISSING_VERSION");
  return upgradeSnapshot(snap).state;
}
```

