export type VotingSessionState =
  | { status: "scheduled"; id: string; opensAt: string }
  | { status: "open"; id: string; openedAt: string; votes: number }
  | { status: "closed"; id: string; closedAt: string; votes: number };

export type VotingSessionEvent =
  | { type: "Scheduled"; id: string; opensAt: string }
  | { type: "Opened"; at: string }
  | { type: "VoteCast" }
  | { type: "Closed"; at: string };

export type Snapshot<S> = { version: number; state: S; revision: bigint };
export const CURRENT_VERSION = 1;
export const initialState: VotingSessionState = { status: "scheduled", id: "", opensAt: "" };

export function evolve(state: VotingSessionState, event: VotingSessionEvent): VotingSessionState {
  switch (event.type) {
    case "Scheduled":
      return { status: "scheduled", id: event.id, opensAt: event.opensAt };
    case "Opened":
      return state.status === "scheduled" ? { status: "open", id: state.id, openedAt: event.at, votes: 0 } : state;
    case "VoteCast":
      return state.status === "open" ? { ...state, votes: state.votes + 1 } : state;
    case "Closed":
      return state.status === "open" ? { status: "closed", id: state.id, closedAt: event.at, votes: state.votes } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export type LoadInput = {
  snapshot: Snapshot<VotingSessionState> | null;
  eventsSince: VotingSessionEvent[];
};

export function loadFromSnapshot(input: LoadInput): VotingSessionState {
  const base = input.snapshot && input.snapshot.version === CURRENT_VERSION ? input.snapshot.state : initialState;
  return input.eventsSince.reduce(evolve, base);
}
