export type PlayerCommand =
  | { type: "sign"; id: string; name: string; club: string }
  | { type: "retire"; reason: string };

export type PlayerEvent =
  | { type: "PlayerSigned"; id: string; name: string; club: string }
  | { type: "PlayerRetired"; reason: string };

export type PlayerState =
  | { status: "none" }
  | { status: "active"; id: string; name: string; club: string }
  | { status: "retired"; id: string };

export const initialPlayer: PlayerState = { status: "none" };

export function decide(c: PlayerCommand, s: PlayerState): PlayerEvent[] {
  switch (c.type) {
    case "sign":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "PlayerSigned", id: c.id, name: c.name, club: c.club }];
    case "retire":
      if (s.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "PlayerRetired", reason: c.reason }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: PlayerState, e: PlayerEvent): PlayerState {
  switch (e.type) {
    case "PlayerSigned":
      return { status: "active", id: e.id, name: e.name, club: e.club };
    case "PlayerRetired":
      if (s.status !== "active") return s;
      return { status: "retired", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: PlayerEvent }>>;
  appendToStream(stream: string, events: readonly PlayerEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export interface RosterRow { club: string; players: string[]; }
export interface ReadStore { loadRoster(club: string): Promise<RosterRow | null>; }

export async function handleCommand(store: EventStore, stream: string, cmd: PlayerCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const s = stored.reduce<PlayerState>((a, { event }) => evolve(a, event), initialPlayer);
  const expected = stored.length === 0 ? "no_stream" as const : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, decide(cmd, s), { expectedRevision: expected });
}

// Roster is a projection: eventually consistent with the Player event stream.
export async function queryRoster(reads: ReadStore, club: string): Promise<RosterRow | null> {
  return reads.loadRoster(club);
}
