export type IncidentEvent =
  | { type: "IncidentOpened"; id: string }
  | { type: "IncidentResolved"; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendResult {
  nextRevision: bigint;
}

export interface ReadResult<E> {
  events: E[];
  revision: bigint | "no_stream";
}

export interface EventStore {
  readStream<E>(stream: string): Promise<ReadResult<E>>;
  appendToStream<E>(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendIncident(
  store: EventStore,
  stream: string,
  newEvents: IncidentEvent[],
): Promise<bigint> {
  const { revision } = await store.readStream<IncidentEvent>(stream);
  try {
    const { nextRevision } = await store.appendToStream(stream, newEvents, { expectedRevision: revision });
    return nextRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("WRONG_EXPECTED_REVISION")) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
