  actions: {
    next: assign({ step: ({ context }) => context.step + 1 }),
    prev: assign({ step: ({ context }) => context.step - 1 })
  }
}).createMachine({
  id: 'tour',
  context: { step: 0, total: 5 },
  initial: 'running',
  output: ({ context }) => ({ lastStep: context.step, completed: context.step >= context.total - 1 }),
  states: {
    running: {
      on: {
        NEXT: [
          { guard: 'hasNext', actions: 'next' },
          { guard: 'onLast', target: 'completed' }
        ],
        PREV: { guard: 'hasPrev', actions: 'prev' },
        SKIP: 'skipped',
        COMPLETE: 'completed'
      }
    },
    completed: { type: 'final' },
    skipped: { type: 'final' }
  }
});
