Store each snapshot as `{ version, state }`. On load, check the version; if it's older than `CURRENT_VERSION`, run the chain of upgraders, then assert the final shape.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type VehicleInspectionV1 = { id: string; odometer: number };
export type VehicleInspectionV2 = {
  id: string;
  odometer: number;
  faults: ReadonlyArray<string>;
};

export type CurrentVehicleInspection = VehicleInspectionV2;
export const CURRENT_VERSION = 2;

class SnapshotUpgradeError extends Error {}

function v1Tov2(s: VehicleInspectionV1): VehicleInspectionV2 {
  return { ...s, faults: [] };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentVehicleInspection> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as VehicleInspectionV1); v = 2; }
  if (v !== CURRENT_VERSION) throw new SnapshotUpgradeError("UNSUPPORTED");
  const out = s as CurrentVehicleInspection;
  if (!out.id || typeof out.odometer !== "number" || !Array.isArray(out.faults)) {
    throw new SnapshotUpgradeError("SHAPE");
  }
  return { version: v, state: out };
}

export function persistSnapshot(state: CurrentVehicleInspection): Snapshot<CurrentVehicleInspection> {
  return { version: CURRENT_VERSION, state };
}
