```typescript
export type EnrolmentState =
  | { status: "none" }
  | { status: "registered"; id: string; learner: string }
  | { status: "confirmed"; id: string; learner: string };

export type EnrolmentCommand =
  | { type: "register"; id: string; learner: string }
  | { type: "confirm" };

export type EnrolmentEvent =
  | { type: "EnrolmentRegistered"; id: string; learner: string }
  | { type: "EnrolmentConfirmed" };

export class DomainError extends Error {}

export const initialState: EnrolmentState = { status: "none" };

export function evolve(s: EnrolmentState, e: EnrolmentEvent): EnrolmentState {
  switch (e.type) {
    case "EnrolmentRegistered":
      return { status: "registered", id: e.id, learner: e.learner };
    case "EnrolmentConfirmed":
      if (s.status !== "registered") return s;
      return { status: "confirmed", id: s.id, learner: s.learner };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: EnrolmentCommand, s: EnrolmentState): EnrolmentEvent[] {
  switch (c.type) {
    case "register":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "EnrolmentRegistered", id: c.id, learner: c.learner }];
    case "confirm":
      if (s.status !== "registered") throw new DomainError("NOT_REGISTERED");
      return [{ type: "EnrolmentConfirmed" }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<EnrolmentEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<EnrolmentEvent>,
    o: { expectedRevision: ExpectedRevision },
  ): Promise<void>;
}

// READ SIDE — the ReadStore is populated asynchronously by a projection.
// It is eventually consistent with the event store; a command's effect is
// visible to queries only after the projection has caught up.
export type EnrolmentView = Readonly<{ id: string; learner: string; confirmed: boolean }>;

export interface ReadStore {
  get(id: string): Promise<EnrolmentView | null>;
}

export async function handleCommand(
  streamName: string,
  command: EnrolmentCommand,
  store: EventStore,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const next = decide(command, state);
  if (next.length === 0) return;
  await store.appendToStream(streamName, next, { expectedRevision: revision ?? "no_stream" });
}

export async function queryView(
  readStore: ReadStore,
  id: string,
): Promise<EnrolmentView | null> {
  return readStore.get(id);
}
