export type SherpaEvent =
  | { type: "SherpaHired"; id: string; name: string }
  | { type: "SherpaAssigned"; expeditionId: string }
  | { type: "SherpaDischarged" };

export interface EventEnvelope<E> {
  readonly event: E;
  readonly position: bigint;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface ReadModel<V, E> {
  load(): Promise<V>;
  apply(view: V, event: E): Promise<V>;
  save(view: V): Promise<void>;
}

export async function runSubscription<V>(
  name: string,
  source: AsyncIterable<EventEnvelope<SherpaEvent>>,
  checkpointStore: CheckpointStore,
  readModel: ReadModel<V, SherpaEvent>,
): Promise<void> {
  const start = await checkpointStore.read(name);
  let view = await readModel.load();
  const readStream = async (): Promise<void> => {
    for await (const envelope of source) {
      if (start !== null && envelope.position <= start) continue;
      view = await readModel.apply(view, envelope.event);
      await readModel.save(view);
      await checkpointStore.write(name, envelope.position);
    }
  };
  await readStream();
}
