  | { type: "create"; id: string; title: string }
  | { type: "submit"; at: string }
  | { type: "approve"; at: string };

export type DocumentEvent =
  | { type: "DocumentCreated"; id: string; title: string }
  | { type: "DocumentSubmitted"; at: string }
  | { type: "DocumentApproved"; at: string };

export class DocumentError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DocumentError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const documentDecider: Decider<DocumentCommand, DocumentEvent, DocumentState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "empty") throw new DocumentError("EXISTS");
        return [{ type: "DocumentCreated", id: command.id, title: command.title }];
      case "submit":
        if (state.status === "submitted") throw new DocumentError("ALREADY_SUBMITTED");
        if (state.status !== "drafting") throw new DocumentError("NOT_DRAFTING");
        return [{ type: "DocumentSubmitted", at: command.at }];
      case "approve":
        if (state.status !== "submitted") throw new DocumentError("NOT_SUBMITTED");
        return [{ type: "DocumentApproved", at: command.at }];
      default: {
        const _n: never = command;
        throw new DocumentError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DocumentCreated":
        return { status: "drafting", id: event.id, title: event.title };
      case "DocumentSubmitted":
        if (state.status !== "drafting") return state;
        return { status: "submitted", id: state.id, title: state.title, submittedAt: event.at };
      case "DocumentApproved":
        if (state.status !== "submitted") return state;
        return { status: "approved", id: state.id, title: state.title, approvedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
