```typescript
export const CURRENT_VERSION = 3;

export interface AquaticFarmV1 {
  readonly id: string;
  readonly region: string;
}

export interface AquaticFarmV2 {
  readonly id: string;
  readonly region: string;
  readonly hectares: number;
}

export interface AquaticFarmV3 {
  readonly id: string;
  readonly region: string;
  readonly hectares: number;
  readonly licenseNumber: string | null;
}

export type AquaticFarmCurrent = AquaticFarmV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(s: AquaticFarmV1): AquaticFarmV2 {
  return { ...s, hectares: 0 };
}

function v2Tov3(s: AquaticFarmV2): AquaticFarmV3 {
  return { ...s, licenseNumber: null };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<AquaticFarmCurrent> {
  if (raw.version === CURRENT_VERSION) {
    return { version: CURRENT_VERSION, state: raw.state as AquaticFarmCurrent };
  }
  let version = raw.version;
  let state: unknown = raw.state;
  if (version === 1) {
    state = v1Tov2(state as AquaticFarmV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as AquaticFarmV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${raw.version}`);
  return { version: CURRENT_VERSION, state: state as AquaticFarmCurrent };
}
