export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  try {
    for await (const event of stream) {
      state = evolve(state, event);
    }
  } catch (err) {
    throw err instanceof Error ? err : new Error(String(err));
  }
  return state;
}

export function loadStoryboardFrame(events: readonly StoryboardFrameEvent[]): StoryboardFrameState {
  return events.reduce(when, { status: "none" } as StoryboardFrameState);
