export type AdSlotEvent =
  | { type: "AdSlotOpened"; slotId: string; floorCents: number }
  | { type: "AdSlotFilled"; slotId: string; advertiserId: string }
  | { type: "AdSlotClosed"; slotId: string };

export interface AppendResult {
  readonly nextRevision: bigint;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: AdSlotEvent }>>;
  appendToStream(
    stream: string,
    events: readonly AdSlotEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(
    public readonly stream: string,
    public readonly expected: ExpectedRevision,
    public readonly actual: bigint | "no_stream",
  ) {
    super(`Concurrency conflict on ${stream}: expected ${String(expected)}, got ${String(actual)}`);
    this.name = "ConcurrencyConflict";
  }
}

function isConflict(err: unknown): err is { code: "WRONG_EXPECTED_REVISION"; actualRevision: bigint | "no_stream" } {
  return typeof err === "object" && err !== null && (err as { code?: unknown }).code === "WRONG_EXPECTED_REVISION";
}

export async function appendAdSlot(
  store: EventStore,
  stream: string,
  events: readonly AdSlotEvent[],
  expectedRevision: ExpectedRevision,
): Promise<AppendResult> {
  try {
    return await store.appendToStream(stream, events, { expectedRevision });
  } catch (err) {
    if (isConflict(err)) {
      throw new ConcurrencyConflict(stream, expectedRevision, err.actualRevision);
    }
    throw err;
  }
}
