export type DiscussionEvent =
  | { type: "DiscussionOpened"; id: string; topic: string }
  | { type: "PostAppended"; id: string; author: string; body: string }
  | { type: "DiscussionArchived"; id: string };

export type DiscussionView = Readonly<{
  threads: Readonly<Record<string, { topic: string; posts: number; archived: boolean }>>;
}>;

export const emptyView: DiscussionView = { threads: {} };

export function project(view: DiscussionView, event: DiscussionEvent): DiscussionView {
  switch (event.type) {
    case "DiscussionOpened":
      return { threads: { ...view.threads, [event.id]: { topic: event.topic, posts: 0, archived: false } } };
    case "PostAppended": {
      const thread = view.threads[event.id];
      if (!thread) return view;
      return { threads: { ...view.threads, [event.id]: { ...thread, posts: thread.posts + 1 } } };
    }
    case "DiscussionArchived": {
      const thread = view.threads[event.id];
      if (!thread) return view;
      return { threads: { ...view.threads, [event.id]: { ...thread, archived: true } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export type Envelope = { revision: bigint; event: DiscussionEvent };

export interface EventStoreReader {
  readForward(from: bigint, batchSize: number): Promise<ReadonlyArray<Envelope>>;
}

export interface ReadModelStore {
  wipe(): Promise<void>;
  get(): Promise<DiscussionView>;
  put(view: DiscussionView): Promise<void>;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  wipeFirst: boolean;
  onProgress?: (cursor: bigint, processed: number) => void;
}

export async function rebuild(
  reader: EventStoreReader,
  store: ReadModelStore,
  options: RebuildOptions,
): Promise<void> {
  if (options.wipeFirst) await store.wipe();
  let cursor: bigint = options.from;
  let processed = 0;
  let view: DiscussionView = options.from === 0n ? emptyView : await store.get();
  while (true) {
    const batch = await reader.readForward(cursor, options.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = project(view, event);
      cursor = revision + 1n;
      processed = processed + 1;
    }
    await store.put(view);
    if (options.onProgress) options.onProgress(cursor, processed);
  }
}
```

Refactor this handler to separate orchestration from business logic: hoist the invariant checks into a pure `decide` and keep the handler thin. Aggregate is a MergeGate.

```ts
async function handle(store: Store, stream: string, cmd: Cmd) {
  const ev = await store.read(stream);
  if (cmd.type === 'lock' && ev.some(e => e.type === 'MergeGateLocked')) throw new Error('locked');
  await store.append(stream, [{ type: 'MergeGateLocked' }]);
}
```

```typescript
export type MergeGateState =
  | { status: "open" }
  | { status: "locked"; lockedBy: string };

export type MergeGateCommand =
  | { type: "lock"; lockedBy: string }
  | { type: "unlock" };

export type MergeGateEvent =
  | { type: "MergeGateLocked"; lockedBy: string }
  | { type: "MergeGateUnlocked" };

export const initialState: MergeGateState = { status: "open" };

export function evolve(state: MergeGateState, event: MergeGateEvent): MergeGateState {
  switch (event.type) {
    case "MergeGateLocked":
      return { status: "locked", lockedBy: event.lockedBy };
    case "MergeGateUnlocked":
      return { status: "open" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: MergeGateCommand, state: MergeGateState): MergeGateEvent[] {
  switch (command.type) {
    case "lock":
      if (state.status === "locked") throw new Error("ALREADY_LOCKED");
      return [{ type: "MergeGateLocked", lockedBy: command.lockedBy }];
    case "unlock":
      if (state.status !== "locked") throw new Error("NOT_LOCKED");
      return [{ type: "MergeGateUnlocked" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ events: MergeGateEvent[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: MergeGateEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handle(store: EventStore, streamName: string, command: MergeGateCommand): Promise<void> {
  const loaded = await store.readStream(streamName);
  const state = loaded.events.reduce(evolve, initialState);
  const events = decide(command, state);
  await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
}
