  initialState: { status: "empty" },
  decide(c, s) {
    switch (c.type) {
      case "plan":
        if (s.status !== "empty") throw new DomainError("RELEASE_EXISTS");
        return [{ type: "ReleasePlanned", id: c.id, version: c.version }];
      case "approve":
        if (s.status === "cancelled") throw new DomainError("CANCELLED");
        if (s.status !== "planned") throw new DomainError("NOT_PLANNED");
        return [{ type: "ReleaseApproved", approver: c.approver }];
      case "rollout":
        if (s.status !== "approved") throw new DomainError("NOT_APPROVED");
        return [{ type: "ReleaseRolledOut", at: c.at }];
      case "cancel":
        if (s.status === "rolled-out") throw new DomainError("ALREADY_OUT");
        if (s.status === "empty") throw new DomainError("UNKNOWN");
        return [{ type: "ReleaseCancelled", reason: c.reason }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN_CMD"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ReleasePlanned":
        return { status: "planned", id: e.id, version: e.version };
      case "ReleaseApproved":
        if (s.status !== "planned") return s;
        return { status: "approved", id: s.id, version: s.version, approver: e.approver };
      case "ReleaseRolledOut":
        if (s.status !== "approved") return s;
        return { status: "rolled-out", id: s.id, version: s.version, at: e.at };
      case "ReleaseCancelled":
        if (s.status === "empty") return s;
        return { status: "cancelled", id: "id" in s ? s.id : "" };
      default: { const _n: never = e; return s; }
    }
  },
};
