export type RecipeState =
  | { status: "none" }
  | { status: "draft"; id: string; title: string; steps: number }
  | { status: "published"; id: string; title: string; steps: number; publishedAt: string }
  | { status: "retired"; id: string; retiredAt: string };

export type RecipeCommand =
  | { type: "create"; id: string; title: string }
  | { type: "addStep" }
  | { type: "publish"; at: string }
  | { type: "retire"; at: string };

export type RecipeEvent =
  | { type: "RecipeCreated"; id: string; title: string }
  | { type: "RecipeStepAdded" }
  | { type: "RecipePublished"; at: string }
  | { type: "RecipeRetired"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const recipeDecider: Decider<RecipeCommand, RecipeEvent, RecipeState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.title.length === 0) throw new DomainError("BAD_TITLE");
        return [{ type: "RecipeCreated", id: command.id, title: command.title }];
      case "addStep":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "RecipeStepAdded" }];
      case "publish":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (state.steps === 0) throw new DomainError("NO_STEPS");
        return [{ type: "RecipePublished", at: command.at }];
      case "retire":
        if (state.status !== "published") throw new DomainError("NOT_PUBLISHED");
        return [{ type: "RecipeRetired", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RecipeCreated":
        return { status: "draft", id: event.id, title: event.title, steps: 0 };
      case "RecipeStepAdded":
        if (state.status !== "draft") return state;
        return { ...state, steps: state.steps + 1 };
      case "RecipePublished":
        if (state.status !== "draft") return state;
        return { status: "published", id: state.id, title: state.title, steps: state.steps, publishedAt: event.at };
      case "RecipeRetired":
        if (state.status !== "published") return state;
        return { status: "retired", id: state.id, retiredAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

