```typescript
export type DonorCommand =
  | { type: "register"; id: string; name: string }
  | { type: "recordGift"; amount: number; at: string }
  | { type: "deactivate" };

export type DonorEvent =
  | { type: "DonorRegistered"; id: string; name: string }
  | { type: "DonorGiftRecorded"; amount: number; at: string }
  | { type: "DonorDeactivated" };

type DonorWriteState =
  | { status: "none" }
  | { status: "active"; id: string; name: string; totalGifts: number }
  | { status: "inactive"; id: string };

const initial: DonorWriteState = { status: "none" };

function evolve(state: DonorWriteState, event: DonorEvent): DonorWriteState {
  switch (event.type) {
    case "DonorRegistered":
      return { status: "active", id: event.id, name: event.name, totalGifts: 0 };
    case "DonorGiftRecorded":
      if (state.status !== "active") return state;
      return { ...state, totalGifts: state.totalGifts + event.amount };
    case "DonorDeactivated":
      if (state.status !== "active") return state;
      return { status: "inactive", id: state.id };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: DonorCommand, state: DonorWriteState): DonorEvent[] {
  switch (command.type) {
    case "register":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "DonorRegistered", id: command.id, name: command.name }];
    case "recordGift":
      if (state.status !== "active") throw new Error("NOT_ACTIVE");
      if (command.amount <= 0) throw new Error("INVALID_AMOUNT");
      return [{ type: "DonorGiftRecorded", amount: command.amount, at: command.at }];
    case "deactivate":
      if (state.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "DonorDeactivated" }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface DonorView {
  readonly id: string;
  readonly name: string;
  readonly totalGifts: number;
  readonly active: boolean;
}

export interface ReadStore {
  load(id: string): Promise<DonorView | null>;
}

export async function handleCommand(
  command: DonorCommand,
  ctx: { streamName: string; eventStore: EventStore<DonorEvent> }
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initial);
  const out = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, out, { expectedRevision: revision });
}

export async function queryView(reader: ReadStore, id: string): Promise<DonorView | null> {
  return reader.load(id);
}
```

Hold the pending text in context, enter a `debouncing` state on FILTER, and `after: 300` commits the text. Re-entering `debouncing` on each keystroke resets the timer.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { text: string; pending: string };
type Ev = { type: 'FILTER'; text: string };

export const filterMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'filter',
  context: { text: '', pending: '' },
  initial: 'idle',
  states: {
    idle: {
      on: {
        FILTER: {
          target: 'debouncing',
          actions: assign({ pending: ({ event }) => event.text }),
        },
      },
    },
    debouncing: {
      on: {
        FILTER: {
          target: 'debouncing',
          reenter: true,
          actions: assign({ pending: ({ event }) => event.text }),
        },
      },
      after: {
        300: {
          target: 'idle',
          actions: assign({ text: ({ context }) => context.pending }),
        },
      },
    },
  },
});
```

The machine counts ready pods and failures as it progresses. Each POD_READY bumps `ready`; when it reaches the target, we transition to `healthy`. Each POD_FAIL bumps `failures`; the first transition is guarded by a failure-budget check that jumps straight to `rollback`, and the fallback just records the failure.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { target: number; ready: number; failures: number; budget: number }
type Ev = { type: 'START'; target: number } | { type: 'POD_READY' } | { type: 'POD_FAIL' };

export const budgetRollout = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    ok: ({ context }) => context.ready + 1 >= context.target,
    over: ({ context }) => context.failures + 1 > context.budget
  }
}).createMachine({
  id: 'budgetRollout',
  context: { target: 0, ready: 0, failures: 0, budget: 2 },
  initial: 'pending',
  states: {
    pending: { on: { START: { target: 'rollingOut', actions: assign({ target: ({ event }) => event.target, ready: () => 0, failures: () => 0 }) } } },
    rollingOut: {
      on: {
        POD_READY: [
          { guard: 'ok', target: 'healthy' },
          { actions: assign({ ready: ({ context }) => context.ready + 1 }) }
        ],
        POD_FAIL: [
          { guard: 'over', target: 'rollback' },
          { actions: assign({ failures: ({ context }) => context.failures + 1 }) }
        ]
      }
    },
    healthy: { type: 'final' },
    rollback: {}
  }
});
