import { Effect } from "effect";

export type RemittanceState =
  | { status: "none" }
  | { status: "initiated"; id: string; amount: number };

export type RemittanceEvent =
  | { type: "RemittanceInitiated"; id: string; amount: number }
  | { type: "RemittanceFunded"; at: string };

export const initialState: RemittanceState = { status: "none" };

export function when(state: RemittanceState, event: RemittanceEvent): RemittanceState {
  switch (event.type) {
    case "RemittanceInitiated":
      return { status: "initiated", id: event.id, amount: event.amount };
    case "RemittanceFunded":
      return state;
    default: { const _n: never = event; return state; }
  }
}

export interface EventStore {
  readStreamPage(
    stream: string,
    from: bigint,
    size: number,
  ): Promise<{ events: ReadonlyArray<RemittanceEvent>; nextFrom: bigint | null }>;
}

export const aggregateStream = (store: EventStore, streamName: string, batchSize: number) =>
  Effect.gen(function* () {
    let state: RemittanceState = initialState;
    let cursor: bigint | null = 0n;
    while (cursor !== null) {
      const page = yield* Effect.promise(() =>
        store.readStreamPage(streamName, cursor as bigint, batchSize),
      );
      for (const event of page.events) {
        state = when(state, event);
      }
      cursor = page.nextFrom;
    }
    return state;
  });
