```typescript
export type Snapshot<S> = { version: number; state: S };

export type DispatchBeaconV1 = { id: string; armed: boolean };
export type DispatchBeaconV2 = { id: string; armed: boolean; pulses: number };
export type DispatchBeaconV3 = {
  id: string;
  status: "armed" | "fired";
  pulses: number;
};

export type CurrentDispatchBeacon = DispatchBeaconV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: DispatchBeaconV1): DispatchBeaconV2 {
  return { ...s, pulses: 0 };
}

function v2Tov3(s: DispatchBeaconV2): DispatchBeaconV3 {
  return { id: s.id, status: s.armed ? "armed" : "fired", pulses: s.pulses };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDispatchBeacon> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as DispatchBeaconV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as DispatchBeaconV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED_VERSION");
  const out = s as CurrentDispatchBeacon;
  if (!out.id || !out.status || typeof out.pulses !== "number") {
    throw new UpgradeError("SHAPE");
  }
  return { version: v, state: out };
}
