export class DomainError extends Error {}

export type DonationDriveState =
  | { status: "none" }
  | { status: "open"; id: string; goal: number; raised: number }
  | { status: "closed"; id: string; finalTotal: number };

export type DonationDriveCommand =
  | { type: "launch"; id: string; goal: number }
  | { type: "pledge"; amount: number; donor: string }
  | { type: "close" };

export type DonationDriveEvent =
  | { type: "launched"; id: string; goal: number }
  | { type: "pledged"; amount: number; donor: string }
  | { type: "closed"; finalTotal: number };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const DonationDriveDecider: Decider<DonationDriveCommand, DonationDriveEvent, DonationDriveState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "launch":
        if (s.status !== "none") throw new DomainError("already launched");
        if (c.goal <= 0) throw new DomainError("goal must be positive");
        return [{ type: "launched", id: c.id, goal: c.goal }];
      case "pledge":
        if (s.status !== "open") throw new DomainError("drive closed");
        if (c.amount <= 0) throw new DomainError("amount must be positive");
        return [{ type: "pledged", amount: c.amount, donor: c.donor }];
      case "close":
        if (s.status !== "open") throw new DomainError("not open");
        return [{ type: "closed", finalTotal: s.raised }];
      default: {
        const _: never = c;
        return _;
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "launched":
        return { status: "open", id: e.id, goal: e.goal, raised: 0 };
      case "pledged":
        return s.status === "open" ? { ...s, raised: s.raised + e.amount } : s;
      case "closed":
        return s.status === "open" ? { status: "closed", id: s.id, finalTotal: e.finalTotal } : s;
      default: {
        const _: never = e;
        return _;
      }
    }
  },
};
