export interface BuildRunV1 {
  readonly id: string;
  readonly commit: string;
  readonly status: "running" | "succeeded" | "failed";
}

export interface BuildRunV2 extends BuildRunV1 {
  readonly artefactId: string | null;
}

export interface BuildRunV3 extends BuildRunV2 {
  readonly durationMs: number;
}

export type CurrentBuildRun = BuildRunV3;
export const CURRENT_VERSION = 3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(state: BuildRunV1): BuildRunV2 {
  return { ...state, artefactId: null };
}

function v2Tov3(state: BuildRunV2): BuildRunV3 {
  return { ...state, durationMs: 0 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentBuildRun> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as BuildRunV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as BuildRunV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unsupported snapshot version ${snap.version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentBuildRun };
}

export function loadSnapshot(snap: Snapshot<unknown>): CurrentBuildRun {
  return upgradeSnapshot(snap).state;
}
