export type AgreementEvent =
  | { type: "AgreementProposed"; id: string; parties: string[] }
  | { type: "AgreementAccepted"; at: string }
  | { type: "AgreementRevoked"; reason: string };

export type AgreementState =
  | { status: "none" }
  | { status: "proposed"; id: string; parties: string[] }
  | { status: "accepted"; id: string; parties: string[]; at: string }
  | { status: "revoked"; id: string; reason: string };

export function when(state: AgreementState, event: AgreementEvent): AgreementState {
  switch (event.type) {
    case "AgreementProposed":
      return { status: "proposed", id: event.id, parties: [...event.parties] };
    case "AgreementAccepted":
      if (state.status !== "proposed") return state;
      return { status: "accepted", id: state.id, parties: state.parties, at: event.at };
    case "AgreementRevoked":
      return { status: "revoked", id: "id" in state ? state.id : "", reason: event.reason };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregate(events: readonly AgreementEvent[]): AgreementState {
  return events.reduce<AgreementState>(when, { status: "none" });
}
