```typescript
export type LivestockHerdState =
  | { status: "none" }
  | { status: "active"; id: string; species: string; headCount: number }
  | { status: "retired"; id: string; retiredAt: string };

export type LivestockHerdCommand =
  | { type: "register"; id: string; species: string }
  | { type: "addAnimals"; count: number }
  | { type: "removeAnimals"; count: number }
  | { type: "retire"; at: string };

export type LivestockHerdEvent =
  | { type: "LivestockHerdRegistered"; id: string; species: string }
  | { type: "LivestockHerdAnimalsAdded"; count: number }
  | { type: "LivestockHerdAnimalsRemoved"; count: number }
  | { type: "LivestockHerdRetired"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const livestockHerdDecider: Decider<LivestockHerdCommand, LivestockHerdEvent, LivestockHerdState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("HERD_EXISTS");
        return [{ type: "LivestockHerdRegistered", id: command.id, species: command.species }];
      case "addAnimals":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.count <= 0) throw new DomainError("COUNT_MUST_BE_POSITIVE");
        return [{ type: "LivestockHerdAnimalsAdded", count: command.count }];
      case "removeAnimals":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.count <= 0) throw new DomainError("COUNT_MUST_BE_POSITIVE");
        if (command.count > state.headCount) throw new DomainError("INSUFFICIENT_HEAD_COUNT");
        return [{ type: "LivestockHerdAnimalsRemoved", count: command.count }];
      case "retire":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "LivestockHerdRetired", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "LivestockHerdRegistered":
        return { status: "active", id: event.id, species: event.species, headCount: 0 };
      case "LivestockHerdAnimalsAdded":
        if (state.status !== "active") return state;
        return { ...state, headCount: state.headCount + event.count };
      case "LivestockHerdAnimalsRemoved":
        if (state.status !== "active") return state;
        return { ...state, headCount: Math.max(0, state.headCount - event.count) };
      case "LivestockHerdRetired":
        if (state.status !== "active") return state;
        return { status: "retired", id: state.id, retiredAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

A checkpointed subscription resumes after a crash by persisting the last successfully-applied stream position. The write order matters: apply the projection first, then advance the checkpoint. If the process dies in between, the next start re-applies the last event at most twice but never skips it.

```typescript
export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(subscription: string): Promise<bigint | null>;
  write(subscription: string, position: bigint): Promise<void>;
}

export interface Batch<E> {
  events: ReadonlyArray<EventEnvelope<E>>;
  lastPosition: bigint | null;
}

export interface EventSource<E> {
  readBatch(from: bigint, size: number): Promise<Batch<E>>;
}

export interface ProjectionHandler<V, E> {
  project(view: V, event: E): V;
  persist(view: V): Promise<void>;
  load(): Promise<V>;
}

export async function runSubscription<V, E>(
  subscriptionName: string,
  source: EventSource<E>,
  checkpoints: CheckpointStore,
  handler: ProjectionHandler<V, E>,
  batchSize: number,
): Promise<void> {
  const last = await checkpoints.read(subscriptionName);
  let from: bigint = last ?? 0n;
  let view: V = await handler.load();
  while (true) {
    const batch = await source.readBatch(from, batchSize);
    if (batch.events.length === 0) return;
    for (const { position, event } of batch.events) {
      view = handler.project(view, event);
      await handler.persist(view);
      await checkpoints.write(subscriptionName, position);
      from = position + 1n;
    }
    if (batch.lastPosition === null) return;
  }
}
```

Refactor this to use optimistic concurrency with expectedRevision. Current code just appends without a revision check:

```ts
async function bid(store: EventStore, stream: string, amount: number) {
  await store.appendToStream(stream, [{ type: 'BidPlaced', amount }]);
}
```

Load the stream first, compute the last revision, then append with that revision so a concurrent writer will be rejected by the store.

```typescript
export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; roomId: string; reservePrice: number }
  | { type: "BidPlaced"; bidder: string; amount: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<readonly StoredEvent<E>[]>;
  appendToStream<E>(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(stream: string) {
    super(`Concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function placeBid(
  store: EventStore,
  stream: string,
  bidder: string,
  amount: number,
): Promise<void> {
  const stored = await store.readStream<AuctionRoomEvent>(stream);
  if (stored.length === 0) throw new Error("AUCTION_NOT_OPEN");
  const expected: ExpectedRevision = stored[stored.length - 1]!.revision;
  const event: AuctionRoomEvent = { type: "BidPlaced", bidder, amount };
  try {
    await store.appendToStream<AuctionRoomEvent>(stream, [event], { expectedRevision: expected });
  } catch (err) {
    if ((err as { code?: string }).code === "WRONG_EXPECTED_REVISION") {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
```

