      case "start":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "VisitRecordStarted", id: c.id, patientId: c.patientId }];
      case "addNote":
        if (s.status !== "open") throw new DomainError("NOT_OPEN");
        if (!c.note.trim()) throw new DomainError("NOTE_EMPTY");
        return [{ type: "NoteAppended", note: c.note }];
