```typescript
export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; count: number }
  | { type: "FishStockHarvested"; id: string; count: number };

export interface EventBatch<E> {
  readonly events: readonly { revision: bigint; payload: E }[];
  readonly nextFrom: bigint;
  readonly done: boolean;
}

export interface EventStore {
  readForward<E>(from: bigint, batchSize: number): Promise<EventBatch<E>>;
}

export interface ReadStore {
  wipe(): Promise<void>;
  persist(view: StockView): Promise<void>;
}

export interface StockView {
  readonly totals: Readonly<Record<string, number>>;
}

export function project(view: StockView, event: FishStockEvent): StockView {
  switch (event.type) {
    case "FishStockSeeded": {
      const prev = view.totals[event.id] ?? 0;
      return { totals: { ...view.totals, [event.id]: prev + event.count } };
    }
    case "FishStockHarvested": {
      const prev = view.totals[event.id] ?? 0;
      return { totals: { ...view.totals, [event.id]: prev - event.count } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStore;
  read: ReadStore;
  onProgress?: (pos: bigint) => void;
}): Promise<void> {
  if (opts.from === 0n) await opts.read.wipe();
  let view: StockView = { totals: {} };
  let cursor = opts.from;
  let done = false;
  while (!done) {
    const batch = await opts.store.readForward<FishStockEvent>(cursor, opts.batchSize);
    for (const env of batch.events) {
      view = project(view, env.payload);
    }
    await opts.read.persist(view);
    cursor = batch.nextFrom;
    done = batch.done;
    opts.onProgress?.(cursor);
  }
}
