```typescript
export type PantryStockEvent =
  | { type: "PantryStocked"; ingredientId: string; grams: number }
  | { type: "PantryDrawn"; ingredientId: string; grams: number }
  | { type: "PantryWasted"; ingredientId: string; grams: number; reason: string }
  | { type: "PantryAudited"; auditedAt: string };

export interface PantryRow {
  readonly ingredientId: string;
  readonly grams: number;
}

export interface PantryStockView {
  readonly rows: Readonly<Record<string, PantryRow>>;
  readonly lastAuditAt: string | null;
}

export const emptyView: PantryStockView = { rows: {}, lastAuditAt: null };

function bump(view: PantryStockView, id: string, delta: number): PantryStockView {
  const existing = view.rows[id] ?? { ingredientId: id, grams: 0 };
  const next: PantryRow = { ingredientId: id, grams: existing.grams + delta };
  return { ...view, rows: { ...view.rows, [id]: next } };
}

export function project(view: PantryStockView, event: PantryStockEvent): PantryStockView {
  switch (event.type) {
    case "PantryStocked":
      return bump(view, event.ingredientId, event.grams);
    case "PantryDrawn":
      return bump(view, event.ingredientId, -event.grams);
    case "PantryWasted":
      return bump(view, event.ingredientId, -event.grams);
    case "PantryAudited":
      return { ...view, lastAuditAt: event.auditedAt };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function buildPantry(events: readonly PantryStockEvent[]): PantryStockView {
  return events.reduce<PantryStockView>(project, emptyView);
}

```

The when function is the aggregate's event-application rule. It's a pure (state, event) => state reducer that a typical load path feeds into Array.prototype.reduce.

```typescript
export type NetPenEvent =
  | { type: "NetPenInstalled"; id: string; capacity: number }
  | { type: "NetPenLoaded"; count: number }
  | { type: "NetPenRetired"; at: string };

export interface NetPenState {
  readonly status: "none" | "installed" | "retired";
  readonly id: string | null;
  readonly capacity: number;
  readonly loaded: number;
}

const initial: NetPenState = { status: "none", id: null, capacity: 0, loaded: 0 };

export function when(state: NetPenState, event: NetPenEvent): NetPenState {
  switch (event.type) {
    case "NetPenInstalled":
      return { status: "installed", id: event.id, capacity: event.capacity, loaded: 0 };
    case "NetPenLoaded":
      return state.status === "installed" ? { ...state, loaded: state.loaded + event.count } : state;
    case "NetPenRetired":
      return state.status === "installed" ? { ...state, status: "retired" } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: NetPenEvent[]): NetPenState {
  return events.reduce(when, initial);
}
```

