The handler is plumbing: it loads the current event stream, folds it into state, asks a pure `decide` for new events, and appends them. Keeping business rules inside `decide` makes them testable without I/O and means the handler can be reused across aggregates. Wrapping the I/O in `Effect.gen` composes well with retries, logging, and tracing layers.

```typescript
import { Effect } from "effect";

export type CommitState = { status: "none" } | { status: "recorded"; sha: string; author: string } | { status: "reverted"; sha: string };
export type CommitCommand =
  | { type: "record"; sha: string; author: string }
  | { type: "revert"; at: string };
export type CommitEvent =
  | { type: "CommitRecorded"; sha: string; author: string }
  | { type: "CommitReverted"; at: string };

export const initialState: CommitState = { status: "none" };

export function evolve(state: CommitState, event: CommitEvent): CommitState {
  switch (event.type) {
    case "CommitRecorded":
      return { status: "recorded", sha: event.sha, author: event.author };
    case "CommitReverted":
      if (state.status !== "recorded") return state;
      return { status: "reverted", sha: state.sha };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: CommitCommand, state: CommitState): CommitEvent[] {
  switch (command.type) {
    case "record":
      if (state.status !== "none") throw new Error("ALREADY_RECORDED");
      return [{ type: "CommitRecorded", sha: command.sha, author: command.author }];
    case "revert":
      if (state.status !== "recorded") throw new Error("NOT_RECORDED");
      return [{ type: "CommitReverted", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ events: CommitEvent[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: CommitEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export function handle(store: EventStore, streamName: string, command: CommitCommand): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const loaded = yield* Effect.promise(() => store.readStream(streamName));
    const state = loaded.events.reduce(evolve, initialState);
    const events = decide(command, state);
    yield* Effect.promise(() => store.appendToStream(streamName, events, { expectedRevision: loaded.revision }));
  });
}
```

Purity is what makes event sourcing trustworthy. If `when` had side effects or consulted a clock, replaying the same event stream twice would produce different states, which defeats the whole point of storing events as the source of truth. A pure `when(state, event)` guarantees that folding a stream is deterministic: given the same events in the same order, you always get the same state, and unit tests don't need any mocking.

