  | { type: "GreenhouseClimateSet"; temperatureC: number; humidity: number }
  | { type: "GreenhouseSealed" };

export const empty: Greenhouse = { id: "", status: "open", temperatureC: 20, humidity: 50 };

export function when(state: Greenhouse, event: GreenhouseEvent): Greenhouse {
  switch (event.type) {
    case "GreenhouseOpened":
      return { id: event.id, status: "open", temperatureC: 20, humidity: 50 };
    case "GreenhouseClimateSet":
