```typescript
export type AdSlotEvent =
  | { type: "AdSlotOpened"; slotId: string; floorCents: number }
  | { type: "AdSlotFilled"; slotId: string; advertiserId: string; bidCents: number }
  | { type: "AdSlotClosed"; slotId: string };

// Write side ----------------------------------------------------------------
interface WriteState {
  readonly status: "closed" | "open" | "filled";
  readonly slotId: string;
  readonly floorCents: number;
}

const initialWrite: WriteState = { status: "closed", slotId: "", floorCents: 0 };

function evolve(state: WriteState, event: AdSlotEvent): WriteState {
  switch (event.type) {
    case "AdSlotOpened":
      return { status: "open", slotId: event.slotId, floorCents: event.floorCents };
    case "AdSlotFilled":
      if (state.status !== "open") return state;
      return { status: "filled", slotId: state.slotId, floorCents: state.floorCents };
    case "AdSlotClosed":
      return { status: "closed", slotId: state.slotId, floorCents: state.floorCents };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export type AdSlotCommand = { type: "open"; slotId: string; floorCents: number } | { type: "close" };

function decide(cmd: AdSlotCommand, state: WriteState): AdSlotEvent[] {
  switch (cmd.type) {
    case "open":
      if (state.status !== "closed") throw new Error("NOT_CLOSED");
      return [{ type: "AdSlotOpened", slotId: cmd.slotId, floorCents: cmd.floorCents }];
    case "close":
      if (state.status === "closed") return [];
      return [{ type: "AdSlotClosed", slotId: state.slotId }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<{ revision: bigint; event: AdSlotEvent }>>;
  appendToStream(s: string, events: readonly AdSlotEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

// Read side (eventually consistent with the event store) --------------------
export interface AdSlotRow {
  readonly slotId: string;
  readonly status: "open" | "filled" | "closed";
  readonly advertiserId: string | null;
}

export interface ReadStore {
  get(slotId: string): Promise<AdSlotRow | null>;
}

export async function handleCommand(store: EventStore, stream: string, cmd: AdSlotCommand): Promise<void> {
  const stored = await store.readStream(stream);
  const state = stored.reduce<WriteState>((s, { event }) => evolve(s, event), initialWrite);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, decide(cmd, state), { expectedRevision: expected });
}

export async function queryView(readStore: ReadStore, slotId: string): Promise<AdSlotRow | null> {
  return readStore.get(slotId);
}
```

