```typescript
export type SoilReadingEvent = { type: "SoilReadingTaken"; fieldId: string; moisture: number; at: string };
export type SoilReadingCommand = { type: "takeReading"; fieldId: string; moisture: number; at: string };

type State = { readings: number };
const initialState: State = { readings: 0 };

function evolve(state: State, event: SoilReadingEvent): State {
  switch (event.type) {
    case "SoilReadingTaken":
      return { readings: state.readings + 1 };
    default: {
      const _n: never = event.type;
      return state;
    }
  }
}

export function decide(cmd: SoilReadingCommand, _state: State): SoilReadingEvent[] {
  if (cmd.moisture < 0 || cmd.moisture > 100) throw new Error("INVALID_MOISTURE");
  return [{ type: "SoilReadingTaken", fieldId: cmd.fieldId, moisture: cmd.moisture, at: cmd.at }];
}

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: SoilReadingEvent }>>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<SoilReadingEvent>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export interface CommandHandler<C> {
  handle(cmd: C, ctx: { streamName: string; store: EventStore }): Promise<void>;
}

export const soilReadingHandler: CommandHandler<SoilReadingCommand> = {
  async handle(cmd, ctx) {
    const stored = await ctx.store.readStream(ctx.streamName);
    const state = stored.reduce<State>((s, r) => evolve(s, r.event), initialState);
    const events = decide(cmd, state);
    const expected: bigint | "no_stream" =
      stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    await ctx.store.appendToStream(ctx.streamName, events, { expectedRevision: expected });
  },
};
