export type FoodInspectionState =
  | { status: "none" }
  | { status: "scheduled"; id: string; facility: string }
  | { status: "conducted"; id: string; facility: string; conductedAt: string }
  | { status: "reported"; id: string; facility: string; score: number; reportedAt: string }
  | { status: "closed"; id: string; closedAt: string };

export type FoodInspectionCommand =
  | { type: "schedule"; id: string; facility: string }
  | { type: "conduct"; at: string }
  | { type: "issueReport"; score: number; at: string }
  | { type: "close"; at: string };

export type FoodInspectionEvent =
  | { type: "FoodInspectionScheduled"; id: string; facility: string }
  | { type: "FoodInspectionConducted"; at: string }
  | { type: "FoodInspectionReported"; score: number; at: string }
  | { type: "FoodInspectionClosed"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const foodInspectionDecider: Decider<FoodInspectionCommand, FoodInspectionEvent, FoodInspectionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "FoodInspectionScheduled", id: command.id, facility: command.facility }];
      case "conduct":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "FoodInspectionConducted", at: command.at }];
      case "issueReport":
        if (state.status !== "conducted") throw new DomainError("NOT_CONDUCTED");
        if (command.score < 0 || command.score > 100) throw new DomainError("BAD_SCORE");
        return [{ type: "FoodInspectionReported", score: command.score, at: command.at }];
      case "close":
        if (state.status !== "reported") throw new DomainError("NOT_REPORTED");
        return [{ type: "FoodInspectionClosed", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FoodInspectionScheduled":
        return { status: "scheduled", id: event.id, facility: event.facility };
      case "FoodInspectionConducted":
        if (state.status !== "scheduled") return state;
        return { status: "conducted", id: state.id, facility: state.facility, conductedAt: event.at };
      case "FoodInspectionReported":
        if (state.status !== "conducted") return state;
        return { status: "reported", id: state.id, facility: state.facility, score: event.score, reportedAt: event.at };
      case "FoodInspectionClosed":
        if (state.status !== "reported") return state;
        return { status: "closed", id: state.id, closedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

