The parent wishlist machine spawns a `fromCallback` actor that owns the websocket / Firestore subscription for a shared wishlist. The actor sends `REMOTE_ADD` and `REMOTE_REMOVE` events back into the parent, which updates `context.shared`. The spawned actor's ref is stored typed as `ActorRefFrom` so teardown can call `stop` if needed.

```typescript
import { setup, assign, fromCallback, type ActorRefFrom } from 'xstate';

interface Item { id: string; title: string }

type SyncEv =
  | { type: 'REMOTE_ADD'; item: Item }
  | { type: 'REMOTE_REMOVE'; id: string };

const sharedSyncActor = fromCallback<{ type: 'PUBLISH'; item: Item }, { listId: string }>(
  ({ sendBack, input }) => {
    void input.listId;
    const t = setInterval(() => sendBack({ type: 'REMOTE_ADD', item: { id: 'x', title: 'Y' } }), 5000);
    return () => clearInterval(t);
  }
);

interface Ctx { shared: Item[]; syncRef: ActorRefFrom<typeof sharedSyncActor> | null }

type Ev = SyncEv | { type: 'OPEN'; listId: string };

export const sharedWishlistMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { sharedSyncActor }
}).createMachine({
  id: 'sharedWishlist',
  context: { shared: [], syncRef: null },
  initial: 'closed',
  states: {
    closed: {
      on: {
        OPEN: {
          target: 'open',
          actions: assign({
            syncRef: ({ spawn, event }) => spawn('sharedSyncActor', { input: { listId: event.listId } })
          })
        }
      }
    },
    open: {
      on: {
        REMOTE_ADD: { actions: assign({ shared: ({ context, event }) => [...context.shared, event.item] }) },
        REMOTE_REMOVE: {
          actions: assign({ shared: ({ context, event }) => context.shared.filter((i) => i.id !== event.id) })
        }
      }
    }
  }
});
```

Make the entry in `setup.delays` a function of `{ context }`. The state references it by name and the machine re-reads context each time it enters.

