export type ConsentPackageState =
  | { status: "none" }
  | { status: "draft"; id: string; subject: string }
  | { status: "signed"; id: string; subject: string; signedAt: string }
  | { status: "revoked"; id: string }
  | { status: "expired"; id: string };

export type ConsentPackageCommand =
  | { type: "draft"; id: string; subject: string }
  | { type: "sign"; at: string }
  | { type: "revoke"; at: string };

export type ConsentPackageEvent =
  | { type: "ConsentPackageDrafted"; id: string; subject: string }
  | { type: "ConsentPackageSigned"; at: string }
  | { type: "ConsentPackageRevoked"; at: string }
  | { type: "ConsentPackageExpired"; at: string };

const GRACE_MS = 30 * 24 * 60 * 60 * 1000;

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export function decide(command: ConsentPackageCommand, state: ConsentPackageState): ConsentPackageEvent[] {
  switch (command.type) {
    case "draft":
      if (state.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ConsentPackageDrafted", id: command.id, subject: command.subject }];
    case "sign":
      if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
      return [{ type: "ConsentPackageSigned", at: command.at }];
    case "revoke": {
      if (state.status !== "signed") throw new DomainError("NOT_SIGNED");
      const elapsed = Date.parse(command.at) - Date.parse(state.signedAt);
      if (Number.isFinite(elapsed) && elapsed > GRACE_MS) {
        return [{ type: "ConsentPackageExpired", at: command.at }];
      }
      return [{ type: "ConsentPackageRevoked", at: command.at }];
    }
    default: {
      const _n: never = command;
      throw new DomainError("UNKNOWN");
    }
  }
}
