Snapshots store the folded state plus a version tag. Between releases, the state shape evolves; rather than rewriting streams, we upgrade the snapshot on load by chaining per-version upgraders until the stored version matches CURRENT_VERSION.

```typescript
export type ConstituencyV4 = {
  id: string;
  code: string;
  boundary: string | null;
  stations: number;
  region: string;
  final: boolean;
};

export type Snapshot<S> = { version: number; state: S };
export const CURRENT_VERSION = 4;

type V1 = { id: string; name: string };
type V2 = { id: string; code: string };
type V3 = { id: string; code: string; boundary: string | null; stations: number };

function v1ToV2(s: V1): V2 {
  return { id: s.id, code: s.name.toUpperCase() };
}
function v2ToV3(s: V2): V3 {
  return { id: s.id, code: s.code, boundary: null, stations: 0 };
}
function v3ToV4(s: V3): ConstituencyV4 {
  return { ...s, region: "unknown", final: false };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<ConstituencyV4> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1ToV2(s as V1); v = 2; }
  if (v === 2) { s = v2ToV3(s as V2); v = 3; }
  if (v === 3) { s = v3ToV4(s as V3); v = 4; }
  if (v !== CURRENT_VERSION) throw new Error(`unknown version ${snap.version}`);
  return { version: CURRENT_VERSION, state: s as ConstituencyV4 };
}
