```typescript
export type PolicyEvent =
  | { type: "PolicyQuoted"; id: string; premium: number }
  | { type: "PolicyActivated"; id: string; at: string };

export type PolicyView = Readonly<{ active: number; drafted: number }>;

export const emptyView: PolicyView = { active: 0, drafted: 0 };

export function project(view: PolicyView, event: PolicyEvent): PolicyView {
  switch (event.type) {
    case "PolicyQuoted":
      return { ...view, drafted: view.drafted + 1 };
    case "PolicyActivated":
      return { ...view, active: view.active + 1, drafted: Math.max(0, view.drafted - 1) };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface EventBatch {
  events: readonly { revision: bigint; event: PolicyEvent }[];
  hasMore: boolean;
}

export interface EventStoreRange {
  read(from: bigint, batchSize: number): Promise<EventBatch>;
}

export interface ViewStore<V> {
  load(): Promise<V>;
  save(v: V): Promise<void>;
  saveCursor(rev: bigint): Promise<void>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStoreRange;
  views: ViewStore<PolicyView>;
}): Promise<void> {
  let cursor = opts.from;
  let view = cursor === 0n ? emptyView : await opts.views.load();
  while (true) {
    const batch = await opts.store.read(cursor, opts.batchSize);
    for (const rec of batch.events) {
      view = project(view, rec.event);
      cursor = rec.revision + 1n;
    }
    await opts.views.save(view);
    await opts.views.saveCursor(cursor);
    if (!batch.hasMore) return;
  }
}
```

Hierarchical routes map cleanly onto compound states: `settings` is a parent, `profile` and `billing` are children. The parent's `initial` acts as the default subroute, and relative targets keep navigation scoped. Typed events with a discriminated `to` payload make transitions exhaustive.

```typescript
import { setup, assign } from 'xstate';

type Path = 'home' | 'settings.profile' | 'settings.billing';
type Ctx = { path: Path };
type Ev = { type: 'NAVIGATE'; to: Path };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    setPath: assign({
      path: ({ event }) => event.to,
    }),
  },
}).createMachine({
  id: 'router',
  context: { path: 'home' },
  initial: 'home',
  states: {
    home: {
      on: {
        NAVIGATE: [
          { guard: ({ event }) => event.to === 'settings.profile', target: 'settings.profile', actions: 'setPath' },
          { guard: ({ event }) => event.to === 'settings.billing', target: 'settings.billing', actions: 'setPath' },
        ],
      },
    },
    settings: {
      initial: 'profile',
      on: { NAVIGATE: { guard: ({ event }) => event.to === 'home', target: 'home', actions: 'setPath' } },
      states: {
        profile: {},
        billing: {},
      },
    },
  },
});
