import { Effect } from 'effect';

type ShotEvent =
  | { type: 'ShotScheduled'; shotPoint: string }
  | { type: 'ShotFired'; at: string; charge: number }
  | { type: 'ShotCancelled'; reason: string };

type State =
  | { status: 'unscheduled' }
  | { status: 'scheduled'; shotPoint: string }
  | { status: 'fired' }
  | { status: 'cancelled' };

export function when(state: State, event: ShotEvent): State {
  switch (event.type) {
    case 'ShotScheduled':
      return { status: 'scheduled', shotPoint: event.shotPoint };
    case 'ShotFired':
      return { status: 'fired' };
    case 'ShotCancelled':
      return { status: 'cancelled' };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (s: S, e: E) => S,
  initial: S,
) {
  return Effect.tryPromise({
    try: async () => {
      let state = initial;
      for await (const event of stream) state = fold(state, event);
      return state;
    },
    catch: (e) => new Error(String(e)),
  });
}

export function load(stream: AsyncIterable<ShotEvent>) {
  return aggregateStream<State, ShotEvent>(stream, when, { status: 'unscheduled' });
}
