export type SpecimenKitState =
  | { status: "none" }
  | { status: "assembled"; id: string; items: number }
  | { status: "sealed"; id: string; items: number };

export type SpecimenKitCommand =
  | { type: "assemble"; id: string }
  | { type: "addPart" }
  | { type: "seal" };

export type SpecimenKitEvent =
  | { type: "SpecimenKitAssembled"; id: string }
  | { type: "SpecimenKitPartLogged" }
  | { type: "SpecimenKitSealed" };

const initial: SpecimenKitState = { status: "none" };

function evolve(state: SpecimenKitState, event: SpecimenKitEvent): SpecimenKitState {
  switch (event.type) {
    case "SpecimenKitAssembled":
      return { status: "assembled", id: event.id, items: 0 };
    case "SpecimenKitPartLogged":
      return state.status === "assembled" ? { ...state, items: state.items + 1 } : state;
    case "SpecimenKitSealed":
      return state.status === "assembled" ? { status: "sealed", id: state.id, items: state.items } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(command: SpecimenKitCommand, state: SpecimenKitState): SpecimenKitEvent[] {
  switch (command.type) {
    case "assemble":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "SpecimenKitAssembled", id: command.id }];
    case "addPart":
      if (state.status !== "assembled") throw new Error("NOT_ASSEMBLED");
      return [{ type: "SpecimenKitPartLogged" }];
    case "seal":
      if (state.status !== "assembled" || state.items === 0) throw new Error("CANT_SEAL");
      return [{ type: "SpecimenKitSealed" }];
    default: {
      const _n: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handle(
  command: SpecimenKitCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const read = await ctx.eventStore.readStream<SpecimenKitEvent>(ctx.streamName);
  const state = read.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: read.revision });
}
