```typescript
export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
  validate?: (state: S) => boolean,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  if (validate && !validate(state)) {
    throw new Error('aggregate invariant violated');
  }
  return state;
}

type ChannelEvent =
  | { type: 'ChannelCreated'; id: string; name: string }
  | { type: 'ChannelJoined'; userId: string }
  | { type: 'ChannelLeft'; userId: string };

type ChannelState = Readonly<{
  id: string | null;
  name: string;
  members: readonly string[];
}>;

const initial: ChannelState = { id: null, name: '', members: [] };

function evolve(state: ChannelState, event: ChannelEvent): ChannelState {
  switch (event.type) {
    case 'ChannelCreated':
      return { id: event.id, name: event.name, members: [] };
    case 'ChannelJoined':
      return { ...state, members: [...state.members, event.userId] };
    case 'ChannelLeft':
      return { ...state, members: state.members.filter((m) => m !== event.userId) };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function loadChannel(stream: AsyncIterable<ChannelEvent>): Promise<ChannelState> {
  return aggregateStream<ChannelState, ChannelEvent>(stream, evolve, initial, (s) => s.id !== null);
}
