```typescript
export interface AppendOptions {
  expectedRevision: bigint | "no_stream" | "any";
}

export interface EventRecord<E> {
  event: E;
  revision: bigint;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<EventRecord<E>[]>;
  appendToStream<E>(
    stream: string,
    events: E[],
    options: AppendOptions,
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: AppendOptions["expectedRevision"]) {
    super("CONCURRENCY_CONFLICT");
    this.name = "ConcurrencyConflict";
  }
}

export type SignificanceCheckEvent =
  | { type: "SignificanceCheckStarted"; id: string; alpha: number }
  | { type: "SignificanceCheckCompleted"; pValue: number };

export async function writeSignificanceCheck(
  store: EventStore,
  stream: string,
  toAppend: SignificanceCheckEvent[],
): Promise<bigint> {
  const current = await store.readStream<SignificanceCheckEvent>(stream);
  const expectedRevision: AppendOptions["expectedRevision"] =
    current.length === 0 ? "no_stream" : current[current.length - 1].revision;
  try {
    const { nextRevision } = await store.appendToStream<SignificanceCheckEvent>(
      stream,
      toAppend,
      { expectedRevision },
    );
    return nextRevision;
  } catch (err) {
    if (err instanceof Error && /WrongExpectedVersion|revision_mismatch/i.test(err.message)) {
      throw new ConcurrencyConflict(stream, expectedRevision);
    }
    throw err;
  }
}
