export interface BatchEvent { type: string; position: bigint; }

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventStore {
  readFromStream(stream: string, from: bigint): AsyncIterable<BatchEvent>;
}

export interface BatchView { seen: number; }

export function project(view: BatchView, _event: BatchEvent): BatchView {
  return { seen: view.seen + 1 };
}

export async function runSubscription(ctx: {
  name: string;
  stream: string;
  store: EventStore;
  checkpoints: CheckpointStore;
  persist: (v: BatchView) => Promise<void>;
}): Promise<void> {
  const start = (await ctx.checkpoints.read(ctx.name)) ?? 0n;
  let view: BatchView = { seen: 0 };
  for await (const event of ctx.store.readFromStream(ctx.stream, start)) {
    view = project(view, event);
    await ctx.persist(view);
    await ctx.checkpoints.write(ctx.name, event.position);
  }
}
```

Store a versioned Snapshot envelope. On load, chain upgraders keyed by source version until the snapshot reaches the current shape.

```typescript
export interface PullRequestV1 {
  readonly id: string;
  readonly branch: string;
  readonly status: "open" | "merged" | "closed";
}

export interface PullRequestV2 extends PullRequestV1 {
  readonly approvals: number;
}

export type CurrentPullRequest = PullRequestV2;
export const CURRENT_VERSION = 2;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(state: PullRequestV1): PullRequestV2 {
  return { ...state, approvals: 0 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentPullRequest> {
  if (snap.version === CURRENT_VERSION) {
    return { version: CURRENT_VERSION, state: snap.state as CurrentPullRequest };
  }
  if (snap.version === 1) {
    const migrated = v1Tov2(snap.state as PullRequestV1);
    return { version: CURRENT_VERSION, state: migrated };
  }
  throw new Error(`unknown snapshot version ${snap.version}`);
}

export function loadPullRequest(snap: Snapshot<unknown>): CurrentPullRequest {
  return upgradeSnapshot(snap).state;
}
