```typescript
export type MatchEvent =
  | { type: "MatchFullTime"; home: string; away: string; homeGoals: number; awayGoals: number }
  | { type: "MatchKickedOff"; id: string };

export interface StandingsRow {
  club: string;
  played: number;
  points: number;
}

export type StandingsView = Record<string, StandingsRow>;

export function project(view: StandingsView, e: MatchEvent): StandingsView {
  switch (e.type) {
    case "MatchKickedOff":
      return view;
    case "MatchFullTime": {
      const h = view[e.home] ?? { club: e.home, played: 0, points: 0 };
      const a = view[e.away] ?? { club: e.away, played: 0, points: 0 };
      const hw = e.homeGoals > e.awayGoals, draw = e.homeGoals === e.awayGoals;
      return {
        ...view,
        [e.home]: { ...h, played: h.played + 1, points: h.points + (hw ? 3 : draw ? 1 : 0) },
        [e.away]: { ...a, played: a.played + 1, points: a.points + (!hw && !draw ? 3 : draw ? 1 : 0) },
      };
    }
    default: { const _n: never = e; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface ReadModelStore {
  load(): Promise<StandingsView>;
  save(view: StandingsView): Promise<void>;
}

export interface StreamSource {
  iterate(from: bigint): AsyncIterable<{ position: bigint; event: MatchEvent }>;
}

export async function runSubscription(
  name: string,
  source: StreamSource,
  checkpoints: CheckpointStore,
  readModel: ReadModelStore,
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? 0n;
  let view = await readModel.load();
  async function run() {
    for await (const { position, event } of source.iterate(start)) {
      view = project(view, event);
      await readModel.save(view);
      await checkpoints.write(name, position);
    }
  }
  await run();
}
```

Upcasting runs at read time, converting raw stored events into the current shape before the aggregate ever sees them. The stream itself is never rewritten.

```typescript
export type RawIssuedV1 = {
  type: "InvoiceIssued";
  version: 1;
  issuedBy: string;
  at: string;
};

export type RawEvent =
  | RawIssuedV1
  | { type: "InvoiceIssued"; version: 2; issuer: { id: string; name: string }; at: string }
  | { type: "InvoiceDrafted"; version: 1; id: string; amount: number };

export type CurrentEvent =
  | { type: "InvoiceIssued"; version: 2; issuer: { id: string; name: string }; at: string }
  | { type: "InvoiceDrafted"; version: 1; id: string; amount: number };

export class UnknownEventError extends Error {}

function assertRaw(raw: unknown): asserts raw is RawEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError("NOT_OBJECT");
}

export function upcast(raw: unknown): CurrentEvent {
  assertRaw(raw);
  switch (raw.type) {
    case "InvoiceIssued":
      if (raw.version === 1) {
        return {
          type: "InvoiceIssued",
          version: 2,
          issuer: { id: raw.issuedBy, name: raw.issuedBy },
          at: raw.at,
        };
      }
      return raw;
    case "InvoiceDrafted":
      return raw;
    default: {
      const _n: never = raw;
      throw new UnknownEventError("UNKNOWN_TYPE");
    }
  }
}

export type InvoiceView = Readonly<{ id: string; amount: number; issuerName: string | null }>;

export const emptyView: InvoiceView = { id: "", amount: 0, issuerName: null };

export function project(view: InvoiceView, event: CurrentEvent): InvoiceView {
  switch (event.type) {
    case "InvoiceDrafted":
      return { ...emptyView, id: event.id, amount: event.amount };
    case "InvoiceIssued":
      return { ...view, issuerName: event.issuer.name };
    default: { const _n: never = event; return view; }
  }
}

export function invoiceViewFrom(rawEvents: unknown[]): InvoiceView {
  return rawEvents.map(upcast).reduce(project, emptyView);
}
```

```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

```typescript
export type ShiftState =
  | { status: "none" }
  | { status: "open"; stationId: string; supervisor: string; openedAt: string }
  | { status: "closed"; stationId: string; closedAt: string };

export type ShiftEvent =
  | { type: "ShiftOpened"; stationId: string; supervisor: string; at: string }
  | { type: "ShiftClosed"; at: string };

export function when(state: ShiftState, event: ShiftEvent): ShiftState {
  switch (event.type) {
    case "ShiftOpened":
      return { status: "open", stationId: event.stationId, supervisor: event.supervisor, openedAt: event.at };
    case "ShiftClosed":
      if (state.status !== "open") return state;
      return { status: "closed", stationId: state.stationId, closedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: S, e: E) => S,
  initial: S
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = reducer(state, event);
  }
  return state;
}
