Replaying millions of events on every boot is expensive, so we persist periodic snapshots. But the aggregate shape drifts over time. A versioned snapshot carries the version it was written at; on load, upgraders compose `v1 -> v2 -> ... -> current` so the in-memory state always matches the code. The event log is untouched.

```typescript
interface PickListV1 {
  id: string;
  picker: string;
  items: ReadonlyArray<string>;
}

interface PickListV2 {
  id: string;
  picker: string;
  items: ReadonlyArray<{ sku: string; qty: number }>;
}

interface PickListV3 {
  id: string;
  picker: string;
  wave: string;
  items: ReadonlyArray<{ sku: string; qty: number }>;
}

export type CurrentPickList = PickListV3;
export const CURRENT_VERSION = 3 as const;

export interface Snapshot<S> { readonly version: number; readonly state: S; }

function v1Tov2(prev: PickListV1): PickListV2 {
  return { id: prev.id, picker: prev.picker, items: prev.items.map((sku) => ({ sku, qty: 1 })) };
}
function v2Tov3(prev: PickListV2): PickListV3 {
  return { ...prev, wave: "LEGACY" };
}

function assertCurrent(value: unknown): asserts value is CurrentPickList {
  const v = value as Partial<CurrentPickList>;
  if (typeof v?.id !== "string" || typeof v?.picker !== "string" || typeof v?.wave !== "string" || !Array.isArray(v?.items)) {
    throw new Error("Not a CurrentPickList");
  }
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentPickList> {
  let state: unknown = snap.state;
  let version = snap.version;
  if (version === 1) { state = v1Tov2(state as PickListV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as PickListV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`Unknown version ${version}`);
  assertCurrent(state);
  return { version: CURRENT_VERSION, state };
}
