import { setup, assign, fromPromise } from 'xstate';

type Ctx = { url: string; attempt: number; bytes: number; error: string | null };
type Ev = { type: 'START'; url: string } | { type: 'RETRY' };

const download = fromPromise<number, { url: string }>(async ({ input }) => {
  const r = await fetch(input.url);
  if (!r.ok) throw new Error('HTTP ' + r.status);
  const buf = await r.arrayBuffer();
  return buf.byteLength;
});

export const dlManager = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { download },
  guards: { canRetry: ({ context }) => context.attempt < 2 },
  delays: { backoff: ({ context }) => 500 * 2 ** context.attempt }
}).createMachine({
  id: 'dlManager',
  initial: 'idle',
  context: { url: '', attempt: 0, bytes: 0, error: null },
  states: {
    idle: {
      on: {
        START: {
          target: 'fetching',
          actions: assign({ url: ({ event }) => event.url, attempt: () => 0, error: () => null })
        }
      }
    },
    fetching: {
      invoke: {
        src: 'download',
        input: ({ context }) => ({ url: context.url }),
        onDone: {
          target: 'success',
          actions: assign({ bytes: ({ event }) => event.output })
        },
        onError: [
          {
            target: 'waiting',
            guard: 'canRetry',
            actions: assign({
              attempt: ({ context }) => context.attempt + 1,
              error: ({ event }) => (event.error instanceof Error ? event.error.message : 'err')
            })
          },
          {
            target: 'failure',
            actions: assign({
              error: ({ event }) => (event.error instanceof Error ? event.error.message : 'err')
            })
          }
        ]
      }
    },
    waiting: { after: { backoff: { target: 'fetching' } } },
    success: { type: 'final' },
    failure: { on: { RETRY: { target: 'fetching', actions: assign({ attempt: () => 0 }) } } }
  }
});
