export type ArtefactCommand = { type: "publish"; id: string; sha256: string } | { type: "retract"; id: string; reason: string };
export type ArtefactEvent =
  | { type: "ArtefactPublished"; id: string; sha256: string }
  | { type: "ArtefactRetracted"; id: string; reason: string };

export type ArtefactWriteState =
  | { status: "none" }
  | { status: "published"; id: string; sha256: string }
  | { status: "retracted"; id: string; reason: string };

export const initialState: ArtefactWriteState = { status: "none" };

export function evolve(state: ArtefactWriteState, event: ArtefactEvent): ArtefactWriteState {
  switch (event.type) {
    case "ArtefactPublished":
      return { status: "published", id: event.id, sha256: event.sha256 };
    case "ArtefactRetracted":
      if (state.status !== "published") return state;
      return { status: "retracted", id: state.id, reason: event.reason };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: ArtefactCommand, state: ArtefactWriteState): ArtefactEvent[] {
  switch (command.type) {
    case "publish":
      if (state.status !== "none") throw new Error("ALREADY_PUBLISHED");
      return [{ type: "ArtefactPublished", id: command.id, sha256: command.sha256 }];
    case "retract":
      if (state.status !== "published") throw new Error("NOT_PUBLISHED");
      return [{ type: "ArtefactRetracted", id: command.id, reason: command.reason }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ events: ArtefactEvent[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: ArtefactEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface ArtefactReadRow {
  readonly id: string;
  readonly sha256: string;
  readonly retractedReason: string | null;
}

export interface ReadStore {
  find(id: string): Promise<ArtefactReadRow | null>;
}

// Read model is eventually consistent via a separate projection runner.
export async function handleCommand(store: EventStore, streamName: string, command: ArtefactCommand): Promise<void> {
  const loaded = await store.readStream(streamName);
  const state = loaded.events.reduce(evolve, initialState);
  const events = decide(command, state);
  await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
}

export async function queryView(reads: ReadStore, id: string): Promise<ArtefactReadRow | null> {
  return reads.find(id);
}
