export type ToolingRequestState =
  | { status: "none" }
  | { status: "submitted"; id: string; tool: string }
  | { status: "approved"; id: string; tool: string; approvedBy: string }
  | { status: "fulfilled"; id: string; tool: string; at: string }
  | { status: "rejected"; id: string; reason: string };

export type ToolingRequestCommand =
  | { type: "submit"; id: string; tool: string }
  | { type: "approve"; by: string }
  | { type: "fulfill"; at: string }
  | { type: "reject"; reason: string };

export type ToolingRequestEvent =
  | { type: "RequestSubmitted"; id: string; tool: string }
  | { type: "RequestApproved"; by: string }
  | { type: "RequestFulfilled"; at: string }
  | { type: "RequestRejected"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const toolingRequestDecider: Decider<ToolingRequestCommand, ToolingRequestEvent, ToolingRequestState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "submit":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "RequestSubmitted", id: c.id, tool: c.tool }];
      case "approve":
        if (s.status !== "submitted") throw new DomainError("NOT_SUBMITTED");
        return [{ type: "RequestApproved", by: c.by }];
      case "fulfill":
        if (s.status === "rejected") throw new DomainError("REJECTED");
        if (s.status !== "approved") throw new DomainError("NOT_APPROVED");
        return [{ type: "RequestFulfilled", at: c.at }];
      case "reject":
        if (s.status === "fulfilled") throw new DomainError("FULFILLED");
        return [{ type: "RequestRejected", reason: c.reason }];
      default: {
        const _n: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "RequestSubmitted":
        return { status: "submitted", id: e.id, tool: e.tool };
      case "RequestApproved":
        if (s.status !== "submitted") return s;
        return { status: "approved", id: s.id, tool: s.tool, approvedBy: e.by };
      case "RequestFulfilled":
        if (s.status !== "approved") return s;
        return { status: "fulfilled", id: s.id, tool: s.tool, at: e.at };
      case "RequestRejected":
        return { status: "rejected", id: "id" in s ? s.id : "", reason: e.reason };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
