export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; count: number }
  | { type: "FishStockHarvested"; id: string; count: number };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventEnvelope<E> {
  readonly position: bigint;
  readonly event: E;
