  name: string,
  source: EventSource,
  checkpoints: CheckpointStore,
  apply: (event: FishStockEvent) => Promise<void>,
): Promise<void> {
  const last = await checkpoints.read(name);
  const iter = source.subscribe(last);
  for await (const envelope of iter) {
    await apply(envelope.event);
    await checkpoints.write(name, envelope.position);
  }
}
