The prior implementation fell through to an implicit return and did not guard the cancelled state. Below is the corrected typed Decider pair.

```typescript
export type ReferenceRequestState =
  | { status: "open"; id: string; topic: string }
  | { status: "answered"; id: string; answeredOn: string }
  | { status: "cancelled"; id: string; reason: string };

export type ReferenceRequestCommand =
  | { type: "open"; id: string; topic: string }
  | { type: "answer"; on: string }
  | { type: "cancel"; reason: string };

export type ReferenceRequestEvent =
  | { type: "Opened"; id: string; topic: string }
  | { type: "Answered"; on: string }
  | { type: "Cancelled"; reason: string };

export class DomainError extends Error {}

export function decide(command: ReferenceRequestCommand, state: ReferenceRequestState): ReferenceRequestEvent[] {
  switch (command.type) {
    case "open":
      return [{ type: "Opened", id: command.id, topic: command.topic }];
    case "answer":
      if (state.status === "cancelled") throw new DomainError("request cancelled");
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "Answered", on: command.on }];
    case "cancel":
      if (state.status !== "open") throw new DomainError("cannot cancel");
      return [{ type: "Cancelled", reason: command.reason }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: ReferenceRequestState, event: ReferenceRequestEvent): ReferenceRequestState {
  switch (event.type) {
    case "Opened":
      return { status: "open", id: event.id, topic: event.topic };
    case "Answered":
      return state.status === "open" ? { status: "answered", id: state.id, answeredOn: event.on } : state;
    case "Cancelled":
      return state.status === "open" ? { status: "cancelled", id: state.id, reason: event.reason } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}
