```typescript
import { setup, assign, fromPromise } from 'xstate';

interface UrlJob { url: string; attempts: number }

interface Ctx {
  queue: UrlJob[];
  failed: UrlJob[];
  maxAttempts: number;
}

type Ev = { type: 'ENQUEUE'; url: string };

const fetchUrl = fromPromise<string, { url: string }>(async ({ input }) => {
  if (input.url.startsWith('bad')) throw new Error('bad');
  return input.url;
});

export const retryingQueueMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { fetchUrl },
  guards: {
    hasJob: ({ context }) => context.queue.length > 0,
    canRetry: ({ context }) => {
      const head = context.queue[0];
      return head !== undefined && head.attempts + 1 < context.maxAttempts;
    }
  },
  actions: {
    enqueue: assign({
      queue: ({ context, event }) => [
        ...context.queue,
        { url: event.url, attempts: 0 }
      ]
    }),
    shift: assign({ queue: ({ context }) => context.queue.slice(1) }),
    bumpAttempt: assign({
      queue: ({ context }) => {
        const [head, ...rest] = context.queue;
        if (!head) return context.queue;
        return [{ url: head.url, attempts: head.attempts + 1 }, ...rest];
      }
    }),
    moveToFailed: assign({
      failed: ({ context }) => {
        const head = context.queue[0];
        return head ? [...context.failed, head] : context.failed;
      },
      queue: ({ context }) => context.queue.slice(1)
    })
  }
}).createMachine({
  id: 'retryQueue',
  context: { queue: [], failed: [], maxAttempts: 3 },
  initial: 'idle',
  states: {
    idle: {
      always: [{ guard: 'hasJob', target: 'working' }],
      on: { ENQUEUE: { actions: 'enqueue' } }
    },
    working: {
      invoke: {
        src: 'fetchUrl',
        input: ({ context }) => ({ url: context.queue[0]?.url ?? '' }),
        onDone: { target: 'idle', actions: 'shift' },
        onError: [
          { guard: 'canRetry', target: 'idle', actions: 'bumpAttempt' },
          { target: 'idle', actions: 'moveToFailed' }
        ]
      },
      on: { ENQUEUE: { actions: 'enqueue' } }
    }
  }
});
