```typescript
export type VendorEvent =
  | { type: "VendorApproved"; at: string }
  | { type: "VendorSuspended"; reason: string };

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    stream: string,
    events: readonly E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {}

async function currentRevision<E>(
  store: EventStore<E>,
  stream: string,
): Promise<bigint | "no_stream"> {
  let rev: bigint | "no_stream" = "no_stream";
  for await (const rec of store.readStream(stream)) rev = rec.revision;
  return rev;
}

export async function appendWithRetry(
  store: EventStore<VendorEvent>,
  stream: string,
  events: readonly VendorEvent[],
  maxAttempts = 3,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    const expected = await currentRevision(store, stream);
    try {
      const res = await store.appendToStream(stream, events, { expectedRevision: expected });
      return res.nextExpectedRevision;
    } catch (err) {
      attempt += 1;
      if (attempt >= maxAttempts) {
        throw new ConcurrencyConflict(
          `stream=${stream} attempts=${attempt} cause=${(err as Error).message}`,
        );
      }
    }
  }
  throw new ConcurrencyConflict(stream);
}
```

