Each snapshot is tagged `{ version, state }`. On load, you run upgraders in order from the stored version up to `CURRENT_VERSION`, each producing a new value. The final shape is type-asserted; a stored version with no upgrader path throws.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type FleetVehicleV1 = { id: string; plate: string };
export type FleetVehicleV2 = { id: string; plate: string; model: string };
export type FleetVehicleV3 = {
  id: string;
  plate: string;
  model: string;
  status: "idle" | "assigned" | "retired";
};

export type CurrentFleetVehicle = FleetVehicleV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: FleetVehicleV1): FleetVehicleV2 {
  return { ...s, model: "unknown" };
}

function v2Tov3(s: FleetVehicleV2): FleetVehicleV3 {
  return { ...s, status: "idle" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentFleetVehicle> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as FleetVehicleV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as FleetVehicleV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED_VERSION");
  const out = s as CurrentFleetVehicle;
  if (!out.id || !out.plate || !out.model || !out.status) throw new UpgradeError("SHAPE");
  return { version: v, state: out };
}
