export type BranchDomainEvent =
  | { type: "Planned"; id: string; code: string }
  | { type: "Opened"; id: string; on: string }
  | { type: "HolidayMarked"; id: string }
  | { type: "Closed"; id: string; on: string };

export type IntegrationEvent =
  | { schema: "library.branch.opened.v1"; payload: { id: string; code: string; on: string } }
  | { schema: "library.branch.closed.v1"; payload: { id: string; on: string } };

const branchCodes = new Map<string, string>();

export function translate(domainEvent: BranchDomainEvent): IntegrationEvent | null {
  switch (domainEvent.type) {
    case "Planned":
      branchCodes.set(domainEvent.id, domainEvent.code);
      return null;
    case "Opened":
      return {
        schema: "library.branch.opened.v1",
        payload: { id: domainEvent.id, code: branchCodes.get(domainEvent.id) ?? "", on: domainEvent.on },
      };
    case "HolidayMarked":
      return null;
    case "Closed":
      return { schema: "library.branch.closed.v1", payload: { id: domainEvent.id, on: domainEvent.on } };
    default: {
      const _: never = domainEvent;
      return _;
    }
  }
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: BranchDomainEvent }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<IntegrationEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export async function publishIntegration(
  store: EventStore,
  sourceStream: string,
  outboxStream: string,
): Promise<void> {
  const integration: IntegrationEvent[] = [];
  for await (const { event } of store.readStream(sourceStream)) {
    const mapped = translate(event);
    if (mapped !== null) integration.push(mapped);
  }
  if (integration.length > 0) {
    await store.appendToStream(outboxStream, integration, { expectedRevision: "any" });
  }
}
