```typescript
import { Effect } from "effect";

export type FineEvent =
  | { type: "FineIssued"; amount: number }
  | { type: "FinePaid"; amount: number }
  | { type: "FineWaived" };

export type FineState = { balance: number; closed: boolean };
export const initial: FineState = { balance: 0, closed: false };

export function when(state: FineState, event: FineEvent): FineState {
  switch (event.type) {
    case "FineIssued":
      return { balance: state.balance + event.amount, closed: false };
    case "FinePaid": {
      const next = state.balance - event.amount;
      return { balance: Math.max(0, next), closed: next <= 0 };
    }
    case "FineWaived":
      return { balance: 0, closed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (state: S, event: E) => S,
  initialState: S,
) {
  return Effect.gen(function* () {
    const state = yield* Effect.promise(async () => {
      let acc = initialState;
      for await (const event of stream) {
        acc = fold(acc, event);
      }
      return acc;
    });
    return state;
  });
}

export function loadFine(stream: AsyncIterable<FineEvent>) {
  return aggregateStream<FineState, FineEvent>(stream, when, initial);
}
```

```typescript
export type MatchEvent =
  | { type: "MatchScheduled"; id: string; home: string; away: string }
  | { type: "MatchKickedOff" }
  | { type: "MatchFullTime"; homeGoals: number; awayGoals: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> {
  revision: bigint;
  event: E;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream<E>(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: ExpectedRevision) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export interface StoreRejection {
  kind: "concurrency";
}

export async function appendMatchEvents(
  store: EventStore,
  stream: string,
  newEvents: readonly MatchEvent[],
): Promise<bigint> {
  const stored = await store.readStream<MatchEvent>(stream);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  try {
    const result = await store.appendToStream<MatchEvent>(stream, newEvents, { expectedRevision: expected });
    return result.nextRevision;
  } catch (err) {
    const rejection = err as Partial<StoreRejection>;
    if (rejection.kind === "concurrency") throw new ConcurrencyConflict(stream, expected);
    throw err;
  }
}
