export type CohortRegisterEvent =
  | { type: "CohortRegisterCreated"; id: string }
  | { type: "CohortRegisterMemberAdded"; id: string }
  | { type: "CohortRegisterLocked"; id: string };

export type CohortRegisterView = { id: string; members: number; locked: boolean };
const empty: CohortRegisterView = { id: "", members: 0, locked: false };

function project(view: CohortRegisterView, event: CohortRegisterEvent): CohortRegisterView {
  switch (event.type) {
    case "CohortRegisterCreated":
      return { id: event.id, members: 0, locked: false };
    case "CohortRegisterMemberAdded":
      return { ...view, members: view.members + 1 };
    case "CohortRegisterLocked":
      return { ...view, locked: true };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface BatchReader<E> {
  readBatch(from: bigint, size: number): Promise<{ events: E[]; nextFrom: bigint | null }>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  reader: BatchReader<CohortRegisterEvent>;
  persist: (view: CohortRegisterView, cursor: bigint) => Promise<void>;
}): Promise<void> {
  let cursor = opts.from;
  let view = empty;
  let done = false;
  while (!done) {
    const { events, nextFrom } = await opts.reader.readBatch(cursor, opts.batchSize);
    for (const event of events) {
      view = project(view, event);
    }
    cursor = nextFrom ?? cursor;
    await opts.persist(view, cursor);
    if (nextFrom === null) done = true;
  }
}
