```typescript
export type BuildRunEvent =
  | { type: "BuildRunStarted"; commit: string; runId: string; at: string }
  | { type: "BuildRunFinished"; runId: string; commit: string; at: string; artefactId: string }
  | { type: "BuildRunFailed"; runId: string; commit: string; at: string; reason: string };

export interface CommitStats {
  readonly total: number;
  readonly succeeded: number;
  readonly failed: number;
}

export interface BuildStatsView {
  readonly perCommit: Record<string, CommitStats>;
}

export const emptyView: BuildStatsView = { perCommit: {} };

function bump(view: BuildStatsView, commit: string, patch: Partial<CommitStats>): BuildStatsView {
  const existing = view.perCommit[commit] ?? { total: 0, succeeded: 0, failed: 0 };
  const next: CommitStats = {
    total: existing.total + (patch.total ?? 0),
    succeeded: existing.succeeded + (patch.succeeded ?? 0),
    failed: existing.failed + (patch.failed ?? 0),
  };
  return { perCommit: { ...view.perCommit, [commit]: next } };
}

export function project(view: BuildStatsView, event: BuildRunEvent): BuildStatsView {
  switch (event.type) {
    case "BuildRunStarted":
      return bump(view, event.commit, { total: 1 });
    case "BuildRunFinished":
      return bump(view, event.commit, { succeeded: 1 });
    case "BuildRunFailed":
      return bump(view, event.commit, { failed: 1 });
    default: {
      const _never: never = event;
      return view;
    }
  }
}
