export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state: S = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export type AnalysisPipelineState =
  | { status: "none" }
  | { status: "configured"; id: string; stages: string[] }
  | { status: "running"; id: string; stages: string[]; cursor: number }
  | { status: "completed"; id: string };

export type AnalysisPipelineEvent =
  | { type: "AnalysisPipelineConfigured"; id: string; stages: string[] }
  | { type: "AnalysisPipelineStarted" }
  | { type: "AnalysisPipelineStageAdvanced" }
  | { type: "AnalysisPipelineCompleted" };

const empty: AnalysisPipelineState = { status: "none" };

function when(state: AnalysisPipelineState, event: AnalysisPipelineEvent): AnalysisPipelineState {
  switch (event.type) {
    case "AnalysisPipelineConfigured":
      return { status: "configured", id: event.id, stages: event.stages };
    case "AnalysisPipelineStarted":
      return state.status === "configured" ? { status: "running", id: state.id, stages: state.stages, cursor: 0 } : state;
    case "AnalysisPipelineStageAdvanced":
      return state.status === "running" ? { ...state, cursor: state.cursor + 1 } : state;
    case "AnalysisPipelineCompleted":
      return state.status === "running" ? { status: "completed", id: state.id } : state;
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function loadPipeline(stream: AsyncIterable<AnalysisPipelineEvent>): Promise<AnalysisPipelineState> {
  return aggregateStream(stream, when, empty);
}
