Model the thread as a discriminated-union state driven by commands that emit events. `decide` checks invariants (no posting to a closed thread); `evolve` folds each event into the next state.

```typescript
export type DiscussionState =
  | { status: "none" }
  | { status: "open"; id: string; posts: number }
  | { status: "archived"; id: string; posts: number };

export type DiscussionCommand =
  | { type: "open"; id: string; topic: string }
  | { type: "post"; author: string; body: string }
  | { type: "archive"; reason: string };

export type DiscussionEvent =
  | { type: "DiscussionOpened"; id: string; topic: string }
  | { type: "PostAppended"; author: string; body: string }
  | { type: "DiscussionArchived"; reason: string };

export class DiscussionError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const discussionDecider: Decider<DiscussionCommand, DiscussionEvent, DiscussionState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "none") throw new DiscussionError("ALREADY_OPEN");
        return [{ type: "DiscussionOpened", id: c.id, topic: c.topic }];
      case "post":
        if (s.status !== "open") throw new DiscussionError("NOT_OPEN");
        if (c.body.length === 0) throw new DiscussionError("EMPTY_BODY");
        return [{ type: "PostAppended", author: c.author, body: c.body }];
      case "archive":
        if (s.status !== "open") throw new DiscussionError("NOT_OPEN");
        return [{ type: "DiscussionArchived", reason: c.reason }];
      default: { const _n: never = c; throw new DiscussionError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "DiscussionOpened":
        return { status: "open", id: e.id, posts: 0 };
      case "PostAppended":
        if (s.status !== "open") return s;
        return { status: "open", id: s.id, posts: s.posts + 1 };
      case "DiscussionArchived":
        if (s.status !== "open") return s;
        return { status: "archived", id: s.id, posts: s.posts };
      default: { const _n: never = e; return s; }
    }
  },
};
