  | { type: "start"; id: string; orderId: string }
  | { type: "scan-item"; sku: string }
  | { type: "seal"; at: string };

export type PackingEvent =
  | { type: "PackingStarted"; id: string; orderId: string }
  | { type: "PackingItemScanned"; sku: string }
  | { type: "PackingSealed"; at: string };

export class PackingError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const packingDecider: Decider<PackingCommand, PackingEvent, PackingState> = {
  initialState: { status: "idle" },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "idle") throw new PackingError("IN_PROGRESS");
        return [{ type: "PackingStarted", id: c.id, orderId: c.orderId }];
      case "scan-item":
        if (s.status !== "packing") throw new PackingError("NOT_PACKING");
        if (c.sku.length === 0) throw new PackingError("SKU_EMPTY");
        return [{ type: "PackingItemScanned", sku: c.sku }];
      case "seal":
        if (s.status !== "packing") throw new PackingError("NOT_PACKING");
        if (s.items.length === 0) throw new PackingError("EMPTY_PACK");
        return [{ type: "PackingSealed", at: c.at }];
      default: { const _n: never = c; throw new PackingError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "PackingStarted":
        return { status: "packing", id: e.id, orderId: e.orderId, items: [] };
      case "PackingItemScanned":
        if (s.status !== "packing") return s;
        return { ...s, items: [...s.items, e.sku] };
      case "PackingSealed":
        if (s.status !== "packing") return s;
        return { status: "sealed", id: s.id, orderId: s.orderId, items: s.items, sealedAt: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
