import { Effect } from "effect";

export type AnnotationEvent =
  | { type: "AnnotationAttached"; id: string; text: string; target: string }
  | { type: "AnnotationEdited"; text: string }
  | { type: "AnnotationRemoved"; at: string };

export type AnnotationState =
  | { status: "none" }
  | { status: "active"; id: string; text: string; target: string }
  | { status: "removed"; id: string; removedAt: string };

export function when(state: AnnotationState, event: AnnotationEvent): AnnotationState {
  switch (event.type) {
    case "AnnotationAttached":
      return { status: "active", id: event.id, text: event.text, target: event.target };
    case "AnnotationEdited":
      return state.status === "active" ? { ...state, text: event.text } : state;
    case "AnnotationRemoved":
      if (state.status !== "active") return state;
      return { status: "removed", id: state.id, removedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export interface EventStore {
  readStream(s: string): Promise<ReadonlyArray<AnnotationEvent>>;
}

export const loadAnnotation = (store: EventStore, stream: string) =>
  Effect.gen(function* () {
    const events = yield* Effect.promise(() => store.readStream(stream));
    return events.reduce(when, { status: "none" } as AnnotationState);
  });
```

A Decider is a pure triple (initialState, decide, evolve). `decide` consumes a command and current state, producing events or throwing on invariant violations. `evolve` folds events into state. No I/O, so it is trivially testable and deterministic.

