export type BaggageClaimEvent =
  | { type: "BagRegistered"; id: string; flight: string }
  | { type: "BagDelivered"; id: string }
  | { type: "BagLost"; id: string };

export interface BaggageClaimView {
  perFlight: Record<string, { registered: number; delivered: number; lost: number }>;
}

export const emptyView: BaggageClaimView = { perFlight: {} };

function bump(v: BaggageClaimView, flight: string, key: "registered" | "delivered" | "lost"): BaggageClaimView {
  const row = v.perFlight[flight] ?? { registered: 0, delivered: 0, lost: 0 };
  return { perFlight: { ...v.perFlight, [flight]: { ...row, [key]: row[key] + 1 } } };
}

export function project(view: BaggageClaimView, event: BaggageClaimEvent): BaggageClaimView {
  switch (event.type) {
    case "BagRegistered": return bump(view, event.flight, "registered");
    case "BagDelivered": return bump(view, "unknown", "delivered");
    case "BagLost": return bump(view, "unknown", "lost");
    default: { const _n: never = event; return view; }
  }
}

export interface Stored { revision: bigint; data: BaggageClaimEvent; }

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  readBatch: (from: bigint, size: number) => Promise<Stored[]>;
  persist: (view: BaggageClaimView, at: bigint) => Promise<void>;
  onProgress?: (at: bigint) => void;
}): Promise<void> {
  let cursor = opts.from;
  let view = emptyView;
  for (;;) {
    const batch = await opts.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const ev of batch) {
      view = project(view, ev.data);
      cursor = ev.revision;
    }
    await opts.persist(view, cursor);
    opts.onProgress?.(cursor);
  }
}
