A Snapshot stores the folded aggregate state along with a schema version. On load, you compare the stored version with the current one and run per-step upgrade functions in order so state layout changes never require rewriting streams. Upgraders are pure.

```typescript
export const CURRENT_VERSION = 3;

export interface AirCrewV1 { id: string; members: string[]; }
export interface AirCrewV2 { id: string; members: string[]; pilotInCommand: string | null; }
export interface AirCrewV3 { id: string; members: string[]; pilotInCommand: string | null; dispatchedAt: string | null; }

export type CurrentState = AirCrewV3;

export interface Snapshot<S> { version: number; state: S; }

function v1Tov2(s: AirCrewV1): AirCrewV2 {
  return { ...s, pilotInCommand: null };
}

function v2Tov3(s: AirCrewV2): AirCrewV3 {
  return { ...s, dispatchedAt: null };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v === 1) { state = v1Tov2(state as AirCrewV1); v = 2; }
  if (v === 2) { state = v2Tov3(state as AirCrewV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`unsupported snapshot version: ${v}`);
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
```

An outbox reconcile picks the head op, tries to send it, and either advances on success, retries on transient error, or moves it to a dead-letter list after N attempts. Attempts live on each op so a partially-drained outbox preserves progress.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Op = { id: string; payload: string; attempts: number };
type Ctx = { outbox: Op[]; dead: Op[] };
type Ev = { type: 'DRAIN' };

export const outboxReconcile = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    send: fromPromise(async ({ input }: { input: { id: string } }) => {
      if (input.id.endsWith('X')) throw new Error('fail');
      return input.id;
    })
  },
  guards: {
    hasOp: ({ context }) => context.outbox.length > 0,
    canRetry: ({ context }) => (context.outbox[0]?.attempts ?? 0) < 3
  }
}).createMachine({
  id: 'reconcile',
  initial: 'idle',
  context: { outbox: [], dead: [] },
  states: {
    idle: { on: { DRAIN: { target: 'sending', guard: 'hasOp' } } },
    sending: {
      invoke: {
        src: 'send',
        input: ({ context }) => ({ id: context.outbox[0]?.id ?? '' }),
        onDone: {
          target: 'idle',
          actions: assign({ outbox: ({ context }) => context.outbox.slice(1) })
        },
        onError: [
          {
            target: 'sending',
            guard: 'canRetry',
            reenter: true,
            actions: assign({
              outbox: ({ context }) =>
                context.outbox.map((op, i) => (i === 0 ? { ...op, attempts: op.attempts + 1 } : op))
            })
          },
          {
            target: 'idle',
            actions: assign({
              dead: ({ context }) => context.dead.concat(context.outbox[0]!),
              outbox: ({ context }) => context.outbox.slice(1)
            })
          }
        ]
      }
    }
  }
});
```

```typescript
export type ReportEvent =
  | { type: "ReportStarted"; id: string; title: string }
  | { type: "SectionAdded"; heading: string; body: string }
  | { type: "ReportPublished"; at: string };

export type Report = Readonly<{
  id: string;
  title: string;
  sections: ReadonlyArray<{ heading: string; body: string }>;
  publishedAt?: string;
}>;

export function when(state: Partial<Report>, event: ReportEvent): Partial<Report> {
  switch (event.type) {
    case "ReportStarted":
      return { id: event.id, title: event.title, sections: [] };
    case "SectionAdded":
      return {
        ...state,
        sections: [...(state.sections ?? []), { heading: event.heading, body: event.body }],
      };
    case "ReportPublished":
      return { ...state, publishedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export function isReport(s: Partial<Report>): s is Report {
  return !!s.id && !!s.title && !!s.sections;
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const s = events.reduce<Partial<A>>(reducer, {});
  if (!check(s)) throw new Error("INVALID_AGGREGATE_STATE");
  return s;
}

export const reportFrom = (events: ReportEvent[]): Report =>
  aggregateStream(events, when, isReport);

