```ts
export function debounce<T extends (...args: any[]) => any>(
  fn: T,
  ms: number,
): T {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<T>): void => {
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => { fn(...args); timer = null; }, ms);
  };
  return debounced as T;
}
```

The return type loses `fn`'s original return type on purpose — debounced calls don't return synchronously (the real call happens later). If you need the eventual return, change the wrapper to return `Promise<ReturnType<T>>` and resolve inside the timer. Using `ReturnType<typeof setTimeout>` keeps this portable across Node (`Timeout`) and DOM (`number`) types.

```typescript
import { Effect } from "effect";

export type DriverAssessmentState = { status: "new" } | { status: "scored"; id: string; score: number };
export type DriverAssessmentCommand =
  | { type: "score"; id: string; score: number }
  | { type: "sign"; signedBy: string };
export type DriverAssessmentEvent =
  | { type: "DriverAssessmentScored"; id: string; score: number }
  | { type: "DriverAssessmentSigned"; signedBy: string };

export class AssessmentError extends Error {}

export const initialState: DriverAssessmentState = { status: "new" };

export function evolve(s: DriverAssessmentState, e: DriverAssessmentEvent): DriverAssessmentState {
  switch (e.type) {
    case "DriverAssessmentScored":
      return { status: "scored", id: e.id, score: e.score };
    case "DriverAssessmentSigned":
      return s;
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: DriverAssessmentCommand, s: DriverAssessmentState): DriverAssessmentEvent[] {
  switch (c.type) {
    case "score":
      if (s.status !== "new") throw new AssessmentError("EXISTS");
      return [{ type: "DriverAssessmentScored", id: c.id, score: c.score }];
    case "sign":
      if (s.status !== "scored") throw new AssessmentError("NOT_SCORED");
      return [{ type: "DriverAssessmentSigned", signedBy: c.signedBy }];
    default: { const _n: never = c; throw new AssessmentError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<{ events: DriverAssessmentEvent[]; revision: bigint | null }>;
  appendToStream(stream: string, events: DriverAssessmentEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export const handleEffect = (
  command: DriverAssessmentCommand,
  ctx: { streamName: string; eventStore: EventStore },
) =>
  Effect.gen(function* () {
    const current = yield* Effect.promise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = current.events.reduce(evolve, initialState);
    const events = decide(command, state);
    if (events.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
    const revision = yield* Effect.promise(() =>
      ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision }),
    );
    return revision;
  });
```

```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: readonly E[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export function commandHandlerFor<C, E, S>(
  decider: Decider<C, E, S>,
  eventStore: EventStore<E>,
) {
  return async function handle(streamName: string, command: C): Promise<bigint | null> {
    const { events, revision } = await eventStore.readStream(streamName);
    const state = events.reduce(decider.evolve, decider.initialState);
    const produced = decider.decide(command, state);
    if (produced.length === 0) return revision;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return eventStore.appendToStream(streamName, produced, { expectedRevision });
  };
}

export function pureHandleCommand<C, E, S>(
  decider: Decider<C, E, S>,
  priorEvents: readonly E[],
  command: C,
): E[] {
  const state = priorEvents.reduce(decider.evolve, decider.initialState);
  return decider.decide(command, state);
}
```

```typescript
export type InventoryEvent =
  | { type: "StockReceived"; sku: string; qty: number }
  | { type: "StockReserved"; sku: string; qty: number }
  | { type: "StockReleased"; sku: string; qty: number }
  | { type: "StockCounted"; sku: string; countedAt: string };

export type LowStockView = Readonly<{
  bySku: Readonly<Record<string, number>>;
  threshold: number;
  lowCount: number;
}>;

export const emptyView: LowStockView = { bySku: {}, threshold: 10, lowCount: 0 };

function adjust(view: LowStockView, sku: string, delta: number): LowStockView {
  const current = view.bySku[sku] ?? 0;
  const next = current + delta;
  const nextBySku: Record<string, number> = { ...view.bySku, [sku]: next };
  const lowCount = Object.values(nextBySku).filter((v) => v < view.threshold).length;
  return { bySku: nextBySku, threshold: view.threshold, lowCount };
}

export function project(view: LowStockView, event: InventoryEvent): LowStockView {
  switch (event.type) {
    case "StockReceived":
      return adjust(view, event.sku, event.qty);
    case "StockReserved":
      return adjust(view, event.sku, -event.qty);
    case "StockReleased":
      return adjust(view, event.sku, event.qty);
    case "StockCounted":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function buildView(events: InventoryEvent[]): LowStockView {
  return events.reduce(project, emptyView);
}
```

