`ZodSchema<T>` flows the inferred type to the return. `parse` throws a `ZodError` on mismatch — the caller can catch it and inspect `err.issues` for field-level detail. Use `safeParse` if the caller prefers discriminated-union handling.

```typescript
export type DomainEvent =
  | { type: "FishStockHarvested"; id: string; count: number; at: string }
  | { type: "FishStockAudited"; id: string; by: string };

export type IntegrationEvent =
  | { schema: "fish-stock.harvested.v1"; payload: { stockId: string; count: number; occurredAt: string } };

export function translate(event: DomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "FishStockHarvested":
      return {
        schema: "fish-stock.harvested.v1",
        payload: { stockId: event.id, count: event.count, occurredAt: event.at },
      };
    case "FishStockAudited":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface OutboxRow {
  readonly id: string;
  readonly payload: IntegrationEvent;
  readonly publishedAt: string | null;
}

export interface TxConn {
  insertOutbox(row: OutboxRow): Promise<void>;
  appendToStream(stream: string, events: DomainEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface Transactor {
  transact<T>(fn: (conn: TxConn) => Promise<T>): Promise<T>;
}

// Publisher role (separate worker): poll outbox rows where publishedAt is null,
// deliver the integration payload to the broker, and mark the row as published.
export async function appendWithOutbox(
  tx: Transactor,
  stream: string,
  events: DomainEvent[],
  expected: bigint | "no_stream" | "any",
  makeId: (e: DomainEvent) => string,
): Promise<void> {
  await tx.transact(async (conn) => {
    await conn.appendToStream(stream, events, { expectedRevision: expected });
    for (const event of events) {
      const integration = translate(event);
      if (integration === null) continue;
      await conn.insertOutbox({ id: makeId(event), payload: integration, publishedAt: null });
    }
  });
}
