```typescript
import { setup, assign, fromCallback } from 'xstate';

interface Point { x: number; y: number }
interface Ctx { strokes: Point[][]; preview: string | null }

type Ev =
  | { type: 'POINTER_DOWN'; point: Point }
  | { type: 'POINTER_MOVE'; point: Point }
  | { type: 'POINTER_UP' }
  | { type: 'PREVIEW'; dataUrl: string }
  | { type: 'SAVE' }
  | { type: 'DISCARD' };

const pointerListener = fromCallback<Ev>(({ sendBack }) => {
  const down = (e: PointerEvent) => sendBack({ type: 'POINTER_DOWN', point: { x: e.clientX, y: e.clientY } });
  const move = (e: PointerEvent) => sendBack({ type: 'POINTER_MOVE', point: { x: e.clientX, y: e.clientY } });
  const up = () => sendBack({ type: 'POINTER_UP' });
  window.addEventListener('pointerdown', down);
  window.addEventListener('pointermove', move);
  window.addEventListener('pointerup', up);
  return () => {
    window.removeEventListener('pointerdown', down);
    window.removeEventListener('pointermove', move);
    window.removeEventListener('pointerup', up);
  };
});

export const signaturePad = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { pointerListener }
}).createMachine({
  id: 'signaturePad',
  context: { strokes: [], preview: null },
  initial: 'idle',
  invoke: { src: 'pointerListener' },
  states: {
    idle: {
      on: {
        POINTER_DOWN: {
          target: 'drawing',
          actions: assign({ strokes: ({ context, event }) => [...context.strokes, [event.point]] })
        }
      }
    },
    drawing: {
      on: {
        POINTER_MOVE: {
          actions: assign({
            strokes: ({ context, event }) => {
              const next = context.strokes.slice();
              const last = next[next.length - 1] ?? [];
              next[next.length - 1] = [...last, event.point];
              return next;
            }
          })
        },
        POINTER_UP: 'preview'
      }
    },
    preview: {
      on: {
        PREVIEW: { actions: assign({ preview: ({ event }) => event.dataUrl }) },
        SAVE: 'saved',
        DISCARD: { target: 'idle', actions: assign({ strokes: () => [], preview: () => null }) }
      }
    },
    saved: { type: 'final' }
  }
});
