```typescript
export type BuildRunEvent =
  | { type: "BuildRunStarted"; commit: string }
  | { type: "BuildRunFinished"; commit: string }
  | { type: "BuildRunFailed"; commit: string; reason: string };

export interface BuildStats {
  readonly totals: { started: number; finished: number; failed: number };
}

export const emptyStats: BuildStats = { totals: { started: 0, finished: 0, failed: 0 } };

export function project(view: BuildStats, event: BuildRunEvent): BuildStats {
  switch (event.type) {
    case "BuildRunStarted":
      return { totals: { ...view.totals, started: view.totals.started + 1 } };
    case "BuildRunFinished":
      return { totals: { ...view.totals, finished: view.totals.finished + 1 } };
    case "BuildRunFailed":
      return { totals: { ...view.totals, failed: view.totals.failed + 1 } };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface Record_<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface Reader<E> {
  readBatch(from: bigint, size: number): Promise<Record_<E>[]>;
}

export interface Persister<V> {
  save(view: V, upTo: bigint): Promise<void>;
}

export async function rebuild(
  reader: Reader<BuildRunEvent>,
  persister: Persister<BuildStats>,
  opts: { from: bigint; batchSize: number },
): Promise<void> {
  let cursor = opts.from;
  let view: BuildStats = emptyStats;
  let done = false;
  while (!done) {
    const batch = await reader.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) {
      done = true;
      break;
    }
    for (const record of batch) {
      view = project(view, record.event);
      cursor = record.revision + 1n;
    }
    await persister.save(view, cursor);
  }
}
```

The `restTimerAfter` state is a hard break between sets. It uses a delayed transition so the clock starts automatically when the set finishes, but also accepts a SKIP event for when the lifter is ready early. We increment the set counter on exit.

```typescript
