```typescript
import { Effect } from "effect";

export type GateState = { status: "none" } | { status: "assigned"; id: string; gate: string };
export type GateCommand = { type: "assign"; id: string; gate: string } | { type: "release" };
export type GateEvent = { type: "GateAssigned"; id: string; gate: string } | { type: "GateReleased" };

export const initialState: GateState = { status: "none" };

export function evolve(s: GateState, e: GateEvent): GateState {
  switch (e.type) {
    case "GateAssigned": return { status: "assigned", id: e.id, gate: e.gate };
    case "GateReleased": return { status: "none" };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: GateCommand, s: GateState): GateEvent[] {
  switch (c.type) {
    case "assign":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "GateAssigned", id: c.id, gate: c.gate }];
    case "release":
      if (s.status !== "assigned") throw new Error("NOT_ASSIGNED");
      return [{ type: "GateReleased" }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream: (name: string) => Promise<{ revision: bigint; data: GateEvent }[]>;
  appendToStream: (name: string, events: GateEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }) => Promise<void>;
}

export const handle = (store: EventStore, streamName: string, cmd: GateCommand) =>
  Effect.gen(function* () {
    const stored = yield* Effect.promise(() => store.readStream(streamName));
    const state = stored.reduce<GateState>((s, r) => evolve(s, r.data), initialState);
    const events = decide(cmd, state);
    const expectedRevision: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
    yield* Effect.promise(() => store.appendToStream(streamName, events, { expectedRevision }));
  });
```

```typescript
export type LoanAgreementEvent =
  | { type: "LoanAgreementDrafted"; id: string; borrower: string }
  | { type: "LoanAgreementSigned"; until: string }
  | { type: "LoanAgreementReturned"; returnedAt: string };

export type LoanAgreementState =
  | { status: "none" }
  | { status: "drafted"; id: string; borrower: string }
  | { status: "signed"; id: string; borrower: string; until: string }
  | { status: "returned"; id: string; returnedAt: string };

const initial: LoanAgreementState = { status: "none" };

export function evolve(state: LoanAgreementState, event: LoanAgreementEvent): LoanAgreementState {
  switch (event.type) {
    case "LoanAgreementDrafted":
      return { status: "drafted", id: event.id, borrower: event.borrower };
    case "LoanAgreementSigned":
      if (state.status !== "drafted") return state;
      return { status: "signed", id: state.id, borrower: state.borrower, until: event.until };
    case "LoanAgreementReturned":
      if (state.status !== "signed") return state;
      return { status: "returned", id: state.id, returnedAt: event.returnedAt };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  step: (state: S, event: E) => S,
  initialState: S
): Promise<S> {
  let state = initialState;
  for await (const event of stream) {
    state = step(state, event);
  }
  return state;
}

export function loadLoanAgreement(stream: AsyncIterable<LoanAgreementEvent>): Promise<LoanAgreementState> {
  return aggregateStream(stream, evolve, initial);
}
