  | { type: "EvaluationStarted"; id: string }
  | { type: "EvaluationRetried" }
  | { type: "EvaluationPassed"; score: number }
  | { type: "EvaluationFailed"; reason: string };

export function evolve(state: EvaluationState, event: EvaluationEvent): EvaluationState {
  switch (event.type) {
    case "EvaluationStarted":
      return { status: "running", id: event.id, retries: 0 };
    case "EvaluationRetried":
      if (state.status !== "running") return state;
      return { ...state, retries: state.retries + 1 };
    case "EvaluationPassed":
      if (state.status !== "running") return state;
      return { status: "passed", id: state.id, retries: state.retries, score: event.score };
    case "EvaluationFailed":
      if (state.status !== "running") return state;
      return { status: "failed", id: state.id, retries: state.retries, reason: event.reason };
    default: {
      const _never: never = event;
      return state;
    }
  }
}
