export type AdvertisementState =
  | { status: "empty" }
  | { status: "draft"; id: string; headline: string }
  | { status: "approved"; id: string; headline: string; approvedAt: string }
  | { status: "retired"; id: string };

export type AdvertisementCommand =
  | { type: "submit"; id: string; headline: string }
  | { type: "approve"; at: string }
  | { type: "retire" };

export type AdvertisementEvent =
  | { type: "AdvertisementSubmitted"; id: string; headline: string }
  | { type: "AdvertisementApproved"; at: string }
  | { type: "AdvertisementRetired" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const advertisementDecider: Decider<AdvertisementCommand, AdvertisementEvent, AdvertisementState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "submit": {
        if (state.status !== "empty") throw new DomainError("ALREADY_SUBMITTED");
        if (command.headline.length === 0) throw new DomainError("HEADLINE_EMPTY");
        return [{ type: "AdvertisementSubmitted", id: command.id, headline: command.headline }];
      }
      case "approve": {
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "AdvertisementApproved", at: command.at }];
      }
      case "retire": {
        if (state.status === "empty" || state.status === "retired") throw new DomainError("CANNOT_RETIRE");
        return [{ type: "AdvertisementRetired" }];
      }
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AdvertisementSubmitted":
        return { status: "draft", id: event.id, headline: event.headline };
      case "AdvertisementApproved":
        if (state.status !== "draft") return state;
        return { status: "approved", id: state.id, headline: state.headline, approvedAt: event.at };
      case "AdvertisementRetired":
        if (state.status === "empty" || state.status === "retired") return state;
        return { status: "retired", id: state.id };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
