export type AmenityCommand = { type: "add"; id: string; name: string } | { type: "retire" };
export type AmenityEvent = { type: "AmenityAdded"; id: string; name: string } | { type: "AmenityRetired" };
export type AmenityState = { status: "none" } | { status: "active"; id: string; name: string } | { status: "retired" };

function evolve(state: AmenityState, event: AmenityEvent): AmenityState {
  switch (event.type) {
    case "AmenityAdded":
      return { status: "active", id: event.id, name: event.name };
    case "AmenityRetired":
      return { status: "retired" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(cmd: AmenityCommand, state: AmenityState): AmenityEvent[] {
  switch (cmd.type) {
    case "add":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "AmenityAdded", id: cmd.id, name: cmd.name }];
    case "retire":
      if (state.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "AmenityRetired" }];
    default: {
      const _never: never = cmd;
      return _never;
    }
  }
}

interface EventStore {
  readStream(s: string): Promise<{ data: AmenityEvent; revision: bigint }[]>;
  appendToStream(s: string, events: AmenityEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export interface AmenityView { id: string; name: string; retired: boolean }

interface ReadStore {
  find(id: string): Promise<AmenityView | null>;
}

// The read store is eventually consistent with the event store.
export function makeBoundary(write: EventStore, read: ReadStore, stream: (id: string) => string) {
  return {
    async handleCommand(id: string, cmd: AmenityCommand): Promise<void> {
      const s = stream(id);
      const stored = await write.readStream(s);
      const state = stored.reduce<AmenityState>((a, e) => evolve(a, e.data), { status: "none" });
      const events = decide(cmd, state);
      const exp: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
      await write.appendToStream(s, events, { expectedRevision: exp });
    },
    queryView(id: string): Promise<AmenityView | null> {
      return read.find(id);
    },
  };
}
