Typed `CALLBACK` event carries the authorization code; a `fromPromise` actor does the token exchange.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { code: string | null; token: string | null; error: string | null };
type Ev =
  | { type: 'LOGIN' }
  | { type: 'CALLBACK'; code: string }
  | { type: 'LOGOUT' };

const exchange = fromPromise<string, { code: string }>(async ({ input }) => `tok-${input.code}`);

export const oauth = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { exchange },
}).createMachine({
  id: 'oauth',
  context: { code: null, token: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { LOGIN: 'redirecting' } },
    redirecting: { on: { CALLBACK: { target: 'exchanging', actions: assign({ code: ({ event }) => event.code }) } } },
    exchanging: {
      invoke: {
        src: 'exchange',
        input: ({ context }) => ({ code: context.code ?? '' }),
        onDone: {
          target: 'authenticated',
          actions: assign({ token: ({ event }) => event.output, error: () => null }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => (event.error instanceof Error ? event.error.message : 'unknown'),
          }),
        },
      },
    },
    authenticated: { on: { LOGOUT: 'idle' } },
    failed: { on: { LOGIN: 'redirecting' } },
  },
});
