```typescript
export class ConcurrencyConflict extends Error {}
export type CourtFilingEvent = { type: "submitted"; filingId: string } | { type: "accepted" } | { type: "rejected"; reason: string };
export interface Stored<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<Stored<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<{ nextRevision: bigint }>;
}
export async function appendFiling(
  store: EventStore<CourtFilingEvent>,
  stream: string,
  events: CourtFilingEvent[],
): Promise<bigint> {
  let expected: bigint | "no_stream" = "no_stream";
  let seen = false;
  for await (const { revision } of store.readStream(stream)) { expected = revision; seen = true; }
  if (!seen) expected = "no_stream";
  try {
    const { nextRevision } = await store.appendToStream(stream, events, { expectedRevision: expected });
    return nextRevision;
  } catch (err) {
    throw new ConcurrencyConflict((err as Error).message);
  }
}
