A parent drop-zone machine holds a list of spawned child actors (one per file). Each child is a `fromPromise` actor that runs the upload and reports completion back to the parent. The parent assigns into its context a typed `ActorRefFrom` reference for each file so subscribers can inspect per-file progress.

```typescript
import { setup, assign, fromPromise, type ActorRefFrom } from 'xstate';

const uploadActor = fromPromise<{ id: string }, { id: string; blob: Blob }>(
  async ({ input }) => {
    await new Promise((r) => setTimeout(r, 50));
    return { id: input.id };
  }
);

interface FileRef { id: string; ref: ActorRefFrom<typeof uploadActor> }
interface Ctx { files: FileRef[] }

type Ev =
  | { type: 'DROP'; items: { id: string; blob: Blob }[] }
  | { type: 'DONE'; id: string };

export const perFileMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { uploadActor }
}).createMachine({
  id: 'perFile',
  context: { files: [] },
  initial: 'ready',
  states: {
    ready: {
      on: {
        DROP: {
          actions: assign({
            files: ({ event, spawn }) =>
              event.items.map((item) => ({
                id: item.id,
                ref: spawn('uploadActor', { input: { id: item.id, blob: item.blob } })
              }))
          })
        },
        DONE: {
          actions: assign({
            files: ({ context, event }) => context.files.filter((f) => f.id !== event.id)
          })
        }
      }
    }
  }
});
