Optimistic concurrency lets multiple writers proceed without locks: each appendToStream carries the revision the writer read when loading state. If another writer advanced the stream in the meantime, the server rejects the append, and the client surfaces a typed ConcurrencyConflict so the caller can retry (reload state and re-decide).

```typescript
export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; species: string; count: number }
  | { type: "FishStockHarvested"; count: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`Concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function safeAppend(
  store: EventStore,
  stream: string,
  events: FishStockEvent[],
  expected: ExpectedRevision,
): Promise<bigint> {
  try {
    return await store.appendToStream<FishStockEvent>(stream, events, { expectedRevision: expected });
  } catch (err: unknown) {
    if (err instanceof Error && /WrongExpected|revision/i.test(err.message)) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
```

