```typescript
export type ParkingEvent =
  | { type: "ParkingSessionStarted"; id: string; zone: string; at: string }
  | { type: "ParkingSessionMetered"; amount: number }
  | { type: "ParkingSessionEnded"; at: string };

export type ParkingView = Readonly<{
  id: string;
  zone: string;
  startedAt: string;
  endedAt?: string;
  totalCharged: number;
  durationMinutes?: number;
  status: "active" | "ended";
}>;

export const emptyParkingView: ParkingView = {
  id: "",
  zone: "",
  startedAt: "",
  totalCharged: 0,
  status: "active",
};

export function project(view: ParkingView, event: ParkingEvent): ParkingView {
  switch (event.type) {
    case "ParkingSessionStarted":
      return {
        id: event.id,
        zone: event.zone,
        startedAt: event.at,
        totalCharged: 0,
        status: "active",
      };
    case "ParkingSessionMetered":
      return { ...view, totalCharged: view.totalCharged + event.amount };
    case "ParkingSessionEnded": {
      const started = Date.parse(view.startedAt);
      const ended = Date.parse(event.at);
      const duration = Number.isFinite(started) && Number.isFinite(ended)
        ? Math.max(0, Math.round((ended - started) / 60000))
        : undefined;
      return { ...view, status: "ended", endedAt: event.at, durationMinutes: duration };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function parkingViewFrom(events: ParkingEvent[]): ParkingView {
  return events.reduce(project, emptyParkingView);
}
