```typescript
export type TableReservationEvent =
  | { type: "ReservationRequested"; id: string }
  | { type: "ReservationConfirmed"; id: string }
  | { type: "ReservationCancelled"; id: string };

export type PipelineView = Readonly<{ pending: number; confirmed: number; cancelled: number }>;
const empty: PipelineView = { pending: 0, confirmed: 0, cancelled: 0 };

export function project(v: PipelineView, e: TableReservationEvent): PipelineView {
  switch (e.type) {
    case "ReservationRequested": return { ...v, pending: v.pending + 1 };
    case "ReservationConfirmed": return { ...v, pending: v.pending - 1, confirmed: v.confirmed + 1 };
    case "ReservationCancelled": return { ...v, pending: v.pending - 1, cancelled: v.cancelled + 1 };
    default: { const _n: never = e; return v; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventFeed {
  readFrom(stream: string, from: bigint | null): AsyncIterable<{ revision: bigint; event: TableReservationEvent }>;
}

export interface ViewStore {
  save(view: PipelineView): Promise<void>;
}

export async function runBatched(
  ctx: { feed: EventFeed; checkpoints: CheckpointStore; views: ViewStore },
  stream: string,
  subscriptionName: string,
  batchSize = 20
): Promise<void> {
  const start = await ctx.checkpoints.read(subscriptionName);
  let view: PipelineView = empty;
  let since = 0;
  let lastRevision: bigint | null = null;
  for await (const { revision, event } of ctx.feed.readFrom(stream, start)) {
    view = project(view, event);
    lastRevision = revision;
    since++;
    if (since >= batchSize) {
      await ctx.views.save(view);
      await ctx.checkpoints.write(subscriptionName, revision);
      since = 0;
    }
  }
  if (since > 0 && lastRevision !== null) {
    await ctx.views.save(view);
    await ctx.checkpoints.write(subscriptionName, lastRevision);
  }
}
