import { Effect } from "effect";

export type ContractState = { status: "none" } | { status: "drafted"; id: string };
export type ContractCommand = { type: "draft"; id: string };
export type ContractEvent = { type: "ContractDrafted"; id: string };

const initial: ContractState = { status: "none" };

function decide(c: ContractCommand, s: ContractState): ContractEvent[] {
  switch (c.type) {
    case "draft":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "ContractDrafted", id: c.id }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

function evolve(s: ContractState, e: ContractEvent): ContractState {
  switch (e.type) {
    case "ContractDrafted":
      return { status: "drafted", id: e.id };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    stream: string,
    events: readonly E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export const handle = (
  command: ContractCommand,
  ctx: { streamName: string; eventStore: EventStore<ContractEvent> },
) =>
  Effect.gen(function* () {
    const loaded = yield* Effect.promise(async () => {
      let state = initial;
      let rev: bigint | "no_stream" = "no_stream";
      for await (const rec of ctx.eventStore.readStream(ctx.streamName)) {
        state = evolve(state, rec.event);
        rev = rec.revision;
      }
      return { state, rev };
    });
    const events = decide(command, loaded.state);
    yield* Effect.promise(() =>
      ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: loaded.rev }),
    );
  });
