export type EnrolmentEvent =
  | { type: "EnrolmentConfirmed"; id: string; learner: string; cohortId: string }
  | { type: "EnrolmentDropped"; id: string; reason: string }
  | { type: "EnrolmentRegistered"; id: string; learner: string; course: string };

export type CohortCommand =
  | { type: "admit"; cohortId: string; learner: string }
  | { type: "noop" };

export function react(event: EnrolmentEvent): CohortCommand | null {
  switch (event.type) {
    case "EnrolmentConfirmed":
      return { type: "admit", cohortId: event.cohortId, learner: event.learner };
    case "EnrolmentDropped":
      return null;
    case "EnrolmentRegistered":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

// `project(events)` runs the saga as a pure projection over the event stream.
export function project(events: ReadonlyArray<EnrolmentEvent>): CohortCommand[] {
  const out: CohortCommand[] = [];
  for (const event of events) {
    const cmd = react(event);
    if (cmd !== null) out.push(cmd);
  }
  return out;
}
