```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

```typescript
export interface ContractV1 { id: string; parties: string[]; }
export interface ContractV2 { id: string; parties: string[]; signedAt?: string; }
export interface ContractV3 { id: string; parties: string[]; signedAt?: string; value: number; }

export type CurrentState = ContractV3;

export interface Snapshot<S> { version: number; state: S; }

export const CURRENT_VERSION = 3;

const upgraders: Record<number, (s: unknown) => { version: number; state: unknown }> = {
  1: (s) => {
    const v1 = s as ContractV1;
    const v2: ContractV2 = { ...v1 };
    return { version: 2, state: v2 };
  },
  2: (s) => {
    const v2 = s as ContractV2;
    const v3: ContractV3 = { ...v2, value: 0 };
    return { version: 3, state: v3 };
  },
};

export function loadSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let cur: { version: number; state: unknown } = { version: snap.version, state: snap.state };
  while (cur.version < CURRENT_VERSION) {
    const up = upgraders[cur.version];
    if (!up) throw new Error(`No upgrader for v${cur.version}`);
    cur = up(cur.state);
  }
  return { version: CURRENT_VERSION, state: cur.state as CurrentState };
}
