export type MatchState =
  | { status: "none" }
  | { status: "scheduled"; id: string; home: string; away: string; kickoffAt: string }
  | { status: "live"; id: string; home: string; away: string; homeGoals: number; awayGoals: number }
  | { status: "final"; id: string; home: string; away: string; homeGoals: number; awayGoals: number };

export type MatchCommand =
  | { type: "schedule"; id: string; home: string; away: string; kickoffAt: string }
  | { type: "kickoff" }
  | { type: "goal"; side: "home" | "away"; scorer: string }
  | { type: "fullTime" };

export type MatchEvent =
  | { type: "MatchScheduled"; id: string; home: string; away: string; kickoffAt: string }
  | { type: "MatchKickedOff" }
  | { type: "MatchGoalScored"; side: "home" | "away"; scorer: string }
  | { type: "MatchFullTime" };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const matchDecider: Decider<MatchCommand, MatchEvent, MatchState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new DomainError("ALREADY_SCHEDULED");
        if (command.home === command.away) throw new DomainError("SAME_OPPONENT");
        return [{ type: "MatchScheduled", id: command.id, home: command.home, away: command.away, kickoffAt: command.kickoffAt }];
      case "kickoff":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "MatchKickedOff" }];
      case "goal":
        if (state.status !== "live") throw new DomainError("NOT_LIVE");
        return [{ type: "MatchGoalScored", side: command.side, scorer: command.scorer }];
      case "fullTime":
        if (state.status !== "live") throw new DomainError("NOT_LIVE");
        return [{ type: "MatchFullTime" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "MatchScheduled":
        return { status: "scheduled", id: event.id, home: event.home, away: event.away, kickoffAt: event.kickoffAt };
      case "MatchKickedOff":
        if (state.status !== "scheduled") return state;
        return { status: "live", id: state.id, home: state.home, away: state.away, homeGoals: 0, awayGoals: 0 };
      case "MatchGoalScored":
        if (state.status !== "live") return state;
        return event.side === "home"
          ? { ...state, homeGoals: state.homeGoals + 1 }
          : { ...state, awayGoals: state.awayGoals + 1 };
      case "MatchFullTime":
        if (state.status !== "live") return state;
        return { status: "final", id: state.id, home: state.home, away: state.away, homeGoals: state.homeGoals, awayGoals: state.awayGoals };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
