export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, p: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(p: bigint): AsyncIterable<EventEnvelope<E>>;
}

export type MaintenanceWindowView = Readonly<{
  id: string;
  startsAt: string;
  startedAt?: string;
  closedAt?: string;
  status: "scheduled" | "active" | "closed";
}>;

export interface Projection<V, E> {
  load(): Promise<V>;
  project(v: V, e: E): V;
  save(v: V): Promise<void>;
}

export function projectMaintenance(
  view: MaintenanceWindowView,
  event: MaintenanceWindowEvent,
): MaintenanceWindowView {
  switch (event.type) {
    case "MaintenanceWindowScheduled":
      return { id: event.id, startsAt: event.startsAt, status: "scheduled" };
    case "MaintenanceWindowStarted":
      return { ...view, status: "active", startedAt: event.at };
    case "MaintenanceWindowClosed":
      return { ...view, status: "closed", closedAt: event.at };
    default: { const _n: never = event; return view; }
  }
}

export const runSubscriptionEffect = (
  name: string,
  source: EventSource<MaintenanceWindowEvent>,
  checkpoints: CheckpointStore,
  projection: Projection<MaintenanceWindowView, MaintenanceWindowEvent>,
) =>
  Effect.gen(function* () {
    const start = yield* Effect.promise(() => checkpoints.read(name));
    let view = yield* Effect.promise(() => projection.load());
    const pump = async (): Promise<void> => {
      for await (const { position, event } of source.readFrom(start ?? 0n)) {
        view = projection.project(view, event);
        await projection.save(view);
        await checkpoints.write(name, position);
      }
    };
    yield* Effect.promise(() => pump());
  });
