```typescript
export type PrerequisiteState =
  | { status: "none" }
  | { status: "declared"; courseId: string; requires: ReadonlyArray<string> };

export type PrerequisiteCommand =
  | { type: "declare"; courseId: string }
  | { type: "require"; prerequisiteId: string; knownEdges: Readonly<Record<string, ReadonlyArray<string>>> }
  | { type: "remove"; prerequisiteId: string };

export type PrerequisiteEvent =
  | { type: "PrerequisiteDeclared"; courseId: string }
  | { type: "PrerequisiteAdded"; prerequisiteId: string }
  | { type: "PrerequisiteRemoved"; prerequisiteId: string };

export class PrerequisiteError extends Error {}

function reachable(
  start: string,
  target: string,
  edges: Readonly<Record<string, ReadonlyArray<string>>>,
): boolean {
  const stack: string[] = [start];
  const seen = new Set<string>();
  while (stack.length > 0) {
    const next = stack.pop();
    if (next === undefined) break;
    if (next === target) return true;
    if (seen.has(next)) continue;
    seen.add(next);
    const out = edges[next];
    if (out !== undefined) stack.push(...out);
  }
  return false;
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const prerequisiteDecider: Decider<PrerequisiteCommand, PrerequisiteEvent, PrerequisiteState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "declare":
        if (s.status !== "none") throw new PrerequisiteError("ALREADY_DECLARED");
        return [{ type: "PrerequisiteDeclared", courseId: c.courseId }];
      case "require":
        if (s.status !== "declared") throw new PrerequisiteError("NOT_DECLARED");
        if (c.prerequisiteId === s.courseId) throw new PrerequisiteError("SELF_REFERENCE");
        if (s.requires.includes(c.prerequisiteId)) throw new PrerequisiteError("ALREADY_REQUIRED");
        if (reachable(c.prerequisiteId, s.courseId, c.knownEdges)) throw new PrerequisiteError("CYCLE");
        return [{ type: "PrerequisiteAdded", prerequisiteId: c.prerequisiteId }];
      case "remove":
        if (s.status !== "declared") throw new PrerequisiteError("NOT_DECLARED");
        if (!s.requires.includes(c.prerequisiteId)) throw new PrerequisiteError("NOT_REQUIRED");
        return [{ type: "PrerequisiteRemoved", prerequisiteId: c.prerequisiteId }];
      default: { const _n: never = c; throw new PrerequisiteError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "PrerequisiteDeclared":
        return { status: "declared", courseId: e.courseId, requires: [] };
      case "PrerequisiteAdded":
        if (s.status !== "declared") return s;
        return { ...s, requires: [...s.requires, e.prerequisiteId] };
      case "PrerequisiteRemoved":
        if (s.status !== "declared") return s;
        return { ...s, requires: s.requires.filter((id) => id !== e.prerequisiteId) };
      default: { const _n: never = e; return s; }
    }
  },
};
```

```typescript
export type RolloutState =
  | { status: "draft" }
  | { status: "active"; id: string; stage: number; total: number };

export type RolloutCommand =
  | { type: "plan"; id: string; total: number }
  | { type: "advance" };

export type RolloutEvent =
  | { type: "RolloutPlanned"; id: string; total: number }
  | { type: "RolloutAdvanced"; stage: number };

export interface AppendOptions { expectedRevision: bigint | "no_stream" | "any"; }
export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], options: AppendOptions): Promise<{ nextRevision: bigint }>;
}

export const initialState: RolloutState = { status: "draft" };

export function evolve(state: RolloutState, event: RolloutEvent): RolloutState {
  switch (event.type) {
    case "RolloutPlanned":
      return { status: "active", id: event.id, stage: 0, total: event.total };
    case "RolloutAdvanced":
      if (state.status !== "active") return state;
      return { ...state, stage: event.stage };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: RolloutCommand, state: RolloutState): RolloutEvent[] {
  switch (command.type) {
    case "plan":
      if (state.status !== "draft") throw new Error("PLANNED");
      if (command.total <= 0) throw new Error("BAD_TOTAL");
      return [{ type: "RolloutPlanned", id: command.id, total: command.total }];
    case "advance":
      if (state.status !== "active") throw new Error("NOT_ACTIVE");
      if (state.stage + 1 > state.total) throw new Error("DONE");
      return [{ type: "RolloutAdvanced", stage: state.stage + 1 }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export async function handle(
  command: RolloutCommand,
  deps: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const records = await deps.eventStore.readStream<RolloutEvent>(deps.streamName);
  const state = records.reduce<RolloutState>((s, r) => evolve(s, r.event), initialState);
  const expected: AppendOptions["expectedRevision"] =
    records.length === 0 ? "no_stream" : records[records.length - 1].revision;
  const events = decide(command, state);
  await deps.eventStore.appendToStream<RolloutEvent>(deps.streamName, events, { expectedRevision: expected });
}
