export type BOMEvent =
  | { type: "BOMRevisionDrafted"; revisionId: string; author: string; position: bigint }
  | { type: "BOMRevisionPublished"; revisionId: string; at: string; position: bigint };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventStore {
  readFromStream(stream: string, from: bigint): AsyncIterable<BOMEvent>;
}

export interface BOMRow { revisionId: string; author: string; publishedAt: string | null; }
export interface BOMView { byRevision: Record<string, BOMRow>; }

export function project(view: BOMView, event: BOMEvent): BOMView {
  switch (event.type) {
    case "BOMRevisionDrafted":
      return { byRevision: { ...view.byRevision, [event.revisionId]: { revisionId: event.revisionId, author: event.author, publishedAt: null } } };
    case "BOMRevisionPublished": {
      const row = view.byRevision[event.revisionId];
      if (!row) return view;
      return { byRevision: { ...view.byRevision, [event.revisionId]: { ...row, publishedAt: event.at } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export async function runSubscription(
  name: string,
  store: EventStore,
  checkpoints: CheckpointStore,
  persist: (v: BOMView) => Promise<void>
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? 0n;
  let view: BOMView = { byRevision: {} };
  for await (const event of store.readFromStream("bom-revisions", start)) {
    view = project(view, event);
    await persist(view);
    await checkpoints.write(name, event.position);
  }
}
