export type DiscoveryRequestCommand = { type: "issue"; requestId: string; topic: string } | { type: "produce"; documentId: string };
export type DiscoveryRequestEvent = { type: "issued"; requestId: string; topic: string } | { type: "produced"; documentId: string };
export type DiscoveryRequestState = { status: "none" } | { status: "issued"; requestId: string; produced: number };
export const initialState: DiscoveryRequestState = { status: "none" };
export function evolve(s: DiscoveryRequestState, e: DiscoveryRequestEvent): DiscoveryRequestState {
  switch (e.type) {
    case "issued": return { status: "issued", requestId: e.requestId, produced: 0 };
    case "produced": return s.status === "issued" ? { ...s, produced: s.produced + 1 } : s;
    default: { const _: never = e; return s; }
  }
}
export function decide(c: DiscoveryRequestCommand, s: DiscoveryRequestState): DiscoveryRequestEvent[] {
  switch (c.type) {
    case "issue": return s.status === "none" ? [{ type: "issued", requestId: c.requestId, topic: c.topic }] : [];
    case "produce": return s.status === "issued" ? [{ type: "produced", documentId: c.documentId }] : [];
    default: { const _: never = c; return []; }
  }
}
interface Stored<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(stream: string): AsyncIterable<Stored<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}
export class CommandHandler {
  constructor(private store: EventStore<DiscoveryRequestEvent>) {}
  async handle(streamName: string, command: DiscoveryRequestCommand): Promise<void> {
    let state: DiscoveryRequestState = initialState;
    let revision: bigint | "no_stream" = "no_stream";
    for await (const rec of this.store.readStream(streamName)) { state = evolve(state, rec.event); revision = rec.revision; }
    const events = decide(command, state);
    await this.store.appendToStream(streamName, events, { expectedRevision: revision });
  }
}
```

```ts
import { z, ZodSchema } from 'zod';

export async function typedFetch<T>(
  url: string,
  schema: ZodSchema<T>,
  init?: RequestInit,
): Promise<T> {
  const res = await fetch(url, init);
  if (!res.ok) {
    throw new Error(`HTTP ${res.status} for ${url}`);
  }
  const body = await res.json();
  return schema.parse(body); // throws ZodError on mismatch
}
```

`ZodSchema<T>` flows the inferred type to the return. `parse` throws a `ZodError` on mismatch — the caller can catch it and inspect `err.issues` for field-level detail. Use `safeParse` if the caller prefers discriminated-union handling.

```typescript
export type RouteOptimisationEvent =
  | { type: "RoutePlanned"; id: string; stops: ReadonlyArray<string> }
  | { type: "RouteRerouted"; stops: ReadonlyArray<string> }
  | { type: "RouteCompleted"; at: string };

export type RouteState = { status: "none" } | { status: "planned"; id: string; stops: ReadonlyArray<string> };
export type RouteCommand =
  | { type: "plan"; id: string; stops: ReadonlyArray<string> }
  | { type: "complete"; at: string };

export class DomainError extends Error {}

export const initialState: RouteState = { status: "none" };

export function evolve(s: RouteState, e: RouteOptimisationEvent): RouteState {
  switch (e.type) {
    case "RoutePlanned":
      return { status: "planned", id: e.id, stops: e.stops };
    case "RouteRerouted":
      if (s.status !== "planned") return s;
      return { ...s, stops: e.stops };
    case "RouteCompleted":
      return s;
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: RouteCommand, s: RouteState): RouteOptimisationEvent[] {
  switch (c.type) {
    case "plan":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "RoutePlanned", id: c.id, stops: c.stops }];
    case "complete":
      if (s.status !== "planned") throw new DomainError("NOT_PLANNED");
      return [{ type: "RouteCompleted", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: RouteOptimisationEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: RouteOptimisationEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export type RouteDashboardView = Readonly<{ id: string; stops: ReadonlyArray<string>; status: "planned" | "completed" }>;

export interface ReadStore {
  find(id: string): Promise<RouteDashboardView | null>;
}

// NOTE: the read store is eventually consistent with the event store
// (populated by a subscription that projects RouteOptimisationEvent into RouteDashboardView).
export async function handleCommand(
  c: RouteCommand,
  ctx: { stream: string; store: EventStore },
): Promise<void> {
  const current = await ctx.store.readStream(ctx.stream);
  const state = current.events.reduce(evolve, initialState);
  const events = decide(c, state);
  if (events.length === 0) return;
  const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
  await ctx.store.appendToStream(ctx.stream, events, { expectedRevision });
}

export async function queryView(id: string, reads: ReadStore): Promise<RouteDashboardView | null> {
  return reads.find(id);
}
```

The machine keeps per-language tab width in a record inside context so switching languages restores its preferred tab width instead of resetting to a global default. We store the active language separately and derive current tab width via a helper at read time.

```typescript
