```typescript
export class DomainError extends Error {}

export type TerritoryMapState =
  | { status: "empty" }
  | { status: "open"; id: string; districts: number }
  | { status: "sealed"; id: string; sealedAt: string };

export type TerritoryMapCommand =
  | { type: "create"; id: string }
  | { type: "addDistrict" }
  | { type: "seal"; at: string };

export type TerritoryMapEvent =
  | { type: "created"; id: string }
  | { type: "districtAdded" }
  | { type: "sealed"; at: string };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const TerritoryMapDecider: Decider<TerritoryMapCommand, TerritoryMapEvent, TerritoryMapState> = {
  initialState: { status: "empty" },
  decide(c, s) {
    switch (c.type) {
      case "create":
        if (s.status !== "empty") throw new DomainError("already created");
        return [{ type: "created", id: c.id }];
      case "addDistrict":
        if (s.status === "sealed") throw new DomainError("map is sealed");
        if (s.status === "empty") throw new DomainError("not created");
        return [{ type: "districtAdded" }];
      case "seal":
        if (s.status !== "open") throw new DomainError("cannot seal");
        return [{ type: "sealed", at: c.at }];
      default: {
        const _: never = c;
        return _;
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "created":
        return { status: "open", id: e.id, districts: 0 };
      case "districtAdded":
        return s.status === "open" ? { ...s, districts: s.districts + 1 } : s;
      case "sealed":
        return s.status === "open" ? { status: "sealed", id: s.id, sealedAt: e.at } : s;
      default: {
        const _: never = e;
        return _;
      }
    }
  },
};
