A projection folds events into a denormalised view. Unlike evolve which rebuilds aggregate state, project targets a query-friendly shape and ignores events outside its interest.

```typescript
export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; species: string; count: number }
  | { type: "FishStockRestocked"; id: string; count: number }
  | { type: "FishStockHarvested"; id: string; count: number }
  | { type: "FishStockAudited"; id: string; by: string };

export interface StockTotalsView {
  readonly totalStocked: number;
  readonly totalHarvested: number;
  readonly perSpecies: Readonly<Record<string, number>>;
}

export const emptyView: StockTotalsView = {
  totalStocked: 0,
  totalHarvested: 0,
  perSpecies: {},
};

export function project(view: StockTotalsView, event: FishStockEvent): StockTotalsView {
  switch (event.type) {
    case "FishStockSeeded": {
      const prev = view.perSpecies[event.species] ?? 0;
      return {
        totalStocked: view.totalStocked + event.count,
        totalHarvested: view.totalHarvested,
        perSpecies: { ...view.perSpecies, [event.species]: prev + event.count },
      };
    }
    case "FishStockRestocked":
      return { ...view, totalStocked: view.totalStocked + event.count };
    case "FishStockHarvested":
      return { ...view, totalHarvested: view.totalHarvested + event.count };
    case "FishStockAudited":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}
```

```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

CQRS splits the write and read sides. Writes flow through a command handler that loads state, calls decide, and appends events. Reads come from a read model kept up to date by a projection subscribing to the same event stream. The read model is eventually consistent with the event store; the two sides share the event union but NOT the state type.

```typescript
export type EndowmentFundEvent =
  | { type: "opened"; fundId: string; name: string }
  | { type: "contributed"; fundId: string; amount: number };

export type EndowmentFundCommand =
  | { type: "open"; fundId: string; name: string }
  | { type: "contribute"; amount: number };

interface WriteState { status: "none" | "open"; name?: string; balance: number }
const initial: WriteState = { status: "none", balance: 0 };

function evolve(s: WriteState, e: EndowmentFundEvent): WriteState {
  switch (e.type) {
    case "opened":
      return { status: "open", name: e.name, balance: 0 };
    case "contributed":
      return { ...s, balance: s.balance + e.amount };
    default: {
      const _: never = e;
      return _;
    }
  }
}

function decide(c: EndowmentFundCommand, s: WriteState): EndowmentFundEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new Error("exists");
      return [{ type: "opened", fundId: c.fundId, name: c.name }];
    case "contribute":
      if (s.status !== "open") throw new Error("closed");
      return [{ type: "contributed", fundId: "?", amount: c.amount }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

export interface EventStore<E> {
  readStream(s: string): Promise<E[]>;
  appendToStream(s: string, e: E[]): Promise<void>;
}
export interface ReadView { fundId: string; name: string; balance: number }
export interface ReadStore { find(id: string): Promise<ReadView | null> }

// read store is eventually consistent with the write side
export async function handleCommand(
  cmd: EndowmentFundCommand,
  stream: string,
  store: EventStore<EndowmentFundEvent>,
): Promise<void> {
  const events = await store.readStream(stream);
  const state = events.reduce<WriteState>(evolve, initial);
  await store.appendToStream(stream, decide(cmd, state));
}

export function queryView(id: string, reads: ReadStore): Promise<ReadView | null> {
  return reads.find(id);
}
```

```typescript
import { Effect } from "effect";

export type MatchNewsEvent =
  | { type: "MatchScheduled"; id: string; home: string; away: string; kickoffAt: string }
  | { type: "MatchFullTime"; id: string; homeGoals: number; awayGoals: number };

export interface NewsItem {
  matchId: string;
  headline: string;
  publishedAt: string;
}

export type NewsfeedView = readonly NewsItem[];

export function project(view: NewsfeedView, e: MatchNewsEvent, now: string): NewsfeedView {
  switch (e.type) {
    case "MatchScheduled":
      return [...view, { matchId: e.id, headline: `${e.home} vs ${e.away}`, publishedAt: now }];
    case "MatchFullTime":
      return [...view, { matchId: e.id, headline: `Final ${e.homeGoals}-${e.awayGoals}`, publishedAt: now }];
    default: { const _n: never = e; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface NewsfeedStore {
  load(): Promise<NewsfeedView>;
  save(v: NewsfeedView): Promise<void>;
}

export interface StreamSource {
  iterate(from: bigint): AsyncIterable<{ position: bigint; event: MatchNewsEvent; at: string }>;
}

export function runNewsfeed(name: string, src: StreamSource, cp: CheckpointStore, store: NewsfeedStore) {
  return Effect.gen(function* () {
    const from = (yield* Effect.promise(() => cp.read(name))) ?? 0n;
    let view = yield* Effect.promise(() => store.load());
    yield* Effect.promise(async () => {
      for await (const { position, event, at } of src.iterate(from)) {
        view = project(view, event, at);
        await store.save(view);
        await cp.write(name, position);
      }
    });
  });
}
```

A CommandHandler is pure orchestration: read the stream, fold to state, call `decide`, append. `decide` owns invariants; the handler only moves bytes. This keeps the domain testable without IO.

```typescript
export type VehicleInspectionState =
  | { status: "pending" }
  | { status: "inspected"; id: string; faults: ReadonlyArray<string> };

export type VehicleInspectionCommand =
  | { type: "inspect"; id: string; faults: ReadonlyArray<string> }
  | { type: "clear"; note: string };

export type VehicleInspectionEvent =
  | { type: "VehicleInspected"; id: string; faults: ReadonlyArray<string> }
  | { type: "VehicleInspectionCleared"; note: string };

export class InspectionError extends Error {}

export const initialState: VehicleInspectionState = { status: "pending" };

export function evolve(s: VehicleInspectionState, e: VehicleInspectionEvent): VehicleInspectionState {
  switch (e.type) {
    case "VehicleInspected":
      return { status: "inspected", id: e.id, faults: e.faults };
    case "VehicleInspectionCleared":
      if (s.status !== "inspected") return s;
      return { status: "inspected", id: s.id, faults: [] };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: VehicleInspectionCommand, s: VehicleInspectionState): VehicleInspectionEvent[] {
  switch (c.type) {
    case "inspect":
      if (s.status !== "pending") throw new InspectionError("ALREADY_INSPECTED");
      return [{ type: "VehicleInspected", id: c.id, faults: c.faults }];
    case "clear":
      if (s.status !== "inspected") throw new InspectionError("NOT_INSPECTED");
      if (s.faults.length === 0) throw new InspectionError("NO_FAULTS");
      return [{ type: "VehicleInspectionCleared", note: c.note }];
    default: { const _n: never = c; throw new InspectionError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<{ events: VehicleInspectionEvent[]; revision: bigint | null }>;
  appendToStream(stream: string, events: VehicleInspectionEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export async function handle(
  command: VehicleInspectionCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const current = await ctx.eventStore.readStream(ctx.streamName);
  const state = current.events.reduce(evolve, initialState);
  const events = decide(command, state);
  if (events.length === 0) return;
  const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision });
}
