```typescript
export type ContractState =
  | { status: "none" }
  | { status: "drafted"; id: string; parties: string[] }
  | { status: "signed"; id: string; parties: string[]; signedAt: string }
  | { status: "terminated"; id: string; terminatedAt: string };

export type ContractCommand =
  | { type: "draft"; id: string; parties: string[] }
  | { type: "sign"; at: string }
  | { type: "terminate"; at: string };

export type ContractEvent =
  | { type: "ContractDrafted"; id: string; parties: string[] }
  | { type: "ContractSigned"; at: string }
  | { type: "ContractTerminated"; at: string };

export class ContractError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const contractDecider: Decider<ContractCommand, ContractEvent, ContractState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "draft":
        if (s.status !== "none") throw new ContractError("EXISTS");
        if (c.parties.length < 2) throw new ContractError("PARTIES");
        return [{ type: "ContractDrafted", id: c.id, parties: c.parties }];
      case "sign":
        if (s.status !== "drafted") throw new ContractError("NOT_DRAFT");
        return [{ type: "ContractSigned", at: c.at }];
      case "terminate":
        if (s.status === "terminated") throw new ContractError("ALREADY_TERMINATED");
        if (s.status === "none") throw new ContractError("NOT_FOUND");
        return [{ type: "ContractTerminated", at: c.at }];
      default: { const _n: never = c; throw new ContractError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ContractDrafted":
        return { status: "drafted", id: e.id, parties: e.parties };
      case "ContractSigned":
        if (s.status !== "drafted") return s;
        return { status: "signed", id: s.id, parties: s.parties, signedAt: e.at };
      case "ContractTerminated":
        return { status: "terminated", id: "id" in s ? s.id : "", terminatedAt: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
