Convert this XState v4 machine to v5 — every callback uses positional signatures:

```js
const tempM = Machine({
  id: 'thermostat',
  context: { temp: 20, target: 22 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        SET: {
          actions: assign({ target: (_, e) => e.value })
        },
        TICK: [
          { target: 'heating', cond: (ctx) => ctx.temp < ctx.target },
          { target: 'cooling', cond: (ctx) => ctx.temp > ctx.target }
        ]
      }
    },
    heating: { on: { DONE: 'idle' } },
    cooling: { on: { DONE: 'idle' } }
  }
});
```

All callbacks get the v5 destructured signature; the two `cond` branches become named guards in `setup.guards`.

```typescript
import { setup, assign } from 'xstate';

type Ev =
  | { type: 'SET'; value: number }
  | { type: 'TICK' }
  | { type: 'DONE' };

export const thermostatMachine = setup({
  types: {
    context: {} as { temp: number; target: number },
    events: {} as Ev
  },
  guards: {
    needsHeat: ({ context }) => context.temp < context.target,
    needsCool: ({ context }) => context.temp > context.target
  }
}).createMachine({
  id: 'thermostat',
  context: { temp: 20, target: 22 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        SET:  { actions: assign({ target: ({ event }) => event.value }) },
        TICK: [
          { target: 'heating', guard: 'needsHeat' },
          { target: 'cooling', guard: 'needsCool' }
        ]
      }
    },
    heating: { on: { DONE: 'idle' } },
    cooling: { on: { DONE: 'idle' } }
  }
});
