export type DatasetVersionState =
  | { status: "none" }
  | { status: "building"; id: string; rows: number }
  | { status: "published"; id: string; rows: number; checksum: string }
  | { status: "deprecated"; id: string; reason: string };

export type DatasetVersionCommand =
  | { type: "start"; id: string }
  | { type: "addRows"; count: number }
  | { type: "publish"; checksum: string }
  | { type: "deprecate"; reason: string };

export type DatasetVersionEvent =
  | { type: "DatasetVersionStarted"; id: string }
  | { type: "DatasetVersionRowsAdded"; count: number }
  | { type: "DatasetVersionPublished"; checksum: string; rows: number }
  | { type: "DatasetVersionDeprecated"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const datasetVersionDecider: Decider<DatasetVersionCommand, DatasetVersionEvent, DatasetVersionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "start":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "DatasetVersionStarted", id: command.id }];
      case "addRows":
        if (state.status !== "building") throw new DomainError("NOT_BUILDING");
        if (command.count <= 0) throw new DomainError("BAD_COUNT");
        return [{ type: "DatasetVersionRowsAdded", count: command.count }];
      case "publish":
        if (state.status !== "building") throw new DomainError("NOT_BUILDING");
        if (state.rows === 0) throw new DomainError("EMPTY");
        return [{ type: "DatasetVersionPublished", checksum: command.checksum, rows: state.rows }];
      case "deprecate":
        if (state.status !== "published") throw new DomainError("NOT_PUBLISHED");
        return [{ type: "DatasetVersionDeprecated", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DatasetVersionStarted":
        return { status: "building", id: event.id, rows: 0 };
      case "DatasetVersionRowsAdded":
        if (state.status !== "building") return state;
        return { ...state, rows: state.rows + event.count };
      case "DatasetVersionPublished":
        if (state.status !== "building") return state;
        return { status: "published", id: state.id, rows: event.rows, checksum: event.checksum };
      case "DatasetVersionDeprecated":
        if (state.status !== "published") return state;
        return { status: "deprecated", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
