Writing the checkpoint before the read model causes lost updates on crash: the projection would skip the event on restart. Apply the projection first and persist it, then write the checkpoint last.

```typescript
export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface StoredEvent<E> { readonly position: bigint; readonly event: E }
export interface EventStore<E> {
  readFromStream(stream: string, from: bigint): AsyncIterable<StoredEvent<E>>;
}

export type LabOrderEvent =
  | { type: "LabOrderPlaced"; id: string; panel: string }
  | { type: "LabOrderResulted"; id: string; at: string };

export interface LabView { readonly placed: number; readonly resulted: number }
export const emptyView: LabView = { placed: 0, resulted: 0 };

export function project(v: LabView, e: LabOrderEvent): LabView {
  switch (e.type) {
    case "LabOrderPlaced": return { ...v, placed: v.placed + 1 };
    case "LabOrderResulted": return { ...v, resulted: v.resulted + 1 };
    default: { const _never: never = e; return v; }
  }
}

export async function runSubscription(
  name: string,
  stream: string,
  store: EventStore<LabOrderEvent>,
  checkpoints: CheckpointStore,
  persist: (v: LabView) => Promise<void>,
): Promise<void> {
  let view: LabView = emptyView;
  const start = (await checkpoints.read(name)) ?? 0n;
  async function loop(): Promise<void> {
    for await (const stored of store.readFromStream(stream, start)) {
      view = project(view, stored.event);
      await persist(view);
      await checkpoints.write(name, stored.position);
    }
  }
  await loop();
}
```

