export type LineState = { status: "none" } | { status: "idle"; id: string } | { status: "running"; id: string };
export type LineCommand = { type: "commission"; id: string } | { type: "start" } | { type: "stop" };
export type LineEvent = { type: "LineCommissioned"; id: string } | { type: "LineStarted" } | { type: "LineStopped" };

export function evolve(s: LineState, e: LineEvent): LineState {
  switch (e.type) {
    case "LineCommissioned": return { status: "idle", id: e.id };
    case "LineStarted":
      if (s.status !== "idle") return s;
      return { status: "running", id: s.id };
    case "LineStopped":
      if (s.status !== "running") return s;
      return { status: "idle", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: LineCommand, s: LineState): LineEvent[] {
  switch (c.type) {
    case "commission":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "LineCommissioned", id: c.id }];
    case "start":
      if (s.status !== "idle") throw new Error("NOT_IDLE");
      return [{ type: "LineStarted" }];
    case "stop":
      if (s.status !== "running") throw new Error("NOT_RUNNING");
      return [{ type: "LineStopped" }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: LineEvent; revision: bigint }>;
  appendToStream(stream: string, events: LineEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handleLine(command: LineCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  let state: LineState = { status: "none" };
  let revision: ExpectedRevision = "no_stream";
  for await (const { event, revision: r } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    revision = r;
  }
  const out = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, out, { expectedRevision: revision });
}
