The idiom is: read the last revision, decide, and append with `expectedRevision` set to that revision. On conflict, re-read and retry once; a second conflict bubbles up as a typed `ConcurrencyConflict` so callers can apply their own backoff.

```typescript
export type PlayerEvent =
  | { type: "PlayerSigned"; id: string; club: string }
  | { type: "PlayerTransferred"; toClub: string };

export type ExpectedRevision = bigint | "no_stream";

export interface StoredEvent<E> {
  revision: bigint;
  event: E;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream<E>(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {}

export async function appendWithRetry(
  store: EventStore,
  stream: string,
  decide: (events: readonly PlayerEvent[]) => readonly PlayerEvent[],
): Promise<bigint> {
  for (let attempt = 0; attempt < 2; attempt++) {
    const stored = await store.readStream<PlayerEvent>(stream);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const newEvents = decide(stored.map((s) => s.event));
    try {
      const result = await store.appendToStream<PlayerEvent>(stream, newEvents, { expectedRevision: expected });
      return result.nextRevision;
    } catch (err) {
      const e = err as { kind?: string };
      if (e.kind !== "concurrency") throw err;
    }
  }
  throw new ConcurrencyConflict("retry exhausted");
}
```

Snapshots freeze derived state so replay is bounded; without a version tag an old snapshot loaded into new code is a silent type mismatch. The loader reads version, runs upgraders in order, and the assertion at the end pins the shape to the current schema.

```typescript
export interface CookingSessionV1 {
  readonly id: string;
  readonly stepsDone: number;
}

export interface CookingSessionV2 extends CookingSessionV1 {
  readonly chefId: string;
}

export interface CookingSessionV3 extends CookingSessionV2 {
  readonly durationMs: number;
}

export type CurrentCookingSession = CookingSessionV3;
export const CURRENT_VERSION = 3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(state: CookingSessionV1): CookingSessionV2 {
  return { ...state, chefId: "" };
}

function v2Tov3(state: CookingSessionV2): CookingSessionV3 {
  return { ...state, durationMs: 0 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentCookingSession> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as CookingSessionV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as CookingSessionV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unsupported snapshot version ${snap.version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentCookingSession };
}

```

`enqueueActions` gives an imperative `enqueue` helper plus a `check('guardName')` predicate, so you can branch side effects in a single action. The builder methods (`enqueue.assign`, `enqueue.raise`, `enqueue.sendTo`, `enqueue.emit`) are type-checked against the machine's setup.

```typescript
import { setup, enqueueActions } from 'xstate';

export const quadMachine = setup({
  types: {
    context: {} as { n: number; warned: boolean },
    events: {} as { type: 'STEP' } | { type: 'WARN' } | { type: 'RESET' },
  },
  guards: {
    nearLimit: ({ context }) => context.n >= 2,
  },
}).createMachine({
  id: 'quad',
  context: { n: 0, warned: false },
  on: {
    STEP: {
      actions: enqueueActions(({ enqueue, check }) => {
        enqueue.assign({ n: ({ context }) => context.n + 1 });
        if (check('nearLimit')) {
          enqueue.assign({ warned: () => true });
          enqueue.raise({ type: 'WARN' });
        }
        enqueue.raise({ type: 'RESET' });
      }),
    },
    WARN: {},
    RESET: {},
  },
});
