```typescript
export type ExpectedRevision = bigint | "no_stream" | "any";

export interface ReadResult<E> { readonly revision: bigint; readonly events: E[] }
export interface AppendResult { readonly nextRevision: bigint }

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export type PrescriptionState =
  | { status: "none" }
  | { status: "active"; id: string; drug: string; refillsLeft: number }
  | { status: "cancelled"; id: string };

export type PrescriptionCommand =
  | { type: "prescribe"; id: string; drug: string; refills: number }
  | { type: "refill" };

export type PrescriptionEvent =
  | { type: "PrescriptionWritten"; id: string; drug: string; refills: number }
  | { type: "PrescriptionRefilled" };

export const initialState: PrescriptionState = { status: "none" };

export function evolve(s: PrescriptionState, e: PrescriptionEvent): PrescriptionState {
  switch (e.type) {
    case "PrescriptionWritten":
      return { status: "active", id: e.id, drug: e.drug, refillsLeft: e.refills };
    case "PrescriptionRefilled":
      if (s.status !== "active") return s;
      return { ...s, refillsLeft: s.refillsLeft - 1 };
    default: {
      const _never: never = e;
      return s;
    }
  }
}

export function decide(c: PrescriptionCommand, s: PrescriptionState): PrescriptionEvent[] {
  switch (c.type) {
    case "prescribe":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "PrescriptionWritten", id: c.id, drug: c.drug, refills: c.refills }];
    case "refill":
      if (s.status !== "active") throw new Error("NOT_ACTIVE");
      if (s.refillsLeft <= 0) throw new Error("NO_REFILLS");
      return [{ type: "PrescriptionRefilled" }];
    default: {
      const _never: never = c;
      throw new Error("UNKNOWN");
    }
  }
}

export interface CommandHandler<C, E> {
  handle(command: C, ctx: { streamName: string; eventStore: EventStore<E> }): Promise<bigint>;
}

export const prescriptionCommandHandler: CommandHandler<PrescriptionCommand, PrescriptionEvent> = {
  async handle(command, { streamName, eventStore }) {
    const read = await eventStore.readStream(streamName);
    const state = read.events.reduce(evolve, initialState);
    const events = decide(command, state);
    const expectedRevision: ExpectedRevision = read.events.length === 0 ? "no_stream" : read.revision;
    const appended = await eventStore.appendToStream(streamName, events, { expectedRevision });
    return appended.nextRevision;
  },
};
```

The flow has two async steps. `requestPermission` resolves to `'granted' | 'denied' | 'default'`. On granted, a second `fromPromise` actor registers the push subscription. Both actors are declared in `setup.actors`, invoked from their own state, and their output flows into context via `onDone`. Strict typing via `setup.types` ensures every transition target is a declared state.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Perm = 'granted' | 'denied' | 'default';

export const notifFlow = setup({
  types: {
    context: {} as { perm: Perm; endpoint: string | null },
    events: {} as { type: 'START' },
  },
  actors: {
    ask: fromPromise<Perm, void>(async () => Notification.requestPermission()),
    subscribe: fromPromise<{ endpoint: string }, void>(async () => {
      const r = await fetch('/push/subscribe', { method: 'POST' });
      return r.json();
    }),
  },
  guards: {
    isGranted: ({ context }) => context.perm === 'granted',
  },
}).createMachine({
  id: 'notifFlow',
  initial: 'idle',
  context: { perm: 'default', endpoint: null },
  states: {
    idle: { on: { START: 'asking' } },
    asking: {
      invoke: {
        src: 'ask',
        onDone: {
          target: 'decide',
          actions: assign({ perm: ({ event }) => event.output }),
        },
      },
    },
    decide: {
      always: [
        { guard: 'isGranted', target: 'subscribing' },
        { target: 'denied' },
      ],
    },
    subscribing: {
      invoke: {
        src: 'subscribe',
        onDone: {
          target: 'subscribed',
          actions: assign({ endpoint: ({ event }) => event.output.endpoint }),
        },
        onError: { target: 'denied' },
      },
    },
    subscribed: { type: 'final' },
    denied: {},
  },
});
```

Keep one checkpoint per subscription name in a small checkpoint store. On start read it, iterate events starting after that position, apply each event to the read model, then write the new checkpoint — always AFTER the projection has been applied so a crash cannot lose an apply without losing the checkpoint.

```typescript
export type DigitalCopyEvent =
  | { type: "CopyAdded"; copyId: string; format: "pdf" | "epub" }
  | { type: "CopyRemoved"; copyId: string };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventSource<E> {
  from(position: bigint | null): AsyncIterable<{ event: E; position: bigint }>;
}

export type CountView = { pdf: number; epub: number };
export const empty: CountView = { pdf: 0, epub: 0 };

export function project(view: CountView, event: DigitalCopyEvent): CountView {
  switch (event.type) {
    case "CopyAdded":
      return event.format === "pdf" ? { ...view, pdf: view.pdf + 1 } : { ...view, epub: view.epub + 1 };
    case "CopyRemoved":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function runSubscription(
  name: string,
  checkpoints: CheckpointStore,
  source: EventSource<DigitalCopyEvent>,
  save: (view: CountView) => Promise<void>,
): Promise<void> {
  const start = await checkpoints.read(name);
  let view = empty;
  for await (const { event, position } of source.from(start)) {
    view = project(view, event);
    await save(view);
    await checkpoints.write(name, position);
  }
}
```

```ts
export type DeepReadonly<T> =
  T extends (...args: any[]) => any ? T
  : T extends readonly (infer U)[] ? readonly DeepReadonly<U>[]
  : T extends object ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;
```

Functions are left alone (you don't want to `readonly`-mark call signatures). Arrays use `readonly U[]` so both `push` and index writes are disallowed. The object branch maps each key with `readonly` and recurses. Primitives fall through unchanged.

```typescript
import { setup, assign } from 'xstate';

type Point = { x: number; y: number };
interface Ctx { strokes: Point[][]; current: Point[] | null; }
type Ev =
  | { type: 'BEGIN'; point: Point }
  | { type: 'EXTEND'; point: Point }
  | { type: 'END' }
  | { type: 'UNDO' };

export const drawingMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    startStroke: assign({
      current: ({ event }) => (event.type === 'BEGIN' ? [event.point] : null)
    }),
    extendStroke: assign({
      current: ({ context, event }) =>
        event.type === 'EXTEND' && context.current
          ? [...context.current, event.point]
          : context.current
    }),
    commitStroke: assign({
      strokes: ({ context }) =>
        context.current ? [...context.strokes, context.current] : context.strokes,
      current: null
    }),
    popStroke: assign({
      strokes: ({ context }) => context.strokes.slice(0, -1)
    })
  }
}).createMachine({
  id: 'drawing',
  initial: 'idle',
  context: { strokes: [], current: null },
  states: {
    idle: {
      on: {
        BEGIN: { target: 'drawing', actions: 'startStroke' },
        UNDO: { actions: 'popStroke' }
      }
    },
    drawing: {
      on: {
        EXTEND: { actions: 'extendStroke' },
        END: { target: 'idle', actions: 'commitStroke' }
      }
    }
  }
});
