Use Array.prototype.reduce with a pure evolve reducer. Each event case updates immutably, with a never default to force exhaustive matching.

```typescript
export type WaypointEvent =
  | { type: "WaypointDefined"; id: string; lat: number; lon: number }
  | { type: "WaypointVisited"; at: string }
  | { type: "WaypointRetired" };

export interface WaypointState {
  readonly id: string | null;
  readonly coord: { lat: number; lon: number } | null;
  readonly visits: number;
  readonly retired: boolean;
}

export const initialWaypoint: WaypointState = { id: null, coord: null, visits: 0, retired: false };

export function evolve(state: WaypointState, event: WaypointEvent): WaypointState {
  switch (event.type) {
    case "WaypointDefined":
      return { ...state, id: event.id, coord: { lat: event.lat, lon: event.lon } };
    case "WaypointVisited":
      return { ...state, visits: state.visits + 1 };
    case "WaypointRetired":
      return { ...state, retired: true };
    default: { const _n: never = event; return state; }
  }
}

export function aggregate(events: readonly WaypointEvent[]): WaypointState {
  return events.reduce(evolve, initialWaypoint);
}
