```typescript
export type GreenhouseCommand =
  | { type: "open"; id: string }
  | { type: "seal" };

export type GreenhouseEvent =
  | { type: "GreenhouseOpened"; id: string }
  | { type: "GreenhouseSealed" };

type State = { status: "closed" } | { status: "open"; id: string } | { status: "sealed"; id: string };

const initialState: State = { status: "closed" };

function evolve(state: State, event: GreenhouseEvent): State {
  switch (event.type) {
    case "GreenhouseOpened":
      return { status: "open", id: event.id };
    case "GreenhouseSealed":
      if (state.status !== "open") return state;
      return { status: "sealed", id: state.id };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

function decide(cmd: GreenhouseCommand, state: State): GreenhouseEvent[] {
  switch (cmd.type) {
    case "open":
      if (state.status !== "closed") throw new Error("NOT_CLOSED");
      return [{ type: "GreenhouseOpened", id: cmd.id }];
    case "seal":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "GreenhouseSealed" }];
    default: {
      const _n: never = cmd;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: GreenhouseEvent }>>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<GreenhouseEvent>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export async function handle(
  cmd: GreenhouseCommand,
  ctx: { streamName: string; store: EventStore }
): Promise<void> {
  const stored = await ctx.store.readStream(ctx.streamName);
  const state = stored.reduce<State>((s, r) => evolve(s, r.event), initialState);
  const events = decide(cmd, state);
  const expected: bigint | "no_stream" =
    stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await ctx.store.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}
```

