export type FeatureStoreState =
  | { status: "none" }
  | { status: "open"; id: string; active: string[] }
  | { status: "sealed"; id: string; active: string[] };

export type FeatureStoreEvent =
  | { type: "FeatureStoreCreated"; id: string }
  | { type: "FeatureAdded"; name: string }
  | { type: "FeatureRetired"; name: string }
  | { type: "FeatureStoreSealed" };

export const initialFeatureStore: FeatureStoreState = { status: "none" };

export function evolve(state: FeatureStoreState, event: FeatureStoreEvent): FeatureStoreState {
  switch (event.type) {
    case "FeatureStoreCreated":
      return { status: "open", id: event.id, active: [] };
    case "FeatureAdded":
      if (state.status !== "open") return state;
      if (state.active.includes(event.name)) return state;
      return { ...state, active: [...state.active, event.name] };
    case "FeatureRetired":
      if (state.status !== "open") return state;
      return { ...state, active: state.active.filter((n) => n !== event.name) };
    case "FeatureStoreSealed":
      if (state.status !== "open") return state;
      return { status: "sealed", id: state.id, active: state.active };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: FeatureStoreEvent[]): FeatureStoreState {
  return events.reduce(evolve, initialFeatureStore);
}
