export type ContractEvent =
  | { type: "ContractSigned"; id: string; at: string }
  | { type: "ContractTerminated"; id: string; at: string };

export interface OutboxRow {
  id: string;
  payload: string;
  publishedAt: string | null;
}

export interface Transaction {
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
  appendToStream(
    stream: string,
    events: readonly ContractEvent[],
    opts: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export interface UnitOfWork {
  run<T>(fn: (tx: Transaction) => Promise<T>): Promise<T>;
}

// The outbox publisher (not implemented here) periodically polls rows
// with publishedAt === null, ships each payload to the message broker,
// and marks them published. This keeps event-store append and broker
// publish atomic from the producer's point of view.
export async function appendWithOutbox(
  uow: UnitOfWork,
  stream: string,
  events: readonly ContractEvent[],
  outbox: readonly OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<void> {
  await uow.run(async (tx) => {
    await tx.appendToStream(stream, events, { expectedRevision });
    await tx.insertOutbox(outbox);
  });
}
