export interface CurrentGalleryShowState {
  readonly id: string;
  readonly title: string;
  readonly rooms: number;
  readonly visitors: number;
  readonly status: "planned" | "open" | "closed";
}

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3;

interface V1 { id: string; title: string; rooms: number; }
interface V2 { id: string; title: string; rooms: number; visitors: number; }

function v1Tov2(snap: Snapshot<V1>): Snapshot<V2> {
  return { version: 2, state: { ...snap.state, visitors: 0 } };
}

function v2Tov3(snap: Snapshot<V2>): Snapshot<CurrentGalleryShowState> {
  return { version: 3, state: { ...snap.state, status: "planned" } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentGalleryShowState> {
  let working: Snapshot<unknown> = raw;
  if (working.version === 1) working = v1Tov2(working as Snapshot<V1>);
  if (working.version === 2) working = v2Tov3(working as Snapshot<V2>);
  if (working.version !== CURRENT_VERSION) {
    throw new Error(`Cannot upgrade GalleryShow snapshot from v${raw.version}`);
  }
  return working as Snapshot<CurrentGalleryShowState>;
}
