type SampleEvent =
  | { type: 'SampleCollected'; by: string; at: string }
  | { type: 'SampleCatalogued'; catalogueId: string };

type State =
  | { status: 'fresh' }
  | { status: 'collected'; by: string }
  | { status: 'catalogued'; catalogueId: string };

export function when(state: State, event: SampleEvent): State {
  switch (event.type) {
    case 'SampleCollected':
      return { status: 'collected', by: event.by };
    case 'SampleCatalogued':
      return { status: 'catalogued', catalogueId: event.catalogueId };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = fold(state, event);
  }
  return state;
}

export async function loadSample(stream: AsyncIterable<SampleEvent>): Promise<State> {
  return aggregateStream<State, SampleEvent>(stream, when, { status: 'fresh' });
}
