export const autoMenu = setup({
  types: { events: {} as Ev }
}).createMachine({
  id: 'autoMenu',
  initial: 'closed',
  states: {
    closed: { on: { OPEN: 'open' } },
    open: {
      after: { 3000: 'closed' },
      on: {
        HOVER: 'open',
        CLOSE: 'closed'
      }
    }
  }
});
```

The `waiting` state holds the code and uses `after` to transition to `expired` once the TTL elapses. Resending from `expired` re-enters `sent` and cycles back through `waiting`, which restarts the timer naturally.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { code: string }
type Ev = { type: 'SEND'; code: string } | { type: 'ENTER'; code: string } | { type: 'RESEND' };

export const verifyResendMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { TTL: 5 * 60 * 1000 },
  guards: { match: ({ context, event }) => event.type === 'ENTER' && event.code === context.code }
}).createMachine({
  id: 'verifyResend',
  context: { code: '' },
  initial: 'idle',
  states: {
    idle: { on: { SEND: { target: 'sent', actions: assign({ code: ({ event }) => event.code }) } } },
    sent: { always: 'waiting' },
    waiting: {
      after: { TTL: 'expired' },
