export type CashRegisterEvent =
  | { type: "register-placed"; data: { id: string; workstation: string } }
  | { type: "shift-started"; data: { cashierId: string } }
  | { type: "transaction-registered"; data: { amount: number } }
  | { type: "shift-ended"; data: Record<string, never> };

export type CashRegister = Readonly<{
  id: string;
  workstation: string;
  float: number;
  currentCashierId: string | null;
}>;

export function when(
  current: Partial<CashRegister>,
  event: CashRegisterEvent,
): Partial<CashRegister> {
  switch (event.type) {
    case "register-placed":
      return { id: event.data.id, workstation: event.data.workstation, float: 0, currentCashierId: null };
    case "shift-started":
      return { ...current, currentCashierId: event.data.cashierId };
    case "transaction-registered":
      return { ...current, float: (current.float ?? 0) + event.data.amount };
    case "shift-ended":
      return { ...current, currentCashierId: null };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function isCashRegister(v: Partial<CashRegister>): v is CashRegister {
  return (
    typeof v.id === "string" && v.id.length > 0 &&
    typeof v.workstation === "string" && v.workstation.length > 0 &&
    typeof v.float === "number" &&
    (v.currentCashierId === null || typeof v.currentCashierId === "string")
  );
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const s = events.reduce<Partial<A>>(reducer, {});
  if (!check(s)) throw new Error("INVALID_STATE");
  return s;
}

export function registerFrom(events: CashRegisterEvent[]): CashRegister {
  return aggregateStream(events, when, isCashRegister);
}
