type PermitEvent =
  | { type: 'PermitIssued'; authority: string }
  | { type: 'PermitAmended'; clause: string }
  | { type: 'PermitRevoked'; reason: string };

type State =
  | { status: 'pending' }
  | { status: 'active'; authority: string; amendments: number }
  | { status: 'revoked'; reason: string };

export function when(state: State, event: PermitEvent): State {
  switch (event.type) {
    case 'PermitIssued':
      return { status: 'active', authority: event.authority, amendments: 0 };
    case 'PermitAmended':
      return state.status === 'active'
        ? { ...state, amendments: state.amendments + 1 }
        : state;
    case 'PermitRevoked':
      return { status: 'revoked', reason: event.reason };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = fold(state, event);
  }
  return state;
}

export async function load(events: AsyncIterable<PermitEvent>): Promise<State> {
  return aggregateStream<State, PermitEvent>(events, when, { status: 'pending' });
}
