export function decide(c: CourtFilingCommand, s: CourtFilingState): CourtFilingEvent[] {
  switch (c.type) {
    case "submit": return s.status === "empty" ? [{ type: "submitted", filingId: c.filingId }] : [];
    case "accept": return s.status === "submitted" ? [{ type: "accepted" }] : [];
    case "reject": return s.status === "submitted" ? [{ type: "rejected", reason: c.reason }] : [];
    default: { const _: never = c; return []; }
  }
