export interface BOMEvent { type: string; payload: unknown; }

export interface OutboxRow {
  readonly id: string;
  readonly payload: unknown;
  readonly publishedAt: string | null;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface Transaction {
  insertOutbox(rows: OutboxRow[]): Promise<void>;
  appendToStream(stream: string, events: BOMEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface Connection {
  beginTransaction(): Promise<Transaction>;
}

// A separate publisher worker polls the outbox for rows where publishedAt is null,
// pushes their payload to the message bus, and marks publishedAt on success.
export async function appendWithOutbox(
  stream: string,
  events: BOMEvent[],
  outboxRows: OutboxRow[],
  conn: Connection,
  expected: ExpectedRevision
): Promise<void> {
  const tx = await conn.beginTransaction();
  try {
    await tx.insertOutbox(outboxRows);
    await tx.appendToStream(stream, events, { expectedRevision: expected });
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
