export interface Snapshot<S> { version: number; state: S }
interface FilingV1 { filingId: string; caseId: string }
interface FilingV2 { filingId: string; caseId: string; status: "open" | "decided" }
interface FilingV3 { filingId: string; caseId: string; status: "open" | "decided"; submittedAt: number }
export type CurrentFilingState = FilingV3;
export const CURRENT_VERSION = 3;
function upgradeV1ToV2(s: FilingV1): FilingV2 { return { ...s, status: "open" }; }
function upgradeV2ToV3(s: FilingV2): FilingV3 { return { ...s, submittedAt: 0 }; }
export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentFilingState> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = upgradeV1ToV2(state as FilingV1); version = 2; }
  if (version === 2) { state = upgradeV2ToV3(state as FilingV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error("unsupported snapshot version");
  return { version, state: state as CurrentFilingState };
}
