export type GreenhouseState =
  | { status: "closed" }
  | { status: "open"; id: string; temperatureC: number; humidity: number }
  | { status: "sealed"; id: string };

export type GreenhouseCommand =
  | { type: "open"; id: string }
  | { type: "setClimate"; temperatureC: number; humidity: number }
  | { type: "seal" };

export type GreenhouseEvent =
  | { type: "GreenhouseOpened"; id: string }
  | { type: "GreenhouseClimateSet"; temperatureC: number; humidity: number }
  | { type: "GreenhouseSealed" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const greenhouseDecider: Decider<GreenhouseCommand, GreenhouseEvent, GreenhouseState> = {
  initialState: { status: "closed" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "closed") throw new DomainError("NOT_CLOSED");
        return [{ type: "GreenhouseOpened", id: command.id }];
      case "setClimate":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (command.humidity < 0 || command.humidity > 100) throw new DomainError("INVALID_HUMIDITY");
        return [{ type: "GreenhouseClimateSet", temperatureC: command.temperatureC, humidity: command.humidity }];
      case "seal":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "GreenhouseSealed" }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "GreenhouseOpened":
        return { status: "open", id: event.id, temperatureC: 20, humidity: 50 };
      case "GreenhouseClimateSet":
        if (state.status !== "open") return state;
        return { ...state, temperatureC: event.temperatureC, humidity: event.humidity };
      case "GreenhouseSealed":
        if (state.status !== "open") return state;
        return { status: "sealed", id: state.id };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
