export type GuardrailMetricEvent =
  | { type: "GuardrailMetricSampled"; metricId: string; value: number; at: string }
  | { type: "GuardrailMetricBreached"; metricId: string; at: string; threshold: number }
  | { type: "GuardrailMetricReset"; metricId: string };

export type MetricStats = Readonly<{ min: number; max: number; count: number; breaches: number }>;
export type GuardrailMetricView = Readonly<{ byMetric: Readonly<Record<string, MetricStats | undefined>> }>;

export const emptyView: GuardrailMetricView = { byMetric: {} };
const emptyStats: MetricStats = { min: Number.POSITIVE_INFINITY, max: Number.NEGATIVE_INFINITY, count: 0, breaches: 0 };

export function project(view: GuardrailMetricView, event: GuardrailMetricEvent): GuardrailMetricView {
  switch (event.type) {
    case "GuardrailMetricSampled": {
      const prev = view.byMetric[event.metricId] ?? emptyStats;
      const next: MetricStats = {
        min: Math.min(prev.min, event.value),
        max: Math.max(prev.max, event.value),
        count: prev.count + 1,
        breaches: prev.breaches,
      };
      return { byMetric: { ...view.byMetric, [event.metricId]: next } };
    }
    case "GuardrailMetricBreached": {
      const prev = view.byMetric[event.metricId] ?? emptyStats;
      return {
        byMetric: { ...view.byMetric, [event.metricId]: { ...prev, breaches: prev.breaches + 1 } },
      };
    }
    case "GuardrailMetricReset": {
      const next = { ...view.byMetric };
      delete next[event.metricId];
      return { byMetric: next };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
