export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], options: AppendOptions): Promise<{ nextRevision: bigint }>;
}

export const initialState: FeatureFlagState = { status: "missing" };

export function evolve(state: FeatureFlagState, event: FeatureFlagEvent): FeatureFlagState {
  switch (event.type) {
    case "FeatureFlagCreated":
      return { status: "disabled", id: event.id, key: event.key };
    case "FeatureFlagEnabled":
      if (state.status !== "disabled") return state;
      return { status: "enabled", id: state.id, key: state.key };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: FeatureFlagCommand, state: FeatureFlagState): FeatureFlagEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "missing") throw new Error("EXISTS");
      return [{ type: "FeatureFlagCreated", id: command.id, key: command.key }];
    case "enable":
      if (state.status !== "disabled") throw new Error("CANNOT_ENABLE");
      return [{ type: "FeatureFlagEnabled" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export async function handle(
  command: FeatureFlagCommand,
  deps: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const records = await deps.eventStore.readStream<FeatureFlagEvent>(deps.streamName);
  const state = records.reduce<FeatureFlagState>((s, r) => evolve(s, r.event), initialState);
  const expected: AppendOptions["expectedRevision"] =
    records.length === 0 ? "no_stream" : records[records.length - 1].revision;
  const events = decide(command, state);
  await deps.eventStore.appendToStream<FeatureFlagEvent>(deps.streamName, events, { expectedRevision: expected });
}
