```typescript
interface StoredEvent<E> { data: E; revision: bigint }

interface AppendResult { nextRevision: bigint }

interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(
    stream: string,
    events: E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export type LeaseEvent =
  | { type: "LeaseDrafted"; id: string }
  | { type: "LeaseSigned"; at: string };

export async function appendLeaseEvents(
  store: EventStore<LeaseEvent>,
  stream: string,
  events: LeaseEvent[],
): Promise<bigint> {
  const existing = await store.readStream(stream);
  const expectedRevision: bigint | "no_stream" =
    existing.length === 0 ? "no_stream" : existing[existing.length - 1].revision;
  try {
    const result = await store.appendToStream(stream, events, { expectedRevision });
    return result.nextRevision;
  } catch (err) {
    if (err instanceof Error && err.message.includes("WrongExpectedVersion")) {
      throw new ConcurrencyConflict(stream, expectedRevision);
    }
    throw err;
  }
}
