export type HarvestWindowEvent =
  | { type: "HarvestWindowOpened"; id: string; farmId: string; startsAt: string }
  | { type: "HarvestWindowExtended"; id: string; newEndsAt: string }
  | { type: "HarvestWindowClosed"; id: string; farmId: string }
  | { type: "HarvestWindowCancelled"; id: string; farmId: string; reason: string };

export interface FarmHarvestView {
  readonly activeByFarm: Readonly<Record<string, number>>;
  readonly totalOpened: number;
  readonly totalClosed: number;
}

export const emptyView: FarmHarvestView = {
  activeByFarm: {},
  totalOpened: 0,
  totalClosed: 0,
};

export function project(view: FarmHarvestView, event: HarvestWindowEvent): FarmHarvestView {
  switch (event.type) {
    case "HarvestWindowOpened": {
      const prev = view.activeByFarm[event.farmId] ?? 0;
      return {
        activeByFarm: { ...view.activeByFarm, [event.farmId]: prev + 1 },
        totalOpened: view.totalOpened + 1,
        totalClosed: view.totalClosed,
      };
    }
    case "HarvestWindowExtended":
      return view;
    case "HarvestWindowClosed": {
      const prev = view.activeByFarm[event.farmId] ?? 0;
      return {
        activeByFarm: { ...view.activeByFarm, [event.farmId]: Math.max(0, prev - 1) },
        totalOpened: view.totalOpened,
        totalClosed: view.totalClosed + 1,
      };
    }
    case "HarvestWindowCancelled": {
      const prev = view.activeByFarm[event.farmId] ?? 0;
      return {
        ...view,
        activeByFarm: { ...view.activeByFarm, [event.farmId]: Math.max(0, prev - 1) },
      };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
