export type BinEvent =
  | { type: "BinRestocked"; binId: string; sku: string; qty: number; revision: bigint }
  | { type: "BinPicked"; binId: string; sku: string; qty: number; revision: bigint };

export interface BinView { readonly onHand: Readonly<Record<string, number>>; }
export const emptyView: BinView = { onHand: {} };

export function project(v: BinView, e: BinEvent): BinView {
  const current = v.onHand[e.sku] ?? 0;
  switch (e.type) {
    case "BinRestocked": return { onHand: { ...v.onHand, [e.sku]: current + e.qty } };
    case "BinPicked": return { onHand: { ...v.onHand, [e.sku]: current - e.qty } };
    default: { const _n: never = e; return v; }
  }
}

export interface EventReader {
  readStream(opts: { from: bigint; batchSize: number }): AsyncIterable<ReadonlyArray<BinEvent>>;
}

export interface ViewStore {
  persist(view: BinView, throughRevision: bigint): Promise<void>;
  reset(): Promise<void>;
}

export interface RebuildOptions {
  readonly from: bigint;
  readonly batchSize: number;
}

export async function rebuild(
  reader: EventReader,
  store: ViewStore,
  opts: RebuildOptions,
): Promise<void> {
  if (opts.from === 0n) await store.reset();
  let view: BinView = emptyView;
  let cursor: bigint = opts.from;
  async function main(): Promise<void> {
    for await (const batch of reader.readStream({ from: cursor, batchSize: opts.batchSize })) {
      for (const event of batch) {
        view = project(view, event);
        cursor = event.revision;
      }
      await store.persist(view, cursor);
    }
  }
  await main();
}
