export type MilestoneState =
  | { status: "none" }
  | { status: "scheduled"; id: string; name: string; dueDate: string }
  | { status: "reached"; id: string; name: string; reachedAt: string };

export type MilestoneCommand =
  | { type: "defineMilestone"; id: string; name: string; dueDate: string }
  | { type: "markReached"; at: string }
  | { type: "postpone"; newDueDate: string };

export type MilestoneEvent =
  | { type: "MilestoneDefined"; id: string; name: string; dueDate: string }
  | { type: "MilestoneReached"; at: string }
  | { type: "MilestonePostponed"; newDueDate: string };

export class MilestoneError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const milestoneDecider: Decider<MilestoneCommand, MilestoneEvent, MilestoneState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "defineMilestone":
        if (s.status !== "none") throw new MilestoneError("ALREADY_DEFINED");
        return [{ type: "MilestoneDefined", id: c.id, name: c.name, dueDate: c.dueDate }];
      case "markReached":
        if (s.status !== "scheduled") throw new MilestoneError("NOT_SCHEDULED");
        return [{ type: "MilestoneReached", at: c.at }];
      case "postpone":
        if (s.status === "reached") throw new MilestoneError("ALREADY_REACHED");
        if (s.status === "none") throw new MilestoneError("NOT_FOUND");
        return [{ type: "MilestonePostponed", newDueDate: c.newDueDate }];
      default: {
        const _n: never = c;
        throw new MilestoneError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "MilestoneDefined":
        return { status: "scheduled", id: e.id, name: e.name, dueDate: e.dueDate };
      case "MilestoneReached":
        if (s.status !== "scheduled") return s;
        return { status: "reached", id: s.id, name: s.name, reachedAt: e.at };
      case "MilestonePostponed":
        if (s.status !== "scheduled") return s;
        return { ...s, dueDate: e.newDueDate };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
```
